INSERT INTO public.news VALUES (788, '2024年高中部（含国际部）招生报名入口', '', '1、报名时间：2024年6月20日8:00至6月24日12:002、报名系统入口链接：http://gaozhong.wiscoor.com3、下载打印准考证：（1）下载打印准考证时间：6月25日14:00—24:00；（2）下载打印方式：登录报名系统，使用报名注册的账号、密码登录系统查看，并下载打印准考证。4、咨询电话：0531-59562266（普通班）、0531-59562288（国际班）', '', '<p><a href="images/e8433c5d65c44847aab85371ecc704a9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e8433c5d65c44847aab85371ecc704a9.jpg" width="500" height="281"/></a></p><p><span>1、报名时间：2024年6月20日8:00至6月24日12:00</span></p><p><span>2、报名系统入口链接：</span><a href="http://gaozhong.wiscoor.com" target="_blank" title="http://gaozhong.wiscoor.com"><span>http://gaozhong.wiscoor.com</span></a></p><p><span>3、下载打印准考证：</span></p><p><span>（1）下载打印准考证时间：6月25日14:00—24:00；</span></p><p><span>（2）下载打印方式：登录报名系统，使用报名注册的账号、密码登录系统查看，并下载打印准考证。</span></p><p><span>4、咨询电话：0531-59562266（普通班）、0531-59562288（国际班）</span></p><p><br/></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images/e8433c5d65c44847aab85371ecc704a9.jpg', NULL, true, '2024-06-20 02:19:00+08', '2024-06-20 02:19:00+08', '2024-06-20 02:19:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '293496');
INSERT INTO public.news VALUES (789, '济南新航实验外国语学校：蓄势向“新”，乘风起“航”', '', '“闪光人格培育人，高尚心灵唤醒人，扎实学识启迪人”——在济南新航实验外国语学校，每间办公室的墙壁上都张贴着这则督学内容。秉持“让每一个生命都精彩绽放”的育人理念，学校把弘扬践行教育家精神作为重要引领，坚持做“温和而又坚定”的教育，成为浸润学生心灵、启迪学生思考、完善学生人格、提升学生能力、让学生终身受益的齐鲁名校。　　◎山东商报·速豹新闻网记者　张舒　　用爱心培育爱心　　老师陪伴助学生“蜕变”　　...', '', '<p><img title="微信图片_20240614102106.jpg" src="/uploads/migration/images/0a36c4baf6254543948b28fb00cbcc2b.jpg"/><span><span>“闪光人格培育人，高尚心灵唤醒人，扎实学识启迪人”——在济南新航实验外国语学校，每间办公室的墙壁上都张贴着这则督学内容。秉持“让每一个生命都精彩绽放”的育人理念，学校把弘扬践行教育家精神作为重要引领，坚持做“温和而又坚定”的教育，成为浸润学生心灵、启迪学生思考、完善学生人格、提升学生能力、让学生终身受益的齐鲁名校。</span><br/><br/><span>　　◎山东商报·速豹新闻网记者　张舒</span><br/><br/><span>　　用爱心培育爱心</span><br/><span>　　老师陪伴助学生“蜕变”</span><br/><br/><span>　　做有情怀的教师，做有温度的教育，这是新航实验的老师们曾经、现在和未来一直坚守的初心。“用热情和专业启迪学生，让爱陪伴学生健康成长。教师的一言一行、一举一动时时刻刻都会给学生留下深刻的印象，有时候甚至会影响学生的一辈子。”新航实验高二级部主任董冬认为，良好的师生关系是提高教学效率的重要条件，处理好与学生的关系，亲其师才能信其言。</span><br/><br/><span>　　正在就读高三的程鲁毅，高一入校时成绩并不理想，上课经常走神，学习习惯和精神状态都比较懈怠。担任班主任的董冬和他交流得知，程鲁毅从小家境优渥，缺乏学习的动力，看到身边努力奋斗的同学们，他感到非常迷茫。</span><br/><br/><span>　　要用热情和专业启迪学生，让爱陪伴学生健康成长。但是怎么才能走入学生的心灵呢？通过与程鲁毅的多次交心长谈，董冬决定从帮助孩子寻找个人价值、感受自我认同着手，激发学生的内生动力。“学习不是只让孩子做题，更是引导他们学会用学习中探索和反思的思维方式去解决生活中的问题。”董冬没有急于纠正程鲁毅的学习态度，而是与孩子多次交心长谈，“孩子能看到对比、独立思考并勇敢表达，说明内心是渴望改变的。要让孩子感受到被家长和老师重视，让他意识到自己肩负的责任和担当，就不会放弃自我。”为此，董冬专门请程鲁毅的家长来到学校，为孩子创造一个相对私密的交流空间，让家长以平等的视角、朋友的身份和孩子沟通对话，让孩子了解父母创业与守业的不易，感受奋斗带来的满足感和自我价值。</span><br/><br/><span>　　这次以后，程鲁毅的变化可以用“脱胎换骨”来形容，不仅课堂上的积极主动性提高了，还会对董冬畅谈学习目标和人生理想。“董老师的关心不仅体现在话语，更是于细微处彰显的言传身教，以行动感染学生，影响学生。”程鲁毅说，进入高三，身边的很多同学都有了高考目标院校，但自己由于对政策和学校都不太了解，所以迟迟没有选好想报考的专业。“我无意中和同学说过一次，没注意当时董老师也在旁边。没想到，过了几天，董老师整理出厚厚的一沓材料给我。原来，他按照我擅长的、喜欢的学科，结合高考政策，推荐了十几所高校，并把学校相关专业的招生政策、录取分数、发展前景等都整理成册，方便我深入了解。”程鲁毅感慨，那沓资料让他第一次感到，爱是有重量和温度的。</span><br/><br/><span>　　用智慧成就智慧</span><br/><span>　　“导师制”实现教育最优化</span><br/><br/><span>　　什么是好的教育？这是新航实验高三级部主任杨海三一直思考和努力回答的问题。在过往的教学经历中，他注意到，有的教师在上课时只表扬那些回答与“标准答案”相符的学生，忽略了提出不同看法的学生。“其实，问题比答案更重要。不能忽略孩子们发现问题的能力，甚至要鼓励学生提出新见解。”杨海三认为，“每一个生命的个体都是独特的，它必然有自己独特的成长方式，有自己独特的思维方式，会遇到自己独特的问题，会碰到自己独特的困惑。”在他看来，学校个性化辅导工作的推行，以及“学生成长导师制”的建立，实现了教育效果的最大化，“对学生的学习起到至关重要的作用，也实现了教师教育价值的最大化。这一形式也越来越得到学生和家长的认可。”</span><br/><br/><span>　　在新航实验，每一位教师都会兼任学生导师，他们会经常从任课老师、班主任、心理老师那里了解每位“亲学生”的近况，并在定期举行的“导师见面会”中，从学业、心理、思想、生活等方面为学生开导答疑，从而建立安全亲密的师生关系。学校的教学模式也为老师们“直击提升学生能力与素养的根本”提供了条件：每个班级不超过30人的小班化教学让因材施教更精准，1：5的师生比则让老师有足够的精力来关注到每一个学生。</span><br/><br/><span>　　学校2020级学生朱柯宇，平时学习成绩在级部名列前茅，高考前的连续三次摸底考试，成绩却出现连续下滑的情况。朱柯宇的成绩波动立刻引起了老师杨海三的注意，他观察到一个细节，每次开考后，朱柯宇的手上就开始飞速转笔，这个机械化的刻板动作会一直持续到考试结束。“通过这个小动作，能感受到孩子的心理压力比较大。”杨海三分析，朱柯宇性格内敛且非常自律，对自我要求也比较高，事事力求全面和完美。“孩子需要的是一个释放压力的窗口。为此，我给他提了一个小建议，考试时不用力求完美，把担子卸下来。有舍才有得，做题是这样，做人也是这样。”</span><br/><br/><span>　　就这样，杨海三每日与朱柯宇同吃同住，利用运动和聊天缓解孩子的焦虑情绪。“我们之间既是师生也是朋友。当孩子学习上遇到困难时，生活中遇到困惑时，和同学闹别扭时，感到孤独无助时，感觉和父母无法沟通时，我随时向孩子们张开双臂。”杨海三真挚而温暖的陪伴，让朱柯宇很快卸下包袱、调整心态，最终以优异的成绩被国家“双一流”高校南方科技大学录取。</span><br/><br/><span>　　用高度成就高度</span><br/><span>　　“硬核”师资赋能高效课堂</span><br/><br/><span>　　“经师易求，人师难得”。一所好的学校，一定有很多好的老师。在济南新航实验外国语学校，集聚着一批大咖级名师。他们擅长的，就是让知识到达学生的最近发展区。国务院津贴专家、国家教学名师邵丽云；济南市政协常委、山东省特级教师刘沂珍；济南市学科带头人、正高级教师王玲；济南市优秀班主任、正高级教师张振春……高中部62名教师中，正高级教师有8人、高级教师人数达到了17人，这种师资配置绝对称得上是“王炸团队”！</span><br/><br/><span>　　此外，学校通过人才引进，拥有了一支高学历、高素质、多语言、多国别的教师队伍。其中，有来自华东师范大学、华中师范大学等国内一流师范大学的优秀毕业生，也有来自北京大学、中国科学技术大学、南京大学等国内顶尖综合性大学的博士、硕士研究生，还有来自世界级名校的毕业生。他们作为一线教师参与实际教学，是学校教学的中枢，更是各个学科的“领头羊”。</span><br/><br/><span>　　课堂是教育的主阵地。新高考下，考题灵活，对学生的核心素养要求更高，老师们也在积极通过新型课堂的创设，让“教”与“学”更入脑入心。“比如，以数学学科为例，它是有思路、方法和结构的，让学生把正确的数学学习思维构筑起来，知识才会融会贯通。”新航实验高中部数学老师马芳告诉记者，“要从学生的角度去思考问题。假如我是学生，需要什么样的教学？假如我是学生，喜欢什么样的老师？多从学生的角度思考教育教学问题，就会创设良好的教育教学氛围。”</span><br/><br/><span>　　知之者不如乐之者，乐之者不如好之者。同在一个班级，同上一堂课，但每位学生对知识的领悟和接受能力是不同的。为此，马芳会根据学生的个性和能力差异因材施教。“个性化辅导以尊重学生们的差异性为前提，着力培养学生的学习兴趣，激发学生的内生动力，碰撞学生的思维火花，让孩子完全释放自己的潜能。”</span><br/><br/><span>　　新航实验也为老师们实现课堂改革提供了条件：学校课程丰富，除了开设的国家课程外，还包括具有学校特色的校本课程、学科拓展类课程、依托科创中心的科技课程、注重实践的研学行走课程、依托学校70亩劳动基地和各科实验室开展的劳动课程，依托学校玄龄书院开展传统文化类课程，还包括在学校体育馆开设的游泳、击剑、体操、网球等诸多体育课程。</span><br/><br/><span>　　教育无痕犹如春风化雨润心田，润物无声恰似于无声处听惊雷。新航实验以“日新博学，志航天下”校训为精神追求，践行“让每一个生命都精彩绽放”的育人理念，在更高远的生命视野中留下孩子的成长足迹。</span></span></p><meta name="ContentStart"/>', '', 'campus', '/uploads/migration/images/0a36c4baf6254543948b28fb00cbcc2b.jpg', NULL, true, '2024-06-14 18:20:00+08', '2024-06-14 18:20:00+08', '2024-06-14 18:20:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293485');
INSERT INTO public.news VALUES (790, '济南新航实验外国语学校：每一个你的绽放，成就这里的精彩', '', '一所学校办得好不好，学生的成长就是最好的答案。　　“让每一个生命都精彩绽放”是济南新航实验外国语学校的办学理念，也是这所校园对家长与学子的承诺。自2019年建校至今，5年的时间过去，这一理念不仅在新航实验的每一个角落落地生根，也让一批批优秀学子通过多元路径圆梦未来，带着新航实验所赋予的底色走得更高、更远。　　“绽放”需要辛勤的培育，更需要适宜的环境与土壤，因为，每一个学生都不一样。学生们说，新航实...', '', '<p><img title="84be2ff6f7ae6580de23b776b3cc258.jpg" src="/uploads/migration/images/f7cf927b3dcb4c9591de915bf4a81f5f.jpg"/></p><p><span>　一所学校办得好不好，学生的成长就是最好的答案。</span></p><p><span>　　“让每一个生命都精彩绽放”是济南新航实验外国语学校的办学理念，也是这所校园对家长与学子的承诺。自2019年建校至今，5年的时间过去，这一理念不仅在新航实验的每一个角落落地生根，也让一批批优秀学子通过多元路径圆梦未来，带着新航实验所赋予的底色走得更高、更远。</span></p><p><span>　　“绽放”需要辛勤的培育，更需要适宜的环境与土壤，因为，每一个学生都不一样。学生们说，新航实验，恰恰是让个性化教育真实发生的育人场，“一生一案”赋予他们每个人不同的成长力量，也让青春有了更多的成长轨迹。</span></p><p><strong><span>　　绽放故事1</span></strong></p><p><strong><span>　　优秀进阶从近水楼台“取经”开始</span></strong></p><p><span>　　新航实验，让学生“优秀进阶”。</span></p><p><span>　　“这里的三年，不仅将我带到了‘双一流’大学，还塑造了我的爱好与性格。”2019年9月，作为新航实验的首届学子，魏子元成为新航实验的一名新生。</span></p><p><span>　　拍摄火车，是魏子元的个人爱好。让他没想到的是，入学仅月余，新生的新鲜感还未褪去，新航实验的老师们不仅捕捉到了他的爱好，还为他办了一场摄影个展。“原本是一个个人的小爱好，却被学校如此重视与珍视，也许，我成长的动力便是从此刻开启的。”</span></p><p><span>　　能动性，首先在文化课学习上展现。“我成绩提升的第一步，其实是从利用好身边的资源开始的。”魏子元说，身边的老师，就是最好的教育资源。新航实验的老师，很多都是大师级，比如一些来自省实验中学的老师，不仅本身教学精湛，也曾教出过非常多优秀的学子，魏子元觉得这是一个近水楼台“取经”的机会，“我会去请教老师学习方法，也会问他们‘优秀的人是如何学习的’，这让我的学习力迅速提升。”</span></p><p><span>　　三年的时光里，魏子元的成绩越来越好，爱好也没落下，并被扬长。“我拍摄火车，是因为从2岁起就开始喜欢火车，也在研究火车知识、火车的历史。”让魏子元没想到的是，这在升学时也变成了他的关键加分项。</span></p><p><span>　　高三下学期，魏子元参加了心仪大学华南理工大学的综招，在面试环节，考官问到的问题正是他的爱好。“聊了很多火车相关的专业知识，这个正好是我的强项。”侃侃而谈的魏子元大方、自信，最终因为面试取得的高分顺利被华南理工大学录取。</span></p><p><span>　　魏子元说，作为一名大学生再去回看自己的高中三年，他认为，新航实验给予他的不只是考取好的分数，更珍贵的在于对他性格的塑造。遇事多换位思考、多去看别人的优点，现在的魏子元已经做到了知行合一。“我也会把这些与我的家人一起分享，他们也觉得我不一样了，成熟、懂事了。”</span></p><p><strong><span>　　绽放故事2</span></strong></p><p><strong><span>　　老师鼓励的目光是向上的阶梯</span></strong></p><p><span>　　新航实验，让学生“融合共享”。</span></p><p><span>　　2020年的9月，李浩然来到了新航实验。初中，并不是被看见的那一个，在军训时，就被班主任杨翠华看到了。</span></p><p><span>　　“这个学生给我的感觉就跟他的名字一样，一身‘浩然正气’，做事很认真，执行力也很强，我就让他在军训时做了班级负责人。”被看到的李浩然果然如杨翠华所说的那样，自己表现出色，更把“负责人”的职责干得完美、漂亮。在军训会演中，还作为新生代表，站在全校师生面前发言。</span></p><p><span>　　这种“看见”有多宝贵?李浩然的每一个进步都是佐证。在学习上，他的每一科成绩都在提升，且在高考中稳定发挥，最终，以优异的成绩考入山东大学。这，不仅完成了李浩然的心愿，也让全家人特别开心。在李浩然父母发给杨翠华的信息里，这样书写着他们的心情：“老师鼓励的目光是学生向上的阶梯，谢谢您给了他成功的自信与勇气！”</span></p><p><span>　　在新航实验，李浩然的成长也不止学业这一面。</span></p><p><span>　　他告诉记者，他喜欢这里的氛围。“这里的同伴关系，是心往一块儿想、劲往一处使，大家相互帮助与扶持，你得到的是精神上的正向反馈。”</span></p><p><span>　　他也在这里找到爱好。“我喜欢摄影，一位学长教会了我很多，现在在大学里，我的特长也在发挥着价值，学院的宣传、公众号的新闻，我也在发挥着我的一份力量。”</span></p><p><span>　　李浩然说，更珍贵的是，在新航实验，让他学会了表达自我与独立思考。“人的一生当中会碰到很多问题，独立思考不仅能让你更理性，也会让你更自由。”</span></p><p><strong><span>　　绽放故事3</span></strong></p><p><strong><span>　　很多时候选择和努力同等重要</span></strong></p><p><span>　　新航实验，让学生“更有选择”。</span></p><p><span>　　2021年9月，姜书亚迈入了新航实验，成为又一届新生。也是在新航实验，姜书亚的一个“卡点”有了新的解开方式。</span></p><p><span>　　其他科目成绩不错，英语却是“瘸腿”科目。在高一下学期学校的一场宣讲中，姜书亚得知可以选择小语种，与老师、家人商量后，姜书亚也转换了赛道，在第一次期末考试中，他就考出了140分的成绩，此后，虽然难度逐渐增加，成绩也保持在130分以上。</span></p><p><span>　　小语种，让姜书亚去掉了“短板”，去掉的更是他心理上的堵点。老师们明显看到，姜书亚自信起来，其他科目的成绩也稳步提升。</span></p><p><span>　　姜书亚的日语老师，在整个高三级部，只带三名学生，但只要一名学生需要，就为其开课，是新航实验一直践行的。</span></p><p><span>　　除了日、俄、德、法、西等小语种课程，学校还在各学段开设了包括具有学校特色的校本课程、学科拓展类课程、依托科创中心的科技课程、注重实践的研学行走课程、依托学校70亩劳动基地和各科实验室开展的劳动课程、依托学校玄龄书院开展传统文化类课程，还包括在学校体育馆开设的游泳、击剑、体操、网球等诸多体育课程。与之相呼应的还有异彩纷呈的实践活动，比如，奇异博士项目、大手拉小手活动、国际美食节、特色夏校活动、学子论坛等，这些，一方面丰富着学生的教育教学内容，另一方面，促使着学生的全面成长。</span></p><p><span>　　除了课程和实践活动，学校还积极为学生创设各种平台和机会，比如信息学奥赛、世界机器人大赛、全国中学生创新作文大赛、美国化学竞赛、英国天文学和天体物理学奥赛、NEC全球经济挑战赛等，这些赛事，让学生站上更大的舞台，也成为学生探索自我的平台。</span></p><p><strong><span>　　记者手记：</span></strong><strong><span>新航实验的育人“全环境”</span></strong></p><p><span>　　如果你初次来到新航实验，想和学生们聊聊天，找不到话题时，可以问他们喜欢校园的哪一方面，只要这个话题打开，学生们便会滔滔不绝。</span></p><p><span>　　成长每天都在真实发生，所以，学生们才会格外有共鸣。</span></p><p><span>　　学生们眼中的新航实验，很治愈，他们说，美丽的校园就是“公园20分钟”最好的地点;学生们眼中的新航实验，很有人情味，他们说，老师很少说“不可以”，学生的每一个感受也都在被认真体谅，他们，甚至可以和老师“称兄道弟”;学生们眼中的新航实验，又很有实效，当一个需求提出，很快就会被反馈，遇到问题，随机经过你身边的一个老师就能帮助解决……</span></p><p><span>　　每个班级不超过30人的小班化教学让因材施教更精准，1：5的师生比让老师有足够的精力来关注到每一个学生，每一处校园空间都是为了育人而搭设，每一个舞台的构建都是助力学生更好地攀登，这里，让你找到你自己，并且，成为你自己。</span></p><p><br/></p><meta name="ContentEnd"/>', '', 'other', '/uploads/migration/images/f7cf927b3dcb4c9591de915bf4a81f5f.jpg', NULL, true, '2024-06-14 18:13:00+08', '2024-06-14 18:13:00+08', '2024-06-14 18:13:00+08', '', '', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293483');
