INSERT INTO public.news VALUES (794, '王玲', '', '王玲，语文正高级三级教师，济南市学科带头人，济南市中学语文研究会副理事长，济南市传统文化研究专业理事会理事。', '', '<p><span><span></span></span></p><p><a href="images/539f2dfc49b84f11bfc989a5ef605a6b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_539f2dfc49b84f11bfc989a5ef605a6b.jpg" width="300" height="428"/></a></p><p><span><span>王玲，</span><span>语文正高级三级教师，济南市学科带头人，济南市中学语文研究会副理事长，济南市传统文化研究专业理事会理事。</span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/539f2dfc49b84f11bfc989a5ef605a6b.jpg', NULL, true, '2024-06-05 20:02:00+08', '2024-06-05 20:02:00+08', '2024-06-05 20:02:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293434');
INSERT INTO public.news VALUES (795, '夏侯张媛', '', '夏侯张媛，“一师一优课”省级优课，全国中小学生建模水平与数学能力展示活动优秀辅导教师。', '', '<p><span><br/></span></p><p><span><span></span></span></p><p><a href="images/d29242ef0e414d3997db8dc4b4b5e6bc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d29242ef0e414d3997db8dc4b4b5e6bc.jpg" width="300" height="436"/></a></p><p><span>夏侯张媛</span><span><span>，</span><span>“一师一优课”省级优课，全国中小学生建模水平与数学能力展示活动优秀辅导教师。</span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/d29242ef0e414d3997db8dc4b4b5e6bc.jpg', NULL, true, '2024-06-05 19:59:00+08', '2024-06-05 19:59:00+08', '2024-06-05 19:59:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293432');
INSERT INTO public.news VALUES (796, '王佩', '', '王佩，槐荫区小学语文学科中心组成员、区教学能手、区小学书法优质课评比一等奖', '', '<p><span></span></p><p><a href="images/9d47532741274dcab18697e944e13db5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9d47532741274dcab18697e944e13db5.jpg" width="300" height="436"/></a></p><p><span>王佩</span><span>，槐荫区小学语文学科中心组成员、区教学能手、区小学书法优质课评比一等奖</span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/9d47532741274dcab18697e944e13db5.jpg', NULL, true, '2024-06-05 19:59:00+08', '2024-06-05 19:59:00+08', '2024-06-05 19:59:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293433');
INSERT INTO public.news VALUES (797, '黄婷婷', '', '黄婷婷，“一师一优课”省级优课，市中区小学教师素质大赛一等奖。', '', '<p><span><span><br/></span></span></p><p><span><span></span></span></p><p><a href="images/dd22b721e839470baa28dbb057d43ba9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_dd22b721e839470baa28dbb057d43ba9.jpg" width="300" height="436"/></a></p><p><span>黄婷婷</span><span><span>，</span><span>“一师一优课”省级优课，市中区小学教师素质大赛一等奖。</span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/dd22b721e839470baa28dbb057d43ba9.jpg', NULL, true, '2024-06-05 19:58:00+08', '2024-06-05 19:58:00+08', '2024-06-05 19:58:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293431');
INSERT INTO public.news VALUES (798, '毕业于国内外名校的青年才俊', '', '', '', '<p><img src="/picture/-1/97c1b84a24df488aae5efb6780335a61.png" title="" alt=""/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/picture/-1/97c1b84a24df488aae5efb6780335a61.png', NULL, true, '2024-06-05 19:49:00+08', '2024-06-05 19:49:00+08', '2024-06-05 19:49:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293430');
INSERT INTO public.news VALUES (799, '宋艺奇', '', '宋艺奇，西南大学优秀毕业研究生，国家二级心理咨询师，济南市优秀教育案例一等奖。', '', '<p><span><br/></span></p><p><span></span></p><p><a href="images/109a108490af41ec94a54d3aae39b0c3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_109a108490af41ec94a54d3aae39b0c3.jpg" width="300" height="428"/></a></p><p><span>宋艺奇，</span><span>西南大学优秀毕业研究生，国家二级心理咨询师，济南市优秀教育案例一等奖。</span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/109a108490af41ec94a54d3aae39b0c3.jpg', NULL, true, '2024-06-05 19:46:00+08', '2024-06-05 19:46:00+08', '2024-06-05 19:46:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293429');
INSERT INTO public.news VALUES (800, '郝海歌', '', '郝海歌，山东大学优秀毕业生。济南市中小学美术教师基本功展示个人全能奖、教学素养奖、专业素养奖一等奖；济南市中小学教育教学信息化一等奖；全国中小学生绘画书法作品比赛优秀指导教师；新航实验首届十大优秀员工、校先进工作者；十佳青年教师“德育案例”“微班会”单项奖。', '', '<p><span><br/></span></p><p><span></span></p><p><a href="images/ae2d6d4a983b4b508ac1abb99d827e7b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ae2d6d4a983b4b508ac1abb99d827e7b.jpg" width="300" height="450"/></a></p><p><span><span>郝海歌</span><span>，山东大学优秀毕业生。</span>济南市中小学美术教师基本功展示个人全能奖、教学素养奖、专业素养奖一等奖；济南市中小学教育教学信息化一等奖；全国中小学生绘画书法作品比赛优秀指导教师；新航实验首届十大优秀员工、校先进工作者；十佳青年教师“德育案例”“微班会”单项奖。</span></p><p><span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/ae2d6d4a983b4b508ac1abb99d827e7b.jpg', NULL, true, '2024-06-05 19:45:00+08', '2024-06-05 19:45:00+08', '2024-06-05 19:45:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293428');
