INSERT INTO public.news VALUES (826, '李想', '', '李想，聊城市课堂教学“十佳”教师，聊城市教学能手，NOIP优秀辅导教师，全国小学信息技术优质课二等奖。', '', '<p><span><span><a href="images/4af39a1292db4dd9b0e947289d162364.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4af39a1292db4dd9b0e947289d162364.jpg" width="300" height="428"/></a></span></span></p><p><span><span>李想，</span><span>聊城市课堂教学“十佳”教师，聊城市教学能手，NOIP优秀辅导教师，全国小学信息技术优质课二等奖。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/4af39a1292db4dd9b0e947289d162364.jpg', NULL, true, '2024-06-05 19:07:00+08', '2024-06-05 19:07:00+08', '2024-06-05 19:07:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293402');
INSERT INTO public.news VALUES (827, '刘晓冉', '', '刘晓冉，历史高级教师，省 “一师一优课”一等奖，国家级论文比赛二等奖。', '', '<p><span><span><a href="images/d83e8bbcb22a4f089a85e65b6f5d6dad.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d83e8bbcb22a4f089a85e65b6f5d6dad.jpg" width="300" height="428"/></a></span></span></p><p><span><span>刘晓冉，</span><span>历史高级教师，省 “一师一优课”一等奖，国家级论文比赛二等奖。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/d83e8bbcb22a4f089a85e65b6f5d6dad.jpg', NULL, true, '2024-06-05 19:04:00+08', '2024-06-05 19:04:00+08', '2024-06-05 19:04:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293401');
INSERT INTO public.news VALUES (828, '史钧', '', '史钧，数学高级教师，市中区数学中心组成员，省优质课比赛二等奖，济南大学硕士研究生指导教师。', '', '<p><span><span><a href="images/a782ca43e1df4768a9b4fca6a46d3e38.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a782ca43e1df4768a9b4fca6a46d3e38.jpg" width="167" height="233"/></a></span></span></p><p><span><span>史钧，</span><span>数学高级教师，市中区数学中心组成员，省优质课比赛二等奖，济南大学硕士研究生指导教师。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/a782ca43e1df4768a9b4fca6a46d3e38.jpg', NULL, true, '2024-06-05 18:59:00+08', '2024-06-05 18:59:00+08', '2024-06-05 18:59:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293400');
INSERT INTO public.news VALUES (829, '石峰', '', '石峰，英语高级教师，省优质课一等奖，省教育教学论文一等奖，“一师一优课”省级优课。济南市优秀班主任。四川省高中英语教师优质课展评一等奖；四川省高中英语教育教学论文一等奖；乐山市高中英语教师优质课展评一等奖第一名；济南市高中英语教学论文一等奖；济南市首届高中英语教师口语素质大赛一等奖；乐山市学科指导委员会委员；工作经历：任教13年，6年班主任工作经验。曾在济南外国与学校任教8年，期间担任国际课程AP...', '', '<p><span><a href="images/fae49f285b0545fa9492d8e2faec08cc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fae49f285b0545fa9492d8e2faec08cc.jpg" width="300" height="428"/></a></span></p><p><span>石峰，英语高级教师，省优质课一等奖，省教育教学论文一等奖，“一师一优课”省级优课。济南市优秀班主任。四川省高中英语教师优质课展评一等奖；四川省高中英语教育教学论文一等奖；乐山市高中英语教师优质课展评一等奖第一名；济南市高中英语教学论文一等奖；济南市首届高中英语教师口语素质大赛一等奖；乐山市学科指导委员会委员；工作经历：任教13年，6年班主任工作经验。曾在济南外国与学校任教8年，期间担任国际课程AP方向英语教师兼班主任及备课组长。所带的2011级20班于2014年被评为济南市优秀班集体。2014年加盟四川某私立高中，担任班主任和年级备课组长，所教年级高考理科重本率达到92%，所任教班级英语高考平均分达到132分。辅导学生多次在全国英语类比赛中获得一等奖。</span></p><p><span></span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/fae49f285b0545fa9492d8e2faec08cc.jpg', NULL, true, '2024-06-05 18:51:00+08', '2024-06-05 18:51:00+08', '2024-06-05 18:51:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293399');
