INSERT INTO public.news VALUES (833, '十四而志 挺膺担当 │ 新航实验为初二学生举行青春礼', '', '', '', '<p><img title="96c857a7086d398f1f64e86f45d11e4.png" src="/uploads/migration/images/f51a192001e3451ca350ecb064d0f363.png"/></p><meta name="ContentStart"/>', '', 'campus', '/uploads/migration/images/f51a192001e3451ca350ecb064d0f363.png', NULL, true, '2024-06-05 17:48:00+08', '2024-06-05 17:48:00+08', '2024-06-05 17:48:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293389');
INSERT INTO public.news VALUES (834, '邵丽云', '', '邵丽云，正高二级教师，山东省特级教师, 齐鲁名师。山东省齐鲁名师人选的指导专家，山东省齐鲁名师领航工作室主持人。在山东省实验中学从事高中数学教学四十年，多年担任班主任，教研组长工作。曾获得获全国五一劳动奖章，全国先进工作者称号。获得国务院政府津贴，国家高层次领军人才、国家教学名师称号，2021年被选为教育部基础教育教学指导委员会专家委员。', '', '<p><span><span><a href="images/1b78eff89dde4ac99d0e667433767ff2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1b78eff89dde4ac99d0e667433767ff2.jpg" width="295" height="413"/></a></span></span></p><p><span><span>邵丽云，正高二级教师，山东省特级教师,</span> <span>齐鲁名师。山东省齐鲁名师人选的指导专家，山东省齐鲁名师领航工作室主持人。在山东省实验中学从事高中数学教学四十年，多年担任班主任，教研组长工作。曾获得获全国五一劳动奖章，全国先进工作者称号。获得国务院政府津贴，国家高层次领军人才、国家教学名师称号，2021年被选为教育部基础教育教学指导委员会专家委员。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/1b78eff89dde4ac99d0e667433767ff2.jpg', NULL, true, '2024-06-04 17:36:00+08', '2024-06-04 17:36:00+08', '2024-06-04 17:36:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293388');
INSERT INTO public.news VALUES (835, '臧丽丽', '', '臧丽丽，语文高级教师，市中区优秀教师，市中区最美巾帼教师。 ', '', '<p><a href="images/070acc9b86374624953fa654f7062070.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_070acc9b86374624953fa654f7062070.jpg" width="300" height="436"/></a></p><p><span><span>臧丽丽，</span><span>语文高级教师，市中区优秀教师，市中区最美巾帼教师。&nbsp;</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/070acc9b86374624953fa654f7062070.jpg', NULL, true, '2024-06-04 17:31:00+08', '2024-06-04 17:31:00+08', '2024-06-04 17:31:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293387');
INSERT INTO public.news VALUES (836, '宋现银', '', '宋现银，数学高级教师，省级教学成果二等奖，济南市优秀班主任。', '', '<p><span><a href="images/3432cdb01a0e4869af929458e2058ebb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3432cdb01a0e4869af929458e2058ebb.jpg" width="300" height="428"/></a></span></p><p><span>宋现银，</span><span>数学高级教师，</span><span>省级教学成果二等奖</span><span>，</span><span>济南市优秀班主任</span><span>。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/3432cdb01a0e4869af929458e2058ebb.jpg', NULL, true, '2024-06-04 17:30:00+08', '2024-06-04 17:30:00+08', '2024-06-04 17:30:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293386');
INSERT INTO public.news VALUES (837, '杨海三', '', '杨海三，物理高级教师，2005年毕业于陕西师范大学物理教育学院，拥有16年一线教学工作经验，曾任教于河南省某省级示范性高中，一直从事高中物理教学，担任物理学科备课组长。曾连续13年担任班主任，送过多届高三实验班，其中，杨海三所带的2018届高考学生中，清北过线11人、录取8人，先后被评选为市教学标兵、省教师技能大赛一等奖、河南省教学标兵、市优质课一等奖、师德标兵、高考功勋班主任、物理学科竞赛优秀辅...', '', '<p><span><a href="images/0c97bb1029c94e00be057d7da798759b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0c97bb1029c94e00be057d7da798759b.jpg" width="300" height="436"/></a></span></p><p><span>杨海三，物理高级教师，2005年毕业于陕西师范大学物理教育学院，拥有16年一线教学工作经验，曾任教于河南省某省级示范性高中，一直从事高中物理教学，担任物理学科备课组长。曾连续13年担任班主任，送过多届高三实验班，其中，杨海三所带的2018届高考学生中，清北过线11人、录取8人，先后被评选为市教学标兵、省教师技能大赛一等奖、河南省教学标兵、市优质课一等奖、师德标兵、高考功勋班主任、物理学科竞赛优秀辅导教师等荣誉称号。</span></p><p><span>工作中认真负责，拥有极强的学生管理能力和管理经验，有较强的适应新环境的能力，性格热情开朗，积极向上，具有极强的事业心和上进心，是同学们心目中正能量满满的“阳光教师”。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/0c97bb1029c94e00be057d7da798759b.jpg', NULL, true, '2024-06-04 17:21:00+08', '2024-06-04 17:21:00+08', '2024-06-04 17:21:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293385');
INSERT INTO public.news VALUES (838, '杨翠华', '', ' 杨翠华，语文高级教师。山东省实验中学语文学科主任，并曾担任2016级东校区级部德育主任。山东省优秀班主任、济南市优秀班主任、济南市第二届“名班主任工作室”、济南市及山东省微课比赛一等奖、山东省演讲指导教师一等奖、济南市“中华优秀传统文化”课堂比赛一等奖。多次获语文报杯、叶圣陶杯、文心雕龙杯、创新作文等全国中学生作文大赛指导教师一等奖。从教三十余年来，披星戴月是她勤恳的绿色标签，踏实认真是她朴实的...', '', '<p><a href="images/b70e38e0f1c64e13bbe7c7ffdad03ebf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b70e38e0f1c64e13bbe7c7ffdad03ebf.jpg" width="300" height="428"/></a></p><p><span>&nbsp;杨翠华，语文高级教师。山东省实验中学语文学科主任，并曾担任2016级东校区级部德育主任。山东省优秀班主任、济南市优秀班主任、济南市第二届“名班主任工作室”、济南市及山东省微课比赛一等奖、山东省演讲指导教师一等奖、济南市“中华优秀传统文化”课堂比赛一等奖。多次获语文报杯、叶圣陶杯、文心雕龙杯、创新作文等全国中学生作文大赛指导教师一等奖。</span></p><p><span>从教三十余年来，披星戴月是她勤恳的绿色标签，踏实认真是她朴实的红颜本真。她爱三尺讲台，所以对教学工作，抓实目标是她，抓细落实是她，团结同仁齐心协力创佳绩。她爱徒儿花朵，所以对学生宽严相济，充满包容和厚爱。在多年的教育教学实践中，始终认定“爱”是教育的都一要义，没有爱就没有教育。有真切的师爱，才有强烈的爱岗敬业的扎实行动。杨翠华老师的班级，学生们总能团结友爱，积极向上，全面发展。在新航实验，老师尤其要关注到每个学生强烈被认可的内心需求，要熟知学生的脾性个性，要善于发现每个学生的闪光点，做到每天表扬一个学生。她的教育培根铸魂，她的课堂启智润心，她全心全意共十里芳草，尽心尽力求尽职尽责。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/b70e38e0f1c64e13bbe7c7ffdad03ebf.jpg', NULL, true, '2024-06-04 17:19:00+08', '2024-06-04 17:19:00+08', '2024-06-04 17:19:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293384');
INSERT INTO public.news VALUES (889, '扬帆·远航——新航实验初三年级帆船体验研学之旅', '', 'var flashvars={ f:"/media/0/e98ad372414d4f188ca46e3f508f6023.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; var video=["/media/0/e98a...', '', '<section>
 <section>
  <section>
   <section>
    <p><strong><span></span></strong></p>
    <div>
     <div id="mediaContent0_0"></div> 
     <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
     <script type="text/javascript">
    var flashvars={
        f:"/media/0/e98ad372414d4f188ca46e3f508f6023.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/e98ad372414d4f188ca46e3f508f6023.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script>
    </div>
    <p><strong><span></span></strong><br></p>
    <p><strong><span>减</span><span>压赋能</span></strong></p>
   </section>
  </section>
 </section>
</section>
<p><br></p>
<section>
 <section>
  <p><span>“身体和灵魂总要有一个在路上”，带着一份憧憬，带着一份期盼，济南新航实验外国语学校初三学子开启了“运动新偶像，未来航海家”主题研学活动，真正实现让学生在体验中学习、在学习中感悟，为接下来的初三学习减压赋能再出发。</span></p>
  <p><span><a href="images/ada32cb1d77c4dd885ceaddda9cebe7c.jpg" target="_blank"><img title="1.webp.jpg" src="/uploads/migration/images/ada32cb1d77c4dd885ceaddda9cebe7c.jpg"></a></span></p>
  <p><span><span>早在一年多前，中国第一个完成帆船环球航海的女性宋坤就曾来到新航实验与孩子们分享自己的航海故事，也为很多学生埋下了驾驶帆船去航海的梦想种子。一听说研学主题和航海有关，孩子们都激动不已。</span></span></p>
 </section>
</section>
<p><br></p>
<p><a href="images/967b127e7c5e4bc09e4de15794998ff0.jpg" target="_blank"></a><a href="images/f8d4a30181054c49a11ddd14546e1adf.jpg" target="_blank"><img title="1.webp (1).jpg" src="/uploads/migration/images/f8d4a30181054c49a11ddd14546e1adf.jpg"></a><img title="2.webp.jpg" src="/uploads/migration/images/967b127e7c5e4bc09e4de15794998ff0.jpg"></p>
<p><span>雪野湖，我们来了！</span><br></p>
<p><span>在雄壮的国歌声中，五星红旗冉冉升起，小航海家们的一天正式开启。野外救援、陆上赛艇、激情皮划艇、扬帆起航、环游世界……跟随宋坤女士的航海经历，学生们用最短的时间完成环绕世界地图的目标，真实感受了航海人坚持、探索、勇敢的航海精神；大家在合作中学会握桨、划桨、倒桨、加速和转弯，并且进行了一场酣畅淋漓的水上皮划艇大战；智慧的新航实验学子还精心设计了一副美丽的皮划艇创意集体拍，为本次研学留下美好的记忆。</span></p>
<p><a href="images/46463960e4f246f1b3c825a7ffeec6e4.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/46463960e4f246f1b3c825a7ffeec6e4.jpg"></a><a href="images/939ac4077f8b4d30875ba505ef2b1fb6.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/939ac4077f8b4d30875ba505ef2b1fb6.jpg"></a><a href="images/0f18d262712941f28f94127e2e0339c9.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/0f18d262712941f28f94127e2e0339c9.jpg"></a><a href="images/57bc23bb35834c2cae5981fa43397ab9.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/57bc23bb35834c2cae5981fa43397ab9.jpg"></a><a href="images/000e3d22767a45b0a9b192f06f4cc132.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/000e3d22767a45b0a9b192f06f4cc132.jpg"></a><a href="images/cb9c4fee41b9479f9ddc28c3df33f304.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/cb9c4fee41b9479f9ddc28c3df33f304.jpg"></a><a href="images/e3171b394ff845a8bd393d948d28dcc1.jpg" target="_blank"><img title="7.webp.jpg" src="/uploads/migration/images/e3171b394ff845a8bd393d948d28dcc1.jpg"></a><a href="images/b4b57c9ff8f04d23aebc19d38b34ba6e.jpg" target="_blank"><img title="8.webp.jpg" src="/uploads/migration/images/b4b57c9ff8f04d23aebc19d38b34ba6e.jpg"></a></p>
<p><span>“没有扎实的理论基础，就没办法更好地驾驶帆船；没有扎实的理论基础，遇到困难时就无法正确应对。”“帆船有风才能扬帆起航，没有风的时候怎么办？没关系，没有风的时候等风来。”“原来测风向、察水流、观天文、识地理、打绳结都是我不曾体会过的新鲜有趣”……每个环节都可以带来不同的启发，孩子们也在无形中获得了很多书本上无法获得的知识。</span></p>
<p><a href="images/aff8c744bfed42149280798b8e7ee5a4.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/aff8c744bfed42149280798b8e7ee5a4.jpg"></a><a href="images/f16ba47e87be4fb6b36646af5d0d5f99.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/f16ba47e87be4fb6b36646af5d0d5f99.jpg"></a></p>
<p><span>在轻松愉快的氛围中，一天的帆船之旅结束，</span><span>无论竞技的结</span><span>果如何，孩子们满载而归</span><span>。</span><span>此次研学活动是同学们与自己的遇见，遇见阳光开朗的</span><span>性格</span><span>，</span><span>遇见团队合作的意识，遇</span><span>见战</span><span>胜自己的勇气</span><span>，遇见冒险意识</span><span>和探索精神</span><span>。</span><span>本次研学也是“双减”政策下，新航实验丰富课程形式，让快乐回归校园的真实举措之一。相信同学们经过此次的蓄能放松之旅，定能乘风破浪，</span><span>朝着梦想，扬帆起航！</span></p>
<p><span><a href="images/474be9acb37b47f3ba72025906de071e.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/474be9acb37b47f3ba72025906de071e.jpg"></a></span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/ada32cb1d77c4dd885ceaddda9cebe7c.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (839, '王茜', '', '王茜，语文高级教师，中考命题专家，省优质课一等奖，市初中语文学科中心组成员。', '', '<p><span><span><br/></span></span></p><p><span><span><a href="images/01eac56204234a26888cfdb7775fc440.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_01eac56204234a26888cfdb7775fc440.jpg" width="300" height="436"/></a></span></span></p><p><span><span>王茜，</span><span>语文高级教师，中考命题专家，省优质课一等奖，市初中语文学科中心组成员。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/01eac56204234a26888cfdb7775fc440.jpg', NULL, true, '2024-06-04 17:18:00+08', '2024-06-04 17:18:00+08', '2024-06-04 17:18:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293383');
INSERT INTO public.news VALUES (840, '冯庆田', '', '冯庆田，全国中小学数学建模优质课、录像课一等奖，天桥区优秀德育工作者 。', '', '<p><span><a href="images/247ccf4f75804f3b82a1e12049fac1ee.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_247ccf4f75804f3b82a1e12049fac1ee.jpg" width="300" height="436"/></a></span></p><p><span><span>冯庆田，</span><span>全国中小学数学建模优质课、录像课一等奖，天桥区优秀德育工作者</span> <span>。</span></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/247ccf4f75804f3b82a1e12049fac1ee.jpg', NULL, true, '2024-06-04 17:13:00+08', '2024-06-04 17:13:00+08', '2024-06-04 17:13:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293382');
INSERT INTO public.news VALUES (841, '邹胜', '', '邹胜，副校长、小学部校长,中学高级教师、全国家庭教育指导师、国家三级心理咨询师、儿童及成人情商训练推行者。先后荣获全国德育科研先进工作者、山东省小学思想品德学科教研教学先进工作者、山东省新长征突击手、威海市优秀教师、教学能手、优秀校长等各领域荣誉称号。', '', '<p><a href="images/b475c219a36549fa8362065259dc58b3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b475c219a36549fa8362065259dc58b3.jpg" width="300" height="436"/></a></p><p><span>邹胜，副校长、小学部校长,中学高级教师、全国家庭教育指导师、国家三级心理咨询师、儿童及成人情商训练推行者。先后荣获全国德育科研先进工作者、山东省小学思想品德学科教研教学先进工作者、山东省新长征突击手、威海市优秀教师、教学能手、优秀校长等各领域荣誉称号。<br/></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/b475c219a36549fa8362065259dc58b3.jpg', NULL, true, '2024-06-04 16:12:00+08', '2024-06-04 16:12:00+08', '2024-06-04 16:12:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293381');
INSERT INTO public.news VALUES (842, '2024各学部教育咨询群正式开放', '', '你想了解新航实验的教育特色吗？你想了解新航实验的校园生活吗？你想近距离感受新航学子风采吗？加入教育咨询QQ群吧！这里有最准确的解答！我们在新航实验等你！', '', '<p><a href="images/4094cb5d26854873911a970818a7fcf9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4094cb5d26854873911a970818a7fcf9.jpg" width="500" height="244"/></a></p><p><a href="images/207afddd3368436fa9fad78d298c848c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_207afddd3368436fa9fad78d298c848c.jpg" width="500" height="244"/></a></p><p><a href="images/891aeda8212149128e31a6da235e0efa.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_891aeda8212149128e31a6da235e0efa.jpg" width="500" height="244"/></a></p><p><a href="images/64506999095443acbd07432cbf677283.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_64506999095443acbd07432cbf677283.jpg" width="500" height="244"/></a></p><p><span>你想了解新航实验的教育特色吗？</span></p><p><span>你想了解新航实验的校园生活吗？</span></p><p><span>你想近距离感受新航学子风采吗？</span></p><p><span>加入教育咨询QQ群吧！</span></p><p><span>这里有最准确的解答！</span></p><p><span>我们在新航实验等你！</span></p><p><br/></p><meta name="ContentEnd"/>', '', 'other', '/uploads/migration/images/4094cb5d26854873911a970818a7fcf9.jpg', NULL, true, '2024-06-04 01:46:00+08', '2024-06-04 01:46:00+08', '2024-06-04 01:46:00+08', '', '', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293379');
INSERT INTO public.news VALUES (843, '济南新航实验外国语学校2024年艺体特长生招生简章', '', '济南新航实验外国语学校隶属于山东省实验中学教育集团，不仅是一所涵盖小学、初中、高中为一体的十二年一贯制学校，更是一个深度链接学生、教师、家长的温馨家园。自2019年建校以来，新航实验持续践行“让每一个生命都精彩绽放”理念，实行全学段小班，贯彻导师制和个性化辅导结合的精致教学，引领学生在丰富多彩的课程和张弛有度的环境中拓宽视野、发掘潜能、追求卓越，为学生提供顶尖资源支持。学校艺体课程丰富、师资配备齐...', '', '<section><p><a href="images/e30d68155bc447cd9e34aabc5b59e3b4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e30d68155bc447cd9e34aabc5b59e3b4.jpg" width="800" height="450"/></a></p><p>济南新航实验外国语学校隶属于山东省实验中学教育集团，不仅是一所涵盖小学、初中、高中为一体的十二年一贯制学校，更是一个深度链接学生、教师、家长的温馨家园。</p><p>自2019年建校以来，新航实验持续践行“让每一个生命都精彩绽放”理念，实行全学段小班，贯彻导师制和个性化辅导结合的精致教学，引领学生在丰富多彩的课程和张弛有度的环境中拓宽视野、发掘潜能、追求卓越，为学生提供顶尖资源支持。学校艺体课程丰富、师资配备齐全、场馆设施先进，持续为社会输送了大批优秀毕业生。</p><p>根据《2024年济南市普通高中学校招收艺体特长生工作方案》和济南市2024年高中阶段学校招生工作意见，经研究决定，2024年我校将招收艺体特长生。</p></section><p><section><section><section><section><section><p><strong><span>一、招生计划</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>根据我校实际，报济南市教育局批准，我校2024年面向全市（不含莱芜、钢城）共招收艺体特长生19人，分音乐和体育两大类，具体专业及人数如下：</p></section><section><section><p><a href="images/aff87770ec024491a4e829683e31b51e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_aff87770ec024491a4e829683e31b51e.jpg" width="600" height="529"/></a></p></section></section><section><section><section><section><section><p><strong><span>二、报考条件</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>（一）基本要求</p><p>初中综合素质评价总评等级、生物、地理学科学业水平考试成绩均须达到D 级（含）以上等级，信息技术、综合实验操作、音乐、美术、综合实践均须达到“合格”且有体育或艺术特长的应届初中毕业生。</p><p>（二）专业要求</p><p>1.音乐：在初中阶段参加国家及省、市、区县教育主管部门举办的艺术比赛中取得优异成绩或具有同等艺术水平的应届初中毕业生（提供有效获奖证书），且有一定演出经验（提供演出现场照片），男女不限。接受过系统的专业训练，熟练并独立演奏有一定难度的曲目，有很好的专业技术与表现能力，且有较熟练地视奏能力。</p><p>备注：所有项目择优录取，考生可兼报测试项目中的两项。</p><p>2.游泳：初中阶段在教育或体育主管部门举办的比赛中获得市级以上（含市级）游泳比赛单项前三名（提供有效证书）或成绩达到国家二级运动员及以上标准，或有发展潜力的优秀学生。至少掌握两种以上泳姿。</p><p>3.击剑：初中阶段获得省以上级别比赛个人前三十二名或团体前八名或初中阶段获得市级击剑比赛个人前十六名运动员或有潜力的优秀学生。</p><p>4.乒乓球：初中阶段在教育或体育主管部门组织并获得市赛团体/单项前六名，或者省赛团体/单项前八名，或者全国比赛团体/单项前十六名的学生或有潜力的优秀学生。</p></section><section><section><section><section><section><p><strong><span>三、</span></strong><strong><span>报名和专业测试</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>（一）报名及资格审查&nbsp; &nbsp;</p><p>2024年我校特长生招生全部实行现场报名，专业老师将会对各位同学携带的报名材料进行审核，审核合格予以报名、发放准考证。</p><p>1.报名时间：6月16日、6月17日每天8:30-17:00</p><p>2.报名地点：济南新航实验外国语学校图书馆三楼</p><p>3.报名材料：</p><p>（1）居民身份证等有效身份证件</p><p>（2）相关等级证书、获奖证书、演出视频或节目单等证明材料（报名时以上材料需携带原件及复印件一份）</p><p>（3）1寸彩色近期免冠照片3张。&nbsp;</p><p>（二）专业测试内容及标准&nbsp;&nbsp;&nbsp;</p><p>1.器乐</p><p>（1）音乐素养测试：</p><p>视奏：视奏乐谱</p><p>听音模唱：单音，音程</p><p>（2）自备作品展示2分钟内</p><p>①自带乐器独奏，不能用音频、视频或钢琴等其他任何乐器现场伴奏。</p><p>②考生提供自选曲目的乐谱一式三份。</p><p>③在测试中评委有权打断考生的表演，并指定考生表演作品或剧目中的任意一个段落或部分。</p><p>④现场报名上交获奖证书或演出照片与现场测试乐器要一致，否则取消测试资格。</p><p>2.体育</p><p>（1）游泳：</p><p>100m专项测试（蝶/仰/蛙/自，四选一，包含跳出发，转身）。</p><p>考试采用一次性决赛，使用手计时计取成绩，参照评分标准换算成得分(比赛成绩占比90%，技术评定占比10%)。手计时每道两名计时员计取成绩，取相同值或中间值为最终成绩。</p><p>备注：自带泳衣、泳镜、泳帽等必需用品。</p><p>（2）击剑：</p><p>体能：立定跳远、单摇跳绳</p><p>专项技术：弓步技术、攻防技术、实战</p><p>（3）乒乓球：学生根据报名顺序进行排号，一个大组进行单打循环赛，五局三胜制。</p></section><section><section><section><section><section><p><strong><span>四、</span></strong><strong><span>专业测试时间、地点</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>（一）测试时间：6月27日上午</p><p>（二）测试地点：</p><p>游泳-游泳馆</p><p>击剑-体育馆二楼</p><p>乒乓球-体育馆二楼</p><p>器乐-黑匣子剧场&nbsp;&nbsp;</p><p>请考生携带居民身份证、准考证、专业测试所需物品8:30前到济南新航实验外国语学校体育馆集合，按项目进行排队。</p></section><section><section><section><section><section><p><strong><span>五、</span></strong><strong><span>专业测试合格名单公示</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>专业测试合格人数按不超过特长生招生计划数的1.5倍确定，测试合格考生名单经市教育局审批，通过学校网站公示三天后发放合格证。</p></section><section><section><section><section><section><p><strong><span>六、录取条件</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>取得我校专业测试合格证的考生，录取时按照非推荐生试点校政策，艺术类考生初中学业水平考试成绩达到济南市普通高中志愿填报资格线下30分（含）以上；体育类考生初中学业水平考试成绩达到济南市普通高中志愿填报资格线下50分（含）以上。同时必须满足初中综合素质评价总评等级、生物、地理、道德与法治、历史学科学业水平考试成绩均须达到D级（含）以上等级，信息技术、综合实验操作、音乐、美术、综合实践均须达到“合格”。在专业测试合格的人员中，严格按照考生成绩和录取人数，从高分到低分择优录取。</p></section><section><section><section><section><section><p><strong><span>七、特别声明</span></strong></p></section></section></section><section><section></section></section></section></section><section><p>（一）根据《2024年济南市普通高中学校招收艺体特长生工作方案》要求，若招生项目出现空缺或该项目考生专业测试成绩未达到学校招生最低标准，经学校招生工作小组研究，将该项目招生计划进行调整或缩减招生计划。</p><p>（二）凡经我校录取的艺体特长生，入校后须代表学校参加有关比赛活动。</p><p>（三）我校艺体特长生招生，不委托任何机构举办考前专业辅导班。</p><p>招生咨询电话：0531-59516633</p><p>音乐：闫老师15069091739</p><p>游泳：乔老师 18221056015</p><p>击剑：高老师18660397397</p><p>乒乓球：刘老师15552578920</p><p>咨询时间：工作日上午8:00-11:30，下午14:00-17:00</p><p>学校地址：济南市历城区经十东路27803号</p><p>学校网站：/</p><p><span></span></p><p>山东省实验中学教育集团</p><p>济南新航实验外国语学校</p><p>2024年5月</p></section></p><p><br/></p><meta name="ContentEnd"/>', '', 'other', '/uploads/migration/images/e30d68155bc447cd9e34aabc5b59e3b4.jpg', NULL, true, '2024-06-03 23:44:00+08', '2024-06-03 23:44:00+08', '2024-06-03 23:44:00+08', '', '', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293380');
INSERT INTO public.news VALUES (844, '记忆达人，一站到底！——国际部Spelling Bee拼词挑战赛高燃来袭', '', '', '', '<p><a href="images/1c70a502d5e2421aa8d4b6c7a431b42b.jpg" target="_blank"><img title="6fdadef8c9cba210f27f193286af093.jpg" src="/uploads/migration/images/s_1c70a502d5e2421aa8d4b6c7a431b42b.jpg"/></a></p><p><br/></p><meta name="ContentStart"/>', '', 'activities', '/uploads/migration/images//1c70a502d5e2421aa8d4b6c7a431b42b.jpg', NULL, true, '2023-03-17 00:09:00+08', '2023-03-17 00:09:00+08', '2023-03-17 00:09:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293353');
INSERT INTO public.news VALUES (845, '为地球种“亿”棵树，最美的地球你“植”得拥有——新航实验高中部举行植树节劳动实践活动', '', '', '', '<p><a href="images/eba42c956ae84c9f8f2724d110905804.jpg" target="_blank"><img title="33b55a3354810f28e98331fa160923d.jpg" src="/uploads/migration/images/s_eba42c956ae84c9f8f2724d110905804.jpg" width="573" height="13933"/></a></p><p><br/></p><meta name="ContentStart"/>', '', 'activities', '/uploads/migration/images/eba42c956ae84c9f8f2724d110905804.jpg', NULL, true, '2023-03-16 23:48:00+08', '2023-03-16 23:48:00+08', '2023-03-16 23:48:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293352');
INSERT INTO public.news VALUES (854, '唯美十月，小航带你走进秋意正浓处……', '', '金秋的阳光，洒在树叶上，洒在花瓣上，也洒在我们的心上。秋风的脚步带来了秋天的故事，在这个富有诗意的季节，新航实验小学部三年级语文组“你好，秋天”单元主题学习活动正如火如荼地进行着！课内，孩子们跟随老师走进诗人和作家文字中的秋风、秋叶、秋雨；课余，流连自然，用心捕捉平时没有注意到的秋日特有的景色，全方位感受秋日情韵。一枚红叶，美了秋韵；一眼金黄，丰了秋实；一滴秋露，盈了秋菊……正当秋意渐浓时，我们一...', '', '<p><span><span>金秋的阳光，洒在树叶上，洒在花瓣上，也洒在我们的心上。秋风的脚步带来了秋天的故事，在这个富有诗意的季节，新航实验小学部三年级语文组</span><span>“你好，秋天”单元主题学习活动正如火如荼地进行着！</span></span></p><p><span><span><a href="images/3ee7911693b743088a8b755a1f628cd2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3ee7911693b743088a8b755a1f628cd2.jpg" width="600" height="525" alt=""/></a></span></span></p><p><span>课内，孩子们跟随老师走进诗人和作家文字中的秋风、秋叶、秋雨；课余，流连自然，用心捕捉平时没有注意到的秋日特有的景色，全方位感受秋日情韵。</span></p><p><span><a href="images/776827dab85e4279af6998115143a286.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_776827dab85e4279af6998115143a286.jpg" width="600" height="450" alt=""/></a></span></p><p><span><span>一枚红叶，美了秋韵；一眼金黄，丰了秋实；一滴秋露，盈了秋菊</span><span>……正当秋意渐浓时，我们一起找秋天吧！寻一枚染黄的秋叶，觅一片尚青的竹林，赏一丛怒放的秋菊，尝一枚酸甜的秋果，秋在小航们的心中变得可爱又灵动。<a href="images/50209b6e53f84da895e43f9c9505321a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_50209b6e53f84da895e43f9c9505321a.jpg" width="600" height="800"/></a></span></span></p><p><span>叶子落在地上，是树对大自然的回馈。如果用它们来作画，又会有怎样的惊喜呢？孩子们用拾起的叶子拼接画作，变成他们想要的样子；用细腻的笔触记下所见所感，秋叶在他们笔尖跳舞！</span></p><p><span></span></p><p><a href="images/a3293d530525487dae0f747731f1245c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a3293d530525487dae0f747731f1245c.jpg" width="300" height="224" alt=""/></a>&nbsp;&nbsp;<a href="images/ecec2d841c664a5b9a90eda8553a1239.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ecec2d841c664a5b9a90eda8553a1239.jpg" width="300" height="224" alt=""/></a>&nbsp;&nbsp;<a href="images/d37615e7773f4fb098dc08eee134edb2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d37615e7773f4fb098dc08eee134edb2.jpg" width="300" height="224" alt=""/></a>&nbsp;&nbsp;<a href="images/ef6e9937791c4c2189f0448d51c2e3c9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef6e9937791c4c2189f0448d51c2e3c9.jpg" width="300" height="299" alt=""/></a><a href="images/741ec18879974a8fbff5babb36f098aa.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_741ec18879974a8fbff5babb36f098aa.jpg" width="300" height="224" alt=""/></a>&nbsp;&nbsp;<a href="images/05d7b44900d64790a4713f35c6426a82.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_05d7b44900d64790a4713f35c6426a82.jpg" width="300" height="217" alt=""/></a>&nbsp;&nbsp;<a href="images/808347b16645438ebe5801b0f7d328de.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_808347b16645438ebe5801b0f7d328de.jpg" width="300" height="224" alt=""/></a>&nbsp;&nbsp;<a href="images/eb2fd2142c144054a8027b9b9ae5752b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_eb2fd2142c144054a8027b9b9ae5752b.jpg" width="300" height="224" alt=""/></a></p><p><br/></p><p><span><span>秋叶、秋花、秋实，美得让人心动，秋天的美是可以入诗的：</span><span>“停车坐爱枫林晚，霜叶红于二月花”“荷尽已无擎雨盖，菊残犹有傲霜枝。一年好景君须记，最是橙黄橘绿时。”孩子们在行文静书中感受诗人的洒脱与傲骨。</span></span></p><p><span><span></span></span></p><p><a href="images/798847221623426183aa03e63baf825b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_798847221623426183aa03e63baf825b.jpg" width="400" height="300"/></a>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<a href="images/b7d698643bd04ea5b6ff022567942fd8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b7d698643bd04ea5b6ff022567942fd8.jpg" width="400" height="400"/></a></p><p><span>秋天以其独特的自然景观，激发着诗人不同的情思，千古文人为秋色赋词吟咏，也引发着小读者的共鸣。小航们在古诗中穿越千年，与诗情画意偶遇。&nbsp;</span></p><p><span></span></p><p><a href="images/3bfa40a1f4c1485b96e4f8f9ffe32c0f.png" target="_blank"><img title="" src="/uploads/migration/images/s_3bfa40a1f4c1485b96e4f8f9ffe32c0f.png" width="350" height="453" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/2b1e86762be94aa18a7ebfffea8a3a1a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2b1e86762be94aa18a7ebfffea8a3a1a.jpg" width="350" height="467" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/7c69120843534ecea490ea064268203f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7c69120843534ecea490ea064268203f.jpg" width="350" height="467" alt=""/></a></p><p><span>语文源自生活，生活孕育语文。三年级语文组聚焦第二单元</span><span>“金色的秋天”，创设“大情境”，开拓“大视野”，让语文学习在实践中彰显出独特的魅力。基于文本的解读，结合生活的体验，超越自我的感受，个体与文本融合，自我与生活对接，完成了学生主体心中新认知的构建，体现出语文课堂的无穷魅力。</span><br/></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//3ee7911693b743088a8b755a1f628cd2.jpg', NULL, true, '2022-10-28 18:18:00+08', '2022-10-28 18:18:00+08', '2022-10-28 18:18:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '293292');
INSERT INTO public.news VALUES (846, '暖心护“航”，爱与责任的不断延伸——新航实验小学部云端家访活动纪实', '', '云端家访，不仅仅是用眼睛去看，更是用心灵去倾听。在一次次心灵的碰撞中，让思维火花更加绚烂绽放，让教育更具内涵，更见温情和深度。为保障线上教育教学质量，给予小航们最“直观”的爱和陪伴，新航实验小学部老师们带着对孩子们的想念和关心，通过微信语音、视频通话、打电话、留言互动等方式，进行了一对一全员家访。伴着清脆的铃声，可爱又熟悉的笑脸出现在屏幕前，当视频接通那一刻，孩子们无比激动与兴奋，热情地和老师打招...', '', '<p>云端家访，</p><p>不仅仅是用眼睛去看，</p><p>更是用心灵去倾听。</p><p>在一次次心灵的碰撞中，</p><p>让思维火花更加绚烂绽放，</p><p>让教育更具内涵，</p><p>更见温情和深度。</p><p><span>为保障线上教育教学质量，给予小航们最“直观”的爱和陪伴，新航实验小学部老师们带着对孩子们的想念和关心，通过微信语音、视频通话、打电话、留言互动等方式，进行了一对一全员家访。</span></p><p><span><a href="images/6a38d7fe1e1e4a8bb9a011f51063339e.png" target="_blank"><img title="1.png" src="/uploads/migration/images/s_6a38d7fe1e1e4a8bb9a011f51063339e.png" width="477" height="977"/></a><a href="images/350ea9d4e8d249daa915c82127d6e752.png" target="_blank"><img title="1.1.png" src="/uploads/migration/images/s_350ea9d4e8d249daa915c82127d6e752.png" width="467" height="977"/></a></span></p><p><span><a href="images/a7d340ec12124549bbab0470dc87b462.png" target="_blank"><img title="2.png" src="/uploads/migration/images/s_a7d340ec12124549bbab0470dc87b462.png" width="468" height="1276"/></a><a href="images/1881af67b38643ffbf734c7e90d73713.png" target="_blank"><img title="2.2.png" src="/uploads/migration/images/s_1881af67b38643ffbf734c7e90d73713.png" width="488" height="1274"/></a></span></p><p><span>伴着清脆的铃声，可爱又熟悉的笑脸出现在屏幕前，当视频接通那一刻，孩子们无比激动与兴奋，热情地和老师打招呼。家访中，老师们深入了解小航两周来居家学习的情况，帮助家长分析孩子线上学习现状；分享科学的学习方法和策略，教给孩子们如何自我管理的小方法；诚恳地倾听家长的需求、困难以及对线上教学的建议，协助家长帮孩子养成良好的学习生活习惯，同时巧妙地帮助学生与家长化解矛盾，彼此解开心结。学科老师、搭班教师、生活老师齐上阵，一个个“幸福锦囊”载满了老师们的关爱，传递到孩子和家长的心中，让线上学习更安心，更温暖。</span></p><p><span><a href="images/03c05614b9bc40f280df0c1d0395ba6a.png" target="_blank"><img title="3.1.png" src="/uploads/migration/images/s_03c05614b9bc40f280df0c1d0395ba6a.png" width="482" height="1081"/></a><a href="images/68e3d91f314e421f9e406df2ffe89c52.jpg" target="_blank"><img title="4.1.jpg" src="/uploads/migration/images/s_68e3d91f314e421f9e406df2ffe89c52.jpg" width="518" height="1080"/></a><a href="images/59d47d850d5940359b7aeb698903c890.png" target="_blank"><img title="3.png" src="/uploads/migration/images/s_59d47d850d5940359b7aeb698903c890.png" width="509" height="1193"/></a></span></p><p><br/></p><p><span>交流中，家长们耐心陪伴孩子身边，认真聆听，用心互动。不少家长在积极配合老师家访工作的同时，也对老师的线上教学工作表示了高度的肯定与感谢。一声声感谢，一份份感动，严峻的疫情打不乱教学的步伐，冰冷的屏幕隔不断家校间温情的流露.</span></p><p><span><a href="images/a1467fcf304a450c9276903e2b97a86c.png" target="_blank"><img title="5.png" src="/uploads/migration/images/s_a1467fcf304a450c9276903e2b97a86c.png" width="425" height="919"/></a><a href="images/740a41e6c8684e749c03dc4c4d882ef2.png" target="_blank"></a><a href="images/68bfc6dd8d714464bcae61931f2df545.jpg" target="_blank"><img title="5.1.jpg" src="/uploads/migration/images/s_68bfc6dd8d714464bcae61931f2df545.jpg" width="606" height="917"/></a><a href="images/77eac4f6d5a3479b89b009b5df233f8d.png" target="_blank"><img title="6.png" src="/uploads/migration/images/s_77eac4f6d5a3479b89b009b5df233f8d.png" width="475" height="1030"/></a><a href="images/da94c0993be14ea39c4c336f3d97b4da.jpg" target="_blank"><img title="6.1.jpg" src="/uploads/migration/images/s_da94c0993be14ea39c4c336f3d97b4da.jpg" width="609" height="1034"/></a></span></p><p><span>家访是心的呼唤，情的交流，更是爱的传递。行动中、话语间、眼神里，家长看到的是一份责任，一种关爱，一个期待。尽管疫情阻隔了师生的空间距离，但暖心的线上家访却拉近了彼此间心灵的距离，增进了家校之间的了解和信任，进一步形成教育合力，为孩子们顺利度过线上学习打下了良好基础。</span><br/></p><p><span><br/></span></p><p><span></span></p><p><span>供稿：小学部&nbsp; &nbsp; 编辑：郝楠楠</span></p><p><span>&nbsp; &nbsp;&nbsp;审核：张 鹏&nbsp; &nbsp; &nbsp; 核发：邹 胜&nbsp;</span></p><p><span><br/></span><br/></p><p><span><br/></span></p><p><span><br/></span></p><meta name="ContentStart"/>', '', 'moral_education', '/uploads/migration/images//6a38d7fe1e1e4a8bb9a011f51063339e.png', NULL, true, '2023-02-28 19:41:00+08', '2023-02-28 19:41:00+08', '2023-02-28 19:41:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293334');
INSERT INTO public.news VALUES (847, '疫情留校很枯燥？不存在！新航实验带你玩转不一样的留校生活！', '', '被疫情“偷走”的休息日，新航实验初中部的学生们没有按照原计划回家，而是自愿选择留在学校，为防疫工作尽自己的一份力。然而，疫情虽封住了我们的脚步，却笼罩不了校园里的欢乐气氛，这不，初中部的一场自由开放活动已经拉开了大幕！晨色来临，夹杂着淡淡薄雾，浅浅的太阳光躲在了云层里。孩子们从教室出发，纷纷前往各个开放场馆，每个场地早已有老师在等候着他们。温馨书吧和图书馆，安静的空间可以满足所有遨游书海的需求；黑...', '', '<p>被疫情“偷走”的休息日，新航实验初中部的学生们没有按照原计划回家，而是自愿选择留在学校，为防疫工作尽自己的一份力。然而，疫情虽封住了我们的脚步，却笼罩不了校园里的欢乐气氛，这不，初中部的一场自由开放活动已经拉开了大幕！</p><p><a href="images/c982f836d1d74f9e9246dd1068ff91b9.png" target="_blank"><img title="1.png" src="/uploads/migration/images/s_c982f836d1d74f9e9246dd1068ff91b9.png"/></a></p><p><a href="images/a550c977c99043f98da85c1b63f3204b.png" target="_blank"><img title="2.png" src="/uploads/migration/images/s_a550c977c99043f98da85c1b63f3204b.png"/></a></p><p>晨色来临，夹杂着淡淡薄雾，浅浅的太阳光躲在了云层里。孩子们从教室出发，纷纷前往各个开放场馆，每个场地早已有老师在等候着他们。温馨书吧和图书馆，安静的空间可以满足所有遨游书海的需求；黑匣子里，超大屏幕带来独特的观影体验；舒适的大剧院，万众瞩目的世界杯开幕式已经就绪；室内体育馆，排球、羽毛球、乒乓球、篮球、游泳，各大“赛事”热火朝天；还有琴房、画室、舞蹈室，多才多艺的新航学子正在尽情绽放……</p><p><a href="images/22903c4b70a844c1bf3559ca75b5971e.png" target="_blank"><img title="3.png" src="/uploads/migration/images/s_22903c4b70a844c1bf3559ca75b5971e.png"/></a></p><p><a href="images/140090707eef41ecb34f2c190b473804.png" target="_blank"><img title="4.png" src="/uploads/migration/images/s_140090707eef41ecb34f2c190b473804.png"/></a></p><p><a href="images/2137a648f62545258a4c4494fb287c93.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/s_2137a648f62545258a4c4494fb287c93.jpg"/></a></p><p><a href="images/d589fbbcd50041a9b3fdbf7e3b7fadd0.png" target="_blank"><img title="6.png" src="/uploads/migration/images/s_d589fbbcd50041a9b3fdbf7e3b7fadd0.png"/></a></p><p><a href="images/7439891acbdf4be7802b7034911e2e76.png" target="_blank"><img title="7.png" src="/uploads/migration/images/s_7439891acbdf4be7802b7034911e2e76.png"/></a></p><p>在这寻常又不寻常的日子里，初中部同学们尽享美好校园生活，用心去感受生活、用心去理解生活，用重获的生机与活力投入到这不平常的日子里，继续迸发着属于自己的青春光芒。</p><p><br/></p><p>供稿：初中部宣传组&nbsp; &nbsp; 编辑：郝楠楠</p><p>审核：张 鹏&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 核发：李正华&nbsp;&nbsp;</p><p><br/></p><meta name="ContentStart"/>', '', 'research', '/uploads/migration/images//c982f836d1d74f9e9246dd1068ff91b9.png', NULL, true, '2023-02-27 19:16:00+08', '2023-02-27 19:16:00+08', '2023-02-27 19:16:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293333');
INSERT INTO public.news VALUES (848, '一课一备、一问题一备，走心的英语教研，新航实验这样做！', '', '教学质量是学校办学的生命线，高效的课堂是学生成长的保障。为了进一步落实立德树人的根本任务，提升教师的备课、讲课、研课、析课、评课能力，形成独具新航实验特色的教学模式，高中英语组以集体教研活动为载体，积极展开探索与实践。每周五下午，掣鲸楼二楼的集体备课间总能看到高中英语组老师们热烈讨论的身影，大家围坐在一起，对近期的教学工作和将要展开的教学任务进行细致的研讨。每次研讨会，主讲人都会提出在课堂教学实践...', '', '<p>教学质量是学校办学的生命线，高效的课堂是学生成长的保障。为了进一步落实立德树人的根本任务，提升教师的备课、讲课、研课、析课、评课能力，形成独具新航实验特色的教学模式，高中英语组以集体教研活动为载体，积极展开探索与实践。</p><p><a href="images/10f20ec6bd974ea8a580a4a617a751e1.png" target="_blank"><img title="微信图片_20230224104959.png" src="/uploads/migration/images/s_10f20ec6bd974ea8a580a4a617a751e1.png"/></a></p><p><a href="images/726fca9c2c4546c4a027daf7616a289d.jpg" target="_blank"><img title="微信图片_20230224105005.jpg" src="/uploads/migration/images/s_726fca9c2c4546c4a027daf7616a289d.jpg"/></a></p><p>每周五下午，掣鲸楼二楼的集体备课间总能看到高中英语组老师们热烈讨论的身影，大家围坐在一起，对近期的教学工作和将要展开的教学任务进行细致的研讨。每次研讨会，主讲人都会提出在课堂教学实践中出现的具体问题，大家一起头脑风暴，讨论可能的突破方式与解决方案。之后的一周，主讲人便带着这些建议去设计课程，并通过公开授课不断进行课程调整，以达到彻底解决问题的目的。</p><p><a href="images/cb299f1629c2442d8bff79c34dfb42d9.jpg" target="_blank"><img title="微信图片_20230224105013.jpg" src="/uploads/migration/images/s_cb299f1629c2442d8bff79c34dfb42d9.jpg"/></a></p><p><a href="images/08dfcbf269c84b04b478d730385d5cb9.jpg" target="_blank"><img title="微信图片_20230224105019.jpg" src="/uploads/migration/images/s_08dfcbf269c84b04b478d730385d5cb9.jpg"/></a></p><p><a href="images/c27dc1fa41a34395b0b83c0f21530c8e.jpg" target="_blank"><img title="微信图片_20230224105026.jpg" src="/uploads/migration/images/s_c27dc1fa41a34395b0b83c0f21530c8e.jpg"/></a></p><section><p>“长篇阅读文章的处理与提炼”便是大家最近在探讨的问题。长篇阅读的难点在于文章篇幅长、信息和词汇量大等，如何做到在一节课的时间里，既让学生对文章有整体把控，又能够作出深入理解呢？针对此问题，高二备课组集思广益，大胆设计，结合日常教学实践，不断思考、调整教学思路，形成了处理长篇文章的理想教学模式，并将在接下来的授课中进行实践和调整。</p><div><p><a href="images/398e962d3e6549188c33759775ac5f1b.jpg" target="_blank"><img title="微信图片_20230224105031.jpg" src="/uploads/migration/images/s_398e962d3e6549188c33759775ac5f1b.jpg"/></a></p></div></section><p>教而不研则浅，研而不教则空。教研，是智慧与创新的碰撞，是理论与实践的磨合，是提升与历练的再现。新航实验高中部英语组一直坚持“切忌空泛、研之有悟”的教研理念，“一课一备”“一问题一备”，相信经过我们的不断探索、实践，在追寻高效课堂的途中，定会看到更加美丽的教育风景，享受到更有意义的教育幸福！&nbsp;</p><p><br/></p><p>供稿：高中部英语组&nbsp; &nbsp; 编辑：郝楠楠</p><p>审核：张 鹏&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp; 核发：吕秀亭</p><p><br/><br/></p><meta name="ContentStart"/>', '', 'research', '/uploads/migration/images//10f20ec6bd974ea8a580a4a617a751e1.png', NULL, true, '2023-02-24 19:27:00+08', '2023-02-24 19:27:00+08', '2023-02-24 19:27:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293332');
INSERT INTO public.news VALUES (849, '学英语还在埋头背语法？快来看新航小学生的妙招！意趣+情境+生活=顺畅表达！', '', '朱熹曾说过：教人未见意趣，必不乐学。英语教学若洋溢美妙意趣，课堂便妙趣横生，学习活动也就越见成效。在意趣英语教学实践中，新航实验小学部始终围绕重意趣、乐表达、融情景、拓视野四个维度，展开生活化、游戏化、活动化的情境式教学，在形式多样的英语教学活动中，学生的语言能力、思维品质和学习能力都在悄悄地提升……    情境教学赋能新课堂什么是语法和规律？对于小学生来说，这些空泛的概念太难理解了。为此，老师们...', '', '<p><span><span>朱熹曾说过：教人未见意趣，必不乐学。英语教学若洋溢美妙意趣，课堂便妙趣横生，学习活动也就越见成效。在意趣英语教学实践中，新航实验小学部始终围绕重意趣、乐表达、融情景、拓视野四个维度，展开生活化、游戏化、活动化的情境式教学，在形式多样的英语教学活动中，学生的语言能力、思维品质和学习能力都在悄悄地提升</span><span>……</span></span></p><p><span>&nbsp; &nbsp; 情境教学赋能新课堂</span></p><p><span>什么是语法和规律？对于小学生来说，这些空泛的概念太难理解了。为此，老师们化繁为简，坚持将教学与交际情景相结合，在交际和学习中帮助学生提升语言能力。</span></p><p><span>在老师们营造的真实情境中，英语语言元素与画面、对话、故事情节等相融合，学生通过沉浸式互动，主动获取各类影音信息，帮助他们从最直观的角度理解所学的知识。</span></p><p><span><span>来看一年级的《</span><span>We can do it！》！老师从两个不同维度，带孩子体验课本剧的魅力，并通过表格统计和小组讨论，培养学生用英文收集信息的能力。</span></span></p><p><span><span></span></span></p><p><a href="images/c6488a5ce0244c1d8979ccdb767cb4a4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c6488a5ce0244c1d8979ccdb767cb4a4.jpg" width="400" height="299"/></a>&nbsp; &nbsp;&nbsp;<a href="images/5ee9046ea9fc4d65a382f94a7226069f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5ee9046ea9fc4d65a382f94a7226069f.jpg" width="400" height="301"/></a></p><p><span><span>二年级的同课异构《</span><span>Fashion Show》同样精彩！以“Betty的衣橱”为任务导向，孩子们既体验到服装的魅力，实现服饰搭配自由，还学会了用英语介绍衣服的种类和颜色。</span></span></p><p><span><span></span></span></p><p><a href="images/ccf334a987ee47d99221209f77360597.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ccf334a987ee47d99221209f77360597.jpg" width="300" height="224" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/b883a5482abf4788bded41a7d397aa38.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b883a5482abf4788bded41a7d397aa38.jpg" width="300" height="225" alt=""/>&nbsp; &nbsp;&nbsp;</a><a href="images/e834b09d755c4b10a86e52614a4ea555.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e834b09d755c4b10a86e52614a4ea555.jpg" width="300" height="224" alt=""/></a></p><p><span><span>三年级老师通过《</span><span>School Fair》，把慈善募捐活动搬进课堂，孩子们活学活用，用英语交谈价格，购买心仪物品，并感受慈善募捐的意义。</span></span><a href="images/d84ad83532b74abca8c25f6f61295749.png" target="_blank"><img title="" src="/uploads/migration/images/s_d84ad83532b74abca8c25f6f61295749.png" width="472" height="190" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/33c0432ecc33447b8c2f1bbc3421cb9f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_33c0432ecc33447b8c2f1bbc3421cb9f.jpg" width="367" height="190" alt=""/></a></p><p><span>&nbsp; &nbsp; 多元舞台助力学生成长</span></p><p><span>结合新课标课程理念，为让孩子们学有所成，学有所长，学有所用，学校还为学生打造了多种展示自己的舞台。</span></p><p><span><span>老师制作的视频号</span><span>“新航英语流利说”，展示孩子们的日常表达作品，在短时间内得到了广泛的关注和好评。让我们一起来欣赏一下一年级小朋友精彩的自我介绍吧！</span></span></p><div><video controls="controls" src="/uploads/migration/media/74f0d48ed89c4f47801437c58058c225.mp4" width="400" height="300"></video><p><span>点击播放视频</span></p></div><p><span><span>少年强则国强。自</span><span>9月份以来，小学部英语组便开展了“向世界讲述中国节日”“传统故事听我说”等主题讲述活动，将爱国主义精神贯穿于学校教育全过程。</span></span></p><p><span><span></span></span></p><div><video controls="controls" src="/uploads/migration/media/a1b00b6326ba4349926d9686a33f1c6c.mp4" width="400" height="300"></video><p><span>点击播放视频</span><strong><span><span></span></span></strong><br/></p></div><div><video controls="controls" src="/uploads/migration/media/393f7df667d94a6ab2784dfb93a0723c.mp4" width="400" height="300"></video><p><span>点击播放视频</span></p></div><p><span>成功的英语学习过程，是学生积极主动的参与过程。课堂上，老师成为学生思维培养的引导者，让主动学习、乐于学习在课堂教学中落地，这是新航实验全体英语教师的不懈追求。相信在老师的精心教学下，在浓厚的英语学习氛围中，学生们的英语学习定会节节高升。</span></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//c6488a5ce0244c1d8979ccdb767cb4a4.jpg', NULL, true, '2022-11-16 17:55:00+08', '2022-11-16 17:55:00+08', '2022-11-16 17:55:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '293313');
INSERT INTO public.news VALUES (850, '学得主动，教得生动，氛围灵动——小学部“基于语文核心素养的三动课堂范式”教研纪实', '', '为落实2022版新课标课程理念，新航实验语文学科组聚焦核心知识的教学，把“导”隐于“学”中，从“学导课堂”和“我为预测代言”入手，进行了大单元各课型教学范式的研讨。“学得主动、教得生动、氛围灵动”是二年级“学导课堂”的主要目标，经过备课解读教材、确定学习目标、编制学习单、培养助教小老师等一系列精心准备，张婧、王佩、狄莉三位老师的课堂可谓是自由欢快，事半功倍。在老师的组织调控和点拨引导下，凡是学生能...', '', '<p><span><span>为落实</span><span>2022版新课标课程理念，新航实验语文学科组聚焦核心知识的教学，把“导”隐于“学”中，从“学导课堂”和“我为预测代言”入手，进行了大单元各课型教学范式的研讨。</span></span></p><p><span><span><a href="images/a1eebbfc12de409ea6519f5cfa77bb14.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a1eebbfc12de409ea6519f5cfa77bb14.jpg" width="400" height="224"/></a></span></span></p><p><span>“学得主动、教得生动、氛围灵动”是二年级“学导课堂”的主要目标，经过备课解读教材、确定学习目标、编制学习单、培养助教小老师等一系列精心准备，张婧、王佩、狄莉三位老师的课堂可谓是自由欢快，事半功倍。在老师的组织调控和点拨引导下，凡是学生能够独自完成或者合作完成的，尽量都由孩子们自己完成，在这样的课堂上，师生变成了学习的共同体，课堂则成为了老师和学生共同展示的舞台。</span></p><p><span></span></p><p><a href="images/e3a902e1de524a85a745a3d66217cc95.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e3a902e1de524a85a745a3d66217cc95.jpg" width="300" height="225"/></a>&nbsp; &nbsp;&nbsp;<a href="images/99ccd9440f3046619b451eae8ccc9102.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_99ccd9440f3046619b451eae8ccc9102.jpg" width="300" height="225" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/bca83c3e58f34874983b6cdd68969dae.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_bca83c3e58f34874983b6cdd68969dae.jpg" width="414" height="200" alt=""/></a></p><p><span><span>三年级语文老师们以</span><span>“我为预测代言”为主线，分别从课内阅读、口语交际、习作和整本书导读四种课型入手，引导孩子们学会“预测”，丰富想象力，提升表达能力。“这节课不像语文课，更像是一节讲故事课。”课后，同学们意犹未尽地交流着。</span></span></p><p><span><span><a href="images/5702b70e2ad4456f9d591c48f525e146.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5702b70e2ad4456f9d591c48f525e146.jpg" width="400" height="225"/></a></span></span></p><p><span><span>往日枯燥的课文范例也变得有趣起来，在老师的带领下，大家通过读题目、看插图、阅读内容等，用</span><span>“当我读到……，我猜……，因为……”的句式大胆地展开联想和预测。</span></span></p><p><span><span><a href="images/cc1e584c27264e07935624d74a48df0f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cc1e584c27264e07935624d74a48df0f.jpg" width="400" height="225"/></a></span></span></p><p><span>原来每个人的名字都暗含着不同的含义，学生们在《名字里的故事》口语交际中感受着姓名中的文化内涵和长辈的关爱期待。</span></p><p><span><a href="images/a14eac83c4c543bb9987270c98cc5a26.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a14eac83c4c543bb9987270c98cc5a26.jpg" width="400" height="299"/></a></span></p><p><span>《习作：续写故事》更加激发了学生的兴趣点，结合自己过生日的体验，孩子们彻底沉浸在头脑风暴和情景演绎中，共同为李明同学策划了一次难忘的生日。</span></p><p><span><a href="images/902fc8ebe09b445588b66070d4083f91.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_902fc8ebe09b445588b66070d4083f91.jpg" width="400" height="299"/></a></span></p><p><span><span>《乌鸦理查》整本书导读课堂上，大家充分运用</span><span>“预测”这一方法，彻底放飞想象力，每一个封面、目录、插图和故事都变成了预测的线索，在积极、快乐、主动的氛围中享受着阅读的快乐。</span></span></p><p><span><span><a href="images/cdeac734ff5e491cb8338930588bfbbe.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cdeac734ff5e491cb8338930588bfbbe.jpg" width="400" height="299"/></a></span></span></p><p><span><span>与此同时，语文组认真进行了互动评课、总结复盘，老师们纷纷表示，</span><span>“学导课堂”采用“抓一放二”的策略，打通了课堂的“任督二脉”，实现了教师从关注课堂流程到关注学生发展的飞跃。</span></span></p><p><span><span>小学部邹胜校长对语文组的学习氛围和教研状态给予了充分肯定，他提出</span><span>“学导课堂”和“大单元教学”对老师的要求更高了，我们备的不仅仅是教材，更多的是学情和资源，好的课堂范式需要坚持做下去，在实践中不断优化，寻求更佳的路径。</span></span></p><p><span><span><a href="images/60a33b46e17f4f46b1c50a14fca656aa.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_60a33b46e17f4f46b1c50a14fca656aa.jpg" width="400" height="300"/></a></span></span></p><p><span><span>新课标理念带给我们挑战，更给予我们机遇。此次语文组呈现的大单元各课型范式研讨，深教研、聚智慧、赋动能，我们定会乘着这波</span><span>“浪潮”，深思而笃行，在课堂中和学生一起追寻语文的诗和远方！</span></span></p><meta name="ContentStart"/>', '', 'research', '/uploads/migration/images//a1eebbfc12de409ea6519f5cfa77bb14.jpg', NULL, true, '2022-11-04 23:50:00+08', '2022-11-04 23:50:00+08', '2022-11-04 23:50:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293310');
INSERT INTO public.news VALUES (851, '以青春之名，赴时代之约——新航实验国际部第三届英语演讲大赛精彩落幕', '', '为厚植学生爱国情怀，培养更多有理想、有能力、敢担当、肯奋斗的优秀青年，近日，新航实验国际部举办第三届国际部英语演讲大赛。本次比赛以“理解中国、沟通世界 China&#39;s wisdom for the world”为主题，用外语讲述中国故事，向世界传递中国声音。      直击现场经过层层选拔，最终14位选手脱颖而出，晋级决赛。站在舞台上，同学们激情洋溢，自信洒脱，以饱满且富有朝气的精神和流利...', '', '<p><span><span>为厚植学生爱国情怀，培养更多有理想、有能力、敢担当、肯奋斗的优秀青年，近日，新航实验国际部举办第三届国际部英语演讲大赛。本次比赛以</span><span>“理解中国、沟通世界 China&#39;s wisdom for the world”为主题，用外语讲述中国故事，向世界传递中国声音。</span></span></p><p><span><span></span></span></p><p><a href="images/64fe27d7ce9e4943bfe2ba1743817f71.png" target="_blank"><img title="" src="/uploads/migration/images/s_64fe27d7ce9e4943bfe2ba1743817f71.png" width="400" height="228"/></a>&nbsp; &nbsp; &nbsp;&nbsp;<a href="images/c0f42849bfbf4431b2874fd3833e1765.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c0f42849bfbf4431b2874fd3833e1765.jpg" width="400" height="266"/></a></p><p><strong><span>直击现场</span></strong></p><p><span><span>经过层层选拔，最终</span><span>14位选手脱颖而出，晋级决赛。站在舞台上，同学们激情洋溢，自信洒脱，以饱满且富有朝气的精神和流利的语言，用青春的声音传递着祖国综合国力的高速腾飞，分享着中国传统文化的魅力。从古代的四大发明、丝绸之路，到当今的5G技术、数字经济、高铁技术、航空航天；从汉服、筷子、建筑，到清洁能源绿色发展、疫情防控生命至上、科技冬奥、脱贫攻坚……同学们结合自身经历，以小故事见大情怀，展现了新时代青年的家国情怀和勇气担当，充分展示了当代高中生的青春面貌！</span></span></p><p><a href="images/58dc82bcc8c04dada1449a3d54868d04.png" target="_blank"><img title="" src="/uploads/migration/images/s_58dc82bcc8c04dada1449a3d54868d04.png" width="300" height="199"/></a>&nbsp; &nbsp;&nbsp;<a href="images/52266826f2aa454c85f815e6ec146f0a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_52266826f2aa454c85f815e6ec146f0a.jpg" width="300" height="248"/></a>&nbsp; &nbsp;&nbsp;<a href="images/49898f9a0521477d96ec07d39424ebc9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_49898f9a0521477d96ec07d39424ebc9.jpg" width="300" height="224"/></a></p><p><a href="images/cce101fff04c414992c861d5b449e589.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cce101fff04c414992c861d5b449e589.jpg" width="300" height="215"/></a>&nbsp; &nbsp;&nbsp;<a href="images/0c45b1b4c6c64ad5b6811b9d7798f34f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0c45b1b4c6c64ad5b6811b9d7798f34f.jpg" width="300" height="199"/></a>&nbsp; &nbsp;&nbsp;<a href="images/24b06b843cb347bf8dd028d49bd5c072.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_24b06b843cb347bf8dd028d49bd5c072.jpg" width="300" height="221"/></a></p><p><a href="images/0428eebffaef4fe69660e3e161848590.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0428eebffaef4fe69660e3e161848590.jpg" width="300" height="199"/></a>&nbsp; &nbsp;&nbsp;<a href="images/42927fc824184b369e71f48f767b6a8e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_42927fc824184b369e71f48f767b6a8e.jpg" width="300" height="199"/></a></p><p><strong><span>高光时刻</span></strong></p><p><strong><span>&nbsp; &nbsp; 金奖：</span></strong><span>任舒予</span></p><p><strong><span>&nbsp; &nbsp; 银奖：</span></strong><span>任俊颖、张子淳</span></p><p><strong><span>&nbsp; &nbsp; 铜奖：</span></strong><span>祝瑞泉、王子墨、李悦齐</span></p><p><strong><span>&nbsp; &nbsp; 优秀奖：</span></strong><span>董芊语、郭子健、袁溪悦、孟圆圆、高小檬、郭奕然、许钧乔、周煜晨</span></p><p><a href="images/ef6871061b2a4132a867f61a5c1afb82.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef6871061b2a4132a867f61a5c1afb82.jpg" width="400" height="259"/></a>&nbsp; &nbsp; &nbsp;&nbsp;<a href="images/6c36b3d5519940ec8d275fcaaae87c6e.png" target="_blank"><img title="" src="/uploads/migration/images/s_6c36b3d5519940ec8d275fcaaae87c6e.png" width="400" height="317"/></a></p><p><strong><span>参赛感言</span></strong></p><p><strong><span><span>高二</span><span>6班 任舒予</span></span></strong></p><p><span>备赛期间，我对演讲的每一个细节包括措辞、语调、肢体动作等都进行了细致的设计和反复训练，这也让我深刻体会到了努力的重要性。日后的学习中，我也会继续保持谦逊，并用更多的努力来取得更大的成就，在未来的道路上贡献更多的中国智慧！</span></p><p><span><a href="images/0a69c6c9a1bc4691ae663f1f3966ce62.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0a69c6c9a1bc4691ae663f1f3966ce62.jpg" width="400" height="302"/></a></span></p><p><strong><span><span>高一</span><span>6班 任俊颖</span></span></strong></p><p><span>在这次稿件的准备、搜集过程中，我更深刻地感受到我国科技的飞速发展以及传统文化的博大精深，也意识到我们年轻一代要肩负的重担。讲好中国故事，向世界传递中国文化，是我们责无旁贷的使命与担当。</span></p><p><span><a href="images/6f0e8e230de94764a7a2ab800b98ab5c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6f0e8e230de94764a7a2ab800b98ab5c.jpg" width="400" height="302"/></a></span></p><p><strong><span>师长点评</span></strong><span>&nbsp;</span></p><p><span>赛后，张爱梅副校长高度赞扬了同学们的精彩表现，不管是演讲语言、舞台姿态，还是演讲情感和演讲内容都展现了新航学子扎实牢固的英语基础、自信从容的精神风貌、贯通中外的全球视野和大国青年的责任担当。刘新利校长也出席当天的活动并上台为获奖选手颁奖。</span></p><p><span>期待新航实验学子在未来的学习中，不断提升语言运用能力、思辨能力和文化素养，做有理想敢担当的新时代好少年，在世界舞台绽放属于中国青年的独特光彩！</span></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//64fe27d7ce9e4943bfe2ba1743817f71.png', NULL, true, '2022-10-31 23:16:00+08', '2022-10-31 23:16:00+08', '2022-10-31 23:16:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '293305');
INSERT INTO public.news VALUES (852, '互学共研融课堂，凝心聚力促发展——新航实验全学段融通一体化发展之数学系列教研活动', '', '为了深化基础教育课程改革，进一步加快全学段融通一体化发展建设步伐，推进课堂育人目标、教学内容、教学方式和评价方式等方面深度改革，近日，新航实验小学、初中、高中三个学段教研组与邵丽云齐鲁名师领航名师工作室联合教研，以三个学段共有的数学核心知识《圆》为主线，开展了全学段融通一体化发展系列教研活动。        小学部祁文焕老师执教三年级的《圆的认知》，让学生不断动手操作，总结经验，边学概念边体会圆的...', '', '<p><span>为了深化基础教育课程改革，进一步加快全学段融通一体化发展建设步伐，推进课堂育人目标、教学内容、教学方式和评价方式等方面深度改革，近日，新航实验小学、初中、高中三个学段教研组与邵丽云齐鲁名师领航名师工作室联合教研，以三个学段共有的数学核心知识《圆》为主线，开展了全学段融通一体化发展系列教研活动。</span></p><p><a href="images/f931f552b58a468a860a24bfafcb70ec.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f931f552b58a468a860a24bfafcb70ec.jpg" width="300" height="200" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/efe0a22f99f6490ea37f0ef39a28c030.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_efe0a22f99f6490ea37f0ef39a28c030.jpg" width="300" height="200" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/101b3bbdd7644b26ab2d5bf59cdc92f8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_101b3bbdd7644b26ab2d5bf59cdc92f8.jpg" width="300" height="200" alt=""/></a></p><p><span>小学部祁文焕老师执教三年级的《圆的认知》，让学生不断动手操作，总结经验，边学概念边体会圆的特征，学生在主动参与的过程中，自然习得关于圆的知识。</span></p><p><span><a href="images/0d4d2c6093554ad0a8671af2c25c6fb8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0d4d2c6093554ad0a8671af2c25c6fb8.jpg" width="400" height="266"/></a></span></p><p><span>初中部杨超老师教授九年级《确定圆的条件》，带领学生在寻找问题和解决问题的过程中探究数学，为学生创造了宽松自主的学习空间和氛围。</span></p><p><span><a href="images/74393a81bd324b8f9b914daa052a3d6a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_74393a81bd324b8f9b914daa052a3d6a.jpg" width="400" height="266"/></a></span></p><p><span>高中部张素文老师则带来了一堂高二年级的《圆的方程》，顺应学生的思维，通过联系学生已有的知识经验，帮助学生找准知识的生长点和落脚点，突出圆的概念与知识的生成过程。</span></p><p><span><a href="images/ef0488fc971846cc9b28caf82bf4196c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef0488fc971846cc9b28caf82bf4196c.jpg" width="400" height="266"/></a></span></p><p><span>山东省实验中学数学组教研组长潘洪艳老师对三位老师的精彩课程给予了充分的肯定，她指出，三位老师在课堂上扮演了很好的组织者、引导者和合作者的角色，给学生一把在知识的海洋中航行的桨，让学生积极思考，大胆尝试，注重数学思想、能力的培养，广度和深度都符合数学课程标准和教材的要求。</span></p><p><span><a href="images/0e9c0bb169fe445f9eea398e96ff8f36.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0e9c0bb169fe445f9eea398e96ff8f36.jpg" width="400" height="266"/></a></span></p><p><span><span>接下来，济南市教研院数学教研员安学保老师以《</span><span>“圆”来如此——全学段贯通数学核心素养》为主题，为大家带来一场精彩的报告。安老师提出，要从小学课堂培养学生数学抽象的思想，明确各学段教学的针对性，不同学段教学的系统性和连贯性。老师应该指导学生用数学语言有逻辑地表述自己的想法，让学生在互动的环节中主动发现问题，提出问题，知识自然生成。</span></span></p><p><span><span><a href="images/dd905aa0a153474ab35695c0b70fe7a0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_dd905aa0a153474ab35695c0b70fe7a0.jpg" width="400" height="266"/></a></span></span></p><p><span>“我校全学段贯通培养教学研究是为学生终身发展奠定基础的有益研究，是新航实验教育理念的一次落地行动。”新航实验教学管理中心主任王云剑介绍道，结合新航实验全学段特色，学校一直致力于进行十二年一贯制贯通式培养模式研究，建立小初高衔接的长效机制，让学生在“全学段贯通式教学”中得到“针对性”“系统性”“连贯性”“发展性”的思维训练，深化教育教学研究，促进教师的专业化发展，为学生和学校的发展奠定坚实的基础。</span></p><p><span></span></p><p><a href="images/1a40643918504a3c892e42e7ef18718e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1a40643918504a3c892e42e7ef18718e.jpg" width="400" height="266"/></a>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/c662a4dbe35941ed98a1f25333c8ba6d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c662a4dbe35941ed98a1f25333c8ba6d.jpg" width="400" height="266"/></a></p><p><br/></p><meta name="ContentStart"/>', '', 'campus', '/uploads/migration/images//f931f552b58a468a860a24bfafcb70ec.jpg', NULL, true, '2022-10-28 23:55:00+08', '2022-10-28 23:55:00+08', '2022-10-28 23:55:00+08', '赵昕晨', '新航实验外国语学校', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '293302');
INSERT INTO public.news VALUES (853, '不一样的导师见面会：在新航，来一场兴趣与兴趣的双向奔赴吧！', '', '英国哲学家罗素曾说过，一个明智地追求快乐的人，除了培养生活赖以支撑的主要兴趣外，总得设法培养许多其他的闲情逸致。为了培养学生对学习、兴趣和生活的热爱，密切师生关系，践行“让每一个生命都精彩绽放”的教育理念，开学之初，初中学部便组织了导师与学生的互选工作，并于近日开展了第一次导师学生见面会。漫步校园，餐厅、教室、公共学习区、书吧、图书馆、操场.....到处都是师父和徒弟切磋交流的身影。他们或漫谈古文...', '', '<p><span><span>英国哲学家罗素曾说过，一个明智地追求快乐的人，除了培养生活赖以支撑的主要兴趣外，总得设法培养许多其他的闲情逸致。为了培养学生对学习、兴趣和生活的热爱，密切师生关系，践行</span><span>“让每一个生命都精彩绽放”的教育理念，开学之初，初中学部便组织了导师与学生的互选工作，并于近日开展了第一次导师学生见面会。</span></span></p><p><span><span>漫步校园，餐厅、教室、公共学习区、书吧、图书馆、操场</span><span>.....到处都是师父和徒弟切磋交流的身影。他们或漫谈古文、或畅聊音乐、或切磋球技、或学习解惑...每一组师徒都在享受“兴趣与兴趣，双向奔赴”的盛会。</span></span></p><p><span>师建立安全亲密的师生关系生关系</span></p><p><span><span>在新航实验，每一位教师都会兼任学生导师，他们会经常从任课老师、班主任、心理老师那里了解每位</span><span>“亲学生”的近况，并在定期举行的“导师见面会”中，从学业、心理、思想、生活等方面为学生开导答疑，从而建立安全亲密的师生关系。</span></span></p><p><span><span></span></span></p><p><a href="images/79c62f9c31254e8ca55afb7febb11dba.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_79c62f9c31254e8ca55afb7febb11dba.jpg" width="400" height="300"/></a>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/07cad93f75634fc780018943274627d6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_07cad93f75634fc780018943274627d6.jpg" width="400" height="300"/></a></p><p><span>培养专注的兴趣方向</span></p><p><span>从本学期开始，学生和导师在互选前，增加了老师的特长展示环节。学生不仅可以选择自己喜欢的学科，更可以选择和自己有相同兴趣爱好的导师，同时结实与自己志同道合的同学。在平时的交流学习中，导师利用自己的学科或兴趣优势，带领学生一起观测星空、做实验、排练表演等，鼓励他们大胆尝试、拓展视野，从多种兴趣的尝试到一种兴趣的专注，启发学生展开对自我认识和自我发展的思考。</span></p><p><a href="images/7d5fdc2a94cb408b9c5cda5aff3ee45e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7d5fdc2a94cb408b9c5cda5aff3ee45e.jpg" width="400" height="300"/></a>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/ec8480db6514456d863a02e91c0123ce.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ec8480db6514456d863a02e91c0123ce.jpg" width="400" height="300"/></a></p><p><span>实现本质上的能力提升</span></p><p><span><span>设定目标，将目标分解后变成行动，这件事对于中学生而言是一种需要学习的能力。在学期的前、中、后期，班主任和导师都会陪学生一起分析阶段目标的实现情况、出现的问题以及如何解决。在一次一次的复盘和总结中，实现学生对</span><span>“经历—反馈—调整”能力的练习，从而最大程度地帮助学生实现自我成长。</span></span></p><p><a href="images/76896bbf2aaf46ca8f79d55ce2be79c2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_76896bbf2aaf46ca8f79d55ce2be79c2.jpg" width="400" height="224"/></a>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/ef1a115c51db4233b6ef3c835086d140.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef1a115c51db4233b6ef3c835086d140.jpg" width="400" height="300"/></a></p><p><span>兴趣与兴趣的双向奔赴</span></p><p><span>新航校园是一方神奇的沃土，这里盛产知识、盛产技能、更盛产快乐，这里有一群热爱生活、博学多才的老师，更有一群朝气蓬勃、有识有礼的少年，他们是生活上的知音，更是学习上的伙伴，相信在导师们的陪伴和引领下，孩子们一定会绽放属于自己生命的精彩。</span></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//79c62f9c31254e8ca55afb7febb11dba.jpg', NULL, true, '2022-10-28 23:06:00+08', '2022-10-28 23:06:00+08', '2022-10-28 23:06:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '293299');
INSERT INTO public.news VALUES (855, '新航恋念，季忆留夏——期待再见，2022届高三毕业生', '', '随着高考落下帷幕， 离别的日子悄悄到来。 又是一年毕业季， 三年光阴如白驹过隙， 从第一次踏入校园到毕业， 每个瞬间都仿佛近在眼前。 一声再见，带不走三年青葱荏苒， 三年拼搏，此刻相聚在最爱的校园， “新航恋念，季忆留夏”， 今天，用这场盛典， 告别精彩纷呈的高中岁月。 第一篇章：春风化雨 情意绵绵 作为新航实验首届高中毕业生，2019年，当同学们义无反顾地选择新航实验时，就意味着他们将与学校共同...', '', '<p><a href="images/ac6385a7a28b471ab1c1982dea4955ad.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/ac6385a7a28b471ab1c1982dea4955ad.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span>随着高考落下帷幕，</span></p>
    <p><span>离别的日子悄悄到来。</span></p>
    <p><span>又是一年毕业季，</span></p>
    <p><span>三年光阴如白驹过隙，</span></p>
    <p><span>从第一次踏入校园到毕业，</span></p>
    <p><span>每个瞬间都仿佛近在眼前。</span></p>
    <p><span>一声再见，带不走三年青葱荏苒，</span></p>
    <p><span>三年拼搏，此刻相聚在最爱的校园，</span></p>
    <p><span>“新航恋念，季忆留夏”，</span></p>
    <p><span>今天，用这场盛典，</span></p>
    <p><span>告别精彩纷呈的高中岁月。</span></p>
    <p><a href="images/f2244843a2e64f4aa8bd732fbb05b432.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f2244843a2e64f4aa8bd732fbb05b432.jpg"></a></p>
    <section>
     <section>
      <section>
       <section>
        <section>
         <p><span><strong><span>第一篇章：春风化雨 情意绵绵</span></strong></span></p>
        </section>
       </section>
      </section>
     </section>
    </section>
    <p></p>
    <section>
     <section>
      <section>
       <section>
        <section>
         <p><span>作为新航实验首届高中毕业生，2019年，当同学们义无反顾地选择新航实验时，就意味着他们将与学校共同成长，他们是当之无愧的新航“开拓者”。也正因为彼此的遇见，才有了这三年最美好的时光。春华秋实，岁月如歌，在所有的点滴与成长中，我们都是追光者，所有的遇见也将成为一生中最充满希望和理想的时光。</span></p>
         <p><span><a href="images/d15e7e0c47464af58ae4a06fb8933cb5.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/d15e7e0c47464af58ae4a06fb8933cb5.jpg"></a><a href="images/61d39ba65e6b4a998ea8ba4c18508322.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/61d39ba65e6b4a998ea8ba4c18508322.jpg"></a></span></p>
         <p><span></span></p>
         <div>
          <div id="mediaContent0_0"></div> 
          <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
          <script type="text/javascript">
    var flashvars={
        f:"/media/0/96a1c725ad4041ee96af25fe26bc89dd.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/96a1c725ad4041ee96af25fe26bc89dd.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script>
         </div>
         <p><span></span><br></p>
         <p><span></span></p>
         <section>
          <section>
           <section>
            <section>
             <section>
              <p><span><strong><span>第二篇章：辉煌时刻 感谢师恩</span></strong></span></p>
             </section>
            </section>
           </section>
          </section>
         </section>
         <p></p>
         <section>
          <section>
           <section>
            <section>
             <section>
              <p><span>山水有时尽，师恩日月长。三年来，老师在讲台上的谆谆教诲，在自习区的细细讲解，在宿舍楼的切切关爱，在运动场的声声鼓励，都将伴随同学们奔赴远方。此情此景，一幕幕往日的记忆涌上心头。同学们手捧鲜花，表达对老师们的感谢和祝福，深情地道一声：“老师，谢谢您！”</span></p>
              <p><a href="images/614ffe7ba1eb48f88e12d65e9fec1103.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/614ffe7ba1eb48f88e12d65e9fec1103.jpg"></a><a href="images/7dcce71c63f8496eaac93b47040c4003.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/7dcce71c63f8496eaac93b47040c4003.jpg"></a><a href="images/6d328e0ed4fb43ca8e8a3c21615f6801.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/6d328e0ed4fb43ca8e8a3c21615f6801.jpg"></a></p>
             </section>
            </section>
            <section>
             <section>
              <section>
               <section>
                <section>
                 <section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                 </section>
                 <section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                 </section>
                </section>
               </section>
              </section>
             </section>
            </section>
            <section>
             <section>
              <section>
               <section>
                <section>
                 <section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                 </section>
                 <section>
                  <section>
                   <section>
                    <section></section>
                   </section>
                  </section>
                  <section>
                   <section></section>
                  </section>
                 </section>
                </section>
               </section>
              </section>
             </section>
            </section>
           </section>
          </section>
         </section>
         <p></p>
         <p><span>“请你们将‘日新博学、志航天下’的校训内化于心，多一些‘吾日三省吾身’的坚持，多一分君子‘有所为，有所不为’的原则，多一些‘自强不息、厚德载物’的品德。未来道阻且长，但行则将至，只要行而不辍，终将不负流年、不悔时光。”仪式感满满的拨穗礼、最后一次的校长寄语，载着深深的期冀和嘱托，祝愿同学们在青春的旅途中，沿着梦想，一路追光，在磨砺中出彩，在奋斗中闪光。<br></span></p>
         <p></p>
         <section>
          <section>
           <section>
            <section>
             <section>
              <section>
               <section>
                <section>
                 <section></section>
                </section>
               </section>
               <section>
                <section>
                 <section></section>
                </section>
               </section>
              </section>
              <section>
               <section>
                <section>
                 <section></section>
                </section>
               </section>
               <section>
                <section></section>
               </section>
              </section>
             </section>
            </section>
           </section>
          </section>
         </section>
         <p></p>
         <p><span><a href="images/8bf4a922d0fa4085959f51da3f3fb1a6.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/8bf4a922d0fa4085959f51da3f3fb1a6.jpg"></a><a href="images/1b380f11ebc2450082ea1b32044fea8e.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/1b380f11ebc2450082ea1b32044fea8e.jpg"></a></span></p>
         <p><span><br></span></p>
         <section>
          <section>
           <section>
            <section>
             <section>
              <p><span><strong><span>第三篇章：相知相遇 一路陪伴</span></strong></span></p>
             </section>
            </section>
           </section>
          </section>
         </section>
         <p></p>
         <section>
          <section>
           <section>
            <section>
             <section>
              <p><span>掣鲸楼里、风雨操场、学生宿舍……三年时光，校园每个角落都散落着美好的记忆，与老师的相遇相知，与同学的一路陪伴，所有青春故事都成为最珍贵的回忆。</span></p>
              <p><span><a href="images/26cd0e82f7e6454da046ae9ba99da494.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/26cd0e82f7e6454da046ae9ba99da494.jpg"></a><a href="images/5c3a42b80af14821917bb5fdec52cb4d.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/5c3a42b80af14821917bb5fdec52cb4d.jpg"></a><a href="images/894e289892e5407496fb004fe0555e27.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/894e289892e5407496fb004fe0555e27.jpg"></a><a href="images/95c93950f01f425695610e6cd30addf9.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/95c93950f01f425695610e6cd30addf9.jpg"></a><a href="images/cee03c1c72d84d3aa37fe42eb1f8201f.jpg" target="_blank"><img title="14.jpg" src="/uploads/migration/images/cee03c1c72d84d3aa37fe42eb1f8201f.jpg"></a></span></p>
              <p><span></span></p>
              <section>
               <section>
                <section>
                 <section>
                  <section>
                   <p><span><strong><span>第四篇章：纸短情长 爱语相送</span></strong></span></p>
                  </section>
                 </section>
                </section>
               </section>
              </section>
              <section>
               <section>
                <section>
                 <section>
                  <section>
                   <p><span>毕业典礼，代表着高中生活的终点，更是人生另一个意义非凡的起点。从今天起，同学们即将离开父母的温暖怀抱独自闯荡，在这个重要的时刻，全体同学起立，深深鞠躬，将成年后的第一封信交到父母手中，“爸爸妈妈，请你们放心，我们已经长大了！”</span></p>
                   <p><a href="images/c92bd1e2ecc04cbc9c431554c2b51264.jpg" target="_blank"><img title="15.jpg" src="/uploads/migration/images/c92bd1e2ecc04cbc9c431554c2b51264.jpg"></a><a href="images/cca4973a70484ac4bad1316a2ad93ec4.jpg" target="_blank"><img title="16.jpg" src="/uploads/migration/images/cca4973a70484ac4bad1316a2ad93ec4.jpg"></a><a href="images/a797ad7f71a44afeaca4ee99315235ca.jpg" target="_blank"><img title="17.jpg" src="/uploads/migration/images/a797ad7f71a44afeaca4ee99315235ca.jpg"></a></p>
                   <section>
                    <section>
                     <section>
                      <section>
                       <section>
                        <p><span><strong><span>第五篇章：星辰大海 永不止步</span></strong></span></p>
                       </section>
                      </section>
                     </section>
                    </section>
                   </section>
                   <p></p>
                   <section>
                    <section>
                     <section>
                      <section>
                       <section>
                        <p><span>虽说三年时光大多是教室、食堂、宿舍三点一线，但这样看似“单调”的生活在学弟学弟的陪伴中、在餐厅物业工作人员的照顾下、在老师们的关爱中，溢满了温馨和感动。孩子们，离开了新航，请好好爱自己；师哥师姐们，愿你光辉，愿你璀璨，愿你声名盛满。</span></p>
                        <div>
                         <div id="mediaContent0_1"></div> 
                         <script type="text/javascript">
    var flashvars={
        f:"/media/0/5476c5ac1b1843b9badf962d40475913.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/5476c5ac1b1843b9badf962d40475913.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_1","ckplayer_mediaContent0_1","400","300",false,flashvars,video,params);
</script>
                        </div>
                        <p><a href="images/ffeb971798ec4419b5ded9fde46aa2d6.jpg" target="_blank"><img title="18.jpg" src="/uploads/migration/images/ffeb971798ec4419b5ded9fde46aa2d6.jpg"></a></p>
                       </section>
                      </section>
                     </section>
                    </section>
                   </section>
                   <p></p>
                  </section>
                 </section>
                </section>
               </section>
              </section>
              <p><span>“时光的河入海流，终于我们分头走……”，典礼即将结束的一刻，全体高三老师惊喜现身舞台，这一场离别的快闪，带着师长无尽的不舍和牵挂。然而，回眸之际，不必伤感，雏鹰终将远行，愿2022届毕业生奔赴碧海蓝天、星河徜徉，一路有光，乘风破浪，未来可期！</span></p>
              <p><br></p>
              <p><a href="images/49decb88f366460b9f11ab026d75c817.jpg" target="_blank"><img title="19.jpg" src="/uploads/migration/images/49decb88f366460b9f11ab026d75c817.jpg"></a><a href="images/c2ac5af4e9884b8baf5994bbeec8a1ab.jpg" target="_blank"><img title="20.jpg" src="/uploads/migration/images/c2ac5af4e9884b8baf5994bbeec8a1ab.jpg"></a><a href="images/030d74117e914cfe915745347f554b88.jpg" target="_blank"><img title="21.jpg" src="/uploads/migration/images/030d74117e914cfe915745347f554b88.jpg"></a></p>
              <p><br></p>
              <p><br></p>
             </section>
            </section>
           </section>
          </section>
         </section>
         <p></p>
         <p><span><br></span><br></p>
        </section>
       </section>
      </section>
     </section>
    </section>
    <p></p>
    <p><br></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <section>
   <section>
    <section>
     <section></section>
    </section>
   </section>
  </section>
 </section>
</section>
<p></p>
<p><br></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/ac6385a7a28b471ab1c1982dea4955ad.jpg', NULL, true, '2022-06-21 08:00:00+08', '2022-06-21 08:00:00+08', '2022-06-21 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (856, '新航实验高中部2022年招生报名开始了！', '', '济南新航实验外国语学校2022年高中部报名提醒请具备2022年参加济南市高中统一招生考试报名资格、身心健康、品德优秀的应届初中毕业生，于2022年6月21日12:00至6月25日12:00，访问链接http://gaozhong.wiscoor.com/，进入报名端口，注册后登录，按要求填写信息报名。学校将对报名考生的报名信息进行审查，请报名同学于6月26日8:00—17:00，访问报名网址查询并...', '', '<section><section><section><section><section><section><p><strong><a href="images/c78f7467d9e446e6af8c0c77836a7035.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/c78f7467d9e446e6af8c0c77836a7035.jpg"/></a></strong></p><p><span><strong>济南新航实验外国语学校</strong></span></p><p><span><strong>2022年高中部报名提醒</strong></span></p></section></section></section><section><section><section></section></section></section></section></section></section><p><section><section><section><p><span>请具备2022年参加济南市高中统一招生考试报名资格、身心健康、品德优秀的应届初中毕业生，于2022年6月21日12:00至6月25日12:00，<span>访问链接http://gaozhong.wiscoor.com/，进入报名端口，注册后登录，按要求填写信息报名。</span></span></p><p><span>学校将对报名考生的报名信息进行审查，请报名同学于6月26日8:00—17:00，访问报名网址查询并打印准考证。</span></p><p><span>请考生及家长及时关注学校公众号及教育咨询QQ群消息，了解后续招生考试的工作安排。</span></p><p><span>招生咨询电话：</span></p><p><span>0531-59562266（普通班）</span></p><p><span>0531-59562288（国际班）</span></p><p><span>感谢您的关注和支持！</span></p><p><span><a href="images/83661cee447e4ad38a9ece171076cb4d.png" target="_blank"><img title="微信截图_20220621115103.png" src="/uploads/migration/images/83661cee447e4ad38a9ece171076cb4d.png"/></a></span></p></section></section></section></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/c78f7467d9e446e6af8c0c77836a7035.jpg', NULL, true, '2022-06-21 08:00:00+08', '2022-06-21 08:00:00+08', '2022-06-21 08:00:00+08', '赵昕晨', '新航实验外国语学校', '实验 新航 招生 高中部 报名', '');
INSERT INTO public.news VALUES (857, '持心守正，以奋进之笔绘就精彩画卷——新航实验举行2022年春季学期开学典礼', '', '最是一年春好处，踔厉奋进正当时。带着新的希望、新的目标，2月21日，济南新航实验外国语学校全体师生迎来2022年春季学期开学典礼。伴随着庄严的国歌声，五星红旗冉冉升起。雄壮激昂的歌声开启新学期的奋进之旅，新航实验学子已站在新的起跑线上，他们将以坚定不移的决心、坚持不懈的付出，迎来花香满路，不负青春，不负韶华。过去的一学期，全体新航实验学子坚定理想信念，秉持善良、勤奋、认真、坚持的优良品质，涌现出一...', '', '<p><span>最是一年春好处，踔厉奋进正当时。带着新的希望、新的目标，2月21日，济南新航实验外国语学校全体师生迎来2022年春季学期开学典礼。</span></p><p><a href="images/437e2c7271044af6a05d5b44ce69d630.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/437e2c7271044af6a05d5b44ce69d630.jpg"/></a><a href="images/50b718a347c5434c99552f074a414f7f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/50b718a347c5434c99552f074a414f7f.jpg"/></a></p><p><span>伴随着庄严的国歌声，五星红旗冉冉升起。雄壮激昂的歌声开启新学期的奋进之旅，新航实验学子已站在新的起跑线上，他们将以坚定不移的决心、坚持不懈的付出，迎来花香满路，不负青春，不负韶华。</span></p><p><span><a href="images/9f49c3a537294a169e24529a1bda460b.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/9f49c3a537294a169e24529a1bda460b.jpg"/></a></span></p><p><span>过去的一学期，全体新航实验学子坚定理想信念，秉持善良、勤奋、认真、坚持的优良品质，涌现出一大批“有礼、有识、有情、有型”的优秀学子和班风正学风浓的先进集体。</span></p><p><span>成子谦、李长健等5名同学获得“志航二级奖励”，田宸玮、兰宇轩等13名同学获得“志航三级奖励”，吴玄瀚、石晟呈、王鹏博等66名同学获得“博学奖”，王小可、许昕泽等74名同学获评“全面发展标兵”，刘冠仪、周子愉等21名同学被评为“优秀团员”，谢玮伦、武君睿、刘君辉等同学获得“日新奖”，顾焱堃、刘雨琪等同学被评为“优秀学生干部”，汪函宇、刘宣懿等同学被评为“优秀学生”，一年级2班、初一4班、高一1班等21个班级被授予“先进班集体”。</span></p><p><span><a href="images/45720ca3933949a784a1e16a0556e781.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/45720ca3933949a784a1e16a0556e781.jpg"/></a><a href="images/a399248972a5494ab7d7d5109284102c.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/a399248972a5494ab7d7d5109284102c.jpg"/></a><a href="images/43f90439d4f64a64a376043aaf9dea9e.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/43f90439d4f64a64a376043aaf9dea9e.jpg"/></a><a href="images/0487837672d0419a87a0b675e3bde678.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/0487837672d0419a87a0b675e3bde678.jpg"/></a></span></p><p><span>“追风赶月莫停留，平芜尽处是春山。”林宝磊校长在致辞中寄语新学期，勉励新航实验师生做勇担使命的爱国者、品德高尚的奉献者、执着追梦的奋斗者，让守正固德成为操守之境，为国为民作为理想信念，以赤子之心为生命赋予意义，一如既往地保持拼搏奋发、积极向上的姿态，用青春拥抱时代，用奋斗点燃未来，凝聚力量、奋发前进，以实际行动献礼党的二十大，一起向未来！</span></p><p><span><a href="images/b5fcf9fa50fb45baaced752b96386894.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/b5fcf9fa50fb45baaced752b96386894.jpg"/></a></span></p><p><span>一切过往，皆为序章。2022，弥足期待。开学典礼已吹响起航的号角，全体师生将以气势如虎之精神，凭生龙活虎之干劲，再整旗鼓，自新航，至远方。</span></p><p><span><br/></span></p><p><br/></p><meta name="ContentStart"/>', '', 'campus', '/uploads/migration/images//437e2c7271044af6a05d5b44ce69d630.jpg', NULL, true, '2022-02-24 16:36:00+08', '2022-02-24 16:36:00+08', '2022-02-24 16:36:00+08', '赵昕晨', '新航实验外国语学校', '举行 新航 实验 春季 画卷', '285961');
INSERT INTO public.news VALUES (858, '顶流助阵、虎力全开！新航实验开学第一天，仪式感拉满！', '', '在万众瞩目的冬奥会赛事正酣之时，济南新航实验外国语学校以独特的方式迎来新学期，2月16日，寂静许久的校园也迎来熟悉的笑声和灵动的身影！没有仪式感的人生，是灰头土脸的！当开学日遇上新晋顶流，“左拥”冰墩墩、“右抱”雪容融是一种怎样的体验呢？让我们前去一探究竟~~教室里，惊喜红包、暖心寄语、荣誉证书、个人分享、奥运主题班会……开学第一课火热开讲，新航师生已整装待发，以饱满的热情和全新的姿态迎接更优秀的...', '', '<section><p><span>在万众瞩目的冬奥会赛事正酣之时，济南新航实验外国语学校以独特的方式迎来新学期，<span>2月16日，</span>寂静许久的校园也迎来熟悉的笑声和灵动的身影！</span></p><p><a href="images/a6ef1de7046a4be792dc5d1d3736a429.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/a6ef1de7046a4be792dc5d1d3736a429.jpg"/></a><a href="images/a0819d5d515943699e98405a8a016ad6.jpg" target="_blank"><img title="11.webp.jpg" src="/uploads/migration/images/a0819d5d515943699e98405a8a016ad6.jpg"/></a><a href="images/c4e6b012d15e4edba48e776e9a4151a7.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/c4e6b012d15e4edba48e776e9a4151a7.jpg"/></a><a href="images/ba7a497d48904dd0a1f527b9a50458f9.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/ba7a497d48904dd0a1f527b9a50458f9.jpg"/></a></p></section><p>没有仪式感的人生，是灰头土脸的！</p><p>当开学日遇上新晋顶流，“左拥”冰墩墩、“右抱”雪容融是一种怎样的体验呢？让我们前去一探究竟~~</p><p><a href="images/5d628f2302ef4d69ad13935f85303032.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/5d628f2302ef4d69ad13935f85303032.jpg"/></a><a href="images/7485d8239531487ba53a6728dccb0c1d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/7485d8239531487ba53a6728dccb0c1d.jpg"/></a><a href="images/4fb4c56b9cab4f46a4277847e7f9297c.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/4fb4c56b9cab4f46a4277847e7f9297c.jpg"/></a><a href="images/e74fb40a66274cbead7bef1428ca5b5d.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/e74fb40a66274cbead7bef1428ca5b5d.jpg"/></a><a href="images/79eb7f5e100d457f892478a40fd15109.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/79eb7f5e100d457f892478a40fd15109.jpg"/></a><a href="images/ded459d9895049f8bf37a1e7e245c498.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/ded459d9895049f8bf37a1e7e245c498.jpg"/></a><a href="images/d6968d5415314820a4bd6262a07eead2.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/d6968d5415314820a4bd6262a07eead2.jpg"/></a><a href="images/1cf408327c0342019e7cc7a31c6a82e4.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/1cf408327c0342019e7cc7a31c6a82e4.jpg"/></a><a href="images/930bd882a3e94828a5ba940f074953a6.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/930bd882a3e94828a5ba940f074953a6.jpg"/></a></p><p><span>教室里，惊喜红包、暖心寄语、荣誉证书、个人分享、奥运主题班会……开学第一课火热开讲，新航师生已整装待发，以饱满的热情和全新的姿态迎接更优秀的自己。</span></p><p><span><a href="images/f4434052be164edaa6d8e98161bd9830.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f4434052be164edaa6d8e98161bd9830.jpg"/></a><a href="images/5d7de1231cc548e499f3f9a93146bd3f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/5d7de1231cc548e499f3f9a93146bd3f.jpg"/></a><a href="images/ec0a674e333e446facf67d3fe093b967.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/ec0a674e333e446facf67d3fe093b967.jpg"/></a><a href="images/2a1ccf287fca418e9b38eda1b2312bc2.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/2a1ccf287fca418e9b38eda1b2312bc2.jpg"/></a><a href="images/ec9c3833939543378b3a22db37324d7e.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/ec9c3833939543378b3a22db37324d7e.jpg"/></a><a href="images/950e5e322d5d4d4c9e7a3ba25078c866.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/950e5e322d5d4d4c9e7a3ba25078c866.jpg"/></a></span></p><p><span></span></p><section><p><span>站在新的旅途上，从不会到会，只需做一件事——努力！</span></p><p><span>新学期的大幕已强势拉开，在冬奥精神的加持下，新航学子定将乘着拼搏进取、永不言败的奥运东风，虎力全开，一起向未来！</span></p></section><p><section><p><br/></p></section></p><p><span><br/></span><br/></p><p><br/></p><p><br/></p><p><br/></p><p><section></section></p><p><br/></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//a6ef1de7046a4be792dc5d1d3736a429.jpg', NULL, true, '2022-02-24 16:17:00+08', '2022-02-24 16:17:00+08', '2022-02-24 16:17:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '285958');
INSERT INTO public.news VALUES (859, '笃行不怠勤耕耘，踵事增华开新篇——新航实验召开新学期全体教职工大会', '', '听春风在耳，一元复始；看春色清和，万象更新。充实愉快的假期匆匆而过，新的学期已款款走来，2月14日，济南新航实验外国语学校2021-2022学年第二学期全体教职工大会在新航剧院召开。山东省实验中学党委委员、东校校长，济南新航实验外国语学校党总支书记、执行校长林宝磊与全体教职工一同开启崭新的篇章，共赴新的征程。“回望刚刚过去的2021年，新航实验全体师生同心同德、团结协作，始终致力于教育教学的提升和...', '', '<section><p><a href="images/67d3abe65ad84e979ba8ecf01b47b5b8.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/67d3abe65ad84e979ba8ecf01b47b5b8.jpg"/></a></p><p><span>听春风在耳，一元复始；看春色清和，万象更新。充实愉快的假期匆匆而过，新的学期已款款走来，2月14日，济南新航实验外国语学校2021-2022学年第二学期全体教职工大会在新航剧院召开。山东省实验中学党委委员、东校校长，济南新航实验外国语学校党总支书记、执行校长林宝磊与全体教职工一同开启崭新的篇章，共赴新的征程。</span></p></section><p><section><section><section><section><section><section></section></section></section></section><section><section><section></section></section></section></section></section></p><p><a href="images/e37a5cba40894f11ae09646499c103c4.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e37a5cba40894f11ae09646499c103c4.jpg"/></a><a href="images/10b7241136314832899f2889958889f3.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/10b7241136314832899f2889958889f3.jpg"/></a></p><p><span>“回望刚刚过去的2021年，新航实验全体师生同心同德、团结协作，始终致力于教育教学的提升和学生的全面发展。”大会上，林宝磊校长从做“精”功、亮“实”招、施“细”策三个方面对学校2021年工作进行总结，同时指出，学校已经进入稳健发展和内涵提升的新阶段，要落实“立德树人”根本任务，继续夯实课程建设、提升教学质量，深挖内涵发展根技术，秉承“以生为本、以师立校”宗旨，向家长和社会交上一份满意的答卷。</span></p><p><a href="images/66a345e612a44c859135b495525e9e52.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/66a345e612a44c859135b495525e9e52.jpg"/></a><span>、</span></p><p><span>追梦需要激情和理想，圆梦需要奋斗和奉献。我们唯有不断探索、不断创新、不断实践，用辛勤付出的汗水、兢兢业业的坚守、专业专注的精神，上下一心、知难勇进，才不负这昂扬奋进的新时代。</span></p><p><span>过去已去，未来已来，愿全体新航实验人，一路向前，一路追光，不负期待，未来继续同行！</span></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//67d3abe65ad84e979ba8ecf01b47b5b8.jpg', NULL, true, '2022-02-23 16:47:00+08', '2022-02-23 16:47:00+08', '2022-02-23 16:47:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '285863');
INSERT INTO public.news VALUES (860, '惊喜+感动+祝福——新航实验初中部老师又为学生们悄悄策划了一场创意“快闪”', '', 'var flashvars={ f:"/media/0/f50fb71cb0994050a432ffc3c8b5f546.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; CKobject.embedSWF("/modul...', '', '<div>
 <div id="mediaContent0_0"></div> 
 <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
 <script type="text/javascript">
    var flashvars={
        f:"/media/0/f50fb71cb0994050a432ffc3c8b5f546.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    
    CKobject.embedSWF("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",flashvars,params);
    
    var support=[''iPad'',''iPhone'',''ios'',''android+false'',''msie10+false''];
    var video=["/media/0/f50fb71cb0994050a432ffc3c8b5f546.mp4->video/mp4"];
    CKobject.embedHTML5("mediaContent0_0","ckplayer_mediaContent0_0","400","300",video,flashvars,support);
</script>
</div>
<p><a href="images/cbfc87609acb42a0bc4e3a38055bc73e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/cbfc87609acb42a0bc4e3a38055bc73e.jpg"></a><a href="images/3f6e534833a442879a0d2e74c7ceb26f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/3f6e534833a442879a0d2e74c7ceb26f.jpg"></a></p>
<p><span>“新年新气象，2022加油！”</span></p>
<p><span>“老师给你点个赞，希望你继续保持学习的激情，衷心祝福你在期末绽放属于自己的精彩！”</span></p>
<p><span>“自信加油、逢考必过”……</span></p>
<p><span>一张张写有班主任和任课老师祝福的纸条，被塞进福袋中。近日，新航实验初中部每逢期末总是会出现的保留项目——“快闪”活动如期举行，50余位老师手拿福袋，在教学楼外等待着下课铃声的响起。</span></p>
<p><a href="images/0976bc09695c4ec5b73e9d3f2895f9e8.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/0976bc09695c4ec5b73e9d3f2895f9e8.jpg"></a><a href="images/34be9eb7916b4b5c8e2779bf60125cfd.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/34be9eb7916b4b5c8e2779bf60125cfd.jpg"></a><a href="images/d5c588388da24462a1053804c8459ec3.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/d5c588388da24462a1053804c8459ec3.jpg"></a><a href="images/9c43aad108744a2295d4f5f2e49bd451.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/9c43aad108744a2295d4f5f2e49bd451.jpg"></a></p>
<p><span>中午放学的铃声响起，刚走出教学楼的学生们看到眼前的“豪华阵容”很是惊讶，人群中爆发出一阵阵欢呼声。尽管天气寒冷，被团团围住的老师们把祝福与鼓励送到每一位初中学子的手中，在这个冬季驱散了寒风，把温暖与关爱送进了学生们的心里。&nbsp;</span></p>
<p><span><a href="images/d3ebad52aa5c4ab39eb069de14ec08ac.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/d3ebad52aa5c4ab39eb069de14ec08ac.jpg"></a><a href="images/f4b498a7826b496c9e0ae5c27e481328.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/f4b498a7826b496c9e0ae5c27e481328.jpg"></a><a href="images/af20c4286c0e4481971f7da0b1757f44.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/af20c4286c0e4481971f7da0b1757f44.jpg"></a><a href="images/f5efc6f602af46d985fa4167ef7476fa.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/f5efc6f602af46d985fa4167ef7476fa.jpg"></a></span></p>
<p><span>当一个个学生打开老师们为他们准备的红包时，更是惊奇地发现，里面不仅有鼓励和祝福的话语，居然还有最爱的“新航学币”，冬日的新航实验校园顿时充满了欢声笑语……</span></p>
<p><span><a href="images/6b85d0bbbcc34696bd2f89327fd123ff.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6b85d0bbbcc34696bd2f89327fd123ff.jpg"></a><a href="images/b827d55e3b26406b96713f1a4ac7c86d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/b827d55e3b26406b96713f1a4ac7c86d.jpg"></a></span></p>
<p><span>尽管活动只有短短的几分钟时间，不仅释放了同学们期末备考的紧张情绪，老师们亲手传递的这份暖暖的鼓励，也让每一个孩子都收获了一份关注和温暖。&nbsp;&nbsp;</span></p>
<p><span><br></span></p><meta name="ContentStart"/>', '', 'campus', '/uploads/migration/images/f=/media/0/f50fb71cb0994050a432ffc3c8b5f546.mp4', NULL, true, '2022-01-14 17:49:00+08', '2022-01-14 17:49:00+08', '2022-01-14 17:49:00+08', '赵昕晨', '新航实验外国语学校', '学生 实验 初中部 老师 新航', '284460');
INSERT INTO public.news VALUES (861, '美，在身边绽放——走进新航实验办公室，寻找老师们心中的诗与远方', '', '在你的印象里，老师的办公室是什么样子？是单调沉闷？还是堆满试卷作业的杂乱和压抑？在新航实验，每一个老师办公室都是不一样的画风！一抹清新的绿色、一张张整洁的桌面、一面面会说话的墙、一处处温暖的角落，代表着新航实验老师们一颗颗澄明的心，老师们在这里收获育人的喜悦、见证学生的成长。作为学校常规管理与校园文化的展示窗口，办公室文化是一种氛围、一种精神，更是一种境界，体现了教师的精神面貌、素质修养与文化品位...', '', '<p><a href="images/15d51bc5957f448c925bbe96340f7082.jpg" target="_blank"><img title="0.jpg" src="/uploads/migration/images/15d51bc5957f448c925bbe96340f7082.jpg"/></a></p><p><span>在你的印象里，老师的办公室是什么样子？是单调沉闷？还是堆满试卷作业的杂乱和压抑？在新航实验，每一个老师办公室都是不一样的画风！</span></p><p><span>一抹清新的绿色、一张张整洁的桌面、一面面会说话的墙、一处处温暖的角落，代表着新航实验老师们一颗颗澄明的心，老师们在这里收获育人的喜悦、见证学生的成长。</span></p><p><span>作为学校常规管理与校园文化的展示窗口，办公室文化是一种氛围、一种精神，更是一种境界，体现了教师的精神面貌、素质修养与文化品位，让原本紧张的期末备考氛围，充满了温暖和力量。</span></p><p><span>在日常工作和交流中，教师们利用业余时间精心构思、创意设计，从文化氛围、物品摆放、清洁卫生、精神风貌等方面进行全方位设计，让办公室变得整洁温馨、舒适雅致、布置合理、各具特色，处处体现了新航实验老师们丰富的精神涵养、多姿多彩的审美情趣和对工作生活的热爱。一起来看看吧</span></p><p><a href="images/64bbdef6ebee49d397002bd23fc428be.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/64bbdef6ebee49d397002bd23fc428be.jpg"/></a><a href="images/b24b21c44ad04b88a0e26998fc30cf0d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/b24b21c44ad04b88a0e26998fc30cf0d.jpg"/></a><a href="images/ad2aecf1f37f483c933ca15df5a08f3a.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/ad2aecf1f37f483c933ca15df5a08f3a.jpg"/></a><a href="images/12345d5a73f3462a8c218a0fb291d4a5.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/12345d5a73f3462a8c218a0fb291d4a5.jpg"/></a><a href="images/e98c1e836cd6489ba39208e43dce5b74.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/e98c1e836cd6489ba39208e43dce5b74.jpg"/></a><a href="images/3d8146d1013f48d2bda5fd52b6916909.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/3d8146d1013f48d2bda5fd52b6916909.jpg"/></a><a href="images/7123e0d1cce64c9ba65ef66c617c052f.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/7123e0d1cce64c9ba65ef66c617c052f.jpg"/></a><a href="images/de2d7fd20bce492f8c605d0ec4625c75.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/de2d7fd20bce492f8c605d0ec4625c75.jpg"/></a><a href="images/2c8839e7152b4dd5a65978abe346cf64.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/2c8839e7152b4dd5a65978abe346cf64.jpg"/></a><a href="images/b1ade11fead7413ba96df09218f87343.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/b1ade11fead7413ba96df09218f87343.jpg"/></a></p><p><a href="images/03dbccb6b23b47189429b43de9bc0d61.jpg" target="_blank"><img title="11.webp.jpg" src="/uploads/migration/images/03dbccb6b23b47189429b43de9bc0d61.jpg"/></a><a href="images/dee35fd5ab2f4bfea8170aa90a7f8d9a.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/dee35fd5ab2f4bfea8170aa90a7f8d9a.jpg"/></a><a href="images/0bc57a043c0b476d8ea854e9416cd069.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/0bc57a043c0b476d8ea854e9416cd069.jpg"/></a><a href="images/ecc247ccf041466faf41d681928b870a.jpg" target="_blank"><img title="14.jpg" src="/uploads/migration/images/ecc247ccf041466faf41d681928b870a.jpg"/></a><a href="images/f348886812cc46da93574516763b9820.jpg" target="_blank"><img title="15.jpg" src="/uploads/migration/images/f348886812cc46da93574516763b9820.jpg"/></a></p><p><a href="images/7adf4684d1fc47bba6f872e75302e4cf.jpg" target="_blank"><img title="16.jpg" src="/uploads/migration/images/7adf4684d1fc47bba6f872e75302e4cf.jpg"/></a><a href="images/74f296483aa74053a75b4c290e80754f.jpg" target="_blank"><img title="17.jpg" src="/uploads/migration/images/74f296483aa74053a75b4c290e80754f.jpg"/></a><a href="images/ee1644355f1f4d649a55b9c3737530e1.jpg" target="_blank"><img title="18.jpg" src="/uploads/migration/images/ee1644355f1f4d649a55b9c3737530e1.jpg"/></a><a href="images/fc8d6b0403f147789814605a8560ea74.jpg" target="_blank"><img title="19.jpg" src="/uploads/migration/images/fc8d6b0403f147789814605a8560ea74.jpg"/></a><a href="images/bea8d0b2c6714d5da9da49e4dd9d866e.jpg" target="_blank"><img title="20.jpg" src="/uploads/migration/images/bea8d0b2c6714d5da9da49e4dd9d866e.jpg"/></a></p><p><a href="images/d5798c9c72d140b69b55eff225c42cde.jpg" target="_blank"><img title="21.jpg" src="/uploads/migration/images/d5798c9c72d140b69b55eff225c42cde.jpg"/></a><a href="images/d697bc0b62df494289475468b031729f.jpg" target="_blank"><img title="22.jpg" src="/uploads/migration/images/d697bc0b62df494289475468b031729f.jpg"/></a><a href="images/9c49cfd95b8b42a5a833d22e22370510.jpg" target="_blank"><img title="23.jpg" src="/uploads/migration/images/9c49cfd95b8b42a5a833d22e22370510.jpg"/></a><a href="images/ff55bfbfb37f48b9bb5777e38252083a.jpg" target="_blank"><img title="24.jpg" src="/uploads/migration/images/ff55bfbfb37f48b9bb5777e38252083a.jpg"/></a><a href="images/c4bf238b1ab644c0bc4cfe3fd59d9f69.jpg" target="_blank"><img title="25.jpg" src="/uploads/migration/images/c4bf238b1ab644c0bc4cfe3fd59d9f69.jpg"/></a><a href="images/3660af17d3894aba8184bed3fd1f8455.jpg" target="_blank"><img title="26.jpg" src="/uploads/migration/images/3660af17d3894aba8184bed3fd1f8455.jpg"/></a><a href="images/219026d13dce4986929a09853e1bd054.jpg" target="_blank"><img title="27.jpg" src="/uploads/migration/images/219026d13dce4986929a09853e1bd054.jpg"/></a><a href="images/17466399245d473c92a80e404d0fc731.jpg" target="_blank"><img title="28.jpg" src="/uploads/migration/images/17466399245d473c92a80e404d0fc731.jpg"/></a></p><section><section><section><p><span>最美办公室&nbsp;</span></p></section></section></section><p></p><section><p><br/></p></section><section><section><p><span>眼前就是诗，何必惦念远方！小小的方寸之地，因为一份用心而变得更加美丽温馨。</span></p><p><span>在新航实验，持续推进“最美办公室”评选，打造各具特色的办公室文化，不仅为老师们提供了舒适的工作环境，也在潜移默化中影响着学生们，以点滴之力塑造着和谐奋进、积极向上的家园。</span></p></section></section><p></p><p><span><br/></span><br/></p><meta name="ContentStart"/>', '', 'news', '/uploads/migration/images//15d51bc5957f448c925bbe96340f7082.jpg', NULL, true, '2022-01-14 17:31:00+08', '2022-01-14 17:31:00+08', '2022-01-14 17:31:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '284457');
INSERT INTO public.news VALUES (862, '喜报：三个省一、十个省二，新航实验学子在第五届山东省创客大赛中再创辉煌', '', '在2021年最后一天，新航实验再次收到喜报，经过二周的鏖战，在前不久刚刚落幕的2021年第五届山东省青少年创客大赛暨第四届山东省青少年电子信息智能创新大赛总决赛中，我校李长健、陈俊羽、兰宇轩三位初中学生获编程挑战赛C++组一等奖，隆正熙、田宸玮等9名同学获得编程挑战赛C++组二等奖，刘烨诚获无人机先锋大赛项目比赛二等奖。本次大赛由中国电子学会、山东省科学技术协会作为指导单位，山东电子学会组织实施。...', '', '<section><section><p><a href="images/c2e14ba0793948368f21337fbe329f00.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/c2e14ba0793948368f21337fbe329f00.jpg"/></a></p><p><span>在2021年最后一天，新航实验再次收到喜报，经过二周的鏖战，在前不久刚刚落幕的2021年第五届山东省青少年创客大赛暨第四届山东省青少年电子信息智能创新大赛总决赛中，我校李长健、陈俊羽、兰宇轩三位初中学生获编程挑战赛C++组一等奖，隆正熙、田宸玮等9名同学获得编程挑战赛C++组二等奖，刘烨诚获无人机先锋大赛项目比赛二等奖。</span></p><p><a href="images/aa73bc22df48455cb3120ddaaa1e1527.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/aa73bc22df48455cb3120ddaaa1e1527.jpg"/></a></p><p><span>本次大赛由中国电子学会、山东省科学技术协会作为指导单位，山东电子学会组织实施。共有来自全省16地市的近5500名师生参加了此次线上、线下赛，我校因在编程挑战赛C++、无人机先锋赛两个项目的比赛中成绩斐然，被授予“优秀组织”奖。</span></p><p><span>山东省创客大赛自2017年创办以来，激发了青少年的科学兴趣与科学梦想，培养了青少年的创新思维与协作意识，提升了青少年发现问题并解决问题的实践能力。为广大青少年、科技爱好者提供了切磋技艺、展示交流的舞台，逐渐成为许多高校发现人才、选拔人才的重要平台和渠道。</span></p><p><a href="images/3be1fca089ad40dbae9dd4342e603c63.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/3be1fca089ad40dbae9dd4342e603c63.jpg"/></a></p></section></section><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/c2e14ba0793948368f21337fbe329f00.jpg', NULL, true, '2022-01-14 08:00:00+08', '2022-01-14 08:00:00+08', '2022-01-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (863, '新航实验召开党总支成立大会，选举产生新一届党总支委员', '', '2021年12月31日下午，济南新航实验外国语学校召开全体党员大会，此次大会主要议程是成立中共济南新航实验外国语学校总支部委员会，并选举产生新一届总支委员。市委教育工委学校党建处处长杨林出席会议并讲话，新航实验全体党员参加会议，张术磊副校长主持会议。会议在庄严的国歌声中拉开序幕，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊代表党支部作了题为《践行初心使命，勇毅前行推进学校高质量发展...', '', '<p><a href="images/e852cb41911e45e3b4329a2e640158b5.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e852cb41911e45e3b4329a2e640158b5.jpg"/></a></p><p><span>2021年12月31日下午，济南新航实验外国语学校召开全体党员大会，此次大会主要议程是成立中共济南新航实验外国语学校总支部委员会，并选举产生新一届总支委员。市委教育工委学校党建处处长杨林出席会议并讲话，新航实验全体党员参加会议，张术磊副校长主持会议。</span></p><p><span><img title="2.jpg" src="/uploads/migration/images/099100e9fdd3494da5ec1c14fb9e6744.jpg"/></span></p><p><span>会议在庄严的国歌声中拉开序幕，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊代表党支部作了题为《践行初心使命，勇毅前行推进学校高质量发展》的工作报告，系统总结了党支部成立以来的主要工作及取得的成绩，明确了未来工作努力的方向和任务。</span></p><p><a href="images/8f62bf0fa9db48ee95d5956766e1c67f.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/8f62bf0fa9db48ee95d5956766e1c67f.jpg"/></a><a href="images/c8636f8b07ab4c51a658d181c3847eb1.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/c8636f8b07ab4c51a658d181c3847eb1.jpg"/></a></p><section><p><span>随后，大会审议表决通过了选举办法和总支委员会委员候选人名单。与会正式党员以无记名投票方式，差额选举产生了中共济南新航实验外国语学校总支部委员会新一届委员。</span></p></section><p><a href="images/18797ccd344b443fb80db0a8a6e30f1a.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/18797ccd344b443fb80db0a8a6e30f1a.jpg"/></a></p><p><span>最后，市委教育工委学校党建处杨林处长总结讲话，他对新航实验党总支成立大会的圆满召开表示热烈祝贺，对学校近年来的党建工作给予充分肯定，并对新一届党总支委员进一步做好党建工作提出明确具体的要求。希望学校新一届党总支委员带领全体党员继续发挥好基层组织战斗堡垒作用，引导党员干部加强政治理论学习，不断提高党建工作实效，努力开创学校发展新局面。</span></p><p><span><a href="images/61d6ed6c3ee248a0ae3d8d46f8b98f57.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/61d6ed6c3ee248a0ae3d8d46f8b98f57.jpg"/></a></span></p><p><span></span></p><section><p><span>大会圆满完成各项议程，在雄壮的国际歌中落下帷幕。会后，新当选的总支委员会委员召开第一次全体委员会议，选举林宝磊同志为党总支书记，讨论确定了委员工作分工等相关事项，明确各自职责，压实主体责任。</span></p></section><p><section><p><span>此次选举工作组织严密、程序规范、进展顺利，全体党员受到了一次严肃、认真、民主的党内政治生活教育。学校新一届党总支班子将赓续立德树人初心，勇担为党育人、为国育才使命，同心同德、同向同行，不断开拓创新，办好人民满意的教育，圆满解答新时代赋予的全新答卷，奋力开创新航实验高质量发展的新局面!</span></p><div><span><br/></span></div></section></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/e852cb41911e45e3b4329a2e640158b5.jpg', NULL, true, '2022-01-14 08:00:00+08', '2022-01-14 08:00:00+08', '2022-01-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (864, '喜报！新航实验5名学生入选中学生“英才计划”', '', '12月21日，英才计划山东省管理办公室公布了2022年山东省“英才计划”入选学生名单，新航实验学子再创佳绩，程鲁毅、王鹏博、李梓赫、潘文栋、朱学硕5位同学榜上有名。经中学推荐、省级初审、学科潜质测试、导师面试等阶段的工作，确定59名同学入选2022年山东省“英才计划”正式学员，18名同学入选省级学员。其中，新航实验高一学生程鲁毅（数学学科）、王鹏博（化学学科）入选正式学员名单，李梓赫（物理学科）、...', '', '<p></p><p><span><a href="images/12861c003417433da3fd43225ee72b91.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/12861c003417433da3fd43225ee72b91.jpg"/></a></span></p><p><span>12月21日，英才计划山东省管理办公室公布了2022年山东省“英才计划”入选学生名单，新航实验学子再创佳绩，程鲁毅、王鹏博、李梓赫、潘文栋、朱学硕5位同学榜上有名。</span></p><p><span>经中学推荐、省级初审、学科潜质测试、导师面试等阶段的工作，确定59名同学入选2022年山东省“英才计划”正式学员，18名同学入选省级学员。其中，新航实验高一学生程鲁毅（数学学科）、王鹏博（化学学科）入选正式学员名单，李梓赫（物理学科）、潘文栋（计算机学科）、朱学硕（计算机学科）入选省级学员名单。</span></p><p><span>为贯彻落实《国家中长期教育改革和发展规划纲要(2010-2020)》有关要求，建立高校与中学联合发现和培养青少年科技创新人才的有效方式，中国科协和教育部自2013年开始共同组织实施中学生科技创新后备人才培养计划(简称“英才计划”)，旨在选拔一批品学兼优、学有余力的中学生走进大学，在自然科学基础学科领域著名科学家指导下参加科学研究、学术研讨和科研实践，发现一批具有学科特长、创新潜质的优秀中学生，为“基础学科拔尖学生培养计划”输送后备力量。</span></p><p><span>新航实验高度重视学生创新意识和创新能力的培养，围绕2022年“英才计划”的报名组织、选拔推荐，教学管理中心牵头配合山东省科协在高一年级学生中广泛宣传，通过个人申请、综合考察等环节，一批意志坚定、品行端正、成绩优异、热爱科学的学生踊跃报名，他们在省级选拔笔试、面试中也充分展示了新航实验学子的风采。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/12861c003417433da3fd43225ee72b91.jpg', NULL, true, '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (865, '喜报！新航实验获评信息学竞赛金牌学校和科普创新基地', '', '近日，山东省2021年信息学总结表彰大会在山东平邑举行，新航实验因在省信息学竞赛中成绩突出，被授予“科普创新基地”和“金牌学校”荣誉称号，这是我校连续第二年获“金牌学校”殊荣。表彰大会上，作为唯一的初中学校优秀教练代表，李想老师做了题为《小学初中高中贯通培养》的典型发言，分享了新航实验在人才培养模式方面的创新做法。本次表彰大会，全省8所学校被授予山东省信息学奥林匹克“科普创新基地”，59所学校被授...', '', '<p><a href="images/0d6b77ae32044a8fb5d74072cd8dd300.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/0d6b77ae32044a8fb5d74072cd8dd300.jpg"/></a></p><p><span>近日，山东省2021年信息学总结表彰大会在山东平邑举行，新航实验因在省信息学竞赛中成绩突出，被授予“科普创新基地”和“金牌学校”荣誉称号，这是我校连续第二年获“金牌学校”殊荣。</span></p><p><a href="images/2a6195156af8445b8186b07a21ef2f11.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/2a6195156af8445b8186b07a21ef2f11.jpg"/></a></p><p><span>表彰大会上，作为唯一的初中学校优秀教练代表，李想老师做了题为《小学初中高中贯通培养》的典型发言，分享了新航实验在人才培养模式方面的创新做法。</span></p><p><a href="images/5cb7ea9c5bee4563befdb0bb98ee7d5c.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/5cb7ea9c5bee4563befdb0bb98ee7d5c.jpg"/></a></p><p><span>本次表彰大会，全省8所学校被授予山东省信息学奥林匹克“科普创新基地”，59所学校被授予“金牌学校”，新航实验均榜上有名。与此同时，李想、高福娜、王雪、张元霞、孟瑞琪等五位老师被评为“山东省信息学奥赛优秀辅导教师”。</span></p><p><a href="images/82ad0aa5667b404da2cfb778fd1486e8.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/82ad0aa5667b404da2cfb778fd1486e8.jpg"/></a></p><p><span>自2019年建校以来，新航实验不断强化人才培养新模式，逐步形成完备的人才培养机制和学科竞赛团队，通过持续加强教师团队建设、做实个性化培养路径、系统规划特色教学，学科奥赛和科技创新已成为新航实验的闪亮名片，学生不同程度的研究性学习和个性化发展需求得以满足，创新精神和实践能力、科技素养得到快速提升。</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/0d6b77ae32044a8fb5d74072cd8dd300.jpg', NULL, true, '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (866, '“父母好好学习，孩子天天向上”——新航实验“家长学堂”继续开讲', '', '为帮助和引导家长树立正确的家庭教育理念，提升家庭教育水平、掌握科学家庭教育方法，实现教育成效的最优化，近日，新航实验“家长学堂”正式开讲，深入浅出的理论指引、发人深思的案例分享，吸引了首期学生家长自愿报名参加，有家长感慨“立志做一名认真刻苦的好学生”。讲座现场，中国首批家庭教育高级指导师、中国百强心理咨询师贾玉文老师引经据典，深入浅出，结合自己的育儿经验及身边事例，从教育的规律、亲子教育的黄金法则...', '', '<p><span>为帮助和引导家长树立正确的家庭教育理念，提升家庭教育水平、掌握科学家庭教育方法，实现教育成效的最优化，近日，新航实验“家长学堂”正式开讲，深入浅出的理论指引、发人深思的案例分享，吸引了首期学生家长自愿报名参加，有家长感慨“立志做一名认真刻苦的好学生”。</span></p><p><span><a href="images/444f59e84fd0441087f38a567ed52054.png" target="_blank"><img title="微信截图_20220107162155.png" src="/uploads/migration/images/444f59e84fd0441087f38a567ed52054.png"/></a></span></p><p><span>讲座现场，中国首批家庭教育高级指导师、中国百强心理咨询师贾玉文老师引经据典，深入浅出，结合自己的育儿经验及身边事例，从教育的规律、亲子教育的黄金法则、抓住教育的黄金时期三个方面，详细分析了家庭教育的重要性以及如何做一位智慧父母。家长们还结合自身教育孩子存在的困惑与贾老师现场交流，贾老师都分别进行了详尽解答。</span></p><p><span><a href="images/a67db0caa2ff4574b786d05e35f54e12.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/a67db0caa2ff4574b786d05e35f54e12.jpg"/></a></span></p><p><span>12月23日，贾玉文老师以《学习力提升系统》为题，向家长们详细阐述了新时代科学育儿观。寥寥数语但又恰到好处地切入了当晚的课程，“动物有本能，机器有智能，人类有慧能。学的是知识，习的是体验，小学阶段一定要让孩子去发展兴趣。”贾老师说道，人工智能时代，虽然可以替代老师们的付出，但却永远取代不了对学生的爱，教育的核心就一个字——爱！“我们常说自己爱孩子，但其实很多人不知道怎么去爱，只是在盲目爱孩子。”</span></p><p><span><a href="images/318ac03c89084d079e8517a0b67626a2.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/318ac03c89084d079e8517a0b67626a2.jpg"/></a></span></p><p><span></span></p><p><span>紧接着，贾老师和家长们探讨了生命力和学习力，学习力是一个人在学习方面的能力、动力和综合体现，“包括三要素——能力、动力和毅力，没有能力走不动，没有动力走不远，没有毅力走不久。学习毅力就是意志力，知识是学习而来，毅力是磨练而来。”<span>他用理论与实践相结合的方式，帮助家长补上了孩子成长和家族发展必备的“正确爱孩子”这堂课。</span></span></p><p><span>他提醒家长们，家庭教育是生命影响、唤醒生命的过程，帮助家长从源头上唤醒了如何提升教育孩子的综合能力，为达到教育的终极目的——让孩子拥有幸福的能力奠定了基础。</span></p><p><span>贾老师的讲座不仅具有理论的高度，还提供了具体操作的方法技巧，大大增强了父母的教育信心，提升了父母对孩子的教育能力。讲座过程中，掌声阵阵，家长们的心中也涌动起教育激情！</span></p><p><span><a href="images/efc48ce1f1bc40c0bcf9f67abb31748f.png" target="_blank"><img title="微信截图_20220107162259.png" src="/uploads/migration/images/efc48ce1f1bc40c0bcf9f67abb31748f.png"/></a></span></p><p><span><br/></span><span>&nbsp; &nbsp; 新航实验“家长学堂”为系列课程，每两周一次课，一期共十次课程。课程的开设，不仅致力于提升家长的教育观念，也彰显新航实验的教育理念，帮助更多学生家长系统学习家庭教育相关理论与育人方式，以教育改善家庭，让家庭助力教育，家校携手，共同助力新航实验学子的美好明天。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/444f59e84fd0441087f38a567ed52054.png', NULL, true, '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '2022-01-07 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (867, '“包”你满意，爱你在“新”——新航实验举办“迎冬至 暖寒冬”花式包饺子大赛', '', '冬至，是中国农历中一个重要的节气，也是中华民族的一个传统节日。近日，新航实验校园里热闹非凡，初高中学生和部分家长正在学生餐厅里忙碌着，物业保安、保洁、宿管、食堂职工都陆续收到了学生们专门送来的惊喜礼物——一盒热气腾腾的水饺、几句真挚朴素的问候、几个暖心的微笑，新航实验学子用自己的感恩和爱心，温暖着校园里的每一个人，连平日里最默默无闻的工作人员，也被学生们这份真挚的关心而深深感动。 为丰富学生校园文...', '', '<p><span>冬至，是中国农历中一个重要的节气，也是中华民族的一个传统节日。近日，新航实验校园里热闹非凡，初高中学生和部分家长正在学生餐厅里忙碌着，物业保安、保洁、宿管、食堂职工都陆续收到了学生们专门送来的惊喜礼物——一盒热气腾腾的水饺、几句真挚朴素的问候、几个暖心的微笑，新航实验学子用自己的感恩和爱心，温暖着校园里的每一个人，连平日里最默默无闻的工作人员，也被学生们这份真挚的关心而深深感动。</span></p>
<p><span>为丰富学生校园文化生活、传承中华传统文化习俗、搭建亲子互动平台、倡导共享友爱的校园氛围，新航实验举行了一场主题为“迎冬至 暖寒冬”的花式包饺子大赛</span>。</p>
<p><a href="images/6c9835bd56f144f4aecf250769b63092.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6c9835bd56f144f4aecf250769b63092.jpg"></a></p>
<p>
