INSERT INTO public.news VALUES (868, '逐梦冬日，师生同跑——新航实验小学部开展冬季校园越野跑', '', '为增强学生体质，培养学生顽强的毅力、坚强的意志，进一步激发师生的体育运动热情，近日，新航实验小学部组织全体师生开展了冬季校园越野跑活动，以健康的方式和昂扬的姿态跑步迎接崭新的每一天。在活动开始前，体育组老师根据新航实验特有的地理优势和学生的年龄特点周密安排，为一、二年级设定了不同的越野长跑路线，认真组织跑前安全教育和热身运动。当冬日的暖阳洒向新航实验校园时，学生们在终点蓄势待发，随着一声哨响，纷纷...', '', '<p><a href="images/d12bf0b36e104c2f929fb1d37226446c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/d12bf0b36e104c2f929fb1d37226446c.jpg"/></a></p><p><span>为增强学生体质，培养学生顽强的毅力、坚强的意志，进一步激发师生的体育运动热情，近日，新航实验小学部组织全体师生开展了冬季校园越野跑活动，以健康的方式和昂扬的姿态跑步迎接崭新的每一天。</span></p><p><a href="images/c6611e74af14473cb4df749c46a62bbe.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/c6611e74af14473cb4df749c46a62bbe.jpg"/></a></p><p><span>在活动开始前，体育组老师根据新航实验特有的地理优势和学生的年龄特点周密安排，为一、二年级设定了不同的越野长跑路线，认真组织跑前安全教育和热身运动。当冬日的暖阳洒向新航实验校园时，学生们在终点蓄势待发，随着一声哨响，纷纷冲出。坚定、执着、耐力与希望，在延伸的跑道中点点凝聚！力量、信念、拼搏与奋斗，在遥远的终点线上渐渐明亮！寒冷的天气阻挡不住小航们奔跑的热情，汗水与笑容流淌在他们的脸庞，强健的步伐和不言放弃的精神将冬天的新航实验校园扮靓。</span></p><p><span><a href="images/2305c6c1e416413483aaa5bd5383894b.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/2305c6c1e416413483aaa5bd5383894b.jpg"/></a></span></p><p><span>作为小学部“乐健”体育特色课程的一个缩影，冬季越野跑活动秉持“挑战自我，坚持不懈；乐享运动，强身健体”的口号，鼓励学生们用双脚丈量美丽校园，以顽强的信念和蓬勃的力量，在越野跑中领略运动的魅力，感受体育的激情与快乐。</span></p><p><span><a href="images/53ae3dd9308a49cd8d97bb3de9fc53ff.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/53ae3dd9308a49cd8d97bb3de9fc53ff.jpg"/></a></span></p><p><span><a href="images/92a252c5680b46a69aacf0c9ab5c6ffe.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/92a252c5680b46a69aacf0c9ab5c6ffe.jpg"/></a></span></p><p><span>文明其精神、野蛮其体魄，小航们以实际行动诠释着“更高、更快、更强”的体育精神，期待着他们经历锤炼后长成傲人的参天大树！</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/d12bf0b36e104c2f929fb1d37226446c.jpg', NULL, true, '2021-12-17 08:00:00+08', '2021-12-17 08:00:00+08', '2021-12-17 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (869, '喜报！新航实验王云剑老师被认定为第三期济南名师', '', '为充分发挥名师在教师队伍建设中的示范引领作用，12月7日，济南市教育局公布第三期济南名师名单，经过三年周期培养，济南新航实验外国语学校高中部王云剑老师被认定为第三期济南名师。济南名师建设工程是济南市培养高素质教师队伍和管理队伍的一项重要措施，历经三年多的培养，通过学习、培训、跟岗、课题、答辩等多环节严格考核，济南市教育局最终认定117名教师为第三期济南名师。在济南新航实验外国语学校，王云剑老师是学...', '', '<p><span>为充分发挥名师在教师队伍建设中的示范引领作用，12月7日，济南市教育局公布第三期济南名师名单，经过三年周期培养，济南新航实验外国语学校高中部王云剑老师被认定为第三期济南名师。</span></p><p><a href="images/a15905106c7642fab9a8c09df5a52a12.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/a15905106c7642fab9a8c09df5a52a12.jpg"/></a></p><p><span>济南名师建设工程是济南市培养高素质教师队伍和管理队伍的一项重要措施，历经三年多的培养，通过学习、培训、跟岗、课题、答辩等多环节严格考核，济南市教育局最终认定117名教师为第三期济南名师。</span></p><p><span><a href="images/778322d54c704a18aab59e7a2c956673.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/778322d54c704a18aab59e7a2c956673.jpg"/></a></span><br/></p><section><section><section><section><section><p><span>在济南新航实验外国语学校，王云剑老师是学生们心中的“魅力女神”，亦师亦友、温雅睿智、追求卓越、逻辑清晰是她的鲜明风格。任教24年来，连续多年担任数学教研组长，作为济南市高中数学中心组成员、济南市数学文化与学法指导中心主任，连续多年从事教科研和教学改革工作，致力于青年教师培养、学科组建设、智慧空间项目和校本课程等，在数学教学、数学文化、命题研究以及教师专业发展方面有丰富的经验和心得。</span></p><p><span>在王云剑老师的课堂上，每一名学生都能全神贯注，她总能把晦涩难懂的数学知识深入浅出地传授给每一位学生。课堂教学风格多样、有趣，注重挖掘数学知识背后的深层次文化价值和思想方法，并且以学生喜爱的方式呈现，把数学冰冷的美丽转化为火热的思考。</span></p><p><span>正是凭借扎实的专业功底，王云剑老师先后荣获济南市总工会建功立业先进个人、济南市教育科研先进个人、济南市教育科学优秀成果奖、济南市优质课比赛一等奖等荣誉，被聘为山东省“互联网+教师专业发展”工作坊主持人，被评选为基础教育+互联网“名师伴我行”最受欢迎教师。</span></p></section></section></section></section></section><p></p><section><section><section><section><p><span>新航实验历来重视教师队伍建设，多措并举，搭建精彩纷呈交流平台，通过建设“教师成长学院”，营造教师合作发展的良好氛围，深入开展“青蓝工程”活动，不定期举办教研交流，打造了一支辛勤奉献、经验丰富、素质一流、精研善思的名师团队。</span></p></section></section></section></section><p></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/a15905106c7642fab9a8c09df5a52a12.jpg', NULL, true, '2021-12-14 08:00:00+08', '2021-12-14 08:00:00+08', '2021-12-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (870, '思辨启真知——新航实验第二届NSDA英语辩论赛顺利收官', '', '明事理、辨是非，一直是新航学子求学的指引，但今天，在新航辩论赛上，新航学子不仅“辨是非”，更要“辩是非”。24支辩论队针对此次辩论赛辩题“社交媒体究竟是利大于弊还是弊大于利”展开激烈交锋，唇枪舌剑、针锋相对，展现出了优秀的英语表达水平和逻辑思辨能力。本次辩论赛采取公共论坛式辩论，24支辩论队根据抽签结果进行两两对垒。经过两轮常规赛和一轮淘汰赛后，成绩最好的四队进入四强，争夺冠亚季军。随着比赛的不断...', '', '<p><a href="images/f0fff905fd0e4bfb910dae893c7de40c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f0fff905fd0e4bfb910dae893c7de40c.jpg"/></a></p><p><span>明事理、辨是非，一直是新航学子求学的指引，但今天，在新航辩论赛上，新航学子不仅“辨是非”，更要“辩是非”。24支辩论队针对此次辩论赛辩题“社交媒体究竟是利大于弊还是弊大于利”展开激烈交锋，唇枪舌剑、针锋相对，展现出了优秀的英语表达水平和逻辑思辨能力。</span></p><p><a href="images/dd14ea39579849be84791abd55864aea.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/dd14ea39579849be84791abd55864aea.jpg"/></a></p><p><span>本次辩论赛采取公共论坛式辩论，24支辩论队根据抽签结果进行两两对垒。经过两轮常规赛和一轮淘汰赛后，成绩最好的四队进入四强，争夺冠亚季军。随着比赛的不断推进，各辩论队也在不断成长。选手和搭档持续分析对手观点，不断对论点进行补充、修改，以期在下一轮找出对手论点的漏洞，一击即中。</span></p><p><a href="images/68bf9c15f6dd4f2a80d2ba73b1fea3ef.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/68bf9c15f6dd4f2a80d2ba73b1fea3ef.jpg"/></a><a href="images/3d719d55a0754c429f5751e142533f66.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/3d719d55a0754c429f5751e142533f66.jpg"/></a></p><p><span>最终，来自初中部的王艺睿、董千语组成的辩论队获得冠军，高中部高梵峪、徐瀚森队伍获得亚军，高中部江通、任舒予队伍和张越、郑子怡队伍获得季军。此外，王艺睿同学凭借缜密的逻辑思辨能力摘得“最佳辩手”称号。</span></p><p><img title="5.jpg" src="/uploads/migration/images/8662326245e94bc3873df98600026147.jpg"/></p><p><span>在整场辩论赛中，新航实验学子展现了新时代公民的必备素质——逻辑思辨能力，希望新航实验学子能够在辩论道路上收获受用一生的智慧。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/f0fff905fd0e4bfb910dae893c7de40c.jpg', NULL, true, '2021-12-14 08:00:00+08', '2021-12-14 08:00:00+08', '2021-12-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (871, '宪法进校园，法润少年心——新航实验开展“国家宪法日”法治讲座', '', '为弘扬宪法精神，维护宪法权威，提高中学生遵法、守法、学法、用法的法治意识，在第八个“国家宪法日”和第四个“宪法宣传周”到来之际，济南新航实验外国语学校特邀山东省高级人民法院刑一庭副庭长罗莹为师生们开设法治讲座，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊校长向罗庭长颁发“法治副校长”聘书。讲座中，罗莹庭长以“法安天下、德润人心”为题，从“道”“德”“法”“宪”的内涵讲起，...', '', '<p><a href="images/5d76e5bce63a4dcd9e18aa26bf3e7c20.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/5d76e5bce63a4dcd9e18aa26bf3e7c20.jpg"/></a></p><p><span>为弘扬宪法精神，维护宪法权威，提高中学生遵法、守法、学法、用法的法治意识，在第八个“国家宪法日”和第四个“宪法宣传周”到来之际，济南新航实验外国语学校特邀山东省高级人民法院刑一庭副庭长罗莹为师生们开设法治讲座，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊校长向罗庭长颁发“法治副校长”聘书。</span></p><p><span><a href="images/84ab2337ac64467fa0ddf1266eabe753.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/84ab2337ac64467fa0ddf1266eabe753.jpg"/></a><a href="images/e462ea58d38848f48a237b4aa697fb1a.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/e462ea58d38848f48a237b4aa697fb1a.jpg"/></a></span></p><p><span>讲座中，罗莹庭长以“法安天下、德润人心”为题，从“道”“德”“法”“宪”的内涵讲起，选取《民法典》《未成年保护法》《预防未成年人犯罪法》等相关法律法规，用生动鲜活的案例，教育引导大家学会用法律武器维护自身权益，正确看待和应对校园欺凌、校园贷、网络诈骗等现象，努力规避危险和伤害；积极承担法律责任和道德责任，文明使用网络，营建全社会知法、守法、用法的良好氛围。此外，罗庭长还以郭永怀等先进人物为榜样，激励大家弘扬革命传统、传承红色基因，努力成长为国家和社会的栋梁之才。</span></p><p><span><a href="images/4a04b3d8abfb4414ad80bb7601613fc9.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/4a04b3d8abfb4414ad80bb7601613fc9.jpg"/></a></span></p><p><span>正如习总书记在北京大学师生座谈会上所说，这就像穿衣服扣扣子一样，如果第一粒扣子扣错了，剩余的扣子都会扣错。青少年们应该知法学法懂法，这是青少年健康成长中不可缺少的重要一环。此次法治讲座既增强了新航实验学子明辨是非、遵纪守法的意识，又帮助同学们学会自我保护、合法抵御侵害，同时也大力推动了新航实验平安校园、法治校园的建设。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/5d76e5bce63a4dcd9e18aa26bf3e7c20.jpg', NULL, true, '2021-12-09 08:00:00+08', '2021-12-09 08:00:00+08', '2021-12-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (872, '团体成绩位列全省初中第一！新航实验3名初中生获全国信息学奥林匹克联赛一等奖', '', '在刚刚结束的全国青少年信息学奥林匹克联赛NOIP2021中，我校初中部3名同学在众多高中学生中脱颖而出，夺得一等奖，3名同学夺得二等奖，团体成绩位列全省初中第一名。在获得一等奖的学生中，初一年级成子谦位列全省39名（初中生中排名第2位），初二年级肖程耀全省74名（初中生中排名第6位），初二年级陈俊羽全省排名102名。获得二等奖的三位同学，分别是初二年级李长健、田宸玮、纪开来。另外，在NOIP前序C...', '', '<p><a href="images/288f4e83f1114c5e8941600ceee6e944.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/288f4e83f1114c5e8941600ceee6e944.jpg"/></a></p><p><span>在刚刚结束的全国青少年信息学奥林匹克联赛NOIP2021中，我校初中部3名同学在众多高中学生中脱颖而出，夺得一等奖，3名同学夺得二等奖，团体成绩位列全省初中第一名。</span></p><p><a href="images/bda5a81197154c1c8d3d03f77b2cefd2.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/bda5a81197154c1c8d3d03f77b2cefd2.jpg"/></a></p><p><br/></p><p><br/></p><section><section><p><span>在获得一等奖的学生中，初一年级成子谦位列全省39名（初中生中排名第2位），初二年级肖程耀全省74名（初中生中排名第6位），初二年级陈俊羽全省排名102名。获得二等奖的三位同学，分别是初二年级李长健、田宸玮、纪开来。</span></p><p><span>另外，在NOIP前序CSP二轮比赛中，李长健、肖程耀、成子谦、陈俊羽夺得提高组一等奖，隆正熙获得入门组一等奖。</span></p><p><a href="images/3fecbf0d0f46401cbc266cfd2aaf48ef.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/3fecbf0d0f46401cbc266cfd2aaf48ef.jpg"/></a></p><p><span>全国青少年信息学奥林匹克联赛(简称NOIP) 是一项面向全国青少年的信息学竞赛和普及活动，旨在向青少年普及计算机科学知识，自1995年至今已举办多次，每年由中国计算机学会统一组织。</span></p><p><br/></p></section></section><p><span></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/288f4e83f1114c5e8941600ceee6e944.jpg', NULL, true, '2021-12-09 08:00:00+08', '2021-12-09 08:00:00+08', '2021-12-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (873, '“英”你精彩，“语”你同唱——快来围观新航实验萌娃们的英文歌曲合唱大赛', '', '英文歌曲合唱大赛 var flashvars={ f:"/media/0/19106dfb9b5e44b2ab5628d425ff15be.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; var video=["/med...', '', '<p><span>英文歌曲合唱大赛</span></p>
<p><br></p>
<p>
 <div id="mediaContent0_0"></div> <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> <script type="text/javascript">
    var flashvars={
        f:"/media/0/19106dfb9b5e44b2ab5628d425ff15be.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/19106dfb9b5e44b2ab5628d425ff15be.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script></p>
<p><br></p>
<p><br></p>
<section>
 <section>
  <section>
   <p><span>想唱就唱，唱得响亮。</span></p>
   <p><span>不怕风雨的阻挡，</span></p>
   <p><span>快乐是我的能量，</span></p>
   <p><span>点亮自己的光芒，</span></p>
   <p><span>我们唱得响亮。</span></p>
  </section>
 </section>
</section>
<p><br></p>
<section>
 <section>
  <section>
   <section>
    <p><span>为营造浓厚的英语学习氛围，能激发同学们学习英语的兴趣，提高英语单词的标准发音和快速识记，近日，济南新航实验外国语学校小学部举行第一届“音乐之声”英文歌曲合唱比赛。</span></p>
   </section>
  </section>
 </section>
</section>
<p><br></p>
<p><a href="images/9d14eecbd4f245f680b30005f3cdd28c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/9d14eecbd4f245f680b30005f3cdd28c.jpg"></a></p>
<p><br></p>
<p><span>“童年，是一个个跳动不安的音符。</span></p>
<p><span>Childhood is a restless note.</span></p>
<p><span>童年，是一首首朗朗上口的儿歌。</span></p>
<p><span>Childhood is a dulcet rhyme.</span></p>
<p><span>让我们放飞梦的翅膀，倾听悠扬的旋律。</span></p>
<p><span>Let‘s fly the wings of dream, listening to the melody of vitality.”</span></p>
<p><span>伴着主持人嘹亮的声音，比赛正式开始。</span></p>
<p><a href="images/25cbf82f502f473291cc2253f4ece84c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/25cbf82f502f473291cc2253f4ece84c.jpg"></a><a href="images/6f80f8a12f33492aae7591e1a0c6be29.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/6f80f8a12f33492aae7591e1a0c6be29.jpg"></a><a href="images/c54efb0828f34227aa47c6b88978b15f.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c54efb0828f34227aa47c6b88978b15f.jpg"></a><a href="images/221219e4920e451ba3ed988ea8de1cec.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/221219e4920e451ba3ed988ea8de1cec.jpg"></a></p>
<p><span>经过赛前精心准备，本届英语节合唱比赛表现形式多样、各具特色。孩子们灵动活泼的歌声在礼堂间跳跃溢散，让每个人都沉浸其中。<br></span></p>
<p><br></p>
<p>
 <div id="mediaContent0_1"></div> <script type="text/javascript">
    var flashvars={
        f:"/media/0/90a91441f1bf4e86abc09f666ea25da2.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/90a91441f1bf4e86abc09f666ea25da2.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_1","ckplayer_mediaContent0_1","400","300",false,flashvars,video,params);
</script></p>
<p><img title="1.jpg" src="/uploads/migration/images/da884366d3de442c97f526e84bdbc5f5.jpg"><a href="images/2566d721112f44468feb6cc490840228.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/2566d721112f44468feb6cc490840228.jpg"></a></p>
<p><span>二年级一班同学演唱了“Where are you going”和 “Say Cheese”两首歌曲，曲风轻快悠扬，踏着节拍，孩子们一蹦一跳，一唱一和，可爱的脸蛋上洋溢着幸福而又阳光的笑容，就像头上佩戴的太阳花一样灿烂。（图、视频）</span></p>
<p><span>二年级二班同学带来的是“I’m short and Tou’re tall”以及“Happy Song”。他们队列有序整齐，动作整齐划一，表情活泼生动，为观众和评委献上了精彩绝伦的表演。</span></p>
<p><span><br></span></p>
<p><br></p>
<p><img title="1.jpg" src="/uploads/migration/images/9209f0e7fa09409d998f4a3c9f5eaadf.jpg"></p>
<p><span>一幕幕精彩的表演赢得了全场的热烈欢呼与赞赏，一曲曲活力四溢的歌曲，让每个同学的脸上都盈满了笑容。精神昂扬、歌声嘹亮，彰显了新航实验学子蓬勃向上、积极进取的风采，为观众们带来了一场精彩的视听盛宴。</span></p>
<p><br><br></p>
<p><br></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/9d14eecbd4f245f680b30005f3cdd28c.jpg', NULL, true, '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (874, '高手对决：第二届“Spelling Bee of STEAM”单词拼写大赛圆满落幕', '', '为激发学生的专业词汇学习兴趣，鼓励学生打下坚实的词汇基础，10月中旬，济南新航实验外国语学校第二届Spelling Bee of STEAM单词拼写大赛正式拉开帷幕，高一融合班全体同学参与了此次大赛。近日，经过层层选拔和激烈比拼，有6位同学获奖，其中，许钧乔同学获得金奖，郝瀚和王郑一同学获银奖，乔善一、徐圣语、郑子怡同学获铜奖。相较于首届单词拼写大赛，此次大赛除常规STEM词汇，同时引入了IG E...', '', '<p><a href="images/bf79ac60db6d48558dc2dc6a1ca2305a.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/bf79ac60db6d48558dc2dc6a1ca2305a.jpg"/></a></p><p><span>为激发学生的专业词汇学习兴趣，鼓励学生打下坚实的词汇基础，10月中旬，济南新航实验外国语学校第二届Spelling Bee of STEAM单词拼写大赛正式拉开帷幕，高一融合班全体同学参与了此次大赛。近日，经过层层选拔和激烈比拼，有6位同学获奖，其中，许钧乔同学获得金奖，郝瀚和王郑一同学获银奖，乔善一、徐圣语、郑子怡同学获铜奖。</span></p><p><img title="1.jpg" src="/uploads/migration/images/2ef23bb14f3b4086ac0a1bb5960d5e48.jpg"/><a href="images/70c163ba08d74d0389ad5a4863bfd6ec.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/70c163ba08d74d0389ad5a4863bfd6ec.jpg"/></a></p><p><br/></p><p><br/></p><section><section><p><span>相较于首届单词拼写大赛，此次大赛除常规STEM词汇，同时引入了IG ESL和 IG Economics的相关专业词汇，学生需要记忆的词汇量超4000个单词，在拼写范围和记忆难度上，相较于首届，均有所增加。</span></p><p><a href="images/1a8c3b941e334c0e84ba9fc6e1543efe.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/1a8c3b941e334c0e84ba9fc6e1543efe.jpg"/></a></p><p><span>经过一个月的准备，11月15日，郝瀚和许钧乔等10名同学以优异的成绩脱颖而出，进入最终的决赛环节。</span></p></section></section><p><br/></p><p><img title="1.jpg" src="/uploads/migration/images/a6b7a48b66b645a09dcd9a60e5b40778.jpg"/><a href="images/8d50132caa6846fab563b0e0319efc4b.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/8d50132caa6846fab563b0e0319efc4b.jpg"/></a><a href="images/be263908fb50415db2ce57e2a225b89a.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/be263908fb50415db2ce57e2a225b89a.jpg"/></a></p><p><span>11月24日下午，伴随着一首来自高一（5）班宋雨珈同学带来的《unstoppable》，大战决赛拉开帷幕。此次单词拼写由Alevel生物学外教Mike担任Pronouncer Bee，在IG化学赵珊珊老师、Alevel物理金晶老师、IG社会学Mahdi老师、升学指导中心吕成主任、升学指导中心王睫莹老师和Alevel化学刘建飞老师等Judge Bees的公正裁决下，经过多轮比拼，最终高一（5）班许钧乔同学获得金奖，高一（5）班的郝瀚和王郑一同学获得银奖，高一（6）班乔善一、（5）班徐圣语和（5）班郑子怡同学获得了铜奖。<a href="images/3a855cd637af4c29bef3aa694d2510a2.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/3a855cd637af4c29bef3aa694d2510a2.jpg"/></a><a href="images/73139afd28814b5b9578d0562b4b902f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/73139afd28814b5b9578d0562b4b902f.jpg"/></a><a href="images/b54cbe0fb35d45b2a56f96904c3fbd53.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/b54cbe0fb35d45b2a56f96904c3fbd53.jpg"/></a></span></p><p><span></span><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/bf79ac60db6d48558dc2dc6a1ca2305a.jpg', NULL, true, '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (875, '竞赛喜报：三个全国一等奖！新航实验学子再获AMC佳绩', '', '近日，2021年澳大利亚数学竞赛（AMC）成绩出炉。此次竞赛共吸引了全国2500余所学校的约4万名学生参赛，新航实验28位学子凭借扎实的数学基础与灵活的思维逻辑，从众多参赛选手中脱颖而出。其中，高二学生王启源、高乐凡、郭维浩分别以97、94、93的好成绩斩获全国一等奖，同时，徐晨曦、肖敬皓等25名同学获得全国二等奖。全国一等奖：高二学生王启源、郭维浩、高乐凡澳大利亚数学竞赛(AMC) 由澳大利亚数...', '', '<p><span><a href="images/fbba693deabc48d1a127323b3807a828.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/fbba693deabc48d1a127323b3807a828.jpg"/></a></span></p><p><span>近日，2021年澳大利亚数学竞赛（AMC）成绩出炉。此次竞赛共吸引了全国2500余所学校的约4万名学生参赛，新航实验28位学子凭借扎实的数学基础与灵活的思维逻辑，从众多参赛选手中脱颖而出。其中，高二学生王启源、高乐凡、郭维浩分别以97、94、93的好成绩斩获全国一等奖，同时，徐晨曦、肖敬皓等25名同学获得全国二等奖。</span></p><p><img title="2.jpg" src="/uploads/migration/images/b80afb3c6d9543e7bcbd77483ae57c3c.jpg"/></p><p><br/></p><section><p><span>全国一等奖：高二学生王启源、郭维浩、高乐凡</span></p></section><p><br/></p><section><section><p><br/></p><p><span>澳大利亚数学竞赛(AMC) 由澳大利亚数学联合会(AMT)主办，是拥有悠久历史的全球性校际数学竞赛，也是全球最大的校际数学竞赛。新颖的题型和多语言试题让全球的数学爱好者们得以在数学领域深刻切磋，共同学习，并深刻认识数学在生活中的重要性。</span></p><p><span>作为多项国际竞赛的考点，新航实验始终致力于开拓优质竞赛渠道，不断拓展新的国际赛事平台，鼓励学生参与国内外各种学术类、综合类活动和比赛。越来越多的新航实验学子在竞赛中不断成长，在收获学科知识技能的同时，培养勇于挑战、积极探索的求知精神。</span></p><p><br/></p></section></section><p><br/></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/fbba693deabc48d1a127323b3807a828.jpg', NULL, true, '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '2021-12-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (876, '献礼建党百年——新航实验举办“红星照耀中国”主题英语演讲比赛', '', '指点江山、激扬文字，不只是魏晋士子的风范，也是新航实验学子所展现的气宇风采。近日，在新航实验第二届英文演讲大赛三分钟定题演讲中，选手们或旁征博引，或侃侃而谈，或娓娓道来，以磅礴之势呈现了新时代学子的精神面貌。根据赛事安排，高中部每班选拔2名同学参加初赛展示。最终，从32名进入初赛展示的选手中，孔维一等10位获奖者脱颖而出。时值中国共产党建党100周年，本次演讲比赛的主题定为“红星照耀中国”（Red...', '', '<p><span>指点江山、激扬文字，不只是魏晋士子的风范，也是新航实验学子所展现的气宇风采。近日，在新航实验第二届英文演讲大赛三分钟定题演讲中，选手们或旁征博引，或侃侃而谈，或娓娓道来，以磅礴之势呈现了新时代学子的精神面貌。根据赛事安排，高中部每班选拔2名同学参加初赛展示。最终，从32名进入初赛展示的选手中，孔维一等10位获奖者脱颖而出。</span></p><p><img title="1.webp (2).jpg" src="/uploads/migration/images/a5e7a093593f467e939b98844933c1f3.jpg"/><a href="images/d50929c09d944dfab278ff89f0276c21.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/d50929c09d944dfab278ff89f0276c21.jpg"/></a></p><p><span>时值中国共产党建党100周年，本次演讲比赛的主题定为“红星照耀中国”（Red Star Over China），各位参赛选手从历史着手，从身边的故事着手，从自身经历着手，用一个个精彩的故事讲述中国共产党这颗伟大的“红星”，如何照耀、指引中国，实现经济腾飞发展，摆脱极端贫困，平衡生态发展，在国际舞台展现大国担当。</span><img title="1.webp (2).jpg" src="/uploads/migration/images/6dd964502ed9499e9d8014abe445aa23.jpg"/><a href="images/9991ce886e604676bd159e18550206af.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/9991ce886e604676bd159e18550206af.jpg"/></a></p><p><span>经过激烈的比拼，最终，高二四班孔维一同学凭借极富历史底蕴的演讲获得金奖，高二五班江通和高一六班任舒予同学获银奖，高一三班任梓萌、高一二班赵楷沣及高二三班刘若云获得铜奖。四名优秀选手也获得了荣誉奖项。</span></p><p><a href="images/ebe00e6a939e41ce948a5bdd9946da63.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/ebe00e6a939e41ce948a5bdd9946da63.jpg"/></a><a href="images/e62f58181e11495fa281a77121d9c904.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/e62f58181e11495fa281a77121d9c904.jpg"/></a><a href="images/5283471ee14f47f185b6cc262f8ad5fb.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/5283471ee14f47f185b6cc262f8ad5fb.jpg"/></a><a href="images/54ef8a87d0414f57897c44347b343787.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/54ef8a87d0414f57897c44347b343787.jpg"/></a></p><p><span>新航实验旨在培养具有国际视野的世界公民，此次比赛为新航实验学子提供了一个讲好中国故事、为祖国发声的契机，向建党百年献礼、向伟大时代致敬。</span></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/a5e7a093593f467e939b98844933c1f3.jpg', NULL, true, '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (877, '联合调研：市教育局联合市外办赴新航实验开展“为民办实事”调研', '', '近日，为全面落实“为民办实事”要求，由济南市教育局国际处发起，市教育局副局长刘绍辉、市外办副主任李茂鑫等一行10人，莅临济南新航实验外国语学校，就教育国际化建设情况开展联合调研，全面考察育人特色，深入了解办学需求。山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊陪同调研。  调研组一行在实地参观校园过程中，对新航实验的科创特色、多元课程、文化氛围、师生风貌、德育做法、艺体特长...', '', '<p><a href="images/9090d7c28a624f6d9b71f50b8adf79c3.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/9090d7c28a624f6d9b71f50b8adf79c3.jpg"/></a></p><p><span>近日，为全面落实“为民办实事”要求，由济南市教育局国际处发起，市教育局副局长刘绍辉、市外办副主任李茂鑫等一行10人，莅临济南新航实验外国语学校，就教育国际化建设情况开展联合调研，全面考察育人特色，深入了解办学需求。山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊陪同调研。</span></p><p><span><a href="images/491b3ed0cbbf4729896aaddce512c46c.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/491b3ed0cbbf4729896aaddce512c46c.jpg"/></a></span></p><p><span>&nbsp; 调研组一行在实地参观校园过程中，对新航实验的科创特色、多元课程、文化氛围、师生风貌、德育做法、艺体特长等都给予了充分肯定。</span></p><p><span><span><img title="3.jpg" src="/uploads/migration/images/cc73e8ef605e427dbe292df8f2dbc03d.jpg"/></span></span></p><p><span><span></span></span></p><section><section><section><p><span>在接下来的座谈上，林宝磊校长围绕学校文化建设、名师团队、课程理念、办学目标等方面做情况汇报。校园规范有序、学生阳光开朗、课程丰富多元，给调研组一行留下了深刻印象，市外办李茂鑫副主任表示，希望发挥市外办友城资源渠道优势，在开展友好城市交流活动上与市教育局联合，共同助力学校国际化发展，支持、鼓励学校积极申报市“类海外”环境建设扶持项目。市外办李玉副主任称赞学校兼具传统优质的教育资源与灵活创新的管理模式，围绕工作中的办学需求，市外办将全力为学校发展做好服务。市教育局刘绍辉副局长为市外办对新航实验国际化发展的大力支持表示感谢。</span></p></section><section><p><span>林宝磊校长对市教育局和市外办对学校发展建设的关心表示感谢，新航实验将进一步高质量抓好教育国际化工作，同时也提出了三点需求，包括引入更多优质传统文化课程资源，强化爱国主义教育，引进更多优秀外籍教师，深化国际理解教育，以及拓展更多国际友好学校资源，加强国际合作交流。</span></p><p><span>市教育局国际处、市委外办秘书处、市外办欧非处主要负责同志和相关工作人员参加了调研。</span></p></section></section></section><p><span><span></span></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/9090d7c28a624f6d9b71f50b8adf79c3.jpg', NULL, true, '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (878, '家校共育，携手同心——新航实验举行2021级家委会成立仪式', '', '为促进家校沟通和配合、提升学校育人品质，营造学校、家庭、社会为一体的教育网络，11月21日，济南新航实验外国语学校举行2021级家长委员会成立仪式，由各学部推选产生的20余位2021级各班家长代表及部分2020级家委会成员前来参会，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊等学校领导出席会议。一纸聘书，蓄势起航本次会议由新航实验副校长张爱梅主持，经过近一个月的精心筹备，...', '', '<p><a href="images/e685ab4044d945b6b832b3987e358205.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e685ab4044d945b6b832b3987e358205.jpg"/></a></p><p><span>为促进家校沟通和配合、提升学校育人品质，营造学校、家庭、社会为一体的教育网络，11月21日，济南新航实验外国语学校举行2021级家长委员会成立仪式，由各学部推选产生的20余位2021级各班家长代表及部分2020级家委会成员前来参会，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊等学校领导出席会议。</span></p><p><a href="images/27a6474eb5274e1299761c929b71e0f6.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/27a6474eb5274e1299761c929b71e0f6.jpg"/></a></p><p></p><section><section><section><p><span>一纸聘书，蓄势起航</span></p></section></section></section><p><section><section><p><span>本次会议由新航实验副校长张爱梅主持，经过近一个月的精心筹备，由家长自主申报、班主任推荐、级部审核推选，确定了小学、初中、高中部 2021级家长常务委员会建议名单，大会选举产生了2021级家长委员会常务委员会主任委员及秘书长。</span></p></section></section></p><p><a href="images/e1dd598badae492ba9401563cbe2ef3e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e1dd598badae492ba9401563cbe2ef3e.jpg"/></a><a href="images/7868412aa6044c41a6e14f93f33a21e5.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/7868412aa6044c41a6e14f93f33a21e5.jpg"/></a><a href="images/9a1ab72b3b0b430087d2c6c39af3274f.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9a1ab72b3b0b430087d2c6c39af3274f.jpg"/></a><a href="images/c2511124a5884270881fc5bdfc5369db.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/c2511124a5884270881fc5bdfc5369db.jpg"/></a><a href="images/3a6de7256871415f87a5db6e4a8d4575.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/3a6de7256871415f87a5db6e4a8d4575.jpg"/></a><br/></p><p></p><section><section><p><span>仪式上，王飞副校长宣读了18位2021级家委会名单，小学、初中、高中三位学部校长分别为各学部家委会成员颁发聘书。经过现场讨论选举，一年级易可欣同学家长刘天华女士、初一年级南文皓同学家长南永东先生、高一年级邢铭远同学家长邢一先生分别被推选为新航实验各学部2021级家委会常务委员会主任委员，一年级曹宇岑同学家长侯燕红女士、初一年级高源骏同学家长禹娜女士、高一年级史卉丛同学家长张丽女士分别被推选为各学部2021级家委会常务委员会秘书长。林宝磊校长为六位家委会主任委员和秘书长颁发聘书。</span></p></section></section><p><a href="images/a4724cd02b1d47439ebaf17625bf9a84.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/a4724cd02b1d47439ebaf17625bf9a84.jpg"/></a></p><p><span>紧接着，林宝磊校长围绕收获、节奏、期待、行动四个关键词，简要介绍了新航实验在教育教学创新、学生习惯养成教育、特色活动育人、精神文化引领等方面的创新做法。同时，与家长代表们分享了五个教育理念，“好成绩好分数是教育成果呈现，不是目标追求”、“培养吃苦能力、奋斗精神，是教育的目标之一”……赢得了家长代表们的高度认可。</span></p><p><span>一份责任，凝聚力量</span></p><p><a href="images/3112cdeb6a974716bfcfd9c918ff82a8.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/3112cdeb6a974716bfcfd9c918ff82a8.jpg"/></a></p><p><span>2020级家委会主任高原对近两年的家委会工作做总结与展望，在过去的两年里，新航实验家委会鼎力支持学校工作，积极开创家校共育特色，共同致力于新航实验学子全面发展。</span></p><p><a href="images/9bfc23b2b3784df4a440da7a4f6578e4.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/9bfc23b2b3784df4a440da7a4f6578e4.jpg"/></a></p><p></p><p><span>新当选的2021级家委主任邢一表示，学校对教育的重视鼓舞人心，校家委会将努力与学校同心协力、同频共振，为孩子们打造一片纯净而美好的教育蓝天。</span></p><p><span>在交流环节，家委会成员分别做表态发言，畅所欲言提出了许多合理化意见或建议。成立仪式在热烈的家校互动中落下帷幕，一纸聘书，家校一体，一份责任，共建共赢。仪式结束后，2021级家长委员会召开了第一次会议。</span></p><p><a href="images/9c7942f69ffe4ada9bfdbd5d0fe2f127.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9c7942f69ffe4ada9bfdbd5d0fe2f127.jpg"/></a><br/></p><p><span>教育是一个同心圆，圆心是孩子，围绕圆心的是家庭、学校和社会，三方同心、同向、同行，才能画好家校同心圆，做好教育合伙人。家长委员会的成立，进一步密切了家校联系，加强了家校沟通，为促进学生健康全面发展打下坚实基础。</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/e685ab4044d945b6b832b3987e358205.jpg', NULL, true, '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (879, '练好根技术 归零再出发——新航实验举行期中德育总结大会', '', '为进一步提升班主任队伍业务能力和工作水平，科学指导、分析、强化班级管理方法，营造积极向上的班风班貌，11月24日，新航实验召开以“练好根技术 归零再出发“为主题的期中德育工作总结大会。新航实验副校长张爱梅、初中部校长李正华、小学部校长邹胜及全体班主任参加了此次活动，会议由学生发展中心副主任陈晶主持。 var flashvars={ f:"/media/0/fe12c4c5f613413d8d572...', '', '<p><span>为进一步提升班主任队伍业务能力和工作水平，科学指导、分析、强化班级管理方法，营造积极向上的班风班貌，11月24日，新航实验召开以“练好根技术 归零再出发“为主题的期中德育工作总结大会。新航实验副校长张爱梅、初中部校长李正华、小学部校长邹胜及全体班主任参加了此次活动，会议由学生发展中心副主任陈晶主持。</span></p>
<p></p>
<p>
 <div id="mediaContent0_0"></div> <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> <script type="text/javascript">
    var flashvars={
        f:"/media/0/fe12c4c5f613413d8d572a6357f97dfd.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/fe12c4c5f613413d8d572a6357f97dfd.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script></p>
<p><a href="images/81939856c4a64458ba20b58c7d30d806.png" target="_blank"><img title="微信截图_20211202094641.png" src="/uploads/migration/images/81939856c4a64458ba20b58c7d30d806.png"></a><br></p>
<p><span>总结会上，来自小学部、初中部、高中部的王真、张瑜、董冬三位老师分别分享了自己对于班级管理的心得体会和经验，从“已所不欲勿施于人”到“已所欲，勿尽施于人”的王真老师，从赏识教育到换位思考、五心并举的张瑜老师，再到“接地气”、“聚人气”、“有底气”的“富”气的董冬老师，他们结合自身教育实践，通过具体案例阐述了自己与学生和家长互相赋能、不断优化班级管理、实现共同成长的心路历程。</span></p>
<p><a href="images/5735cd8cd350422fb516597bb2e566a2.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/5735cd8cd350422fb516597bb2e566a2.jpg"></a></p>
<p></p>
<section>
 <p><span>初中部李正华校长分享了期中“三味三境”家长会工作情况，从会前周全考虑、细致准备到会中反复推演和会后及时反思，形成真正的闭环，让学生获益，赢得家长一致好评。</span></p>
 <p><a href="images/4009c9ea18ab4658955b878930be204f.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/4009c9ea18ab4658955b878930be204f.jpg"></a></p>
 <p><span>紧接着，心理发展辅导中心的宋艺奇老师详细介绍了学校编写的《心理危机预防与干预指导手册》的使用，提醒班主任老师们借助手册中的知识与方法，为学生心理健康与生命安全保驾护航。</span></p>
</section>
<p><a href="images/53a768247bc6445897f7cf7400585e45.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/53a768247bc6445897f7cf7400585e45.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span>预见：班主任工作总结及展望</span></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <p><span>陈晶主任从疫情防控、健康卫生、班级常规工作、安全保障四方面，运用数据和案例，总结回顾近期德育工作亮点。同时对工作中存在的问题进行分析，并提出了具体建议，包括常规工作按时做细做实，班级管理刚柔并济、尺度统一等。最后，张爱梅副校长从班主任工作八个意识的意义、策略、注意事项等方面分享了自己的经验。与会班主任认真聆听、仔细记录、深刻体悟。</span></p>
 </section>
</section>
<p></p>
<p><img title="1.jpg" src="/uploads/migration/images/7d0d3dec62464aa39762b6bc90a4e21f.jpg"></p>
<p><span>拳拳真情映日月，丹心热血沃新花。正是因为有一个又一个的小“我”不遗余力地用智管理、用情沟通、用心育人，新航实验学子才能在这沃土之上尽情绽放，养德于行、润德于心、知行合一。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/81939856c4a64458ba20b58c7d30d806.png', NULL, true, '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (880, '“暴徒”闯校？别慌！这是防暴恐实战处置演练', '', '为维护师生生命安全，切实提高应对校园暴恐事件的处置自救及逃生避险能力，11月26日，济南新航实验外国语学校联合历城分局彩石派出所开展校园防暴恐演练活动。济南市公安局反恐支队首席反恐专家、二级高级警长张龙，历城区公安分局反恐专班主任韩兆盛，历城区公安分局巡警大队副大队长、反恐专班副主任王继刚及彩石派出所领导等莅临指导。演练设定模拟场景：某日放学期间，学校值班教师及保安在校门口执勤，一男子趁学生出入时...', '', '<section><section><p><span>为维护师生生命安全，切实提高应对校园暴恐事件的处置自救及逃生避险能力，11月26日，济南新航实验外国语学校联合历城分局彩石派出所开展校园防暴恐演练活动。济南市公安局反恐支队首席反恐专家、二级高级警长张龙，历城区公安分局反恐专班主任韩兆盛，历城区公安分局巡警大队副大队长、反恐专班副主任王继刚及彩石派出所领导等莅临指导。</span></p></section></section><p></p><section><p><a href="images/93f0ca2a7e2f480f994d8cb54a136175.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/93f0ca2a7e2f480f994d8cb54a136175.jpg"/></a></p><p><span>演练设定模拟场景：某日放学期间，学校值班教师及保安在校门口执勤，一男子趁学生出入时拿出棍棒，意图袭击学生。险情发生后，保安手持防暴器械对“暴徒”进行拦截并呼叫支援，门岗内值班保安立刻开启一键报警装置；老师迅速组织学生进入就近班级躲避并关闭教室门，严防“歹徒”破门而入，时刻保持警惕。所有防暴组成员持器械增援，阻止暴恐分子袭击学生，并等待警察处置。</span></p><p><a href="images/1dd8648c7ef24c3aa73341e249fe2fb3.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/1dd8648c7ef24c3aa73341e249fe2fb3.jpg"/></a><a href="images/198b9ad454054a599a56536a25ad161c.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/198b9ad454054a599a56536a25ad161c.jpg"/></a><a href="images/2b80fa6ea21c492c97f5a2984c076240.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/2b80fa6ea21c492c97f5a2984c076240.jpg"/></a><a href="images/c1f449f056d340df90ea2161db235b16.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/c1f449f056d340df90ea2161db235b16.jpg"/></a></p><p><span>本次演练过程有序、紧凑、逼真，提高了我校安保人员和师生的警惕性，达到了警校共建的突出效果。在观摩点评环节，张龙警长充分肯定了新航实验安全保卫工作，演练处置过程干脆利索，安保人员精神状态饱满，师生防暴恐意识较高，并指出演练过程中的不足之处，“希望持续强化自身防暴技能，掌握防暴恐战略战术，用生命捍卫学生安全”。&nbsp; &nbsp; &nbsp;</span></p></section><p></p><p><a href="images/ebaa376d59b94d4daceb8775c5f58771.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/ebaa376d59b94d4daceb8775c5f58771.jpg"/></a><a href="images/57e89adb948549109f98fd2f935567b5.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/57e89adb948549109f98fd2f935567b5.jpg"/></a><a href="images/9d4c30f489cf43888a8c08421770c5e7.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9d4c30f489cf43888a8c08421770c5e7.jpg"/></a></p><p><span>最后，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊校长对本次演练活动进行总结点评，对学校安保工作提出了更高更严格的要求，同时提醒师生提高政治站位，时刻保持高度警惕，增强防暴恐意识，重点关注容易发生暴恐事件的时间及地点，学会自救互救技能，珍爱生命。</span></p><p><a href="images/6c8330a4fb284005aac8fbfa5f8aa07e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6c8330a4fb284005aac8fbfa5f8aa07e.jpg"/></a></p><p><span>新航实验始终把“预防为先”作为防暴恐工作的出发点，在防暴恐工作中持续强化人防、物防、技防三位一体的预防机制，抓好关键部位的安全防范，力争把违法犯罪行为遏制在预谋阶段，把各种灾害事故消灭在萌芽之中。学校将以本次防暴恐应急演练为契机，加强警校联动，努力为师生打造优质、安全的教育环境。‍</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/93f0ca2a7e2f480f994d8cb54a136175.jpg', NULL, true, '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '2021-12-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (881, '青春正当时 奋进启新程——新航实验召开第二届学生代表大会', '', '近日，济南新航实验外国语学校迎来第二届学生代表大会，185位学生代表、27位学生会候选人以及2019级、2020级学生会成员参与此次大会。大会由高中部学生会主席段淑雯主持，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊，以及新航实验副校长张爱梅等学校领导出席会议。会议审议通过了第一届学生会工作报告，选举产生了第二届学生会委员。大会在雄壮的国歌声中拉开序幕，学生会初中部主席华...', '', '<p><img title="1.webp (2).jpg" src="/uploads/migration/images/e52fd64764a14ffe9e52c09f925dd484.jpg"/></p><p><span>近日，济南新航实验外国语学校迎来第二届学生代表大会，185位学生代表、27位学生会候选人以及2019级、2020级学生会成员参与此次大会。大会由高中部学生会主席段淑雯主持，山东省实验中学党委委员、东校校长、济南新航实验外国语学校执行校长林宝磊，以及新航实验副校长张爱梅等学校领导出席会议。</span></p><p><a href="images/5251f83845f3416592d2d78baa5b4d29.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/5251f83845f3416592d2d78baa5b4d29.jpg"/></a><a href="images/b853d7f92bc24059bd05b2c2ca86adaf.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/b853d7f92bc24059bd05b2c2ca86adaf.jpg"/></a><a href="images/f81b3308cf794ae1a3c2689173b7ec5f.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/f81b3308cf794ae1a3c2689173b7ec5f.jpg"/></a></p><p><span>会议审议通过了第一届学生会工作报告，选举产生了第二届学生会委员。大会在雄壮的国歌声中拉开序幕，学生会初中部主席华俊杰同学代表首届学生会委员会做工作报告，全面、客观地回顾了一年来我校学生会工作，总结成绩、分析不足，同时预祝学生会在未来的日子里不负使命、团结一心，精诚协作、服务同学，创造无限辉煌的美好明天。</span></p><section><section><section><section><p><strong><span>薪火相传 美德不灭：2019级学生会成员谢幕</span></strong></p></section></section></section></section><p><section><section><section><section><p><span>首届学生会成立以来，先后举办了一系列精彩有意义的活动：百花齐放的“社团文化节”，角逐激烈的“飞花令”、“曲水流觞”，精彩有趣的“趣味运动会”，亲手设计制作的新航日历“募集善款”……首届学生会热心为同学们服务，也赢得了交口称赞，每天早晨总有专人到教室看看地面、摸摸讲桌，每天傍晚教室里的广播总是会按时响起……首届学生会给全校同学们留下了一幕幕美好的回忆。</span></p></section></section></section></section></p><p><a href="images/3c169eeed7e24577b5cae34f5501568d.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/3c169eeed7e24577b5cae34f5501568d.jpg"/></a></p><section><section><section><section><p><span>林宝磊校长、张爱梅副校长分别为2019级全体学生会成员颁发纪念品，感谢他们的认真负责与辛勤付出。</span></p><p><strong><span>朝气蓬勃 实力满满：第二届学生会闪亮登场</span></strong></p></section></section></section></section><p><section><section><section><section><p><span>根据大会议程，本次学代会参加竟选的27名同学，利用PPT自我介绍和现场演讲的方式进行了竞职演说。他们分别从竞选原因、对工作的理解、工作思路等方面向老师及各与会代表展示着自己的能力和工作蓝图，并在许多方面提出了创新性想法。候选人严谨认真的态度和展现出的极高的个人能力，获得了代表们的阵阵掌声。大会本着民主、公开、公正的原则，采用无记名投票的方式，最终选举产生了新一届学生会成员，任梓萌、周子墨等18名同学光荣当选。</span></p></section></section></section></section></p><p><a href="images/58f261bd566343fb903d4276494f36e7.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/58f261bd566343fb903d4276494f36e7.jpg"/></a><a href="images/ef1613ca29d74b6980b8f5031897dd73.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/ef1613ca29d74b6980b8f5031897dd73.jpg"/></a></p><p><span>据统计，在前期广泛征集同学意见建议的基础上，当天大会共收到200余份学生代表提案，作为学生代表充分发挥职责、参与学校民主管理的载体，提案内容涉及教育教学、成长成才、权益维护、学生发展等方面，学生代表们为校园发展踊跃建言献策。</span></p><p><span>新航实验始终秉承“让每一个生命都精彩绽放”的教育理念，搭建学生自我成长的舞台，相信并全力支持学生自主管理、自主发展，在新航这片沃土找寻精彩绽放的密钥。此次大会在热烈的掌声中圆满落下帷幕。</span></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/e52fd64764a14ffe9e52c09f925dd484.jpg', NULL, true, '2021-11-23 08:00:00+08', '2021-11-23 08:00:00+08', '2021-11-23 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (882, '喜报！新航实验陈晶老师荣获“2021年度济南市优秀思政课教师”', '', '在日前结束的2021年济南市优秀思政课教师评选活动中，经学校申报、教育部门遴选推荐、外省专家材料评审和面试答辩、公示等程序，确定了2021年济南市优秀思政课教师名单。其中，济南新航实验外国语学校陈晶老师榜上有名。作为新航实验学生发展中心副主任，陈晶老师还先后被认定为济南市高中思想政治学科青年骨干教师，被选聘为济南市思想政治学科中心组成员，2020年4月入选济南市首批“立德树人双领军”团队，今年9月...', '', '<p><span>在日前结束的2021年济南市优秀思政课教师评选活动中，经学校申报、教育部门遴选推荐、外省专家材料评审和面试答辩、公示等程序，确定了2021年济南市优秀思政课教师名单。其中，济南新航实验外国语学校陈晶老师榜上有名。</span></p><p><a href="images/181b057f2a354650a5121ba6ae23e1c1.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/181b057f2a354650a5121ba6ae23e1c1.jpg"/></a></p><p></p><section><section><p><span>作为新航实验学生发展中心副主任，陈晶老师还先后被认定为济南市高中思想政治学科青年骨干教师，被选聘为济南市思想政治学科中心组成员，2020年4月入选济南市首批“立德树人双领军”团队，今年9月被授予“济南市教书育人楷模“称号。</span></p><p><span>陈晶老师先后主持、参与近十项国家、省、市重点课题，通过课题研究，进一步提高教学水平和能力。作为政治学科教研组长，陈晶老师带领思政老师们深入研究、实践如何实现小、初、高思政课一体化教学，努力探索“大中小学思政课一体化”的有效实施路径，灵活运用教学方法，有针对性的开展教学，将思政（道法）课打造成学生展示、发展、成长的舞台。</span></p><p><img title="2.webp (1).jpg" src="/uploads/migration/images/21d3e4b47554486b834b56eaef01c3b2.jpg"/></p><p><span>为更好地了解学生，做学生合格的知心人，科学有效地指导学生面对、解决学习、生活中的各种疑惑，陈晶老师自学考取了国家二级心理咨询师资质。不仅如此，陈晶老师还连续11年默默资助重庆酉阳山区的两位女童分别考上了西南民族大学和重庆巴蜀中学。在她的带领下，她所教过的班级先后与重庆酉阳车田乡中心小学、西藏白朗中学、新疆维吾尔自治区阿克苏地区新和县排先拜巴扎乡中心小学结对助学，为边远地区儿童捐赠图书近5000册以及篮球、足球等体育活动用品，和学生们一起用萤火之光为山区孩子点亮梦想。</span></p></section></section><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/181b057f2a354650a5121ba6ae23e1c1.jpg', NULL, true, '2021-11-22 08:00:00+08', '2021-11-22 08:00:00+08', '2021-11-22 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (883, '大洋探险、趣味游园，新航实验小学部开启乐评嘉年华', '', '新航实验小学部阶段学情回顾活动在小航们的欢声笑语中落下帷幕啦！一项项有趣的检测、一个个醒目的印章、一张张灿烂的笑脸，为小航们的小学生活打上了温暖的底色。为了带给孩子们别样的乐评经历，老师们精心策划，从方案的缜密构思到考核内容的确定，从设计精美的道具到充满童真童趣的会场布置......每一处细节都凝结着教研团队的智慧。一年级组为孩子们准备了生动有趣的“小航启航·大洋探险”闯关活动。认读音节、“节奏对...', '', '<p><a href="images/c003afe1b6124575a56deed695d31eed.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/c003afe1b6124575a56deed695d31eed.jpg"/></a><a href="images/27e45b93f90a4c8f9473f5fa8222cf84.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/27e45b93f90a4c8f9473f5fa8222cf84.jpg"/></a><a href="images/ef3354510d95433bb69e4958b2193660.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/ef3354510d95433bb69e4958b2193660.jpg"/></a></p><section><section><p><span>新航实验小学部阶段学情回顾活动在小航们的欢声笑语中落下帷幕啦！一项项有趣的检测、一个个醒目的印章、一张张灿烂的笑脸，为小航们的小学生活打上了温暖的底色。</span></p></section></section><p><img title="微信截图_20211117153603.jpg" src="/uploads/migration/images/16c35555d6c64f1ea4ee5d8ce4013f4b.jpg"/></p><p><span>为了带给孩子们别样的乐评经历，老师们精心策划，从方案的缜密构思到考核内容的确定，从设计精美的道具到充满童真童趣的会场布置......每一处细节都凝结着教研团队的智慧。</span></p><p><a href="images/611c791d4c694da8a0757b170b850b44.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/611c791d4c694da8a0757b170b850b44.jpg"/></a><a href="images/9b34721a7f524faa86b26fcefb8d4437.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/9b34721a7f524faa86b26fcefb8d4437.jpg"/></a><a href="images/36bdeee06ce14eefb081a12e10245a1b.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/36bdeee06ce14eefb081a12e10245a1b.jpg"/></a><a href="images/590183a7afd846aab8b60b75c656242b.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/590183a7afd846aab8b60b75c656242b.jpg"/></a><a href="images/3ce6c14a686b413ca7a0d95e0822be68.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/3ce6c14a686b413ca7a0d95e0822be68.jpg"/></a><a href="images/9284ac05b21d4c2da7f4a0ee045c7b51.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/9284ac05b21d4c2da7f4a0ee045c7b51.jpg"/></a></p><p><span>一年级组为孩子们准备了生动有趣的“小航启航·大洋探险”闯关活动。认读音节、“节奏对对拍”、口算智慧解锁、智慧小讲师、“Greetings”“I can act！”“I can &nbsp;repeat!”……丰富有趣的闯关环节引领小航们经历“太平洋之旅”“大西洋探险”“北冰洋漂流”“印度洋巡航”，顺利结束航程，也让“零起点”的一年级小航们有了崭新的体验，收获了别样的快乐。</span></p><p><a href="images/256e73d59cd3424dad83ceb5180038a7.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/256e73d59cd3424dad83ceb5180038a7.jpg"/></a><a href="images/6f1b2c0b73524e29b78897c2e75d2bd3.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/6f1b2c0b73524e29b78897c2e75d2bd3.jpg"/></a><a href="images/40fa60c37f9c44c58dafd44c67529a7e.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/40fa60c37f9c44c58dafd44c67529a7e.jpg"/></a><a href="images/84d87ee4d4194475959a34c9e00a8f1d.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/84d87ee4d4194475959a34c9e00a8f1d.jpg"/></a><a href="images/9bf17b1d2a7b4144bdd8138fac5434d7.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/9bf17b1d2a7b4144bdd8138fac5434d7.jpg"/></a><a href="images/817fe8c46a824fd09ba20a2293b52469.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/817fe8c46a824fd09ba20a2293b52469.jpg"/></a><a href="images/e93c6109278948e8a07df97cdb54fccb.jpg" target="_blank"><img title="7.webp.jpg" src="/uploads/migration/images/e93c6109278948e8a07df97cdb54fccb.jpg"/></a></p><p><span>二年级的小航们则搭乘“小航趣味游园会”的列车，先后游玩了“词语糖果屋”“神机妙算探宝岛”“测量高手”“英语口语嘉年华”“自拼对对碰”“快乐诵读吧”等站点。游乐园式的闯关形式、趣味化的题卡，小航们或互相加油鼓劲，或交流闯关成功的喜悦，在参与中锻炼勇气、培养信心。</span></p><p><a href="images/306b082311c640e08b06466f34f1b6e4.jpg" target="_blank"><img title="微信截图_20211117153933.jpg" src="/uploads/migration/images/306b082311c640e08b06466f34f1b6e4.jpg"/></a></p><p><span>此次活动也深受家长们的广泛认可和一致好评，“这是我心中一年级小学生最好的样子”、“小航已顺利通关，感谢老师们给孩子们一次寓教于乐的测试模式，让孩子又成长一步”、“好羡慕这群小朋友啊，在同龄人为期中考试紧张刷题的时间，他们欢快地结束了真正属于他们自己的期中考试，此试卷绝无雷同，每个孩子离最优秀的自己又近了一步，也不禁感叹此教研团队确实在孩子们身上用心了，真正的全面发展”、“趣味游园会让一张试卷变身为一场体验，通过富有弹性的考题和巧妙的情境设计，为学生创造一种宽松、愉悦的测试氛围，给孩子一个爱上学习、爱上学校的理由”......</span></p><p><a href="images/3efb110a7d9249da93bcc6ec8ee49eb2.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/3efb110a7d9249da93bcc6ec8ee49eb2.jpg"/></a><a href="images/5a4bebdf45aa400b9947be2d717fa001.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/5a4bebdf45aa400b9947be2d717fa001.jpg"/></a></p><p><span>此次乐评活动以趣味性直击学生们内在潜能，为宝贵的童年打上阳光的底色。这不仅仅是一场考察学生阶段所学知识的测试，更是对学习习惯、学习兴趣、学习情感和态度的综合评价。孩子们在各种情境中完成真实的任务，在实践中运用知识解决问题，在轻松愉悦的氛围中全方位地展现阶段性的成长，让评价真正成为了促进学生综合素养的支点。</span></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/c003afe1b6124575a56deed695d31eed.jpg', NULL, true, '2021-11-17 08:00:00+08', '2021-11-17 08:00:00+08', '2021-11-17 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 游园 实验小学 趣味 开启', '');
INSERT INTO public.news VALUES (884, '喜报：我校杜菲菲、祁文焕老师在济南市中小学班主任育人关键能力展示提升活动中获佳绩', '', '为贯彻落实立德树人根本任务，展示新时代中小学班主任队伍的综合素质、专业水平和育人能力，进一步提高教育教学水平，济南市教育局于今年9月—10月组织开展了“济南市中小学班主任和思政课教师育人关键能力展示提升活动”，我校初中部杜菲菲老师荣获一等奖、小学部祁文焕老师荣获二等奖。杜菲菲老师在济南市中小学班主任育人关键能力展示提升活动中，评选共包括讲述育人故事、阐述带班育人方略、组织开展主题班会等三个项目的比...', '', '<p><span>为贯彻落实立德树人根本任务，展示新时代中小学班主任队伍的综合素质、专业水平和育人能力，进一步提高教育教学水平，济南市教育局于今年9月—10月组织开展了“济南市中小学班主任和思政课教师育人关键能力展示提升活动”，我校初中部杜菲菲老师荣获一等奖、小学部祁文焕老师荣获二等奖。</span></p><p><span><a href="images/f8eaf068e114410c9029a5c96be1d74c.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/f8eaf068e114410c9029a5c96be1d74c.jpg"/></a></span></p><p>杜菲菲老师</p><p><span><img title="2.webp (1).jpg" src="/uploads/migration/images/11ac88775bd341dba76f9173de75786f.jpg"/></span></p><p><br/></p><p><span>在济南市中小学班主任育人关键能力展示提升活动中，评选共包括讲述育人故事、阐述带班育人方略、组织开展主题班会等三个项目的比拼，经过层层选拔，杜菲菲老师和祁文焕老师凭借出色的表现，赢得了现场评委专家和观众的一致好评。</span></p><p><span>新航实验高度重视班主任队伍建设，为班主任的专业成长提供广阔的舞台，通过不定期举办班主任交流会、班主任工作坊、班级活动展示等活动，打造了一支辛勤奉献、经验丰富、素质一流、精研善思的班主任团队，此次获奖的两位老师就是其中的优秀代表。</span></p><p><span></span></p><section><section><section><section><section><p><span><strong>参 赛 感 言</strong></span></p></section></section></section><section><section><section><section></section></section></section></section></section></section><p></p><section><section><section><section><p><span>杜菲菲老师：</span></p><p><span>备赛过程中，我不断回顾和重温与学生们相处的每一个瞬间，系统梳理自己的带班策略，反复斟酌班会形式，反思在日常工作中的不足，这些都是我参加此次展示活动最大的收获。在展示环节，我学习到了其他优秀教师的带班策略，得以借鉴参考，会把这些有效的方法运用到接下来自己的日常工作中。</span></p></section></section><section><section><section></section></section></section></section></section><section><section><section><section><p><span>祁文焕老师：</span></p><p><span>备赛时间紧迫、任务繁重，在学校领导的关心指导、组内老师和办公室老师们的热心帮助下，精心录制主题班会课、选择育人故事、梳理班级育人方略，逐字逐句推敲，一次次修改完善，最终取得了较为理想的成绩，向背后默默付出的所有人表示感谢！我将把感恩化为行动，加倍努力工作，继续努力，继续成长。</span></p></section></section></section></section><p></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/f8eaf068e114410c9029a5c96be1d74c.jpg', NULL, true, '2021-11-13 08:00:00+08', '2021-11-13 08:00:00+08', '2021-11-13 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (885, '防患于未', '', '为进一步强化师生消防安全教育，增强师生消防安全意识，掌握消防安全知识，提高紧急逃生能力，12日中午，济南新航实验外国语学校举行以“落实消防责任，防范安全风险”为主题的消防应急演练，全校1300余名师生参加此次活动。演练前，学校制定了详细的消防疏散演练方案，对各宿舍的疏散路线及每位老师的职责都进行了明确划分，各班主任向学生介绍了火灾逃生注意事项和方法。下午13：20，学生宿舍楼前突然浓烟滚滚、烟雾弥...', '', '<p><a href="images/7a4e3154a84943ce8ce642806a3c1823.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/7a4e3154a84943ce8ce642806a3c1823.jpg"/></a><br/></p><p><span><span>为进一步强化师生消防安全教育，增强师生消防安全意识，掌握消防安全知识，提高紧急逃生能力，12日中午，济南新航实验外国语学校举行以“落实消防责任，防范安全风险”为主题的消防应急演练，全校1300余名师生参加此次活动。</span></span></p><p><span><span><a href="images/0831195fc3e7479babf7da966b800ff6.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/0831195fc3e7479babf7da966b800ff6.jpg"/></a><a href="images/f734e31fcaca47c8a2c544d952f8cb8b.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/f734e31fcaca47c8a2c544d952f8cb8b.jpg"/></a></span></span></p><p><span>演练前，学校制定了详细的消防疏散演练方案，对各宿舍的疏散路线及每位老师的职责都进行了明确划分，各班主任向学生介绍了火灾逃生注意事项和方法。</span></p><p><span><a href="images/e7ebce8e1e8d4d4cbc05007d93822700.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/e7ebce8e1e8d4d4cbc05007d93822700.jpg"/></a><a href="images/bb51433b6a4448769a4101fd781c0f85.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/bb51433b6a4448769a4101fd781c0f85.jpg"/></a><a href="images/2788b73a13254b67976977fd572b93ad.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/2788b73a13254b67976977fd572b93ad.jpg"/></a><a href="images/01d3f8b5fb8f4cd8b7bdbdc463fd1cfe.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/01d3f8b5fb8f4cd8b7bdbdc463fd1cfe.jpg"/></a><a href="images/677e7edf7a714e67994f95f075b2be7f.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/677e7edf7a714e67994f95f075b2be7f.jpg"/></a><a href="images/c0c041b6178d4914a85960a1caad84f9.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/c0c041b6178d4914a85960a1caad84f9.jpg"/></a></span></p><p><span>下午13：20，学生宿舍楼前突然浓烟滚滚、烟雾弥漫。此时，拉响了消防疏散的警报声，全体工作人员马上赶到现场，准备组织学生进行疏散，学生们拿出平时备用的小毛巾迅速地用水浇湿并捂住口鼻，在老师的带领下弯腰有序地前行，在烟雾中快速通过走廊和楼梯，跑向操场。在整个演练过程中，全校师生有机配合、密切协作，演练按照预定方案进行，保障了过程中学生安全，全校1300余名师生安全有序地疏散到操场。</span></p><p><span><a href="images/92f259dfb8f44ccfbb88bcd85273c2ad.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/92f259dfb8f44ccfbb88bcd85273c2ad.jpg"/></a><a href="images/c39d277bcd514618b2a5af073b0dc35e.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/c39d277bcd514618b2a5af073b0dc35e.jpg"/></a><a href="images/fe2b2628fae547169b3bb2180b22209f.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/fe2b2628fae547169b3bb2180b22209f.jpg"/></a><a href="images/4de4b7bd290544b3ba1089c9a6702fe1.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/4de4b7bd290544b3ba1089c9a6702fe1.jpg"/></a><a href="images/c6772c92f69a4300bd37899daa345a7f.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/c6772c92f69a4300bd37899daa345a7f.jpg"/></a><a href="images/735ffccc18184809a0e33428ae4c225b.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/735ffccc18184809a0e33428ae4c225b.jpg"/></a></span></p><p><span>张术磊副校长充分肯定了师生们在演练中的沉着表现，针对演练中暴露出的问题提出具体要求。紧接着，由专业人员采用边讲解边示范的方式向师生详细演示了灭火器的使用方法及注意事项，向师生展示了灭火服的快速穿着及消防水带的使用。学生们亲身体验了现场灭火的过程，面对燃烧的火堆，沉着、熟练地按照灭火的步骤和方法，将火成功、迅速扑灭。</span></p><p><span><a href="images/2ad1c2c13a134314ad6ee39b0cd2b39b.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/2ad1c2c13a134314ad6ee39b0cd2b39b.jpg"/></a><a href="images/2e677259ac134570bfab7f45518fec14.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/2e677259ac134570bfab7f45518fec14.jpg"/></a></span></p><p><span>维护生命安全是学校安全工作的核心，此次消防演练活动，不仅使抽象的安全知识变成具体的实战操作，极大地增强了师生的安全意识与自护自救技能，也切实加强了学校的安全教育工作</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/7a4e3154a84943ce8ce642806a3c1823.jpg', NULL, true, '2021-11-13 08:00:00+08', '2021-11-13 08:00:00+08', '2021-11-13 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (886, '位列全省初中第一名！新航实验4名初中生在CSP高中组比赛中斩获省一', '', '在日前结束的2021CSP比赛（等同于信息学奥林匹克联赛）中，新航实验初中部十名同学获奖，其中，李长健、肖程耀、成子谦、陈俊羽四位同学在李想教练团队带领下，与全省高中生共同竞技，在提高组（高中组）斩获一等奖，数量位居全省第一名。同时，在入门组比赛中，初三三班隆正熙同学斩获一等奖。2019年，CCF（中国计算机学会）推出CSP非专业级别的能力认证，分CSP-J（入门组，面向初中生）和CSP-S（提高...', '', '<p><a href="images/75f2fcd8dc0d4cc58d47e93783d4a39b.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/75f2fcd8dc0d4cc58d47e93783d4a39b.jpg"/></a></p><p><span>在日前结束的2021CSP比赛（等同于信息学奥林匹克联赛）中，新航实验初中部十名同学获奖，其中，李长健、肖程耀、成子谦、陈俊羽四位同学在李想教练团队带领下，与全省高中生共同竞技，在提高组（高中组）斩获一等奖，数量位居全省第一名。同时，在入门组比赛中，初三三班隆正熙同学斩获一等奖。</span></p><p><img title="1.webp (2).jpg" src="/uploads/migration/images/7b174ea681014d5292ac780fd13f1c1c.jpg"/></p><p><span>2019年，CCF（中国计算机学会）推出CSP非专业级别的能力认证，分CSP-J（入门组，面向初中生）和CSP-S（提高组，面向高中生）两个级别进行。由于信息学奥赛仅限高中生可报名参赛，CSP比赛成为与信息学奥赛同等重要的一场重要赛事，诸多高校综合评价招生认可CSP-S奖项。</span></p><p><a href="images/a5235652b66b44d2b1093977fc7e1357.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/a5235652b66b44d2b1093977fc7e1357.jpg"/></a></p><p></p><p><span>根据赛事安排，CSP-J和CSP-S均分别举办两轮：CSP-J1、CSP-S1及CSP-J2、CSP-S2，认证方式均为现场认证。参赛者必须参加第一轮比赛，达到一定的分数者方可晋级第二轮比赛。此次全省有1200余名选手晋级第二轮提高组比赛，1300余名选手晋级第二轮入门组比赛。<br/></span></p><p><span>此外，纪开来、田宸玮、安琪儿、孙小雅、肖敬浩等五位同学分别斩获提高组和入门组二等奖。</span></p><p><img title="1.webp (2).jpg" src="/uploads/migration/images/5f7a3ffbaa9749bf9cd199914f925866.jpg"/><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/75f2fcd8dc0d4cc58d47e93783d4a39b.jpg', NULL, true, '2021-11-11 08:00:00+08', '2021-11-11 08:00:00+08', '2021-11-11 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (887, '喜报：新航实验获评第十四届全国创新作文大赛优秀组织单位', '', '11月5日，第十五届全国中学生创新作文大赛山东赛区启动会在山东教育电视台成功举办，在刚刚落幕的第十四届全国中学生创新作文大赛中，新航实验积极动员、认真备赛，最终有十位同学获奖，其中，2020级学生李姿璇荣获全国总决赛二等奖，同时获山东赛区复赛二等奖，2020级学生高名漩、高可攀、张艺檬、田静远及2019级学生田雨舒、李紫菡、殷睿孜、瞿睿、赵洪婕获山东赛区复赛三等奖。济南新航实验外国语学校被评为优秀...', '', '<p><span>11月5日，第十五届全国中学生创新作文大赛山东赛区启动会在山东教育电视台成功举办，在刚刚落幕的第十四届全国中学生创新作文大赛中，新航实验积极动员、认真备赛，最终有十位同学获奖，其中，2020级学生李姿璇荣获全国总决赛二等奖，同时获山东赛区复赛二等奖，2020级学生高名漩、高可攀、张艺檬、田静远及2019级学生田雨舒、李紫菡、殷睿孜、瞿睿、赵洪婕获山东赛区复赛三等奖。济南新航实验外国语学校被评为优秀组织单位。</span></p><p><a href="images/93520954fb3245549c81a96f11133342.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/93520954fb3245549c81a96f11133342.jpg"/></a></p><p><span>作为经教育部审批通过的2021—2022学年面向全国中小学生的36项竞赛之一，全国中学生创新作文大赛（原名全国中小学生创新作文大赛）由北京大学中文系和课堂内外联合发起，大赛以“群读共写”为理念，提高广大青少年的综合能力、创新思维、审美情趣和人文素养，致力于挖掘和培养一批具有语文学科特长和创新潜质的优秀学生。</span></p><p><a href="images/237c9a38d17f4b87b163cea3e09b24cd.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/237c9a38d17f4b87b163cea3e09b24cd.jpg"/></a></p><p></p><p><span>自2009年起，大赛得到北京大学、南京大学、复旦大学、南开大学等38所重点高校支持，全国总决赛高中组二等奖以上奖项获奖选手，享有综合评价招生报考资格。</span></p><p><span>新航实验秉承“让每一个生命都精彩绽放“的教育理念，学校重视提升学生核心素养和综合能力。自成立伊始，新航实验致力于营造积极健康的校园文化氛围，语文组通过小初高集体教研以及初高作文教学一体化改革培养学生写作与创作的能力，鼓励学生积极参加各类比赛，让学生在猛烈发展的时代洪流中学会用文字记录生活、表达内心、感悟生命。</span></p><p><br/><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/93520954fb3245549c81a96f11133342.jpg', NULL, true, '2021-11-10 08:00:00+08', '2021-11-10 08:00:00+08', '2021-11-10 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (888, '济南新航实验外国语学校2021年秋季招聘简章', '', '济南新航实验外国语学校是一所十二年一贯制民办非营利学校，秉持“让每一个生命都精彩绽放”的育人理念，现已打造成一所高起点、高品位、高质量的多元化创新型学校。学校现有教职工243位，其中正高级、特级教师3位，高级教师24位，硕博研究生97位，985、211重点大学68位。学校目前在校生1300余人，实行全学段小班化教学。招聘原则招聘将秉承“公平、公开、择优录取”原则。招聘岗位及条件备注说明：如未招聘到...', '', '<p><a href="images/485ad13c390c4d5485fdef3b3854b4c0.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/485ad13c390c4d5485fdef3b3854b4c0.jpg"/></a></p><p><span>济南新航实验外国语学校是一所十二年一贯制民办非营利学校，秉持“让每一个生命都精彩绽放”的育人理念，现已打造成一所高起点、高品位、高质量的多元化创新型学校。</span></p><p><span>学校现有教职工243位，其中正高级、特级教师3位，高级教师24位，硕博研究生97位，985、211重点大学68位。学校目前在校生1300余人，实行全学段小班化教学。</span></p><section><section><section><section><section><p><span><strong>招聘原则</strong></span></p></section></section><section><section><section><p><br/></p></section></section></section></section></section></section><p><br/></p><section><section><p><span>招聘将秉承“公平、公开、择优录取”原则。</span></p></section></section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section><br/></section></section></section><section><section><section><p><span><strong>招聘岗位及条件</strong></span></p><p><strong><a href="images/958edf911f8e49c6a36183dc84c63b39.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/958edf911f8e49c6a36183dc84c63b39.jpg"/></a></strong></p><p><strong><span>备注说明：如未招聘到符合上述岗位条件者，学校有权取消或调整岗位招聘计划。</span></strong></p><p><strong><a href="images/28f20b8bc35844a0a2197c20546a9a39.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/28f20b8bc35844a0a2197c20546a9a39.jpg"/></a><a href="images/7548867f80024686b40fb75ed29af480.jpg" target="_blank"><img title="2.webp.jpg" src="/uploads/migration/images/7548867f80024686b40fb75ed29af480.jpg"/></a><a href="images/82a2129927ab4b638bb5ba5431f12ee6.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/82a2129927ab4b638bb5ba5431f12ee6.jpg"/></a></strong></p><p><strong><br/></strong></p></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span><strong>薪资福利</strong></span></p></section></section><section><section><section><p><br/></p></section></section></section></section></section></section><p><br/></p><section><section><p><span>（一）学科教师优秀应届毕业生年薪10万起，竞赛教练年薪15万起，具体年薪将根据学校薪酬体系定级。</span></p><p><span>（二）五险一金（按照公务员标准缴纳）、子女就读优惠、寒暑假带薪休假、节日福利。</span></p></section></section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section><br/></section></section></section><section><section><section><p><span><strong>报名信息</strong></span></p></section></section><section><section><section><p><br/></p></section></section></section></section></section></section><section><section><p><span><strong>报名网址：</strong>http://baoming.wiscoor.com</span></p><p><span><strong>招聘时间安排：</strong></span></p><p><span>岗位报名时间：2021.11.1-2021.11.30</span></p><p><span>查询简历筛选时间：2021.12.6</span></p><p><span>打印准考证时间：2021.12.10（登录报名网址打印）</span></p><p><span><strong>联系人：</strong>左老师&nbsp;&nbsp;董老师&nbsp;&nbsp;</span></p><p><span><strong>咨询电话：</strong>0531-59516699，0531-59516627</span></p><p><span><strong>招聘报名咨询QQ群：</strong>443223308</span></p><p><span><strong>学校微信公众号</strong><strong>：</strong>济南新航实验外国语学校</span></p><p><span><strong>学校地址</strong><strong>：</strong>山东省济南市经十东路27803号</span></p></section></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/485ad13c390c4d5485fdef3b3854b4c0.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (890, '新航好少年 | 新航实验学子臧鹤睿在杜克数学大会斩获三枚金牌', '', '随着新航实验多元人才培养模式持续创新，一大批优秀学子涌现而出，他们勤学奋进、品学兼优，他们多才多艺、自律自强，他们已经初具新航实验学子的独特气质。请持续关注系列报道——新航好少年。刚刚结束的2021年杜克大学青少年数学大会传来喜报，济南新航实验外国语学校融合班臧鹤睿同学，与来自全国各地的优秀学生进行了为期两天的激烈角逐，斩获Best team Gold，Power round Gold，Team ...', '', '<section><section><p><span>随着新航实验多元人才培养模式持续创新，</span></p><p><span>一大批优秀学子涌现而出，</span></p><p><span>他们勤学奋进、品学兼优，</span></p><p><span>他们多才多艺、自律自强，</span></p><p><span>他们已经初具新航实验学子的独特气质。</span></p><p><span>请持续关注系列报道——新航好少年。</span></p></section></section><p><a href="images/946c7fbe90e6420bbfe132683b0b5628.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/946c7fbe90e6420bbfe132683b0b5628.jpg"/></a></p><p><span>刚刚结束的2021年杜克大学青少年数学大会传来喜报，济南新航实验外国语学校融合班臧鹤睿同学，与来自全国各地的优秀学生进行了为期两天的激烈角逐，斩获Best team Gold，Power round Gold，Team round Gold三个金奖，两轮比赛第一名及总积分第一名的好成绩。</span></p><p><a href="images/8d71ca875d284b3088b179f17bbcc444.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/8d71ca875d284b3088b179f17bbcc444.jpg"/></a></p><section><p><span>臧鹤睿（第一排中间）与BPhO获奖同学合影</span></p><p><br/></p></section><p><section><section><p><span>“臧老师”是同学们对臧鹤睿亲切的称呼。从入学以来，臧鹤睿就对数学、物理表现出了浓厚的兴趣，并且热心帮助身边的同学，主动承担起“小助教”的职责。过去一年中，臧鹤睿在各项竞赛中获得了耀眼的成绩，2021年加拿大滑铁卢（Waterloo Math Contest）系列数学竞赛校园冠军（School Champion），2021年澳大利亚（AMC）数学竞赛二等奖，2021年英国物理思维挑战赛（BPhO）全球金奖。</span></p><p><span>凭借出色的表现，臧鹤睿得到老师和同学的肯定，并获得了新航实验2020-2021学年全面发展标兵、校级三好学生，担任2020级融合班学生大使（Student Ambassador）。</span></p></section></section></p><p><a href="images/be42cb94572340028e821f5fed54e79c.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/be42cb94572340028e821f5fed54e79c.jpg"/></a><a href="images/35f067e4f4334989914415f42236632b.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/35f067e4f4334989914415f42236632b.jpg"/></a></p><section><section><p><span>在新航实验，2021关键词是“Memorable”（难忘的，值得纪念的）。这一年，我收获了满意的成绩，赢得了荣誉，获得了新的学习感悟……</span></p></section></section><p><section><section><p><span>在刚上高一的时候，我认为IG课程的内容都比较简单，所以基本不预习也不复习。考试时我却发现，一个明明自己很熟悉的知识点，到题目里就不会做了。这次的“轻敌”行为，直接导致了第一次附加数学（Additional Math）模拟考试成绩很不理想。此后，记录错题并且在书中找到相应的知识点复习成为了我每天的必修课。一个半月后，模考成绩获得A*并且接近满分。我意识到了预习和复习的重要性，课上的知识能否熟练掌握并灵活运用，靠的是课下不懈努力。</span></p></section></section></p><p><a href="images/85a234c2ab1445d3b4e1ee1a87642736.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/85a234c2ab1445d3b4e1ee1a87642736.jpg"/></a></p><p><span>今年6月，我当选为融合班2020级学生大使。作为学生大使中的学术大使（Academic Ambassador），对于有些问题，我更加倡导同伴学习（Peer study）。通过同学之间的交流和讨论，常常会有“柳暗花明又一村”的感觉，大家对这个题背后的知识点也会有更深的理解。一个人的能力是有限的，团队协作的能量却是无穷的。</span></p><p><img title="1.webp (2).jpg" src="/uploads/migration/images/123919052788460e9d97663a073f22b2.jpg"/></p><p><span>每个新航实验人都如夜空中繁星点点，相互照亮、彼此温暖，让我们携手共进，在美好的年华里收获最好的自己。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/946c7fbe90e6420bbfe132683b0b5628.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (891, '在新航有一种惊喜，叫做“把秋天穿在身上”', '', '“远村秋色如画，红树间疏黄”玉皇山下，新航实验的秋天，是被打翻的调色板，少了几分萧瑟，多了几分喜悦。如果把秋天穿在身上，会是一种怎样的体验呢？带着秋日的这份纯净，在热闹的生活里，重逢诗意，这是秋日里限定的味道。', '', '<section><section><p>“远村秋色如画，红树间疏黄”</p><p>玉皇山下，新航实验的秋天，</p><p>是被打翻的调色板，</p><p>少了几分萧瑟，多了几分喜悦。</p><p>如果把秋天穿在身上，</p><p>会是一种怎样的体验呢？</p><p><a href="images/fbbbf9b93f6241b3b4164b17966922d8.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/fbbbf9b93f6241b3b4164b17966922d8.jpg"/></a><a href="images/55a40847267f484d8c99fb8826cc4e97.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/55a40847267f484d8c99fb8826cc4e97.jpg"/></a><a href="images/b7a5e9ef8b3e4f48831eec9e127d82cc.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/b7a5e9ef8b3e4f48831eec9e127d82cc.jpg"/></a><a href="images/71b4fab008164c05851bde4501e4dcd6.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/71b4fab008164c05851bde4501e4dcd6.jpg"/></a><a href="images/79ce371bc5f1486f9754eb7ba3933e8b.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/79ce371bc5f1486f9754eb7ba3933e8b.jpg"/></a></p><p>带着秋日的这份纯净，</p><p>在热闹的生活里，</p><p>重逢诗意，</p><p>这是秋日里限定的味道。</p><p><a href="images/4fa5ef33b39246a7a92a8e4654f1fe18.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/4fa5ef33b39246a7a92a8e4654f1fe18.jpg"/></a><a href="images/c9bb9ef6ae1647c5836d481c7873752b.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/c9bb9ef6ae1647c5836d481c7873752b.jpg"/></a><a href="images/662490e09caf44bbbc36fadcc2f88560.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/662490e09caf44bbbc36fadcc2f88560.jpg"/></a><a href="images/557cb7e132494355a938a1ee32b88257.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/557cb7e132494355a938a1ee32b88257.jpg"/></a><a href="images/9ac743ffdbd04a46bf2d87ed5f05ed38.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/9ac743ffdbd04a46bf2d87ed5f05ed38.jpg"/></a></p></section></section><p><section><section><section></section></section></section></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/fbbbf9b93f6241b3b4164b17966922d8.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (892, '今朝纸上梦想 明日圆梦天空——新航实验9名学子在国际航联青少年航空绘画大赛中获奖', '', '近日，由国家体育总局航管中心、中国航空运动协会主办的2021年“飞北”绘画评比活动暨国际航联青少年航空绘画大赛落下帷幕，济南新航实验外国语学校9名学子突出重围，喜获佳绩，其中，初二2班纪子昂同学荣获中国区选拔赛一等奖，济南新航实验外国语学校获评“优秀组织单位”。本次比赛，山东地区选拔赛共有1.5万余幅作品参赛，选拔出的优秀作品通过山东省航空运动协会报送中国航协参与更高层次的奖项角逐。初二2班 纪子...', '', '<p><span>近日，由国家体育总局航管中心、中国航空运动协会主办的2021年“飞北”绘画评比活动暨国际航联青少年航空绘画大赛落下帷幕，济南新航实验外国语学校9名学子突出重围，喜获佳绩，其中，初二2班纪子昂同学荣获中国区选拔赛一等奖，济南新航实验外国语学校获评“优秀组织单位”。</span></p><p><a href="images/6346da06f3db414d91eab73efc185299.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/6346da06f3db414d91eab73efc185299.jpg"/></a><a href="images/9904252c4ff24bf493c376ff3bd93958.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/9904252c4ff24bf493c376ff3bd93958.jpg"/></a></p><p><span>本次比赛，山东地区选拔赛共有1.5万余幅作品参赛，选拔出的优秀作品通过山东省航空运动协会报送中国航协参与更高层次的奖项角逐。</span></p><p><span><a href="images/67011573df964d60b8e07b0537a6636f.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/67011573df964d60b8e07b0537a6636f.jpg"/></a><a href="images/539c0688218643f68fc48f458f07bf20.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/539c0688218643f68fc48f458f07bf20.jpg"/></a><a href="images/4a967863678d425a8ac48d96e175a508.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/4a967863678d425a8ac48d96e175a508.jpg"/></a></span></p><p><span><strong>初二2班 纪子昂 《飞行，让世界友谊长存》</strong></span></p><p><span><strong><a href="images/7a71010a66de4ba3863d8fd97650d75f.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/7a71010a66de4ba3863d8fd97650d75f.jpg"/></a></strong></span></p><p><span><strong><strong>初二4班 薛子都&nbsp;《航空·筑梦》</strong></strong></span></p><p><span><strong><strong><a href="images/1a0325d4a5f841f38ffb50e60afcd1aa.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/1a0325d4a5f841f38ffb50e60afcd1aa.jpg"/></a></strong></strong></span></p><p><span><strong><strong><strong>初二5班 李笑羽&nbsp;《起飞·远行》</strong></strong></strong></span></p><p><span><strong><strong><strong><a href="images/0e74b15564b543309142b4e6b7250c47.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/0e74b15564b543309142b4e6b7250c47.jpg"/></a></strong></strong></strong></span></p><p><span><strong><strong><strong><strong>初二1班 石雨琪&nbsp;《不凡的航天年》</strong></strong></strong></strong></span></p><p><span><strong><strong><strong><strong><a href="images/c00492186b264b7b99cfaf7ba332c8e4.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/c00492186b264b7b99cfaf7ba332c8e4.jpg"/></a></strong></strong></strong></strong></span></p><p><span><strong><strong><strong><strong><strong>高二1班 王禹霏《飞行，让世界友谊长存》</strong></strong></strong></strong></strong></span></p><p><span><strong><strong><strong><strong><strong><a href="images/8e2ed850f03641c3be108ef3699841dc.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/8e2ed850f03641c3be108ef3699841dc.jpg"/></a></strong></strong></strong></strong></strong></span></p><p><span><strong><strong><strong><strong><strong><strong>高二3班 武辰耕&nbsp;《联系世界的友谊》</strong></strong></strong></strong></strong></strong></span></p><p><a href="images/0e611321d4a6440ab54baf66ae19837c.jpg" target="_blank"><img title="6.webp.jpg" src="/uploads/migration/images/0e611321d4a6440ab54baf66ae19837c.jpg"/></a></p><p><span>参与青少年航空绘画大赛，进一步向新航实验学子普及了航空航天知识，不仅培养了学生的动手动脑能力，也将航空运动与艺术有机地融合起来，提升了学生们敏锐地观察、领悟世界的意识和审美判断能力，激励着新航实验学子今天用画笔描绘、明天用知识实现美好的航空航天梦。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/6346da06f3db414d91eab73efc185299.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (893, '遇见·携手·共未来——初一级部举行学生成长导师制师生见面会', '', '“师者，传道授业解惑也。”教师不仅是教授知识的教书匠，更是照亮学生前进道路的灯塔。为进一步密切师生关系，增进教师和学生的深入了解，落实全员全过程全方位的育人理念，济南新航实验外国语学校初一级部举行学生成长导师制师生见面会。健全的导师团队初一导师团队融合了语文、数学、英语、物理、历史、政治、地理、生物和体育九大学科，极大满足了学生的个性化需求。在此基础上，初一级部参照研究生导师的管理制度，实施导师与...', '', '<p><span>“师者，传道授业解惑也。”教师不仅是教授知识的教书匠，更是照亮学生前进道路的灯塔。为进一步密切师生关系，增进教师和学生的深入了解，落实全员全过程全方位的育人理念，济南新航实验外国语学校初一级部举行学生成长导师制师生见面会。</span></p><p><a href="images/d2c69d5dca1144638b98911ac6e62d5e.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/d2c69d5dca1144638b98911ac6e62d5e.jpg"/></a><a href="images/9a5817fb3c1043c09f5bf8c5e8267dfc.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/9a5817fb3c1043c09f5bf8c5e8267dfc.jpg"/></a><a href="images/75f6b2bafbd141c6a41738430965ce49.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/75f6b2bafbd141c6a41738430965ce49.jpg"/></a></p><section><section><section><section><section><section><section><p><span><strong>健全的导师团队</strong></span></p></section></section></section></section></section></section></section><p></p><section><section><section><section><section><p><br/></p></section></section></section><section><section><p><span>初一导师团队融合了语文、数学、英语、物理、历史、政治、地理、生物和体育九大学科，极大满足了学生的个性化需求。在此基础上，初一级部参照研究生导师的管理制度，实施导师与学生双向选择制，以便在深入了解学生学习和生活的同时，为学生量身定制成长计划，真正达到“因材施教”的教育目标。</span></p></section></section></section></section><p></p><p><a href="images/b3a5e615caa240e287b8cc08453cb95e.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/b3a5e615caa240e287b8cc08453cb95e.jpg"/></a><a href="images/4a9e3c21019b40a3b31ca5b80a166f56.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/4a9e3c21019b40a3b31ca5b80a166f56.jpg"/></a><a href="images/e97af8e1f04645a49e0c9bf8c97c4bbe.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/e97af8e1f04645a49e0c9bf8c97c4bbe.jpg"/></a><a href="images/850dc7cfe70a4966a21ef87cb84d22f9.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/850dc7cfe70a4966a21ef87cb84d22f9.jpg"/></a><a href="images/5965d827d7ee4d4d86ba691b013b29bc.jpg" target="_blank"><img title="5.webp.jpg" src="/uploads/migration/images/5965d827d7ee4d4d86ba691b013b29bc.jpg"/></a></p><section><section><section><section><section><section><section><p><span><strong>完善的预约制度</strong></span></p></section></section></section></section></section></section></section><p></p><section><section><section><section><section><p><br/></p></section></section></section><section><section><p><span>为了提高学生成长导师制的实施效率，老师们充分利用每班门口的电子班牌，将预约信息以“跑马灯”样式<span>滚动显示，既避免了迟到现象的发生，也有利于学生提前做好准备，提高了与导师的沟通效率。</span></span></p></section></section></section></section><p></p><p><a href="images/a5e8df70aea44d939746a5a453659055.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/a5e8df70aea44d939746a5a453659055.jpg"/></a><a href="images/613c6e30445047e88eb04f2012ac25dd.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/613c6e30445047e88eb04f2012ac25dd.jpg"/></a><a href="images/17275635340e46738c459c05fde57472.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/17275635340e46738c459c05fde57472.jpg"/></a></p><section><section><section><section><section><section><section><p><span><strong>高效的指导效率</strong></span></p></section></section></section></section></section></section></section><p></p><section><section><section><section><section><p><br/></p></section></section></section><section><section><p><span>在学生成长导师制师生见面会过程中，导师与学生开展了深入且高效的交流。学生分享自己学习和生活上遇到的问题，导师则根据自己的经验给予他们恰当的指导，一起制定学习、生活规划，让孩子们快乐学习，快乐成长！</span></p></section></section></section></section><p></p><p><a href="images/9211d10dfb6a4396afd2599ed8ecaee5.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/9211d10dfb6a4396afd2599ed8ecaee5.jpg"/></a><a href="images/72ed828c8d05442f93fb24d5596f53ec.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/72ed828c8d05442f93fb24d5596f53ec.jpg"/></a></p><p><span>世界上没有两片一模一样的树叶，人亦如此，每一个生命都是独特的。初一级部学生成长导师制活动，将始终致力于学生的个性化发展，让每一个生命都能绽放出属于自己的耀眼光芒！</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/d2c69d5dca1144638b98911ac6e62d5e.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (894, '模拟真实场景，以“练”促“防”——新航实验组织开展防疫实战演练', '', '为严格落实近日省市教育系统疫情防控工作视频会议精神，确保师生平安健康，坚决守住校园疫情防控底线，济南新航实验外国语学校在行动。11月1日、2日，新航实验先后组织全体教职工、全体外包工作人员召开了学校安全工作和疫情防控部署会。11月4日、5日，新航实验在全校范围内开展疫情实战演练活动，使师生熟知疫情防控要求和流程，提高防范和应急处置能力。入校篇       校门口保安对入校的学生进行体温检测，并提醒...', '', '<section><section><section><p><span>为严格落实近日省市教育系统疫情防控工作视频会议精神，确保师生平安健康，坚决守住校园疫情防控底线，济南新航实验外国语学校在行动。</span></p></section></section></section><p><section><section><section><section><section><section></section></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><section><section><section><p><span>11月1日、2日，新航实验先后组织全体教职工、全体外包工作人员召开了学校安全工作和疫情防控部署会。</span></p></section></section></section></p><p><a href="images/f4d689346d684417b3bddc497fcf4f60.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/f4d689346d684417b3bddc497fcf4f60.jpg"/></a><a href="images/870deacd3bec461b98fe20eb79e9d1e2.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/870deacd3bec461b98fe20eb79e9d1e2.jpg"/></a></p><section><section><section><p><span>11月4日、5日，新航实验在全校范围内开展疫情实战演练活动，使师生熟知疫情防控要求和流程，提高防范和应急处置能力。</span></p></section></section></section><p><section><section><section><section><p><span><strong>入校篇</strong></span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><section><section><section><p><span>&nbsp; &nbsp; &nbsp;&nbsp; 校门口保安对入校的学生进行体温检测，并提醒佩戴口罩，与被测者保持距离。一旦体温超过37.3℃，则不得进入校门，送到临时处置点，由校医详细询问登记后通知其家长接回，消毒组对校门口进行消毒。</span></p><p><a href="images/f734a06ed43c43f3b260416853994fe5.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/f734a06ed43c43f3b260416853994fe5.jpg"/></a></p><section><section><section><section><p><span><strong>教室篇</strong></span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><p><section><section><section><p><span>对于出现发热、咳嗽等症状的学生，任课老师首先对其进行体温测量。如果体温超过37.3℃，则按照疫情应急处置预案，第一时间转移发热学生至临时处置点，并交由校医进行下一步处理；另一位老师将班内其他学生转移至备用教室，并对原教室进行彻底消毒。</span></p></section></section></section></p><p><a href="images/42ab970244504f61924e9036c2d311dd.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/42ab970244504f61924e9036c2d311dd.jpg"/></a><a href="images/a8f625a1df9b4c8bbc90cccff8ae132b.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/a8f625a1df9b4c8bbc90cccff8ae132b.jpg"/></a><a href="images/fd17b55095ea4f60a32d5fe8c05e0597.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/fd17b55095ea4f60a32d5fe8c05e0597.jpg"/></a></p><section><section><section><section><p><span><strong>宿舍篇</strong></span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><p><section><section><section><p><span>宿舍内，生活指导老师与宿管协同配合，测温、联系校医、转移学生至隔离宿舍、终末消毒等，每个步骤有条不紊地进行。</span></p></section></section></section></p><p><a href="images/3f875c037c454bf6868018efd30d38d1.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/3f875c037c454bf6868018efd30d38d1.jpg"/></a><a href="images/f16fb53c953a415da76b35d0ae190b58.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/f16fb53c953a415da76b35d0ae190b58.jpg"/></a></p></section></section></section></p><section><section><section><section><p><span><strong>餐厅篇</strong></span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><p><section><section><section><p><span>某同学进入餐厅时，测温设备报警，值班教师立即通知校医，将其转移到餐厅外临时处置点。校医做好防护措施后对其进行体温复测，并发现该学生具有流行病史等。根据疫情防控预案，学校立即上报相关部门，联系120转运至医院发热门诊，同时启动应急预案，对餐厅进行紧急管控。</span></p></section></section></section></p><p><a href="images/40b52a5171b148e6a767851aedc2ee4a.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/40b52a5171b148e6a767851aedc2ee4a.jpg"/></a><a href="images/2e163dee40ec42fd95239dfe2935edce.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/2e163dee40ec42fd95239dfe2935edce.jpg"/></a></p><p><span>生命重于泰山，疫情就是命令。通过此次疫情防控应急演练，新航实验师生进一步熟知掌握各环节操作流程和防控重点，并在实战中发现问题、解决问题，为应对疫情突发状况积累经验，为常态化疫情防控工作打下坚实基础。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/f4d689346d684417b3bddc497fcf4f60.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (895, '一生一案——初中部持续落实个性化辅导，为学生全面发展保驾护航', '', '对于济南新航实验外国语学校初中部的不少同学来说，每天进行的个性化辅导是一天中“幸福感和获得感满满”的时刻。学生自步入初中伊始，就拥有了自己的“专属老师”，量身定制的学习目标、触手可及的每日计划、个性鲜明的辅导方案，从基础训练到能力提升，让每一位同学获益匪浅，真正践行了“让每一个生命都精彩绽放”的理念。 var flashvars={ f:"/media/0/09dab63671aa4977bb30...', '', '<p><span>对于济南新航实验外国语学校初中部的不少同学来说，每天进行的个性化辅导是一天中“幸福感和获得感满满”的时刻。学生自步入初中伊始，就拥有了自己的“专属老师”，量身定制的学习目标、触手可及的每日计划、个性鲜明的辅导方案，从基础训练到能力提升，让每一位同学获益匪浅，真正践行了“让每一个生命都精彩绽放”的理念。</span></p>
<p><span></span></p>
<p>
 <div id="mediaContent0_0"></div> <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> <script type="text/javascript">
    var flashvars={
        f:"/media/0/09dab63671aa4977bb309e9b4d476517.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/09dab63671aa4977bb309e9b4d476517.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script></p>
<p><span><br></span></p>
<p><span><a href="images/a5d0ed0f93d54501ad959f3f605d2ded.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/a5d0ed0f93d54501ad959f3f605d2ded.jpg"></a><a href="images/64019e911dd041d1afd9a143bd35f4e0.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/64019e911dd041d1afd9a143bd35f4e0.jpg"></a><a href="images/5b3c3a82cf594d7b858d4ae8c1c8e4fb.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/5b3c3a82cf594d7b858d4ae8c1c8e4fb.jpg"></a><a href="images/f276b36edb2948d3b87cea0b1fe9f519.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/f276b36edb2948d3b87cea0b1fe9f519.jpg"></a></span></p>
<p><span>初中部始终致力于打造全体教师全员参与学生学习发展全过程，落实差异化教育、个性化培养这一育人机制，把学生初中三年纳入整体规划：初一针对学情、夯实基础，侧重于习惯养成。初二规划提升、塑造能力，中考保驾护航……在新中考背景下，立足全员育人理念，满足学生个性化发展需求，强化老师全方位、全过程指导，让“育人”之种开花结果。</span></p>
<p><a href="images/076ab5cb4be84d46bdb0567626ea365d.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/076ab5cb4be84d46bdb0567626ea365d.jpg"></a><a href="images/ea172b59ced44bcea33640999af08091.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/ea172b59ced44bcea33640999af08091.jpg"></a><a href="images/cdc286928c3c41f29e178d0376be3687.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/cdc286928c3c41f29e178d0376be3687.jpg"></a><a href="images/9cf6287aed4549acbc63ab2c71dd3315.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/9cf6287aed4549acbc63ab2c71dd3315.jpg"></a></p>
<p><span>以初二8班班主任王梦雅为例，根据个性化辅导方案，她与学生双向选择，负责12名学生英语成绩的强化培优工作，给予学生悉心指导。每一次学业成绩的变动、每一次学生参与各类比赛的努力成果、每一次学生的奋斗行动，她都如实记录在学生成长手册上。针对不同学情，详细列出12位同学的优势与短板，给出针对性建议，引导学生找到自己未来发展的方向。</span></p>
<p><span>“个性化辅导以尊重学生们的差异性为前提，因材施教。我们应当支持、鼓励学生的变化，让孩子完全释放自己的潜能。”对于个性化辅导，王梦雅老师这样理解。</span></p>
<p><a href="images/452e3a3ee4424bec91dc55405046de37.jpg" target="_blank"><img title="1.webp (2).jpg" src="/uploads/migration/images/452e3a3ee4424bec91dc55405046de37.jpg"></a><a href="images/722fa4dab42a47e4b8c0664bd3afd52b.jpg" target="_blank"><img title="2.webp (1).jpg" src="/uploads/migration/images/722fa4dab42a47e4b8c0664bd3afd52b.jpg"></a><a href="images/1f8fd83ee506476fbe0755e1ac363da9.jpg" target="_blank"><img title="3.webp.jpg" src="/uploads/migration/images/1f8fd83ee506476fbe0755e1ac363da9.jpg"></a><a href="images/8ae79854279a44689d7e197f7cf09d51.jpg" target="_blank"><img title="4.webp.jpg" src="/uploads/migration/images/8ae79854279a44689d7e197f7cf09d51.jpg"></a></p>
<section>
 <section>
  <p><span>个性化辅导工作的推行，实现了教育效果的最大化，对学生的学习起到至关重要的作用。同时，实现了教师教育价值的最大化，这一形式也越来越得到学生和家长的认可。</span></p>
 </section>
</section>
<p></p>
<section>
 <section>
  <section></section>
 </section>
</section>
<p></p>
<p><br></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/a5d0ed0f93d54501ad959f3f605d2ded.jpg', NULL, true, '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '2021-11-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (896, '写好中国字 做好中国人——探秘新航实验小学部常态化写字教育', '', 'var flashvars={ f:"/media/0/3c6afdab90634f94bbe8e586182e52ba.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; var video=["/media/0/3c6a...', '', '<p><br></p>
<p><br></p>
<p>
 <div id="mediaContent0_0"></div> <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> <script type="text/javascript">
    var flashvars={
        f:"/media/0/3c6afdab90634f94bbe8e586182e52ba.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/3c6afdab90634f94bbe8e586182e52ba.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script></p>
<p><span>写好中国字,做好中国人。为开展汉字书写教学研究与实践，切实提高学生书写水平，让学生在规范汉字书写中养成习惯，涵养性格，济南新航实验外国语学校小学部“书香墨韵”规范汉字书写工作扎实起步。</span></p>
<p><span><a href="images/6ba86a52bddf4a6fb481000e3b53f4b1.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6ba86a52bddf4a6fb481000e3b53f4b1.jpg"></a><a href="images/e2d7c199992a466c8bee83f6e6a74e52.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e2d7c199992a466c8bee83f6e6a74e52.jpg"></a><a href="images/4f7487dbde2e45939b0667c32f1eda18.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/4f7487dbde2e45939b0667c32f1eda18.jpg"></a><a href="images/14671e0373414245be06c82927c0affe.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/14671e0373414245be06c82927c0affe.jpg"></a></span></p>
<p><span></span></p>
<section>
 <section>
  <section>
   <section>
    <section>
     <p><span><strong>先做学生 再做先生</strong></span></p>
    </section>
   </section>
  </section>
  <section>
   <section>
    <section>
     <section>
      <section>
       <section>
        <section>
         <section></section>
        </section>
       </section>
      </section>
     </section>
    </section>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <section>
   <section>
    <section>
     <p><span>小学部把落实师资力量作为头等大事来抓，要求所有语文老师先做学生，再做先生。一年级年级主任、市教学能手、市优课一等奖获得者王真老师，二年级年级主任、山东省远程研修优秀研修组长、市中区学生硬笔书法比赛优秀指导教师张婉老师，骨干教师、全国中小学生绘画书法大赛优秀指导教师王佩老师对全体语文老师进行写字指导经验分享和专题培训。</span></p>
     <p><span><a href="images/9ba0654c9be9460fbffc1b0c33c373a0.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/9ba0654c9be9460fbffc1b0c33c373a0.jpg"></a><a href="images/51d9cd5338f941638bb389c530e257a2.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/51d9cd5338f941638bb389c530e257a2.jpg"></a><a href="images/73a32b0f19b04a2bb058a7b072b9f496.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/73a32b0f19b04a2bb058a7b072b9f496.jpg"></a></span></p>
     <section>
      <section>
       <p><span>教师的板书和批语是对学生最好的示范，用扎实美观的书写，潜移默化激发学生写好字的欲望，真正在每一节课上都起到示范作用。</span></p>
      </section>
     </section>
     <p><a href="images/a8ddb5a7dc2144679250ae93a8fc4836.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/a8ddb5a7dc2144679250ae93a8fc4836.jpg"></a><a href="images/4dc15aca5708441db3b9d5feba93ae88.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/4dc15aca5708441db3b9d5feba93ae88.jpg"></a><a href="images/84ffbef3ff914b20abcb48c2ea074589.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/84ffbef3ff914b20abcb48c2ea074589.jpg"></a></p>
     <section>
      <section>
       <section>
        <section>
         <section>
          <p><span><strong>编写教材 临帖模仿</strong></span></p>
         </section>
        </section>
       </section>
       <section>
        <section>
         <section>
          <section>
           <section>
            <section>
             <section>
              <section></section>
             </section>
            </section>
           </section>
          </section>
         </section>
        </section>
       </section>
      </section>
     </section>
     <p></p>
     <section>
      <section>
       <section>
        <section>
         <section>
          <p><span>王佩老师结合教材内容和教学进度，为一二年级小航们编写了手写体楷书配套书法练习册，并对教材使用进行了专项培训。练习册采用活页形式，一课一练，扎实练好笔画，认真观察布局，起笔、运笔、收笔，逐字临摹，为学生规范书写提供了很好的范例。</span></p>
         </section>
        </section>
       </section>
      </section>
     </section>
     <p></p>
     <p><a href="images/62e7944c124c403ebd0f19804e856b25.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/62e7944c124c403ebd0f19804e856b25.jpg"></a><a href="images/fbce7a5c3ae84e1792f7e7125dd22ace.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/fbce7a5c3ae84e1792f7e7125dd22ace.jpg"></a></p>
     <section>
      <section>
       <p><span>求术之长者，必同其根本。新航实验小学部的写字时间分为两部分，一是午写一刻钟，周一至周五雷打不动，精讲精练。二是随堂写字指导练习，将规范汉字书写作为课堂的一个基本环节加以落实。</span></p>
      </section>
     </section>
     <p><a href="images/1a5e418a91074449bb4954435d39a0f9.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/1a5e418a91074449bb4954435d39a0f9.jpg"></a><a href="images/a9942cb08432408dbee3608826fa917b.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/a9942cb08432408dbee3608826fa917b.jpg"></a><a href="images/c08fd2187a8141c492e50d30e52a4b26.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c08fd2187a8141c492e50d30e52a4b26.jpg"></a><span></span></p>
     <section>
      <section>
       <section>
        <section>
         <section>
          <p><span><strong>留存写字档案 记录成长足迹</strong></span></p>
         </section>
        </section>
       </section>
       <section>
        <section>
         <section>
          <section>
           <section>
            <section>
             <section>
              <section></section>
             </section>
            </section>
           </section>
          </section>
         </section>
        </section>
       </section>
      </section>
     </section>
     <p></p>
     <section>
      <section>
       <section>
        <section>
         <section>
          <p><span>各班为小航们专门建立了写字小档案，呈现孩子习字的过程和成长变化，激励孩子横向比较中，不断突破和成就自己，督促其养成“提笔就练字”的好习惯。</span></p>
          <p><span><a href="images/14d91f154fc34b6aaee691f4b5e37c65.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/14d91f154fc34b6aaee691f4b5e37c65.jpg"></a><a href="images/877c97401fca44a7b9440b6b2eb26bae.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/877c97401fca44a7b9440b6b2eb26bae.jpg"></a><a href="images/6fd93b9e289d4bb3b02614af1ec41c1c.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/6fd93b9e289d4bb3b02614af1ec41c1c.jpg"></a><a href="images/d6a4ccf5f3404d24b844d4f70245b842.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/d6a4ccf5f3404d24b844d4f70245b842.jpg"></a></span></p>
          <p><span></span></p>
          <section>
           <section>
            <section>
             <section>
              <section>
               <p><span><strong>搭建展示平台 体验成功之乐</strong></span></p>
              </section>
             </section>
            </section>
            <section>
             <section>
              <section>
               <section>
                <section>
                 <section>
                  <section>
                   <section></section>
                  </section>
                 </section>
                </section>
               </section>
              </section>
             </section>
            </section>
           </section>
          </section>
          <p></p>
          <section>
           <section>
            <section>
             <section>
              <section>
               <p><span>为检验练字实效，小学部定期举行“书香墨韵”学生书写展示，巩固正确坐姿和执笔姿势，培养干净、整洁的良好书写习惯；每班推选出优秀书法作品在班级展台展示，树立班级小榜样；教室专设书法角，课余时间挥毫泼墨，师生切磋共进，生生互学互评，一批批“新航小书法家”将在这里孕育，诞生！</span></p>
               <p><a href="images/2d940c2ecae44577bc0f4826deac70ae.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/2d940c2ecae44577bc0f4826deac70ae.jpg"></a><a href="images/cd59d8bce8cd4e23a3bac6bc12c24339.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/cd59d8bce8cd4e23a3bac6bc12c24339.jpg"></a><a href="images/f1ab19f72e354cf0ad3b083688beb930.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/f1ab19f72e354cf0ad3b083688beb930.jpg"></a><a href="images/eabd5296861b425bb13c779cbf7363bc.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/eabd5296861b425bb13c779cbf7363bc.jpg"></a><a href="images/5bcc40a56acf4504bc6f80f7e87a547d.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/5bcc40a56acf4504bc6f80f7e87a547d.jpg"></a><a href="images/040e95c9cc3a4c4f86e8d3046749c631.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/040e95c9cc3a4c4f86e8d3046749c631.jpg"></a></p>
               <p><span>一手好字，终生受益。小学低年级是书法启蒙的敏感期、关键期，也是硬笔书法练习的最佳时期。抓住这一黄金阶段，充分认识写字的重要性，让学生乐于写好字，有能力写好字，自觉写好字，语文教师肩上的责任重大。做学生习字路上的领航人，新航实验小学部“让练字成为常态，让教育回归本真”的教研之花初现蓓蕾。</span></p>
              </section>
             </section>
            </section>
           </section>
          </section>
          <p></p>
          <p><span><br><br></span></p>
         </section>
        </section>
       </section>
      </section>
     </section>
     <p></p>
     <p><br></p>
    </section>
   </section>
  </section>
 </section>
</section>
<p></p>
<p><span><br><br></span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/6ba86a52bddf4a6fb481000e3b53f4b1.jpg', NULL, true, '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (897, '触摸历史，巧手传承——新航实验首届历史文物模型手工制作大赛收官', '', '敦煌飞天的舞姿 从长江三峡的涛声 到两弹腾空的轨道 …… 琳琅满目的历史文物， 让我们认识了历史的悠久 领略着历史的飘逸 读懂了历史的雄厚 感受着历史的壮阔   历史记忆·巧手传承 为进一步弘扬中华传统文化，增强学生的民族文化自信，丰富校园文化生活，2021年9月16日至10月19日，济南新航实验外国语学校初中部举办了以“历史记忆·巧手传承”为主题的首届历史文物模型手工制作大赛，学校初中部初一、初...', '', '<p><span>敦煌飞天的舞姿</span></p>
<p><span>从长江三峡的涛声</span></p>
<p><span>到两弹腾空的轨道</span></p>
<p><span>……</span></p>
<p><span>琳琅满目的历史文物，</span></p>
<p><span>让我们认识了历史的悠久</span></p>
<p><span>领略着历史的飘逸</span></p>
<p><span>读懂了历史的雄厚</span></p>
<p><span>感受着历史的壮阔</span></p>
<p><span>&nbsp;</span></p>
<p><strong><span>历史记忆·巧手传承</span></strong></p>
<p><span>为进一步弘扬中华传统文化，增强学生的民族文化自信，丰富校园文化生活，2021年9月16日至10月19日，济南新航实验外国语学校初中部举办了以“历史记忆·巧手传承”为主题的首届历史文物模型手工制作大赛，学校初中部初一、初二全体学生参加了此次活动。</span></p>
<p><span>活动中，新航学子穿越时间隧道，在品味先辈智慧、感受历史源于生活中，展示着良好的社会历史风貌，滋养着自身好学乐学的精神。</span></p>
<p><span>下面就让我们一起来回顾一下，</span></p>
<p><span>此次大赛的精彩瞬间吧！</span></p>
<p><strong><span>闻“令”而动</span></strong></p>
<p><span>新航实验学子闻“令”而行，利用“双节”假期大显身手，以单独制作和集体协作的方式参与到此次大赛中，展现了超强的动手能力和实践能力。家长们全力配合，照片、视频齐上阵，记录着孩子们制作过程的点点滴滴。</span></p>
<p><span><a href="images/95e833b2e3ca4093af08c66fc3cd341c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/95e833b2e3ca4093af08c66fc3cd341c.jpg"></a><a href="images/3d50ad95a79649d9b5e3860493b1148d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/3d50ad95a79649d9b5e3860493b1148d.jpg"></a><a href="images/a96818a8c87e4569abd71f90dc5687c8.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/a96818a8c87e4569abd71f90dc5687c8.jpg"></a><a href="images/d880717114c84f15a8eb98b2058d9b32.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/d880717114c84f15a8eb98b2058d9b32.jpg"></a><a href="images/506e04f745994594b2b88730bbd7cf12.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/506e04f745994594b2b88730bbd7cf12.jpg"></a><a href="images/bd897f4df48c4d28a4db13f5c97db46b.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/bd897f4df48c4d28a4db13f5c97db46b.jpg"></a><a href="images/17a07cb45aff443ebfc2c5424b533e79.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/17a07cb45aff443ebfc2c5424b533e79.jpg"></a><a href="images/3574d546848243a59e0e88fd7aecdc4f.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/3574d546848243a59e0e88fd7aecdc4f.jpg"></a>&nbsp;</span></p>
<p><strong><span>大“展”风采</span></strong></p>
<p><span>经过同学们的认真准备，此次活动共收到学生参赛作品200余件。所有参赛作品在学校进行展览，让全校学生在观摩历史文物作品中，进一步感受传统历史文化的魅力，激发历史的学习热情。</span></p>
<p><span><a href="images/5267d771d94a4488b06ff79a10523890.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/5267d771d94a4488b06ff79a10523890.jpg"></a><a href="images/5d7574ed368443e899696c0c34b07502.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/5d7574ed368443e899696c0c34b07502.jpg"></a><a href="images/88fbf6c17f094c118bd02f47e7c4cba8.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/88fbf6c17f094c118bd02f47e7c4cba8.jpg"></a><a href="images/f97134588a664592a8286a7427478cfa.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/f97134588a664592a8286a7427478cfa.jpg"></a><a href="images/a4d0386a86de462683b200d8cf2c7e47.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/a4d0386a86de462683b200d8cf2c7e47.jpg"></a><a href="images/3d2c0277ba224ca99c1657f49c2bc1a3.jpg" target="_blank"><img title="14.jpg" src="/uploads/migration/images/3d2c0277ba224ca99c1657f49c2bc1a3.jpg"></a><a href="images/5f8652dc8784406e953460c7b5689fcc.jpg" target="_blank"><img title="15.jpg" src="/uploads/migration/images/5f8652dc8784406e953460c7b5689fcc.jpg"></a><a href="images/a5c99de6461c4ecf89334d995fed7db0.jpg" target="_blank"><img title="16.jpg" src="/uploads/migration/images/a5c99de6461c4ecf89334d995fed7db0.jpg"></a><a href="images/2b05a3e8f410453c9f04b8e782f42014.jpg" target="_blank"><img title="17.jpg" src="/uploads/migration/images/2b05a3e8f410453c9f04b8e782f42014.jpg"></a><a href="images/a85b9a28e3704deab777323ef575c310.jpg" target="_blank"><img title="18.jpg" src="/uploads/migration/images/a85b9a28e3704deab777323ef575c310.jpg"></a><a href="images/fe96178c0836435cb7056e901f18bd70.jpg" target="_blank"><img title="19.jpg" src="/uploads/migration/images/fe96178c0836435cb7056e901f18bd70.jpg"></a><a href="images/230534a6841b485eb860c57e49ed59b7.jpg" target="_blank"><img title="20.jpg" src="/uploads/migration/images/230534a6841b485eb860c57e49ed59b7.jpg"></a>&nbsp;</span></p>
<p><span>&nbsp;</span></p>
<p><span>经过最终评选，62件作品脱颖而出，其中特等奖6名，一等奖12名，二等奖18名，三等奖26名。</span></p>
<p><span>&nbsp;<a href="images/87d6b5bf22ae4289808f9d57aba224fe.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/87d6b5bf22ae4289808f9d57aba224fe.jpg"></a><a href="images/7bc07de1b9dc45c79bdf9f3a21f0f18e.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/7bc07de1b9dc45c79bdf9f3a21f0f18e.jpg"></a><a href="images/c1f9df665c0548de8cad328ea2b6c03f.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c1f9df665c0548de8cad328ea2b6c03f.jpg"></a><a href="images/5f14de0bf6e340e69cfb1f10962362d5.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/5f14de0bf6e340e69cfb1f10962362d5.jpg"></a><a href="images/8dc5037bd77045ea96ce0482db036431.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/8dc5037bd77045ea96ce0482db036431.jpg"></a></span></p>
<p><span><strong>有“感”而发</strong></span></p>
<p><span><strong><a href="images/c539ba7cca3444ec89767a4257e73cec.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/c539ba7cca3444ec89767a4257e73cec.jpg"></a></strong></span></p>
<p><span>从最初宣布历史作业，我的目光便锁定在了赵州桥上。看着复杂的结构工艺，我简直不敢想象李春先生是如何设计出这样巧妙的图纸，先人们又是如何在技术有限的情况下，将每个机关都做得恰到好处。与其说是一座桥，不如说是先人智慧的结晶。制作过程确实很累，也有很多不足和犯难的地方，但既提高了手工能力，又提高了我对古代手工技艺的认知。</span></p>
<p><span><strong><span><a href="images/9be9357b9eae47e59504203e01478a95.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/9be9357b9eae47e59504203e01478a95.jpg"></a></span></strong></span></p>
<p><span><strong></strong></span></p>
<div>
 <div id="mediaContent0_0"></div> 
 <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
 <script type="text/javascript">
    var flashvars={
        f:"/media/0/3b695a7a76bd45b081253f437a2ee3e3.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/3b695a7a76bd45b081253f437a2ee3e3.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script>
</div>
<p><span>创作小故事：作品的主要材料纸板不够用，邻居们纷纷“慷慨解囊”，送了我们几个大箱子。制作屋顶时，因为纸箱不合适，我们来回试验了好几种材料，铁丝、吸管等，最后决定用筷子来制作。</span><span><strong></strong></span><br></p>
<p><span><a href="images/f39db09faec1445fac360048ea0198f2.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f39db09faec1445fac360048ea0198f2.jpg"></a></span></p>
<p><span></span></p>
<div>
 <div id="mediaContent0_1"></div> 
 <script type="text/javascript">
    var flashvars={
        f:"/media/0/e87c84f96a1c4a0eb33f7cacb71c9eae.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/e87c84f96a1c4a0eb33f7cacb71c9eae.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_1","ckplayer_mediaContent0_1","400","300",false,flashvars,video,params);
</script>
</div>
<p><span>我们本以为制作很容易，其实面临很多挑战，比如裁剪尺寸、黏土的硬度、上色的均匀程度等，最终通过不懈的努力我们完成了复原作品。这不仅仅是普通的手工制作，在活动与实践中我们更多地了解了历史，提高了动手能力，体会到了主动学习历史的快乐。</span><br></p>
<p><span><a href="images/3a6db7f663e64f9ab507c19d863165ad.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/3a6db7f663e64f9ab507c19d863165ad.jpg"></a><a href="images/967b8dd568154dccb96b0a34ecbfd359.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/967b8dd568154dccb96b0a34ecbfd359.jpg"></a><a href="images/6da329e2c7c84adcbbb3c2ff02aee141.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/6da329e2c7c84adcbbb3c2ff02aee141.jpg"></a><a href="images/c4d5749fb77146ebaaddbfe8c9eeb023.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/c4d5749fb77146ebaaddbfe8c9eeb023.jpg"></a><a href="images/68315482f63645ff9c3cbb62d55d38ae.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/68315482f63645ff9c3cbb62d55d38ae.jpg"></a><a href="images/818ea070e483461cb0ba3ef00ce26aee.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/818ea070e483461cb0ba3ef00ce26aee.jpg"></a><a href="images/f34491d953794977809c8d35448c3da4.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/f34491d953794977809c8d35448c3da4.jpg"></a></span></p>
<p><span></span></p>
<p><br></p>
<p><span>历史是一门学问，</span></p>
<p><span>它既有科学的精深严谨，</span></p>
<p><span>又像艺术一样美妙动人。</span></p>
<p><span>历史是一幅流芳百世的锦绣画卷，</span></p>
<p><span>在人类社会中展现着它永恒的艺术魅力。</span></p>
<p><span>相信同学们，</span></p>
<p><span>定会以此次历史文物模型手工制作大赛为起点，</span></p>
<p><span>在感悟历史文物的魅力中，</span></p>
<p><span>增强自身的历史责任感，</span></p>
<p><span>书写无愧于时代、</span></p>
<p><span>无愧于自己的壮美华章！</span></p>
<p><span><br></span><br></p>
<p><span>&nbsp;</span></p>
<p><br></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/95e833b2e3ca4093af08c66fc3cd341c.jpg', NULL, true, '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (898, '品历史树自信 观科技当自强——记新航实验行走的思政课', '', 'var flashvars={ f:"/media/0/faea279d0f9f409a92f6794d388bb80b.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; var video=["/media/0/faea...', '', '<div>
 <div id="mediaContent0_0"></div> 
 <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
 <script type="text/javascript">
    var flashvars={
        f:"/media/0/faea279d0f9f409a92f6794d388bb80b.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/faea279d0f9f409a92f6794d388bb80b.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script>
</div>
<section>
 <section>
  <section>
   <section>
    <p><strong><span>研&nbsp; 学&nbsp; 日</span></strong></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <p><span>为丰富教学形式，培养学生自主、独立、团结、合作的精神以及研学实践能力，济南新航实验外国语学校初二级部学生来到济南华侨城，开展“生物多样性保护和可持续发展”“中华文明五千年”双主题教育实践活动暨选题现场调研活动，将思政课搬出课堂，增强学生文化自信，践行可持续发展道路。</span></p>
 </section>
</section>
<p></p>
<p><a href="images/aa7c4eb0ac964c23bc3eb0170451a99b.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/aa7c4eb0ac964c23bc3eb0170451a99b.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span><strong>解读历史密码 树立文化自信</strong></span></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <p><span>研学第一站，学生们来到国家宝藏场馆，感受中华文明早期历史的灿烂成就，进行了一场穿越时空之旅。</span></p>
  <p><span>“古老文物”与“现代技术”的碰撞，让学生们真切感知“文化认同”的历史深意。从《千里江山图》到《良渚玉琮》数千年宝藏互动式的呈现，再到国家剧场《蛋壳陶寻亲记》时空穿越上演的奇幻故事，<span>一个个历史故事的生动展现，一个个历史人物对话今人。契合时代足音、融入时代语境，学生们在娱乐和探索中，了解中华文明</span><span>，寻找文化之根、自信之源。</span></span></p>
 </section>
</section>
<p></p>
<p><a href="images/812a9b67684043e4bc0a737150d1821a.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/812a9b67684043e4bc0a737150d1821a.jpg"></a><a href="images/9431cb1502d7437bba4ba60adb71f654.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/9431cb1502d7437bba4ba60adb71f654.jpg"></a><a href="images/af1287cecc484ed69b7853a2cb83000a.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/af1287cecc484ed69b7853a2cb83000a.jpg"></a><a href="images/a0181e7e7ccb4e5d8ba38105d61303ec.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/a0181e7e7ccb4e5d8ba38105d61303ec.jpg"></a><a href="images/83f88ebcc1394091af7cad45e85b2e31.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/83f88ebcc1394091af7cad45e85b2e31.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span><strong>感受</strong></span><strong><span>科技魅力 激发成长自觉</span></strong></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <p><span>在国家地理场馆，学生们亲手触摸科普设备，享受科普文化盛宴。走近蛟龙号、耐力大挑战、感受航天员失重感，同学们通过亲身体验，感受科技的奥秘，激发研究问题的兴趣，让科学的种子在心中生根发芽，也进一步坚定了大家科技强国的信念与信心。</span></p>
 </section>
</section>
<p></p>
<p><a href="images/e38b73f6fa8842c78dddb1b4b71001a3.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e38b73f6fa8842c78dddb1b4b71001a3.jpg"></a><a href="images/e18b009c27aa4d5380fe7262f3cf5443.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e18b009c27aa4d5380fe7262f3cf5443.jpg"></a><a href="images/e35d325169c04a3ea21ef44bef23bde2.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/e35d325169c04a3ea21ef44bef23bde2.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span><strong>走近自然地理 坚定持续发展</strong></span></p>
   </section>
  </section>
 </section>
</section>
<p></p>
<section>
 <section>
  <p><span>在国家地理场馆中，还有一个神秘的地方。在这里，学生们可以了解保护生物多样性的重要性和实用方法，可以增强保护生物多样性的实践能力，可以学习到很多关于生物多样性的知识。在大自然中感悟多彩世界，学生们更清楚地认识到每一种生物都不可替代，每一个生命都不容忽视，为自觉参与更多保护行动储蓄动能。</span></p>
 </section>
</section>
<p></p>
<p><a href="images/08bc79c160984888906651481bf55256.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/08bc79c160984888906651481bf55256.jpg"></a><a href="images/e2e5567d709c48a493594e6659fe9b40.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e2e5567d709c48a493594e6659fe9b40.jpg"></a><a href="images/db59056cadff461c92d58925042c4beb.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/db59056cadff461c92d58925042c4beb.jpg"></a></p>
<p><span>在成长道路上，因为付出，我们收获成长的喜悦；因为学习，我们懂得前行的意义。本次研学活动拉近了生活与课堂的距离，进一步激发了学生们的探究欲，培养学生自强、自立、自信的少年精神，是一场“知行合一”研学之旅，是生活这本教科书最美的赠予。</span></p>
<p><span><a href="images/92821da3f5c04b2f971e1682569fb0e8.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/92821da3f5c04b2f971e1682569fb0e8.jpg"></a><a href="images/e3432a9ef40e4881a9de0e42d6ed4ff6.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e3432a9ef40e4881a9de0e42d6ed4ff6.jpg"></a><a href="images/c5afaab9abb94722b9af294fc714bf89.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c5afaab9abb94722b9af294fc714bf89.jpg"></a><a href="images/b72126b48b004b7e948d2ca8bb1711c3.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/b72126b48b004b7e948d2ca8bb1711c3.jpg"></a><a href="images/00df33be2cd742f3bc0f9ec86dba1134.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/00df33be2cd742f3bc0f9ec86dba1134.jpg"></a><a href="images/3afaaea5be844fb6b591a125a3224548.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/3afaaea5be844fb6b591a125a3224548.jpg"></a><a href="images/159fc76880d549948353f2283b68c66a.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/159fc76880d549948353f2283b68c66a.jpg"></a><a href="images/0a10032eb5104d8d9e383c658ded97a7.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/0a10032eb5104d8d9e383c658ded97a7.jpg"></a></span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/aa7c4eb0ac964c23bc3eb0170451a99b.jpg', NULL, true, '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '2021-10-25 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (899, '这就是新航少年！直击新航实验运动会热血现场', '', '秋风为羽翼，竞技显峥嵘。雨后的新航实验，热情洋溢，欢声笑语，1300多名师生相约运动场，共同迎来期盼已久的秋季运动会。青春跃动的啦啦操点燃运动会的序幕，教师方队、裁判员方队、班级方队依次入场。全体新航实验人以饱满的热情，接受检阅，致敬祖国；用昂扬的斗志，大声宣告，“请党放心，强国有我！”看，他们正以新时代的青春姿态向我们走来。伴随激昂的国歌声，五星红旗冉冉升起，舞动的旗帜象征着新航实验人的骄傲与自...', '', '<p><span>秋风为羽翼，竞技显峥嵘。</span></p><p><span>雨后的新航实验，</span></p><p><span>热情洋溢，欢声笑语，</span></p><p><span>1300多名师生相约运动场，</span></p><p><span>共同迎来期盼已久的秋季运动会。</span></p><p><a href="images/6a5e62fcab45483689ea337c008d2179.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6a5e62fcab45483689ea337c008d2179.jpg"/></a><a href="images/e789287d44dc4e51aa87762850656a5c.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/e789287d44dc4e51aa87762850656a5c.jpg"/></a></p><p><span>青春跃动的啦啦操点燃运动会的序幕，</span></p><p><span>教师方队、裁判员方队、班级方队依次入场。</span></p><p><span>全体新航实验人以饱满的热情，</span></p><p><span>接受检阅，致敬祖国；</span></p><p><span>用昂扬的斗志，</span></p><p><span>大声宣告，“请党放心，强国有我！”</span></p><p><span>看，他们正以新时代的青春姿态向我们走来。</span></p><p><a href="images/e3983372c2d348428bf0cd0d503ca49d.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e3983372c2d348428bf0cd0d503ca49d.jpg"/></a><a href="images/c6ea59c339a443d299dd6fff2f185b74.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/c6ea59c339a443d299dd6fff2f185b74.jpg"/></a><a href="images/40567cb4ac1c41efbb3a91048a9d4c28.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/40567cb4ac1c41efbb3a91048a9d4c28.jpg"/></a><a href="images/29eb171633f94dfe8fdd6ee99c042eb8.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/29eb171633f94dfe8fdd6ee99c042eb8.jpg"/></a><a href="images/bacf3fdf73104ed6a6f4bcbd0f7e5f21.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/bacf3fdf73104ed6a6f4bcbd0f7e5f21.jpg"/></a><a href="images/ccc3218135d742a180d8a5ed1909a523.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/ccc3218135d742a180d8a5ed1909a523.jpg"/></a><a href="images/a9829bf50ccd450d801e105ed8baa5bb.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/a9829bf50ccd450d801e105ed8baa5bb.jpg"/></a><a href="images/ac0da59f5c27450892dc9d6d962b50ae.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/ac0da59f5c27450892dc9d6d962b50ae.jpg"/></a><a href="images/dd36e86cfe4a433fb5d39cea40a667e7.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/dd36e86cfe4a433fb5d39cea40a667e7.jpg"/></a><a href="images/88099024b9574cdc858d6173a1b476b5.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/88099024b9574cdc858d6173a1b476b5.jpg"/></a><a href="images/9aee3f251d604d27b13717ad899555ee.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/9aee3f251d604d27b13717ad899555ee.jpg"/></a><a href="images/0b0399389b27422e9ca999863bc4620d.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/0b0399389b27422e9ca999863bc4620d.jpg"/></a><a href="images/8431dc5acafa44f2bb8ae4a0dedbc11a.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/8431dc5acafa44f2bb8ae4a0dedbc11a.jpg"/></a><a href="images/d9b5d979dd684aeaa958a2c29c35187d.jpg" target="_blank"><img title="14.jpg" src="/uploads/migration/images/d9b5d979dd684aeaa958a2c29c35187d.jpg"/></a></p><p><span>伴随激昂的国歌声，五星红旗冉冉升起，</span></p><p><span>舞动的旗帜象征着新航实验人的骄傲与自豪。</span></p><p><a href="images/bd3f7978cb2546dd80e95a6cedd4e3ec.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/bd3f7978cb2546dd80e95a6cedd4e3ec.jpg"/></a><a href="images/7b3ad2c6f88d4cfda4c5d5e75dd820ac.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/7b3ad2c6f88d4cfda4c5d5e75dd820ac.jpg"/></a><a href="images/0270b653097647dfaf27ba88d4ae4e32.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/0270b653097647dfaf27ba88d4ae4e32.jpg"/></a></p><p><span>尽管天气微凉、地面有些潮湿，</span></p><p><span>但同学们竞技的热情丝毫未减。</span></p><p><span>终点冲刺的爆发，</span></p><p><span>铅球划过的弧线，</span></p><p><span>跳高、跳远的奋力一跃，</span></p><p><span>是运动，是青春，</span></p><p><span>是新航实验学子绽放的模样。</span></p><p><a href="images/d14e4bbbcc85445ab1488b04c1efcbb7.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/d14e4bbbcc85445ab1488b04c1efcbb7.jpg"/></a><a href="images/d2861991c7034aa0af0bcd279ed61179.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/d2861991c7034aa0af0bcd279ed61179.jpg"/></a><a href="images/d0549c8cbe3046d59397ccc665caf430.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/d0549c8cbe3046d59397ccc665caf430.jpg"/></a><a href="images/e9f95b7add5b48e09fe5689e7b5519ab.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/e9f95b7add5b48e09fe5689e7b5519ab.jpg"/></a><a href="images/41e67cfb08674691a4ac41323c0ee5f6.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/41e67cfb08674691a4ac41323c0ee5f6.jpg"/></a><a href="images/0324f02ed9ec4197a93c16ad5daf3026.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/0324f02ed9ec4197a93c16ad5daf3026.jpg"/></a><a href="images/a2e9c6ccca004941b9c425b60decc894.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/a2e9c6ccca004941b9c425b60decc894.jpg"/></a><a href="images/858de8a19416439e872efcc4c70938c6.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/858de8a19416439e872efcc4c70938c6.jpg"/></a><a href="images/9fc97e117c214889b191d5d522567e4e.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/9fc97e117c214889b191d5d522567e4e.jpg"/></a><a href="images/997973cabcc8437baaf198056ad698d8.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/997973cabcc8437baaf198056ad698d8.jpg"/></a><a href="images/57adb3c9f02c4058bdd9700145f92911.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/57adb3c9f02c4058bdd9700145f92911.jpg"/></a><a href="images/36add4ba55e241b386c8cb3200994c14.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/36add4ba55e241b386c8cb3200994c14.jpg"/></a><a href="images/6835962a042c4821af18b700d9aaa0e5.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/6835962a042c4821af18b700d9aaa0e5.jpg"/></a></p><p><span>齐聚心，凝聚力，</span></p><p><span>竞技的初心从来都不只是速度和力量，</span></p><p><span>今天，团队的精神胜过一切。</span></p><p><a href="images/f24f4ff56ba24bbab34c28cb32253275.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f24f4ff56ba24bbab34c28cb32253275.jpg"/></a><a href="images/86159c35093544f1b203bdfebd94fb22.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/86159c35093544f1b203bdfebd94fb22.jpg"/></a><a href="images/a33449610e3c461e8aaa12f58e9ea0da.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/a33449610e3c461e8aaa12f58e9ea0da.jpg"/></a></p><section><section><p><span>小学生当然也不甘示弱，</span></p><p><span>骄傲的小少年们学着哥哥姐姐的样子，</span></p><p><span>奋力向前，争创佳绩，</span></p><p><span>这一刻，定格最可爱的你。</span></p></section></section><p><a href="images/e6383a210f1b4dc7b5f5efa5cf4a6fb1.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e6383a210f1b4dc7b5f5efa5cf4a6fb1.jpg"/></a><a href="images/10525cd498bc46c6af3f2bf3b1521f03.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/10525cd498bc46c6af3f2bf3b1521f03.jpg"/></a><a href="images/df6ba94218674c988de9e2cb4ab34e7c.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/df6ba94218674c988de9e2cb4ab34e7c.jpg"/></a><a href="images/f44d983da3354035a0b71d8c20339eca.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/f44d983da3354035a0b71d8c20339eca.jpg"/></a><a href="images/cdbe5ab689c44f18bd5d4162e85947d9.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/cdbe5ab689c44f18bd5d4162e85947d9.jpg"/></a><a href="images/1713a04b251346d2ac4bd73f82a36e81.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/1713a04b251346d2ac4bd73f82a36e81.jpg"/></a><a href="images/071f92da1870415db461334394a0e2db.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/071f92da1870415db461334394a0e2db.jpg"/></a></p><p><span>赛场上，运动员们奋力拼搏，</span></p><p><span>赛场外，此起彼伏的呐喊助威是最佳后援团。</span></p><p><span>每一次的挥动旗帜，</span></p><p><span>每一次的振臂欢呼，</span></p><p><span>都是这个赛场最燃的青春印记。</span></p><p><a href="images/52037d80cb7d4604ae43d0ed8e242667.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/52037d80cb7d4604ae43d0ed8e242667.jpg"/></a><a href="images/274c40f93bff4e1ea989514517c1b0b7.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/274c40f93bff4e1ea989514517c1b0b7.jpg"/></a><a href="images/6c9de6371216400884faa51628c92b2f.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/6c9de6371216400884faa51628c92b2f.jpg"/></a><a href="images/88f69735f43f40539c3e6c41297e72bc.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/88f69735f43f40539c3e6c41297e72bc.jpg"/></a></p><p><span>公正的裁判守护运动精神，</span></p><p><span>奔跑的“摄影师”抢下赛场的每一分精彩，</span></p><p><span>赛事播报时刻传递着最新的赛况，</span></p><p><span>校医、检录员、平沙员、颁奖组……</span></p><p><span>全力保障赛事顺畅进行。</span></p><p><span>一个个身影汇聚成这个秋天最美的风景。</span></p><p><a href="images/59ed7b8b81df432083c627a85898636e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/59ed7b8b81df432083c627a85898636e.jpg"/></a><a href="images/5440c9b7a4ae4e528315e7a44a917ba4.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/5440c9b7a4ae4e528315e7a44a917ba4.jpg"/></a><a href="images/dfaaa8e52a1b4dcd8aa87e958d4c0f16.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/dfaaa8e52a1b4dcd8aa87e958d4c0f16.jpg"/></a><a href="images/aa4797fc6c124132be35f152c7afd359.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/aa4797fc6c124132be35f152c7afd359.jpg"/></a><a href="images/fef4bafc77904b24805aa6d77cb2cc99.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/fef4bafc77904b24805aa6d77cb2cc99.jpg"/></a><a href="images/c6ed5edac9cf4732950ea3b9e3b3ffe9.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/c6ed5edac9cf4732950ea3b9e3b3ffe9.jpg"/></a><a href="images/12d626a1fe90443384a8cf86b4d26780.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/12d626a1fe90443384a8cf86b4d26780.jpg"/></a><a href="images/2f86c631a29f4908bda7996de1a58d47.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/2f86c631a29f4908bda7996de1a58d47.jpg"/></a><a href="images/815f92f587844193ad2080ce215a54b3.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/815f92f587844193ad2080ce215a54b3.jpg"/></a></p><p><span>上得讲台，出得赛场，</span></p><p><span>平日里优雅稳重的老师们，</span></p><p><span>今天也卸下“伪装”。</span></p><p><span>看他们或疯狂，或俏皮，或帅气，或飒爽，</span></p><p><span>还记得起他们在课堂上严厉的样子吗</span></p><p><a href="images/22424badbd4f401496fc8ca06b7a6c7e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/22424badbd4f401496fc8ca06b7a6c7e.jpg"/></a><a href="images/75ae6331bde5440e8ef9fb44613c0fa7.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/75ae6331bde5440e8ef9fb44613c0fa7.jpg"/></a><a href="images/cdb77807de714fc6b2b77b6e121afe38.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/cdb77807de714fc6b2b77b6e121afe38.jpg"/></a><a href="images/d414db1ff2d346f48910a94be821f9c6.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/d414db1ff2d346f48910a94be821f9c6.jpg"/></a><a href="images/dbef160e5c264ef2ace5bb36236ee71f.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/dbef160e5c264ef2ace5bb36236ee71f.jpg"/></a><a href="images/10af8b7f48e94a5898d972d47d3c6af1.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/10af8b7f48e94a5898d972d47d3c6af1.jpg"/></a><a href="images/310497e161324a53b974dd80fbf7dac0.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/310497e161324a53b974dd80fbf7dac0.jpg"/></a><a href="images/20315ef827274fa38a9b35d679bc250c.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/20315ef827274fa38a9b35d679bc250c.jpg"/></a><a href="images/ddce80c242b44cdfb831c3ae58f9a15a.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/ddce80c242b44cdfb831c3ae58f9a15a.jpg"/></a><a href="images/36525078378148af8101aad6a5d7cb7f.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/36525078378148af8101aad6a5d7cb7f.jpg"/></a></p><p><span>今天，</span></p><p><span>我们共同见证成绩，抹去汗水，</span></p><p><span>青春犹如一场接力，</span></p><p><span>一次次拼尽全力。</span></p><p><a href="images/21346055e09c49d88fcb5110cce1aeda.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/21346055e09c49d88fcb5110cce1aeda.jpg"/></a><a href="images/af81f9b95ccb491d95718834f00bbc22.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/af81f9b95ccb491d95718834f00bbc22.jpg"/></a><a href="images/9eb25e6b488d43e9901c161a6e464aa2.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9eb25e6b488d43e9901c161a6e464aa2.jpg"/></a><a href="images/85259653d9c14dae80d7a76aa4e4d44b.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/85259653d9c14dae80d7a76aa4e4d44b.jpg"/></a><a href="images/b5c46376eb0845e8b24759b591ca9de3.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/b5c46376eb0845e8b24759b591ca9de3.jpg"/></a><a href="images/3eaf02fcba444898bcc813b5c5f79eba.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/3eaf02fcba444898bcc813b5c5f79eba.jpg"/></a><a href="images/a8c755f8b25d46939f7603ae7826e016.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/a8c755f8b25d46939f7603ae7826e016.jpg"/></a><a href="images/6b8d244f498349739c2b330fc0c68610.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/6b8d244f498349739c2b330fc0c68610.jpg"/></a></p><p><span>奔跑之中，</span></p><p><span>意志的对决，名为不言弃；</span></p><p><span>跳跃之间，</span></p><p><span>勇气的比拼，名为无所惧。</span></p><p><span>永不忘，</span></p><p><span>运动场上十月的记忆。</span></p><p><span>身为新航实验学子，</span></p><p><span>我们愿用强壮的体魄，</span></p><p><span>向更好的自己进击！</span></p><p><span>强国有我，未来可期！</span></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/6a5e62fcab45483689ea337c008d2179.jpg', NULL, true, '2021-10-19 08:00:00+08', '2021-10-19 08:00:00+08', '2021-10-19 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (900, '热爱每一位孩子的“独一无二”——新航实验初中部启动一对一专属个体化家长会', '', '为总结开学以来初中部教育教学工作，与家长共研育人智慧、探索教育方法，10月12-16日，济南新航实验外国语学校初中部启动一对一专属个体化家长会，家校结成合作共育力量，为每一位学生的全面发展精准把脉。专属时光 创新精准育人模式近年来，新航实验致力于探索精准育人家长会新模式，初中部老师与学生家长一对一面谈、心与心交流，最大程度帮助家长理性悦纳学生成长发展，共同梳理探索学生成长之路，获得了家长的一致好评...', '', '<section><section><p><span>为总结开学以来初中部教育教学工作，与家长共研育人智慧、探索教育方法，10月12-16日，济南新航实验外国语学校初中部启动一对一专属个体化家长会，家校结成合作共育力量，为每一位学生的全面发展精准把脉。</span></p></section></section><p></p><section><section><section><section><section><section><section><section><section></section></section></section></section><section><section><section><section></section></section></section></section><section><section><p><span><strong>专属时光 创新精准育人模式</strong></span></p></section></section></section></section></section></section></section><section><section><p><span>近年来，新航实验致力于探索精准育人家长会新模式，初中部老师与学生家长一对一面谈、心与心交流，最大程度帮助家长理性悦纳学生成长发展，共同梳理探索学生成长之路，获得了家长的一致好评。</span></p><p><span>据初二2班班主任卢宝镇老师介绍，在“一对一家长会”的前两周，班主任老师已经在学部的统一组织下进行前期准备，与学生家长密切沟通预约时间。在学部的统筹安排下，落实一对一专属个体化家长会的相关方案。家长到校后，班主任与每位家长进行40-70分钟的细致交流，几天下来，家长会的总时长达320多个小时。<span>&nbsp;</span></span></p></section></section><p></p><p><a href="images/f72a20d947a845428cff9be1fa225663.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/f72a20d947a845428cff9be1fa225663.jpg"/></a><a href="images/ea9f69e0903c418d81dcd3b6e0887f2f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/ea9f69e0903c418d81dcd3b6e0887f2f.jpg"/></a><a href="images/7565e4634dbc48a585bb5d54d39fdc8d.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/7565e4634dbc48a585bb5d54d39fdc8d.jpg"/></a></p><section><section><section><section><section><section><section><p><span><strong>深入交流 专业分析精准施策</strong></span></p></section></section></section></section></section></section></section><p></p><section><section><p><span>初中阶段学生的成长是一个变量，各有快慢节奏。班主任老师尊重学生个体发展差异，整理“问诊笔记”，使得家长刚一落座就能拿到一份属于自己孩子的“独有方案”，为每一位家长提供成长的“锦囊妙计”，帮助每一位学生圆梦新航……<br/></span></p><p><span>孩子有一百种语言，有一百种发展可能，每个孩子都有自己的“独一无二”。班主任老师为每位家长详细展示了孩子的学业进步情况和在校生活记录，这是成长的见证，也是长大的标志。正是由于学校坚持为学生提供发展可能，支持各种发现，新航实验初中学子们一定会带给我们无限惊喜。<span>&nbsp;</span></span></p></section></section><p></p><p><a href="images/924065d5de7f4cd481c1250e537fbcd3.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/924065d5de7f4cd481c1250e537fbcd3.jpg"/></a><a href="images/6ef01d5075f3414cb91c0019e2bbd49f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/6ef01d5075f3414cb91c0019e2bbd49f.jpg"/></a></p><section><section><section><section><section><section><section><p><span><strong>家校共育 家长感叹“神奇变化”</strong></span></p></section></section></section></section></section></section></section><p></p><section><section><p><span>经过一段时间以来家校双方的共同努力，为初一、初二每一名学子的健康成长搭建了坚实的基础，创设出孩子们温和坚定快乐成长的优良环境。通过深入交流，家长发现，不知不觉间，自家宝贝身上有了太多变化。学生原有的学习习惯已经主动实现更新超越；之前性格内向的女同学，现在在校园中喜欢交朋友，大胆地表达自己的想法……学生一点点的变化与进步，给予家长关键而有力的支持，让家长们开心又自豪。<br/></span></p><p><span>大家纷纷感慨，这样的家长会，让他们更全面细致地观察了孩子在校的表现、身心特点等，在孩子的一些心理和习惯养成等方面，也得到了老师们更加科学的指导和帮助。</span></p></section></section><p></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/f72a20d947a845428cff9be1fa225663.jpg', NULL, true, '2021-10-19 08:00:00+08', '2021-10-19 08:00:00+08', '2021-10-19 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (901, '邂逅我的“一亩三分地”——新航实验小学生种植初体验', '', '为了更好地让学生劳有所学、种有所获，济南新航实验外国语学校小学部主题探究课程为学生们订制了一场蔬菜种植之旅。通过组织学生查阅资料、课堂分享、实地播种、定期观察记录……形成良好的探究学习闭环，引导学生了解常见蔬菜，知晓蔬菜生长环境及周期，在实践中体会劳动不易，养成节约粮食的好习惯。其实，早在国庆假期期间，学生们就已经在家里研究起了蔬菜——有去南部山区田里考察的，有在家里买蔬菜观察的，还有孩子买来蔬菜...', '', '<p><span>为了更好地让学生劳有所学、种有所获，济南新航实验外国语学校小学部主题探究课程为学生们订制了一场蔬菜种植之旅。通过组织学生查阅资料、课堂分享、实地播种、定期观察记录……形成良好的探究学习闭环，引导学生了解常见蔬菜，知晓蔬菜生长环境及周期，在实践中体会劳动不易，养成节约粮食的好习惯。</span></p><p><a href="images/2229c3e4c75049e9bcc297898eb8e7c0.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/2229c3e4c75049e9bcc297898eb8e7c0.jpg"/></a><a href="images/b79772f651454ff1a670048e7a99d4c3.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/b79772f651454ff1a670048e7a99d4c3.jpg"/></a><a href="images/cafeada5fd2047b99f7755df3712f131.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/cafeada5fd2047b99f7755df3712f131.jpg"/></a></p><p><br/></p><p></p><section><section><p><span>其实，早在国庆假期期间，学生们就已经在家里研究起了蔬菜——有去南部山区田里考察的，有在家里买蔬菜观察的，还有孩子买来蔬菜种子想要“自给自足”。掀起这一股热潮的原因就是学校后山的劳动教育实践基地。在这里，有一片孩子们的“专属地”，大家可以进行劳动、种植、养殖、观察、采摘等等课程活动。</span></p><p><span>带着假期积攒满满的知识，再加上课堂上的深入讨论和学习，一切准备就绪！孩子们迎着阳光和秋风，满怀期待和喜悦地朝着向往已久的劳动基地出发。</span></p><p><a href="images/0b187eb1ac814358b65c77d730432c8d.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/0b187eb1ac814358b65c77d730432c8d.jpg"/></a><a href="images/d9fb2016c4ef46029fffce5f1c96e5d2.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/d9fb2016c4ef46029fffce5f1c96e5d2.jpg"/></a><a href="images/c3658af85dc346af963837f2519353ca.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c3658af85dc346af963837f2519353ca.jpg"/></a></p><p><br/></p></section></section><p><section><section><section><section><section><section></section></section></section></section><section><section><section></section></section></section></section></section></p><p></p><section><section><section><section><p><span>园丁老师已早早地为孩子们准备了各种蔬菜种子。大家跃跃欲试、欣喜不已，认真地学习播种技巧，播撒着种子，也播撒着自己内心的喜悦，一个个成就感满满。</span></p></section></section><section><section><section><section><section><section></section></section></section></section><section><section><section><section></section></section></section></section></section></section></section></section><p><a href="images/51b911dc1371450e895e1d2458bc9d7e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/51b911dc1371450e895e1d2458bc9d7e.jpg"/></a><a href="images/9e4d7c8e217545268aad9366577cebd8.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/9e4d7c8e217545268aad9366577cebd8.jpg"/></a><a href="images/e1c5cda815cd45d4bc9c05c2736cf5fa.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/e1c5cda815cd45d4bc9c05c2736cf5fa.jpg"/></a><a href="images/31291c7ec5ad4df99fe46f7a8c7dd5e2.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/31291c7ec5ad4df99fe46f7a8c7dd5e2.jpg"/></a><a href="images/ba7529980de8444299b82d2a8461eb96.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/ba7529980de8444299b82d2a8461eb96.jpg"/></a><a href="images/916567159a2c4b588d765fba448fdd8c.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/916567159a2c4b588d765fba448fdd8c.jpg"/></a><a href="images/75faea62127f407891f73f01d5297a0f.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/75faea62127f407891f73f01d5297a0f.jpg"/></a><a href="images/008e3d78e7db4b2ba994dba3add93442.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/008e3d78e7db4b2ba994dba3add93442.jpg"/></a><a href="images/0ba5a070e56049faa4388ddab4bfdd70.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/0ba5a070e56049faa4388ddab4bfdd70.jpg"/></a><a href="images/1151c2d154ff4d8087981a96f515f18c.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/1151c2d154ff4d8087981a96f515f18c.jpg"/></a><br/></p><p><a href="images/df6575e84add49cc91fb8d980ece8a59.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/df6575e84add49cc91fb8d980ece8a59.jpg"/></a></p><p><span>“老师，我们会在食堂吃到自己播种的蔬菜吗？”小小的期待已经种在心田。一次简单的实践劳动，激发了孩子们内心对植物学科的好奇心，对饮食就餐的思考和探讨。</span></p><p><span>接下来，老师们也安排了“值日生”，每班学生会定期上山观察和记录本班蔬菜的生长过程，在实践中达到深度学习的效果。正如新航实验的教育理念一下，撒下种子，更要悉心养护，静待每一个生命的精彩绽放。</span></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/2229c3e4c75049e9bcc297898eb8e7c0.jpg', NULL, true, '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (902, '筑牢“安全防火墙”——新航实验开展秋季应急疏散演练', '', '为切实加强学校安全工作，提高广大师生安全防范意识和安全疏散自救能力，10月13日，济南新航实验外国语学校初中部和高中部组织开展秋季应急疏散演练活动。按照演习安排，上午9点35分，教学楼警报突然响起，各班教室广播里传来紧急情况疏散通知。各楼层负责老师根据学校安全预案，立即到达指定岗位。学生们反应迅速，在老师的指引下，分别沿消防通道有序撤离到操场安全区域。在接下来的点评环节，张爱梅副校长针对暴露出的问...', '', '<p><span>为切实加强学校安全工作，提高广大师生安全防范意识和安全疏散自救能力，10月13日，济南新航实验外国语学校初中部和高中部组织开展秋季应急疏散演练活动。</span></p><p><span><a href="images/d507af1291534f28a35e160440114484.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/d507af1291534f28a35e160440114484.jpg"/></a><a href="images/de27e1203e4a404489ca3e32a1050036.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/de27e1203e4a404489ca3e32a1050036.jpg"/></a></span></p><p><span>按照演习安排，上午9点35分，教学楼警报突然响起，各班教室广播里传来紧急情况疏散通知。各楼层负责老师根据学校安全预案，立即到达指定岗位。学生们反应迅速，在老师的指引下，分别沿消防通道有序撤离到操场安全区域。</span></p><p><span><a href="images/e319009d131c4469a9da5472bc60880a.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e319009d131c4469a9da5472bc60880a.jpg"/></a><a href="images/ad05ea8e2e95499eb2b1fab06b4b8952.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/ad05ea8e2e95499eb2b1fab06b4b8952.jpg"/></a><a href="images/c162efb426ac4e6daaaff92034102ffc.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/c162efb426ac4e6daaaff92034102ffc.jpg"/></a></span></p><p><span>在接下来的点评环节，张爱梅副校长针对暴露出的问题和安全隐患提出具体要求，提醒每一名师生高度重视安全。学校后续还将继续定期组织相关应急疏散演练，使学生熟悉逃生路线，为学校安全和谐发展打下坚实基础。</span></p><p><span><a href="images/fcaf3cfb672a4777a7607020b0738cef.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/fcaf3cfb672a4777a7607020b0738cef.jpg"/></a><a href="images/076f0d69c1414afc951e83e575d9f478.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/076f0d69c1414afc951e83e575d9f478.jpg"/></a><a href="images/6d7e5fe3bcad4f28b92b6e71579a4050.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/6d7e5fe3bcad4f28b92b6e71579a4050.jpg"/></a></span></p><p><span>此次应急疏散演练是对我校应急预案的一次检验，提高了学校实际应对和处置安全事件的能力，同时也进一步增强了师生的安全意识，真正掌握在危险中迅速逃生、自救、互救的基本方法，筑牢师生的“安全防火墙”。</span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/d507af1291534f28a35e160440114484.jpg', NULL, true, '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (903, '红领巾，我们来了！第72个建队日，新航实验师生这样庆祝……', '', 'var flashvars={ f:"/media/0/81ce3673c27a410dafd5c96ab6d8975a.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"}; var video=["/media/0/81ce...', '', '<p>
 <div id="mediaContent0_0"></div> <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> <script type="text/javascript">
    var flashvars={
        f:"/media/0/81ce3673c27a410dafd5c96ab6d8975a.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/81ce3673c27a410dafd5c96ab6d8975a.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script></p>
<p><span>10月14日，在第72个建队日来临之际，济南新航实验外国语学校师生齐聚大剧院，隆重举行2021年建队日主题活动暨少先队第二批入队仪式。</span></p>
<p><a href="images/a53f33c2e5f54d97bbdeb36ddc1ca165.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/a53f33c2e5f54d97bbdeb36ddc1ca165.jpg"></a><a href="images/80f5fca1cb2a4ee5a4216968937ec1bc.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/80f5fca1cb2a4ee5a4216968937ec1bc.jpg"></a></p>
<p></p>
<section>
 <section>
  <p><span>活动伊始，张爱梅副校长宣布，济南新航实验外国语学校少工委正式成立！</span></p>
 </section>
</section>
<p></p>
<section></section>
<p></p>
<p><a href="images/5be92b853bb04638a5090c80eebeeb43.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/5be92b853bb04638a5090c80eebeeb43.jpg"></a><br></p>
<p><span>少工委的成立，将更好地担负起培养社会主义事业合格建设者和接班人的历史重托，推动学校和社会关心少年儿童健康成长，支持和发展少先队工作。</span></p>
<p><a href="images/193f7c69300f40b9be25a93324a70d26.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/193f7c69300f40b9be25a93324a70d26.jpg"></a><a href="images/5dd9cfa32cdc4e108e9e4c266e18cda9.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/5dd9cfa32cdc4e108e9e4c266e18cda9.jpg"></a></p>
<p><span>“红领巾奖章”争章活动激励引领着队员们奋勇拼搏，砥砺前行。</span></p>
<p><a href="images/115f44eae7d543a2a5bd3c46429413b1.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/115f44eae7d543a2a5bd3c46429413b1.jpg"></a><a href="images/401875f4db184e48bf48a7f0ed78ce1d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/401875f4db184e48bf48a7f0ed78ce1d.jpg"></a><a href="images/235d1a10a9dc4088820c4d62e64a9b18.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/235d1a10a9dc4088820c4d62e64a9b18.jpg"></a></p>
<p><span>初一年级少先队中队的成立为学校少先队注入新鲜血液，相信同学们定能循着红领巾的足迹，志存高远，志航天下！</span></p>
<p><a href="images/14c64336c70e40d7a29abd38d16e8d26.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/14c64336c70e40d7a29abd38d16e8d26.jpg"></a><a href="images/ad81ff3c8b7d49b18776ddd5e0376fb9.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/ad81ff3c8b7d49b18776ddd5e0376fb9.jpg"></a><a href="images/0438c43b983f4f0dbd2a5039f36dc433.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/0438c43b983f4f0dbd2a5039f36dc433.jpg"></a></p>
<p></p>
<section>
 <section>
  <section>
   <section>
    <p><span>伴随嘹亮的少先队队歌，初一年级的老队员们为82名新队员佩戴上鲜艳的红领巾，欢迎你们加入少先队组织的大家庭。</span></p>
    <p><a href="images/98b49b66ac004d6db496e3ee3e9c566e.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/98b49b66ac004d6db496e3ee3e9c566e.jpg"></a><a href="images/c118a843b6144c24ab14de7a035dc70b.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/c118a843b6144c24ab14de7a035dc70b.jpg"></a><a href="images/7d19e3fa3aa147c5bff0ac99e10d44f3.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/7d19e3fa3aa147c5bff0ac99e10d44f3.jpg"></a><a href="images/8a6d74fcb28343a0b0689c9527c235f5.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/8a6d74fcb28343a0b0689c9527c235f5.jpg"></a></p>
    <p><span>单薄的身躯呼喊出坚毅的誓言，指引我们前进的方向，带领我们扬帆起航。</span></p>
   </section>
  </section>
  <section>
   <section>
    <section></section>
   </section>
  </section>
 </section>
</section>
<p><a href="images/2f9c70ccd7694c5db9ab2d2fe670e5ce.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/2f9c70ccd7694c5db9ab2d2fe670e5ce.jpg"></a><a href="images/11cb2dbf556846c784157c61451cf184.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/11cb2dbf556846c784157c61451cf184.jpg"></a></p>
<p><span>初一少先队队员代表发言。</span></p>
<p><a href="images/fae3e6a2667e47578bc645a29829e57b.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/fae3e6a2667e47578bc645a29829e57b.jpg"></a></p>
<section>
 <section>
  <section>
   <section>
    <p><span>高亢的呼号声响彻全场，嘹亮的队歌唱响新时代少年的朝气与希望。今天的红领巾，明天祖国的栋梁；插上梦想的翅膀，搏击长空，实现理想，怀揣梦想，扬帆起航。</span></p>
    <p><a href="images/fae187589f5540a9aee4934529383937.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/fae187589f5540a9aee4934529383937.jpg"></a><a href="images/2bcaa741630540a794e79679d9dd3e46.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/2bcaa741630540a794e79679d9dd3e46.jpg"></a></p>
    <p></p>
    <section>
     <section>
      <section>
       <section>
        <p><span>未来的建设和发展属于新时代的你们，相信队员们定会沐浴太阳的光芒，寄托祖国的期望，赓续红色血脉，争做新时代好队员，共筑祖国明天的辉煌。</span></p>
       </section>
      </section>
      <section>
       <section>
        <section></section>
       </section>
      </section>
     </section>
    </section>
    <p><br></p>
   </section>
  </section>
  <section>
   <section>
    <section></section>
   </section>
  </section>
 </section>
</section>
<p><br></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/a53f33c2e5f54d97bbdeb36ddc1ca165.jpg', NULL, true, '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '2021-10-18 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (904, '猜谜语、记口令、互夸奖……新航实验小学部将生活搬进课堂', '', '为让孩子们与好习惯携手同行，济南新航实验外国语学校小学部生活指导老师把习惯养成教育从学生公寓搬进教室，进行了生活技能趣味实践主题班队会。根据不同年龄段的成长规律，生活老师从物品摆放、衣物收纳、床铺整理、餐桌礼仪、文明问候等细节入手，对小航们进行了分层指导和训练。 var flashvars={ f:"/media/0/61a14d017ddf4b3d868ef123ee0475fc.mp4", c...', '', '<p><span>为让孩子们与好习惯携手同行，济南新航实验外国语学校小学部生活指导老师把习惯养成教育从学生公寓搬进教室，进行了生活技能趣味实践主题班队会。根据不同年龄段的成长规律，生活老师从物品摆放、衣物收纳、床铺整理、餐桌礼仪、文明问候等细节入手，对小航们进行了分层指导和训练。</span></p>
<div>
 <div id="mediaContent0_0"></div> 
 <script type="text/javascript" src="/module/jslib/ckplayer/ckplayer.js" charset="utf-8"></script> 
 <script type="text/javascript">
    var flashvars={
        f:"/media/0/61a14d017ddf4b3d868ef123ee0475fc.mp4",
        c:"0"
    };
    var params={bgcolor:"#FFF",allowFullScreen:"true",allowScriptAccess:"always",wmode:"transparent"};
    var video=["/media/0/61a14d017ddf4b3d868ef123ee0475fc.mp4->video/mp4"];
    CKobject.embed("/module/jslib/ckplayer/ckplayer.swf","mediaContent0_0","ckplayer_mediaContent0_0","400","300",false,flashvars,video,params);
</script>
</div>
<p><span>谜语开场添乐趣</span></p>
<p><span>“两棵小树十个杈，不长叶子不开花，能写会算还会画，天天干活不说话。”一个有趣的开场谜语，让小航们迅速集中精力，进入状态。“答案是‘双手’！”在老师的启发下，小家伙儿们通过回顾自己已经学会的生活小技能，迅速找出谜底，对接下来的学习内容也是跃跃欲试。</span></p>
<p><span><a href="images/18e0afddf1e644ef944a1cf5c28c09ed.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/18e0afddf1e644ef944a1cf5c28c09ed.jpg"></a><a href="images/23cb104d00d14a0cb171b39bc3671623.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/23cb104d00d14a0cb171b39bc3671623.jpg"></a></span></p>
<p><span><br></span></p>
<p><span></span></p>
<section>
 <p><span>巧记口令提速度</span></p>
 <section>
  <br>
 </section>
</section>
<p></p>
<section>
 <p><span>除了提前录制的教学视频和现场演示教学，生活老师们还辅以简洁明了、朗朗上口的口令。“拉一拉，抱一抱，折一折，对一对”、“铺一铺，折一折，对一对”，一句口令一个步骤，小航们积极模仿，举手投足透着一股认真劲儿。经过反复练习，大家叠衣服和被子的速度不断提高，衣物和“小被”在学生们手下变得服服贴贴。</span></p>
 <p><span><a href="images/9e6fe91871664fb0984a2ea14bb7d89b.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9e6fe91871664fb0984a2ea14bb7d89b.jpg"></a><a href="images/3594d4cde598430bb2e176898eed4f70.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/3594d4cde598430bb2e176898eed4f70.jpg"></a><a href="images/44be40dee2b8429d8ad5836d33360231.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/44be40dee2b8429d8ad5836d33360231.jpg"></a><a href="images/fd4c28cffe424062b0634b660327bcf6.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/fd4c28cffe424062b0634b660327bcf6.jpg"></a><a href="images/4378d2ae84964b939e22f07e5ee535ba.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/4378d2ae84964b939e22f07e5ee535ba.jpg"></a><a href="images/8c5727c3adde4736b802289f44129932.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/8c5727c3adde4736b802289f44129932.jpg"></a></span></p>
 <p><span><br></span></p>
 <p><span></span></p>
 <section>
  <p><span>互比互夸齐进步</span></p>
  <section>
   <br>
  </section>
 </section>
 <p></p>
 <section>
  <section>
   <p><span>要进行同桌互比互夸小比赛啦！小航们认真找出同桌在练习中的优点和不足，兵教兵，兵帮兵，宛如一个个耐心的小老师和挑剔的小法官呢！谁说稚嫩的小手，叠不出美的衣裳？寒露时节，一朵朵小苗拔节而长。小航们看着叠得板板正正的校服和“小被”，自豪感溢于言表，笑容洋溢在脸上。</span></p>
   <p><a href="images/25c121e59b044b60be543a78ce0d2f3c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/25c121e59b044b60be543a78ce0d2f3c.jpg"></a><a href="images/c1c514ccc14648139f348ab5cb38f0f7.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/c1c514ccc14648139f348ab5cb38f0f7.jpg"></a></p>
   <p><span>天下大事，必作于细，好习惯就附着在叠衣、叠被、清理桌面、整理储物柜、摆放餐具等生活小事中。清晨、午后，随手叠好方方正正的小花被，铺平小床单，整洁清新的环境让居处可恭；进入室内，收纳小外套，睡前叠好小衣裤，物有定位的习惯让储物柜平添了秩序感。</span></p>
  </section>
 </section>
 <p></p>
 <p><span><a href="images/ecab917bb8b14f16960a0f4fc0c514ec.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/ecab917bb8b14f16960a0f4fc0c514ec.jpg"></a><a href="images/706083d53cd74d80b610e9f6e335c54d.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/706083d53cd74d80b610e9f6e335c54d.jpg"></a><a href="images/15608637e853475a979f3839439f4fa6.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/15608637e853475a979f3839439f4fa6.jpg"></a></span></p>
 <p><span>当我们将自己的周边环境整理得井井有条时，不光能使他人感觉舒适，更能给自己一个良好的精神状态。一节趣味盎然的生活技能实践主题班队会很快就结束了，但是小航们的佳习相伴之路永远是进行时。<br></span></p>
</section>
<p></p>
