INSERT INTO public.news VALUES (905, '节能环保爱国行 新航实验学子在行动', '', '节能环保爱国行，新航实验初二六班同学们来到山东书城，化身“小小宣讲员”，推广垃圾分类知识，帮助工作人员打包、整理书架，立志为资源的可持续利用贡献自己的一份力量。 var flashvars={ f:"/media/0/c4aebeaaa6d34561b33bb4f04d746865.mp4", c:"0" }; var params={bgcolor:"#FFF",allowFullScreen:...', '', '<p><span>节能环保爱国行，新航实验初二六班同学们来到山东书城，化身“小小宣讲员”，推广垃圾分类知识，帮助工作人员打包、整理书架，立志为资源的可持续利用贡献自己的一份力量。</span></p>
<p><span></span></p>
