INSERT INTO public.news VALUES (907, '聚焦学生活动，引领教学新航向——济南市高中语文面对面培训会在新航实验举行', '', '近日，济南市高中语文2021年面对面培训会及新教材使用报告会在济南新航实验外国语学校举行。济南市教研院高中语文教研员万福成老师以《活动式语文课堂——指向核心素养的语文教学》为题作了精彩的报告。本次活动采用现场直播的方式，不能到场参会的老师们均可通过网络线上聆听学习。培训会上，万老师对语文新课标进行了深入解读，重点指出语文课堂教学应将以学生为中心转换为以学生活动为中心，构建自动生成的活动式课堂。同时...', '', '<p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf6DHHXdMpOlAeicowwox6ibmGOTmMSNwQULicISUaJ8YruF2N8SgLzpWkXTBGBFiby39chk0hL74BT1ibQ/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><span>近日，济南市高中语文2021年面对面培训会及新教材使用报告会在济南新航实验外国语学校举行。济南市教研院高中语文教研员万福成老师以《活动式语文课堂——指向核心素养的语文教学》为题作了精彩的报告。本次活动采用现场直播的方式，不能到场参会的老师们均可通过网络线上聆听学习。</span></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf6DHHXdMpOlAeicowwox6ibmGZpxe9GhFRibF2znhp2m2NtlibobrHV3cfyXvAQpYZaRX5L3kEFm2LpHg/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><span>培训会上，万老师对语文新课标进行了深入解读，重点指出语文课堂教学应将以学生为中心转换为以学生活动为中心，构建自动生成的活动式课堂。同时，对于如何设计课堂活动、整本书阅读以及写作教学做了进一步指导和建议。</span></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf6DHHXdMpOlAeicowwox6ibmG24bekHe14RCnkMQj8CkibzUaJpgAozqsL09JEVrZQMjp4n0LYFDNHBw/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf6DHHXdMpOlAeicowwox6ibmGhia4uHCpbF48JicHxdvfdKksBzmFQGBhNxBIutWDSInTJoeicOERaZwWQ/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><br/></p><section><section><section><section><p><span>本场讲座不仅站位高、视野广而且指向性与操作性极强，通过理论与实践的结合为老师们指点迷津，拨云见日。相信通过此次培训，老师们能够更加全面、深入、准确地理解新课标的要求，有效提高语文教师的教育教学能力，培养学生语文核心素养，助力减负提质。</span></p></section></section><section><section><section></section></section></section></section></section><p><br/></p><section></section><p><br/></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'news', '', NULL, true, '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (908, '@新航实验的家长们，学校向您发出安全倡议书！', '', '☆致各位学生家长的安全倡议书☆亲爱的家长朋友们：大家好！为进一步落实全省学校安全工作电视电话会议精神，筑牢家校共管的学校安全防线，共同维护学生的身心生命健康安全，特向您发出以下倡议：疫情防控不松懈疫情并未结束，请继续配合疫情防控工作，积极响应假期尽量不离济，非必要不出省。如确需出省，应谨慎评估前往地疫情风险，了解当地防控政策，提前向学生班主任报告。学生返济后须持48小时内核酸检测阴性报告返校。假期...', '', '<section><section><section><section><p><span><strong>☆</strong><span><strong>致各位学生家长的安全倡议书</strong></span><strong>☆</strong></span></p></section></section></section></section><p><br/></p><section><section><p><span>亲爱的家长朋友们：</span></p><p><span>大家好！为进一步落实全省学校安全工作电视电话会议精神，筑牢家校共管的学校安全防线，共同维护学生的身心生命健康安全，特向您发出以下倡议：</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>疫情防控不松懈</strong></span></p></section></section></section><section><section><p><span>疫情并未结束，请继续配合疫情防控工作，积极响应假期尽量不离济，非必要不出省。如确需出省，应谨慎评估前往地疫情风险，了解当地防控政策，提前向学生班主任报告。学生返济后须持48小时内核酸检测阴性报告返校。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>假期作业要完成<span></span></strong></span></p></section></section></section><section><section><p><span>假期临近结束，请家长朋友们提醒并及时协助学生完成假期书面和实践活动作业。我们特别欣赏您和学生一起学习共同进步的样子，千万不要一边玩手机一边命令学生赶紧完成作业，这种“鼓励”恐怕只会产生反作用。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>交通安全常叮咛</strong></span></p></section></section></section><section><section><p><span>假期出行人流多，车辆多，请为学生做好榜样，模范遵守交通规则，遇到各种交通问题牢记安全第一。未成年孩子有时确实难“管”，但更需要身为成年人的我们，巧用心思，注重学习并使用科学的教育方法，特别是安全教育要坚持“适时教育、经常教育、循循善诱、以身示范”。孩子外出，请和孩子沟通好，确保知晓他要去哪里、干什么、和谁去、何时回。对低龄儿童，更要全程看护，保证孩子不离开您的视线，防止意外伤害发生。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>防溺水攻略请重温</strong></span></p></section></section></section><section><section><p><span>虽已入秋，前期全国各地仍接连发生多起学生溺水事故。生命只一次，防溺水教育一刻不能放松。请您带着孩子重温防溺水攻略：不私自下水游泳、不擅自与他人结伴游泳、不在无家长和教师带领的情况下游泳、不在无安全设施、无救援人员的水域游泳、不到不熟悉的水域游泳嬉戏、不擅自下水施救。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>心理安全莫忘记</strong></span></p></section></section></section><section><section><p><span>关注学生心理健康，建议和孩子一起观看《我和我的父辈》《长津湖》等国庆电影，陪孩子去看一看喷涌的济南名泉，跟孩子爬一爬山、看一看星空，和孩子一起做一次饭、打扫一下卫生……孩子成长得很快，假期是一个绝佳的相处机会。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>“安全红线”须牢记</strong></span></p></section></section></section><section><section><p><span>孩子的世界，充满对未知的好奇和探索。在保护孩子童趣和求知欲的前提下，请您和我们一起，为孩子画出“安全红线”：不与同伴做危险的游戏，不玩不携带刀具、火机等危险品；防止在景区、商场等人员密集的地方遭遇拥挤踩踏；不轻易“探险”走入荒僻区域或其他景区禁入的区域；不攀爬树木、电力设施及其他禁止攀爬的建筑物、构筑物和设施；不在铁路沿线放风筝，更不能在铁轨上玩耍，放置砖块等，防止造成列车停运事故；不在施工工地等危险区域逗留、玩耍。</span></p></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>卫生安全要警惕</strong></span></p></section></section></section><section><section><p><span>每个人关于美食的记忆，都有一味“妈妈的味道”。比起其他的言语和行为，食物对于爱的表达，总是别具温度与烟火气。作为一名合格的“饲养员”，请您教育孩子培养良好的个人卫生习惯：饭前便后勤洗手；不贪吃不暴饮暴食，不以零食充当正餐，注意健康饮食；不吃“三无”、变质、过期食品，少吃或不吃“三高”食品（高盐、高糖及高脂）；不喝生水，少喝冷饮。</span></p><p><span>尊敬的家长，孩子的健康成长是我们最大的心愿，让我们积极行动起来，从自己做起，从现在做起，共同守护孩子的安全！&nbsp;</span></p><p><br/></p><p><br/></p><p><span><strong>济南新航实验外国语学校</strong></span></p><p><span><strong>2021年10月7日</strong></span></p><div><span><strong><br/></strong></span></div></section></section><section></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '', NULL, true, '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (909, '名家开讲：人大附中语文特级教师于树泉老师在新航实验畅谈阅读与写作', '', '写作能力是语文素养的综合体现，为更好研讨写作教学新思路，近日，北京市语文特级教师于树泉老师在新航实验正式开讲“中学作文教学漫谈”，来自省实验中学中心校区、东校区以及新航实验的全体语文教师到场聆听讲座。作为北京市语文特级教师、教育部“国培计划”专家、部编语文教材评审专家、整本书阅读的倡导者和践行者，于树泉老师在人大附中连续八年高三把关，先后培养出文理高考状元4人，作文满分多人。他的学生中，平均每年有...', '', '<section><section><section><section><p><span><br/></span></p><p><span>写作能力是语文素养的综合体现，为更好研讨写作教学新思路，近日，北京市语文特级教师于树泉老师在新航实验正式开讲“中学作文教学漫谈”，来自省实验中学中心校区、东校区以及新航实验的全体语文教师到场聆听讲座。</span></p></section></section><section><section><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqc62pfKZ6WZbkhs7d9mwo5RjX3QvWoffbgKU8r4bQdZkXB95NOcVWUA/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqYbhKgNbqglwISv0vlH4DRD7tEI46RDiak10dAuqCu1HG9v0VHyE2pkg/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></section></section></section></section><p><br/></p><section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span>作为北京市语文特级教师、教育部“国培计划”专家、部编语文教材评审专家、整本书阅读的倡导者和践行者，于树泉老师在人大附中连续八年高三把关，先后培养出文理高考状元4人，作文满分多人。他的学生中，平均每年有50多人考入北大清华，高考语文校平均分连续8年位居全市之冠。</span></p></section></section><section><section><br/></section></section><section><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqjsT00IYQHE8bHWNXHNJKWj2oV2j44SnaSlibtSICDIL5lk4SSRnAd3g/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><span>讲座中，于树泉老师结合高考作文阅卷与自身教学经历，指出作文是心灵的某种外化，作文内容所暴露的种种问题影射出目前中学生心灵世界的苍白。“当下语文教育出现的种种问题，都可以直接或间接地从丢失了读书之‘根’上找原因，学生要想写好作文，‘唯勤读书而多为之’，此外没有别的捷径可走。”</span></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPq2nvibL556oPwbL3EThb3eibTnP8uARQibv4SM6mwk0ibvSo9lcyR5feUBA/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqKJcEZepsVwiblx9ibZYHbQGVuYFfc2d0tWyqwlzMtVewCPq5XicSQE1ibg/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p></section><p><span>于老师认为，以阅读带动写作，以写作深化阅读，是老师们应该一直坚持的做法，是写好作文的筑基功夫和不二法门。把学生引导到经典面前，引导他们与伟大的心灵对话，教育的伟力就发生了。</span></p></section></section><p><span>对于教师而言，有喜爱阅读的老师，才会有喜爱阅读的学生。要引导学生阅读，老师自己首先要阅读，不仅要进行职业阅读，还要对文史哲、时政、经济、社会、心理等领域广有涉猎，以不断充实智库，裨补精神。</span></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPq18veMNK52zcXIgEIKvaPN9eo4yMWVvHhEua0VO9clynVryockMSCMg/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPq75N7plDjeXRUcibVIxMmxrmqGmWMHrRDkBEvOpUlXu3ibA3f5PpehD5w/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqUR3YQVI6SwbfVo3BHXBPLtNmwF1II6sC596OoMM99Ztex436WtpFFQ/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section><section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><section><section><p><span>将孩子从题海中捞出来，从行文的套路中拽出来，从作文的假大空中站出来。多读书，让心灵绿草如茵、繁花似锦；让表达别具一格，丰盈灵动；让语文厚重多彩，有趣有味。</span></p><p><span>于树泉老师的讲座，深入浅出，既有他从教一生的经验和感悟，更有他对语文教学的探索和实践，不仅为如何上好作文课给出明确的指导，也为今后的课堂作文教学作了示范和引领。到场的老师们享受了一席丰盛的精神大餐，受益匪浅，收获满满！</span></p></section></section><section><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqzYc2ibh9suJIRbFWfkIySVICPmRDYHj5h0TsLcy5ls1OiaqJSllz6ctQ/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqPPiaComLib7yYTqM1DgPtTJ6ecU8X4Piasxuu7qPMibHPYJooZNiboaStPA/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p><p><img src="https://mmbiz.qpic.cn/mmbiz_jpg/8KA0h1ic1Cf7rrXeYn1HLnfluqJIaIGPqfpHDwPWfEtMaZjsARMymCclFKmoIyb21yQ7NZhCTGQAXc4uufAk1mQ/640?wx_fmt=jpeg&tp=webp&wxfrom=5&wx_lazy=1&wx_co=1"/></p></section></section></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '', NULL, true, '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (910, '欢度国庆 新航实验各路达人齐“上线”', '', '', '', '<a href="images/2a8ed356685c429e84104f22fe6a37e9.jpg" target="_blank"><img title="0.jpg" src="/uploads/migration/images/2a8ed356685c429e84104f22fe6a37e9.jpg"/></a><a href="images/263aea424b31484babae8e927348fd32.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/263aea424b31484babae8e927348fd32.jpg"/></a><a href="images/2ed037ce6a3a4863976e2f59def5ed8f.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/2ed037ce6a3a4863976e2f59def5ed8f.jpg"/></a><a href="images/912d51a7de6e423fb229465c52129e26.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/912d51a7de6e423fb229465c52129e26.jpg"/></a><a href="images/b6ef0a3341994583b14765efc0742424.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/b6ef0a3341994583b14765efc0742424.jpg"/></a><a href="images/68838caf792b42f39ed629992b46a5d4.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/68838caf792b42f39ed629992b46a5d4.jpg"/></a><a href="images/6403b180bccc45ce9d3986fe7a4cf74b.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/6403b180bccc45ce9d3986fe7a4cf74b.jpg"/></a><a href="images/4e321a453d6845c799581a2e34e1dc8d.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/4e321a453d6845c799581a2e34e1dc8d.jpg"/></a><a href="images/3559ca31f4bb4383b58a1cc23f8a763c.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/3559ca31f4bb4383b58a1cc23f8a763c.jpg"/></a><a href="images/d2075dac76e740d48a9077e39cbe67a8.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/d2075dac76e740d48a9077e39cbe67a8.jpg"/></a><a href="images/c37fdc479d684386a5068a23fe07ad99.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/c37fdc479d684386a5068a23fe07ad99.jpg"/></a><a href="images/a73e0db017244c038822f1eae191d0da.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/a73e0db017244