INSERT INTO public.news VALUES (912, '新航好少年 | 数学+信息学“双料”奥赛达人：练习和坚持一个都不能少', '', '随着新航实验多元人才培养模式持续创新，一大批优秀学子涌现而出，他们勤学奋进、品学兼优，他们多才多艺、自律自强，他们已经初具新航实验学子的独特气质。请持续关注系列报道——新航好少年。陈俊羽获奖情况澳大利亚数学思维挑战AMC-E组中国区一等奖2020年美国思维挑战AMC8全球卓越奖中国区一等奖2021年美国数学思维挑战AMC10：全球优秀奖、中国区一等奖AMC12：中国区二等奖2021年加拿大计算机竞...', '', '<section><section><p><span>随着新航实验多元人才培养模式持续创新，</span></p><p><span>一大批优秀学子涌现而出，</span></p><p><span>他们勤学奋进、品学兼优，</span></p><p><span>他们多才多艺、自律自强，</span></p><p><span>他们已经初具新航实验学子的独特气质。</span></p><p><span>请持续关注系列报道——新航好少年。</span></p></section></section><p></p><section><section><section><section><section><p><br/></p><p><span><strong>陈俊羽获奖情况</strong></span></p><p><span><strong><br/></strong></span></p></section></section></section><section><section><br/></section></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section><section><section><p><span><strong><span>澳大利亚数学思维挑战AMC-E组</span></strong></span></p></section></section></section></section><section><section><section><section><section><p><span>中国区一等奖</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span><strong>2020年美国思维挑战AMC8</strong></span></p></section></section></section></section><section><section><section><section><section><p><span>全球卓越奖</span></p><p><span>中国区一等奖</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>2021年美国数学思维挑战</span></p></section></section></section></section><section><section><section><section><section><p><span>AMC10：全球优秀奖、中国区一等奖</span></p><p><span>AMC12：中国区二等奖</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>2021年加拿大计算机竞赛（CCC）高级组</span></p></section></section></section></section><section><section><section><section><section><p><span>全球优秀奖</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>2021年加拿大费马数学竞赛（高中组）<br/></span></p></section></section></section></section><section><section><section><section><section><p><span>全球优秀奖</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>2021美国计算机科学思维挑战活动全明星赛<br/></span></p></section></section></section></section><section><section><section><section><section><p><span>团队全国金奖/TOP3(队长)</span></p><p><span>全国个人铜牌</span></p><p><span>现场抢答赛全场第一名</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>2021年数学学科特长生夏令营“九月联盟杯”<br/></span></p></section></section></section></section><section><section><section><section><section><p><span>一等奖</span></p></section></section></section></section></section></section></section><section><section><section><section><section><section><section><section><section></section></section></section></section><section><p><span>陈俊羽</span></p></section><section><p><br/></p></section></section><section><section><p><a href="images/e116a4f477504493a2c28f27ca1fe70a.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/e116a4f477504493a2c28f27ca1fe70a.jpg"/></a></p><p><span>大家好，我是济南新航实验外国语学校初中部2020级4班陈俊羽。回想过去的一学年，在学校广阔自由的学习环境中，在刘翼老师和李想老师的培育和关爱下，在班主任和各学科老师的陪伴下，我在保证校内成绩的同时，积极参加国内外各项比赛并取得优异成绩。总结过往，有些成长路上的感受和经验与大家共勉。</span></p><p><img title="1.jpg" src="/uploads/migration/images/92499cbfe35f4a0f99a42f2005de5af4.jpg"/></p><p><br/></p></section><section><section><p><span>兴趣，兴趣，兴趣！重要的事情说三遍。对于任何一门学科，兴趣和热爱程度决定着你能在这个学科上走多远，能有多大决心去面对遇到的困难。正所谓“知之者不如好之者，好之者不如乐之者”。对我来说，如果接触到的数理题目不能解答，就感觉很不踏实，会千方百计地寻找答案，甚至研究解答这个题目所必须的一套从没接触过的理论，这些都源于我对理工科的热爱。</span></p></section></section><section><section><p><span>众所周知，“文科”是一个偏记忆方向的学科，其实对于理科学习来说，记忆同样很重要。公式以及公理、定理是计算过程和逻辑推理过程的桥梁，是从已知条件达到解题答案或者证明结论不可或缺的材料，直接影响着解题。所以，多阅读、多记忆是学好理科的基础。</span></p><p><a href="images/bbd18e5e2b434db6a6af64cdb759a654.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/bbd18e5e2b434db6a6af64cdb759a654.jpg"/></a></p><p><span>学有余力的同时还要加强知识点的拓展学习，有意识提升个人能力。在学科学习上，眼界应该放得广阔一些，知识点的拓展会帮助你举一反三，触类旁通，有足够的能力应付一些基本知识点的问题。</span></p><p><span>最后，要有坚持不懈的精神。提高成绩的方法就是经常应用，通过多做题反复加强记忆，且熟能生巧。其实这也是我经常会忽略的一点，因为总喜欢挑战难题新知识，忽略了常规练习，导致在考试中犯低级错误，与满分无缘。正所谓“会当凌绝顶，一览众山小”，当我们通过自己的努力站在高峰之上以后，就会发现之前经历的困难都算不上什么。</span></p><p><a href="images/c985840fd8d3469a82dd8d01c4870a2c.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/c985840fd8d3469a82dd8d01c4870a2c.jpg"/></a></p></section></section><section><section><p><span>良禽择木而栖，士为知己者而搏。“让每一个生命都精彩绽放”的新航实验，关注个体差异，因材施教，让我在学习中感受到了快乐，从竞争中体悟到了欢愉。相信我们在新航的呵护下，一步一个脚印地在人生道路上前行，定能征服一个个艰难险阻，把握好自己精彩的人生。</span></p></section></section></section></section></section></section></section><p></p><p><br/></p><meta name="ContentEnd">', '', 'highlights', '/uploads/migration/images/e116a4f477504493a2c28f27ca1fe70a.jpg', NULL, true, '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '2021-10-08 08:00:00+08', '赵昕晨', '新航实验外国语学校', '奥赛 信息学 达人 练习 数学', '');
INSERT INTO public.news VALUES (913, '导吾以狭路，示吾以通途——高二级部举行“学生成长导师制”启动仪式', '', '学生成长导师制九月金秋好时光，导师陪伴我成长，近日，济南新航实验外国语学校成功举办高二级部“学生成长导师制”启动仪式。“成长，从改变开始；改变，从自律开始”，导师制使得教育的个性化变为可能，使得学生不同的成长需求得到满足，使得“让每一个生命都精彩绽放”成为现实。启动仪式上，高一、高二级部主任杨翠华向大家介绍，“学生成长导师制”以生命教育为出发点，关注每一个学生的成长和进步，这既是学校教育工作的新思...', '', '<section><section><section><section><p><strong><span>学</span><span>生成长导师制</span></strong></p></section></section></section></section><p><section><section><p><span>九月金秋好时光，导师陪伴我成长，近日，济南新航实验外国语学校成功举办高二级部“学生成长导师制”启动仪式。“成长，从改变开始；改变，从自律开始”，导师制使得教育的个性化变为可能，使得学生不同的成长需求得到满足，使得“让每一个生命都精彩绽放”成为现实。</span></p></section></section></p><p><span><a href="images/ae5c540f2166438a982fb43ec0f16607.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/ae5c540f2166438a982fb43ec0f16607.jpg"/></a></span><br/></p><p><span>启动仪式上，高一、高二级部主任杨翠华向大家介绍，“学生成长导师制”以生命教育为出发点，关注每一个学生的成长和进步，这既是学校教育工作的新思路，又是大教育观念下的一项长期的工作，有助于师生共同成长。</span></p><p><span>“从今天开始，我们之间在既有的师生关系基础上，关系又近了一层，交流又直接了一层，沟通又便捷了一层。当你学习上遇到困难时，当你生活中遇到困惑时，当你和朋友闹别扭时，当你感到孤独无助时，当你感觉和自己的父母无法沟通时，你要知道，有那么一位或几位‘亲’老师正在向你张开温暖的双臂。”导师代表宋武栋老师真挚又温暖的话语感动着在场的每一位师生。话音落地，现场响起热烈的掌声。掌声中，有感恩，有感动，有奋起……</span></p><p><a href="images/25e1e2aaf5714eb18743c4c596793ef7.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/25e1e2aaf5714eb18743c4c596793ef7.jpg"/></a></p><section><section><p><span>新航实验副校长、高中部校长王飞以“新起点、新征程”为题，分析高二的特点及当下学习现状，鼓励大家抓住青春的大好时光，不懈奋斗，实现学业梦想。<span>杨翠华主任则分析了学生开学后存在的问题及不良习惯，并有针对性地给出改正措施和建议，将“改变”与“自律”娓娓道来，令学生受到莫大鼓舞。</span></span></p></section></section><p><section><section><section><section><section><section></section></section></section><section><section><section></section></section></section></section><section><section><section><section></section></section></section></section></section></section><section><section><p><span>每一个生命的个体都是独特的，它必然有自己独特的成长方式，有自己独特的思维方式，会遇到自己独特的问题，会碰到自己独特的困惑。新航实验导师制实施两年多来，一直秉承满足学生个性化发展的初衷，最大程度实现生命的多元发展，努力成就每位新航学子的滚烫青春。</span></p></section></section></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/ae5c540f2166438a982fb43ec0f16607.jpg', NULL, true, '2021-09-18 08:00:00+08', '2021-09-18 08:00:00+08', '2021-09-18 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (914, '爱了，爱了！儿时的露天电影回来啦~~~', '', '金秋九月，秋意在一个多雾的黎明溜来，到了炎热的下午便不见踪影。在经历了新奇而又紧张的开学季以后，济南新航实验外国语学校小学部一、二年级的小朋友们迎来了新航第一次露天观影活动。《夏日友晴天》这部电影讲述的是海怪卢卡、阿贝托和人类女孩朱丽娅之间的故事。在电影中孩子们不仅看到了夏天、海滩、梦幻的海底世界，还有天马行空的想象，以及最动人的友情故事。观影过程中，小学生们聚精会神，心紧紧跟随着故事主线，为主人...', '', '<p><span>金秋九月，秋意在一个多雾的黎明溜来，到了炎热的下午便不见踪影。在经历了新奇而又紧张的开学季以后，济南新航实验外国语学校小学部一、二年级的小朋友们迎来了新航第一次露天观影活动。</span></p><p><img title="1.jpg" src="/uploads/migration/images/5c4e679872154430ac3b498e0b7bc80e.jpg"/></p><p><br/></p><p><span>《夏日友晴天》这部电影讲述的是海怪卢卡、阿贝托和人类女孩朱丽娅之间的故事。在电影中孩子们不仅看到了夏天、海滩、梦幻的海底世界，还有天马行空的想象，以及最动人的友情故事。</span></p><p><span>观影过程中，小学生们聚精会神，心紧紧跟随着故事主线，为主人公参加比赛而紧张，为主人公实现梦想而激动。小海怪和人类女孩互相帮助、互相关爱的场景，以及他们勇敢探索未知世界，用智慧和友谊克服困难的勇气都深深感染着孩子们。</span></p><p><span><img title="2.jpg" src="/uploads/migration/images/13e1dabc34d144139c9ffca952c6f61f.jpg"/></span></p><p><span><img title="3.jpg" src="/uploads/migration/images/57b506f4b0ea4db0a268c9cb7c90d5dd.jpg"/></span></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/5c4e679872154430ac3b498e0b7bc80e.jpg', NULL, true, '2021-09-18 08:00:00+08', '2021-09-18 08:00:00+08', '2021-09-18 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (915, '新航好少年 | 新航实验学子如何斩获5个A*', '', '随着新航实验多元人才培养模式持续创新，一大批优秀学子涌现而出，他们勤学奋进、品学兼优，他们多才多艺、自律自强，他们已经初具新航实验学子的特质。请持续关注系列报道——新航好少年。陈烁宁成绩情况● IGCSE学科 5个A* 1个A● 英国物理思维挑战赛全球金奖、美国AMC数学竞赛全国二等奖、国际语言学奥林匹克竞赛个人三等奖● 校级三好学生、全面发展标兵大家好，我是济南新航实验外国语学校高中部融合班20...', '', '<section><section><section><section><p><span>随着新航实验多元人才培养模式持续创新，</span></p><p><span>一大批优秀学子涌现而出，</span></p><p><span>他们勤学奋进、品学兼优，</span></p><p><span>他们多才多艺、自律自强，</span></p><p><span>他们已经初具新航实验学子的特质。</span></p><p><span>请持续关注系列报道——新航好少年。</span></p></section></section></section></section><p><section><section><section><section><p><br/></p></section></section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section><section><section><section><p><span>陈烁宁成绩情况</span></p></section></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><p><span>● IGCSE学科&nbsp;5个A* 1个A</span></p><p><span>● 英国物理思维挑战赛全球金奖、美国AMC数学竞赛全国二等奖、国际语言学奥林匹克竞赛个人三等奖</span></p><p><span>● 校级三好学生、全面发展标兵</span></p></section></section></section></section></p><p><a href="images/9801e891d34748ff81ee47a0b052ba30.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/9801e891d34748ff81ee47a0b052ba30.jpg"/></a></p><p><span>大家好，我是济南新航实验外国语学校高中部融合班2020级4班陈烁宁，过去的1年中，致力于学习IG课程，为进入梦校积蓄力量。从一个国际课程小白，到IG考试获得5个A*1个A的成绩，回顾这1年来的学习历程，非常感激陪伴我成长的各位老师，感谢与我共同进步的同学们。我也总结自己在高一学习生活中的所感所失所得，与大家分享。</span></p><p><a href="images/da17b6edacfc4fffb95ef0c871376399.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/da17b6edacfc4fffb95ef0c871376399.jpg"/></a></p><p></p><p><span>汪国真先生曾在《热爱生命》中写下“既然选择了远方，便只顾风雨兼程”，分享这句话给所有选择国际高中课程的同学们。</span></p><p><span>首先，选择国际课程，相比国内高考，就是选择远方。远方不止有诗意，还有很多未知，尤其是在后疫情时代，我们、我们的家长常常被各色新闻包围。于是就偶尔会动摇，时常会怀疑，总是在焦虑。我想说，二战的炮火都没有隔断科技文化的交流，疫情也不会。一旦选择了远方，我们就要相信自己的选择，坚定信心。如果有的同学还没有考虑清楚，请一定考虑清楚，带着迷茫的选择不利于后期的学习。</span></p><p><span>选择了远方，道阻且长。标化、学科、IG、AS等等等等，各种名词都涌到我们面前，起初是很不适应的。我的经验是，请相信我们的新航，语言老师、学科老师会全力教我们，规划老师会及时给我们建议，我们要做的，就是脚踏实地，努力学习，风雨兼程。</span></p><p><a href="images/40c48e2bc77a45b29ba5dc7c73543668.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/40c48e2bc77a45b29ba5dc7c73543668.jpg"/></a></p><p><span>IG学习是第一年的重点，选择学科是首要任务。虽然学校给我们提供了很多学科可以选择，最重要还是认清自己，选择自己最擅长的学科。爱好可以成就学科，但是爱好无法取代成绩；热点可以启发选择，但是热点也不能取代成绩。起初我的父母也是希望我选择相对热门的计算机、经济这类学科，可是我觉得我更加擅长数理化，于是我坚持了自己的想法，也更加努力证明自己，付出也有了收获。</span></p><p><span>IG学习过程中，我想分享一点经验，必须重视英语学习、高度重视英语学习、强烈重视英语学习。英语学习是一切学科学习的基础，是我们走向远方的桥梁，学习英语没有捷径，如同打基础、建桥梁，只有努力一条路，只有点滴积累、每日不辍一个办法。</span></p><p><span>关于IG考试，我想分享一点教训，不能忽视体育锻炼。IG考试日程很长，一个半月的考试周期，不仅考查我们的学习，也考查我们的体魄和意志力。只有具备了强壮的身体和强大的意志，我们才能够更加从容地应对IG、A-level和大学阶段的学习。</span></p><p><span>新的学期已经开始，我们又开启了新征程，为了远方、为了梦校，我会继续努力，也想和大家一起风雨兼程。</span></p><p><br/></p><meta name="ContentEnd">', '', 'highlights', '/uploads/migration/images/9801e891d34748ff81ee47a0b052ba30.jpg', NULL, true, '2021-09-17 08:00:00+08', '2021-09-17 08:00:00+08', '2021-09-17 08:00:00+08', '赵昕晨', '新航实验外国语学校', '斩获 实验 新航 少年 学子', '');
INSERT INTO public.news VALUES (916, '来一场说走就走的“穿越丛林”之旅', '', '为增强同学彼此信任感和班级凝聚力，帮助学生进一步适应校园生活，9月2日，济南新航实验外国语学校组织开展了新生心理团体拓展活动——“穿越丛林”。此次活动以班级为单位进行，所有同学蒙住双眼，在各班老师和负责同学的带领下，从学校体育馆出发，沿不同的路线返回教室，并在途中完成一次队伍排头和排尾的翻转。日常看似简单的路程，在戴上眼罩后变得异常艰难，大家手拉手摸索前行，相互扶持、彼此鼓励，穿过校园、爬过陡坡、...', '', '<section><section><p><span>为增强同学彼此信任感和班级凝聚力，帮助学生进一步适应校园生活，9月2日，济南新航实验外国语学校组织开展了新生心理团体拓展活动——“穿越丛林”。</span></p></section></section><p><section><section><a href="images/b52a31dc99e94b66a0905c29fb233ddf.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/b52a31dc99e94b66a0905c29fb233ddf.jpg"/></a></section></section><section><section><p><span>此次活动以班级为单位进行，所有同学蒙住双眼，在各班老师和负责同学的带领下，从学校体育馆出发，沿不同的路线返回教室，并在途中完成一次队伍排头和排尾的翻转。</span></p></section></section><section><section><a href="images/6af48e551e0c43edbba57e4cff8171fe.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/6af48e551e0c43edbba57e4cff8171fe.jpg"/></a><a href="images/ded9c7c441f941a2bb014d6e75355e19.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/ded9c7c441f941a2bb014d6e75355e19.jpg"/></a></section></section><section><section><br/></section></section><section><section><p><span>日常看似简单的路程，在戴上眼罩后变得异常艰难，大家手拉手摸索前行，相互扶持、彼此鼓励，穿过校园、爬过陡坡、越过台阶、迈过坎坷，在集体的力量下成功抵达目的地。</span></p></section></section><section><section><a href="images/372a65fd9fd04922a796bd7a594d9469.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/372a65fd9fd04922a796bd7a594d9469.jpg"/></a><a href="images/029529e270f44ad59be1c783692ba8aa.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/029529e270f44ad59be1c783692ba8aa.jpg"/></a><a href="images/677938d9c5d548c980cefb425fc8a234.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/677938d9c5d548c980cefb425fc8a234.jpg"/></a><a href="images/827daf46fdb5417dad4fc93ebdbdbf0a.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/827daf46fdb5417dad4fc93ebdbdbf0a.jpg"/></a></section></section><section><section><br/></section></section><section><section><p><span>通过此次具有挑战性和协作性的心理拓展活动，同学们真切感受到“团结就是力量”的真正含义，学会了感恩与换位思考，更加明白了班级凝聚力的重要性。活动虽然短暂，但是留在学生心中的触动却是永恒的，相信在接下来的新航实验学习生活中，大家定能团结协作，突破自我，逐渐成长为有识、有礼、有情、有型的“四有新航学子”。</span></p></section></section><section><section><a href="images/028b6c48c04f47e98b1da4c624c15cbe.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/028b6c48c04f47e98b1da4c624c15cbe.jpg"/></a><a href="images/57172d01212e49898daf6cda4ae1a65e.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/57172d01212e49898daf6cda4ae1a65e.jpg"/></a><a href="images/951d89d2e2d744ce941944b7056fc911.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/951d89d2e2d744ce941944b7056fc911.jpg"/></a></section></section><section><section><br/></section></section><section><section><br/></section></section><section><section><section><section><section><p><span><strong>学生感言</strong></span></p></section></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section><section><section><section><section></section></section></section></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><p><span>让我印象最为深刻的是，一开始我是一个跟随者、一个被帮助者，后来，成为了一个帮助别人的人，正因为有了这样的转变，让我更坚信团结的力量是最大的。</span></p></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><section><p><span>在集体的共同努力下，我们完成了本次活动。就像人生的旅途一样，不同阶段有不同的困难需要我们面对，但我们的身边总有一个集体在陪伴着我们共同面对一次又一次的考验。充分地融入一个集体，相信一个集体，在集体中努力，积极帮助集体中的人，也从集体中获得力量与温暖。</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><section><p><span>每个人既帮助别人，也被别人帮助着，我们要试着去相信他人，并相信这种相信的力量，它会在迷茫中帮你回归正轨。人生路上，也有许多人会在你遇到挫折、碰壁时将你拉回，正是因为有这些人，在那些黑暗的日子里，生活才会重回灿烂，阴霾会烟消云散，未来会一片光明。</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><section><p><span>当再次遇到漆黑一片时，我不会再害怕，因为我明白，总会有一个人指导我、牵引我，让我变得勇敢，让我安心我的每一步都是在正轨上行走。</span></p></section></section></section></section></section><section><section><section><section><section><section></section></section></section></section><section><section><section><p><span>我们的成长也是如此，从一开始的牙牙学语，到后来征战考场，这期间少不了老师、家长、同学的帮助，他们如同黑夜中的灯塔，引领我们绕过暗礁，抵达终点。</span></p></section></section></section></section></section></p><p><br/></p><meta name="ContentEnd">', '', 'highlights', '/uploads/migration/images/b52a31dc99e94b66a0905c29fb233ddf.jpg', NULL, true, '2021-09-17 08:00:00+08', '2021-09-17 08:00:00+08', '2021-09-17 08:00:00+08', '赵昕晨', '新航实验外国语学校', '穿越 丛林 之旅', '');
INSERT INTO public.news VALUES (917, '专家领航促提升 精准赋能助成长——新航实验开展全体教师培训', '', '为持续增强任课教师的综合素养和业务能力，精准赋能教师专业水平发展，9月12日，作为教师年度培训系列活动的重要组成部分，济南新航实验外国语学校全体教师培训如期举行，四位重量级专家从学生管理、心理辅导、法律法规、教师成长等方面入手，既有理论高度，又有实操指导意义，为老师们献上一场场精彩纷呈的报告，进一步提升了新航实验教师团队的教育教学素养和理论水平。学生管理问题的处置与思考培训伊始，山东省实验中学副校...', '', '<section><section><p><span>为持续增强任课教师的综合素养和业务能力，精准赋能教师专业水平发展，9月12日，作为教师年度培训系列活动的重要组成部分，济南新航实验外国语学校全体教师培训如期举行，四位重量级专家从学生管理、心理辅导、法律法规、教师成长等方面入手，既有理论高度，又有实操指导意义，为老师们献上一场场精彩纷呈的报告，进一步提升了新航实验教师团队的教育教学素养和理论水平。</span></p><p><br/></p></section><p><strong>学生管理问题的处置与思考</strong><br/></p><p><strong><br/></strong></p><section><p><img title="" src="/uploads/migration/images/s_41a7634c1f5045e5a30572355efaffa7.jpg" width="500" height="312"/></p><p><br/></p></section><section><p><span>培训伊始，山东省实验中学副校长李丽以《学生管理问题的处置与思考》为题，针对中小学生成长过程中的心理问题和学生矛盾的预防、识别与干预进行了深入的分析与解读，“学生发展和教育是复杂的，既需要老师们有教无类，也需要因材施教，不断提升学生的心理健康水平及自我化解危机的能力。“作为老师更要提升育人工作水平，以积极的态度、科学的方法参与学生成长过程。</span></p><p><br/></p></section><section><section><section><p><span><strong>系统式家庭治疗对家庭教育的启示</strong></span></p></section></section></section><section><p><img title="" src="/uploads/migration/images/s_fbe22248c38c4d4597a470c3b6227d79.jpg" width="500" height="292"/></p><p><a href="images/a5d2a140d1bc4c9c901d75254a6b1e25.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a5d2a140d1bc4c9c901d75254a6b1e25.jpg" width="500" height="333"/></a><a href="images/e13844eb22a9448e97f2e9cfd579f2e0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e13844eb22a9448e97f2e9cfd579f2e0.jpg" width="500" height="333"/></a></p><p><a href="images/ad05a34473ba4aac9d7c84cf4078101b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ad05a34473ba4aac9d7c84cf4078101b.jpg" width="500" height="333"/></a><a href="images/75cf59a54eee4e20a849a5c3a72c2dfb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_75cf59a54eee4e20a849a5c3a72c2dfb.jpg" width="500" height="333"/></a></p><p><br/></p></section><section><p><span>在第二场专家报告中，中国心理学会注册系统心理师、中德高级家庭治疗师项目成员、教育部“国培计划”授课专家逄霞，为教师们带来青少年心理辅导，并详细介绍了系统式家庭治疗对家庭教育的启示。讲座中，逄霞老师通过生动的交流互动，引导老师们在处理学生问题时，不仅要加强日常教育和管理，也要重视对学生家庭因素的分析，利用家校合作实现教育效果的最大化。</span></p><p><br/></p></section><section><section><section><p><span><strong>新时代未成年人犯罪预防与权益保护</strong></span></p><p><span><strong><br/></strong></span></p></section></section></section><section><p><img title="" src="/uploads/migration/images/s_20a07641cc584ebf86aa276515637d0e.jpg" width="500" height="333"/></p><p><br/></p></section><section><p><span>紧接着，历城区人民法院少年法庭法官姬广锴围绕《新时代未成年人犯罪预防与权益保护》这一主题，结合真实案例故事，对未成年人保护的相关法律法规进行详细解读，引导老师们从知法到学法、懂法、会用法，学会正确引导和避免未成年人违法犯罪行为，保护和维护学生合法权益。</span></p><p><br/></p></section><section><section><section><p><span><strong>迈好走上讲台的第一步</strong></span></p><p><span><strong><br/></strong></span></p></section></section></section><section><section><p><img title="" src="/uploads/migration/images/s_18f6161cc7b141afb36ed185ac588431.jpg" width="500" height="355"/></p></section><section><br/></section></section><section><p><span>“教师的功力在于把一切难题进行技术化破解。”济南西城实验中学副校长钟红军带领老师们探讨如何“迈好走上讲台的第一步”，她以自己20多年的教育经历为主线，通过视频分享和经验交流，从基本功的养成和教学方法的探索两方面，指导老师们如何成长为一名优秀的人民教师。</span></p></section><section><section><p><img title="" src="/uploads/migration/images/s_442225aeda274be08ba190bd27375f5b.jpg" width="500" height="525"/></p></section></section><section><p><span>此次培训活动，进一步点燃了老师们的教学激情，激励大家不断提高自身教育教学水平，用专业引领学生成长。相信在接下来的工作中，老师们定能将培训的内容转化为自身的专业，做好个人规划，立足本职岗位，牢记教书育人初心，成为最好的自己！</span></p></section><p><br/></p><p><br/></p></section><section><section><p><br/></p></section></section><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/a5d2a140d1bc4c9c901d75254a6b1e25.jpg', NULL, true, '2021-09-14 08:00:00+08', '2021-09-14 08:00:00+08', '2021-09-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (918, '铿锵步履绽芳华 迷彩军魂燃青春——新航实验2021级新生入校教育汇报展演', '', '入校教育恰同学少年，风华正茂，书生意气，挥斥方遒。迎着朝阳上操，踏着夕阳解散，经过七天的艰苦训练，今天，济南新航实验外国语学校迎来2021级新生入校教育汇报展演。学生们用飒爽的英姿和昂扬的激情，向家长和师长们交上一份满意的答卷。01入校教育进行时在激昂的国歌声中，汇报展演正式开始。列队动作、擒敌拳术、集体手语操……动作整齐划一，口号铿锵有力，一招一式尽显少年风范，四百多名新航学子犹如四百多名战士，...', '', '<p><span><strong><span>入校教育</span></strong></span></p><p><span><strong><span></span></strong></span></p><p><span>恰同学少年，风华正茂，</span></p><p><span>书生意气，挥斥方遒。</span></p><p><span><a href="images/3e1b23fbd9f4482e905ea9f0f7748fb6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3e1b23fbd9f4482e905ea9f0f7748fb6.jpg" width="500" height="333"/></a></span></p><p><span><a href="images/743be03f38a246028438d51a1b0c77cc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_743be03f38a246028438d51a1b0c77cc.jpg" width="500" height="333"/></a></span></p><p><span>迎着朝阳上操，</span></p><p><span>踏着夕阳解散，</span></p><p><span>经过七天的艰苦训练，</span></p><p><span>今天，济南新航实验外国语学校</span></p><p><span>迎来2021级新生入校教育汇报展演。</span></p><p><span>学生们用飒爽的英姿和昂扬的激情，</span></p><p><span>向家长和师长们交上一份满意的答卷。</span></p><p><br/></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>01</strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>在激昂的国歌声中，汇报展演正式开始。</span></p><p><span>列队动作、擒敌拳术、集体手语操……</span></p><p><span>动作整齐划一，</span></p><p><span>口号铿锵有力，</span></p><p><span>一招一式尽显少年风范，</span></p><p><span>四百多名新航学子犹如四百多名战士，</span></p><p><span>苦炼成钢，勇往直前！</span></p><p><a href="images/29d78cfb9b5c425e98eb0c8d58a52f3a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_29d78cfb9b5c425e98eb0c8d58a52f3a.jpg" width="500" height="387"/></a><a href="images/408f389efa474be18999d671931a26bc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_408f389efa474be18999d671931a26bc.jpg" width="500" height="333"/></a><a href="images/a7504ac3ff934414b672db1fd48edb4a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a7504ac3ff934414b672db1fd48edb4a.jpg" width="500" height="333"/></a><a href="images/7f3f4e51a9bd4ee08e6f8a6f271e87ff.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7f3f4e51a9bd4ee08e6f8a6f271e87ff.jpg" width="500" height="333"/></a><a href="images/8512e85c28af4079bd37b3e245620840.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8512e85c28af4079bd37b3e245620840.jpg" width="500" height="333"/></a><a href="images/0f750060207e4d468c6f5cc9139139d1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0f750060207e4d468c6f5cc9139139d1.jpg" width="500" height="333"/></a><a href="images/6ce9d78d475441a2befd341a89e37b12.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6ce9d78d475441a2befd341a89e37b12.jpg" width="500" height="333"/></a></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>02</strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>犹记得开营时的你们，</span></p><p><span>带着初入学的稚嫩，</span></p><p><span>怀揣着对未知的紧张和憧憬，</span></p><p><span>开启了崭新的新航实验生活。</span></p></section></section></section></section></section><p><a href="images/03d47504ff9243f6bce1df7dd018720d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_03d47504ff9243f6bce1df7dd018720d.jpg" width="500" height="333"/></a><a href="images/96813091d1514215b2fdcb5d0ffd70f3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_96813091d1514215b2fdcb5d0ffd70f3.jpg" width="500" height="333"/></a></p></section></section></section></section></section><p><span><strong><span></span></strong></span></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>03</strong><strong></strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong><strong></strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>骄阳烈日毫不畏惧，</span></p><p><span>风雨交加不为动容。</span></p><p><span>这里有汗流浃背，也有欢声笑语；</span></p><p><span>有泪水疼痛，也有“我还能坚持”。</span></p><p><span>这里的踏步声依旧整齐，</span></p><p><span>一张张面庞依旧坚毅，</span></p><p><span>这里的朝气与迷彩交相辉映。</span></p><p><a href="images/fd97ee7db3c74624acdc32230359a4e6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fd97ee7db3c74624acdc32230359a4e6.jpg" width="500" height="333"/></a><a href="images/8c6813e8f8ef45188de30206aa0488dc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8c6813e8f8ef45188de30206aa0488dc.jpg" width="500" height="699"/></a><a href="images/8d535f7fc86c4ef784301409b266021d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8d535f7fc86c4ef784301409b266021d.jpg" width="500" height="699"/></a><a href="images/dcfa4902e5e746169e9955e34466be27.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_dcfa4902e5e746169e9955e34466be27.jpg" width="500" height="404"/></a><a href="images/719afcb5cd7044d3b13d1c0444e7628f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_719afcb5cd7044d3b13d1c0444e7628f.jpg" width="500" height="333"/></a><a href="images/3ab96733d2f04d478c2ddca5cb7c4b65.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3ab96733d2f04d478c2ddca5cb7c4b65.jpg" width="500" height="375"/></a></p></section></section></section></section></section><p><span><strong><span></span></strong></span></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>04</strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>训练再苦，也有“战友”陪伴。</span></p><p><span>汗水中，你们收获了友谊，</span></p><p><span>结识了交心的朋友，</span></p><p><span>更懂得了集体的珍贵。</span></p></section></section></section></section></section><p><a href="images/a4c4ff972e604057b03182042c54845d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a4c4ff972e604057b03182042c54845d.jpg" width="500" height="375"/></a><a href="images/09ee5aba13be43d395d31067a0c1f13f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_09ee5aba13be43d395d31067a0c1f13f.jpg" width="500" height="750"/></a><a href="images/eabdb589efa54ad3852204daf2b921d6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_eabdb589efa54ad3852204daf2b921d6.jpg" width="497" height="497"/></a><a href="images/545781c1073947f188d33b1f378390c9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_545781c1073947f188d33b1f378390c9.jpg" width="500" height="332"/></a><a href="images/4a46beef939945b2a12128ca38dbe7db.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4a46beef939945b2a12128ca38dbe7db.jpg" width="500" height="375"/></a></p><p><span><strong><span></span></strong></span></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>05</strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>“稍息——立正！”</span></p><p><span>“手贴紧、腿绷直、脚并拢！”</span></p><p><span>训练时严厉的教官，</span></p><p><span>训练之余却是可爱的伙伴。</span></p><p><span>他们时刻关注着每一位同学的变化，</span></p><p><span>喜悦着每一名“战士”的成长。</span></p></section></section></section></section></section><p><a href="images/417bfac1981c412c8dfbc4377322e3fe.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_417bfac1981c412c8dfbc4377322e3fe.jpg" width="500" height="375"/></a><a href="images/9942cb83142f463b8f7007618b51b6c8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9942cb83142f463b8f7007618b51b6c8.jpg" width="500" height="333"/></a><a href="images/46b255061bec4ff4acbee8e843b948c8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_46b255061bec4ff4acbee8e843b948c8.jpg" width="500" height="333"/></a><a href="images/d1bb430c5bd44fd589e8fd89f34ced90.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d1bb430c5bd44fd589e8fd89f34ced90.jpg" width="500" height="333"/></a></p><p><span><strong>06</strong><br/></span></p><section><section><section><section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>训练场上有你们整齐的身姿，</span></p><p><span>校园里有你们军歌不断飞扬。</span></p><p><span>嘹亮的歌声响彻每个角落，</span></p><p><span>青春的风华体现到淋漓尽致，</span></p><p><span>你们唱出对青春的无所畏惧，</span></p><p><span>对未来的无限展望。</span></p></section></section></section></section></section><p><a href="images/62313cc2b9ff4ffcbd87a180e41e1f69.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_62313cc2b9ff4ffcbd87a180e41e1f69.jpg" width="500" height="375"/></a><a href="images/36e5ea284c084608a725cfccfed81581.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_36e5ea284c084608a725cfccfed81581.jpg" width="500" height="375"/></a><a href="images/8650c6483e59459b950eadf1573f371b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8650c6483e59459b950eadf1573f371b.jpg" width="500" height="377"/></a></p><p><span><strong><span><br/></span></strong><strong><span></span></strong><strong></strong></span></p><p><span><strong><span></span></strong><strong></strong></span></p><section><section><section><section><section><section><section><section><section><section><section><p><span><strong>07</strong><strong></strong></span></p></section></section><section><section><section></section></section></section></section></section></section></section><section><section><p><span><strong>入校教育进行时</strong><strong></strong></span></p></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>老师们精心准备的冷餐会，</span></p><p><span>成为这场入校教育中最撒欢的一刻。</span></p><p><span>点心、水果、牛奶……</span></p><p><span>所有想家的思绪一扫而空，</span></p><p><span>在这里，老师和同学便是最温暖的陪伴。</span></p></section></section></section></section></section><p><a href="images/9300ebd4fb9e4077b914c9bd83260311.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9300ebd4fb9e4077b914c9bd83260311.jpg" width="500" height="375"/></a><a href="images/681aa1e01a0d4587a4b8dfd44a11368d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_681aa1e01a0d4587a4b8dfd44a11368d.jpg" width="500" height="230"/></a><a href="images/3686e07af679460eb625c9632fe7db59.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3686e07af679460eb625c9632fe7db59.jpg" width="500" height="666"/></a><a href="images/1678a59528194f4b83e8d4a1456ab7b9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1678a59528194f4b83e8d4a1456ab7b9.jpg" width="500" height="375"/></a></p><p><span><strong><span></span></strong></span></p><section><section><section><section><p><span><strong>青春奋斗时</strong></span></p></section><section><section><section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>如果说成长是一种蜕变，</span></p><p><span>入校教育则助力你们破茧成蝶。</span></p><p><span>告别这一场不可复制的青春</span></p><p><span>奋斗正式开场！</span></p><p><span>请党放心，强国有我，</span></p><p><span>新航实验的少年们，</span></p><p><span>请你们牢记此时顽强的斗志和坚毅的品格，</span></p><p><span>保持心中有火、眼里有光的状态，</span></p><p><span>无畏前行，恣意高歌！</span></p></section></section></section></section></section><p><img title="" src="/uploads/migration/images/s_6da3b239fdc24393b04357d7eeb5f9da.jpg" width="500" height="333"/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/3e1b23fbd9f4482e905ea9f0f7748fb6.jpg', NULL, true, '2021-09-09 08:00:00+08', '2021-09-09 08:00:00+08', '2021-09-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (919, '常规教育、德育创新、奥运传承……新航实验开学典礼惊艳亮相', '', ' 9月2日晚，济南新航实验外国语学校的师生们迎来了一场创意十足的开学典礼，这次我们不仅把开学典礼搬到了草地上，更是请来了山东历史上第一块奥运金牌获得者，把开学典礼办成了一场内容丰富的草地音乐节。三大主题，教育内容“干货十足” 晚上18：30，新航实验的操场上，千余名学生陆续以学部为单位，井然有序地坐在一起。前面的舞台上光影交织，伴随一曲怀旧的开学歌曲串烧，开学典礼大幕正式拉开。 据了解，当晚的活动...', '', '<p><a href="images/ef4a13a4bce3449d8d32a7324a6f2a61.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/ef4a13a4bce3449d8d32a7324a6f2a61.jpg"/></a><img title="2.jpg" src="/uploads/migration/images/e8f22343909742e786595f91d60aceb9.jpg"/><img title="3.jpg" src="/uploads/migration/images/f4618eab3464472cba2aedadc0426227.jpg"/></p><p><span>&nbsp;9月2日晚，济南新航实验外国语学校的师生们迎来了一场创意十足的开学典礼，这次我们不仅把开学典礼搬到了草地上，更是请来了山东历史上第一块奥运金牌获得者，把开学典礼办成了一场内容丰富的草地音乐节。</span></p><p><br/></p><section><section><section><section><section><p><strong><span>三大主题，教育内容“干货十足”</span></strong></p></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>&nbsp;晚上18：30，新航实验的操场上，千余名学生陆续以学部为单位，井然有序地坐在一起。前面的舞台上光影交织，伴随一曲怀旧的开学歌曲串烧，开学典礼大幕正式拉开。</span></p><p><span><a href="images/14bf9fc21bf74d4f90fd541c1eb7ddb0.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/14bf9fc21bf74d4f90fd541c1eb7ddb0.jpg"/></a></span><a href="images/ad630f3d31cd4c55955dc0f540aaf1ba.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/ad630f3d31cd4c55955dc0f540aaf1ba.jpg"/></a></p></section></section></section></section></section><p><br/></p><p><span>&nbsp;据了解，当晚的活动共分为三个主题，即“以心迎新 同新起航”、“行己有耻 止于至善”、“新航逐梦 未来可期”，分别聚焦欢迎新生、规范常规教育、助力初三高三这三个内涵。</span></p><p><span><a href="images/28aa04e28d604360b65e4901875cc64a.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/28aa04e28d604360b65e4901875cc64a.jpg"/></a></span><a href="images/68da7d9af66140b6b15dce75884ebc78.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/68da7d9af66140b6b15dce75884ebc78.jpg"/></a><a href="images/94b70beceb564dbf9f368012278a4337.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/94b70beceb564dbf9f368012278a4337.jpg"/></a></p><p><span>&nbsp;活动伊始，山东省实验中学党委委员、东校校长，济南新航实验外国语学校执行校长林宝磊代表学校，欢迎新生的加入，并为学生们送上新学期的期望和嘱托，勉励同学们保持志存高远、朝气蓬勃的状态，安静读书、努力拼搏，用每一天的努力慢慢接近心中的梦想。</span></p><p><span><a href="images/6cf5db5578fc4759b62eb4d14b26ab45.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/6cf5db5578fc4759b62eb4d14b26ab45.jpg"/></a></span></p><p><br/></p><p><span>&nbsp;紧接着，初一年级孙华澈同学作为新生代表发言，岁月峥嵘须拼搏，年华潇洒莫蹉跎，新同学的到来势必为新航实验注入更多的活力与荣耀。</span></p><p><span><a href="images/d12c2b0264124143af2663be0010bd48.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/d12c2b0264124143af2663be0010bd48.jpg"/></a></span></p><section><section><section><section><section><p><strong><span>学生当“老师”，德育设计形式活</span></strong></p></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>&nbsp;对于学生来说，校纪校规就像校园里的“红绿灯”，时刻提醒学生注意自己的言行。不同于以往的课堂说教，这次，新航实验的德育课堂变成学生来主导，幽默风趣的三句半、生动形象的卡通视频、小初高同学的经典合诵以及着装规范、阳光靓丽的校服展示，都将校园安全、课堂、早操、就餐、学习、休息、着装、文明礼仪等校规校纪传递给每位同学，活泼新颖的形式，让学生在欢声笑语中将校规校纪、一日常规、十项禁令牢记心中，真切领悟修身养性、文明知礼的真谛。接下来，由一首师生合唱的《不忘初心》，唱出新航实验人牢记使命、严于律己、志存高远、报效祖国的决心与信心。</span></p><section><section><section><section><section><p><a href="images/a428dee5d4d24a17a95cf7c8b4487781.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/a428dee5d4d24a17a95cf7c8b4487781.jpg"/></a><a href="images/55fd65a336624aaa84b94b4a98faacaa.jpg" target="_blank"><img title="12.jpg" src="/uploads/migration/images/55fd65a336624aaa84b94b4a98faacaa.jpg"/></a><a href="images/5130f9b88eee497fad5197b90d4890cd.jpg" target="_blank"><img title="13.jpg" src="/uploads/migration/images/5130f9b88eee497fad5197b90d4890cd.jpg"/></a><a href="images/7231e447b36e4a009236f748877a3a28.jpg" target="_blank"><img title="14.jpg" src="/uploads/migration/images/7231e447b36e4a009236f748877a3a28.jpg"/></a><a href="images/3e4f92b7ee3c4d9ea2e13159f5c834c3.jpg" target="_blank"><img title="15.jpg" src="/uploads/migration/images/3e4f92b7ee3c4d9ea2e13159f5c834c3.jpg"/></a><a href="images/296c9dbfc87f43faa1f7904448016a73.jpg" target="_blank"><img title="16.jpg" src="/uploads/migration/images/296c9dbfc87f43faa1f7904448016a73.jpg"/></a><a href="images/37f9a1c0fcdd4714a4ede3a4e43f4fda.jpg" target="_blank"><img title="17.jpg" src="/uploads/migration/images/37f9a1c0fcdd4714a4ede3a4e43f4fda.jpg"/></a><a href="images/23cd4d5c7fe24a6dbb616e2ec8b3e901.jpg" target="_blank"><img title="18.jpg" src="/uploads/migration/images/23cd4d5c7fe24a6dbb616e2ec8b3e901.jpg"/></a><a href="images/6ae6eedb0b7b438da3cbb74d90e6a4be.jpg" target="_blank"><img title="19.jpg" src="/uploads/migration/images/6ae6eedb0b7b438da3cbb74d90e6a4be.jpg"/></a></p><p><strong><span>冠军现场助阵，奥运精神引领强</span></strong></p></section></section></section><section><section><section><section><section><section><section><section></section></section></section></section></section></section></section></section></section></section><p><br/></p><section><section><section><section><section><p><span>&nbsp;在刚刚落幕的东京奥运会，我们共同见证了无数中国体育健儿奋勇争先的精彩瞬间。在“新航逐梦 未来可期”主题，四名山东籍奥运冠军孙梦雅、庞伟、张成龙、王峰，由于训练原因无法亲临现场，通过大屏幕为新航学子送上开学寄语，鼓励大家发扬更高、更快、更强的奥运精神，努力拼搏，早日成为自己领域的佼佼者。</span></p><p><span><a href="images/2d674e4aed864fd4a790a86e07130408.jpg" target="_blank"><img title="20.jpg" src="/uploads/migration/images/2d674e4aed864fd4a790a86e07130408.jpg"/></a></span></p><p><span>&nbsp;在现场热烈的掌声和欢呼声中，奥运精神的种子在新航实验学子心中已经悄然埋下。活动现场，山东历史上第一位奥运冠军林伟宁登上讲台，与新航实验学子们分享自己10年夺冠的奋斗路，鼓励新航实验学子在人生道路上顽强拼搏，坚韧不拔，“当你觉得自己坚持不下去的时候，请你再坚持一下，成功可能就在不远处。”奥运冠军平实的话语、动人的讲述，赢得了现场欢呼声不断。</span></p><p><span><a href="images/4b2f6e73f3064f8c89ef43ab39ef57c2.jpg" target="_blank"><img title="21.jpg" src="/uploads/migration/images/4b2f6e73f3064f8c89ef43ab39ef57c2.jpg"/></a><a href="images/59bb887caa054c08ab9885e755b25b93.jpg" target="_blank"><img title="22.jpg" src="/uploads/migration/images/59bb887caa054c08ab9885e755b25b93.jpg"/></a></span></p></section></section></section></section></section><p><span>&nbsp;在新航实验，每一学年总会涌现出这样一批学生，他们认真踏实，勤奋好学；他们温暖自信，超越自我；他们才学博雅，品德高尚；他们坚守信念，笃定前行；他们是榜样的力量，召唤着见贤思齐、择善而从。</span></p><p><span><a href="images/9a2c753e3bf14148972242655e7357b9.jpg" target="_blank"><img title="23.jpg" src="/uploads/migration/images/9a2c753e3bf14148972242655e7357b9.jpg"/></a></span><a href="images/4247506a27214176a22088249898b89e.jpg" target="_blank"><img title="24.jpg" src="/uploads/migration/images/4247506a27214176a22088249898b89e.jpg"/></a><a href="images/754eb45e717c4ec68350eae7973f6892.jpg" target="_blank"><img title="25.jpg" src="/uploads/migration/images/754eb45e717c4ec68350eae7973f6892.jpg"/></a><a href="images/0670462b16744ecfb55d4080e61ea4ce.jpg" target="_blank"><img title="26.jpg" src="/uploads/migration/images/0670462b16744ecfb55d4080e61ea4ce.jpg"/></a><a href="images/7aeb5293078b4a4a8de0fe54f772108f.jpg" target="_blank"><img title="27.jpg" src="/uploads/migration/images/7aeb5293078b4a4a8de0fe54f772108f.jpg"/></a><a href="images/cb7df4a3a672482fb1255938a7b08499.jpg" target="_blank"><img title="28.jpg" src="/uploads/migration/images/cb7df4a3a672482fb1255938a7b08499.jpg"/></a><a href="images/c0a17c3059f9446f99cf03226ca484aa.jpg" target="_blank"><img title="29.jpg" src="/uploads/migration/images/c0a17c3059f9446f99cf03226ca484aa.jpg"/></a><a href="images/dd631b4fdf104b9db2a5974eba2739cc.jpg" target="_blank"><img title="30.jpg" src="/uploads/migration/images/dd631b4fdf104b9db2a5974eba2739cc.jpg"/></a><a href="images/601fd4494bbc4453b04919bc517f9d6c.jpg" target="_blank"><img title="31.jpg" src="/uploads/migration/images/601fd4494bbc4453b04919bc517f9d6c.jpg"/></a><a href="images/bc66feeab19c4d75a4115c1cde349c43.jpg" target="_blank"><img title="32.jpg" src="/uploads/migration/images/bc66feeab19c4d75a4115c1cde349c43.jpg"/></a></p></section></section></section></section></section><p><span>&nbsp;今年，新航实验迎来第一届初三和高三毕业班。“三年砺剑今日策马闯雄关，一朝试锋六月扬眉凯歌旋”，接下来的授旗环节，初三、高三普通班、高三融合班师生代表登台，郑重接过凝聚着雄心壮志的三面大旗，在全场观众的呐喊和助威中用力挥舞。“请党放心，强国有我！”随着那掷地有声的话语，他们将脚踏实地、奋力远航。<br/></span></p><p><span><a href="images/3d7c40420def43609c59f2f584b813f2.jpg" target="_blank"><img title="33.jpg" src="/uploads/migration/images/3d7c40420def43609c59f2f584b813f2.jpg"/></a></span><a href="images/2ba9ab3afa8849cdb9b8dfdaad0c2261.jpg" target="_blank"><img title="34.jpg" src="/uploads/migration/images/2ba9ab3afa8849cdb9b8dfdaad0c2261.jpg"/></a></p><p><span>&nbsp;伴随着最后一曲《我们都是追梦人》，全场合唱，每一字、每一句都蕴藏着催人奋进的力量，整场活动在合唱中落下帷幕。</span></p><p><span><a href="images/f0e2c447e00746f8b72c34147010f883.jpg" target="_blank"><img title="35.jpg" src="/uploads/migration/images/f0e2c447e00746f8b72c34147010f883.jpg"/></a></span><a href="images/b3a0404ef566478981a4db738f820af3.jpg" target="_blank"><img title="36.jpg" src="/uploads/migration/images/b3a0404ef566478981a4db738f820af3.jpg"/></a></p><p><br/></p><p><span></span><br/></p><p><span><br/></span></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/ef4a13a4bce3449d8d32a7324a6f2a61.jpg', NULL, true, '2021-09-03 08:00:00+08', '2021-09-03 08:00:00+08', '2021-09-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (920, '你好，新新新航人，终于等到你！', '', '盼望着，盼望着你们终于来啦！夏日洗净即入秋韵你们的到来成为校园最亮丽的风景线多少美好熔铸成一场相遇        老师们已等候多时秋雨绵绵无法阻挡他们迎新的热情与激动                          在这里你们即将开启新的生活遇见新的伙伴跨越新的挑战            在这里青春与梦想将一起放飞青春与汗水将一起挥洒青春与歌声将一起激荡        加油吧新新新航人前路漫漫我...', '', '<p><span>盼望着，盼望着</span></p><p><span>你们终于来啦！</span></p><p><span>夏日洗净</span></p><p><span>即入秋韵</span></p><p><span>你们的到来</span></p><p><span>成为校园最亮丽的风景线</span></p><p><span>多少美好</span></p><p><span>熔铸成一场相遇</span></p><p><a href="images/0a6a993973364f768e9badb88a6067f6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0a6a993973364f768e9badb88a6067f6.jpg" width="376" height="250" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/1799e3b3b5f444918b4e570dc35feaf2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1799e3b3b5f444918b4e570dc35feaf2.jpg" width="270" height="250" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/6822b7f294c24e95b98d9514ca450361.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6822b7f294c24e95b98d9514ca450361.jpg" width="333" height="250" alt=""/></a></p><p><br/></p><section><p><span>老师们已等候多时</span></p><p><span>秋雨绵绵<br/></span></p><p><span>无法阻挡他们迎新的热情与激动</span></p><p><span><br/></span></p><p><span><a href="images/6a8d66cbafa64a9b807035f74ffec3cb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6a8d66cbafa64a9b807035f74ffec3cb.jpg" width="376" height="250" alt=""/></a>&nbsp; &nbsp;&nbsp;</span><img title="" src="/uploads/migration/images/s_09d31a8565974645ba84186cf65c972a.jpg" width="375" height="250" alt=""/><span>&nbsp; &nbsp;&nbsp;</span><img title="" src="/uploads/migration/images/s_ed65fdcf5d30471ea8f861e851ce8492.jpg" width="333" height="250" alt=""/></p><p><br/></p><p><a href="images/2713cbda156645bf8eb30033152e5773.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2713cbda156645bf8eb30033152e5773.jpg" width="376" height="250" alt=""/></a>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_184f94f3a7b047c1b57cc4718115e211.jpg" width="376" height="250" alt=""/></p><p><span>&nbsp; &nbsp;&nbsp;</span></p><p><span><br/></span></p></section><p><span>在这里</span></p><p><span>你们即将开启新的生活<br/></span></p><p><span>遇见新的伙伴</span></p><p><span>跨越新的挑战</span></p><p><span><br/></span></p><p><span><a href="images/3c51a04bc6c344b1a9ccf7b6500033ea.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3c51a04bc6c344b1a9ccf7b6500033ea.jpg" width="376" height="250" alt=""/></a></span><img title="" src="/uploads/migration/images/s_0ca46bc80d7840fe94ac13a1da932167.jpg" width="446" height="250" alt=""/><span>&nbsp; &nbsp;&nbsp;</span><img title="" src="/uploads/migration/images/s_13e1ae4877524c748de3ebeb3ffa617f.jpg" width="291" height="250" alt=""/></p><p><br/></p><p><a href="images/45565eab069d4ca4a47ecaacbaff569c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_45565eab069d4ca4a47ecaacbaff569c.jpg" width="376" height="250" alt=""/></a><span>&nbsp; &nbsp;&nbsp;</span><a href="images/df01a1eb96ae4ea2a1d4678c5ff58179.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_df01a1eb96ae4ea2a1d4678c5ff58179.jpg" width="376" height="250" alt=""/></a></p><p><span>&nbsp; &nbsp;&nbsp;</span></p><p><br/></p><p><span>在这里</span></p><p><span>青春与梦想将一起放飞<br/></span></p><p><span>青春与汗水将一起挥洒</span></p><p><span>青春与歌声将一起激荡</span></p><p><span><br/></span><a href="images/b4b2284cc19848d9b54bb902efbd350b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b4b2284cc19848d9b54bb902efbd350b.jpg" width="333" height="250" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/5e15210f821b4dbc836d9b72cae11de7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5e15210f821b4dbc836d9b72cae11de7.jpg" width="333" height="250" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/52079361d4b6471bb3f56d6cf01e3210.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_52079361d4b6471bb3f56d6cf01e3210.jpg" width="333" height="250" alt=""/></a></p><p><span><br/></span></p><p><span>加油吧</span></p><p><span>新新新航人</span></p><p><span>前路漫漫<br/></span></p><p><span>我们携手同行！</span></p><p><span><br/></span></p><p><a href="images/ab06b35d512646368d20b2cf4290c235.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ab06b35d512646368d20b2cf4290c235.jpg" width="400" height="300" alt=""/></a>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/2f2b1d87f8344ba7967f149547417b33.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2f2b1d87f8344ba7967f149547417b33.jpg" width="451" height="300" alt=""/></a></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/0a6a993973364f768e9badb88a6067f6.jpg', NULL, true, '2021-09-01 08:00:00+08', '2021-09-01 08:00:00+08', '2021-09-01 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 终于 你好', '');
INSERT INTO public.news VALUES (921, '56个省一等奖！新航实验学子在第二十五届全国中小学生绘画书法作品比赛中喜获佳绩', '', '由中国儿童中心主办的第二十五届全国中小学生绘画书法作品比赛于近日完成省级评审工作。经过多轮严格细致的评选，济南新航实验外国语学校参赛学生表现突出，56件作品荣获省级一等奖。 2020年10月，中共中央办公厅、国务院办公厅印发的《关于全面加强和改进新时代学校美育工作的意见》中指出，美育是审美教育、情操教育、心灵教育，也是丰富想象力和培养创新意识的教育，能提升审美素养、陶冶情操、温润心灵、激发创新创造...', '', '<p><span><span>由中国儿童中心主办的第二十五届全国中小学生绘画书法作品比赛于近日完成省级评审工作。经过多轮严格细致的评选，济南新航实验外国语学校参赛学生表现突出，</span><span>56件作品荣获省级一等奖。</span></span></p><p><span><span><a href="images/a2026c1635434372bac3d6a1a5adbc9b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a2026c1635434372bac3d6a1a5adbc9b.jpg" width="400" height="300"/></a>&nbsp;<a href="images/92a3008f02924776b0f6e33dda93373e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_92a3008f02924776b0f6e33dda93373e.jpg" width="225" height="300" alt=""/></a></span></span></p><p><span>2020年10月，中共中央办公厅、国务院办公厅印发的《关于全面加强和改进新时代学校美育工作的意见》中指出，美育是审美教育、情操教育、心灵教育，也是丰富想象力和培养创新意识的教育，能提升审美素养、陶冶情操、温润心灵、激发创新创造活力。</span></p><p><span>作为一所十二年一贯制学校，新航实验始终致力于打造美育课程体系，将美育纳入学校人才培养全过程，探索十二年一体化美育培养的实施路径，培养德智体美劳全面发展、有情有型的新航实验学子。</span></p><p><span><span>&nbsp; 全国中小学生绘画书法作品比赛创办于</span><span>1995年, 获得了教育部的肯定和支持，并被教育部列为《2020-2021学年面向中小学生开展的全国性竞赛活动名单》，是一项有着广泛影响力的青少年素质教育活动。</span></span></p><p><span><span><a href="images/39f0368bbd964f65af90f8ce4124ba85.png" target="_blank"><img title="" src="/uploads/migration/images/s_39f0368bbd964f65af90f8ce4124ba85.png" width="400" height="247"/></a></span></span></p><p><span><span>此次比赛以</span><span>“祖国繁荣昌盛”为创作方向，不仅激发了学生的民族自豪感和爱国之心、强国之愿，也开拓了学生们的艺术视野，拓宽了他们的艺术思维，提高了学生们的艺术审美水平、艺术创造力以及表现力。</span></span></p><p><span>在第二十五届龙杯全国中小学生绘画书法比赛的赛讯发布之后，我校美术组的老师们积极参与，精心打磨学生作品，并且严格把关，从小学部、大初中部、高中部三个学部分别选出高质量的书画作品参赛。最终，比赛的结果不负众望，新航实验学子们在此次比赛中成绩斐然。</span></p><p><span><a href="images/ca4c536cc1b243ed9a52fa2d70abfbf6.png" target="_blank"><img title="" src="/uploads/migration/images/s_ca4c536cc1b243ed9a52fa2d70abfbf6.png" width="314" height="1597"/></a></span></p><p><span>未来，新航实验的学子们将继续乘风而上，破浪前行！</span></p><p><span>部分优秀作品展示</span></p><p><span><a href="images/2d649031912b49da8cbdeb9dd98df4b4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2d649031912b49da8cbdeb9dd98df4b4.jpg" width="345" height="240" alt=""/></a>&nbsp;<a href="images/8622932c7efb467894127d3eb5c6521e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8622932c7efb467894127d3eb5c6521e.jpg" width="353" height="240" alt=""/></a>&nbsp;<a href="images/96a274a3da7b4206b4d2956a97188357.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_96a274a3da7b4206b4d2956a97188357.jpg" width="361" height="240" alt=""/></a></span></p><p><span><a href="images/2b660a6954e048879d3d9e954205bbb1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2b660a6954e048879d3d9e954205bbb1.jpg" width="357" height="240" alt=""/></a>&nbsp;<a href="images/da0d205bbc1d493a9bc7fafaf7d984c5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_da0d205bbc1d493a9bc7fafaf7d984c5.jpg" width="340" height="240" alt=""/></a>&nbsp;<a href="images/7a1ab73fe9984b46864ad1c16da1495c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7a1ab73fe9984b46864ad1c16da1495c.jpg" width="320" height="240" alt=""/></a></span></p><p><span><img title="" src="/uploads/migration/images/s_c9627f69d5c444bb877982d3506451db.jpg" width="143" height="500" alt=""/><a href="images/9743197760d7494787a0c3cd2bf83aaf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9743197760d7494787a0c3cd2bf83aaf.jpg" width="333" height="500" alt=""/></a><a href="images/4edde338f0ba4d2d9d1be00014fea7cf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4edde338f0ba4d2d9d1be00014fea7cf.jpg" width="238" height="500" alt=""/>&nbsp;</a><a href="images/5c719fff300d47029c87b8f62db6d242.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5c719fff300d47029c87b8f62db6d242.jpg" width="379" height="500" alt=""/></a></span></p><p><span><a href="images/9743197760d7494787a0c3cd2bf83aaf.jpg" target="_blank"></a><a href="images/4edde338f0ba4d2d9d1be00014fea7cf.jpg" target="_blank"></a><a href="images/f0a89e57d6ef43c0a0df6714cd8af656.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f0a89e57d6ef43c0a0df6714cd8af656.jpg" width="362" height="470" alt=""/></a>&nbsp;<a href="images/7ed42b7104504f79bbf2a0761aa909c3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7ed42b7104504f79bbf2a0761aa909c3.jpg" width="348" height="470" alt=""/></a>&nbsp;</span><img title="" src="/uploads/migration/images/s_fd45502f372042c7b40ac8d5cfb803ae.jpg" width="313" height="470" alt=""/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/a2026c1635434372bac3d6a1a5adbc9b.jpg', NULL, true, '2021-07-14 08:00:00+08', '2021-07-14 08:00:00+08', '2021-07-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '全国 书法 中小学生 绘画 学子', '');
INSERT INTO public.news VALUES (922, '知行合一，“遇见”未来的自己——新航实验融合班Career Day职业体验日', '', '7月9日，济南新航实验外国语学校融合班组织开展职业体验日，同学们分别参观了国家超级计算济南中心、山东省科学院、中国银行和齐鲁晚报，大家身临其境，体验了一次精彩的职场生活。超算能力，国之重器丨国家超级计算济南中心     在济南超算中心，同学们近距离感受到了技术力量的震撼和国家实力的彰显，作为世界各国竞相角逐的科技制高点，超算充分展示出国家的创新力量和科技力量。在这里，大家亲眼见到了千万亿次超级计算...', '', '<p><span>7月9日，济南新航实验外国语学校融合班组织开展职业体验日，同学们分别参观了国家超级计算济南中心、山东省科学院、中国银行和齐鲁晚报，大家身临其境，体验了一次精彩的职场生活。</span></p><p><span><strong><span>超算能力，国之重器丨国家超级计算济南中心</span></strong></span></p><p>&nbsp;<a href="images/40eb7d1b30e841c0aaa03d0371ced764.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_40eb7d1b30e841c0aaa03d0371ced764.jpg" width="400" height="300"/></a>&nbsp; &nbsp;&nbsp;<a href="images/624d34c139e84f6293728407f7e96ea9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_624d34c139e84f6293728407f7e96ea9.jpg" width="400" height="300"/></a></p><p><span>在济南超算中心，同学们近距离感受到了技术力量的震撼和国家实力的彰显，作为世界各国竞相角逐的科技制高点，超算充分展示出国家的创新力量和科技力量。在这里，大家亲眼见到了千万亿次超级计算机，了解了其在天气预报、医疗、交通、军事、环保、机械等领域的广泛运用，同学们纷纷构画超算加持的未来世界。</span></p><p><span><strong><span>科研的种子开始萌发丨山东省科学院生物研究所</span></strong></span></p><p><span><span><a href="images/1e2538aa0f424da5ab197bdf5a58a860.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1e2538aa0f424da5ab197bdf5a58a860.jpg" width="400" height="300"/></a>&nbsp;<a href="images/f8429a675f9c40e9bd8d14bb5c4f63da.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f8429a675f9c40e9bd8d14bb5c4f63da.jpg" width="400" height="300"/></a></span></span></p><p><span><span>在张云研究员和赵佩佩研究员的带领下，学生们参观了山东省科学院生物研究所的抗生素提取、食品药品研究、毒理和药理研究等多个实验室。张云研究员耐心细致地向同学们介绍了实验室重点科研项目的主角</span><span>——斑马鱼。荧光显微镜下马斑鱼的血液流动和心脏跳动情况以及马斑鱼能够进行药物活性筛选及药物作用机制研究的独特特点，生动形象地向同学们展示了科研人员为了实现特定研究目的所采用的多样的分析手段。最后，张云研究员表示，非常欢迎同学们到她的实验室进行相关研究或者验证自己的想法。</span></span></p><p><strong><span>探寻金融业的神秘密码丨中国银行</span></strong></p><p><span><span><a href="images/1df9c2caa7e14889b6ef766980e94a4a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1df9c2caa7e14889b6ef766980e94a4a.jpg" width="400" height="300"/>&nbsp; </a><a href="images/76d05ca67c8a40a39b745b4d432104a1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_76d05ca67c8a40a39b745b4d432104a1.jpg" width="444" height="300" alt=""/></a></span></span></p><p><span><span>近距离参观银行一直是金融方向学生们最向往的事情。在中国银行职业体验行程中，同学们对岗位分工、银行功能分区、智能科技、设备构成和留学金融知识等都有了更加深入的了解。其中，最让大家兴奋的就是</span><span>“大咖讲座”，由中行营业部专家带来关于2021年经济金融展望及汇率走势的分析讲解。干货满满的讲座加深了同学们对于金融学的了解，对校内经济课堂上学到的货币政策也有了更加直观的体会。</span></span></p><p><strong><span>全媒体时代下的探索丨齐鲁晚报</span></strong></p><p><span><a href="images/cf6aa7b9eeac454ca2caea3848495060.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_cf6aa7b9eeac454ca2caea3848495060.jpeg" width="400" height="266"/></a>&nbsp;<a href="images/4a5a1f88b16b41e5b6b9e55d131968e6.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_4a5a1f88b16b41e5b6b9e55d131968e6.jpeg" width="400" height="266"/></a></span></p><p><span>在大众传媒大厦，同学们先后参观了齐鲁晚报和新媒体平台齐鲁壹点。新闻的制作、话题的收录和发布、新闻背后的例会以及热点新闻的抓取等都让大家感到新奇和惊喜。</span></p><p><span>如何以最快的速度获取热点是同学们最感兴趣的事情。工作人员给大家展示了一张地图，上面标记着每个记者的实时位置，一旦有新闻点出现，就可以派最近的记者前往，获得一手资讯。</span></p><p><span><span>在齐鲁壹点，工作人员向同学们介绍，在这个平台上每个人都可以成为新闻的通讯员，发布自己关心的话题、与其他用户互动。就在此时，屏幕上连续弹出了</span><span>“大明湖的并蒂莲”，原来是通讯员们发现大明湖里长出了一支并蒂莲，纷纷拍下这个景色并上传到了平台，齐鲁晚报编辑部也派记者前往进行了直播。</span></span></p><p><span>&nbsp; 这次的职业体验日，既拓宽了学生的视野，也让他们对未来的升学方向有了更准确的定位和认识，找准方向后，相信大家在接下来的学习生活中一定会更加努力，朝着自己的理想职业努力前行。</span></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/40eb7d1b30e841c0aaa03d0371ced764.jpg', NULL, true, '2021-07-14 08:00:00+08', '2021-07-14 08:00:00+08', '2021-07-14 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 未来 实验 融合 遇见', '');
INSERT INTO public.news VALUES (947, '不负青春 “犇”向未来——济南新航实验外国语学校举行2020-2021学年度第二学期开学典礼', '', '3月1日下午，伴着雪后带来的清新，济南新航实验外国语学校隆重举行2020-2021学年度第二学期开学典礼，全体师生及家长代表齐聚体育馆共同迎接新学期的到来。    嘹亮的国歌声响起，开学典礼正式拉开帷幕。全场庄严肃立，高声合唱，激荡人心的旋律响彻整个体育馆。新的学期，新航实验师生一定会不忘初心、牢记使命，坚定地迈向新目标和新高地。在过去的一年里，新航实验师生勠力同心，谱写了学校发展新篇章。学生们在...', '', '<p><span>3月1日下午，伴着雪后带来的清新，济南新航实验外国语学校隆重举行2020-2021学年度第二学期开学典礼，全体师生及家长代表齐聚体育馆共同迎接新学期的到来。</span></p><p><span><a href="images/e11491b9245b49d6b1f8ae5e639e7661.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e11491b9245b49d6b1f8ae5e639e7661.jpg" width="400" height="226"/></a>&nbsp;<a href="images/6ccfc79bf1824340b764f9078c0b2197.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6ccfc79bf1824340b764f9078c0b2197.jpg" width="400" height="225"/></a></span></p><p><span>&nbsp;&nbsp; </span><span>嘹亮的国歌声响起，开学典礼正式拉开帷幕。全场庄严肃立，高声合唱，激荡人心的旋律响彻整个体育馆。新的学期，新航实验师生一定会不忘初心、牢记使命，坚定地迈向新目标和新高地。</span></p><p><span><a href="images/2573ad2a95a543369a21bb2ab5f70640.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2573ad2a95a543369a21bb2ab5f70640.jpg" width="400" height="266"/></a></span></p><p><span>在过去的一年里，新航实验师生勠力同心，谱写了学校发展新篇章。学生们在艺、体、学科、科技等比赛中捷报频传，充分展现了新航学子的高素养；老师们也在省、市比赛及专业评比中接连取得优异成绩，全面展示了过硬的专业水平，为此，本次开学典礼也对优秀学生和教职工提出表彰。</span></p><p><span>刘子依、陈钰璐、杜怡萱、洪一鸣、刘天佑、刘思辰、赵玥婷、贺雅雯、丰天润等36名同学进步较大，获得新航实验“日新奖”；杨淅月、匡志瑜、于东俊、闫格、徐晨曦、尹琦淇、王启源、马海钦、徐砻宸、于家豪等48名同学成绩优异，获得新航实验“博学奖”；郑景元、兰宇轩、李弘俊、纪开来、单怀宇等11名同学在各项比赛中表现突出，获得新航实验“志航奖”；初一一班、初一三班、初一五班、初一六班、初二二班、初二三班、高一一班、高一二班、高二二班、高二五班班级成绩优异，获得新航实验“同舟奖”。</span></p><p><span><a href="images/f7952b3d834e48f48103a80fd8c2146f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f7952b3d834e48f48103a80fd8c2146f.jpg" width="355" height="200" alt=""/></a>&nbsp;<a href="images/7440d1b871504ccfa80bd8cb11739ea6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7440d1b871504ccfa80bd8cb11739ea6.jpg" width="355" height="200" alt=""/></a>&nbsp;<a href="images/511cf20bf7954c0682468eee7a1845f4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_511cf20bf7954c0682468eee7a1845f4.jpg" width="355" height="200" alt=""/></a></span></p><p><a href="images/f40e502227b74479b4f9a75b3ec93560.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f40e502227b74479b4f9a75b3ec93560.jpg" width="309" height="210" alt=""/></a>&nbsp; &nbsp;&nbsp;&nbsp;<a href="images/a15a45a4b6504d60bcf7c9c3b8cf7243.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a15a45a4b6504d60bcf7c9c3b8cf7243.jpg" width="316" height="210" alt=""/></a>&nbsp; &nbsp; &nbsp;&nbsp;&nbsp;<a href="images/7a7caaa210f04f58b6aab26a7acbd755.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7a7caaa210f04f58b6aab26a7acbd755.jpg" width="316" height="210" alt=""/></a></p><p><a href="images/96cc7ef04c014702b364e34eb8cac780.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_96cc7ef04c014702b364e34eb8cac780.jpg" width="316" height="210" alt=""/></a>&nbsp; &nbsp; &nbsp;&nbsp;<a href="images/3cb161807ee444ffb1c50a52fb89ae1d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3cb161807ee444ffb1c50a52fb89ae1d.jpg" width="316" height="210" alt=""/></a>&nbsp; &nbsp; &nbsp;<a href="images/d1b061ce933148c99ac46742f202218b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d1b061ce933148c99ac46742f202218b.jpg" width="316" height="210" alt=""/></a></p><p><a href="images/86b5814ef95544479bc989a71828fc8c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_86b5814ef95544479bc989a71828fc8c.jpg" width="316" height="210" alt=""/></a>&nbsp; &nbsp;&nbsp;&nbsp;<a href="images/465932c24be7488586a431d9b004dea5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_465932c24be7488586a431d9b004dea5.jpg" width="316" height="210" alt=""/></a>&nbsp; &nbsp; &nbsp;&nbsp;<a href="images/9d0542a19c3f4c1599ba7789ff4ae0d4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9d0542a19c3f4c1599ba7789ff4ae0d4.jpg" width="316" height="210" alt=""/></a></p><p><span>学生成长的背后离不开老师的默默耕耘，离不开学校教职工的悉心守护。2020年新航实验涌现出一大批爱生如子、爱岗敬业的优秀员工，他们心系教育、扎根新航，他们不计得失、冲在一线，学生成才是他们的毕生追求，陪伴新航实验成长壮大是他们的奋斗目标，他们被评为新航实验第二届“十大优秀员工”——祁文焕、李夏萌、刘晓冉、胡小会、牛众、张素芹、管煜程、纪晓萌、周倩、张鹏，同时，外教Declan Francis Roche被评为“最美外教”。</span></p><p><span><a href="images/35d7a74190a14187a7b58dbb724e79df.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_35d7a74190a14187a7b58dbb724e79df.jpg" width="400" height="266"/></a></span></p><p><span>接下来，学生代表张苏雅和谷超然以《新语心愿 梦想起航》为题做了精彩的发言，新航实验学子从来不怕未知和挑战，新学期我们定会乘风破浪、扬帆远航，敢于担当、严格自律，争做有识、有礼、有情、有型的新航少年。</span></p><p><span><a href="images/040ce0746e344ff1abc55620d3094c31.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_040ce0746e344ff1abc55620d3094c31.jpg" width="267" height="400" alt=""/></a></span></p><p><span>“谁持彩练当空舞，且看今朝新航人。”教师代表张素芹老师在新学期伊始鼓励同学们带上理想和目标、自信和坚强、勤奋和努力，坚定“天生我材必有用”的信心，拿出“吹尽黄沙始见金”的毅力，鼓足“直挂云帆济沧海”的勇气，扬起风帆，带着阳光和力量开启新的学习征程。</span></p><p><span><a href="images/75f7618327ff4f83b09190398e8480d6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_75f7618327ff4f83b09190398e8480d6.jpg" width="400" height="266"/></a></span></p><p><span>家长代表高原受邀出席开学典礼，他说，“有一种幸福叫感同身受，有一种培养叫新航实验，有一种爱叫师者父母。”家长们一定会在思想、行动上时刻与学校理念保持一致，做孩子教育的给力参与者和坚强的后盾。</span></p><p><span><a href="images/f01f51e0c4c74df5950efe0dcdb099fd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f01f51e0c4c74df5950efe0dcdb099fd.jpg" width="400" height="266"/></a></span></p><p><span>之后，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊校长向全体同学表达了祝愿并提出希望，希望新航实验学子具有德才兼备、家国情怀的品行，抬头看路、埋头读书的精神和海纳百川、胸怀世界的情怀，做一个能经历风雨、心中有榜样、直得起脊梁的新航实验学子，努力涵养大情怀，逐梦世界大舞台，将新航实验学子独特与坚定的面貌展现在世人面前。</span></p><p><span><a href="images/04033813423e4b559a5ed941b4444d6b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_04033813423e4b559a5ed941b4444d6b.jpg" width="400" height="600"/></a></span></p><p><span>&nbsp; 随着开学典礼落下帷幕，新航实验正式踏上新征程，我们会继续坚定心中梦想，脚踏实地，攻坚克难。创造奇迹，我们一直都在！</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/e11491b9245b49d6b1f8ae5e639e7661.jpg', NULL, true, '2021-03-02 08:00:00+08', '2021-03-02 08:00:00+08', '2021-03-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '实验 举行 学校 外国语 年度', '');
INSERT INTO public.news VALUES (923, '卢宝镇', '', '  槐荫区初中物理课件评比一等奖  2013-2014学年槐荫区初中教学工作先进个人  槐荫区第十四届“走青春路，做育人花”主题教育活动一等奖  槐荫区初中物理学科中心组成员  槐荫区初中物理优秀教学设计评比一等奖  2017年度全国初中应用物理竞赛山东省优秀指导教师  槐荫区初中物理实验优质课评比一等奖  2020年一师一优课济南市一等奖  槐荫区初中教师素质大赛一等奖  槐荫区初中物理实验优质...', '', '<p><a href="images/1e4b8245a13d4ce4a4eb34573fa86d7b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1e4b8245a13d4ce4a4eb34573fa86d7b.jpg" width="300" height="436"/></a></p><p><span>&nbsp; 槐荫区初中物理课件评比一等奖</span></p><p><span>&nbsp; 2013-2014学年槐荫区初中教学工作先进个人</span></p><p><span>&nbsp; 槐荫区第十四届“走青春路，做育人花”主题教育活动一等奖</span></p><p><span>&nbsp; 槐荫区初中物理学科中心组成员</span></p><p><span>&nbsp; 槐荫区初中物理优秀教学设计评比一等奖</span></p><p><span>&nbsp; 2017年度全国初中应用物理竞赛山东省优秀指导教师</span></p><p><span>&nbsp; 槐荫区初中物理实验优质课评比一等奖</span></p><p><span>&nbsp; 2020年一师一优课济南市一等奖</span></p><p><span>&nbsp; 槐荫区初中教师素质大赛一等奖</span></p><p><span>&nbsp; 槐荫区初中物理实验优质课评比一等奖</span></p><p><span><br/></span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/1e4b8245a13d4ce4a4eb34573fa86d7b.jpg', NULL, true, '2021-07-03 17:25:00+08', '2021-07-03 17:25:00+08', '2021-07-03 17:25:00+08', '赵昕晨', '新航实验外国语学校', '卢宝镇', '270595');
INSERT INTO public.news VALUES (924, '盛燕', '', '  济南市中学数学优质课评比济南市优质课一等奖  第十一届“走青春路，做育花人“主题活动二等奖   槐荫区“探索版”自主合作课堂说课评比一等奖  2010年度槐荫区教育系统优秀共产党员  2018年全国初中数学联合竞赛山东省优秀教练员  2017年全国初中数学联合竞赛山东省优秀教练员  2016年初中数学“一师一优课，一课一名师”', '', '<p><a href="images/cfb7ace0ab3a4bb18225dd1b860a24a3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cfb7ace0ab3a4bb18225dd1b860a24a3.jpg" width="300" height="436"/></a></p><p><span>&nbsp; 济南市中学数学优质课评比济南市优质课一等奖</span></p><p><span>&nbsp; 第十一届“走青春路，做育花人“主题活动二等奖&nbsp;</span></p><p><span>&nbsp; 槐荫区“探索版”自主合作课堂说课评比一等奖</span></p><p><span>&nbsp; 2010年度槐荫区教育系统优秀共产党员</span></p><p><span>&nbsp; 2018年全国初中数学联合竞赛山东省优秀教练员</span></p><p><span>&nbsp; 2017年全国初中数学联合竞赛山东省优秀教练员</span></p><p><span>&nbsp; 2016年初中数学“一师一优课，一课一名师”</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/cfb7ace0ab3a4bb18225dd1b860a24a3.jpg', NULL, true, '2021-07-03 17:18:00+08', '2021-07-03 17:18:00+08', '2021-07-03 17:18:00+08', '赵昕晨', '新航实验外国语学校', '盛燕', '270593');
INSERT INTO public.news VALUES (925, '狄莉', '', '      槐荫区中小学生语文能力素质大赛指导一等奖  济南市第七届中小学优秀教育案例评选一等奖  山东省中小学教育科研优秀成果二等奖  连续三年全国青少年冰心文学辅导教师一等奖  曾指导学生作品选登在《冰心少年文学》“写作园地”栏目', '', '<p><span>&nbsp;&nbsp;<a href="images/e47f81d5c5bf4956a02ff108f4f6239f.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_e47f81d5c5bf4956a02ff108f4f6239f.jpeg" width="356" height="540"/></a></span></p><p><span>&nbsp;&nbsp;</span></p><p><span>&nbsp; 槐荫区中小学生语文能力素质大赛指导一等奖</span></p><p><span>&nbsp; 济南市第七届中小学优秀教育案例评选一等奖</span></p><p><span>&nbsp; 山东省中小学教育科研优秀成果二等奖</span></p><p><span>&nbsp; 连续三年全国青少年冰心文学辅导教师一等奖</span></p><p><span>&nbsp; 曾指导学生作品选登在《冰心少年文学》“写作园地”栏目</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/e47f81d5c5bf4956a02ff108f4f6239f.jpeg', NULL, true, '2021-07-03 17:15:00+08', '2021-07-03 17:15:00+08', '2021-07-03 17:15:00+08', '赵昕晨', '新航实验外国语学校', '狄莉', '270592');
INSERT INTO public.news VALUES (926, '王亚超', '', ' 王亚超，语文中级教师，济南市“一师一优课” 一等奖，山东省中小学师资培训中心评为优秀学员（省级）', '', '<p><span><a href="images/923f17b4073a4d87b07eb66a702c2799.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_923f17b4073a4d87b07eb66a702c2799.jpg" width="295" height="413"/></a></span></p><p><span>&nbsp;<span>王亚超，语文中级教师，济南市“一师一优课” 一等奖，</span>山东省中小学师资培训中心评为优秀学员（省级）</span></p><p><span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/923f17b4073a4d87b07eb66a702c2799.jpg', NULL, true, '2021-07-03 17:12:00+08', '2021-07-03 17:12:00+08', '2021-07-03 17:12:00+08', '赵昕晨', '新航实验外国语学校', '王亚超', '270591');
INSERT INTO public.news VALUES (927, '张婉', '', '张婉，市中区优秀班主任，中国小学德育研究分会班主任工作学术委员会论文评审一等奖，中国教育学会中小学德育研究分会班主任工作学术委员会班会设计方案评比二等奖，山东省中小学教师全员远程研修优秀研修组长、优秀学员，济南市教育科学研究所心理教育案例评选二等奖，市中区“我的教学故事”讲述活动一等奖', '', '<p><span><span><a href="images/412e460109a74bb9ab59a18811ac5965.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_412e460109a74bb9ab59a18811ac5965.jpg" width="300" height="436"/></a></span></span></p><p><span><span>张婉，</span><span>市中区优秀班主任，中国小学德育研究分会班主任工作学术委员会论文评审一等奖，</span>中国教育学会中小学德育研究分会班主任工作学术委员会班会设计方案评比二等奖，山东省中小学教师全员远程研修优秀研修组长、优秀学员，济南市教育科学研究所心理教育案例评选二等奖，市中区“我的教学故事”讲述活动一等奖</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/412e460109a74bb9ab59a18811ac5965.jpg', NULL, true, '2021-07-03 17:10:00+08', '2021-07-03 17:10:00+08', '2021-07-03 17:10:00+08', '赵昕晨', '新航实验外国语学校', '张婉', '270590');
INSERT INTO public.news VALUES (928, '孔祥慧', '', '孔祥慧，语文高级教师，县青年学术带头人，市小学语文学科中心组成员，市小学语文优质课评比一等奖，省优课、市“一师一优课”一等奖，参与省级课题、主持市级课题结题，省教科研优秀成果一等奖，市论文评比一等奖', '', '<p><a href="images/91413e970b4841528d9dd2a237a09668.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_91413e970b4841528d9dd2a237a09668.jpg" width="300" height="436"/></a></p><p><span>孔祥慧，语文高级教师，县青年学术带头人，市小学语文学科中心组成员，市小学语文优质课评比一等奖，省优课、市“一师一优课”一等奖，参与省级课题、主持市级课题结题，省教科研优秀成果一等奖，市论文评比一等奖</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/91413e970b4841528d9dd2a237a09668.jpg', NULL, true, '2021-07-03 17:07:00+08', '2021-07-03 17:07:00+08', '2021-07-03 17:07:00+08', '赵昕晨', '新航实验外国语学校', '孔祥慧', '270589');
INSERT INTO public.news VALUES (929, '王莹', '', '    山东省教育学会先进工作者  济南市优秀班主任  市中区优秀教师  市中区首席班主任  市中区“师德建设先进个人”  市中区“教书育人先进个人”  市中区英语学科带头人  市中区优质课评比一等奖', '', '<p><span>&nbsp;<a href="images/2d4c89fa61fb4afcb3d8c123051fbbcd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2d4c89fa61fb4afcb3d8c123051fbbcd.jpg" width="400" height="571"/></a>&nbsp;</span></p><p><span>&nbsp; 山东省教育学会先进工作者</span></p><p><span>&nbsp; 济南市优秀班主任</span></p><p><span>&nbsp; 市中区优秀教师</span></p><p><span>&nbsp; 市中区首席班主任</span></p><p><span>&nbsp; 市中区“师德建设先进个人”</span></p><p><span>&nbsp; 市中区“教书育人先进个人”</span></p><p><span>&nbsp; 市中区英语学科带头人</span></p><p><span>&nbsp; 市中区优质课评比一等奖</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/2d4c89fa61fb4afcb3d8c123051fbbcd.jpg', NULL, true, '2021-07-03 17:06:00+08', '2021-07-03 17:06:00+08', '2021-07-03 17:06:00+08', '赵昕晨', '新航实验外国语学校', '王莹', '270588');
INSERT INTO public.news VALUES (930, '李夏萌', '', '  2009年省优秀论文一等奖  2011年区教学能手  2013年省教学研究优秀成果一等奖  2014年市优质课一等奖  2014年省优质课程资源一等奖  2015年市一师一优课一等奖  2015年市微课一等奖  2016年省教育科学规划课题结题  2017年区第三批名师  2019年区教学能手', '', '<p><a href="images/73f37b1ae5744fc596f0b82873c5af7b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_73f37b1ae5744fc596f0b82873c5af7b.jpg" width="400" height="570"/></a></p><p><span>&nbsp; 2009年省优秀论文一等奖</span></p><p><span>&nbsp; 2011年区教学能手</span></p><p><span>&nbsp; 2013年省教学研究优秀成果一等奖</span></p><p><span>&nbsp; 2014年市优质课一等奖</span></p><p><span>&nbsp; 2014年省优质课程资源一等奖</span></p><p><span>&nbsp; 2015年市一师一优课一等奖</span></p><p><span>&nbsp; 2015年市微课一等奖</span></p><p><span>&nbsp; 2016年省教育科学规划课题结题</span></p><p><span>&nbsp; 2017年区第三批名师</span></p><p><span>&nbsp; 2019年区教学能手</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/73f37b1ae5744fc596f0b82873c5af7b.jpg', NULL, true, '2021-07-03 17:03:00+08', '2021-07-03 17:03:00+08', '2021-07-03 17:03:00+08', '赵昕晨', '新航实验外国语学校', '李夏', '270586');
INSERT INTO public.news VALUES (931, '济南新航实验外国语学校2021年高中部自主招生重要通知', '', '温馨提示根据《济南新航实验外国语学校2021年高中部自主招生方案》，参与我校7月2日普通班招生校测的考生可于7月3日14:00起，登录济南新航实验外国语学校官方网站（/）进行成绩查询，并关注7月4日上午8:30—12:00到校现场面试核对的通知。同时，也欢迎济南市学业水平考试总成绩在435分以上的考生及家长携带考生身份证、中考准考证以及中考成绩单于7月4日上午8:30—12:00到济南新航实验外国...', '', '<section><section><section><section><section><p><span><strong><span>温馨提示</span></strong></span></p></section></section></section><section><section><section><section><section></section></section></section></section></section><section><section></section></section></section></section><p><a href="images/5cefa4def89a4e44883d251497eca856.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5cefa4def89a4e44883d251497eca856.jpg" width="500" height="280" alt=""/></a></p><section><section><p><span><br/></span></p><p><span>根据《济南新航实验外国语学校2021年高中部自主招生方案》，参与我校7月2日普通班招生校测的考生可于7月3日14:00起，登录济南新航实验外国语学校官方网站（/）进行成绩查询，并关注7月4日上午8:30—12:00到校现场面试核对的通知。</span></p><p><span>同时，也欢迎济南市学业水平考试总成绩在435分以上的考生及家长携带考生身份证、中考准考证以及中考成绩单于7月4日上午8:30—12:00到济南新航实验外国语学校图书馆进行现场咨询。</span></p></section></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/5cefa4def89a4e44883d251497eca856.jpg', NULL, true, '2021-07-03 08:00:00+08', '2021-07-03 08:00:00+08', '2021-07-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '高中部 学校 自主 外国语 实验', '');
INSERT INTO public.news VALUES (932, '精准把脉，助力提升——济南市教研院专家莅临新航实验调研视导', '', '6月2日，来自济南市教育教学研究院语文、数学、英语、物理、化学、生物、地理、政治、历史、美术、音乐、心理、研学、信息等十余个学科的教研员，在院长助理田序海的带领下，莅临济南新航实验外国语学校深入教学一线，全面调研教学工作。山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊以及副校长张爱梅、教学综合管理部主任王飞，带领相关教学部门负责人陪同调研督导。林宝磊校长首先以《运用“根”技术，进行个...', '', '<section><section><p>6月2日，来自济南市教育教学研究院语文、数学、英语、物理、化学、生物、地理、政治、历史、美术、音乐、心理、研学、信息等十余个学科的教研员，在院长助理田序海的带领下，莅临济南新航实验外国语学校深入教学一线，全面调研教学工作。山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊以及副校长张爱梅、教学综合管理部主任王飞，带领相关教学部门负责人陪同调研督导。</p><p><a href="images/e20e13bf0b634b6abd4533935ea4a2bc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e20e13bf0b634b6abd4533935ea4a2bc.jpg" width="400" height="266"/></a></p></section></section><p><br/></p><section><section><p>林宝磊校长首先以《运用“根”技术，进行个性化培养，实现个体化成长》为主题，详细介绍了新航实验的教育理念、培养目标、办学特色、课程设置、教师队伍建设、培养模式等，同时针对学校取得的教学成果、组织的特色活动等进行了汇报。</p><p>田序海充分肯定了新航实验专业的教学模式和一流的师资水准，同时指出，随着新高考的深入推进，对高中学校和老师也提出了更高的要求，要把教学工作做精做深做实，为学生的升学提供坚实保障。</p></section></section><section><section><section><section><section><p><a href="images/720e5e959d574da58282c2d8b9ab892a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_720e5e959d574da58282c2d8b9ab892a.jpg" width="300" height="169" alt=""/></a>&nbsp;&nbsp;<a href="images/c63b5a7a805245c8982948a272786c7a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c63b5a7a805245c8982948a272786c7a.jpg" width="300" height="169" alt=""/></a>&nbsp;&nbsp;<a href="images/f29ee69af8de462c92f762368abf32c2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f29ee69af8de462c92f762368abf32c2.jpg" width="300" height="169" alt=""/></a></p></section></section></section></section></section><section><section><p>在听取了学校情况汇报后，各科教研员老师分别走进班级，现场听课，实地感受课堂氛围和学生的学习环境，深入一线调研教学情况，为教学工作“现场把脉问诊”。</p></section></section><section><section><section><section><p><a href="images/4f38ba3e67c348f4b6b9b41fdd6bf9a9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4f38ba3e67c348f4b6b9b41fdd6bf9a9.jpg" width="300" height="168"/></a>&nbsp;&nbsp;<a href="images/f06e0e66efc04319a3e70a5aef6d38e6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f06e0e66efc04319a3e70a5aef6d38e6.jpg" width="300" height="168"/></a>&nbsp;&nbsp;<a href="images/feae5608afc143b5abf9f90ffd526a29.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_feae5608afc143b5abf9f90ffd526a29.jpg" width="300" height="168"/></a></p><p><a href="images/025f51688c374036bd54173840dbf131.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_025f51688c374036bd54173840dbf131.jpg" width="300" height="168"/></a>&nbsp;&nbsp;<a href="images/02a55caa94674d29b70a7ae31d8cbe21.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_02a55caa94674d29b70a7ae31d8cbe21.jpg" width="300" height="149" alt=""/></a>&nbsp;&nbsp;<a href="images/6d11c995f7ef4f649f9009c2b38df8a4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6d11c995f7ef4f649f9009c2b38df8a4.jpg" width="300" height="168"/></a></p></section></section></section></section><section><section><p>新航实验各学科老师们也都积极跟听，把握与教研员面对面交流和提升自我的机会。听课结束后，教研员们来到各学科办公室，深入了解各学科组的教学规划，详细解答老师们在工作中遇到的困惑和问题，为教育教学工作指明方向、答疑解惑。</p></section></section><section><section><section><section><p><a href="images/651648d08efb42659eed691be662383c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_651648d08efb42659eed691be662383c.jpg" width="260" height="195" alt=""/></a>&nbsp;&nbsp;<a href="images/61b23fd8a0114eddbd454ef833b353e3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_61b23fd8a0114eddbd454ef833b353e3.jpg" width="260" height="195" alt=""/></a>&nbsp;&nbsp;<a href="images/c426d0a1ab3f490990f8de95bec89713.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c426d0a1ab3f490990f8de95bec89713.jpg" width="260" height="195" alt=""/></a>&nbsp;&nbsp;<a href="images/d45bdda7e44c442698f161b60f0a157f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d45bdda7e44c442698f161b60f0a157f.jpg" width="260" height="161" alt=""/></a></p><p><a href="images/0a8dc4c6af0d4a07a997b8b19d9fe89f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0a8dc4c6af0d4a07a997b8b19d9fe89f.jpg" width="260" height="173" alt=""/></a>&nbsp;&nbsp;<a href="images/a8f9163248cd4fdbabef648ae80d2819.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a8f9163248cd4fdbabef648ae80d2819.jpg" width="260" height="173" alt=""/></a>&nbsp;&nbsp;<a href="images/ce742bd280b747bfb643ae2259b989c0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ce742bd280b747bfb643ae2259b989c0.jpg" width="260" height="146" alt=""/></a>&nbsp;&nbsp;<a href="images/616e7c16a50745a9b60f43ae08d047a6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_616e7c16a50745a9b60f43ae08d047a6.jpg" width="268" height="150" alt=""/></a></p></section></section></section></section><section><section><p>活动最后，步东军主任代表各学科专家对调研情况进行了集中反馈，为学校持续推进精准教学和个性化培养指明了方向。田序海对本次调研活动进行了总结，并为学校下一步的课程建设和教学创新给出了专业指导。</p><p>林宝磊校长代表学校感谢济南市教研院专家一直以来对新航实验的支持和帮助，为新航实验的教育教学带来提升。新航实验将继续深挖高品质、高质量的教学特色，力争成为济南市基础教育领域的一张亮丽名片。</p></section></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'research', '/uploads/migration/images/e20e13bf0b634b6abd4533935ea4a2bc.jpg', NULL, true, '2021-07-03 08:00:00+08', '2021-07-03 08:00:00+08', '2021-07-03 08:00:00+08', '赵昕晨', '新航实验外国语学校', '专家 教研 莅临 新航 济南市', '');
INSERT INTO public.news VALUES (933, '杜菲菲', '', '中学一级教师 2010年12月，德城区“师德杯”初中语文青年教师基本功大赛荣获一等奖；2012年2月，撰写的论文《点亮学生的书香之路》在德城区教育教学论文评选中荣获二等奖；2012年4月，课件《背影》在2012年德州市基础教育多媒体课件评选中荣获三等奖；2013年4月，被共青团德城区委授予“优秀团员”荣誉称号；2013年12月，德州市初中语文教师教学基本功比赛荣获三等奖；2013年12月，德城区青...', '', '<p><span><a href="images/fb413f0b53f1479492b95b36b143e458.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fb413f0b53f1479492b95b36b143e458.jpg" width="400" height="571"/></a></span></p><p><span>中学一级教师&nbsp;</span></p><p><span>2010年12月，德城区“师德杯”初中语文青年教师基本功大赛荣获一等奖；</span></p><p><span>2012年2月，撰写的论文《点亮学生的书香之路》在德城区教育教学论文评选中荣获二等奖；</span></p><p><span>2012年4月，课件《背影》在2012年德州市基础教育多媒体课件评选中荣获三等奖；</span></p><p><span>2013年4月，被共青团德城区委授予“优秀团员”荣誉称号；</span></p><p><span>2013年12月，德州市初中语文教师教学基本功比赛荣获三等奖；</span></p><p><span>2013年12月，德城区青年教师高效课堂限时备课大赛荣获三等奖；</span></p><p><span>2015年10月，执教《湖心亭看雪》一课在2015年德城区信息技术与教学融合优质课评选中荣获二等奖；</span></p><p><span>2016年10月，执教《祖国啊，我亲爱的祖国》一课在德城区初中语文优质课评选活动中荣获一等奖；</span></p><p><span>2018年11月，撰写的论文《浅谈初中语文教学中传统文化的渗透》在中国教育学会开展的全国教育教学优秀论文、教案评选中，荣获“全国教育教学成果”一等奖；</span></p><p><span>2020年1月，德城区青年教师基本功大赛荣获一等奖。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/fb413f0b53f1479492b95b36b143e458.jpg', NULL, true, '2021-07-03 01:29:00+08', '2021-07-03 01:29:00+08', '2021-07-03 01:29:00+08', '赵昕晨', '新航实验外国语学校', '杜菲菲', '270571');
INSERT INTO public.news VALUES (948, '有一种给力叫“家校共育”——新航实验召开2021年第一次校家委会会议', '', '为让家长更深入了解学校工作，提升家校共育成效，2月28日，济南新航实验外国语学校召开校家委会2021年第一次工作会议，小学部、初中部、高中普通班、高中融合班全体校家委会成员出席会议，围绕学校新学期工作安排、创新性活动等方面进行了深入探讨。会议伊始，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊校长首先向家委会成员们解读了学校新学期工作计划。2020年，新航实验在师资调整、课程升级、校...', '', '<p><span>为让家长更深入了解学校工作，提升家校共育成效，2月28日，济南新航实验外国语学校召开校家委会2021年第一次工作会议，小学部、初中部、高中普通班、高中融合班全体校家委会成员出席会议，围绕学校新学期工作安排、创新性活动等方面进行了深入探讨。</span></p><p><span><a href="images/154fa313ecba4279b4ac34462ad4b298.jpg" target="_blank"></a><a href="images/f1033fe2e0b04da2b19a1053073c5394.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f1033fe2e0b04da2b19a1053073c5394.jpg" width="400" height="248"/></a></span></p><p><span>会议伊始，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊校长首先向家委会成员们解读了学校新学期工作计划。2020年，新航实验在师资调整、课程升级、校园文化、环境建设等方面都上了一个新台阶，新学期学校将着力打造特色课程，完善节日课程、研学实践课程、活动体验类课程，挖掘校内外资源，在科技、艺体、外语及基础学科领域形成特色。除了课程的再升级，今年还将重点推进多个项目建设，为学生搭建更多的展示平台和自主发展的成长空间。</span></p><p><span><a href="images/154fa313ecba4279b4ac34462ad4b298.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_154fa313ecba4279b4ac34462ad4b298.jpg" width="400" height="226"/></a></span></p><p><span><span>之后，学校领导、各学部负责人与家委会成员进行了热烈的分组讨论，家长们献计献策，针对学校的教育教学、学生的全面健康成长和家校配合等方面进行了深入探讨和交流。</span></span></p><p><a href="images/0c3e18acde104b50aa1c93c54a73c380.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0c3e18acde104b50aa1c93c54a73c380.jpg" width="371" height="210" alt=""/></a><span>&nbsp;</span><a href="images/433d26b7ec824e59af6936add53a07a0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_433d26b7ec824e59af6936add53a07a0.jpg" width="371" height="210" alt=""/></a><span>&nbsp;</span><a href="images/de217739c1cf4385ab5777a38cf4e0ce.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_de217739c1cf4385ab5777a38cf4e0ce.jpg" width="371" height="210" alt=""/></a><span></span></p><p><a href="images/160b4468084842a99f20de9656c8213b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_160b4468084842a99f20de9656c8213b.jpg" width="372" height="210" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/287bb3ae02b04ef18f1d86db30f2edd8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_287bb3ae02b04ef18f1d86db30f2edd8.jpg" width="372" height="210" alt=""/></a>&nbsp; &nbsp;&nbsp;<a href="images/be0435e7b7854e3784ba235b4da86330.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_be0435e7b7854e3784ba235b4da86330.jpg" width="372" height="210" alt=""/></a></p><p><span>&nbsp; 著名的教育家苏霍姆林斯基曾说过，“没有家庭教育的学校和没有学校教育的家庭，都不可能完成造就全面发展的人这一极其细致艰巨的工程”。新航实验始终致力于让家长真正参与到学生教育当中，并通过体验式家长会、一对一家访等多种途径来实现这一目标，家校保持思想和行动上的统一，互相配合、形成合力，共同打造最适合孩子成长的教育环境。</span></p><p><br/></p><meta name="ContentEnd">', '', 'home_school', '/uploads/migration/images/154fa313ecba4279b4ac34462ad4b298.jpg', NULL, true, '2021-03-01 08:00:00+08', '2021-03-01 08:00:00+08', '2021-03-01 08:00:00+08', '赵昕晨', '新航实验外国语学校', '家委会 新航 会议 召开 实验', '');
INSERT INTO public.news VALUES (934, '陈晶', '', '陈晶，政治高级教师，济南市高中思想政治教学工作中心组成员、济南市思想政治学科青年骨干教师，连续17年从事高中思想政治教学工作，入选济南市“立德树人双领军”学科教师领军团队。在陈晶的课堂上，没有一个学生会走神，让原本有些枯燥的政治课变得很有魔力，让学生乐学、好学、爱学，思政课的教学效果不应仅仅在试卷分数上，学生未来人生道路走的每一步都是对课堂教学效果的检验。在陈晶眼中，学生都是可爱的，她始终兢兢业业...', '', '<p><a href="images/c34fd301502b4817bd3ed81b2f0de159.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c34fd301502b4817bd3ed81b2f0de159.jpg" width="400" height="559"/></a></p><p><span><br/></span></p><p><span>陈晶，政治高级教师，济南市高中思想政治教学工作中心组成员、济南市思想政治学科青年骨干教师，连续17年从事高中思想政治教学工作，入选济南市“立德树人双领军”学科教师领军团队。</span></p><p><span>在陈晶的课堂上，没有一个学生会走神，让原本有些枯燥的政治课变得很有魔力，让学生乐学、好学、爱学，思政课的教学效果不应仅仅在试卷分数上，学生未来人生道路走的每一步都是对课堂教学效果的检验。在陈晶眼中，学生都是可爱的，她始终兢兢业业、一丝不苟地努力工作，并不断总结教育教学的经验，所带班级被评为济南市先进班集体。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/c34fd301502b4817bd3ed81b2f0de159.jpg', NULL, true, '2021-07-03 00:23:00+08', '2021-07-03 00:23:00+08', '2021-07-03 00:23:00+08', '赵昕晨', '新航实验外国语学校', '陈晶', '270561');
INSERT INTO public.news VALUES (935, '王云剑', '', '王云剑，数学高级教师，济南名师，任教21年来，连续7年担任数学教研组长，济南市高中数学中心组成员，济南市数学文化与学法指导中心主任，连续多年从事教科研和教学改革工作，致力于青年教师培养、学科组建设、智慧空间项目和校本课程等，在数学教学、数学文化、命题研究以及教师专业发展方面有丰富的经验和心得。亦师亦友、温雅睿智、追求卓越、逻辑清晰是王云剑的特点，她总能把晦涩难懂的知识深入浅出地传授给每一位学生，是...', '', '<p><span><a href="images/8d1e944c05394c69b4794eb3f24a4e3e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8d1e944c05394c69b4794eb3f24a4e3e.jpg" width="390" height="567"/></a></span></p><p><span><br/></span></p><p><span>王云剑，数学高级教师，济南名师，任教21年来，连续7年担任数学教研组长，济南市高中数学中心组成员，济南市数学文化与学法指导中心主任，连续多年从事教科研和教学改革工作，致力于青年教师培养、学科组建设、智慧空间项目和校本课程等，在数学教学、数学文化、命题研究以及教师专业发展方面有丰富的经验和心得。</span></p><p><span>亦师亦友、温雅睿智、追求卓越、逻辑清晰是王云剑的特点，她总能把晦涩难懂的知识深入浅出地传授给每一位学生，是学生心中的魅力教师。课堂教学风格多样、有趣，注重挖掘数学知识背后的深层次文化价值和思想方法，并且以学生喜爱的方式呈现，把数学冰冷的美丽转化为火热的思考。</span></p><p><span>曾入选济南市第三期名师人选，先后荣获济南市总工会建功立业先进个人、济南市教育科研先进个人、济南市教育科学优秀成果奖、济南市优质课比赛一等奖，被聘为山东省“互联网+教师专业发展”工作坊主持人，被评选为基础教育+互联网“名师伴我行”最受欢迎教师。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/8d1e944c05394c69b4794eb3f24a4e3e.jpg', NULL, true, '2021-07-03 00:22:00+08', '2021-07-03 00:22:00+08', '2021-07-03 00:22:00+08', '赵昕晨', '新航实验外国语学校', '王云剑', '270559');
INSERT INTO public.news VALUES (936, '山东省实验中学教育集团 济南新航实验外国语学校 2021年高中部自主招生方案', '', '一、招生计划      济南新航实验外国语学校高中部2021年面向济南市招收高一新生指导性计划180名（含融合课程班60名）。二、报名要求1. 报名条件：符合济南市普通高中报考条件的2021年应届初中毕业生，思想品德优秀，身体健康，认同我校教育教学管理理念。2. 报名方式：网上报名。考生登录济南新航实验外国语学校官方网站（http://xhshiyan.jinan.cn/），点击校园动态“济南新航...', '', '<p><span></span>一、招生计划</p><p>&nbsp; &nbsp; &nbsp;&nbsp;济南新航实验外国语学校高中部2021年面向济南市招收高一新生指导性计划180名（含融合课程班60名）。</p><p>二、报名要求</p><p>1. 报名条件：符合济南市普通高中报考条件的2021年应届初中毕业生，思想品德优秀，身体健康，认同我校教育教学管理理念。</p><p>2. 报名方式：网上报名。</p><p>考生登录济南新航实验外国语学校官方网站（http://xhshiyan.jinan.cn/），点击校园动态“济南新航实验外国语学校2021年高中招生报名端口”，按要求填写信息。</p><p>3. 网上报名截止时间为：2021年6月30日24:00。</p><p>4. 学校对网上报名考生的报名信息进行审查。请报名普通班的同学于7月1日14:00后访问济南新航实验外国语学校官方网站（http://xhshiyan.jinan.cn/），点击“济南新航实验外国语学校2021年高中招生报名端口”查询并打印准考证。</p><p>三、组织考查</p><p>1. 考查时间：普通班为2021年7月2日，具体时间及注意事项以准考证通知为准。融合班为7月1日下午14：00。</p><p>2. 普通班考查学科为：语文、数学、英语；融合班为英语。</p><p>3. 地点：济南新航实验外国语学校（济南市经十东路27803号）。</p><p>4. 要求：报考普通班考生凭居民身份证、打印的准考证和中考准考证（三证）参加考查，报考融合班考生凭居民身份证和中考准考证（两证）参加考查，没有办理身份证的考生，请到当地派出所办理临时身份证或带照片的户籍证明。</p><p>四、成绩查询</p><p>1. 成绩查询：考生可于7月3日14:00起，登录济南新航实验外国语学校官方网站（http://xhshiyan.jinan.cn/）进行成绩查询。</p><p>2. 录取流程：根据初中学业水平考试成绩结合我校考查成绩自主录取。考生一经缴费确认被我校录取后不再享有下次志愿填报的资格。</p><p>3. 根据济南市有关部门规定，失信被执行人员子女不能报考我校。</p><p>五、招生咨询</p><p>招生咨询电话：</p><p>0531—59562266（普通班）&nbsp; &nbsp;</p><p>0531—59562288（融合班）</p><p>&nbsp;</p><p>&nbsp;</p><p>山东省实验中学教育集团</p><p>济南新航实验外国语学校</p><p>&nbsp;</p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-07-02 08:00:00+08', '2021-07-02 08:00:00+08', '2021-07-02 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 学校 实验 外国语 高中部', '');
INSERT INTO public.news VALUES (937, '马芳', '', '马芳，华南师范大学理学硕士，数学高级教师。教学经历跨南北，融会贯通不同理念，怀教书育人之初心，诚对三尺讲台。十五年教学生涯，秉承“幽默严肃间，授学生以渔”，带过四届学生，教学成绩优异，多篇论文收录汇编，积极参加市课题研究及学校举办的各项比赛，多次获得校“综合先进”。多年班主任经验，坚持“亦师亦友间，育学生德才”。成绩优秀是基础，培养学生德才之道、常怀少年之心方为愿景。多次获校“优秀班主任”，福州市...', '', '<p><span><a href="images/13cd8d728b6e44cc9bad5ad7f3aa706f.jpg" target="_blank"><a href="images/5cb8c2a038e1416386459d5323eaf949.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5cb8c2a038e1416386459d5323eaf949.jpg" width="300" height="436"/></a></a></span></p><p><span>马芳，华南师范大学理学硕士，数学高级教师。教学经历跨南北，融会贯通不同理念，怀教书育人之初心，诚对三尺讲台。十五年教学生涯，秉承“幽默严肃间，授学生以渔”，带过四届学生，教学成绩优异，多篇论文收录汇编，积极参加市课题研究及学校举办的各项比赛，多次获得校“综合先进”。多年班主任经验，坚持“亦师亦友间，育学生德才”。成绩优秀是基础，培养学生德才之道、常怀少年之心方为愿景。多次获校“优秀班主任”，福州市优秀班主任，所带班级获得市“优秀班集体”称号。</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/13cd8d728b6e44cc9bad5ad7f3aa706f.jpg', NULL, true, '2021-06-22 16:41:00+08', '2021-06-22 16:41:00+08', '2021-06-22 16:41:00+08', '赵昕晨', '新航实验外国语学校', '马芳', '268770');
INSERT INTO public.news VALUES (938, '王希刚', '', '王希刚，中共党员，数学高级教师。2005年9月参加工作，从教16年任教高中数学教学工作，并一直担任班主任，成绩优异，学生管理经验丰富。教学成绩优异，曾连续多年担任高三毕业班教学工作，先后获得济南市优秀班主任、济南市市级优课、区级政府优秀教师、区级政府优秀共产党员、区级优质课一等奖、区青年教师素质大赛一等奖等荣誉称号。爱岗敬业，无私奉献，求实创新，敢打敢拼，不忘对党教育事业无私奉献的初心。“传递正能...', '', '<p><a href="images/736571185e084c208add1a782c5ceab2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_736571185e084c208add1a782c5ceab2.jpg" width="300" height="436"/></a></p><p><span>王希刚，中共党员，数学高级教师。2005年9月参加工作，从教16年任教高中数学教学工作，并一直担任班主任，成绩优异，学生管理经验丰富。教学成绩优异，曾连续多年担任高三毕业班教学工作，先后获得济南市优秀班主任、济南市市级优课、区级政府优秀教师、区级政府优秀共产党员、区级优质课一等奖、区青年教师素质大赛一等奖等荣誉称号。</span></p><p><span>爱岗敬业，无私奉献，求实创新，敢打敢拼，不忘对党教育事业无私奉献的初心。“传递正能量，让学生成为有社会责任感的人”是他的工作信条。所教学生曾以686的总分被中国科技大学录取。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/736571185e084c208add1a782c5ceab2.jpg', NULL, true, '2021-06-22 16:39:00+08', '2021-06-22 16:39:00+08', '2021-06-22 16:39:00+08', '赵昕晨', '新航实验外国语学校', '王希刚', '268768');
INSERT INTO public.news VALUES (949, '开学啦！看，新航实验的“神兽”这样“归笼”', '', '      经过近一个月的假期，      终于迎来了开学日。      都说，      “神兽归笼”时，      父母的心情是这样的      ↓↓↓            孩子的心情是这样的      ↓↓↓          但是，      新航实验的“神兽”们却是这样的      ↓↓↓          就连小学部的小家伙们，      也没有要离开家长的失落，      都在忙着...', '', '<p><span></span></p><p><span>&nbsp; &nbsp; &nbsp; 经过近一个月的假期，</span></p><p><span>&nbsp; &nbsp; &nbsp; 终于迎来了开学日。</span></p><p><span>&nbsp; &nbsp; &nbsp; 都说，</span></p><p><span>&nbsp; &nbsp; &nbsp; “神兽归笼”时，</span></p><p><span>&nbsp; &nbsp; &nbsp; 父母的心情是这样的</span></p><p><span>&nbsp; &nbsp; &nbsp; ↓↓↓</span></p><p><span>&nbsp; &nbsp; &nbsp;&nbsp;<a href="images/1d3bf7a817044610b1e197a81d3d3839.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1d3bf7a817044610b1e197a81d3d3839.jpg" width="246" height="266"/></a></span></p><p><span>&nbsp; &nbsp; &nbsp; 孩子的心情是这样的</span></p><p><span>&nbsp; &nbsp; &nbsp; ↓↓↓</span></p><p><span>&nbsp; &nbsp;&nbsp;<a href="images/720aca2868274fa5bffdb3e257c301e3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_720aca2868274fa5bffdb3e257c301e3.jpg" width="400" height="400"/></a></span></p><p><span>&nbsp; &nbsp; &nbsp; 但是，</span></p><p><span>&nbsp; &nbsp; &nbsp; 新航实验的“神兽”们却是这样的</span></p><p><span>&nbsp; &nbsp; &nbsp; ↓↓↓</span></p><p><span><a href="images/cb681248bc714e88867941b21a31fd2c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cb681248bc714e88867941b21a31fd2c.jpg" width="275" height="300" alt=""/></a>&nbsp;&nbsp;<a href="images/65e367ffec03443184780c3e0a778a36.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_65e367ffec03443184780c3e0a778a36.jpg" width="315" height="300" alt=""/></a>&nbsp;&nbsp;<a href="images/40dfc2cfb7384e0fad788cb053eba61b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_40dfc2cfb7384e0fad788cb053eba61b.jpg" width="382" height="300" alt=""/></a></span></p><p><span>&nbsp; &nbsp; &nbsp; 就连小学部的小家伙们，</span></p><p><span>&nbsp; &nbsp; &nbsp; 也没有要离开家长的失落，</span></p><p><span>&nbsp; &nbsp; &nbsp; 都在忙着玩耍、嬉闹、分享假期趣事。</span></p><p><span>&nbsp; &nbsp; &nbsp; ↓↓↓</span></p><p><span>&nbsp;<img title="" src="/uploads/migration/images/s_775ca9222270423e8b9b92135a9da1fb.jpg" width="327" height="220" alt=""/>&nbsp;&nbsp;&nbsp;<a href="images/806f71045272440a89b20699116d03e1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_806f71045272440a89b20699116d03e1.jpg" width="389" height="220" alt=""/></a>&nbsp;&nbsp;<a href="images/6d2f3fc63d5a44c8b08cd872e56fc405.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6d2f3fc63d5a44c8b08cd872e56fc405.jpg" width="389" height="220" alt=""/></a></span></p><p><span>&nbsp; &nbsp; &nbsp; 现场到底如何？</span></p><p><span>&nbsp; &nbsp; &nbsp; 我们去一探究竟。</span></p><p><span></span><span>&nbsp; &nbsp; &nbsp; ↓↓↓</span></p><p><span>&nbsp; &nbsp; &nbsp; 一大早，各部门按照预定职责提前到岗准备，疫情防控、入校流程、车辆疏导等，每一环节都严谨对待，保证学生们顺利入学。</span></p><p>&nbsp;&nbsp;<a href="images/021dd645c94c4cb9b89e83f12daf405a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_021dd645c94c4cb9b89e83f12daf405a.jpg" width="451" height="300" alt=""/></a>&nbsp; <a href="images/1acf10a3e21247c1b6cc6a8432aaa376.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1acf10a3e21247c1b6cc6a8432aaa376.jpg" width="482" height="300" alt=""/></a></p><p><span>&nbsp; &nbsp; &nbsp; 宿舍楼前，开学的仪式感正式开启。老师装扮成的“新航牛”带着他的“牛气相框”已在这里恭候多时，开学第一天为大家送上牛气满满的祝福。收到这样的惊喜，家长和孩子们兴奋不已，纷纷合影留念，也为学校的精心准备点赞。</span></p><p>&nbsp;<a href="images/9ca6b1a327394b969d04d5ab97362cae.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9ca6b1a327394b969d04d5ab97362cae.jpg" width="400" height="200"/></a>&nbsp;&nbsp;<a href="images/fb0660ff7d914070bb06daf6e6143795.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fb0660ff7d914070bb06daf6e6143795.jpg" width="311" height="200" alt=""/></a>&nbsp; <a href="images/e0ed792aac7747cb946da83ac9570f2b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e0ed792aac7747cb946da83ac9570f2b.jpg" width="351" height="200" alt=""/></a></p><p><a href="images/7410eaff7c7a421eaa5e5f7f2cff837d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7410eaff7c7a421eaa5e5f7f2cff837d.jpg" width="354" height="200" alt=""/></a>&nbsp;&nbsp;<a href="images/a1f2eb499a5e434fb6fc9fbec2fc0f8f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a1f2eb499a5e434fb6fc9fbec2fc0f8f.jpg" width="354" height="200" alt=""/></a>&nbsp;&nbsp;<a href="images/1bd432b99038417ca226af05c3ace8fb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1bd432b99038417ca226af05c3ace8fb.jpg" width="388" height="200" alt=""/></a></p><p><span>&nbsp; &nbsp; &nbsp; 老师们也早早等在宿舍楼前迎接孩子们归队，帮他们搬运行李、整理物品，与家长交流学生的假期生活，个个脸上洋溢着幸福的笑容。</span></p><p>&nbsp;<a href="images/957741aad4164c9bb26e74b9b8d446b8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_957741aad4164c9bb26e74b9b8d446b8.jpg" width="322" height="250" alt=""/></a>&nbsp; <a href="images/5966f4eaf8a843bf9df89e19aaef7ade.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5966f4eaf8a843bf9df89e19aaef7ade.jpg" width="314" height="250" alt=""/></a>&nbsp; <a href="images/6644fa86c13e4dccaab420cecddf2418.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6644fa86c13e4dccaab420cecddf2418.jpg" width="443" height="250" alt=""/></a></p><p><a href="images/f81cce6549cf4bbeb7d9880e3a6f23c8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f81cce6549cf4bbeb7d9880e3a6f23c8.jpg" width="442" height="250" alt=""/></a>&nbsp;&nbsp;<a href="images/ee1a38bd1d0541069c8361ff41a519f4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ee1a38bd1d0541069c8361ff41a519f4.jpg" width="300" height="250" alt=""/></a>&nbsp;&nbsp;<a href="images/75ad6ef0f67045e0ae864950ca72dbf6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_75ad6ef0f67045e0ae864950ca72dbf6.jpg" width="382" height="250" alt=""/></a></p><p><span>&nbsp; &nbsp; &nbsp; 开学仪式感第二站，在班级、剧院、多媒体教室，各学部的开学大幕正式拉开。这里，有老师准备的精美礼物，有写满黑板的祝福语，有不同年级间的惊喜祝福，有上学期的评优表彰，还有老师对新学期的期待和鼓励。</span></p><p>&nbsp;<a href="images/da5af4a9918540be81cad46d648ef010.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_da5af4a9918540be81cad46d648ef010.jpg" width="389" height="220" alt=""/></a>&nbsp; &nbsp;<a href="images/b6ffe69f1da84e808e845696ca6e437f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b6ffe69f1da84e808e845696ca6e437f.jpg" width="331" height="220" alt=""/></a>&nbsp; &nbsp;<a href="images/8479bf2affd44573aa8a5c31dc257d6f.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_8479bf2affd44573aa8a5c31dc257d6f.jpeg" width="294" height="220" alt=""/></a></p><p><a href="images/37cea598e5274067849e7d0227ecede4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_37cea598e5274067849e7d0227ecede4.jpg" width="331" height="220" alt=""/></a>&nbsp;&nbsp; <a href="images/35217827b09645ebabc098325a2de0a1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_35217827b09645ebabc098325a2de0a1.jpg" width="331" height="220" alt=""/></a>&nbsp; &nbsp;<a href="images/d87012800d574025bad904fa4e94b1ca.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d87012800d574025bad904fa4e94b1ca.jpg" width="293" height="220" alt=""/></a></p><p><span>&nbsp; &nbsp; &nbsp; 下午，仪式感继续。初中、高中学部全体学生开学动员大会在新航剧院召开，山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊为学生们做了关于诊断、关于课程、关于学习、关于自己的开学动员报告，鼓励大家做自信淡然、乐观友善、高贵平和、志向高远、心存敬畏的新航实验好少年！</span></p><p><span>&nbsp;<a href="images/b996daeb78f24a02b951247465c7ba52.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b996daeb78f24a02b951247465c7ba52.jpg" width="358" height="220" alt=""/></a>&nbsp;&nbsp;<a href="images/beeb1b88551b44febc88c8d8d30715df.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_beeb1b88551b44febc88c8d8d30715df.jpg" width="319" height="220" alt=""/></a>&nbsp;&nbsp;<a href="images/075e0d2fbbfd498a8e6ee9c93a825657.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_075e0d2fbbfd498a8e6ee9c93a825657.jpg" width="390" height="220" alt=""/></a></span></p><p><span>新学期正式开启，</span></p><p><span><span>新航实验学子已经整装待发，</span></span></p><p><span>带着新的希望和动力，</span></p><p><span>奋勇向前，</span></p><p><span>&nbsp; &nbsp; &nbsp; 努力奔跑！</span></p><p><span><a href="images/f402a26feab74a2d810c1892e4bf9efc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f402a26feab74a2d810c1892e4bf9efc.jpg" width="389" height="220" alt=""/></a>&nbsp;&nbsp;<a href="images/1eabba8ddb914ed8b00f848193305a0d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1eabba8ddb914ed8b00f848193305a0d.jpg" width="331" height="220" alt=""/></a>&nbsp; <a href="images/4841a45504604fb490cf9c5824fce817.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4841a45504604fb490cf9c5824fce817.jpg" width="389" height="220" alt=""/></a></span></p><p><br/></p><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/1d3bf7a817044610b1e197a81d3d3839.jpg', NULL, true, '2021-02-28 08:00:00+08', '2021-02-28 08:00:00+08', '2021-02-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (939, '张素芹', '', '张素芹，数学数学高级教师。曾获得济南市优质课一等奖；济南市“走青春路，做育花人”一等奖；山东省中学数学创新课堂评比一等奖；山东省中小学教育科研成果一等奖；承担济南市教师专项课题；济南市三等功。从教二十多年来，张老师始终把教师职业作为神圣的事业去追求。教学工作中，她不断研究探索，让课堂成为学生成长的阵地。班级教育中，她尊重学生的个体特点，善于发现孩子身上的闪光点，不断增强学生的学习信心。她在教授知识...', '', '<p><a href="images/dd21c4596d6a498586cf52231ea6a6df.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_dd21c4596d6a498586cf52231ea6a6df.jpg" width="400" height="514"/></a></p><p><span>张素芹，数学数学高级教师。曾获得济南市优质课一等奖；济南市“走青春路，做育花人”一等奖；山东省中学数学创新课堂评比一等奖；山东省中小学教育科研成果一等奖；承担济南市教师专项课题；济南市三等功。</span></p><p><span>从教二十多年来，张老师始终把教师职业作为神圣的事业去追求。教学工作中，她不断研究探索，让课堂成为学生成长的阵地。班级教育中，她尊重学生的个体特点，善于发现孩子身上的闪光点，不断增强学生的学习信心。她在教授知识的同时，也在潜移默化中传达给孩子们做人的态度，积极乐观的人生观，价值观。“吾生也有涯，而知也无涯”，她在探索中，陪伴中，和孩子们同行同发展。</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/dd21c4596d6a498586cf52231ea6a6df.jpg', NULL, true, '2021-06-22 16:37:00+08', '2021-06-22 16:37:00+08', '2021-06-22 16:37:00+08', '赵昕晨', '新航实验外国语学校', '张素芹', '268764');
INSERT INTO public.news VALUES (940, '筑牢学生安全防护网——新航实验开展体验式防溺水安全演习', '', '今年6月是第二十个全国安全生产月，也是溺水事故的高发期，为进一步提升学生防溺水安全意识以及识别险情、遇险逃生、自护自救、抢救溺水人员的能力，济南新航实验外国语学校紧紧围绕“落实安全责任，推动安全发展”这一主题，组织开展了防溺水专题安全演习活动。演练活动伊始，游泳教练郭婷允老师首先进行了防溺水知识讲解，教给大家游泳时遇到抽筋等意外情况时如何自救；校医则从判断意识、呼救帮助、矫正体位、胸外按压、开放气...', '', '<p><span><span>今年</span>6<span>月是第二十个全国安全生产月，也是溺水事故的高发期，为进一步提升学生防溺水安全意识以及识别险情、遇险逃生、自护自救、抢救溺水人员的能力，济南新航实验外国语学校紧紧围绕</span><span>“</span><span>落实安全责任，推动安全发展</span><span>”</span><span>这一主题，组织开展了防溺水专题安全演习活动。</span></span></p><p><span><span>演练活动伊始，游泳教练郭婷允老师首先进行了防溺水知识讲解，教给大家游泳时遇到抽筋等意外情况时如何自救；校医则从判断意识、呼救帮助、矫正体位、胸外按压、开放气道、人工呼吸等多方面讲解和演示了对溺水人员上岸后的急救处理方法，使同学们对如何预防溺水及溺水后急救有了系统、全面的了解。</span></span></p><p><span><a href="images/f05fb2311dd04c578baa9cb4c7828d13.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f05fb2311dd04c578baa9cb4c7828d13.jpg" width="400" height="225"/></a>&nbsp; &nbsp;<a href="images/ef7f5075d4bc4946acaa10c87c7835a8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef7f5075d4bc4946acaa10c87c7835a8.jpg" width="400" height="225"/></a>&nbsp; </span></p><p><span><span>为确保演练活动取得实效，第二阶段进行实战模拟演练，老师现场指导学生进行求救、互救，同时校医连贯演示如何救助。讲练结合，在紧张有序的现场模拟演练中帮助学生掌握自救、求救、互救的方法，锻炼了遇到紧急情况时的应变能力和实际操作技能。</span></span></p><p><span><span>最后，张术磊副校长对此次演练进行总结，他指出，要让安全演习成为常态，并且提高实战占比，同时，提醒同学们一定要牢记防溺水知识，学会救助技能，远离危险区域，通过正规途径学习游泳，时刻绷紧安全弦。</span></span></p><p><span><a href="images/c5b7c843ffea42408f7a6117041a257d.jpg" target="_blank"><img title="光影魔术手拼图.jpg" src="/uploads/migration/images/c5b7c843ffea42408f7a6117041a257d.jpg"/></a>&nbsp;</span></p><p><span><span>一直以来，新航实验都将防溺水宣传教育作为常态化工作来抓，通过宣传条幅、主题班会、宣传片等多种形式，增强学生的防溺水安全意识，把防溺水宣传教育工作落到实处，为新航学子的生命安全套上</span>“<span>救生圈</span><span>”</span><span>。</span></span></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/f05fb2311dd04c578baa9cb4c7828d13.jpg', NULL, true, '2021-06-21 08:00:00+08', '2021-06-21 08:00:00+08', '2021-06-21 08:00:00+08', '赵昕晨', '新航实验外国语学校', '安全 体验 新航 开展 实验', '');
INSERT INTO public.news VALUES (941, '济南新航实验外国语学校2021年高中招生报名端口', '', '济南新航实验外国语学校2021年高中招生报名端口:http://jngz.wiscoor.com/Home/Default/Login', '', '<p><span>济南新航实验外国语学校2021年高中招生报名端口:</span></p><p><a href="http://jngz.wiscoor.com/Home/Default/Login"><span>http://jngz.wiscoor.com/Home/Default/Login</span></a></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2021-06-19 08:00:00+08', '2021-06-19 08:00:00+08', '2021-06-19 08:00:00+08', '赵昕晨', '新航实验外国语学校', '学校 外国语 高中 实验 招生', '');
INSERT INTO public.news VALUES (942, '图书馆', '', '', '', '<meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-03-17 08:00:00+08', '2021-03-17 08:00:00+08', '2021-03-17 08:00:00+08', '徐毅', '大汉网络', '济南新航实验外国语学校,新航实验外国语学校,山东省实验中学教育集团新航实验学校,新航', '');
INSERT INTO public.news VALUES (943, '植树、投地掷球、扔飞盘、打高尔夫……这样的户外体验，让课程“活”起来！', '', '投地掷球、抛扔飞盘、打高尔夫球、亲手种下一棵树……3月11-12日，济南新航实验外国语学校初中部、高中部师生在清晨淡淡的雾霭中出发，乘车前往长清区崮云湖进行了丰富多彩的户外体验研学课程。 正值第43个植树节到来之际，“植树”是此次户外体验研学课程的重要内容之一。到达崮云湖畔，映入眼帘的湖光山色让同学们不禁感叹大自然的鬼斧神工，充满生机的绿色造就了如此的美景，大家体会到爱护植被、保护树木的重要性，更...', '', '<p><span><span>投地掷球、抛扔飞盘、打高尔夫球、亲手种下一棵树</span><span>……3月11-12日，济南新航实验外国语学校初中部、高中部师生在清晨淡淡的雾霭中出发，</span></span><span>乘车前往长清区崮云湖进行了丰富多彩的户外体验研学课程。</span></p><p><span><a href="images/0bf056ed1ca34847bae32cfeb4117f0c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0bf056ed1ca34847bae32cfeb4117f0c.jpg" width="325" height="230" alt=""/></a>&nbsp;<a href="images/eea5bd705bc7407fab6b60d32e8bea1d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_eea5bd705bc7407fab6b60d32e8bea1d.jpg" width="407" height="230" alt=""/></a></span></p><p><span><span>正值第</span><span>43个植树节到来之际，“植树”是此次户外体验研学课程的重要内容之一。到达崮云湖畔，映入眼帘的湖光山色让同学们不禁感叹大自然的鬼斧神工，充满生机的绿色造就了如此的美景，大家体会到爱护植被、保护树木的重要性，更了解了植树的重要意义。</span></span></p><p><span><span>现场，每三人一组，共植一棵树。有人挖土，有人扶树，有人浇水，大家互帮互助、分工明确。碰上树坑里石头比较多，大家就一起动手，没有一点</span><span>“娇气”。虽然同学们都是第一次使用铁锨、锄头等农具，虽然他们的动作难免笨拙，但都带着一股认真的劲头儿。</span></span></p><p><span><span>初二的一位男生说，</span><span>“这次植树更有意义，小时候是跟着爸爸妈妈植树，这次跟同学一起，团结合作让我们之间的感情又加深了很多。”</span></span></p><p><span>“树的下面有块大石头，那是我们艰难挖出的，也是荣耀”“新航dorm 305的树”……植完树后，大家纷纷写下了自己的寄语，就像就此种下了希望一样。</span></p><p><span><a href="images/0294206544964214ae72caa766388edb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0294206544964214ae72caa766388edb.jpg" width="319" height="240" alt=""/></a>&nbsp;<a href="images/6de3d2cbb5dd443d8b0d14e86627a5f0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6de3d2cbb5dd443d8b0d14e86627a5f0.jpg" width="361" height="240" alt=""/></a>&nbsp;<a href="images/5dbcb004ffd14c7fa4d8246469b93621.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5dbcb004ffd14c7fa4d8246469b93621.jpg" width="180" height="240" alt=""/></a></span></p><p><span><a href="images/8a30107da1e744a69fcae01c93b4e685.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8a30107da1e744a69fcae01c93b4e685.jpg" width="320" height="240" alt=""/></a>&nbsp;<a href="images/6bd043ee52c548d08d423889704f8a3c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6bd043ee52c548d08d423889704f8a3c.jpg" width="320" height="240" alt=""/></a>&nbsp;<a href="images/b501970383e0496e852c81868cd2f7ea.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b501970383e0496e852c81868cd2f7ea.jpg" width="241" height="240" alt=""/></a></span></p><p><span>除了植树，同学们还参加了高尔夫球体验活动。虽然有专业高尔夫球教练的指导，但绝大多数同学都是初次体验，一击即中的难度还是比较大的。于是同学们相互鼓励、加油打气，凭着不服输、不气馁的劲头，在一次次挑战后都打出了比较满意的成绩。与此同时，高尔夫运动中自律、谦让、优雅的优秀品质也在学生们心中播种萌芽。</span></p><p><span><a href="images/294a350d334648048f8dc9f143b2e173.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_294a350d334648048f8dc9f143b2e173.jpg" width="333" height="250" alt=""/></a>&nbsp;<a href="images/5eaadf00b5e04b3c8681299ab28bf5b4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5eaadf00b5e04b3c8681299ab28bf5b4.jpg" width="340" height="250" alt=""/></a></span></p><p><span><span>在随后的</span><span>“飞盘嘉年华”和地掷球运动中，学生们以班级为组，开动脑筋、集思广益，尽力让自己队的大球更靠近小球，旁边的同学一边指点着怎么投球，一边发出兴奋的喝彩声……大家不仅在活动中收获了快乐，锻炼了体魄，而且认识到团队配合的重要性，学会更加努力地去维护集体荣誉。</span></span></p><p><span><span><a href="images/2fc84f8d43244f5aab142ff77c132630.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2fc84f8d43244f5aab142ff77c132630.jpg" width="331" height="220" alt=""/></a>&nbsp;<a href="images/0844a46ac3ad494487b89cb8955084ce.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0844a46ac3ad494487b89cb8955084ce.jpg" width="391" height="220" alt=""/></a></span></span></p><p><span><span><a href="images/c73b620e254644d2a8f1ce47661d7eaf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c73b620e254644d2a8f1ce47661d7eaf.jpg" width="293" height="220" alt=""/></a>&nbsp;<a href="images/66c2a29e45574b95b52fd304678580e2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_66c2a29e45574b95b52fd304678580e2.jpg" width="331" height="220" alt=""/></a></span></span></p><p><span><a href="images/cd8682b3fc534204afb1d5f5f5406c90.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cd8682b3fc534204afb1d5f5f5406c90.jpg" width="356" height="200" alt=""/></a>&nbsp;<a href="images/912777d8c14f46b2bbb57f0921369dce.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_912777d8c14f46b2bbb57f0921369dce.jpg" width="354" height="200" alt=""/></a>&nbsp;<a href="images/391525f2024449ac9e068e5ef387a7a8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_391525f2024449ac9e068e5ef387a7a8.jpg" width="307" height="200" alt=""/></a></span></p><p><span><a href="images/a0db3d4784994436ae60fd3f03ab1bba.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a0db3d4784994436ae60fd3f03ab1bba.jpg" width="301" height="200" alt=""/></a>&nbsp;<a href="images/e899bf0975634b5aa1d54f8cdb13690c.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_e899bf0975634b5aa1d54f8cdb13690c.jpeg" width="356" height="200" alt=""/></a>&nbsp;<a href="images/7139c66ce1cf4e47896a2dcae044f093.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7139c66ce1cf4e47896a2dcae044f093.jpg" width="267" height="200" alt=""/></a></span></p><p><span>&nbsp; 这次户外体验研学课程，既是一次解放天性的活动，也让同学们更加懂得了团结协作、挑战自我的意义。活动结束前，大家看着这美好的景色，满怀不舍，他们期盼着自己的小树生根发芽、长成参天大树，而那个时候的自己，也一定是栋梁之材。</span></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/0bf056ed1ca34847bae32cfeb4117f0c.jpg', NULL, true, '2021-03-15 08:00:00+08', '2021-03-15 08:00:00+08', '2021-03-15 08:00:00+08', '赵昕晨', '新航实验外国语学校', '高尔夫 体验 户外 飞盘 课程', '');
INSERT INTO public.news VALUES (944, '【国旗下讲话】庆建党百年 展巾帼风采', '', '各位老师、同学们：大家好！和着初春的韵律，我们相约在鲜艳的国旗下，举行庄严的升旗仪式。正值“三八”国际劳动妇女节，我代表所有的同学们，把最美好的祝福献给辛勤培育我们的女老师，献给悉心哺育我们的母亲，也献给天下千千万万个伟大女性!非常荣幸能作为同学代表在国旗下演讲，今天我在国旗下演讲的题目是：庆建党百年，展巾帼风采。首先，我们说母爱是最伟大的，母亲于我们有三重恩：生我之痛、养我之辛、育我之苦。然而作...', '', '<p><span><a href="images/6bfcc027ed084fbc8ccaad051b4b4fbf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6bfcc027ed084fbc8ccaad051b4b4fbf.jpg" width="460" height="260" alt=""/></a></span></p><p><span>各位老师、同学们：</span></p><p><span>大家好！</span></p><p><span>和着初春的韵律，我们相约在鲜艳的国旗下，举行庄严的升旗仪式。正值“三八”国际劳动妇女节，我代表所有的同学们，把最美好的祝福献给辛勤培育我们的女老师，献给悉心哺育我们的母亲，也献给天下千千万万个伟大女性!</span></p><p><span>非常荣幸能作为同学代表在国旗下演讲，今天我在国旗下演讲的题目是：庆建党百年，展巾帼风采。</span></p><p><span>首先，我们说母爱是最伟大的，母亲于我们有三重恩：生我之痛、养我之辛、育我之苦。然而作为学生的我们，有时嫌她唠叨，或因一些小事就大发雷霆……她却永远默默地支持我们，不厌其烦地开导我们，给予我们最大支持和鼓励，是母亲用她那勤劳的双手、温暖的怀抱、博爱的肩膀为我们撑起了广阔的天空。</span></p><p><span>第二位伟大母亲就是我们党，在时代洪流之中，我们党是中流砥柱；在千钧一发之际，伟大领袖力挽狂澜。在《共产党宣言》发表173年后，在中国共产党成立100周年，新中国走过72年风雨，改革开放经历43年辉煌。世界局势风云变幻，百年变局即将来临。我们党，我们的国家，以及世界人民，都来到了历史的十字路口。五位一体，四个全面，社会主义新的事业正在稳步推进；“悟空”上天，“蛟龙”入海，创新驱动，新发展理念逐渐深入人心。全面小康，两个一百年的奋斗目标，是人民对美好生活向往的集中体现。</span></p><p><span>在历史的烽烟中，巾帼英雄也留下自己浓墨重彩的一笔。从代父从军的花木兰，到五十三岁又重掌帅印的穆桂英，从为推翻数千年封建统治而牺牲的女英雄秋瑾，到坚贞不屈忍辱负重的女党员赵一曼。中国女英雄的故事代代流传，激励着一代代的中华儿女。从为了申请修路资金奔波于县乡之间的驻村扶贫书记刘双燕，到新冠疫情期间带领专家组进驻武汉的中国工程院院长陈薇，从第一位成功登上太空的女性刘洋，到创制新型抗疟疾药青蒿素和双氢青蒿素的中国首位诺贝尔医学奖获得者屠呦呦。铮铮铁骨，寸寸柔肠，在她们身上合而为一，她们是中国历史上的一座丰碑。</span></p><p><span>谁言寸草心，报得三春晖，我们怎么来回报她们，其实很简单，站在庄严的国旗下，我们不需要豪言壮语，更不需要对天发誓。善言天者，必有验于人；善言古者，必有合于今。我们需要积极学习党史，把报国忠党的这份决心、这份誓言记在心里，落实到行动上，用我们优异的成绩给他们交上满意的答卷。</span></p><p><span>最后，让我们再次向辛勤工作的女教师们、含辛茹苦的母亲们说声：你们辛苦了，谢谢你们!</span></p><p><span><br/></span></p><p><span>高二五班 宋若瑾</span></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/6bfcc027ed084fbc8ccaad051b4b4fbf.jpg', NULL, true, '2021-03-10 08:00:00+08', '2021-03-10 08:00:00+08', '2021-03-10 08:00:00+08', '赵昕晨', '济南新航实验外国语学校', '讲话 风采 建党 国旗', '');
INSERT INTO public.news VALUES (945, '学百年党史 悟真理力量——新航实验开展“学党史 悟真理”学习活动', '', '为贯彻落实习近平总书记在党史学习教育动员大会上的重要讲话精神，引领广大师生“回望过往的奋斗路，眺望前方的奋进路，把党的历史学习好、总结好，把党的成功经验传承好、发扬好”，树立正确的人生观和价值观，增强历史责任感和使命感，以奋进姿态迎接建党100周年。近日，济南新航实验外国语学校组织全校师生通过升旗仪式开展学党史、悟真理学习活动。 “今年是中国共产党成立100周年，百年来，党带领人民谱写了中华民族自...', '', '<p><span>为贯彻落实习近平总书记在党史学习教育动员大会上的重要讲话精神，引领广大师生“回望过往的奋斗路，眺望前方的奋进路，把党的历史学习好、总结好，把党的成功经验传承好、发扬好”，树立正确的人生观和价值观，增强历史责任感和使命感，以奋进姿态迎接建党100周年。近日，济南新航实验外国语学校组织全校师生通过升旗仪式开展学党史、悟真理学习活动。</span></p><p><a href="images/c38d03ccb82244009618becad1c9a55f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c38d03ccb82244009618becad1c9a55f.jpg" width="327" height="240" alt=""/></a><span>&nbsp;</span><a href="images/1e1f9854900b4300805a584d6cde6dac.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1e1f9854900b4300805a584d6cde6dac.jpg" width="361" height="240" alt=""/></a></p><p><span>“今年是中国共产党成立100周年，百年来，党带领人民谱写了中华民族自强不息、顽强奋进的壮丽史诗。”新航实验党支部书记、副校长张术磊以“学百年党史 悟真理力量”为题为广大师生做了精彩的演讲，分别从为什么、学什么、怎样学三方面对党史学习进行深入解读。</span></p><p><span><a href="images/a63c1ac9ba7a47c591843fc6c1d9393a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a63c1ac9ba7a47c591843fc6c1d9393a.jpg" width="362" height="400" alt=""/></a></span></p><p><span><strong><span>为什么要学习党史</span></strong></span></p><p><span>古人说：“灭人之国，必先去其史。”因为历史是一个民族安身立命的基础，历史是一个民族、一个国家、一个政党形成和发展及其盛衰兴亡的真实记录。学习历史，可以帮助我们“看成败、鉴得失、知兴替”。知史爱党，知史爱国，知史明智，知史鉴今。只有了解了过去，才能正确认识现在；只有正确认识了现在，才能科学把握未来。</span></p><p><span>我们党历来重视党史学习教育，注重用党的奋斗历程和伟大成就鼓舞斗志、明确方向；用党的光荣传统和优良作风坚定信念、凝聚力量；用党的实践创造和历史经验启迪智慧、砥砺品格。习近平总书记曾指出，“一切向前走，都不能忘记走过的路；走得再远、走到再光辉的未来，也不能忘记走过的过去，不能忘记为什么出发。”</span></p><p><span><strong>要从党史中学习什么</strong></span></p><p><span>俗话说，“人无精神则不立，国无精神则不强。”我们党的每一段革命历史，都是一部理想信念的生动教材。我们党在各个历史时期创立的革命精神都是“党和国家的宝贵财富”，其中包括五四精神、红船精神、井冈山精神、长征精神、延安精神、红岩精神、太行精神、沂蒙精神、西柏坡精神、抗美援朝精神、北大荒精神、大庆精神、铁人精神、红旗渠精神、焦裕禄精神、雷锋精神、王杰精神、工匠精神、塞罕坝精神、抗疫精神等。正是这些精神构筑起了中国共产党人的精神谱系，是激励我们前行的强大力量之源，为我们深刻学习党史提供了丰厚滋养。</span></p><p><span>近代以来，中国人民面临着争取民族独立、人民解放和实现国家富强、人民幸福两大历史任务，这两大历史任务就是中国共产党历史发展的主题主线。我们要深刻理解党的历史的主流本质，概括起来讲，就是“不懈奋斗史”“理论探索史”“自身建设史”。这样也自然就回答了一系列的问题，包括近代中国为什么会产生中国共产党？中国共产党怎样改变了中国、影响了世界？中国共产党为中国人民、中华民族、人类文明进步事业作出了什么样的伟大历史贡献？</span></p><p><strong><span>要怎样学党史</span></strong></p><p><span>学习党的历史，不是为了学习而学习，学史重在力行，学校团委要积极开展“知党恩 听党话 跟党走”系列活动，把青少年红色传承教育引向深入；把学党史与读书节、音乐节等新航实验节日课程有机结合，进一步激发同学们颂党爱党的热情；学校党支部通过举办师生学党史知识竞赛、组织师生“颂歌献给党”合唱比赛、举行“致敬100年”学生社团展演和学科核心素养主题教育活动、开展“不忘初心 牢记使命”主题党日、给党员过“政治生日”重温入党誓词等教育活动，厚植爱党爱国情怀。</span></p><p><span>&nbsp; 对于新航实验的师生来说，“学百年党史 悟真理力量”不仅意味着一次新的学习，更是一场心灵的洗礼，一次境界的升华。在之后的学习和生活中，党史学习将成为新航实验的一门“必修课”，成为师生成长进步的精神指引。</span><br/></p><p><br/></p><meta name="ContentEnd">', '', 'other', '/uploads/migration/images/c38d03ccb82244009618becad1c9a55f.jpg', NULL, true, '2021-03-10 08:00:00+08', '2021-03-10 08:00:00+08', '2021-03-10 08:00:00+08', '赵昕晨', '新航实验外国语学校', '真理 党史 开展 新航 力量', '');
INSERT INTO public.news VALUES (946, '惊喜又又又来啦！致敬新航实验最美的“她”', '', '  冰心曾说，世界上若没有女人，这世界至少要失去十分之五的真，十分之六的善，十分之七的美。  在济南新航实验外国语学校，有这样一群“跨界女王”，她们是老师，是伙伴，是妈妈，是女儿，是妻子，是姐妹，她们可盐可甜，可温柔如水可干练如风，她们用智慧和责任撑起新航实验的“半边天”。为感谢这些辛勤工作在教育教学岗位的“巾帼英雄”，在第111个国际妇女节到来之际，新航实验特别组织开展了“颂女神风貌 展巾帼风采...', '', '<p><span></span></p><p><span>&nbsp; 冰心曾说，世界上若没有女人，这世界至少要失去十分之五的真，十分之六的善，十分之七的美。</span></p><p><span>&nbsp; 在济南新航实验外国语学校，有这样一群“跨界女王”，她们是老师，是伙伴，是妈妈，是女儿，是妻子，是姐妹，她们可盐可甜，可温柔如水可干练如风，她们用智慧和责任撑起新航实验的“半边天”。为感谢这些辛勤工作在教育教学岗位的“巾帼英雄”，在第111个国际妇女节到来之际，新航实验特别组织开展了“颂女神风貌 展巾帼风采”系列活动，为女教师们送上多重大礼。</span></p><p><span><img title="" src="/uploads/migration/images/s_d02f538b4eda469cbc51b4561bff77ee.jpg" width="476" height="150" alt=""/></span></p><p><span>&nbsp; 美好的一天从惊喜开始。</span></p><p><span>&nbsp; 今天的升旗仪式有些特别，当精心制作的视频出现在大屏幕上时，全场“哇”声一片。视频中，新航实验驰骋在教育教学一线的“铿锵玫瑰”们，从黑发到白头、从稚嫩到成熟，她们辛勤耕耘三十载，这份对教育事业的坚守与付出感染着在场的每一位师生。</span></p><p><span>&nbsp; 为表达对老教师们的敬意与感谢，山东省实验中学东校校长、济南新航实验外国语学校执行校长林宝磊亲手送上鲜花，祝老师们芳华常在，愿她们的精彩教育人生继续抒写。</span></p><p><span><a href="images/e9c462958e5849cea6961117c55169ed.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e9c462958e5849cea6961117c55169ed.jpg" width="331" height="220" alt=""/></a>&nbsp;<a href="images/b599fd144e924276b8faf34b2a960a50.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b599fd144e924276b8faf34b2a960a50.jpg" width="331" height="220" alt=""/></a>&nbsp;<a href="images/f4f233ba2d4c4716b71027147e3557ab.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f4f233ba2d4c4716b71027147e3557ab.jpg" width="341" height="220" alt=""/></a></span></p><p><span>&nbsp; 升旗仪式结束后，全体女教师与林宝磊校长合影留念，留下2021年属于我们的共同美好。作为新航实验的“颜值担当”，我们将团结一心，共同奋进，以更加饱满的热情投入教育教学工作，绽放在新时代教坛之上。</span></p><p><span>&nbsp; 节日的重磅惊喜在中午拉开帷幕。午餐前，男士们以最正式的着装早早等候在餐厅，巧克力、蛋糕、自助餐、心愿墙、彩色气球，所有的美好已准备就绪，只等“女神”们大驾光临。</span></p><p><span>&nbsp; 林宝磊校长也与老师们相聚一起，共同庆祝“女神节”的到来。他肯定了女性对社会、事业和家庭的辛劳付出，感谢新航实验的女教师们对学校发展、学生成长做出的贡献，祝愿所有女教师节日快乐，永远灿烂夺目。</span></p><p><span><a href="images/2dd861dcaacd4b9b89ecf27f272b2b73.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2dd861dcaacd4b9b89ecf27f272b2b73.jpg" width="393" height="220" alt=""/></a>&nbsp;<a href="images/501946d293a84d09b81555793c540148.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_501946d293a84d09b81555793c540148.jpg" width="393" height="220" alt=""/></a></span></p><p><span><a href="images/89cb138026ee4d6fa232c7a9af1c7e10.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_89cb138026ee4d6fa232c7a9af1c7e10.jpg" width="393" height="220" alt=""/></a>&nbsp;</span><a href="images/cafbc635b8544fd5bf43599e8dbb0161.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cafbc635b8544fd5bf43599e8dbb0161.jpg" width="279" height="220" alt=""/></a><span>&nbsp;</span></p><p><span>&nbsp; 下午，“花为媒 你最美”花艺体验活动在玄龄书院开课，女教师们欢聚一堂，在特聘花艺专家的指导下，搭配自己精巧的构思，一件件精美的作品在指尖绽放。</span></p><p><span>&nbsp; 鲜花的世界里，芬芳着最美的年华。</span></p><p><a href="images/ee309816de2943eca59f2c827054eeed.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ee309816de2943eca59f2c827054eeed.jpg" width="293" height="220" alt=""/></a>&nbsp;<a href="images/b21d07679e69463cb5c259a591cedfc7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b21d07679e69463cb5c259a591cedfc7.jpg" width="293" height="220" alt=""/></a>&nbsp;<a href="images/fbdcaed4e226450a9062690823ee527e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fbdcaed4e226450a9062690823ee527e.jpg" width="393" height="220" alt=""/></a></p><p><a href="images/27c0e52b1c5c4f37ab005b6e18a990ef.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_27c0e52b1c5c4f37ab005b6e18a990ef.jpg" width="393" height="220" alt=""/></a>&nbsp;<a href="images/cb38d9a02e5e44898ead520ad995185d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cb38d9a02e5e44898ead520ad995185d.jpg" width="162" height="220" alt=""/></a>&nbsp;<a href="images/cece0cd577fb48069fd4ecc62d838fc3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cece0cd577fb48069fd4ecc62d838fc3.jpg" width="393" height="220" alt=""/></a></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/e9c462958e5849cea6961117c55169ed.jpg', NULL, true, '2021-03-09 08:00:00+08', '2021-03-09 08:00:00+08', '2021-03-09 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 致敬 惊喜 实验', '');
INSERT INTO public.news VALUES (970, '2020年艺体特长生招生简章', '', '山东省实验中学教育集团    济南新航实验外国语学校2020年艺体特长生招生简章 根据《2020年济南市普通高中学校招收艺体特长生工作方案》和济南市2020年高中阶段学校招生工作意见，经研究决定，2020年我校将招收艺体特长生。一、招生计划：根据我校实际，报济南市教育局批准，我校2020年共招收艺体特长生10人，分体育和音乐两大类，2个专业，具体专业及人数如下：      二、报名条件： 1.基本...', '', '<p><span><strong><span>山东省实验中学</span></strong><strong><span><span>教育集团</span> &nbsp;&nbsp;&nbsp;<span>济南新航实验外国语学校</span></span></strong></span></p><p><span><strong><span>2020</span></strong><strong><span>年</span></strong><strong><span>艺体特长生</span></strong><strong><span>招生简章</span></strong></span></p><p><span>&nbsp;</span></p><p><span><span>根据《</span></span><span>2020年济南市普通高中学校招收艺体特长生工作方案</span><span><span>》</span></span><span><span>和</span></span><span><span>济南市</span>2020年高中阶段学校招生工作意见，经研究决定，20</span><span>20</span><span><span>年我校</span></span><span><span>将招收艺体特长生。</span></span></p><p><span><span></span></span></p><p><span>一、</span><strong><span><span>招生计划</span></span></strong><strong><span><span>：</span></span></strong></p><p><span><span>根据我校实际，报济南市教育局批准，我校</span></span><span>2020年共招收艺体特长生10人，分体育和音乐两大类，2个专业，具体专业及人数如下：</span></p><p><a href="images/5efac49247694338ac54564473988faf.png" target="_blank"></a><a href="images/5efac49247694338ac54564473988faf.png" target="_blank"></a><a href="images/5efac49247694338ac54564473988faf.png" target="_blank"><img title="" src="/uploads/migration/images/s_5efac49247694338ac54564473988faf.png" width="800" height="131"/></a><strong><span>&nbsp;</span></strong></p><p><strong><span><span>&nbsp; &nbsp; &nbsp;二</span></span></strong><strong><span><span>、报名</span></span></strong><strong><span><span>条件：</span></span></strong></p><p><strong><span>&nbsp;1.基本要求：</span></strong></p><p><span><span>品行端正</span></span><span><span>，等级科目成绩在</span>“合格”级、D级及以上等次，</span><span><span>具备报考普通高中资格，有体育或艺术特长</span></span><span><span>的</span></span><span><span>应届初中毕业生。</span></span></p><p><strong><span>&nbsp; &nbsp; 2.</span></strong><strong><span><span>专业要求：</span></span></strong></p><p><strong><span><span>（</span>1）游泳：</span></strong><span><span>男女生不限。在初中阶段获得市级以上（含市级）游泳比赛单项前三名或成绩达到国家二级运动员及以上标准，或有潜力的优秀学生。泳姿至少会两种以上。</span></span></p><p><strong><span><span>（</span>2）舞蹈：</span></strong><span><span>男女生不限，中国舞、芭蕾舞、民间舞都可。获得业余舞蹈专业十级证书（提供艺术等级证书），或在省市举办的舞蹈比赛中取得市级一等奖及以上个人奖励（提供有效证书），且有一定演出经验（提供演出视频或节目单等证明材料），形象气质佳，身高</span>1.65-1.72米之间。</span></p><p><strong><span><span>三、</span></span></strong><strong><span><span>网上报名及审核</span></span></strong><strong><span><span>时间：</span></span></strong><strong><span>7</span></strong><strong><span><span>月</span></span></strong><strong><span>16</span></strong><strong><span><span>日</span></span></strong><strong><span><span>上午</span>8：30</span></strong><strong><span>—</span></strong><strong><span>7月</span></strong><strong><span>1</span></strong><strong><span>7</span></strong><strong><span><span>日</span>17:00。</span></strong></p><p><span><span>因工作流程更加简化及疫情防控需要，</span>2020年特长生全部实行网上报名，学生专业发展材料同时在报名系统中以图片形式上传，我校专业老师将会在报名系统中对各位同学提交的材料进行审核。</span></p><p><span><span>请考生登录济南市教育招生考试院网站（</span>http://www.jnzk.net）</span><a href="http://www.jnzk.net，点击"><span><span>，点击</span>“</span></a><a><span><span>济南市（除莱芜地区外）中考艺体特长生网上报名</span></span></a><span>”的链接,即可打开报名登录界面。</span><span><span>学生登录的用户名为其身份证号，初始密码为其学籍号。具体以招考院的报考指南为准。</span></span></p><p><strong><span><span>★注意：</span></span></strong><strong><span><span><br/></span></span></strong><strong><span>1、学生提交的各项材料必须加盖初中学校公章以后再拍照上传，每位</span></strong></p><p><strong><span><span>同学最多可上传大小为</span>300K-500K的4张图片。</span></strong></p><p><strong><span>2、虽然进行了网上报名，但是如果考生在网上提供的相关材料信息达不到我校特长生招生的相关专业要求，或者提交材料信息经审核有虚假</span></strong><strong><span><span>成分，</span></span></strong><strong><span><span>则不能通过审核，不能参加我校的艺体特长生测试。</span></span></strong></p><p><strong><span><span>四、网上打印准考证：</span></span></strong></p><p><strong><span>7月19日9:00开始，</span></strong><span><span>请登录济南市教育招生考试院网站（</span>http://www.jnzk.net）</span><a href="http://www.jnzk.net，点击"><span><span>，点击</span>“</span></a><a href="http://xk.jnzk.net:8000/"><span><span>济南市（除莱芜地区外）中考艺体特长生网上报名</span></span></a><span>”的链接,</span><span><span>打印网上报名准考证。</span></span></p><p><strong><span><span>五、</span></span></strong><strong><span><span>专业测试安排及注意事项：</span></span></strong></p><p><span>1、专业测试时间：7月21日</span></p><p><span><span>请所有考生携带准考证、准考证和彩色打印的健康码，于</span>7月21日早8:30前，到济南新航实验外国语学校体育馆集合，按项目进行排队。</span></p><p><strong><span><span>★注意：</span></span></strong></p><p><strong><span><span>（</span>1）请携带好专业测试项目及内容中注意事项提示的所需物品，保证专业测试顺利进行。</span></strong></p><p><strong><span><span>（</span>2）根据防疫要求，所有前来测试的学生需要携带彩色打印健康码、身份证和准考证，并带好口罩，配合学校做好体温检测工作。</span></strong></p><p><span>2、参加测试时需要携带的资料（原件与复印件）：</span></p><p><span><span>（</span>1）《2020年济南市高中学校招收特长生测试审批表》</span></p><p><span><span>（</span>2）相关等级证书</span></p><p><span><span>（</span>3）相关获奖证书</span></p><p><span><span>（</span>4）演出视频或节目单等证明材料</span></p><p><span><span>（</span>5）与网络报名同底版的1寸彩色近期免冠照片3张。</span></p><p><span>3、专业测试项目及内容：</span></p><p><strong><span><a href="images/de86d75b305941268c93b95c57e79ccc.png" target="_blank"></a><a href="images/de86d75b305941268c93b95c57e79ccc.png" target="_blank"><img title="" src="/uploads/migration/images/s_de86d75b305941268c93b95c57e79ccc.png" width="800" height="284"/></a>&nbsp;</span></strong><br/></p><p><strong><span><span>六、</span></span></strong><strong><span><span>专业</span></span></strong><strong><span><span>测试合格名单</span></span></strong><strong><span><span>公示</span></span></strong><strong><span><span>：</span></span></strong></p><p><span><span>专业测试项目当场公布成绩，考生本人签字。专业测试合格人数按招生计划</span></span><span>1:1</span><span>.5的比例确定，</span><span><span>测试合格者名单将于</span></span><span><span>专业测试结束后次</span></span><span><span>日通过学校网站</span></span><span><span>公示</span></span><span><span>。</span></span></p><p><strong><span><span>七</span></span></strong><strong><span><span>、</span></span></strong><strong><span><span>录取条件：</span></span></strong></p><p><span><span>游泳、舞蹈专业</span></span><span><span>等级科目成绩须在</span></span><span>C</span><span><span>级（含）以上</span></span><span><span>，初中学业水平考试成绩达到济南市普通高中最低录取资格线（含）以上。</span></span></p><p><strong><span><span>说明：</span></span></strong><span><span>考生初中阶段在省级及以上教育主管部门举办的体育、艺术比赛中获得一等奖第一名，且在</span></span><span><span>我校</span></span><span><span>艺体特长生专业测试中获得第一名（考生的比赛项目和测试项目必须一致）</span></span><span><span>，文化课未达到我校相应专业录取分数线的，根据《</span>2020年济南市普通高中学校艺体特长生招生方案》精神，由我校</span><span><span>提出申请，报请</span></span><span><span>济南</span></span><span><span>市中考艺体特长生招录工作小组审批同意后，分别在</span></span><span><span>我校</span></span><span><span>和初中毕业学校同时公示三</span></span><span><span>日</span></span><span><span>无异议</span></span><span><span>后</span></span><span><span>可破格录取。</span></span></p><p><strong><span><span>八、特别声明：</span></span></strong></p><p><span>1.根据《2020年济南市普通高中学校招收艺体特长生工作方案》要求，若招生项目出现空缺或该项目考生专业测试成绩未达到学校招生最低标准，经学校招生工作小组研究，将该项目招生计划进行调整或缩减招生计划。</span></p><p><span>2.凡经我校专业测试合格的同学，入校后须代表学校参加有关比赛活动。</span></p><p><span>3.我校艺体特长生招生，不举办也不委托任何机构举办辅导班。</span></p><p><strong><span><span>九、</span></span></strong><strong><span><span>济南新航实验外国语学校</span></span></strong><strong><span><span>艺体特长生招生解释权归</span></span></strong><strong><span><span>学校教学中心</span></span></strong><strong><span><span>所有。</span></span></strong></p><p><span><span>招生咨询电话：</span> 0531—59562266 &nbsp;59562288</span></p><p><span>&nbsp;</span></p><p><span><span>济南新航实验外国语学校</span></span></p><p><span>2020年6月24日</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-07-04 08:00:00+08', '2020-07-04 08:00:00+08', '2020-07-04 08:00:00+08', '王雪', '新航实验外国语学校', '特长生 招生 简章', '');
INSERT INTO public.news VALUES (950, '共话成长 我们一直都在——新航实验开展“不进门家访2.0版”开学教育特色活动', '', '“面对面、多对一，老师们不仅是家访，更是来真心为孩子的学习出谋划策、现场把脉的。老师慈爱的点评、诚恳的话语、耐心细致的开导，句句都说到了我们的心坎里，让我们真切体会到了新航实验教育的温度。”20日上午，新航实验初一级部学生家长马先生这样感慨道。从2月19日开始，来自济南新航实验外国语学校初中学部和高中学部的近百名任课教师，马不停蹄地奔波在家访的路上，户外广场、咖啡店、公共会议室等，都留下了他们忙碌...', '', '<p><span>“面对面、多对一，老师们不仅是家访，更是来真心为孩子的学习出谋划策、现场把脉的。老师慈爱的点评、诚恳的话语、耐心细致的开导，句句都说到了我们的心坎里，让我们真切体会到了新航实验教育的温度。”20日上午，新航实验初一级部学生家长马先生这样感慨道。</span></p><p><span>从2月19日开始，来自济南新航实验外国语学校初中学部和高中学部的近百名任课教师，马不停蹄地奔波在家访的路上，户外广场、咖啡店、公共会议室等，都留下了他们忙碌的身影。</span></p><p><span><img title="" src="/uploads/migration/images/s_6fcb06b0c7cc4ac69f2ef51a9832cc41.jpg" width="400" height="300"/>&nbsp; &nbsp;<img title="" src="/uploads/migration/images/s_7fef62210df540fb9b3c6e8fd9553e1b.jpg" width="541" height="300" alt=""/></span><span></span></p><p><span>本次家访初高中级部各学科老师全员出动，早早就开始着手准备，家访形式、场地选择、学生分组、老师分工、疫情防控等悉数安排周全，保证家访活动的顺利进行。</span></p><p><span>为了更好地掌握学生假期的学习效果，初中部每班的主课老师在各学科组长的带领下提前准备好学科检测题，学生现场作答，老师现场指导批改；对于假期作业以及学生遇到的问题，老师们也都进行了逐一的检查和解答。</span></p><p><span>高中部老师则针对该年龄段学生的性格和学习特点，进行了阶段性作业抽查和讲解，并布置了开学前的复习预习任务，叮嘱学生们保持良好的学习节奏，迎接新学期的到来。</span></p><p><span>要说现场最有趣的事情，非“父子大PK”莫属了。老师出题，父子一起竞答，得分高者获胜。这样新颖的方式极大地提高了学生主动思考的积极性，尤其当“战胜”父母时，每个孩子脸上都洋溢着兴奋和自豪的笑容。</span></p><p><span><img title="" src="/uploads/migration/images/s_ec61197efaec4aed8231d57b06ec5f1d.jpg" width="334" height="250" alt=""/>&nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_721a1211fd814895ab5d815df936bbf0.jpg" width="376" height="250" alt=""/>&nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_6a415afeb5104057be78581195161e68.jpg" width="334" height="250" alt=""/>&nbsp;&nbsp;</span><a href="images/c110d97d91e04014ac6f1e3f7739d26b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c110d97d91e04014ac6f1e3f7739d26b.jpg" width="334" height="250" alt=""/></a><span>&nbsp;&nbsp;</span><a href="images/1b563853935247678e5fabd74ce4c49b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1b563853935247678e5fabd74ce4c49b.jpg" width="426" height="250" alt=""/></a><span>&nbsp;&nbsp;</span><img title="" src="/uploads/migration/images/s_fb517f8e2a4e4655a424dc650d53e725.jpg" width="333" height="250" alt=""/></p><p><span>除了关注学生的学习，这次家访还有一项重要任务就是家校交流。老师与学生和家长面对面交流，解答家长疑问，深入了解孩子的成长环境和家庭教育理念，将学生在校表现和成长进步反馈给家长，指导学生有效地进行开学前的作息和心理调适。与此同时，三方还结合目前的情况对下学期的学习和生活规划进行了全面探讨，家校合力，为学生营造良好的成长环境。</span></p><p><span>“这次家访真是及时雨，给孩子们日渐放松的假期生活适时地踩下刹车，同时也起到了对孩子学习和未来发展的促进作用。”此次活动受到家长们的一致点赞。</span></p><p><span><a href="images/16e2ed5e5c4d4fb187a65f11d2fa095c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_16e2ed5e5c4d4fb187a65f11d2fa095c.jpg" width="370" height="250" alt=""/></a>&nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_4bc1f63ca3414299a1c46461e579008a.jpg" width="333" height="250" alt=""/>&nbsp;&nbsp;<a href="images/60517372618f4628aeb967b88e5efafd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_60517372618f4628aeb967b88e5efafd.jpg" width="333" height="250" alt=""/></a></span></p><p><span>家访结束后，各学科老师第一时间将了解到的情况整理汇总，充实学生档案，结合学生实际情况制定更高效的教育计划，保证学生全面的、个性化的发展。</span></p><p><span>&nbsp; 这次活动不止是家访，更是诚意满满的对教育工作的热爱与尊重。家校沟通、学情诊断、作业讲解、新学期规划、心理调适、习惯教育等这样的“开学大礼包”，让每位学生和家长都亲身体会到了新航实验的体贴和暖心，也对即将到来的开学返校学习充满了期待和信心。</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/c110d97d91e04014ac6f1e3f7739d26b.jpg', NULL, true, '2021-02-24 08:00:00+08', '2021-02-24 08:00:00+08', '2021-02-24 08:00:00+08', '赵昕晨', '新航实验外国语学校', '实验 家访 进门 开展 新航', '');
INSERT INTO public.news VALUES (951, '山东省实验中学教育集团济南新航实验外国语学校2020年面向全省自主招生方案（高中部）', '', '一、招生计划济南新航实验外国语学校高中部2020年面向全省（不含济南市）招收高一新生，指导性计划普通班30名、融合课程班30名。二、报名要求    1.报名条件：2020年应届初中毕业生，思想品德优秀，身体健康，具备2020年参加山东各地市高中统一招生考试报名资格。 　 2.报名方式：采取网上报名。 　考生登录山东省实验中学教育集团官方网站（http：//sdshiyan.jinan.cn/），点...', '', '<p><strong><span>一、招生计划</span></strong></p><p><span>济南新航实验外国语学校高中部2020年面向全省（不含济南市）招收高一新生，指导性计划普通班30名、融合课程班30名。</span></p><p><strong><span>二、报名要求</span></strong></p><p><span>&nbsp;&nbsp;</span><span>&nbsp; 1.</span><span>报名条件：2020年应届初中毕业生，思想品德优秀，身体健康，具备2020年参加山东各地市高中统一招生考试报名资格。<br/> 　 2.报名方式：采取网上报名。<br/> 　考生登录山东省实验中学教育集团官方网站（http：//sdshiyan.jinan.cn/），点击校园动态“济南新航实验外国语学校报名端口”，按要求填写信息。</span></p><p><strong><span>三、网上报名时间</span></strong></p><p><span>2020</span><span>年7月11日12：00至7月16日17：00。<br/> 　　学校对网上报名考生的报名信息进行审查，请报名同学于7月17日8：00——17：00访问山东省实验中学教育集团官方网站（http：//sdshiyan.jinan.cn/），点击“济南新航实验外国语学校报名端口”查询并打印准考证。</span></p><p><strong><span>四、组织考查</span></strong></p><p><span>1.</span><span>考查时间：7月18日；<br/> &nbsp; &nbsp; &nbsp;2.考查内容：侧重学科知识、语言文字运用能力、阅读分析能力、逻辑分析能力、语言表达能力考查；</span></p><p><span>3.</span><span>地点：济南新航实验外国语学校（济南市经十东路27803号）；</span></p><p><span>4.</span><span>要求：考生凭居民身份证和准考证参加考查，没有办理身份证的考生，请到当地派出所办理临时身份证或带照片的户籍证明。</span></p><p><strong><span>五、成绩查询及录取</span></strong></p><p><span>1.</span><span>成绩查询：请考生于考查结束后，关注济南新航实验外国语学校官微，查看成绩查询时间。按照查询时间登录山东省实验中学教育集团官方网站（http：//sdshiyan.jinan.cn/）进行成绩查询。<br/> 　　2.录取流程：根据学生志愿类别，按照学校自主考查成绩（含面试）由高到低进行录取。</span></p><p><span>招生咨询电话：</span>高中普通班：0531-59562266&nbsp; &nbsp; &nbsp;高中融合班：0531-59562288</p><p><span>：</span><br/></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '赵昕晨', '新航实验外国语学校', '全省 新航 面向 实验 外国语', '');
INSERT INTO public.news VALUES (952, '济南新航实验外国语学校2020年面向济南市自主招生方案（高中部）', '', '一、招生计划济南新航实验外国语学校高中部2020年面向济南市招收高一新生指导性计划90名（含普通班60名和国际融合课程班30名）。二、报名要求1.报名条件：2020年应届初中毕业生，思想品德优秀，身体健康，参加济南市初中学业水平考试并具备普通高中录取条件的济南市应届初中毕业生。 　　2.报名方式：采取网上报名。考生登录山东省实验中学教育集团官方网站（http：//sdshiyan.jinan.cn...', '', '<p><strong><span>一、招生计划</span></strong></p><p><span>济南新航实验外国语学校高中部2020年面向济南市招收高一新生指导性计划90名（含普通班60名和国际融合课程班30名）。</span></p><p><strong><span>二、报名要求</span></strong></p><p><span>1.</span><span>报名条件：2020年应届初中毕业生，思想品德优秀，身体健康，参加济南市初中学业水平考试并具备普通高中录取条件的济南市应届初中毕业生。<br/> 　　2.报名方式：采取网上报名。考生登录山东省实验中学教育集团官方网站</span></p><p><span>（http：//sdshiyan.jinan.cn/），点击校园动态“新航实验高中部市招报名端口”，按要求填写信息。</span></p><p><strong><span>三、网上报名时间</span></strong></p><p><span>　&nbsp; 7月19日8：00至7月25日17：00。</span></p><p><strong><span>四、准考证打印</span></strong></p><p><span>7</span><span>月28日8：00-17：00登录报名系统，查询并打印准考证。</span></p><p><strong><span>五、组织考查</span></strong></p><p><span>1.</span><span>考查时间：7月29日（以准考证通知时间为准）。<br/> &nbsp; &nbsp; &nbsp;2.考查内容：普通班物理+化学笔试（共120分）、国际融合课程班英语笔试（共120分）。</span></p><p><span>3.</span><span>地点：济南新航实验外国语学校（济南市经十东路27803号）。<br/> &nbsp;&nbsp; &nbsp; &nbsp;4.要求：考生凭居民身份证和准考证参加考查（详见准考证）。</span></p><p><strong><span>六、成绩查询及录取</span></strong></p><p><span>1.</span><span>成绩查询：请考生于7月30日下午14：00后登录报名系统查询成绩。<br/> 　　2.录取流程：根据学生志愿类别，按照学校自主考查成绩与初三学业水平考试成绩相加计算综合成绩，按照综合成绩由高到低进行录取。7月31日上午开始确认录取交费，最终录取名单将按有关要求上报市中招办。</span></p><p><span>招生咨询电话：</span>高中普通班：0531-59562266&nbsp; &nbsp; &nbsp;高中融合班：0531-59562288</p><p><span><br/></span><br/></p><p><span><br/></span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '赵昕晨', '新航实验外国语学校', '济南市 学校 面向 外国语 自主', '');
INSERT INTO public.news VALUES (953, '小升初来了! 济南新航实验外国语学校启动初中部2020年入学申请信息登记', '', '亲爱的家长朋友：您好！感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。新航实验是山东省实验中学与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制管理，山东省实验中学全面负责新航实验教育教学工作，与省实验中学一脉相承、资源共享，是名副其实的“省实验+”。秉持“日新博学，志航天下”的校训和“让每一个生命都精彩绽放...', '', '<p><span>亲爱的家长朋友：</span></p><p><span>您好！</span></p><p><span>感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。</span></p><p><span>新航实验是山东省实验中学与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制管理，山东省实验中学全面负责新航实验教育教学工作，与省实验中学一脉相承、资源共享，是名副其实的“省实验+”。秉持“日新博学，志航天下”的校训和“让每一个生命都精彩绽放”的办学理念，新航实验为每位学生提供独一无二、量身定制的教育，旨在培养尚德求思、卓越笃行、面向未来的“齐鲁君子 世界公民”。</span></p><p><span>如果您的孩子身心健康、思想品德优秀、综合素养突出，是具有济南市户籍或学籍（招收符合济南市外来务工子女入学政策的毕业生）的2020年应届小学毕业生，并有意向到新航实验初中部就读，请登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn）点击“新航实验初中部2020年入学申请”，完成信息注册。</span></p><p><span>信息注册系统开放时间为2020年6月30日10：00至7月4日24:00,届时系统将自动关闭。注册时请提前准备孩子的近期一寸免冠电子版照片方便上传，请自行设定密码并记住，在确定填写信息真实无误后，提交并打印注册信息单，以便后期招生录取时使用。</span></p><p><span>招生咨询电话：0531-59516688</span></p><p><span>再次感谢您对新航实验的信任，顺祝孩子学业有成！</span></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '赵昕晨', '新航实验外国语学校', '初中部 外国语 学校 启动 实验', '');
INSERT INTO public.news VALUES (954, '小学部来啦！济南新航实验外国语学校2020年开始招收适龄儿童', '', '亲爱的家长朋友：您好！感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。新航实验是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制（小学可走读）管理，山东省实验中学全面负责新航实验教育教学工作，与实验中学一脉相承、资源共享，是名副其实的“省实验+”。秉持“日新博学，志航天下”的校训和“让...', '', '<p><span>亲爱的家长朋友：</span></p><p><span>您好！</span></p><p><span>感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。</span></p><p><span>新航实验是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制（小学可走读）管理，山东省实验中学全面负责新航实验教育教学工作，与实验中学一脉相承、资源共享，是名副其实的“省实验+”。秉持“日新博学，志航天下”的校训和“让每一个生命都精彩绽放”的办学理念，新航实验为每位学生提供独一无二、量身定制的教育，旨在培养尚德求思、卓越笃行、面向未来的“齐鲁君子 世界公民”。</span></p><p><span><br/></span></p><p><a href="images/2102221116206637582.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2102221116206637582.jpg" width="399" height="254"/></a><span></span></p><p><span>（小学部教学楼）</span></p><p><a href="images/14c6ccb4be2f4c22b66d98e82260c50e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_14c6ccb4be2f4c22b66d98e82260c50e.jpg" width="400" height="273"/></a></p><p><span><span>（小学部宿舍楼）</span></span></p><p><a href="images/749d2ebfd6dc46a694c7b9aab5081bb8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_749d2ebfd6dc46a694c7b9aab5081bb8.jpg" width="400" height="300"/></a></p><p><span>（小学部教室）</span></p><p><a href="images/6007114cba324f68bfe321db12f85cc3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6007114cba324f68bfe321db12f85cc3.jpg" width="400" height="300"/></a></p><p><span>（小学部女生宿舍）</span></p><p><a href="images/9cca03d3445047d782b5b1a237e7965d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9cca03d3445047d782b5b1a237e7965d.jpg" width="400" height="318"/></a></p><p><span>（小学部男生宿舍）</span></p><p><span>如果您的孩子<strong>年满六周岁（2014年8月31日（含）前出生）</strong>，并有意向让孩子到新航实验就读，请登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn）点击<strong>“新航实验小学部2020年适龄儿童入学申请”</strong>，完成信息注册。</span></p><p><strong><span>信息注册系统开放时间为2020年6月20日12：00至6月24日24:00</span></strong><span>。注册时请提前准备孩子的<strong>近期一寸免冠电子版照片</strong>方便上传，请自行设定密码并记住，在确定填写信息真实无误后，提交并打印注册信息单，以便后期招生录取时使用。</span></p><p><span>招生咨询电话：0531-59557766</span></p><p><span>再次感谢您对新航实验的信任，顺祝孩子健康成长！</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '/uploads/migration/images/2102221116206637582.jpg', NULL, true, '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '2021-02-22 08:00:00+08', '赵昕晨', '新航实验外国语学校', '外国语 实验 新航 学校 招收', '');
INSERT INTO public.news VALUES (955, '济南新航实验外国语学校2019年面向全省自主招生方案 （高中部）', '', '一、招生计划济南新航实验外国语学校高中部2019年面向全省招收高一新生指导性计划90名（含融合课程班30名）。二、报名要求1.报名条件：2019年应届初中毕业生，思想品德优秀，身体健康，具备2019年参加各地市高中统一招生考试报名资格。2.报名方式：采取网上报名。考生登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/），点击校园动态“济南新航实验外国语学校报名端...', '', '<p><strong><span>一、招生计划</span></strong></p><p><span>济南新航实验外国语学校高中部2019年面向全省招收高一新生指导性计划90名（含融合课程班30名）。</span></p><p><strong><span>二、报名要求</span></strong></p><p><span>1.</span><span>报名条件：2019年应届初中毕业生，思想品德优秀，身体健康，具备2019年参加各地市高中统一招生考试报名资格。</span></p><p><span>2.</span><span>报名方式：采取网上报名。考生登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/），<strong>点击校园动态</strong>“济南新航实验外国语学校报名端口”，按要求填写信息。</span></p><p><span>网上报名时间：<strong>2019年6月4日8:00至6月14日17:00。</strong></span></p><p><span>学校对网上报名考生的报名信息进行审查，请报名同学于6月16日10:00后访问山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/），点击“济南新航实验外国语学校报名端口”查询并打印准考证。</span></p><p><strong><span>三、组织考查</span></strong></p><p><span>1.考查时间：具体实施时间依据教育行政部门批复为准，详见准考证。</span></p><p><span>2.考查内容：</span><span>侧重逻辑推理思维、科学知识、语言文字运用能力、阅读分析能力、审辩思维、价值判断考查</span></p><p><span>3.地点：山东省实验中学中心校区（济南市经七路73号）</span></p><p><span>4.要求：考生凭居民身份证和准考证参加考查，没有办理身份证的考生，请到当地派出所办理临时身份证或带照片的户籍证明。</span></p><p><strong><span>四、成绩查询及录取</span></strong></p><p><span>1.</span><span>成绩查询：考生可于考查结束两天以后，登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/）进行成绩查询。</span></p><p><span>2.</span><span>录取流程：根据学生志愿类别，按照考查成绩由高到低进行录取。</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-02-21 08:00:00+08', '2021-02-21 08:00:00+08', '2021-02-21 08:00:00+08', '赵昕晨', '新航实验外国语学校', '学校 全省 面向 外国语 自主', '');
INSERT INTO public.news VALUES (956, '济南新航实验外国语学校初中部 2019年自主招生方案', '', '一、招生计划济南新航实验外国语学校初中部2019年招收初一新生指导性计划120名。二、报名要求1.报名条件：主要面向济南市七区（市中、历下、槐荫、天桥、历城、高新和南山),具有学籍的2019年应届小学毕业生，思想品德优秀，身体健康。2.报名方式：（1）网上申请登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/）进行网上申请。时间：2019年6月30日8:30 -...', '', '<p><strong><span>一、招生计划</span></strong></p><p><span>济南新航实验外国语学校初中部2019年招收初一新生指导性计划120名。</span></p><p><strong><span>二、报名要求</span></strong></p><p><span>1.</span><span>报名条件：主要面向济南市七区（市中、历下、槐荫、天桥、历城、高新和南山),具有学籍的2019年应届小学毕业生，思想品德优秀，身体健康。</span></p><p><span>2.</span><span>报名方式：</span></p><p><span>（1）网上申请</span></p><p><span>登录山东省实验中学教育集团官方网站（http://sdshiyan.jinan.cn/）进行网上申请。</span></p><p><strong><span>时间：2019年6月30日8:30 - 7月5日17:00。</span></strong></p><p><span>网上申请完成后请关注山东省实验中学及济南新航实验外国语学校官方微信，及时了解学校相关招生信息。</span></p><p><span>（2）现场报名。网上申请成功后，请于7月4日—6日（8:30—17:00），带齐报名材料到山东省实验中学中心校区（济南市经七路73号）实验科苑二层多媒体教室（济南新航实验外国语学校初中部招生报名处）现场报名。</span></p><p><span>附：需要的报名材料</span></p><p><span>（1）学籍号，共19位，例如 2013370102002010456，可以联系学校班主任获取。</span></p><p><span>（2）考生个人简介一份，要求学生用方格稿纸书写，400字以内。</span></p><p><span>（3）户口本及身份证复印件，户口本索引页、父母页以及考生页复印在一张A4纸（可正反面），身份证正反面复印到一张A4纸。</span></p><p><span>（4）能体现考生特长及能力的证明材料（荣誉证书需是2016.1—2019.7期间获得，查原件，留复印件），最多五件。</span></p><p><span>请将材料按(2)—(4)的顺序装订成册。</span></p><p><span>3.</span><span>材料审核：</span></p><p><span>学校招生中心根据学校育人目标和办学特色对上报的材料进行初审。7月9日8:00—17:00，考生登录山东省实验中学教育集团官网查询初审结果。</span></p><p><strong><span>三、录取时间</span></strong></p><p><span>7</span><span>月13日，山东省实验中学教育集团官网公布预录名单。</span></p><p><span>7</span><span>月16日8：00，组织录取新生办理缴费、量制校服、领取《入学通知书》等入学手续。</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2021-02-21 08:00:00+08', '2021-02-21 08:00:00+08', '2021-02-21 08:00:00+08', '赵昕晨', '新航实验外国语学校', '学校 初中部 外国语 自主 实验', '');
INSERT INTO public.news VALUES (957, '对照数据来会商，“云端”相聚再升级——新航实验初中部举行5.0版线上家长会', '', '                 在这个“疫”样假期里，为增进家校联系，同时结合当前常态化疫情防控工作的需要，1月28日~30日，济南新航实验外国语学校初中部开展了“三味三境”5.0版家长会，各班主任及任课教师通过线上的方式与家长见面，就学生这一学期在校的学习和生活以及日后的培养目标等方面进行了沟通交流。虽然是线上家长会，但老师们没有丝毫怠慢，利用一周时间进行了充足的会前准备。大家经过讨论、分析和...', '', '<p><span>&nbsp;</span><span>&nbsp; &nbsp; &nbsp;</span><span>&nbsp;</span><img title="" src="/uploads/migration/images/s_c05d7a0c78064348865c98e19684e5e7.jpg" width="465" height="300" alt=""/>&nbsp; &nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_04d61f34fc5c459fbeaa652b9d851fb1.jpg" width="400" height="300" alt=""/></p><p><span>&nbsp; &nbsp; &nbsp; <span>在这个“疫”样假期里，为增进家校联系，同时结合当前常态化疫情防控工作的需要，1月28日~30日，济南新航实验外国语学校初中部开展了“三味三境”5.0版家长会，各班主任及任课教师通过线上的方式与家长见面，就学生这一学期在校的学习和生活以及日后的培养目标等方面进行了沟通交流。</span></span></p><p><span></span></p><p><span>虽然是线上家长会，但老师们没有丝毫怠慢，利用一周时间进行了充足的会前准备。大家经过讨论、分析和成绩汇总，综合学生这一学期的学习、生活、阅读、课外活动等多方面表现，为每位学生制作了“新航大脑”专属档案，其中包含五份重量级数据报告，智能化学科成绩分析雷达图、宿舍表现分析表、图书借阅数据、电子班牌考勤记录、家庭教育环境分析报告，这种横向及纵向的数据分析，为学生日后学习和发展指明了方向，有助于他们更精准地规划自己的未来目标。</span></p><p><span>当学生们打开自己档案袋时，还会收到老师精心准备的一份小惊喜——花草种，希望这份种子能够为孩子们的假期学习生活带来一丝放松，同时也让大家利用这难得的长假期亲眼见证生命的神奇和精彩，更加懂得珍惜当下。</span></p><p><img title="" src="/uploads/migration/images/s_7f4d0fbb18294551b2379ad627a1e02c.jpg" width="400" height="266" alt=""/>&nbsp;&nbsp;<a href="images/dd90dffc014c45a1bff03cf3d4757bff.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_dd90dffc014c45a1bff03cf3d4757bff.jpg" width="400" height="266"/></a></p><p><a href="images/289892f5d10b4441ae028365fea671d8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_289892f5d10b4441ae028365fea671d8.jpg" width="350" height="358" alt=""/></a><span></span><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<a href="images/28394e0a9f5b47278975950bd221eeed.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_28394e0a9f5b47278975950bd221eeed.jpg" width="400" height="300"/></a></span></p><p><span></span></p><p><span>此次家长会仍延续新航实验“三味三境”家长会的一对一形式，通过提前预约的方式，给每位家长和各科老师预留了充足的沟通时间，双方从学习情况分析、学科知识重点与学习建议等多方面进行了深入探讨。同时，班主任还对学生的习惯培养、寒假活动、安全问题等做了重点提醒，特别是做好疫情防护工作，确保学生的假期安全。</span></p><p><span>为及时关注每个学生的假期情况，不让任何一个孩子掉队，班主任老师还提出采取一对一“云家访”的形式，将针对学生作息习惯、作业情况、身心健康等方面及时与家长联系，双方形成“育人共同体”，确保学生假期的学习和生活健康有序地进行。</span></p><p><span><a href="images/b44adf00842f41ddbfc362b70fab8212.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b44adf00842f41ddbfc362b70fab8212.jpg" width="400" height="266"/></a>&nbsp; &nbsp; <a href="images/d04d3ebf034d473f8132779af56a1c54.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d04d3ebf034d473f8132779af56a1c54.jpg" width="400" height="266"/></a></span></p><p><span>&nbsp; &nbsp; &nbsp; <span>本次线上家长会搭建起非常时期家校沟通的新模式，既加深了老师对学生的了解，也解答了家长对学校和孩子学习等方面的疑问，隔屏不隔爱，为孩子成长提供更好的支持，获得了家长们的一致点赞。</span></span></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/dd90dffc014c45a1bff03cf3d4757bff.jpg', NULL, true, '2021-02-01 08:00:00+08', '2021-02-01 08:00:00+08', '2021-02-01 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航 相聚 升级 云端 实验', '');
INSERT INTO public.news VALUES (958, '这样的家访很走心~新航实验小学部开展“两言一语”别样家访', '', '                             家访的目的是什么？怎样利用有限的时间达到最好的沟通效果？带着这样的思考，济南新航实验外国语学校小学部的老师们精心准备了一场别样的家访。通过一学期对学生各方面的观察了解，将学校、家庭、学生三方的育人目标进行整合统一，以更好地满足学生的个性化发展和整体协调性成长。怀着这样的初衷，“两言一语”探讨式家访便是一次有效的尝试。  正式家访前，学校就与...', '', '<p><span></span></p><h2 class="rich_media_title"><span></span></h2><p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<img title="" src="/uploads/migration/images/s_2d9f48b1057142be96eb98d14fd42f6d.jpg" width="446" height="331"/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<a href="images/1279ead1aeee4cb0b0a1d9e7b38aea38.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1279ead1aeee4cb0b0a1d9e7b38aea38.jpg" width="500" height="327"/></a></p><p><span>家访的目的是什么？怎样利用有限的时间达到最好的沟通效果？带着这样的思考，济南新航实验外国语学校小学部的老师们精心准备了一场别样的家访。通过一学期对学生各方面的观察了解，将学校、家庭、学生三方的育人目标进行整合统一，以更好地满足学生的个性化发展和整体协调性成长。怀着这样的初衷，“两言一语”探讨式家访便是一次有效的尝试。</span></p><p><span><img title="" src="/uploads/migration/images/s_86825623bd974fe390771c44804033fc.jpg" width="509" height="240"/>&nbsp; <a href="images/624ecb5592f349f687ba3271fc195949.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_624ecb5592f349f687ba3271fc195949.jpg" width="506" height="240"/></a></span></p><p><span>正式家访前，学校就与小学部家长委员会成员进行了沟通，提供了线上、入户、不进门三种方式，由家委会组织家长讨论并根据个人情况进行自由选择及预约登记。小学部老师们全员参与，集体备课，认真分析每一个拟与家长沟通的要点。除班主任以外，各学科及生活老师分别加入各家访小组，家访过程中就学科、体能、生活、艺术、沟通、合作等多方面与家长进行探讨，既让家长全面了解孩子这一学期的成长情况，也实现了家校对于孩子培养目标的统一。</span></p><p><span>&nbsp; &nbsp;<a href="images/ea1b18958d634438b5236f5d52ecf004.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ea1b18958d634438b5236f5d52ecf004.jpg" width="500" height="375"/></a></span></p><p><span>家访过程中，老师们为每一位学生准备了一个信封，里面有三张词卡，前两张词卡颜色鲜艳，代表着学生目前阶段表现较突出的两种能力素养，一张来自于第一次家长会时家长写下的对孩子的培养目标，另一张则是老师们综合考量后认为孩子表现极为优秀之处。第三张词卡颜色较深，代表着老师认为孩子们还有提升空间的地方，背面还有三句教师寄语，“你试一试”“你可以的”“你觉得呢？”。当孩子缺乏自信时，“你试一试”，鼓励他勇敢地尝试和挑战；当孩子遇到挫折和困难时，“你可以的”，让他重新鼓起勇气，突破自我；当孩子面对一个决定时，“你觉得呢”，给他更多独立思考的空间和机会。</span></p><p><a href="images/aac7ac69880040e0beaf88f0252ab3f9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_aac7ac69880040e0beaf88f0252ab3f9.jpg" width="500" height="340"/></a><span></span></p><p><span>&nbsp; 不进门家访把沟通地点选在了美术馆、博物馆、小区的文化场馆等地方，更是获得了家长们的一致好评。这样的沟通交流更加愉悦舒畅，这样的意见建议的反馈更加真实自然，这样的家校合力，会更有利于孩子们全面而个性化的发展。</span></p><h2 class="rich_media_title"><span></span><br/></h2><meta name="ContentEnd">', '', 'news', '/uploads/migration/images/1279ead1aeee4cb0b0a1d9e7b38aea38.jpg', NULL, true, '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (959, '用细菌也能画画？新航实验微生物课这样做！', '', '色彩浓厚的油彩勾勒出了梵高脑海中似真似幻的《星空》，描绘出了达芬奇心中最美的《蒙娜丽莎》；淡逸劲爽的竹帛丹青挥洒出徐悲鸿笔下栩栩如生的《八骏》，涂抹出齐白石眼里可爱至极的《墨虾》。可是谁能想到，平日里总是被人视为腌臜之物的细菌和真菌，也能成为我们手下勾勒色彩的颜料。         新航实验秉承“让每个生命都精彩绽放”的教学理念，在本学期开设了多门校本课程，其中生物组开设的《微生物绘画创作》课程很...', '', '<p><span><a href="images/e29cf8849b1943948fd95d51b1fac7a4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e29cf8849b1943948fd95d51b1fac7a4.jpg" width="500" height="375"/></a></span></p><p><span>色彩浓厚的油彩勾勒出了梵高脑海中似真似幻的《星空》，描绘出了达芬奇心中最美的《蒙娜丽莎》；淡逸劲爽的竹帛丹青挥洒出徐悲鸿笔下栩栩如生的《八骏》，涂抹出齐白石眼里可爱至极的《墨虾》。可是谁能想到，平日里总是被人视为腌臜之物的细菌和真菌，也能成为我们手下勾勒色彩的颜料。</span></p><p><img title="" src="/uploads/migration/images/s_3b2248b350634823acbbab827615c57a.jpg" width="350" height="350" alt=""/>&nbsp; &nbsp; &nbsp;<a href="images/c83666ad110c43ffaef2bf0309f3dd7b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c83666ad110c43ffaef2bf0309f3dd7b.jpg" width="350" height="351" alt=""/></a></p><p><span>&nbsp;<img title="" src="/uploads/migration/images/s_368a5d8a7599488096148ce2f377946f.jpg" width="350" height="350" alt=""/>&nbsp;<img title="" src="/uploads/migration/images/s_0698ccc03db04f21ab4f8ff07f9a2ef8.jpg" width="350" height="350" alt=""/>&nbsp; </span></p><p><span>新航实验秉承“让每个生命都精彩绽放”的教学理念，在本学期开设了多门校本课程，其中生物组开设的《微生物绘画创作》课程很受学生欢迎。同学们经过学习和操作训练，掌握了部分微生物学知识，具备了相当的微生物操作基础。实验技术从零开始，大家在几周之内消化吸收了大量知识，并利用两周时间进行创意方案的绘制和菌种的培养、作画。</span></p><p><span><span>“看似是简单的图案，这可不是画出来，而是通过无菌操作，经过细菌的纯培养，在培养基上长出来的！”说起学生的作品，指导老师姚明霞、李苗苗和董冬都很骄傲。</span></span></p><p><span><span><a href="images/79ded524762b49b8a53bb4550b937739.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_79ded524762b49b8a53bb4550b937739.jpg" width="500" height="375"/></a></span></span></p><p><span><span><img title="" src="/uploads/migration/images/s_81abaf5ee3fa4744951bc89d1e57ce9a.jpg" width="350" height="466" alt=""/>&nbsp; <a href="images/93498e319fbe4ce2b8e86dd99b180aa9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_93498e319fbe4ce2b8e86dd99b180aa9.jpg" width="350" height="466" alt=""/></a></span></span></p><p><span>制作过程中，同学们经过前期试做，不断摸索，一次次重来，最终克服困难，提交了作品。虽然由于对这种作画方式的不熟悉导致有些作品不太满意，但是通过这种新颖的学习方式，学生们收获很多，并且还有机会在下学期的生物实验中为其他同学进行试验示范。</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/e29cf8849b1943948fd95d51b1fac7a4.jpg', NULL, true, '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '细菌 微生物 新航 画画 实验', '');
INSERT INTO public.news VALUES (960, '再传捷报！新航实验学子斩获国际生物奥赛大奖', '', '       日前，又有国际性赛事传来喜讯！在2021生物与健康未来领袖挑战（HOSA 2021）区域站中，济南新航实验外国语学校国际教育中心董朝伦、栾奕柠两名同学分别斩获全国铜奖和区域铜奖，并全部晋级全国展比赛！同时，董朝伦同学还在2020英国中级生物奥赛（IBO）中斩获银牌！  学科竞赛是国际教育很重要的一项学生课外活动，也是学习的重要组成部分，不仅能检验学生科学思维、逻辑推理和知识点归纳能力...', '', '<p><img title="" src="/uploads/migration/images/s_a7d0a2ac8c7d406ca8ecaf61a2f1f10f.jpg" width="526" height="350" alt=""/>&nbsp; &nbsp;&nbsp;&nbsp; &nbsp;<img title="" src="/uploads/migration/images/s_da35c4deb3c74997925a0fc91dfaacb6.jpg" width="306" height="350" alt=""/></p><p><span><br/></span></p><p><span>日前，又有国际性赛事传来喜讯！在2021生物与健康未来领袖挑战（HOSA 2021）区域站中，济南新航实验外国语学校国际教育中心董朝伦、栾奕柠两名同学分别斩获全国铜奖和区域铜奖，并全部晋级全国展比赛！同时，董朝伦同学还在2020英国中级生物奥赛（IBO）中斩获银牌！</span></p><p><br/></p><p><a href="images/d1596df7f82d40749c5bee4ee6ad32da.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d1596df7f82d40749c5bee4ee6ad32da.jpg" width="451" height="300" alt=""/></a><span>&nbsp; </span><a href="images/79ded524762b49b8a53bb4550b937739.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_79ded524762b49b8a53bb4550b937739.jpg" width="400" height="300" alt=""/></a></p><p><span><br/></span></p><p><span>学科竞赛是国际教育很重要的一项学生课外活动，也是学习的重要组成部分，不仅能检验学生科学思维、逻辑推理和知识点归纳能力，同时还能增加知识掌握的广度和深度。在备赛过程中，学生的潜心研究至关重要，但老师的悉心指导与陪伴也不可忽视，国际教育中心生物教师王晓婷和外教Mike给予了学生充分的支持和帮助，挖掘学生的好奇心，培养学生刨根问底的学习态度，同时，营造特色的课堂气氛，通过实验和探究，亲身体验生物学科中的无穷奥秘。</span></p><p><span>凭借良好的学术能力以及综合素养，董朝伦、栾奕柠两位同学在国际赛场上脱颖而出，斩获多个奖项，接下来，他们还将代表学校参加HOSA 2021中国站总决赛，期待他们在更广阔的舞台上绽放精彩！</span></p><p><span>获奖感言</span></p><p><span>栾奕柠：HOSA是我第一次参加生物领域的比赛，我选择CE行为健康和ATC生物，完全取决于我对心理学和生物学的浓厚兴趣。HOSA带给我最大的挑战就是要记忆很多新的知识，例如不同心理疾病的原因、症状和不同的治疗方法等，还要将独立的知识进行有规律的联结，因此思维导图是我备战的法宝。</span></p><p><span>董朝伦：很荣幸能获得HOSA和IBO的奖项，在备考过程中，我收获了学习生物的乐趣，尤其是在备考HOSA营养学的时候，不仅增加了我的生物学科素养，同样也让我知道了如何在生活中均衡营养。</span></p><p><span>赛事介绍</span></p><p><span>HOSA生物与健康未来领袖挑战（HOSA-Future Health Professionals）是美国教育部官方认证、全球极具影响力的生物与健康领域学生成长平台。44年的举办历史中，每年全球超过25万名学生参与其中，HOSA2021挑战季共有超过1000名中国学生参与。</span></p><p><span>英国中级生物奥赛(Intermediate Biology Olympiad)不仅考察学生的生物学知识，还鼓励他们在校外继续学习生物科学，成绩优秀者将增加世界名校医学、生物等理科专业申请优势。2020年共有来自全国116所国际学校和重点中学的400多名学生参赛。</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/d1596df7f82d40749c5bee4ee6ad32da.jpg', NULL, true, '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '斩获 国际 学子 生物 实验', '');
INSERT INTO public.news VALUES (961, '期末巧释压——老师化身“皮卡丘”和“大棕熊”，新航实验上演快闪大片燃爆全场', '', '期末来临，学生们都在紧锣密鼓地准备考试，然而，长时间的“拉锯战”让他们在紧张的氛围中压力满满。为帮助学生释放压力，保证更高的期末复习效率，日前，济南新航实验外国语学校初中部组织了一场特殊的释压快闪活动……午餐时间，老师们借着要宣布考试事宜的理由将学生们全部留在食堂，正当大家都在猜测考试将有何变化时，两只超大“萌宠”突然走进来，瞬间引起全场欢呼。学生们一拥而上，围着“皮卡丘”和“大棕熊”高兴地蹦跳着...', '', '<p><a href="images/c059bb1c725345a1a2e1a91fadbe4ea6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c059bb1c725345a1a2e1a91fadbe4ea6.jpg" width="461" height="451"/></a></p><p><span>期末来临，学生们都在紧锣密鼓地准备考试，然而，长时间的“拉锯战”让他们在紧张的氛围中压力满满。为帮助学生释放压力，保证更高的期末复习效率，日前，济南新航实验外国语学校初中部组织了一场特殊的释压快闪活动……</span></p><p><span>午餐时间，老师们借着要宣布考试事宜的理由将学生们全部留在食堂，正当大家都在猜测考试将有何变化时，两只超大“萌宠”突然走进来，瞬间引起全场欢呼。学生们一拥而上，围着“皮卡丘”和“大棕熊”高兴地蹦跳着，纷纷合影，其实，他们的扮演者是学生们最熟悉的“超哥”和“安哥”，数学老师杨超和历史老师安浩客串玩偶，引得学生们兴奋不已。</span></p><p><span><a href="images/fe5fbdcb8c674402a05b0300df1a8980.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fe5fbdcb8c674402a05b0300df1a8980.jpg" width="400" height="226" alt=""/></a>&nbsp;<a href="images/2155d31db9984a46b84ada03689ab64f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2155d31db9984a46b84ada03689ab64f.jpg" width="400" height="226" alt=""/></a></span></p><p></p><section><section><section><section><p><span><a href="images/04451eeaef3e408db77f4af7724de6cd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_04451eeaef3e408db77f4af7724de6cd.jpg" width="400" height="226" alt=""/></a>&nbsp;<a href="images/70e6c15ec555469a8c6a2a5c38685f3d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_70e6c15ec555469a8c6a2a5c38685f3d.jpg" width="400" height="226" alt=""/></a></span></p><p><span>紧接着，初中部的老师们手捧彩色气球出场，每个人手里拿着为期末考试定制的啪啪圈，吸引了所有学生的注意。“祝愿你：该会的题都对，不该丢的分不丢！”“有平常心，就会有最佳的发挥；怀自信心，便能跨越每一个障碍！”“人易我易，我不大意；人难我难，我不畏难”，啪啪圈上的每一句话都说到了学生们的心里。老师们贴心地为每位学生带上啪啪圈，鼓励大家调整好心态，以最佳的状态迎接期末，现场的气氛被推向高潮。</span></p><p><span>这份“小惊喜”时间虽然很短，但却能让学生们从考前的紧张中获得一些难得的释放。每个孩子脸上都洋溢着幸福的笑容，很多学生直呼，“惊喜来的太突然，老师们太用心，在新航太幸福了！”</span></p></section></section></section></section><p></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '/uploads/migration/images/c059bb1c725345a1a2e1a91fadbe4ea6.jpg', NULL, true, '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '上演 棕熊 新航 实验 快闪', '');
INSERT INTO public.news VALUES (962, '学校简介', '', '让每一个生命都精彩绽放济南新航实验外国语学校是由山东省实验中学与山东出版集团强强联合、精心打造的一所小初高十二年一贯制学校，占地面积约227亩，总建筑面积7.7万平方米，可同时容纳1800名在校生。截至2021年7月，现有在校生1300余名、教职工260余名。校园分为三大板块——教学区、活动区和生活区，各功能室和场馆设施先进。作为山东省实验中学教育集团成员校，新航实验是山东省实验中学课程文化、组织...', '', '<p><span>让每一个生命都精彩绽放</span></p><p><span><img title="" src="/uploads/migration/images/s_e771f529591e4b37b17d76019a45b46f.jpg" width="600" height="400" alt=""/></span></p><p><span></span></p><p><span>济南新航实验外国语学校是由山东省实验中学与山东出版集团强强联合、精心打造的一所小初高十二年一贯制学校，占地面积约227亩，总建筑面积7.7万平方米，可同时容纳1800名在校生。截至2021年7月，现有在校生1300余名、教职工260余名。校园分为三大板块——教学区、活动区和生活区，各功能室和场馆设施先进。</span></p><p><span>作为山东省实验中学教育集团成员校，新航实验是山东省实验中学课程文化、组织文化和管理文化的传承、发展与创新者，是名副其实的“实验+”。以“日新博学，志航天下”校训为精神追求，秉持“让每一个生命都精彩绽放”的育人理念，坚持做“温和而又坚定”的教育，突出中西交融、文理并重、多元融合的办学特色，致力于培育搏击风浪、勇立潮头的“齐鲁君子、世界公民”。</span></p><p><span>学校全学段实行小班化教学，依托1:5的高师生比，主打精准个性、一生一案的培养模式，为每位学生配备学业导师、升学导师、生活导师、专职心理咨询师，为学生做好学业上的辅导、升学上的引导、生活上的指导、心理上的疏导，打造独一无二、量身定制的精品教育。</span></p><p><span>新航实验教育教学工作由省实验中学全面负责，校长、管理团队及骨干教师皆由省实验中学统一调配。来自国内外一流大学、世界名校的名师团队中，既有众多荣誉等身的特级、正高级教师，又有省教学能手、全国优质课评比一等奖、省部级优课获得者。</span></p><p><span>新航实验探索“引领教育”新模式，坚持五育并举，依托数理思维培养中心、科技创新培养中心（小平科创实验室）、人文素养培养中心、艺体审美培养中心、劳动教育实践基地，打造涵盖学科特长、科技创新、传统文化、艺体素养等各领域的综合体验课程群。</span></p><meta name="ContentEnd">', '', 'other', '/uploads/migration/images/s_e771f529591e4b37b17d76019a45b46f.jpg', NULL, true, '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '2021-01-28 08:00:00+08', '赵昕晨', '新航实验外国语学校', '学校 简介', '');
INSERT INTO public.news VALUES (963, '招贤纳士！2020年山东省实验中学教育集团济南新航实验外国语学校名优教师引进公告', '', '济南新航实验外国语学校，是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所12年一贯制民办非营利学校。作为山东省实验中学教育集团成员校，山东省实验中学全面负责学校的教育教学工作，校长、优秀管理团队及骨干教师皆由山东省实验中学统一调配，秉持“让每一个生命都精彩绽放”的育人理念与“齐鲁君子、世界公民”的培养目标，致力于打造一所高起点、高品位、高质量的多元化创新型学校。根据学校战略发展规划，...', '', '<p>济南新航实验外国语学校，是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所12年一贯制民办非营利学校。</p><p><a href="images/e2e28f5d9e464b68935bd72af184bcc2.jpg" target="_blank"></a><a href="images/46ff46a7804d42d08ab36659fbfcdc12.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_46ff46a7804d42d08ab36659fbfcdc12.jpg" width="500" height="281"/></a></p><p>作为山东省实验中学教育集团成员校，山东省实验中学全面负责学校的教育教学工作，校长、优秀管理团队及骨干教师皆由山东省实验中学统一调配，秉持“让每一个生命都精彩绽放”的育人理念与“齐鲁君子、世界公民”的培养目标，致力于打造一所高起点、高品位、高质量的多元化创新型学校。</p><p>根据学校战略发展规划，现面向全国公开招聘名优教师。</p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; 招聘将秉承“公开、平等、竞争、择优”原则。</span></p><p><span><a href="images/f9e355df2c3e4b998086cf4058ba328d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f9e355df2c3e4b998086cf4058ba328d.jpg" width="485" height="707"/></a></span><span><a href="images/68628f1fbb734a14bb2178e34749deaf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_68628f1fbb734a14bb2178e34749deaf.jpg" width="485" height="640"/></a></span></p><p><br/></p><p><span></span></p><p><span>1.学科教师应届毕业生年薪10万起，一级教师20万起，高级教师25万起，生活老师年薪8万起，特殊人才薪资面议，其他岗位年薪将根据学校薪酬体系入职定级。</span></p><p><span>2.五险二金（按照公务员标准缴纳）、子女就读优惠。</span></p><p><span><a href="images/1d4b84fbcb52401899b47ebad24ced00.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1d4b84fbcb52401899b47ebad24ced00.jpg" width="500" height="375"/></a><a href="images/e2e28f5d9e464b68935bd72af184bcc2.jpg" target="_blank"></a><a href="images/7d30d3b708a340cebc3ef981eb2ba6d0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7d30d3b708a340cebc3ef981eb2ba6d0.jpg" width="500" height="282"/></a></span></p><p><span></span></p><p><span>报名时间：2020.11.2—2020.11.30</span></p><p><span>报名链接：http://baoming.wiscoor.com</span></p><p><span></span><span>联系人：左老师&nbsp; 董老师</span></p><p><span>联系电话：0531-59516627</span></p><p><span>招聘报名咨询QQ群：361533803</span></p><p><span>学校地址：山东省济南市经十东路27803号</span></p><p><span><br/></span><br/></p><p><span><br/><br/></span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '/uploads/migration/images/e2e28f5d9e464b68935bd72af184bcc2.jpg', NULL, true, '2020-11-03 08:00:00+08', '2020-11-03 08:00:00+08', '2020-11-03 08:00:00+08', '王雪', '新航实验外国语学校', '学校 济南 外国语 新航 实验', '');
