INSERT INTO public.news VALUES (969, '公示', '', '       根据《中共山东省委办公厅、山东省人民政府办公厅  关于为新冠肺炎疫情防控一线医务人员办好十二件实事的通知》（鲁办发电【2020】40号）和《中共济南市委办公厅、济南市人民政府办公厅 关于强化落实疫情防控一线医务人员服务保障措施的通知》精神，以及济南市市中区卫生和计划生育监督所疫情防控一线医务人员王珊珊同志的申请，济南新航实验外国语学校拟录取王珊珊同志的子女王柯润（男，身份证号3701...', '', '<p><span>&nbsp; &nbsp; &nbsp;&nbsp; 根据《中共山东省委办公厅、山东省人民政府办公厅&nbsp; 关于为新冠肺炎疫情防控一线医务人员办好十二件实事的通知》（鲁办发电【2020】40号）和《中共济南市委办公厅、济南市人民政府办公厅 关于强化落实疫情防控一线医务人员服务保障措施的通知》精神，以及济南市市中区卫生和计划生育监督所疫情防控一线医务人员王珊珊同志的申请，济南新航实验外国语学校拟录取王珊珊同志的子女王柯润（男，身份证号370103200710290175）到学校初中部就读。现予以公示，公示期为：2020年8月18日—8月20日。</span><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;对以上情况如有异议的，请向0531—59516620反映情况。</span></p><p><span>&nbsp;</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <span>&nbsp; &nbsp; &nbsp;济南新航实验外国语学校</span></span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2020年8月17日</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-08-17 08:00:00+08', '2020-08-17 08:00:00+08', '2020-08-17 08:00:00+08', '王雪', '新航实验外国语学校', '公示', '');
INSERT INTO public.news VALUES (971, '初中部2020年入学申请信息登记', '', '山东省实验中学教育集团  济南新航实验外国语学校初中部2020年入学申请信息登记亲爱的家长朋友：       您好！‍       感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。       新航实验是山东省实验中学与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制管理，山东省实验中学全面负责新航实验教育教...', '', '<p><span>山东省实验中学教育集团 &nbsp;济南新航实验外国语学校</span></p><p><span>初中部2020年入学申请信息登记</span></p><p><span>亲爱的家长朋友：</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 您好！</span><span><span>‍</span><span></span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 感谢您对济南新航实验外国语学校的关注和对学校办学理念的认可。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 新航实验是山东省实验中学与山东出版集团强强联合、精心打造的一所高起点、现代化、高水准的十二年一贯制民办非营利学校，实行全学段小班化（每班30人）、寄宿制管理，山东省实验中学全面负责新航实验教育教学工作，与实验中学一脉相承、资源共享，是名副其实的“省实验+”。秉持“日新博学，志航天下”的校训和“让每一个生命都精彩绽放”的办学理念，新航实验为每位学生提供独一无二、量身定制的教育，旨在培养尚德求思、卓越笃行、面向未来的“齐鲁君子 世界公民”。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 如果您的孩子身心健康、思想品德优秀、综合素养突出，是具有济南市户籍或学籍（符合济南市外来务工子女入学政策的毕业生除外）的2020年应届小学毕业生，并有意向到新航实验初中部就读，请登录山东省实验中学教育集团官方网站（</span><a href="/"><span>http://sdshiyan.jinan.cn</span></a><span>）点击“新航实验初中部2020年入学申请”，完成信息注册。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 信息注册系统开放时间为2020年6月30日10：00至7月4日24:00,<strong><span>届时系统将自动关闭</span></strong>。注册时请提前准备孩子的近期一寸免冠电子版照片方便上传，请自行设定密码并记住，在确定填写信息真实无误后，<strong><span>提交并打印注册信息单</span></strong>，以便后期招生录取时使用。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 再次感谢您对新航实验的信任，顺祝孩子学业有成！</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 咨询电话：0531—59557788、59557766</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 新航实验官方微信：济南新航实验外国语学校</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 新航实验初中教育交流QQ群：981510867</span></p><p>&nbsp;</p><p><span>山东省实验中学教育集团</span></p><p><span>济南新航实验外国语学校</span></p><p><span>2020年6月29日</span></p><p></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-06-30 08:00:00+08', '2020-06-30 08:00:00+08', '2020-06-30 08:00:00+08', '王雪', '新航实验外国语学校', '信息 申请 初中部 入学 登记', '');
INSERT INTO public.news VALUES (972, '学子已归逐梦未来，新航实验举行2020年复学典礼', '', '      5月25日下午，济南新航实验外国语学校2020年度春季学期复学典礼在学校操场举行，新航实验全体师生及部分学生家长代表参加了当天的活动。    活动在嘹亮的国歌声中拉开帷幕，全体师生面向国旗高唱国歌。首先进行表彰环节，为表彰先进，发挥榜样的示范作用，学校决定对2019 年9月至今被同学们民主推选出来的徐晨曦、段淑雯等82名校级三好学生以及马骁函等11名优秀团员，华俊杰、张筱迪等20名优秀...', '', '<p>&nbsp; &nbsp; &nbsp; 5月25日下午，济南新航实验外国语学校2020年度春季学期复学典礼在学校操场举行，新航实验全体师生及部分学生家长代表参加了当天的活动。</p><p><a href="images/48f1e1e2e0664d47b31067e86830df66.jpg" target="_blank"></a><a href="images/48f1e1e2e0664d47b31067e86830df66.jpg" target="_blank"></a><a href="images/48f1e1e2e0664d47b31067e86830df66.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_48f1e1e2e0664d47b31067e86830df66.jpg" width="700" height="543"/></a></p><p><a href="images/975c7b4f22384ea48d455404cf048ea7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_975c7b4f22384ea48d455404cf048ea7.jpg" width="700" height="521"/></a></p><p>&nbsp; &nbsp; 活动在嘹亮的国歌声中拉开帷幕，全体师生面向国旗高唱国歌。首先进行表彰环节，为表彰先进，发挥榜样的示范作用，学校决定对2019 年9月至今被同学们民主推选出来的徐晨曦、段淑雯等82名校级三好学生以及马骁函等11名优秀团员，华俊杰、张筱迪等20名优秀学生干部和陈倍乐、葛沐昕等20名全面发展标兵进行表彰。有23名同学在2019-2020 学年第一学期学习成绩优异，获评“学习先锋”，同时获颁新航实验“志航奖”。</p><p><a href="images/baaadacee0c34b299b9ad5507d778624.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_baaadacee0c34b299b9ad5507d778624.jpg" width="700" height="421"/></a></p><p><a href="images/c5cb908ef27d4cd0afb848eb564ce1ac.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c5cb908ef27d4cd0afb848eb564ce1ac.jpg" width="700" height="466"/></a></p><p>&nbsp; &nbsp; 在刚刚结束的居家学习期间中，新航实验有三名学生在国际赛事中获奖，其中包括NSDA 演讲比赛全国十强于家豪，他同时还获得了英国物理挑战赛金奖，以及NSDA 辩论公开组亚军得主王艺睿、英国物理挑战赛金奖得主张修玮，张爱梅副校长代表学校宣读表彰决定。</p><p><br/></p><p>&nbsp; &nbsp; 在此前的工作中，新航实验涌现出一大批兢兢业业、无私奉献的教职员工，为表彰先进，发挥优秀榜样的引领作用，经民主投票，十位教职工获评第一届新航实验“优秀员工”，他们中既有爱生如子、深受学生爱戴的的一线教师代表，也有兢兢业业、辛勤奉献的后勤员工代表，也有尽心竭力、为学校发展贡献才智的中层干部代表。他们是：董凤菊、孙庆华、王梦雅、张杰、孙雨辰、石峰、郝海歌、李洪伟、李正华、郭斌。</p><p><a href="images/23f1a67a7d584401be3798a7e5239830.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_23f1a67a7d584401be3798a7e5239830.jpg" width="700" height="484"/></a></p><p>&nbsp; &nbsp; 在新航实验，还有一个特殊的群体，他们为这所学校付出了太多心血，奠定了这所学校的根基。从杆石桥畔到赵山之阳，从德行天下到志航天下，他们见证了新航实验的诞生，成就了一个“让教育真实发生的地方”。“或风华正茂但已是奠基之人，或年近花甲但仍然是勇敢的开拓者。以赤子之心将学术、美德薪火相传，血脉绵延。他们奠定了新航实验稳固的基石，站成了一块群体雕塑。这就是他们所追求的教育人生，无名无利无悔，有情有义有爱。”张术磊副校长在颁奖词中介绍道，“新航实验奠基奖”颁发给来自山东省实验中学的十位教师代表。</p><p><br/></p><p>&nbsp; &nbsp; 颁奖环节结束后，学生代表张铭珂、李明航代表全体同学致复学辞——《新航实验赋》。</p><p><a href="images/cb18a7a2941541d8b5c81b3924f24f74.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_cb18a7a2941541d8b5c81b3924f24f74.jpg" width="700" height="1050"/></a></p><p>&nbsp; &nbsp; 之后，山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊致辞，“晴空万里，不如新航有你！我们终于见面了！记得你们离开校园时，冬雪还未完全融化。转眼一帘微雨，一树桃红。终于在迎风笑落红的小满时节，我们等来了你们。”</p><p><br/></p><p>&nbsp; &nbsp; 林宝磊校长在致辞中从抗击疫情说起，勉励新航实验学生要学会三种意识，“在这场我们全员见证的抗击灾难、保卫生命的人生大课中，作为新航实验的一名学子，我们应该从中学会些什么？”首先要有思辨意识，学会独立思考、清醒判断，二是要有使命意识，树立远大理想、勇为敢当。三是要有全球公民意识，尊重多元价值，开放合作。</p><p><br/></p><p>&nbsp; &nbsp; “亲爱的孩子，请你牢记，在困境之中，你会学到更多。希望你用真心感知时代脉搏的跳动，用青春共系世界的发展。祝你平安，愿你正义、勇敢和善良，愿你在社会中真正的长大。”林宝磊校长说道。</p><p><a href="images/902ce16169f74ddd8e608db464729ae8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_902ce16169f74ddd8e608db464729ae8.jpg" width="700" height="466"/></a></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-06-08 08:00:00+08', '2020-06-08 08:00:00+08', '2020-06-08 08:00:00+08', '王雪', '新航实验外国语学校', '新航 实验 未来 举行 复学', '');
INSERT INTO public.news VALUES (973, '告别童年，争做新时代好少年——新航实验初一级部举行“庆六一”主题活动', '', '       童年承载着数不尽的美好回忆，童年编织着五彩斑斓的梦。对于济南新航实验外国语学校初一学生们来说，今年的六一儿童节是他们童年时代的最后一个儿童节，意义非凡。为了给同学们留下一份珍贵的回忆，初一级部精心策划了“告别童年，争做新时代好少年”六一庆祝活动，让这次儿童节过得异常温暖、感动又难忘。       6月1日下午15:00，活动正式开始，除了新航实验的初一级部学生和老师外，还有100余位...', '', '<p>&nbsp; &nbsp; &nbsp; &nbsp;童年承载着数不尽的美好回忆，童年编织着五彩斑斓的梦。对于济南新航实验外国语学校初一学生们来说，今年的六一儿童节是他们童年时代的最后一个儿童节，意义非凡。为了给同学们留下一份珍贵的回忆，初一级部精心策划了“告别童年，争做新时代好少年”六一庆祝活动，让这次儿童节过得异常温暖、感动又难忘。</p><p>&nbsp; &nbsp; &nbsp; &nbsp;6月1日下午15:00，活动正式开始，除了新航实验的初一级部学生和老师外，还有100余位初一学生家长到场，共同见证孩子们由童年到少年的全新转变。在两位小主持人的精彩开场中，活动正式拉开帷幕。</p><p>&nbsp; &nbsp; &nbsp; &nbsp;首先进行的项目是“我唱队歌献祖国“，5位学生代表出中国少先队队旗，全体少先队员起立，敬礼，齐唱队歌，整齐的动作与嘹亮的歌声，将大家对少先队的热爱表达得淋漓尽致。优秀的团员学长，是孩子们学习的榜样，同学们在倾听了高一学长与共青团的故事后，更加坚定了成为一名优秀团员的信念。</p><p><a href="images/83ed392265024e669ad083189deb999a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_83ed392265024e669ad083189deb999a.jpg" width="700" height="478"/></a></p><p><a href="images/84cb3ac968b349e6b48cf6b2e585867c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_84cb3ac968b349e6b48cf6b2e585867c.jpg" width="700" height="1050"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp;红领巾是队旗的一角，陪伴了同学们整个童年时期，在将它郑重摘下叠放整齐、珍藏在信封中后，这份纪念也被同学们永久珍藏起来。前辈的教诲，像春风化雨，洗涤心灵，在这个特殊的日子里，山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊给学生们送上殷切的嘱托，“你们要记住珍惜时光，花开新时代，立志为社会做贡献”。</p><p>&nbsp; &nbsp; &nbsp; &nbsp;初一级部的老师们将千言万语化作一首诗，给同学们带来了诗歌朗诵《我们为希望歌唱》，让学生们再次感到了老师的用心和爱心。童年像一个五彩缤纷的万花筒，让人留恋，老师们精心制作的视频《美丽童年我的梦》，让孩子们仿佛回到了无忧无虑的童年时代，纷纷热烈讨论，现场气氛达到高潮！</p><p><a href="images/2a2f733c97f64592b4a836b57b55b84b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2a2f733c97f64592b4a836b57b55b84b.jpg" width="700" height="466"/></a></p><p><a href="images/f0a4ad757f3d480dad32904f3f3c5a1e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f0a4ad757f3d480dad32904f3f3c5a1e.jpg" width="700" height="466"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp;接下来，《感恩的心》表达了同学们对父母与老师的感激之情，初一家长带来的舞蹈《魔性小孩》，更让学生们看到了家长们的童真和对孩子们的殷切期望。在《闪闪红星》动听的旋律中，本次“告别童年，争做新时代好少年”六一庆祝活动圆满结束。这是孩子们儿童时代的最后一个“六一”，也是最难忘的一个“六一”。</p><p><a href="images/3a10d87229264e2fbb6e233cc94a2c9e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3a10d87229264e2fbb6e233cc94a2c9e.jpg" width="700" height="466"/></a></p><p><a href="images/2b5aef557e314417ab7a84c475954cfc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2b5aef557e314417ab7a84c475954cfc.jpg" width="700" height="466"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp;孩子们，节日快乐！愿你们在接下来的时光里，在新航实验这片沃土中，继续茁壮成长！</p><p><a href="images/0498361cfa5145078d08210a2aab297f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0498361cfa5145078d08210a2aab297f.jpg" width="700" height="466"/></a></p><p><span>供稿：初一级部&nbsp;付真玉</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-06-08 08:00:00+08', '2020-06-08 08:00:00+08', '2020-06-08 08:00:00+08', '王雪', '新航实验外国语学校', '新航 少年 实验 新时代 举行', '');
INSERT INTO public.news VALUES (974, '清华大学教授讲座现场连出两道难题，新航实验高一学生“秒答”', '', '       5月28日上午，济南新航实验外国语学校“专家进校园”活动如期进行，清华大学陈永强教授来到新航实验，为初一、高一学生们带来一场主题为“走进清华”的报告。期间，陈永强教授接连给出两道清华大学此前的自主招生面试考题，没想到，高一三班单怀宇同学在听完题目后直接举手，给出了正确答案，几乎算得上是“秒答”。        在一个小时的专题报告中，陈永强教授首先向同学们介绍了清华大学的办学历程、文...', '', '<p><br/></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;5月28日上午，济南新航实验外国语学校“专家进校园”活动如期进行，清华大学陈永强教授来到新航实验，为初一、高一学生们带来一场主题为“走进清华”的报告。期间，陈永强教授接连给出两道清华大学此前的自主招生面试考题，没想到，高一三班单怀宇同学在听完题目后直接举手，给出了正确答案，几乎算得上是“秒答”。</span></p><p><span><a href="images/abd25dba5c79433e87467b2e57c8bf49.jpg" target="_blank"><img width="500" height="610" title="" src="/uploads/migration/images/s_abd25dba5c79433e87467b2e57c8bf49.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在一个小时的专题报告中，陈永强教授首先向同学们介绍了清华大学的办学历程、文化情怀、学术成果等，鼓励同学们常立志、立长志，追求卓越，结合自己的学业情况、兴趣特长树立远大的目标，努力实现自己的“名校梦”。之后，陈永强教授向同学们介绍清华大学的校园生活、校情校史，围绕清华大学的学科特点详细分享了部分专业的特色、主要学习内容和未来的发展方向，拓宽了新航实验学子的视野，让大家对自己未来的学业规划有了更深刻的认知和思考。同时，他也鼓励同学们继续砥砺奋进，最终能考入理想大学就读喜欢并适合自己的专业。</span></p><p><span><a href="images/e2781ffb4f0549caa031f621a929fa68.jpg" target="_blank"><img width="500" height="750" title="" src="/uploads/migration/images/s_e2781ffb4f0549caa031f621a929fa68.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;为了现场考验一下新航实验学子，陈永强教授在互动环节给出了两道清华大学之前的自主招生面试考题，“给大家3分钟时间思考一道难题，1000缸酒里面只有1缸是有毒的，毒发时间是7天之后，问需要多少只老鼠才能在7天内试出哪一缸酒是有毒的？”“十只老鼠！”陈永强教授刚刚说完题目，坐在台下的高一三班单怀宇同学直接举手作答，给出了正确答案，几乎算得上是“秒答”。紧接着，第二道题目也很快被单怀宇和另外几名高一学生说出了答案。</span></p><p><span><a href="images/0e346c1ebabf45ccb073e6ab9efa9f86.jpg" target="_blank"><img width="400" height="300" title="" src="/uploads/migration/images/s_0e346c1ebabf45ccb073e6ab9efa9f86.jpg"/></a><a href="images/5db877708ac54da9960913248ba34639.jpg" target="_blank"><img width="400" height="300" title="" src="/uploads/migration/images/s_5db877708ac54da9960913248ba34639.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 讲座结束后，陈永强教授与现场的学生们进行了交谈和互动，多名新航实验学子踊跃提问，活动现场很是热烈。</span><span><span>&nbsp;</span></span></p><p><span><span><a href="images/35982cd7f5ab4aca8b403e24960b7316.jpg" target="_blank"><img width="400" height="300" title="" src="/uploads/migration/images/s_35982cd7f5ab4aca8b403e24960b7316.jpg"/></a></span></span></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-06-03 08:00:00+08', '2020-06-03 08:00:00+08', '2020-06-03 08:00:00+08', '王雪', '新航实验外国语学校', '难题 连出 现场 新航 讲座', '');
INSERT INTO public.news VALUES (975, '好样的！新航实验学子于家豪入围NSDA 演讲比赛全国前十', '', '  近日，NSDA全美演讲与辩论联盟组织的“China To the World”演讲大赛复赛落下帷幕，济南新航实验外国语学校高一融合班学生于家豪，突破重重关卡，位列全国前十名，成功入围决赛！  在新型冠状病毒肆虐全球的背景下，NSDA首次举办线上演讲与写作比赛，以“China to the world”为主题，希望通过比赛这一形式，倾听学生在疫情当下的故事、对中国和世界的思考，旨在培养慎思明辨、...', '', '<p><span>&nbsp; 近日，NSDA全美演讲与辩论联盟组织的“China To the World”演讲大赛复赛落下帷幕，济南新航实验外国语学校高一融合班学生于家豪，突破重重关卡，位列全国前十名，成功入围决赛！</span></p><p><span>&nbsp; 在新型冠状病毒肆虐全球的背景下，NSDA首次举办线上演讲与写作比赛，以“China to the world”为主题，希望通过比赛这一形式，倾听学生在疫情当下的故事、对中国和世界的思考，旨在培养慎思明辨、懂得表达、崇尚理性，具有世界公民意识和未来领袖气质的青年学生。</span></p><p><span><br/></span></p><p><a href="images/c430fe6f4f15417d9f01c1ffabe7b14e.jpg" target="_blank"><img width="1080" height="811" title="640.webp.jpg" src="/uploads/migration/images/c430fe6f4f15417d9f01c1ffabe7b14e.jpg"/></a></p><p><span>&nbsp; 于家豪（右一）参加国际教育中心首届Public Forum Debate辩论赛并获得冠军</span></p><p><span><br/></span></p><p><span>&nbsp; 这次演讲比赛的主题“China to the World”，引导参赛学生思考如何积极面对这一场疫情，作为世界公民和未来领袖，该具有怎样的特质，承担怎样的责任。在准备演讲比赛的过程中，于家豪积极搜集、整理和分辨可靠的信息，进行批判性的思考，更与学校老师密切沟通，反复修改演讲稿，学习根据理据来判断和发声。他全身心投入，用实际行动实践着“学习运用世界语言，讲好中国故事。从中国到世界，让世界了解中国”。</span></p><p><br/></p><p><a href="images/a35207d6c66d4210804eff03c714b1c0.jpg" target="_blank"><img width="1045" height="644" title="640.webp (1).jpg" src="/uploads/migration/images/a35207d6c66d4210804eff03c714b1c0.jpg"/></a></p><p><span>&nbsp;</span></p><p><span>&nbsp; NSDA全美演讲与辩论联盟，是美国历史最悠久、规模最大的中学演讲与辩论荣誉组织，也是世界演讲与辩论领域最大的专业教练会员组织。自1925年成立以来，NSDA累计拥有超过150万学生会员，仅2016年，就有逾18万中学生会员参加了NSDA举办的各类活动，学习成为批判性思考者、有效沟通者和道德实践者。NSDA培养学生的批判性思维、细心倾听与深入研究的能力，帮助学生经过理性论证，得出有充足证据支撑、有充足吸引力和说服力的观点。</span></p><p><span>&nbsp;</span></p><p><span>&nbsp;</span></p><p><strong><span><span><span><span><span>获奖感言：</span></span></span></span></span></strong></p><p><span>&nbsp;</span></p><p><span>&nbsp;&nbsp;<span>我是抱着学习和尝试的心态去参加的这次比赛，开始都没有想过能进复赛更不要提全国总决赛了。我报名的那一天距离海选交稿的截止日期只有一周时间，出于deadline（截止时间）的压迫，我只能牺牲休息时间来赶上进度，现在想想那一周过的真的是十分充实！一周的时间里，在老师的帮助和我的努力下，当我改完第五稿之后，才得到了自己较为满意的演讲初稿。</span></span></p><p><br/></p><p><a href="images/156fb97f065a4ad39e912b13c43a7c5b.jpg" target="_blank"><img width="1077" height="807" title="640.webp (2).jpg" src="/uploads/migration/images/156fb97f065a4ad39e912b13c43a7c5b.jpg"/></a></p><p><span>&nbsp;&nbsp;<span>我之前从未参加过演讲比赛，多少还是有点紧张的。渐渐发现演讲绝不仅仅是背诵这么简单，情感的表达、动作的规范、眼神的交流以及语速的控制都十分重要。而对于一些演讲的技巧，我也只是从老师推荐的TED演讲中一点点学习。此外，最令人头疼的还有NSDA演讲比赛的时间限制，海选时演讲时长不得超过五分半，复赛时演讲时长不得超过五分钟。因此，我只好再次修改我的演讲稿，删除了很多冗杂的叙述，让演讲变得更加简洁，最终成功闯入了复赛。</span></span></p><p><span><span>&nbsp;&nbsp;<span>复赛时，面对着各个省份选拔出的高手，我却感觉不到紧张。因为我把比赛当成了一次锻炼自己的机会，而并非追求功利。我想，我唯一的对手也许只是我自己，我仅仅想让现在的我变得比以前更好，这就足够了。</span></span></span></p><p><span><span><span><span>&nbsp; 通过这次比赛，我学会了如何更好地管理时间，并在有限的时间内且在不耽误功课学习的前提下来规划自己的活动。同时，不但我的语言水平得到了锻炼，而且还掌握了一些有关演讲方面的技能。作为新航学子，我们应该勇于参加各种比赛，不尝试一下怎么会知道自己不行？而我也有很多不足之处需要加以改进，希望能继续完善做更好的自己！</span></span></span></span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-05-13 08:00:00+08', '2020-05-13 08:00:00+08', '2020-05-13 08:00:00+08', '王雪', '新航实验外国语学校', '于家豪 入围 学子 实验 演讲', '');
INSERT INTO public.news VALUES (976, '两金两银八铜！新航实验学子在英国物理挑战赛斩获佳绩', '', '   日前，被公认为“英国最高水平的高中物理竞赛之一”的英国物理挑战赛（GSCE&AS Challenge）落下帷幕。此次竞赛中国赛区共有来自全国270多所国际学校和重点中学的近2000名学生参赛，其中，来自济南新航实验外国语学校高一融合班的学生于家豪、张修玮获得全球金奖Golden Award,李国铖、明子丰获得全球银奖Silver Award，贾祥熙、岳笑然、徐晗洋、苑兆润、徐瀚森获得全球铜奖...', '', '<p><span>&nbsp;</span></p><p><span>&nbsp; 日前，被公认为“英国最高水平的高中物理竞赛之一”的英国物理挑战赛（GSCE&amp;AS Challenge）落下帷幕。此次竞赛中国赛区共有来自全国270多所国际学校和重点中学的近2000名学生参赛，其中，来自济南新航实验外国语学校高一融合班的学生于家豪、张修玮获得全球金奖Golden Award,李国铖、明子丰获得全球银奖Silver Award，贾祥熙、岳笑然、徐晗洋、苑兆润、徐瀚森获得全球铜奖Bronze I Award，许露丹、张益明、玄子涵获得全球铜奖Bronze II&nbsp; Award。</span></p><p><span>&nbsp;</span></p><p><a href="images/ab53c712fea94caf8769c42e6243c68a.jpg" target="_blank"><img width="1079" height="1904" title="640.webp (1).jpg" src="/uploads/migration/images/ab53c712fea94caf8769c42e6243c68a.jpg"/></a></p><p><span>&nbsp; 英国 GCSE 物理挑战赛由英国物理奥赛组委会主办，比赛题型新颖，在试题中将基本的物理原理与生活联系在一起，旨在拓展学生的横向思维能力，激发学生的物理潜能，是一项极具挑战性的赛事。该赛事为个人赛，所有中英试卷将被寄回牛津大学物理系接受统一评审。每张试卷都会被3个评审员进行评判，最终评选出金牌Golden Award、银牌Silver Award、铜牌Bronze I Award、铜牌Bronze II Award。</span></p><p><span>&nbsp;</span></p><p><a href="images/9cce519a91ca4fb8b74957aad803b23e.jpg" target="_blank"><img width="614" height="466" title="360截图20200513095546774.jpg" src="/uploads/migration/images/9cce519a91ca4fb8b74957aad803b23e.jpg"/></a></p><p><span><br/></span></p><p><span>&nbsp; 在日益竞争激烈的国外大学申请中，学生的差异化竞争力显得尤为重要，参加国际化竞赛并取得优异的成绩，必然是证明学生学术水平和综合素质的强有力证据。新航实验学子积极报名英国物理挑战赛，不仅体现出学生们对物理学科的浓厚热情，以及扎实的专业素养和不断超越自我的精神，也是学校重视学术水平、鼓励并指导学生参加国际化竞赛，增强学生的专业素养、提高学生的差异化竞争力的体现。</span></p><p>&nbsp;</p><p><strong><span>获奖学生感受</span></strong></p><p><span>&nbsp;</span></p><p><span><span><span><span><span>于家豪：这是我第一次参加英文作为比赛语言且全球竞争性的物理比赛，真的从未想过自己能获奖。出于对物理的兴趣，以及IG物理课程的学习奠定了良好基础，我想去尝试一下，以赛代练，学习一些较为拓展的知识来锻炼自己的思维并提高能力。以后我会继续参加各项比赛，挑战自我，希望我能始终带着一份“热爱”在未来的学习中遇见更好的自己。</span></span></span></span></span></p><p><span>&nbsp;</span></p><p><span>&nbsp;</span><a href="images/5104a5744cf04fa7b646c169f5944e8d.jpg" target="_blank"><img width="1080" height="1526" title="640.webp (2).jpg" src="/uploads/migration/images/5104a5744cf04fa7b646c169f5944e8d.jpg"/></a></p><p><span>&nbsp;</span></p><p><span>张修玮：一切的基础是老师与同学的共同努力，在考前的物理辅导发挥了至关重要的作用。在此我要感谢初中、高中的物理老师，为我打下了坚实的基础，让我具备竞争的条件，也感谢学校升学指导的考试，让我可以临考“冲刺”，最终获奖。</span></p><p><span>&nbsp;</span></p><p><span><span><span>李国铖：这次挑战赛，开拓了大家的视野，见识到了自己的不足，明白了人外有人的道理。虽然经过了艰辛的努力，但最终还是没能取得金奖。不过也给了我继续进步的空间，希望下次能取得更好的成绩。</span></span></span></p><p><span>&nbsp;</span></p><p><span><span><span>明子丰：感谢老师提供的机会和平台，还有父母的支持，很荣幸获奖，但是在做题过程中，仍然有题没有十分肯定的解决，仍有一些知识的漏洞，在之后的学习过程中我会拓宽思维，多学习课本以后的知识，提升自己的能力，争取在之后的比赛中取得更好的成绩。</span></span></span></p><p><span>&nbsp;</span></p><p><span><span><span>贾祥熙：尽管由于疫情使得原本线下的物理竞赛改为线上，但我和同学们学习物理和积极参加竞赛的热情依旧十分高涨。通过物理竞赛，我不仅收获了奖项，提高了自信心，更有了继续探究物理奥妙的动力，提高了我的抗压能力，让我在未来能够迎接更多挑战。小小的成就激励着我不断学习进步，也让我认识到自身和别人的差距。这促使我在接下来的学习生活中更加投入、加倍付出。</span></span></span></p><p><span>&nbsp;</span></p><p><span>&nbsp;</span><a href="images/3471642f8ddb4125a9272dbee68591b6.jpg" target="_blank"><img width="1080" height="1526" title="640.webp (3).jpg" src="/uploads/migration/images/3471642f8ddb4125a9272dbee68591b6.jpg"/></a></p><p><span><span>岳笑然：很荣幸在这次物理竞赛中获得铜奖，最终能取得不错的成绩，要感谢我的物理老师一直以来认真严谨的教学和父母在这方面对我的鼓励和指导。我会继续努力的！</span></span></p><p><span><span><span><span>&nbsp;</span></span></span></span></p><p><span>徐晗洋：这次物理竞赛，与我们学习的IG物理和日常生活息息相关，平常的学习和生活中的观察对我这次考试帮助非常大，在这场考试里面，有很多题目涉及到了我喜欢的物理领域，所以我对这次考试十分感兴趣。</span></p><p><span>&nbsp;</span></p><p><span>&nbsp;</span><a href="images/b6c5ce6aa2304229a25d9094c1b1efb5.jpg" target="_blank"><img width="1077" height="1528" title="640.webp (4).jpg" src="/uploads/migration/images/b6c5ce6aa2304229a25d9094c1b1efb5.jpg"/></a></p><p><span>&nbsp;</span></p><p><span>苑兆润：在这一次的物理挑战赛中，我在对自己的一步步挑战中不断收获进步。在最开始的时候，经常会碰到一两个没有学过的知识点。通过问老师和上网查询学习的方式，慢慢学会并记牢，IG物理课程知识逐渐丰富起来，一些陌生的单词也在努力的记忆。通过这次考试，我把物理学科的词汇进行了提高，还提前学到了一些知识。</span></p><p>&nbsp;</p><p><a href="images/21cf8d52572342e1911b2ba31d84935d.jpg" target="_blank"><img width="1076" height="1525" title="640.webp (5).jpg" src="/uploads/migration/images/21cf8d52572342e1911b2ba31d84935d.jpg"/></a></p><p>&nbsp;</p><p><span>徐瀚森：从报名到准备，再到模考，再到最后的正式考试，我和我的朋友们准备了很长的时间，我们一起经历了很多。从最初的抱怨到从容的解决每一道题，我感觉自己很有收获。通过这次竞赛我也对IG和AS的物理有了一个更深刻了解。在我的学习生涯中这是一个突破，毕竟是第一次参与这种比赛。我认为很有收获，也向一起努力的同学们表示敬意。</span></p><p><span>&nbsp;</span></p><p><span><span><span><span>许露丹：能够获得这份奖项，首先我要感谢老师的辛勤付出，也要感谢自己的不懈努力。这个奖项不仅是对我在学习上的一种肯定，更是对我在学习上的一种激励和鼓励。我会珍惜这一份奖项，并把它转化为我前进的动力，继续向着更高更远的目标前进。</span></span></span></span></p><p><span>&nbsp;</span></p><p><span><span><span><span>张益明：名次不是最重要的，通过这次比赛，我认识到了自己的不足，并通过比较，间接地见识了英国学子的风采，虽然只收获了铜奖，但对我成长路上的帮助却远不止一个铜奖。</span></span></span></span></p><p><span>&nbsp;</span></p><p><span><span><span><span>玄子涵：面对获奖，除了些许紧张和激动，更多了一份坦然。虽然只是铜奖，但仍然是自己努力的证明。我们都相信努力就能成功。在此我也衷心希望融合班的全部同学都可以放飞自己的理想，成为自己想要成为的样子。</span></span></span></span></p><p><span>&nbsp;</span></p><p>&nbsp;</p><p>&nbsp;</p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-05-13 08:00:00+08', '2020-05-13 08:00:00+08', '2020-05-13 08:00:00+08', '王雪', '新航实验外国语学校', '英国 学子 物理 挑战赛 实验', '');
INSERT INTO public.news VALUES (977, '线上直播答疑，新航实验“空中课堂”架起学习新桥梁', '', '    日前，山东省教育厅发布《关于推迟高等学校、中小学、幼儿园开学的公告》后，济南新航实验外国语学校积极推进“空中课堂”教学方案实施，为学生提供更加有效的学习指导。2月3日上午，筹备已久的线上直播答疑课程顺利进行，为“教”与“学”架起新桥梁，新航学子在家也能与亲切的老师沟通交流，感受知识带来的充实与欢乐。    高效沟通，线上直播胜似“面对面”    上午8点，新航实验初一级部和高中级部的近30...', '', '<p><span>&nbsp;&nbsp;&nbsp; 日前，山东省教育厅发布《关于推迟高等学校、中小学、幼儿园开学的公告》后，济南新航实验外国语学校积极推进“空中课堂”教学方案实施，为学生提供更加有效的学习指导。2月3日上午，筹备已久的线上直播答疑课程顺利进行，为“教”与“学”架起新桥梁，新航学子在家也能与亲切的老师沟通交流，感受知识带来的充实与欢乐。</span></p><p><span></span><a href="images/e56506a87ea9409a8e2ba2845e6d340d.jpg" target="_blank"><img width="1077" height="818" title="640.webp.jpg" src="/uploads/migration/images/e56506a87ea9409a8e2ba2845e6d340d.jpg"/></a></p><p><br/><strong><span>&nbsp;&nbsp;&nbsp; 高效沟通，线上直播胜似“面对面”</span></strong></p><p><span>&nbsp;&nbsp;&nbsp; 上午8点，新航实验初一级部和高中级部的近30名老师，按照课程表，准时在家打开电脑，开始线上集中答疑课程的直播。“孩子，有什么问题？师傅给你解答一下”，“老李，你布置的那几篇古文我都烂熟于心了，再给发些新挑战呗！”2月3日上午9点，新航实验初一五班班主任李正华的直播群里，学生们纷纷晒出前几天的成果，让老师“检验”。</span></p><p><span>虽然是“空中课堂”，但是课程的质量丝毫没有打折扣。本次课程开始前，老师们已经收集了同学们对于本学科的各类问题，包括寒假作业的问题、预习过程中发现的问题、各小组合作探究的问题等。问题收集上来后，各学科教研组开启了认真充分地备课，力求让每一个问题的解答都准确、简洁和全面，在正式课前，每位老师都做了充分的准备。</span></p><p><a href="images/c124061437f448178f44825146d76b07.jpg" target="_blank"><img width="944" height="549" title="640.webp (1).jpg" src="/uploads/migration/images/c124061437f448178f44825146d76b07.jpg"/></a></p><p><br/></p><p><strong><span>&nbsp;&nbsp;&nbsp; 学生自选，每个直播室配双导师</span></strong></p><p><span>&nbsp;&nbsp;&nbsp; 直播过程中，每个直播室除了有一名老师外，还分别配备了一名助教老师，辅助老师进行答疑解惑。初一数学老师张素文的直播室里，始终有20多名学生正在找她答疑，忙到10点多。</span></p><p><span>学生在家按照学校提前发放的操作指南登录上线后，见到了朝夕相处的老师，分外亲切，丝毫没有因网络的距离而降低学习的热情，他们将自己作业完成情况和对于新问题的所思所想，有条不紊地告诉老师，师生之间进行着充分的沟通和交流，彷佛打破了网络的桎梏，沟通效果堪比面对面！</span></p><p><span>每个学生可以进入任一学科老师的直播间，自己的问题得到解答后可以退出这一直播间，也可以继续听讲其他同学的问题。老师可以一对一或者一对多解答，非常的高效方便。从早上八点开始到中午十二点，初一7科和高一8科完成集中答疑。</span></p><p><br/></p><p><span>&nbsp;</span><a href="images/be99e4d5d32643849dd01c16c2a994e4.jpg" target="_blank"><img width="928" height="850" title="640.webp (2).jpg" src="/uploads/migration/images/be99e4d5d32643849dd01c16c2a994e4.jpg"/></a></p><p><br/></p><p><strong><span>&nbsp;&nbsp;&nbsp; 多管齐下，在线答疑和课程直播结合</span></strong></p><p><span>&nbsp;&nbsp;&nbsp; 根据学校安排，将充分借助学校高端的智慧化校园系统中常态化录播、智慧教室中的软硬件设备以及丰富的在线教育资源，开展“空中课堂”在线教学，组织各学科名师、骨干教师对全体学生进行在线教学和在线答疑辅导，确保学生“延迟不延学”，教师“离校不离教”、“停课不停导”。</span></p><p><span>1月31日至2月7日期间，原定假期的义务答疑辅导改为在线答疑，学生通过群接龙，晒每日学习计划及学习成果，导师总结点评，2月6日上午还将进行集中答疑。</span></p><p><br/></p><p><a href="images/297edeed834342629795e6020026bb28.jpg" target="_blank"><img width="1079" height="689" title="640.webp (3).jpg" src="/uploads/migration/images/297edeed834342629795e6020026bb28.jpg"/></a><span></span></p><p><span>&nbsp;&nbsp;&nbsp; 从2月10日开始，借助新航实验高端先进的智慧校园系统，初一及高一级部将开设直播课，同时利用山东省实验中学空中课堂、济南市网络资源平台和人人通等网络资源，作为新航实验“空中课堂”教学的有力补充，让新航实验学生度过一个安全、充实而有意义的假期。</span></p><p><br/></p><p><span></span></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-02-11 08:00:00+08', '2020-02-11 08:00:00+08', '2020-02-11 08:00:00+08', '王雪', '新航实验外国语学校', '实验 空中 课堂 新航 学习', '');
INSERT INTO public.news VALUES (978, '师生隔空互动，济南新航实验“空中课堂”正式开课啦', '', '    2月10日，是济南不少中小学原定开学的日子，一场突如其来的疫情让开学时间延迟，但“教师离校不离教，学生停课不停学”，从这一天开始，济南新航实验外国语学校精心打造的“空中课堂”正式亮相，启动全员全学科网络直播课程，任课教师们精心为学生准备了形式多样的知识大餐，对学生进行防疫知识宣传、学法指导及新学期课程预习，让学习不断线。    隔空点名，学生积极参与课堂互动    2月10日上午7点，济南...', '', '<p><span>&nbsp; &nbsp; 2月10日，是济南不少中小学原定开学的日子，一场突如其来的疫情让开学时间延迟，但“教师离校不离教，学生停课不停学”，从这一天开始，济南新航实验外国语学校精心打造的“空中课堂”正式亮相，启动全员全学科网络直播课程，任课教师们精心为学生准备了形式多样的知识大餐，对学生进行防疫知识宣传、学法指导及新学期课程预习，让学习不断线。</span></p><p><a href="images/8e07f3d20463401f8f31cd61b7494e03.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/8e07f3d20463401f8f31cd61b7494e03.jpg" width="332" height="397"/></a><a href="images/16d437aae7894dc9a1c275b454c49de0.jpg" target="_blank"></a><a href="images/16d437aae7894dc9a1c275b454c49de0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_16d437aae7894dc9a1c275b454c49de0.jpg" width="323" height="398"/></a></p><p><strong><span>&nbsp; &nbsp; 隔空点名，学生积极参与课堂互动</span></strong></p><p><span>&nbsp; &nbsp; 2月10日上午7点，济南新航实验外国语学校语文组的王坤元老师早早就坐在电脑前，登录直播软件，调试设备确认正常。7：50开始，学生们陆续进入教室，不过，和往常不同的是，此时她和学生们并没有出现在学校，而是坐在自家电脑前，从面对面到端对端，空中课堂的虚拟教室，让师生们顺畅沟通未受到阻碍。</span></p><p><span>&nbsp; &nbsp; 早上8:00，空中课堂第一堂课正式开讲，初一学生和高一普通班学生、高一融合班学生分别在三个直播间内，与李正华、王坤元和孙雨辰三位老师隔空互动。学生们早已备好齐全的学习用品和课本等资料，端坐在书桌前，认真做着笔记，除了三位任课教师外，此时，每个直播间内还有一位助教老师在线，协助任课教师为学生做好答疑解惑。</span></p><p><span><a href="images/4580f00d15c944869f4b3c25a19296ee.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4580f00d15c944869f4b3c25a19296ee.jpg" width="500" height="375"/></a></span></p><p><a href="images/a03e2da11bba4ad384b80149b1ac6fbe.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a03e2da11bba4ad384b80149b1ac6fbe.jpg" width="500" height="375" alt=""/></a></p><p><a href="images/a2460893df6e4a29a495b5b046984406.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a2460893df6e4a29a495b5b046984406.jpg" width="500" height="375"/></a></p><p><span>&nbsp; &nbsp; 10日下午，融合班学生开始了他们的在线艺术课学习。艺术老师Alexander通过网络课堂向同学们介绍了几何抽象画派先驱Piet Mondrian的生平、作品，并对该画家的创作风格、构图技巧和绘画手法进行了分析。接下来，Alex要求每个学生进行创作，通过线条、色彩的搭配，使用自己的英文名字创作一幅抽象派作品。</span></p><p><a href="images/bd448c60ebed4daea313cc26142ec28f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_bd448c60ebed4daea313cc26142ec28f.jpg" width="500" height="263"/></a></p><p><span>&nbsp; &nbsp; 对于“空中课堂”课程直播的效果，学生和家长们也很认可。“上课特别认真，第一个被提问，然后被表扬，要求全体同学给她掌声，孩子美的不行。”一位学生家长调侃道，课程直播过程中热情很高，不仅会被老师随机提问点名互动，还能主动举手提问题，师生沟通毫无障碍。</span></p><p><br/></p><p><strong><span>&nbsp; &nbsp; 不止学书本知识，还有防疫和艺体课程</span></strong></p><p><span>&nbsp; &nbsp; 除了学习书本知识外，新航实验“空中课堂”还专门在每天上、下午上课前15分钟安排了防疫知识讲授，每天早上7：45到8：00是防疫新闻，下午13：45到13：50是新航学生防疫作品展示，还有校医老师精心准备的防疫知识讲座。</span></p><p><span>&nbsp; &nbsp; 此外，还有心理健康讲座、抗击疫情励志音乐视频赏析、升学生涯指导讲座、家庭健身指导等丰富的课程内容，全新的授课方式，形式多样的内容，让孩子们在家的学习生活静而不闲、丰富充实。</span></p><p><a href="images/a1f398a738e04ebdad0457fcae3d588a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a1f398a738e04ebdad0457fcae3d588a.jpg" width="500" height="264"/></a></p><p><span>&nbsp; &nbsp; 按照之前公布的课程表，新航实验“空中课堂”每天的课程从早上8：00开始第一节课，一直到下午17：10第四节课结束，2月10日当天初一年级学生要完成语文、数学、英语、疫情知识讲座等课程的学习，高一年级普通班学生则要完成语文、数学、疫情知识讲座、物理、政治这几门课的学习。在接下来的几天，学生们除了完成新课的预习外，还会先后迎来心理、美术、体育、音乐、生涯规划等内容丰富的课程。</span></p><p><a href="images/1d7a8046820d41e88abd2ca63c5e4981.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1d7a8046820d41e88abd2ca63c5e4981.jpg" width="500" height="414"/></a></p><p><a href="images/1d7a8046820d41e88abd2ca63c5e4981.jpg" target="_blank"></a><a href="images/ad86e838399e45f186a08553b72b9838.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ad86e838399e45f186a08553b72b9838.jpg" width="500" height="419"/></a></p><p><br/></p><p><a href="images/86f63c2867d343bab60421ed5cb90d0c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_86f63c2867d343bab60421ed5cb90d0c.jpg" width="500" height="394"/></a></p><p><span>&nbsp; &nbsp;“形式很新鲜，和老师面对面交流，就像我们坐在教室里一样，还有助教老师在线，大家状态都很不错。”济南新航实验初一学生渠清源感慨道，看得出来，老师们为了备课也付出了很多劳动，接下来要做的就是按学校安排好的节奏开始学习。</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-02-11 08:00:00+08', '2020-02-11 08:00:00+08', '2020-02-11 08:00:00+08', '王雪', '新航实验外国语学校', '实验 空中 新航 课堂 济南', '');
INSERT INTO public.news VALUES (979, '济南新航实验外国语学校疫情防控工作举报电话、邮箱', '', '  电话：0531—59516617  邮箱：jxefls_po@jn.shandong.cn', '', '<p><br/></p><p><br/></p><p><span>&nbsp; 电话：0531—59516617</span></p><p><span>&nbsp; 邮箱：jxefls_po@jn.shandong.cn</span></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-02-04 08:00:00+08', '2020-02-04 08:00:00+08', '2020-02-04 08:00:00+08', '王雪', '新航实验外国语学校', '疫情 学校 工作 外国语 实验', '');
INSERT INTO public.news VALUES (980, '回望既往，展望未来——新航实验初一级部举行2.0版“三味三境”家长会', '', '     1月11日下午，济南新航实验外国语学校初一级部精心筹备的2.0版“三味三境”家长会正式举行。此次家长会以“望”为主题词，意在与全体家长共同回望2019年的足迹与收获，同时立足高远，共同展望未来的道路与前景。2.0版更是在原有“三味三境“家长会的基础上，进行了优化升级，让前来参会的家长连连感叹“学校太用心了！”“收获特别大！”       下午13：30，家长们手持邀请函走进新航实验大剧院...', '', '<p><a href="images/a311b5c01a85405ebed869c17ee83a56.jpg" target="_blank"></a><a href="images/a311b5c01a85405ebed869c17ee83a56.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a311b5c01a85405ebed869c17ee83a56.jpg" width="600" height="400"/></a></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; 1月11日下午，济南新航实验外国语学校初一级部精心筹备的2.0版“三味三境”家长会正式举行。此次家长会以“望”为主题词，意在与全体家长共同回望2019年的足迹与收获，同时立足高远，共同展望未来的道路与前景。2.0版更是在原有“三味三境“家长会的基础上，进行了优化升级，让前来参会的家长连连感叹“学校太用心了！”“收获特别大！”</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 下午13：30，家长们手持邀请函走进新航实验大剧院，参与初一级部全体家长会。会议在主持人董凤菊老师的温暖话语中开场，初一级部主任李正华作了题为“在方圆的世界里起航”的主题报告，从“期末反馈”“级部管理”“共话教育”“同迎未来”四个方面娓娓道来。不仅让家长看到了孩子入学半年来的成长蜕变，并且用生动形象的语言诠释了新航实验特色的办学理念，让家长们产生了强烈的共鸣，鼓励家长站在高处，充满信心，静待花开。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 接着，新航实验张爱梅副校长和教学管理中心主任王飞先后点评发言，充分肯定了初一级部这半年来工作和学生成长变化，预祝孩子们在新航这片沃土中不断茁壮成长。</span></p><p><span><a href="images/c30ac532f8c84bc69c0e4d6e347ca3f5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c30ac532f8c84bc69c0e4d6e347ca3f5.jpg" width="600" height="400"/></a><br/></span></p><p><span></span><span><a href="images/4dc21d98e9a64ffc95f720232403472f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4dc21d98e9a64ffc95f720232403472f.jpg" width="600" height="665"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 接下来进入家长会的第二阶段，家长们移步到了各班教室。一进教室门，就看到桌上摆着的“小惊喜”——每个孩子的成长档案。档案里面有孩子的各科成绩分析、导师评语、优点单、个人总结、组长评价等等，彷佛一个个脚印，记录了孩子学习生活的点点滴滴，每位家长都细细翻阅，备受感动。班主任对本班情况作了整体介绍后，各学习组长和班长分别对班级工作进行汇报，天真明朗的笑容，活泼有趣的语言，引得家长们开怀大笑。接着是语数外老师的成绩分析汇报，让家长们对本班孩子们的成绩有了明确具体的认识。</span></p><p><span><a href="images/a2b99763a9bb49b6a062aa43eb7e473f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a2b99763a9bb49b6a062aa43eb7e473f.jpg" width="600" height="350"/></a></span><span><a href="images/e9914700f3d84a02b8599aea28bbc2d6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e9914700f3d84a02b8599aea28bbc2d6.jpg" width="600" height="400"/></a></span><span><a href="images/53eff3b337654060b28ff00655910603.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_53eff3b337654060b28ff00655910603.jpg" width="600" height="400"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 最后是本次家长会的重头戏，即第三阶段的双导师学情会商活动。家长们移步到了明亮整洁的图书馆，各位导师早已就位，他们以专业的语言，亲切地与各位家长进行交谈。导师对每个孩子的情况都十分清楚，生活习惯、人际交往、学习状态、自习效率等等，家长对导师的用心和爱心称赞不已。各位家长也敞开心扉，与导师交流自己的教育理念、对孩子成长道路上的困惑，家校沟通就像架起一座无形的桥梁，只为让孩子的成长之路更加广阔。</span></p><p><span><a href="images/d69ad7123fed4a35855373b88debcfa2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d69ad7123fed4a35855373b88debcfa2.jpg" width="600" height="400"/></a></span><span><a href="images/9daa983b1b254debbbd78f837bfc31e8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9daa983b1b254debbbd78f837bfc31e8.jpg" width="600" height="407"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 下午18时许，此次2.0版“三味三境”家长会圆满结束。本次家长会让学校与家庭的沟通联系更加密切，为初一上学期画上了完美的句点。同时这又是一把开启初一下学期的钥匙，预示着新的学期，在家校共同努力下，会更加充满期待，多姿多彩！</span></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-01-16 08:00:00+08', '2020-01-16 08:00:00+08', '2020-01-16 08:00:00+08', '王雪', '新航实验外国语学校', '实验 未来 新航 举行 展望', '');
INSERT INTO public.news VALUES (981, '雪地狂欢——新航实验初一级部举行冰雪创意大赛', '', '      2020年第一场大雪如约而至，对于济南新航实验外国语学校初一学生们来说，紧张的期末考试也告一段落，正式迎来考后的放松调整阶段。1月7日下午，整个新航实验校园银装素裹，置身其中彷佛走入了冰雪世界。于是，一场以“冰雪奇缘，雪地狂欢”为主题的雪地创意大赛如火如荼地开展起来。1月7日下午16时，冰雪创意大赛正式拉开帷幕。首先，每个班级分为三组，每组在明确主题后，进行了激烈的头脑风暴，商定了本组...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2020年第一场大雪如约而至，对于济南新航实验外国语学校初一学生们来说，紧张的期末考试也告一段落，正式迎来考后的放松调整阶段。1月7日下午，整个新航实验校园银装素裹，置身其中彷佛走入了冰雪世界。于是，一场以“冰雪奇缘，雪地狂欢”为主题的雪地创意大赛如火如荼地开展起来。</p><p><a href="images/93c76e61421e464589fbb7856dba7ad1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_93c76e61421e464589fbb7856dba7ad1.jpg" width="500" height="375"/></a><a href="images/ed56d4d827e4499ba1c0623961e5c45a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ed56d4d827e4499ba1c0623961e5c45a.jpg" width="500" height="375"/></a></p><p><a href="images/067072293e69494eb3c6fc8154c3fa6c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_067072293e69494eb3c6fc8154c3fa6c.jpg" alt="" width="700" height="525"/></a></p><p>1月7日下午16时，冰雪创意大赛正式拉开帷幕。首先，每个班级分为三组，每组在明确主题后，进行了激烈的头脑风暴，商定了本组的创意造型。接着，组长带领组员，清点好所需工具和装饰品，奔向共同的创作基地——操场。选定好位置后，各组开始进行有趣有序的创作。动听的音乐、爽朗的笑声，交织成一支欢快的歌曲在风中飘荡，雪天的寒冷似乎变得微不足道，偌大的操场已是一片欢乐的海洋。<br/></p><p>为了配合此次活动，学校食堂特意为学生们的“创作”准备了所需的物料，包括手套、胡萝卜、大枣、白菜等，晚餐时食堂还专门为学生们提供姜汤驱寒。</p><p><a href="images/84e16e5c743a42d18a6644017c9f705a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_84e16e5c743a42d18a6644017c9f705a.jpg" width="500" height="666"/></a><a href="images/ee39cc273908443b8926e0e61d59b227.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ee39cc273908443b8926e0e61d59b227.jpg" width="500" height="666"/></a></p><p><a href="images/bd1689346faf43bc94b920288708c380.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_bd1689346faf43bc94b920288708c380.jpg" width="500" height="375"/></a><a href="images/8fb47fb2d79841a29bb0d149bf021771.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8fb47fb2d79841a29bb0d149bf021771.jpg" width="500" height="375"/></a></p><p><br/></p><p>不到一小时的时间，各组成员在组长的统筹协调下，已经将本组的创意造型做出来了，他们自豪地向在场的评委老师们展示各自的作品，只见有的是活泼可爱的龙猫，有的是栩栩如生的小兔子，还有寓意新年大吉的萌鼠，更有造型精美的特色建筑……形式多样，解说有趣，看得人眼花缭乱，不禁令人感叹，孩子们果然是创意无限！</p><p><a href="images/49520a37d90544fa94a7c62331d0468b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_49520a37d90544fa94a7c62331d0468b.jpg" width="500" height="333"/></a></p><p><a href="images/08ad135dbbd04f9984d351118ecd9735.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_08ad135dbbd04f9984d351118ecd9735.jpg" width="500" height="666"/></a></p><p><br/></p><p>下午17时，此次冰雪创意大赛在一片欢声笑语中接近尾声，充分释放了孩子们热爱大自然的天性，发挥了“00后”无尽的想象力和创造力，锻炼了他们的统筹协作能力，更让学生们在紧张的考试后，获得了身心的放松调整，开启了接下来学习与生活的新篇章！<br/></p><p>最后再来上几张美到令人窒息的新航实验校园雪景，一种大片既视感来袭，你心动了吗？</p><p><a href="images/f60aec3173984aadbd3ec5bfb21bdafe.jpg" target="_blank"></a></p><p><a href="images/a1abe99d48424c44a46730d3be12549a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a1abe99d48424c44a46730d3be12549a.jpg" width="500" height="239"/></a><a href="images/c40e3edd036e4cf081f393928dddcb7d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c40e3edd036e4cf081f393928dddcb7d.jpg" width="500" height="239"/></a></p><p><a href="images/27a0e83c8685440d9d8724f62f505751.jpg" target="_blank"></a><a href="images/27a0e83c8685440d9d8724f62f505751.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_27a0e83c8685440d9d8724f62f505751.jpg" width="500" height="375"/></a><a href="images/27a0e83c8685440d9d8724f62f505751.jpg" target="_blank"></a><a href="images/57966923dc7f456cae3a6b06e70db54a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_57966923dc7f456cae3a6b06e70db54a.jpg" width="500" height="375"/></a></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'activities', '', NULL, true, '2020-01-16 08:00:00+08', '2020-01-16 08:00:00+08', '2020-01-16 08:00:00+08', '王雪', '新航实验外国语学校', '实验 举行 新航 冰雪 狂欢', '');
INSERT INTO public.news VALUES (982, '心连新•梦飞young ——新航实验举行2020年新年联欢会', '', '       喜迎2020，共庆新年。1月6日下午，济南新航实验外国语学校举行“心连新·梦飞young ”为主题的2020年新年联欢会，全体新航实验师生欢聚一堂、其乐融融，整场演出充满了惊喜与欢笑。美妙的舞姿、嘹亮的歌声、美好的愿景、高昂的斗志，为新航实验2019年的发展画上圆满的句号，也为2020年再创佳绩开启新篇章。       随着一首欢快的《欢聚一堂》开场舞，整场活动在热烈的氛围中拉开帷幕...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span> 喜迎2020，共庆新年。1月6日下午，济南新航实验外国语学校举行“心连新·梦飞young ”为主题的2020年新年联欢会，全体新航实验师生欢聚一堂、其乐融融，整场演出充满了惊喜与欢笑。美妙的舞姿、嘹亮的歌声、美好的愿景、高昂的斗志，为新航实验2019年的发展画上圆满的句号，也为2020年再创佳绩开启新篇章。</span></p><p><span>&nbsp; &nbsp;&nbsp; &nbsp; 随着一首欢快的《欢聚一堂》开场舞，整场活动在热烈的氛围中拉开帷幕。山东省实验中学校长、党委书记、济南新航实验外国语学校副理事长韩相河到场致辞，为全体新航实验师生送上节日的祝福。</span></p><p><a href="images/262386171b9e418dafb33a2631b5234d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_262386171b9e418dafb33a2631b5234d.jpg" width="627" height="451"/></a></p><p><a href="images/17f6d5f6b1b34c108512adcc713eed7e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_17f6d5f6b1b34c108512adcc713eed7e.jpg" alt="" width="627" height="418"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>两支学生乐队分别演唱《那一天从梦中醒来》、《光年之外》，之后，初一教师代表李正华、刘双双、崔佩佩等，带来诗朗诵《新航的星空》，精炼的文字、恰如其分的表达，都让在场的不少老师和学生都沉浸在对新航实验深沉的爱中。紧接着，20余位女教师代表带来舞蹈串烧《大田后生仔》，当看到平日里一板一眼的老师们用这种活泼的形象出现在舞台上，台下的学生们立刻沸腾了，“太棒了！”“实力圈粉啊！”</span></p><p><a href="images/f5ab5efa901f4cec83a9b635dd3c4bf4.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f5ab5efa901f4cec83a9b635dd3c4bf4.jpg" width="500" height="333"/></a><a href="images/239defb4e15746cea4783aaeaae7bdb1.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_239defb4e15746cea4783aaeaae7bdb1.jpg" width="500" height="333"/></a></p><p><a href="images/eebc7abd9fb64dafba00af774e6c172b.jpg" target="_blank"></a><a href="images/a716ffc1792d4c46a67ba2666222cf4c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a716ffc1792d4c46a67ba2666222cf4c.jpg" alt="" width="404" height="343"/></a><img title="" src="/uploads/migration/images/s_eebc7abd9fb64dafba00af774e6c172b.jpg" alt="" width="500" height="343"/></p><p>&nbsp;&nbsp;&nbsp;&nbsp;<span>&nbsp;&nbsp; 整场活动高潮不断，沈安琪、赵奕鸥等七名同学带来舞蹈《what is love》后，来自后勤服务中心的保安、餐厅和物业员工代表献上一首《我的中国心》，动漫社带来舞蹈串烧《触摸天空》，精彩的魔术表演、学生萨克斯独奏吸引了全场的目光。在教师代表汉服走秀环节中，身穿汉服的老师们一出场就引起了现场阵阵尖叫，同时，高一学生代表张仪秦、贾祥熙现场挥毫，“万事如意步步高，一帆风顺年年好”，寓意2020年好彩头。</span></p><p><a href="images/edbb9cd9a72d424799a58b41d1d68cbd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_edbb9cd9a72d424799a58b41d1d68cbd.jpg" alt="" width="500" height="404"/></a><a href="images/4f887a2528184e2380a307bd6b545eec.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4f887a2528184e2380a307bd6b545eec.jpg" width="500" height="404"/></a></p><p><a href="images/8517148efff849a2b8472b11cf78a920.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8517148efff849a2b8472b11cf78a920.jpg" width="500" height="333"/></a><a href="images/4f887a2528184e2380a307bd6b545eec.jpg" target="_blank"></a><a href="images/524a733631e14a538dbbb0e3be1278fc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c4a3cab69c1a4b949f76ce91cbe1c565.jpg" width="500" height="333"/><br/></a></p><p><a href="images/94a66895a5df40cfb48ad26368ed5ecc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_94a66895a5df40cfb48ad26368ed5ecc.jpg" alt="" width="500" height="302"/></a><a href="images/77916cfffb6a4edabd3a936149686fd5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_77916cfffb6a4edabd3a936149686fd5.jpg" width="500" height="302"/></a></p><p><a href="images/109bcdba15aa4311b757048a8f8ee11d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_109bcdba15aa4311b757048a8f8ee11d.jpg" width="500" height="333"/></a><a href="images/56630195af724c9b9b9d3cb5715ba735.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_56630195af724c9b9b9d3cb5715ba735.jpg" width="500" height="333"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>联欢会现场，由省实验中学退休教师吴大同老师带领的“芳园”合唱团来到登上舞台高唱《游击队之歌》，他们中年龄最大的已经80多岁高龄，“实验精神，代代传承，作为省实验中学的退休老教师，我们这群平均年龄71.8岁的‘70后’，很欣慰看到，实验精神在这里传承。”深沉感人的歌声寄托了老一辈教师对新航实验师生的殷殷教诲、寄托了新航实验美好未来的殷切期望，他们对生活的热爱感染着在场的每一个人。</span></p><p><a href="images/56630195af724c9b9b9d3cb5715ba735.jpg" target="_blank"></a><a href="images/04e9fc1a0d804c5a9b054696c1b8b61f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_04e9fc1a0d804c5a9b054696c1b8b61f.jpg" width="500" height="321"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span> 在之后的民乐重奏《青花瓷》和教师走秀节目中，新航实验副校长张爱梅带领七位新航实验女教师代表穿上旗袍，现场走秀，民国范儿十足的台步、得体大方的举止，彰显了新航实验教师团队积极进取的青春活力与热情。</span></p><p><a href="images/4f1bd2a52e4b45a7b9396e0650423e48.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4f1bd2a52e4b45a7b9396e0650423e48.jpg" width="500" height="262"/></a></p><p><a href="images/f550f35b08814fe5b7c5c9159f971ac9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f550f35b08814fe5b7c5c9159f971ac9.jpg" width="500" height="339"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span> 紧接着，两名外教Victoria 和Evgeny在高一学生米云迪的钢琴伴奏下，演唱了《rima》、《今日无人入眠》。高一级部主任吕秀亭带领十一位新航实验青年教师，现场表演《野狼disco》，动感十足的歌曲和舞蹈、冷峻帅气的造型设计，立刻引起了学生们的阵阵叫好。多语言、多风格的精彩碰撞，现场气氛随着台上教师们的舞姿而变得活跃轻快。之后，高一二班7名同学带来音乐表演《琵琶行》。</span></p><p><a href="images/fcc08d25c451468bba609241edc81508.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fcc08d25c451468bba609241edc81508.jpg" alt="" width="500" height="336"/></a><a href="images/584bfdb3430c41dd8e266d9ce394b0f8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_584bfdb3430c41dd8e266d9ce394b0f8.jpg" width="500" height="336"/></a></p><p><a href="images/f1c39b326b9545219260561bc6c64529.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_524a733631e14a538dbbb0e3be1278fc.jpg" alt="" width="500" height="300"/><img title="" src="/uploads/migration/images/s_f1c39b326b9545219260561bc6c64529.jpg" alt="" width="500" height="300"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>最后，由济南新航实验外国语学校执行校长林宝磊，带领新航实验副校长张术磊、张爱梅，以及教学管理中心主任王飞、音乐教师闫浩艺共同献上一曲《共筑中国梦》，宽厚饱满的歌声，饱含着家国情怀的浓浓深情，将整场活动推到最高潮，新年联欢会在《共筑中国梦》的旋律中落下帷幕。</span></p><p><a href="images/2599f6bc34e04e7997e95c7bd7229061.jpg" target="_blank"></a><a href="images/2599f6bc34e04e7997e95c7bd7229061.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_2599f6bc34e04e7997e95c7bd7229061.jpg" width="500" height="333"/></a></p><p><a href="images/773b34a4e4f349ae81e75e3767cfb40f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_773b34a4e4f349ae81e75e3767cfb40f.jpg" width="500" height="252"/></a></p><section><section><p>&nbsp;&nbsp;<span>&nbsp;&nbsp;&nbsp;&nbsp; 此次新年联欢会充分展示了新航实验师生的多才多艺与团队精神，增强了新航实验的凝聚力。祝愿新航实验在新的一年再创佳绩，祝愿祖国繁荣昌盛！<br/></span></p></section></section><p><br/><br/></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2020-01-09 08:00:00+08', '2020-01-09 08:00:00+08', '2020-01-09 08:00:00+08', '王雪', '新航实验外国语学校', '新年 新航 举行 联欢会 实验', '');
INSERT INTO public.news VALUES (983, 'Chinese Dream，Xinhang Dream', '', '&quot;Speak Chinese, write Chinese characters, learn Chinese history, eat Chinese food,and listen to Chinese songs. On this honorable and warm-blooded land, I am happy to feel the atmosphere of China....', '', '<p><span>&quot;Speak Chinese, write Chinese characters, learn Chinese history, eat Chinese food,and&nbsp;listen to&nbsp;Chinese songs.&nbsp;On this honorable and warm-blooded&nbsp;land, I am happy to feel the atmosphere of China.&nbsp;We are&nbsp;Chinese&nbsp;students,&nbsp;and&nbsp;we are members of Jinan XinHang Experimental Foreign Language School.&nbsp;we&nbsp;have the Chinese dream,&nbsp;and&nbsp;we&nbsp;have a XinHang&nbsp;dream...&quot;. On&nbsp;December 9</span><sup><span>th</span></sup><span>,&nbsp;the &quot;Dream of Youth&quot; patriotic theme speech&nbsp;contest&nbsp;of&nbsp;Jinan Xinhang&nbsp;experimental foreign language school officially kicked off&nbsp;with punchy voice and&nbsp;beautiful melody.&nbsp;Starting from 16:40&nbsp;in the afternoon, the contest lasted nearly two hours, and all the participants&nbsp;express their love to motherland and wish a&nbsp;better future.</span></p><p><span><a href="images/c57106d77882420abc3e61cef3a62b76.jpg" target="_blank"><img title="8f78acd61f50f40f779cb07cb96b4d6.jpg" src="/uploads/migration/images/c57106d77882420abc3e61cef3a62b76.jpg"/></a></span></p><p><span><a href="images/50431a82e9ae48a5af266946616f5ce8.jpg" target="_blank"><img title="1cda7652f580151affc21827e0de107.jpg" src="/uploads/migration/images/50431a82e9ae48a5af266946616f5ce8.jpg"/></a><a href="images/68e24a99a81d4bbc8bb6c0427670373e.jpg" target="_blank"><img title="412e94081ad7147d6dae90b6ee48ea4.jpg" src="/uploads/migration/images/68e24a99a81d4bbc8bb6c0427670373e.jpg"/></a></span></p><p><span>The contest began with&nbsp;secondary school groups, and three students from class five gave&nbsp;a speech entitled &quot;carry forward a better Xinhang”. They deeply reviewed when they&nbsp;was a child&nbsp;lying on their grandpa&#39;s shoulder and listening to a story, from&nbsp;a&nbsp;decade of hard studying to serving the country by joining&nbsp;the army,&nbsp;the content of speech&nbsp;impressed&nbsp;all&nbsp;the&nbsp;audience&nbsp;deeply.&nbsp;When it came&nbsp;to the end &quot;The&nbsp;sunshine&nbsp;is&nbsp;in your heart,&nbsp;the power is under your&nbsp;feet &quot;, the brilliant competitors gained&nbsp;the applause instantly.&nbsp;Such a wonderful speech&nbsp;competition&nbsp;full of passion and emotions&nbsp;made&nbsp;the judges struggle&nbsp;to choose&nbsp;who is the winner.</span></p><p><span>The speech of senior high school students was also eye-catching, especially the works of Chen Jiayao, a senior high school freshman who left a deep impression on the audience. Her speech included&nbsp;the&nbsp;dream of home and the dream of our country as well as her dream. When she was a child, her dream was to be a judge. She thought the judge having&nbsp;white and curly hair&nbsp;was cool, and they always&nbsp;wear&nbsp;a long robe, and hold a mallet like a magic wand. When she grew up, she knew that the magic wand was a symbol of justice. In the competition between good and evil, between right and evil, the magic wand could defend the right way of the world and retain the warmth of the world, so she never forgot he</span><span>r </span><span>original heart Ask for help. All the audience were&nbsp;deeply moved by her wonderful speech.</span></p><p><span><a href="images/15cadab1a13e478e869cd9385041c63e.jpg" target="_blank"></a><a href="images/599275e53b94441fa13ad631279bae20.jpg" target="_blank"><img title="5b1b27d045ec96dcb0b45e94d4a0bda.jpg" src="/uploads/migration/images/599275e53b94441fa13ad631279bae20.jpg"/></a></span></p><p><span>Patriotism is not just a slogan.&nbsp;As a student of Xinhang Experimental Foreign Language School, we should be down-to-earth while looking up to the starry sky. We should start from scratch, living up to our expectation to our youth, and strive to realize our life value and youth dream!</span></p><p><span><br/></span></p><p><span>供稿：付真玉</span></p><p><span>翻译：董朝伦、张修玮、司陆阳、玄子涵</span></p><p><span>翻译指导：孙雨辰</span></p><p><span><br/></span></p><p><span><br/></span></p><p>&nbsp;</p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-12-26 08:00:00+08', '2019-12-26 08:00:00+08', '2019-12-26 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (984, 'Look! 10 Key Words of JXEFLS in 2019', '', ' Key word 1 : The Culture of CampsPilot Summer Camp was held in July, 2019 to welcome the new Grade 7 and Grade 10, after which came the Summer Camp for Talents in science and the Summer Camp for Orie...', '', '<p><span></span></p><p>&nbsp;</p><p><span>Key word</span><span>&nbsp;1 </span><span>: The Culture of Camps</span></p><p><span>Pilot Summer Camp was held in July, 2019</span><span>&nbsp;</span><span>to welcome the new Grade 7 and Grade 10, after which came the Summer </span><span>C</span><span>amp for</span><span>&nbsp;</span><span>T</span><span>alents</span><span>&nbsp;in science and the Summer</span><span>&nbsp;C</span><span>amp for </span><span>O</span><span>rientation</span><span>. &nbsp;The culture of camps has become a unique</span><span>&nbsp;</span><span>characteristic of Jinan Xinhang Experimental Foreign Language School. </span></p><p><span></span></p><p><a href="images/58cb2d8f5b3146ab95be8e82816bb4fb.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/58cb2d8f5b3146ab95be8e82816bb4fb.jpg"/></a><a href="images/10cfb6fb0e244525872543df45269de9.jpg" target="_blank"><img title="11.jpg" src="/uploads/migration/images/10cfb6fb0e244525872543df45269de9.jpg"/></a></p><p><span></span></p><p>&nbsp;</p><p><span>Key word</span><span>&nbsp;2 </span><span>: Debut</span></p><p><span>The news conference for the debut of Jinan</span><span>&nbsp;</span><span>Xinhang Experimental Foreign Language School was held on May 24th, 2019.</span><span>&nbsp;</span><span>Present at the conference are Mr. Han Xianghe, Principal of Shandong</span><span>&nbsp;</span><span>Experimental High School, Mr. Li Tao, </span><span>President</span><span>&nbsp;</span><span>of </span><span>B</span><span>oard </span><span>of Jinan Xinhang</span><span>&nbsp;</span><span>Experimental Foreign Language School, and Mr. Lin Baolei, Executive Principal of Jinan</span><span>&nbsp;</span><span>Xinhang Experimental Foreign Language School. </span><span>From </span><span>June 10th, four Information</span><span>&nbsp;</span><span>Sessions for enrolment </span><span>were</span><span>&nbsp;</span><span>held </span><span>to </span><span>a </span><span>full-house.</span><span>&nbsp;</span><span>&nbsp;<span>&nbsp;</span></span></p><p><a href="images/8b9dbf11780a46bb9814cd85149b0594.jpg" target="_blank"><img title="2.jpg" src="/uploads/migration/images/8b9dbf11780a46bb9814cd85149b0594.jpg"/></a><a href="images/6c7a10a6b4db4381a5246a00e62d6333.jpg" target="_blank"><img title="22.jpg" src="/uploads/migration/images/6c7a10a6b4db4381a5246a00e62d6333.jpg"/></a></p><p><span></span></p><p>&nbsp;</p><p><span>Key word 3</span><span>&nbsp;: F</span><span>reshmen</span></p><p><span>&nbsp;</span><span>&nbsp;&nbsp;&nbsp;</span><span>Jinan Xinhang Experimental Foreign Language School embraced the successful enrollment with 150 freshmen for each grade (grade 7 and grade 10) in July. As for these students, it is a brand-new start to join in JXEFLS; as for the school, their arrival also freshen the campus us with new vigor and energy.</span></p><p><span></span></p><p><a href="images/96ec33885cf244719b7db15c17926225.jpg" target="_blank"><img title="33.jpg" src="/uploads/migration/images/96ec33885cf244719b7db15c17926225.jpg"/></a><a href="images/9f7b728e1877422992c074ab2241507b.jpg" target="_blank"><img title="3.jpg" src="/uploads/migration/images/9f7b728e1877422992c074ab2241507b.jpg"/></a></p><p><span></span></p><p>&nbsp;</p><p><span>Key word 4</span><span>&nbsp;: </span><span>&nbsp;Brand new chapter</span></p><p><span>&nbsp;</span><span>&nbsp;&nbsp;&nbsp;&nbsp;</span><span>On the morning of September 9, the opening ceremony of Jinan Xinhang Experimental Foreign Language School was held in the newly established multimedia auditorium with 300 freshmen and more than 200 parents witnessing the big moment. From that moment on, JXEFLS </span><span>offic</span><span>i</span><span>ally </span><span>started a new chapter and set sail.</span></p><p><span></span></p><p><span><a href="images/aa1a990078704d079e5450032383b9ee.jpg" target="_blank"><img title="4.jpg" src="/uploads/migration/images/aa1a990078704d079e5450032383b9ee.jpg"/></a><a href="images/6e3907661b164041b2a25e7eb2821c6d.jpg" target="_blank"><img title="44.jpg" src="/uploads/migration/images/6e3907661b164041b2a25e7eb2821c6d.jpg"/></a></span></p><p><span><span></span></span></p><p>&nbsp;</p><p><span>Key word 5 </span><span>: </span><span>Home-School Co-education</span></p><p><span>&nbsp;</span><span>&nbsp;&nbsp;</span><span>On September 20, the cooperative education between the school and </span><span>families </span><span>came into being with the fifteen-member Parents&#39; </span><span>Commission</span><span>&nbsp;</span><span>officially established. In order to strengthen its education mode and to </span><span>enable the </span><span>teachers </span><span>to </span><span>have </span><span>a</span><span>&nbsp;</span><span>more comprehensive and deeper understanding of </span><span>the </span><span>students, JXEFLS created the experience-based</span><span>,</span><span>&nbsp;</span><span>face-to-face</span><span>&nbsp;parents&#39; meeting</span><span>, </span><span>which </span><span>gained </span><span>praise</span><span>&nbsp;</span><span>from both parents and students. The theme of this activity is &quot;</span><span>U</span><span>nderstanding and </span><span>S</span><span>olution</span><span>s</span><span>&quot;, that is, understanding </span><span>the </span><span>students, understanding</span><span>&nbsp;</span><span>the</span><span>&nbsp;</span><span>teachers and understanding problem-solving methods.</span><span>&nbsp;</span></p><p><span></span></p><p><span><a href="images/6a8cc37025a84705aeeb67bbcfc26d59.jpg" target="_blank"><img title="5.jpg" src="/uploads/migration/images/6a8cc37025a84705aeeb67bbcfc26d59.jpg"/></a><a href="images/680be5a0ba944811bf3362f86f055a88.jpg" target="_blank"><img title="55.jpg" src="/uploads/migration/images/680be5a0ba944811bf3362f86f055a88.jpg"/></a></span></p><p><span><span></span></span></p><p>&nbsp;</p><p><span>Key word</span><span>&nbsp;6 </span><span>: Party Building</span></p><p><span>On 25th, September, Branch </span><span>Committee </span><span>of </span><span>the </span><span>CPC </span><span>of JXEFLS was founded. All the Party members attended the ceremony and</span><span>&nbsp;elected the committee members of </span><span>CPC</span><span>&nbsp;Branch of JXEFLS.</span></p><p><span></span></p><p><span>&nbsp;<a href="images/85c7543723a547fa863d0ee403b2a0f6.jpg" target="_blank"><img title="6.jpg" src="/uploads/migration/images/85c7543723a547fa863d0ee403b2a0f6.jpg"/></a><a href="images/bee07a1913fb4431989bdcc5a49a46f6.jpg" target="_blank"><img title="66.jpg" src="/uploads/migration/images/bee07a1913fb4431989bdcc5a49a46f6.jpg"/></a></span></p><p><span><span></span></span></p><p>&nbsp;</p><p><span>K</span><span>ey word</span><span>&nbsp;7 </span><span>: </span><span>A</span><span>wards</span></p><p><span>Even though it&#39;s been only a few months since school started, JXEFLS students have achieved good results in various competitions. On Sep 21st, Bian Haoyu won one gold and two bronze medals in the 2019 China Youth Equestrian Competition. On Oct. 24th, Wei Ziyuan won </span><span>th</span><span>e first prize&nbsp;in 2019 National Defense Knowledge Contest for </span><span>P</span><span>rimary and </span><span>S</span><span>econdary </span><span>S</span><span>chool </span><span>S</span><span>tudents.</span><span>&nbsp;On Oct. 26th, the team of Grade 7 won the</span><span>&nbsp;</span><span>first</span><span>&nbsp;</span><span>prize in the </span><span>R</span><span>ope </span><span>S</span><span>kipping </span><span>C</span><span>ompetition for Elementary and</span><span>&nbsp;S</span><span>econdary </span><span>S</span><span>chools in Jinan. </span></p><p><span></span></p><p><span><a href="images/3a88f43acc6e4ae0acefd0a9f4bcd9d8.jpg" target="_blank"><img title="7.jpg" src="/uploads/migration/images/3a88f43acc6e4ae0acefd0a9f4bcd9d8.jpg"/></a><a href="images/d80691d0cbde46c2aa95947ed56f2c1d.jpg" target="_blank"><img title="77.jpg" src="/uploads/migration/images/d80691d0cbde46c2aa95947ed56f2c1d.jpg"/></a></span></p><p><span></span></p><p>&nbsp;</p><p><span>K</span><span>ey word</span><span>&nbsp;8 </span><span>:</span><span>&nbsp;</span><span>Experts</span></p><p><span>Each month ,</span><span>&nbsp;</span><span>our school is visited by well-known experts from different fields</span><span>. </span><span>Since the school started, we have received more than 20 experts, including</span><span>&nbsp;</span><span>Dr. Song Xuejun </span><span>from</span><span>&nbsp;</span><span>Southern&nbsp;University&nbsp;of&nbsp;Science&nbsp;and&nbsp;Technology</span><span>; </span><span>Professor Hao Jingcheng, </span><span>D</span><span>ean of </span><span>C</span><span>hemistry and Chemical Engineering, Shandong University</span><span>; </span><span>Professor Huang</span><span>&nbsp;</span><span>Yingqiang from Duke</span><span>-</span><span>Kunshan University</span><span>; Mr.</span><span>&nbsp;Gennady Varlamov</span><span>, </span><span>vice president of</span><span>&nbsp;the</span><span>&nbsp;State Technical University of Ukraine</span><span>;</span><span>&nbsp;Professor Qiu Jing</span><span>, </span><span>tenure</span><span>&nbsp;</span><span>of Electrical and Information Engineering of University of Sydney, Australia. </span><span>All the experts brought to</span><span>&nbsp;our students a series of academic feasts</span><span>. </span></p><p><span><span></span></span></p><p><span><a href="images/65675c0698f54847abaece9ee3fa7bb2.jpg" target="_blank"><img title="8.jpg" src="/uploads/migration/images/65675c0698f54847abaece9ee3fa7bb2.jpg"/></a><a href="images/4dad3d1bbad04b8ea9971a473461563a.jpg" target="_blank"><img title="88.jpg" src="/uploads/migration/images/4dad3d1bbad04b8ea9971a473461563a.jpg"/></a></span></p><p><span><span></span></span></p><p>&nbsp;</p><p><span>K</span><span>ey word</span><span>&nbsp;</span><span>9</span><span>&nbsp;:</span><span>&nbsp;Tutor</span></p><p><span>Students can choose any teacher they like to be their tutor or </span><span>adviser</span><span>, to whom they can </span><span>turn </span><span>for academic assistance</span><span>, </span><span>career guidance and even confide their secrets from the bottom of their heart. On December 11 and 12, all the 36 tutors </span><span>met </span><span>their tutees, </span><span>marking </span><span>the start of the tutor program. Like a parent in a family, every tutor will </span><span>ac</span><span>company </span><span>his/her</span><span>&nbsp;tutee</span><span>s</span><span>&nbsp;and </span><span>organize different activities to offer professional guidance about students’ academic study, personal life and </span><span>career planning</span><span>. </span></p><p><span></span></p><p><span><a href="images/094a8a9c944c4544ad0bef313b61d723.jpg" target="_blank"><img title="9.jpg" src="/uploads/migration/images/094a8a9c944c4544ad0bef313b61d723.jpg"/></a><a href="images/b76db8875a824aa784906f106c8210e8.jpg" target="_blank"><img title="99.jpg" src="/uploads/migration/images/b76db8875a824aa784906f106c8210e8.jpg"/></a></span></p><p><span></span></p><p>&nbsp;</p><p><span>K</span><span>ey word</span><span>&nbsp;</span><span>10</span><span>&nbsp;: </span><span>Curriculum</span></p><p><span>In order to promote the all-round development of our students and help everyone of them find their interests, highly distinctive courses </span><span>are developed in </span><span>JXEFLS</span><span>. These courses cover various topics including labor education, patriotic education, safety education</span><span>,</span><span>&nbsp;</span><span>extra-curriculum</span><span>&nbsp;</span><span>courses </span><span>on</span><span>&nbsp;</span><span>weekends, and abundant school-based courses, covering the knowledge and skills of nearly every aspect in life. On December, 12, 2019, many students and teachers </span><span>work</span><span>ed</span><span>&nbsp;</span><span>together to make pickled vegetables, </span><span>and </span><span>bake</span><span>d</span><span>&nbsp;cupcakes, marking the official launch of labor education course. The activities are creative and practical, winning the acclaim from teachers, students and parents. Some other </span><span>wonderful</span><span>&nbsp;</span><span>and meaningful activities</span><span>,</span><span>&nbsp;including drawing </span><span>the plan of </span><span>the campus</span><span>, holding patriotic speech contests, organizing painting and calligraphy exhibition, help make the patriotic education and safety education more effective.</span></p><p><span></span></p><p><span><a href="images/07642a0045724f97b33d76d4859f1562.jpg" target="_blank"><img title="10.jpg" src="/uploads/migration/images/07642a0045724f97b33d76d4859f1562.jpg"/></a><a href="images/aa19a6b0589040a58462200cb7f650e0.jpg" target="_blank"><img title="1010.jpg" src="/uploads/migration/images/aa19a6b0589040a58462200cb7f650e0.jpg"/></a></span></p><p><span>翻译：石峰、孙雨辰、王冉、王春晓</span></p><p><br/></p><p><span></span></p><p><span></span></p><p><span><br/></span></p><p>&nbsp;</p><p><span></span></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-12-26 08:00:00+08', '2019-12-26 08:00:00+08', '2019-12-26 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (985, '回眸2019，济南新航实验十件大事请您检阅', '', '       即将过去的2019年，对于济南新航实验外国语学校来说是极不平凡的一年，既是开元之年，也是起航之年，一座高起点、高定位的新航实验在济南东部拔地而起。坚持以学生为中心，推进教师学术专业成长，着力打造“精品小班、多元融合”的民办教育新高地，为济南教育贡献力量。       2019年即将进入尾声，一个个温暖人心的新航实验故事，一幕幕值得回味的精彩瞬间，一件件载入新航实验校史的大事，都在发生...', '', '<p><br/></p><p><br/></p><p><a href="images/34fe597020a146c99d5f7e10999fc303.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_34fe597020a146c99d5f7e10999fc303.jpg" width="500" height="281"/></a><br/></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 即将过去的2019年，对于济南新航实验外国语学校来说是极不平凡的一年，既是开元之年，也是起航之年，一座高起点、高定位的新航实验在济南东部拔地而起。坚持以学生为中心，推进教师学术专业成长，着力打造“精品小班、多元融合”的民办教育新高地，为济南教育贡献力量。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2019年即将进入尾声，一个个温暖人心的新航实验故事，一幕幕值得回味的精彩瞬间，一件件载入新航实验校史的大事，都在发生着，我们共同见证着新航实验的成长。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 新的一年即将到来之际，用关键词做串联，“2019济南新航实验十件大事”（排名不分先后）出炉，你我共同阅读新航实验的2019吧！</p><p><strong><span>关键词1.营文化</span></strong></p><p><strong><span><a href="images/40410d2a62434004983469e766c2dd6c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_40410d2a62434004983469e766c2dd6c.jpg" width="500" height="333"/></a><a href="images/c5c5408ece4f4f2b9e1ec383ee64fc13.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c5c5408ece4f4f2b9e1ec383ee64fc13.jpg" width="500" height="333"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2019年7月13日—14日、19日，新航实验在山东省实验中学中心校区举办领航夏令营暨新生家长见面会活动，分别为新航实验首届初一学子和高一学子提前进入新航实验打下基础。领航营期间，学生们走进省实验中学、聆听专家报告，在实验学长的带领下触摸实验文化和校史。紧接着，2019年基础学科拔尖创新人才夏令营、入学教育夏令营相继开营，营文化已经成为新航实验一道靓丽风景。</p><p><strong><span>关键词2.亮相</span></strong></p><p><strong><span><a href="images/7d6347d2fe9040e6a92e6b1981bc13aa.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_7d6347d2fe9040e6a92e6b1981bc13aa.jpg" width="500" height="333"/></a><br/></span></strong></p><p><strong><span></span></strong><strong><span><a href="images/c6a382a7932e48df892fc5e501309410.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c6a382a7932e48df892fc5e501309410.jpg" width="500" height="278"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2019年5月24日，新航实验首场新闻发布会在山东省实验中学召开，山东省实验中学党委书记、校长韩相河，山东出版文化置业有限公司董事长李涛，济南新航实验外国语学校执行校长林宝磊带领管理团队首次集中亮相，“官宣”后立刻引爆了济南家长的关注点。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2019年6月10日开始，新航实验接连举办三场高中说明会，7月10日又进行了初中招生说明会，场场迅速爆满。作为今年备受瞩目的新起之秀，新航实验自进入大众视野以来，来自社会各界的关注度就一路升温，各种线下咨询热度仍然持续不减。</p><p><strong><span>&nbsp;关键词3.新生</span></strong></p><p><strong><span><a href="images/e8bac2509f9f4237bd56bbfeaf5b4017.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e8bac2509f9f4237bd56bbfeaf5b4017.jpg" width="500" height="333"/></a></span></strong><strong><span><a href="images/f20f8eb370e54d82ae6aef3623f1041a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f20f8eb370e54d82ae6aef3623f1041a.jpg" width="500" height="328"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 2019年7月，新航实验圆满完成首届招生，从数千名报名学生中遴选出初一和高一新生各150名，高质量完成2019年招生计划。加入新航实验对于这些学生们来说是一次全新的起航，他们的到来对于新航实验来说也意味着注入了新的生机，随着8月25日和9月1日高一、初一新生报到，崭新的新航校园迎来了全新的活力和生命，新航实验的序幕正式揭开。</p><p><strong><span>关键词4.起航</span></strong></p><p><strong><span><a href="images/d55b24ded63c4bc3ac3a837696d85eb7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d55b24ded63c4bc3ac3a837696d85eb7.jpg" width="500" height="333"/></a></span></strong><strong><span><a href="images/a90b21eee8e24f8abb6f9cdf40aba349.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a90b21eee8e24f8abb6f9cdf40aba349.jpg" width="500" height="333"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 9月9日上午，新航实验建校后的第一次开学典礼在新落成的多媒体大剧院隆重举行，300名新生与200余位家长代表与知名嘉宾教授齐聚一堂，共同见证首批新航学子的人生重要时刻，这也意味着，备受关注的新航实验正式扬帆起航。</p><p><strong><span>关键词5.家校</span></strong></p><p><strong><span><a href="images/25f8ccc21b84499888eee285365ed2f7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_25f8ccc21b84499888eee285365ed2f7.jpg" width="500" height="333"/></a></span></strong></p><p><strong><span><a href="images/1e449136fc3f4e53ae1604f8923557e5.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1e449136fc3f4e53ae1604f8923557e5.jpg" width="500" height="333"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 9月20日，新航实验举行2019级家长委员会成立大会。经过自荐、班级推荐、学校研究确定，初一级部和高一级部共有15位家长当选为2019级家长委员会委员，新航实验家校合作之路正式启程。</p><p>为加强家校沟通，让老师更全面、更深入地认识学生，同时也让家长近距离了解学生的学习和生活情况，从10月17日开始，一直到22日晚，新航实验以班为单位举行“剧组式”学生家长交流会，分批邀请家长进校座谈，学生、家长、任课教师、班主任四方共同参与。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 11月14日开始，新航实验首创的“三味三境”体验式家长会暨学情会商活动正式拉开帷幕，此次活动的主题是“解”，即了解学生、理解老师、解决困惑，每个班分批邀请家长到校参加家长会，家长和学生分别与各科老师面谈，获得学生和家长的一致认可。</p><p><strong><span>关键词6.党建</span></strong></p><p><strong><span><a href="images/d33a31b7f0654ab8bb4102caa3b825dc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d33a31b7f0654ab8bb4102caa3b825dc.jpg" width="500" height="333"/></a></span></strong></p><p><strong><span><a href="images/1f3ae0ce13684da0ae04ffbe0bbfbc34.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1f3ae0ce13684da0ae04ffbe0bbfbc34.jpg" width="500" height="750"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 9月25日，正值举国欢庆新中国成立70周年之际，新航实验迎来建校史上值得纪念的一件大事——学校党支部成立暨委员会选举大会，全体党员以及中层以上非党员干部参会。本次党员大会以无记名投票的方式差额选举第一届支部委员会，根据大会通过的选举办法，确认当选的第一届支部委员会委员。</p><p><strong><span>关键词7.获奖</span></strong></p><p><strong><span><a href="images/325ef1f902c44c8cbcaca751ef06b48b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_325ef1f902c44c8cbcaca751ef06b48b.jpg" width="500" height="315"/></a><br/></span></strong></p><p><strong><span></span></strong><strong><span><a href="images/75458802f80c470b8439c75ee5390723.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_75458802f80c470b8439c75ee5390723.jpg" width="500" height="281"/></a></span></strong></p><p>&nbsp;&nbsp; &nbsp; &nbsp; 尽管开学时间不长，新航实验学子在全市各项比赛中屡获佳绩。9月21日，为期两天的“水发·体彩杯”2019年中国马术青少年大赛在济南国际赛马场拉开战幕，新航实验高一五班学生卞浩宇，摘得一枚金牌和两枚铜牌。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 10月24日下午，新航实验高一三班学生魏子元代表学校参加济南市2019年中小学生国防知识竞赛，经过现场激烈角逐，最终斩获高中组一等奖。10月26日，在济南市教育局主办的“2019年济南市中小学生跳绳比赛”中，新航实验初一级部代表队获初中组团体一等奖，高一级部代表队获高中组团体二等奖、优秀表演奖。</p><p><strong><span>关键词8.名家</span></strong></p><p><strong><span><a href="images/0d6b921a8ba84934adcc61e070c477a2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0d6b921a8ba84934adcc61e070c477a2.jpg" width="500" height="394"/></a><br/></span></strong></p><p><strong><span><a href="images/c58c36303af5444c8e44b34caa8d74a9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c58c36303af5444c8e44b34caa8d74a9.jpg" width="500" height="281"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在新航实验，几乎每个月都有知名专家进校园，为学生们带来前沿报告和讲座，提升了新航学子的眼界。从9月9日的开学典礼开始，新航实验先后迎来数位学术“大咖”，其中包括长江学者特聘教授、南方科技大学教授博导宋学军，长江学者特聘教授、山东大学化学与化工学院院长郝京诚，昆山杜克大学教授黄英强，乌克兰国立技术大学副校长根纳季·瓦尔拉莫夫教授，澳大利亚悉尼大学电气与信息工程学院讲师（终身教职）邱靖等，名家的高端引领为新航实验师生们带来一场场重量级学术大餐。</p><p><strong><span>&nbsp;关键词9.导师</span></strong></p><p><strong><span><a href="images/e8c2df9f9ae44e549f6b65b281877320.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e8c2df9f9ae44e549f6b65b281877320.jpg" width="500" height="333"/></a><br/></span></strong></p><p><strong><span><a href="images/272f08fd3dd3462fa0ad77da5ff11b29.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_272f08fd3dd3462fa0ad77da5ff11b29.jpg" width="500" height="375"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 倾听倾诉，共话成长，随着导师制的落地，12月11日、12日，新航实验举行导师集体见面会，36位学生导师分别与学生探讨学业和生活话题，共话成长，每一位新航实验学子都有了专属的学习导师，导师自组“家庭”和学生共同成长，通过定期举办的谈话、辅导、聚会、座谈等面对面交流，积极沟通学习生活、生涯规划、期末复习等问题。</p><p><strong><span>关键词10.融合</span></strong></p><p><strong><span><a href="images/9ae1f8d6a2db4cc9961588d3e4d61114.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9ae1f8d6a2db4cc9961588d3e4d61114.jpg" width="500" height="375"/></a><a href="images/03276934742d4d02903779e60bb8ca53.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_03276934742d4d02903779e60bb8ca53.jpg" width="500" height="375"/></a></span></strong></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在做好常规课程的同时，新航实验开发了周末延伸课程、校本课程、劳动课程等特色课程。为促进学生全面且富有个性的发展， 10月12日，新航实验周末拓展课程正式亮相。其中，既有为学生提供精准帮助的学业辅导，也有邀请学生家长进校陪餐的关怀，既有为学生升学规划提前指导的专家讲座，也有丰富多彩的艺体课程和观影活动。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在课程建设方面，国际教育中心推出系列融合课程，供学生自主选择。同时，33门校本课为新航实验学子提供“私人订制”，门类多，33门校本课跨度大，天文地理古今中外全囊括，高精尖，先进高端的设备令学生惊呼“帅呆了”。12月13日，新航实验开发的劳动教育正式启动，师生动手制作泡菜、烤蛋糕等，注重实效，创新课堂，获得师生和家长们的一致好评。</p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-12-25 08:00:00+08', '2019-12-25 08:00:00+08', '2019-12-25 08:00:00+08', '王雪', '新航实验外国语学校', '新航 实验 十件 大事 济南', '');
INSERT INTO public.news VALUES (986, '向身边榜样学习，新航实验举行期中表彰活动', '', '       经过开学以来两个多月的学习和生活，新航实验涌现出一大批学生们身边的榜样，他们中，既有钻研学习的“学霸大神”，也有进步显著的“飞跃之星”，更有学科特长鲜明的“单科状元”，为表彰优秀、鼓励先进、营造浓厚的学习氛围，进一步调动新航实验学子学习的主动性和积极性，11月18日，济南新航实验外国语学校隆重举行期中表彰活动，初一级部、高一级部全体师生参加此次活动。       18日上午，新航实验...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 经过开学以来两个多月的学习和生活，新航实验涌现出一大批学生们身边的榜样，他们中，既有钻研学习的“学霸大神”，也有进步显著的“飞跃之星”，更有学科特长鲜明的“单科状元”，为表彰优秀、鼓励先进、营造浓厚的学习氛围，进一步调动新航实验学子学习的主动性和积极性，11月18日，济南新航实验外国语学校隆重举行期中表彰活动，初一级部、高一级部全体师生参加此次活动。</span></p><p><span><a href="images/626536ae0f634a27891707faa53fe36f.jpg" target="_blank"><a href="images/0a9032426fc446caaf3789a48d8ad34e.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0a9032426fc446caaf3789a48d8ad34e.jpg" width="500" height="357"/><a href="images/0a9032426fc446caaf3789a48d8ad34e.jpg" target="_blank"><a href="images/b9ea3e9a0c184035b5f9507eedfc0cbc.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b9ea3e9a0c184035b5f9507eedfc0cbc.jpg" width="500" height="385"/></a></a></a></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 18日上午，新航实验多媒体大剧院内，新航实验学子边鼓掌边热切注视着台上领奖的同学们——他们用自己的勤奋赢得了走上领奖台的瞩目一刻，今天他们每个人都是主角。单科学习状元、学习进步奖、学习优胜奖……台上一位位新航实验学子意气风发、精神抖擞，台下各班同学凝神细看。稳健优秀的同学成为典范，起点一般但努力进步的同学也倍受关注。济南新航实验外国语学校执行校长林宝磊，以及新航实验副校长张爱梅、张术磊等学校领导，分别上台为获奖学生颁发奖状。</span></p><p><span><a href="images/af0b1c465b3a46bb8e987aca77e73e7c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_af0b1c465b3a46bb8e987aca77e73e7c.jpg" width="500" height="325"/></a><a href="images/9f46ec681db34915b779ab8922f3a3df.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_9f46ec681db34915b779ab8922f3a3df.jpg" width="500" height="362"/></a><a href="images/74629a7f5acb485980b8b5f47d3ad5bd.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_74629a7f5acb485980b8b5f47d3ad5bd.jpg" width="500" height="275"/></a></span></p><p></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 颁奖仪式结束后，新航实验教学管理中心主任王飞对期中教育教学工作进行总结，对同学们表示肯定的同时，也督促大家继续努力，养成良好的学习习惯，同时他还勉励全体同学调整步伐、迎头赶上，争取在下一阶段的学习中取得更大进步。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在新航实验，只要努力，每一个人都有机会站上领奖台！成功来自坚持，执着创造奇迹；积一时之跬步，致千里之遥程。这次表彰大会，极大地鼓舞了新航实验师生的士气，振作了他们的精神，互相鼓励，共同向身边的榜样学习。期中总结虽然结束，但成长的征程才刚刚开始，接下来的时间里，每一个新航实验人都将齐心协力、努力拼搏！</span></p><p><span><a href="images/626536ae0f634a27891707faa53fe36f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_626536ae0f634a27891707faa53fe36f.jpg" width="500" height="295"/></a></span></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '王雪', '新航实验外国语学校', '实验 举行 新航 学习 期中', '');
INSERT INTO public.news VALUES (987, '名家进校园，与新航学子对话新能源与环境话题', '', '       27日下午，济南新航实验外国语学校专家进校园主题讲座持续拉开帷幕，此次讲座包括两个主题：新能源与生态环境、电力市场，分别由乌克兰国立技术大学副校长根纳季·瓦尔拉莫夫教授和澳大利亚悉尼大学电气与信息工程学院讲师（终身教职）邱靖博士主讲，为新航实验师生们带来一场学术大餐。     “如果没有了能源，我们的生活会怎样？没有暖气，可以重回穴居时代。没有电灯，蜡烛可以带来光明。没有能源我们如何...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 27日下午，济南新航实验外国语学校专家进校园主题讲座持续拉开帷幕，此次讲座包括两个主题：新能源与生态环境、电力市场，分别由乌克兰国立技术大学副校长根纳季·瓦尔拉莫夫教授和澳大利亚悉尼大学电气与信息工程学院讲师（终身教职）邱靖博士主讲，为新航实验师生们带来一场学术大餐。</span></p><p><span><a href="images/5624113f8a384d29a70871e3bd4ac584.jpg" target="_blank"><a href="images/5624113f8a384d29a70871e3bd4ac584.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5624113f8a384d29a70871e3bd4ac584.jpg" width="500" height="394"/></a></a></span></p><p></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; “如果没有了能源，我们的生活会怎样？没有暖气，可以重回穴居时代。没有电灯，蜡烛可以带来光明。没有能源我们如何生活？我们已经习惯了能源赋予我们的种种便利。因为能源，我们的生活多么舒适，舒适就需要有供电、热水和供暖，因此，能源生产和节约能源非常必要。” 根纳季·瓦尔拉莫夫教授首先通过通俗的举例，将同学们的注意力带入到能源这个看似遥远实则近在咫尺的话题。紧接着他又从可持续发展、能源开发的生态平衡原则、新能源计划等角度展开，介绍了目前最前沿的新能源理念和设备，引起了学生们的强烈兴趣。<br/></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 紧接着，邱靖博士为新航实验学子们们带来了电力市场概论相关主题讲座。他首先从自己的求学经历讲到电力工业，详细介绍了电力工业生产经营的技术特点、市场含义、如何构建电力市场、国内外电力市场情况等方面的前沿学科知识。在讲座过程中，邱靖博士充分考虑到中学生的接受能力，中英文结合，生动有趣、深入浅出的从物理学、经济学两个角度介绍了电力市场相关知识，赢得了学生们的一致好评。<br/></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 两场讲座结束后，新航实验三位学生代表踊跃发言，围绕新能源和生态环境话题与两位专家进行了深入交流。</span></p><p><span>日前，中央深改委审议通过了《关于全面加强新时代大中小学劳动教育的意见》、《关于深化新时代教育督导体制机制改革的意见》等，其中明确强调，劳动教育是中国特色社会主义教育制度的重要内容，同时明确指出，要以推进环境治理体系和治理能力现代化为目标，推动生态环境根本好转、建设美丽中国。</span></p><p><span><a href="images/b184c2e56d7c491b97564ba7e5c96d68.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b184c2e56d7c491b97564ba7e5c96d68.jpg" width="500" height="331"/></a><a href="images/a268b8c081a44eadb3dbddf4049366eb.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a268b8c081a44eadb3dbddf4049366eb.jpg" width="500" height="401"/></a></span></p><p><span><a href="images/91a49b79c3d340789bb265e4cfab4a89.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_91a49b79c3d340789bb265e4cfab4a89.jpg" width="500" height="307"/></a><br/></span></p><p><span><span>&nbsp;&nbsp;&nbsp;&nbsp; 日前，中央深改委审议通过了《关于全面加强新时代大中小学劳动教育的意见》、《关于深化新时代教育督导体制机制改革的意见》等，其中明确强调，劳动教育是中国特色社会主义教育制度的重要内容，同时明确指出，要以推进环境治理体系和治理能力现代化为目标，推动生态环境根本好转、建设美丽中国。</span></span></p><p><span><span><a href="images/32afaf076cf44b6ea73be1670e7cc783.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_32afaf076cf44b6ea73be1670e7cc783.jpg" width="500" height="331"/></a><a href="images/c7798afbed744190879cfa39f4580ca6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c7798afbed744190879cfa39f4580ca6.jpg" width="500" height="333"/></a></span></span></p><p></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 济南新航实验外国语学校始终坚持立德树人，高度重视劳动教育和环保教育在育人中的重要地位，将其纳入人才培养全过程，注重教育实效，实现知行合一。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 此次专家讲座活动不仅为新航实验学子提供了别开生面的前沿知识讲座，提高了学生们在环保领域的理论认知，还为日常点滴行动提供了切实指导。专家进校园系列主题活动在引导同学们多领域学习的基础上，充分开拓了同学们的国际视野，为成为“齐鲁君子，世界公民”助力。</span></p><p><br/></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '王雪', '新航实验外国语学校', '对话 学子 新能源 新航 校园', '');
INSERT INTO public.news VALUES (988, '安全记心间：新航实验举行消防安全逃生演练', '', '      11月7日上午，在“119消防安全日”即将到来前夕，为进一步提高全体师生的消防安全意识，增强应急处置突发事件的能力和遇到火险时逃生、自救能力，新航实验举行全员消防安全逃生演练活动，全校10个班级参加了此次活动。       中午13时20分，随着警报声响起，此次消防演练正式拉开序幕。学生们在听到警报声后，第一时间从公寓楼内有序撤出，在刺耳的警报声中，学生们在班主任的引导下，按照各自的疏...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 11月7日上午，在“119消防安全日”即将到来前夕，为进一步提高全体师生的消防安全意识，增强应急处置突发事件的能力和遇到火险时逃生、自救能力，新航实验举行全员消防安全逃生演练活动，全校10个班级参加了此次活动。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 中午13时20分，随着警报声响起，此次消防演练正式拉开序幕。学生们在听到警报声后，第一时间从公寓楼内有序撤出，在刺耳的警报声中，学生们在班主任的引导下，按照各自的疏散逃生路线，有的用湿毛巾捂住口鼻，利用最快速度完成疏散任务，到达操场安全区域后，各班班主任清点人数，最快抵达操场学生仅用时25秒。</span></p><p><span><a href="images/42d668c8bcc543bd9003a13b7430e57c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_42d668c8bcc543bd9003a13b7430e57c.jpg" width="500" height="368"/></a><a href="images/348dc08cda764897a86719df9d280d78.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_348dc08cda764897a86719df9d280d78.jpg" width="500" height="412"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 此次活动由新航实验学生发展中心、安全保卫科联合物业公司组织，事先制定了详细方案，既有消防知识的讲解，也有实际操作的演练，真正落实“关注消防，人人有责”的主题。<br/></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在之后的点评环节，新航实验副校长张术磊提醒全体师生，“安全重于一切，生命至关重要，不带易燃易爆物品进入校园，自觉爱护校园内的各种消防设施。”同时，他还提醒同学们，要认真对待学校组织的每一次消防安全知识讲座和疏散演习，掌握消防安全知识，熟悉疏散演习的路线和有关流程，以便遇到危险时有序地迅速疏散。</span></p><p><span><a href="images/28729fffb7364a2f8001f2c81c3a4776.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_28729fffb7364a2f8001f2c81c3a4776.jpg" width="500" height="333"/></a><a href="images/6bb117f3700e4e6e98feeffd81cc31c3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6bb117f3700e4e6e98feeffd81cc31c3.jpg" width="500" height="330"/></a></span></p><section><section><section><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 整个疏散过程中，师生配合默契、疏散路线清楚、组织有条不紊、人人各尽其责，达到了预期效果。通过此次消防演练，让同学们了解了消防安全知识以及怎样预防火灾事故的发生，懂得了“珍爱生命，安全第一”的意义。<br/></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 实际上，早在开学之初，学校就将安全教育作为一项日常工作，通过形式多样的安全主题班会和安全演练活动，让学生将安全牢记在心间。将接下来，新航实验还将根据方案定期开展系列安全主题教育活动，组织多种场景下的逃生演练和疏散，通过实战教育，真正提高学生的消防意识和防火防灾的应变能力。</span></p></section></section></section><p><br/></p><section><section><br/><br/></section></section><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '王雪', '新航实验外国语学校', '举行 安全 实验 逃生 新航', '');
INSERT INTO public.news VALUES (989, '热爱不息 青春无限：新航实验举行首届篮球3V3对抗赛', '', '       为贯彻落实“全国亿万青少年阳光体育运动”精神，践行“健康第一，全面发展”指导思想，提升新航实验学子的身体素质与文化修养，进一步丰富同学们的校园生活，12月1日下午，济南新航实验外国语学校高一级部举行主题为“热爱不息，青春无限”三人制篮球比赛。       比赛一开始，篮球健儿们迅速进入状态，立即主动出击，以矫健熟练的动作迅速传球，直逼篮板，个个雄姿英发。在场上你争我夺、你攻我守，展开...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span>为贯彻落实“全国亿万青少年阳光体育运动”精神，践行“健康第一，全面发展”指导思想，提升新航实验学子的身体素质与文化修养，进一步丰富同学们的校园生活，12月1日下午，济南新航实验外国语学校高一级部举行主题为“热爱不息，青春无限”三人制篮球比赛。</span></p><p><span><a href="images/c4f417838b32439499d0eeb3d42bfdf6.jpg" target="_blank"><a href="images/c4f417838b32439499d0eeb3d42bfdf6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_c4f417838b32439499d0eeb3d42bfdf6.jpg" width="500" height="403"/></a></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 比赛一开始，篮球健儿们迅速进入状态，立即主动出击，以矫健熟练的动作迅速传球，直逼篮板，个个雄姿英发。在场上你争我夺、你攻我守，展开了一轮轮的投球，帅气利落的动作赢得了周围观众的叫好。比赛过程中，场外的粉丝们也踊跃为本班队员加油助威，用他们的热情将比赛气氛推向了最高潮。每名队员激情高涨，争夺异常激烈，球场气氛十分活跃。最终高一四班、三班、五班在激烈的角逐中脱颖而出分别摘得冠军、亚军和季军。</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 此次“三人制”篮球比赛，不仅仅培养了参赛同学的竞争意识和持之以恒的优良品质，也增加了班级凝聚力和集体荣誉感，极大促进了学生对篮球运动的兴趣。在比赛过程中，每个同学都很开心，以各自的热情感染他人，释放自己青春的力量，使自己的课余生活更加精彩。</span></p><p><span><a href="images/a7e25ea1f4fd4e15b4d61c113b942a2b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a7e25ea1f4fd4e15b4d61c113b942a2b.jpg" width="500" height="333"/></a><a href="images/70dd8e12724f4d2d953ab7f949b85756.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_70dd8e12724f4d2d953ab7f949b85756.jpg" width="500" height="333"/></a><a href="images/866a9080842d463f9ed013ddd815d5c8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_866a9080842d463f9ed013ddd815d5c8.jpg" width="500" height="333"/></a></span></p><meta name="ContentEnd">', '', 'activities', '', NULL, true, '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '2019-12-19 08:00:00+08', '王雪', '新航实验外国语学校', '新航 无限 实验 举行 青春', '');
INSERT INTO public.news VALUES (990, '倾听倾诉共话未来，每位新航实验学生都有专属导师', '', '       为加强新航实验学生和各自学业导师之间的沟通交流，营造乐学好学的学习氛围，12月11日、12日，济南新航实验外国语学校初一级部和高一级部分别举行导师集体见面会，36位学业导师分别与学生探讨学业和生活话题，共同成长。  面对面交流，学生与导师成为一家人      “我们这个家的名字是‘基因重组’，我们的导师是生物老师崔佩佩，九个家庭成员团结友爱，大家一起快乐成长。”11日中午，新航实验初...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 为加强新航实验学生和各自学业导师之间的沟通交流，营造乐学好学的学习氛围，12月11日、12日，济南新航实验外国语学校初一级部和高一级部分别举行导师集体见面会，36位学业导师分别与学生探讨学业和生活话题，共同成长。</p><p><a href="images/18867658d05f42848bb2b99f9b3969e6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_18867658d05f42848bb2b99f9b3969e6.jpg" width="500" height="375"/>&nbsp; </a></p><p><span><strong>面对面交流，学生与导师成为一家人</strong></span></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “我们这个家的名字是‘基因重组’，我们的导师是生物老师崔佩佩，九个家庭成员团结友爱，大家一起快乐成长。”11日中午，新航实验初一学生冯绘如自豪的说道，在接到当天中午要和导师见面的消息后大家都很兴奋，特意准备了几个“刁钻”的难题，打算和导师探讨“切磋”一下。<br/></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 11日中午，随着下课音乐响起，学生食堂里开始变得热闹起来，学生们兴奋地跑向各自的导师，16张餐桌上摆放着花瓶和鲜花，同时16个相框里写着导师和每一位家庭成员的名字，“菊子之家”、“心灵华约”、“春天的家园”、“易师易友”……每个家庭的名字都各有特色，有的出自导师的名字，有的则来自于兴趣学科，都是学生们集思广益的杰作。</p><p><a href="images/e18322f4c0d14b558a6d045e8914ddc2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e18322f4c0d14b558a6d045e8914ddc2.jpg" width="500" height="333"/></a></p><p><a href="images/23c6af66df6b4753bf44027703ef45de.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_23c6af66df6b4753bf44027703ef45de.jpg" width="500" height="333"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 此次导师制见面会的主题是“倾听倾诉，共话未来”，活动采取小组座谈的形式分两天举行，继11日中午的初一级部导师见面会后，12日中午高一级部的活动也吸引了众多学生的踊跃参与。午饭期间，每一位学业导师和自己所负责的所有学生坐在一起就餐，导师们积极和学生们交流学校生活、学习规划、期末复习等方面的问题，同时动员学生们积极备考，实现成绩的进步飞跃。</p><p><a href="images/0fb24fd5568e49d8bec3eadb723b21ad.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0fb24fd5568e49d8bec3eadb723b21ad.jpg" width="500" height="375"/></a></p><p><span><strong>双向选择，导师辅导学生直至毕业离校</strong></span></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 实际上，早在开学之初，学校就开始筹备导师制的落地工作，为每位学生配备导师。经过前期全校师生的双向选择和重点梳理，各级部根据学生成绩、日常表现及男女生比例等，在尊重学生意愿的基础上，适当调配确定学生名单，最终初一级部和高一级部共产生了36位学生导师，他们负责组建各自的“导师家庭”。其中，人数最多的家庭里有10名成员，人数最少的有1-2名成员，指导老师和学生一经确定，保持稳定性，也就是说，从成员确定之日起一直到学生毕业，原则上导师不再增加学生。</p><p><a href="images/6b58f2a310614584b249eca5ab555242.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6b58f2a310614584b249eca5ab555242.jpg" width="500" height="333"/></a></p><p><a href="images/8e408495aad9451ba10dda7e0ab777ab.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_8e408495aad9451ba10dda7e0ab777ab.jpg" width="500" height="666"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在导师制的日常运营方面，通过定期举办谈话、辅导、聚会、座谈等面对面交流活动，导师不仅可以了解到每位家庭成员的问题和学业情况，还能够对学生实现精准点评，按照对学生“思想引导、心理疏导、生活指导、学业辅导”的要求，在学生的学习和生活方面帮助他们共同成长。</p><p><a href="images/a26d5e34db264379bc88e1397df1ef8f.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_a26d5e34db264379bc88e1397df1ef8f.jpg" width="500" height="375"/></a></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-12-13 08:00:00+08', '2019-12-13 08:00:00+08', '2019-12-13 08:00:00+08', '王雪', '新航实验外国语学校', '新航 实验 未来 学生 共话', '');
INSERT INTO public.news VALUES (991, '中国梦，新航梦，我的梦——新航实验举办爱国主题演讲比赛', '', '      “说中国话，写方块字，学中国史，食中国菜，听东方红。在这片热土上，我快乐得感受着中国的气息。我是中国人，我是新航人，我有中国梦，我有新航梦……”。铿锵有力的声音伴随着动人心弦的旋律，12月9日下午，济南新航实验外国语学校首届“恰同学少年”爱国主题演讲比赛正式拉开帷幕，从下午16：30开始，经过层层角逐，共有10组选手代表各自班级参赛，在近两个小时的演讲中，学生们立足当下，放眼未来，共话...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “说中国话，写方块字，学中国史，食中国菜，听东方红。在这片热土上，我快乐得感受着中国的气息。我是中国人，我是新航人，我有中国梦，我有新航梦……”。铿锵有力的声音伴随着动人心弦的旋律，12月9日下午，济南新航实验外国语学校首届“恰同学少年”爱国主题演讲比赛正式拉开帷幕，从下午16：30开始，经过层层角逐，共有10组选手代表各自班级参赛，在近两个小时的演讲中，学生们立足当下，放眼未来，共话浓浓爱国情！</p><p><a href="images/f405aee4c9bf412e80aa7a2d99969b59.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f405aee4c9bf412e80aa7a2d99969b59.jpg" width="500" height="333"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 比赛从初中组选手开始，经过公平抽签，首先由初一（5班）三位同学带来题为《青春奋发，扬帆新航》的演讲作品，他们深情回顾了小时候趴在爷爷肩头，听爷爷讲故事的情景，从“少时寒窗苦读、披星戴月”，到“青年投笔从戎、报效祖国”，爷爷感人的故事和她们讲述时动人的情感牵动着在场所有观众的心绪，当讲到结尾处“心中有阳光，脚下有力量”时，赢得了现场阵阵掌声。比赛如火如荼进行中，初中的同学虽人小却志气高，一场场精彩的演讲让现场评委都难以取舍。</p><p><a href="images/4130f80db8314266a09f934881d1cf89.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4130f80db8314266a09f934881d1cf89.jpg" width="500" height="333"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 高中组同学的演讲同样让人眼前一亮，尤其是高一三班陈嘉瑶同学的作品更是给现场听众留下了深刻印象。她从家国梦讲到自己的梦，小时候的梦想是当一名法官，认为法官很酷，头顶白色羊毛卷发，身着大长袍，拿着魔法棒一样的法槌，长大后才知道魔法棒是公正的象征，在善与恶、正与邪的较量中，魔法棒可以捍卫人间正道，留住世间温情，于是更加不忘初心、上下求索。她的精彩演讲让在场所有观众都为之动容。</p><p><a href="images/d900f7aa64184f35a6ae5e0406057755.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_d900f7aa64184f35a6ae5e0406057755.jpg" width="500" height="333"/></a><a href="images/6b525aafcd5d4f068e7dbecb72289440.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_6b525aafcd5d4f068e7dbecb72289440.jpg" width="500" height="368"/></a></p><p><a href="images/903e955c1f8544668700a3c4976b47a7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_903e955c1f8544668700a3c4976b47a7.jpg" width="500" height="333"/></a><a href="images/51b3a56d1ae94dc883f42aff22e43f5b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_51b3a56d1ae94dc883f42aff22e43f5b.jpg" width="500" height="333"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 少年强则国强，爱国不是空喊口号，身为新航学子，应在仰望星空的同时，脚踏实地，从点滴做起，不负期待，不负韶华，为实现人生价值、实现青春梦想而努力！</p><p><a href="images/11382d74ba98463e865e8edbe5b9cff0.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_11382d74ba98463e865e8edbe5b9cff0.jpg" width="500" height="333"/></a></p><meta name="ContentEnd">', '', 'activities', '', NULL, true, '2019-12-11 08:00:00+08', '2019-12-11 08:00:00+08', '2019-12-11 08:00:00+08', '王雪', '新航实验外国语学校', '举办 实验 爱国 主题 新航', '');
INSERT INTO public.news VALUES (992, 'The seminar on the construction and development of the future classroom in Shandong Province was held in JXEFLS', '', 'On November 29, the seminar on the construction and development of the future classroom in Shandong Province was held in Jinan Xinhang Experimental Foreign Language School. The event was hosted by Sha...', '', '<p><span>On November 29, the seminar on </span><span>the </span><span>construction and development </span><span>of the </span><span>future</span><span>&nbsp;</span><span>classroom</span><span>&nbsp;</span><span>in Shandong Province was held in Jinan </span><span>Xinhang </span><span>Experimental Foreign Language School. The event was hosted by Shandong Academy of Education </span><span>and </span><span>Sciences and Shandong Education </span><span>Association. On the same day, more than 400 subject instructors, school principals and core teachers from all over the Shandong province gathered to discuss and decide the future development of the classroom.</span></p><p><a href="images/72aff882a19a4393b1757cc204ae9c84.jpg" target="_blank"><img title="72aee6d0325443011f3a54360dad31a.jpg" src="/uploads/migration/images/72aff882a19a4393b1757cc204ae9c84.jpg"/></a></p><p><span>Baolei Lin, Deputy principal of Shandong Experimental High School and executive principal of </span><span>Jinan </span><span>Xinhang </span><span>Experimental Foreign Language School</span><span>, first delivered a welcome speech on behalf of the school, and briefly introduced the exploration of construction and development of the future classroom in </span><span>Jinan </span><span>Xinhang </span><span>Experimental Foreign Language School.</span><span>&nbsp;</span><span>“</span><span>F</span><span>rom hardware to software, </span><span>together we could</span><span>&nbsp;explore new way</span><span>s</span><span>, seek new methods, and </span><span>lead</span><span>&nbsp;to </span><span>the </span><span>future teaching and learning</span><span>&nbsp;</span><span>for future classroom.”</span></p><p><span>In the first lecture of the day, Jinsong</span><span>&nbsp;</span><span>Zhang , the director of the middle school mathematics editing </span><span>department </span><span>of the </span><span>P</span><span>eople&#39;s </span><span>E</span><span>ducation </span><span>P</span><span>ress and the deputy editor</span><span>&nbsp;of</span><span>&nbsp;the junior high school mathematics textbook of the </span><span>P</span><span>eople&#39;s Education Edition, </span><span>delivered</span><span>&nbsp;a report entitled &quot;grasp the overall mathematics teaching and improve the students&#39; </span><span>quality of </span><span>mathematics&quot;. Through the deduction of </span><span>mathematical </span><span>concepts</span><span>&nbsp;and examples</span><span>, the experts on the scene were attracted to participate in the interaction actively.</span></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>After that, Qinghua&nbsp;Sun&nbsp;, the&nbsp;teacher&nbsp;of Jinan Xinhang Experimental Foreign Language School, led 30 students from class</span><span>&nbsp;3, </span><span>grade</span><span>&nbsp;1</span><span>&nbsp;of junior high school to do </span><span>a d</span><span>emonstration </span><span>c</span><span>lass&nbsp;for the participating experts&nbsp;on the topic of “the application of linear equation”. Jun Yang, the&nbsp;mathematics instructor of Jinan Academy of </span><span>E</span><span>ducation and </span><span>S</span><span>cience, and&nbsp;Yuqi&nbsp;Wang, the&nbsp;leader of Beijing mathematics discipline, respectively made comments on the </span><span>demonstration class</span><span>, &quot;through the deep&nbsp;and simple explanation&nbsp;and some specific&nbsp;and vivid examples, each student was motivated&nbsp;to actively participate in the classroom teaching. The teacher&#39;s leading role and the students’ initiative cooperated with each other, reflecting the interactivity and extensibility of the classroom in the future.&quot; Yang Jun commented.</span></p><p><span><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Then, Li Wenjun, secretary-general of Shandong Education </span><span>Association</span><span>, </span><span>delivered</span><span>&nbsp;a lecture entitled &quot;the construction and development of the future classroom.&quot;</span><span>,</span><span>&nbsp;“</span><span>H</span><span>ow to define the future classroom? How to construct the future classroom? What will happen to teaching in the future? </span><span>The future classroom is near at hand, and it</span><span>&nbsp;will bring profound changes to teachers&#39; teaching and students&#39; learning&quot;</span><span>.</span></span></p><p><span><a href="images/976a6c94edc04b3ba6645bae27a43d35.jpg" target="_blank"><img title="1f035c92264629dd1f8ea4b585f7cab.jpg" src="/uploads/migration/images/976a6c94edc04b3ba6645bae27a43d35.jpg"/></a><a href="images/577eb639630144a6b6affb1448d1b52a.jpg" target="_blank"><img title="6530cc177dfaefb0b4d78291b63ed86.jpg" src="/uploads/migration/images/577eb639630144a6b6affb1448d1b52a.jpg"/></a><a href="images/96e15bde06a744a1b7787bd5c344d35b.jpg" target="_blank"><img title="dd612e50b04f39884dec48351f347dd.jpg" src="/uploads/migration/images/96e15bde06a744a1b7787bd5c344d35b.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>At noon of the same day, the experts at the meeting visited the teaching building, gymnasium, library and other places of Jinan Xin</span><span>h</span><span>ang Experimental Foreign Language School. The advanced &nbsp;facilities and strong campus culture of </span><span>Jinan </span><span>Xinhang </span><span>Experimental Foreign Language School</span><span>, especially the exploration in the future classroom, won the praise </span><span>and compliment </span><span>of the experts at the meeting.</span></span></p><p><span>In the afternoon &quot;</span><span>E</span><span>xcellent principal - Case Sharing&quot;</span><span>&nbsp;section</span><span>, the experts at the meeting held a heated discussion on the topic of &quot;</span><span>Mixing</span><span>&nbsp;micro class </span><span>with </span><span>video teaching and developing mathematical core </span><span>quality</span><span>&quot;. After that,</span><span>&nbsp;</span><span>&quot;special</span><span>&nbsp;</span><span>sharing</span><span>&nbsp;of </span><span>mathematics</span><span>&nbsp;teaching</span><span>&quot; </span><span>brought by </span><span>Yuqi</span><span>&nbsp;</span><span>Wang and &quot;President&#39;s Forum - manager&#39;s whole school promotion&quot; hosted by Zhengguo</span><span>&nbsp;</span><span>Jin were held at the same time in two </span><span>branch sessions</span><span>, and the lectures of two experts also made more than 400 participants feel &quot;full of gains</span><span>&nbsp;and enrichment</span><span>&quot;.</span></p><p><span>At about </span><span>5</span><span>&nbsp;p.m., the whole seminar ended in a strong atmosphere of discussion.</span></p><p><span><br/></span></p><p><span>翻译：管煜程</span></p><p><span><br/></span></p><p><a href="images/69f14f7d94f54b2593c1774443224cea.jpg" target="_blank"><br/></a></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-11-30 08:00:00+08', '2019-11-30 08:00:00+08', '2019-11-30 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (993, 'Experts entered the campus and communicated with students on the topics of new energy and environment', '', 'On the afternoon of the Nov. 27, Jinan Xinhang Experimental Foreign Language School ‘s theme activity of “experts enter the campus” started. The lecture contained two topics: new energy and ecological...', '', '<p><span>On the afternoon of the Nov. 27, Jinan Xinhang Experimental Foreign Language School&nbsp;‘s theme activity&nbsp;of “experts enter the campus”&nbsp;started. The lecture contained&nbsp;two topics: new energy and ecological environment, and electricity market. It was hosted by Professor Gennadii Varlamov, vice president of Ukraine National University of technology, and Dr. Jing Qing, lecturer (lifelong employment) of The School of Electrical and Information Engineering&nbsp;of University of Sydney, bringing the students and teachers of Jinan Xinhang Experimental Foreign Language School an academic feast.</span></p><p><span>&nbsp;<a href="images/79e31de3323a4f709eab536629097f46.jpg" target="_blank"><img title="6418ad83156b8fdaa5ef253beb8b2cf.jpg" src="/uploads/migration/images/79e31de3323a4f709eab536629097f46.jpg"/></a><a href="images/0e4606fb875a48c3af018d4acbdf3da0.jpg" target="_blank"><img title="3ea4399252d7fed0a88599d9cc7197e.jpg" src="/uploads/migration/images/0e4606fb875a48c3af018d4acbdf3da0.jpg"/></a></span></p><p><span><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &quot;What would our life be&nbsp;without energy? Without heating, we can go back to the cave age. Without lights, candles can bring light. How could&nbsp;we live without energy? We are used to the conveniences that energy gives us. Because of energy, our&nbsp;life is&nbsp;so comfortable,&nbsp;and&nbsp;we need power supply, hot water and heating for our comfort. Therefore, energy production and energy conservation are very necessary. &quot; Through common&nbsp;examples, Professor Gennadii Varlamov first drew&nbsp;students&#39; attention to the topic of energy, which seems to be far away but close at hand. Then he introduced the most advanced new energy concept and equipment from the perspective of sustainable development, ecological balance principle of energy development, and new energy plan, etc., which aroused the students&#39; strong interest.</span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>Then, Dr. Jing&nbsp;Qiu gave lectures on the topics of the introduction to the electricity market to the students of Jinan Xinhang Experimental Foreign Language School. He first talked about the electricity industry from his own study experience, and detailedly introduced the technical characteristics of the production and operation of the electricity industry, the meaning of the market, how to build the electricity market, and the situation of the&nbsp;electricity market at home and abroad, etc. During&nbsp;of the lecture, Dr.&nbsp;Qiu&nbsp;fully considered the acceptance ability of middle school students&nbsp;and combined&nbsp;Chinese and English&nbsp;to&nbsp;vividly and interestingly&nbsp;introduce the relevant knowledge of electricity market from two aspects&nbsp;of physics and economics, winning&nbsp;the praise and compliment from&nbsp;the students.</span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>After the two lectures, three student representatives of Jinan Xinhang Experimental Foreign Language School had deep and enthusiastic communications&nbsp;with two experts on the topic of new energy and ecological environment.</span></span></p><p><span>&nbsp;</span></p><p><span><a href="images/ec54c0981c70481b9cb7351821255ed2.jpg" target="_blank"><img title="ab426336d02baa5985761440c9318e4.jpg" src="/uploads/migration/images/ec54c0981c70481b9cb7351821255ed2.jpg"/></a></span></p><p><span><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Recently,&nbsp;The Central Comprehensively Deepening Reforms Commission&nbsp;of China&nbsp;approved&nbsp;and passed “the advice on comprehensively strengthening the labor education in primary and secondary schools in the new era”&nbsp;and “the advice on deepening the reform of mechanism&nbsp;of the educational supervision system in the new era”, which clearly emphasized that labor education is an important part of the socialist education system with Chinese characteristics, and also clearly pointed out that we should aim for promoting the modernization of the environmental governance system and governance capacity to improve the ecological environment and build a beautiful China.</span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>Jinan Xinhang Experimental Foreign Language School&nbsp;always adheres to the principle of strengthening&nbsp;moral education and cultivating&nbsp;people, highly emphasizes&nbsp;on the important position of labor education and environmental protection education, integrates them into the whole process of teaching,&nbsp;pays attention to the actual effect of education, and realizes&nbsp;the unity of knowledge and practice.</span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>The lectures of experts have not only provided&nbsp;new frontier knowledge lectures for students of Jinan Xinhang Experimental Foreign Language School&nbsp;and improved&nbsp;students&#39; theoretical cognition in the field of environmental protection, but also offered&nbsp;practical guidance for their daily actions. On the basis of guiding students to study in various&nbsp;fields, the series of theme activities of “experts enter the campus”&nbsp;fully opened up students&#39; international view&nbsp;and helped them to become &quot;Qilu gentleman, citizens of the world&quot;.</span></span></p><p><span>摄影：学生记者 魏子元 等</span></p><p><span>翻译：管煜程</span></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-11-28 08:00:00+08', '2019-11-28 08:00:00+08', '2019-11-28 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (994, '三味三境精准会诊，新航实验推出首场“体验式家长会”', '', '       “新航实验总是给我们带来惊喜，这样的家长会，收获太大了，老师们确实太用心了！”15日下午，一位济南新航实验外国语学校的学生家长感慨道，一场家长会下来，不仅和各科老师都见了一面，还深入了解到孩子的学习情况，老师们精准到位的点评让人心里非常踏实，“精准，量体打造，这些老师确实太懂每一个孩子了！”       继10月份“剧组式”家长会之后，从11月14日开始，新航实验首创的“体验式家长会...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “新航实验总是给我们带来惊喜，这样的家长会，收获太大了，老师们确实太用心了！”15日下午，一位济南新航实验外国语学校的学生家长感慨道，一场家长会下来，不仅和各科老师都见了一面，还深入了解到孩子的学习情况，老师们精准到位的点评让人心里非常踏实，“精准，量体打造，这些老师确实太懂每一个孩子了！”</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 继10月份“剧组式”家长会之后，从11月14日开始，新航实验首创的“体验式家长会”暨学情会商活动正式拉开帷幕，此次“三味三境”家长会的主题词是“解”，即了解学生、理解老师、解决困惑。初一、高一级部每个班分批邀请家长到校参加家长会，家长和学生分别与各科老师面谈</p><p><a href="images/0bf386d70c594a4cad6b77c4cd0a2b19.jpg" target="_blank"><a href="images/015b500bf58e4e9181d36d1af8085e36.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_015b500bf58e4e9181d36d1af8085e36.jpg" width="540" height="368"/></a></a></p><p><a href="images/0bf386d70c594a4cad6b77c4cd0a2b19.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_0bf386d70c594a4cad6b77c4cd0a2b19.jpg" width="500" height="333"/></a></p><p><a href="images/f5b815d8c0184b6cbb15c5d7daf5ec8a.jpg" target="_blank"></a><a href="images/0bf386d70c594a4cad6b77c4cd0a2b19.jpg" target="_blank"></a><a href="images/f5b815d8c0184b6cbb15c5d7daf5ec8a.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f5b815d8c0184b6cbb15c5d7daf5ec8a.jpg" width="500" height="333"/></a></p><p>充分沟通，老师比家长更懂孩子<br/></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 15日下午，新航实验“三味三境”体验式家长会暨学情会商活动继续进行中，从13:30开始，在接下来的几个小时里，老师们按照不同学科分组，陆续迎来家长和学生们。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 按照活动流程，此次活动共分三个阶段，初一、高一级部分别在六个教室进行。一是学情反馈，任课老师在教室里展示学生的作业本、课堂笔记、批改记录等，让家长充分了解孩子在校表现。浏览后，家长填写学情反馈表。紧接着，家长与每一位任课教师面对面交流，任课教师与家长和孩子沟通，给孩子支招解忧。</p><p><a href="images/112172bcfc42478e9432d0f39551f3de.jpg" target="_blank"><a href="images/899946bc41864f1b883649239be268f2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_899946bc41864f1b883649239be268f2.jpg" width="500" height="333"/></a><a href="images/112172bcfc42478e9432d0f39551f3de.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_112172bcfc42478e9432d0f39551f3de.jpg" width="500" height="375"/></a></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp; “稳重踏实是你的优点，希望你继续开动脑筋，在课堂上产生更多奇思妙想的新点子。”一位学生拿到了英语老师宋武栋老师特意准备的纪念卡片后，兴奋的向家长展示，背面手写的这行字也让家长很是感慨，“老师们太用心了，比我们这些家长还要更懂孩子。”<br/></p><p></p><p>在家长会现场，每个学生都拿到了老师提前准备的学科“锦囊妙计”，每一张纪念卡背面是老师为每名同学写下的鼓励或学习方法，每个人的内容都是截然不同的。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在完成前两项“任务”后，家长和学生们开始与班主任面对面交流，班主任分析孩子的期中考试成绩，并评价入校来的整体情况，提出对孩子个性化培养及学业规划的建议。&nbsp;</p><p>“三味三境”，家长与老师一对一面谈</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “第一次参与这种打破常规的家长会，真的让我和孩子收获满满！带着孩子一起和各学科老师面对面一对一沟通交流，更能直观透彻的了解孩子在学习和生活中存在的问题，听着老师们温声细语中给予的建议和方法，都是根据孩子量身打造，好几次湿了眼眶，让我们触动很大！”15日傍晚，一位学生家长在走出新航实验校门时，难掩心中的激动之情，“很庆幸把孩子送到新航实验，老师们能在青春期阶段给了他足够的肯定、尊重、理解和引导。”</p><p><a href="images/b0d0c99f0a2942b692a152dd70a7a6b3.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b0d0c99f0a2942b692a152dd70a7a6b3.jpg" width="500" height="353"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “三味三境”的“三味”是指问题丹、兴趣散、信心汤，这是当年胡适给学生们开出的三味中药。而“三境”则取自于王国维提出的“人生三境界说”，包括“昨夜西风凋碧树。独上高楼，望尽天涯路。”、“衣带渐宽终不悔，为伊消得人憔悴。”、“众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。”</p><p>&nbsp;&nbsp;&nbsp;&nbsp; “这就提醒学生们，排除干扰，不为暂时的烟雾所迷惑，这是取得成功的基础。在这个世界上干什么都没有平坦大道，要敢于创新，也要善于等待。在经过多次周折和磨练后，逐渐成熟起来，豁然领悟。”初一级部主任李正华解释道，通过一对一面谈实现教育会诊，做到智慧分享和体验互动，家长与孩子共同发现问题，找到兴趣，获得信心，不为暂时的烟雾所迷惑，执着地追求，忘我的奋斗。经过多次的磨练，成熟起来。</p><p>&nbsp;&nbsp;&nbsp;&nbsp; “自始至终老师们都非常耐心，嗓子哑了都没有出去休息一下，新航人的敬业真的让人很感动。把孩子送到这里，我们觉得非常放心。”一位学生家长这样感慨道。</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 接下来，类似的家长交流会在新航实验还将定期展开，加强家校交流，共同为学生成长成才保驾护航。</p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-11-26 08:00:00+08', '2019-11-26 08:00:00+08', '2019-11-26 08:00:00+08', '王雪', '新航实验外国语学校', '实验 推出 新航 会诊 体验', '');
INSERT INTO public.news VALUES (995, '筑巢引凤，“职”等您来——济南新航实验外国语学校诚聘英才', '', '     学校概况        济南新航实验外国语学校隶属于山东省实验中学教育集团，是山东省实验中学与山东出版集团强强联合、精心打造的一所十二年一贯制民办非营利学校。作为山东省实验中学成员校，山东省实验中学全面负责新航实验的教育教学工作，校长、优秀管理团队及骨干教师皆由省实验中学统一调配，秉持“让每一个生命都精彩绽放”的育人理念与“齐鲁君子、世界公民”的培养目标、“日新博学、志航天下”的校训精神...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong><span>学校概况</span></strong>&nbsp; <br/></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 济南新航实验外国语学校隶属于山东省实验中学教育集团，是山东省实验中学与山东出版集团强强联合、精心打造的一所十二年一贯制民办非营利学校。</p><p>作为山东省实验中学成员校，山东省实验中学全面负责新航实验的教育教学工作，校长、优秀管理团队及骨干教师皆由省实验中学统一调配，秉持“让每一个生命都精彩绽放”的育人理念与“齐鲁君子、世界公民”的培养目标、“日新博学、志航天下”的校训精神追求，致力于打造一所高起点、高品位、高质量的多元化创新型学校。</p><p>学校已于2019年9月正式开学，高端先进的硬件设施、一流水准的师资配置、精品小班的培养模式，力争为师生提供最优质的教育和发展平台。</p><p>根据学校战略发展规划，现面向社会公开招聘引进优秀师资。</p><p><a href="images/1a68d2e1659046a98db0625819aaf10c.jpg" target="_blank"><a href="images/1a68d2e1659046a98db0625819aaf10c.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1a68d2e1659046a98db0625819aaf10c.jpg" width="500" height="361"/></a></a></p><p><strong><span>招聘计划及岗位</span></strong></p><p>1.初中教师18人：初中语文3人、初中数学3人、初中英语2人、初中物理2人、初中生物2人、初中政治2人、初中地理2人、初中历史2人。</p><p>2.高中教师13人：高中语文2人、高中数学2人、高中英语2人、高中物理1人、高中化学1人、高中生物1人、高中政治2人、高中历史1人、高中地理1人。</p><p>3. 国际课程A-level中方教师11人：数学1人、物理1人、英语1人、化学1人、生物1人、历史1人、地理1人、经济1人、心理1人、计算机1人、A- level Accounting 1人。</p><p>4.奥赛教练2人：物理1人、生物1人。</p><p>5.国外升学指导教师2人。</p><p>6.美术1人：国画类</p><p>7.实验室教师3人：物理1人、化学1人、生物1人。</p><p>8.图书管理员2人，教育教学管理员3人，生活指导老师3人。</p><p><a href="images/54f3badea55840efb200174d2f3d2d74.jpg" target="_blank"><a href="images/e34aa55030d44a1992b46057556201bf.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_e34aa55030d44a1992b46057556201bf.jpg" width="500" height="337"/></a><a href="images/54f3badea55840efb200174d2f3d2d74.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_54f3badea55840efb200174d2f3d2d74.jpg" width="500" height="375"/></a></a></p><p><strong><span>应聘条件</span></strong><span></span></p><p>1.具有中华人民共和国国籍，遵守中华人民共和国宪法和法律。<br/>2.热爱教育事业，具有良好的品行和适应岗位的身体条件，身心健康，服从学校工作安排，具有团队精神。</p><p>3.具有相应的教师资格证书或相应的专业资格证书。</p><p>4.年龄在45周岁以下，全日制本科学历以上；本硕专业方向需一致。特别优秀者，年龄和学历可适当放宽。</p><p>5.初高中教师：获得过以下荣誉或奖励的优先录取：省级特级教师、省优质课一等奖、齐鲁名师、地市级专业技术拔尖人才、教学能手、优秀教师等优秀奖及以上奖励。</p><p>6.国际课程中方教师：国际课程A-Level学科3年以上教学经验，了解A-Level学科的知识结构体系，能进行全英文授课，了解CIE教材的优先考虑；硕士研究生以上学历，英语水平达六级以上，其中综合英语教师须达到专业八级或雅思7.5分或托福100分以上；具备相关专业背景，海外留学经历者优先。</p><p>7.学科教练：在职教师要求是指导学生曾获省赛区一等奖以上的主教练，在业内有一定影响力；应届毕业生要求获高中学科竞赛省赛区一等奖及以上，获奖科目与大学专业相一致；获得国家级学科竞赛金牌教练等荣誉的优先录取 (仅限通过学科竞赛学生能对应升入一流学校的学科)。</p><p>8.国外升学指导教师：教育学、心理学专业，英语六级以上，具有相关工作经验或海外留学经历者优先。</p><p><a href="images/1825453d09404be09f2478e3b4eb2850.jpg" target="_blank"><a href="images/4d2eefaa72824938b48ca6a735c7816d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4d2eefaa72824938b48ca6a735c7816d.jpg" width="500" height="239"/></a><a href="images/1825453d09404be09f2478e3b4eb2850.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1825453d09404be09f2478e3b4eb2850.jpg" width="500" height="240"/></a></a></p><p><strong><span>薪资福利</span></strong><span></span><br/></p><p>1.优秀应届毕业生及二级教师：10万—15万元/年，北京大学、清华大学毕业生入职年薪20万起，其他C9高校毕业生入职年薪15万起。</p><p>2.一级教师：15-20万元/年，高级教师：20-30万元/年，其他岗位：8-13万元/年，高级人才年薪面议并享受住房补贴。</p><p>3.单位福利：五险一金、学校团购房优惠、子女就读优惠、餐费补助、教师公寓、员工生日会、节日福利、量身定制工装。</p><p><strong><span>成长平台</span></strong><span></span></p><p>在新航实验，雄厚的师资团队为中青年教师的成长提供了高层次的交流平台。在目前的师资团队中，不仅有十余位特级教师、正高级教师，还有43位教师获得博士、硕士学位，毕业于北大、中国科学技术大学、南开大学、山东大学等名校，聚合起一支理念先进、素质过硬、梯度合宜的师资团队。</p><p>与此同时，秉持“让每一个生命都精彩绽放”的理念，新航实验高度注重教师专业技术及素养培养，定期邀请知名专家教授进校园，为教师提供年度研修培训、月度素养提升等成长机会。此外，阵容强大的外教师资团队，也为教师的职业发展提供了国际化交流平台。</p><p><a href="images/57e68d0b65ed4bdca691fee94e8f0683.jpg" target="_blank"><a href="images/57e68d0b65ed4bdca691fee94e8f0683.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_57e68d0b65ed4bdca691fee94e8f0683.jpg" width="500" height="301"/></a></a></p><p><strong><span>报名方式</span></strong></p><p>请将简历以word文档发送到学校邮箱，并在简历后附个人身份证及相关证书材料。</p><p>人力资源部邮箱：jxefls_hr@jn.shandong.cn</p><p>联系人：左老师，0531-59516627</p><p>学校地址：山东省济南市经十东路27803号</p><p>这里有一片干事创业的热土，这里有一群踏实钻研学术的伙伴，这里有一群好学求知的青春脸庞，这里还有一幅幅未就的画卷等着你来书写，还有一个个蓬勃的生命等着你去点燃……</p><p><a href="images/57b407277d064853b74d358e3312aea7.jpg" target="_blank"><a href="images/57b407277d064853b74d358e3312aea7.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_57b407277d064853b74d358e3312aea7.jpg" width="500" height="326"/></a><a href="images/3dc035f1b9d14d5eb0a279d27448c4c8.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_3dc035f1b9d14d5eb0a279d27448c4c8.jpg" width="500" height="333"/></a></a></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '', NULL, true, '2019-11-06 08:00:00+08', '2019-11-06 08:00:00+08', '2019-11-06 08:00:00+08', '王雪', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (996, '名家讲堂：昆山杜克大学黄英强教授在新航实验开讲“跨领域学习”', '', '       10月26日下午，昆山杜克大学著名教授黄英强到访济南新航实验外国语学校，并为学生们带来一场题为“跨领域学习——大数据 医学 物理”的学术讲座，黄英强教授从医学生物领域的杰出人物出发，通过一个个鲜活的事例，肯定了跨学科和大数据在未来社会的重要性，并对学生们的日常学习提出建议。        黄英强教授在讲到医用影像与临床诊断时，给学生们观看了几组放射图，以晒太阳东方人会变黑，患皮肤癌的...', '', '<p>&nbsp; &nbsp; &nbsp;&nbsp; 10月26日下午，昆山杜克大学著名教授黄英强到访济南新航实验外国语学校，并为学生们带来一场题为“跨领域学习——大数据 医学 物理”的学术讲座，黄英强教授从医学生物领域的杰出人物出发，通过一个个鲜活的事例，肯定了跨学科和大数据在未来社会的重要性，并对学生们的日常学习提出建议。</p><p><a href="images/45d1bf62fafb495d8baa25612debcd81.jpg" target="_blank"><img width="621" height="385" title="昆山1.jpg" src="/uploads/migration/images/45d1bf62fafb495d8baa25612debcd81.jpg"/></a></p><section><section><p>&nbsp; &nbsp; &nbsp; &nbsp; 黄英强教授在讲到医用影像与临床诊断时，给学生们观看了几组放射图，以晒太阳东方人会变黑，患皮肤癌的机率远远小于不会变黑的白人患皮肤癌的机率为例，让学生们了解到太阳辐射的危害。随后他还给学生们科普了人工智能在生活中的实际应用。</p><p>&nbsp; &nbsp; &nbsp; &nbsp; “人工智能是以大数据为支撑，上传到云端。它在医学中可以准确判断患者患癌症后活下去的时间，效率远超于人工。它还可以根据患者的情况自动设计化疗计划，对于医学十分有帮助。”黄英强教授在讲座中指出，根据目前技术，通过辐射只能看到人类的骨骼，希望在未来可以看到分子、细胞甚至基因影像。“这项任务或许十分艰巨，但需要我们青年一代不断去努力，去创新发现，好好学习，尽早为国家贡献自己的力量。”黄英强教授说道。</p><p><a href="images/d39056faf40749c49560b4bba5adbdcb.jpg" target="_blank"><img width="650" height="373" title="昆山2.jpg" src="/uploads/migration/images/d39056faf40749c49560b4bba5adbdcb.jpg"/></a></p></section></section><p></p><section><section></section></section><p></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 对于平时的课程学习，黄英强教授也提出建议，建议在平时学习要注重跨领域，因为在人工智能的时代，只要跨领域广，才不会被机器人取代。随后，黄英强教授向学生们介绍了昆山杜克大学的招生方式和培养模式，通识博雅教育旨在多种学科知识融合，促使学生拥有活跃的思维模式，在已知探索未知的同时传承创新。</p><p><a href="images/a64cfb677a594c4a975860f72d7c8650.jpg" target="_blank"><img width="500" height="888" title="" src="/uploads/migration/images/s_a64cfb677a594c4a975860f72d7c8650.jpg"/><a href="images/21ef3802fd4c47449588b18a6f4bca65.jpg" target="_blank"><img title="昆山4.jpg" src="/uploads/migration/images/21ef3802fd4c47449588b18a6f4bca65.jpg"/></a></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 整场讲座大约持续了90分钟，黄英强教授通过深入浅出的讲解，将原本高深的专业知识转化为学生们易于接受的身边事例。他那幽默风趣的语言，吸引了同学们积极参与，在最后的提问环节踊跃举手提出自己的疑问。本次讲座在帮同学们了解医学和物理知识的同时，也在同学们心里埋下了奋发学习的种子。<br/></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 昆山杜克大学(Duke Kunshan University)，是一所由美国杜克大学和中国武汉大学合作创办的非营利性中美合办高校，是具有独立法人地位的综合性研究型大学，以通识博雅教育传统为基础，注重解决问题的能力，鼓励<span>学生学以致用。</span></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '王雪', '新航实验外国语学校', '大学 新航 黄英强 教授 实验', '');
INSERT INTO public.news VALUES (997, '喜报：新航实验学子在全市“中小学生跳绳比赛”中获初中组一等奖', '', '       10月26日，由济南市教育局主办的“2019年济南市中小学生跳绳比赛”在济南九中举行，济南新航实验外国语学校初一级部和高一级部分别选派20名学生代表参赛，经过激烈的比拼，初一级部代表队获初中组团体一等奖，高一级部代表队获高中组团体二等奖、优秀表演奖。        这是新航实验自今年9月开学以来第一次代表学校参加全市体育比赛，从两位指导老师颜晨熙和郭婷允到40名学生，都既紧张又兴奋。...', '', '<p>&nbsp; &nbsp; &nbsp;&nbsp; 10月26日，由济南市教育局主办的“2019年济南市中小学生跳绳比赛”在济南九中举行，济南新航实验外国语学校初一级部和高一级部分别选派20名学生代表参赛，经过激烈的比拼，初一级部代表队获初中组团体一等奖，高一级部代表队获高中组团体二等奖、优秀表演奖。</p><p><a href="images/071f5a5b5d0f442c8eaa8239a4051f04.jpg" target="_blank"><img width="788" height="481" title="比赛1.jpg" src="/uploads/migration/images/071f5a5b5d0f442c8eaa8239a4051f04.jpg"/></a><a href="images/6e34ce432d294c2b82f675300936fcd5.jpg" target="_blank"><img width="706" height="540" title="比赛2.jpg" src="/uploads/migration/images/6e34ce432d294c2b82f675300936fcd5.jpg"/></a></p><p><br/></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 这是新航实验自今年9月开学以来第一次代表学校参加全市体育比赛，从两位指导老师颜晨熙和郭婷允到40名学生，都既紧张又兴奋。接到通知时距离比赛只有短暂一周时间，在不影响正常上课的情况下，40名学生只能利用课余时间加紧训练。</p><p>&nbsp; &nbsp; &nbsp; &nbsp; “这个任务对我们所有人来说都是一项极限挑战，在训练过程中孩子们没有喊苦喊累，每个人都在认真积极的训练，甚至有些项目对很多学生来说都是第一次接触，但他们不畏困难，仍然努力地在坚持。”指导老师颜晨熙表示，在26日的比赛现场，在面对未知选手的情况下，新航实验学子仍奋勇直追，他们不畏强者的挑战，哪怕对手的实力强大，他们依旧坚持到了最后一项，每一个人都赛出了自己最好的水平。</p><p><a href="images/cc36c8954b164d6d8eea9858ea6277e3.jpg" target="_blank"><img width="786" height="409" title="比赛3.jpg" src="/uploads/migration/images/cc36c8954b164d6d8eea9858ea6277e3.jpg"/></a><a href="images/e6867d002cd44e8fad72fa2a057b691e.jpg" target="_blank"><img width="483" height="512" title="比赛4.jpg" src="/uploads/migration/images/e6867d002cd44e8fad72fa2a057b691e.jpg"/></a><a href="images/cc1034ad581440179e580bcb1bc70ab6.jpg" target="_blank"><img width="623" height="499" title="比赛5.jpg" src="/uploads/migration/images/cc1034ad581440179e580bcb1bc70ab6.jpg"/></a><a href="images/bc1f383d997c4d34afe4f2995bb6b80c.jpg" target="_blank"><img width="800" height="651" title="比赛6.jpg" src="/uploads/migration/images/bc1f383d997c4d34afe4f2995bb6b80c.jpg"/></a></p><p><br/></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 短暂的时间虽不足以完全体现出新航实验学子的实力，但他们仍在比赛中取得了不俗的成绩，最终，初一级部代表队在上午的比赛中获初中组团体一等奖、4x45秒男子组接力集体奖的好成绩，高一级部代表队在下午的比赛中，获高中组团体二等奖、优秀表演奖。</p><p><span></span><br/></p><p><span><br/></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '王雪', '新航实验外国语学校', '中小学生 全市 跳绳 学子 比赛', '');
INSERT INTO public.news VALUES (998, 'Here comes the admissions officer', '', 'Amy Mu, the admission officer of National University of Singapore, visited Jinan Xinhang Experimental Foreign Language School on October 31th. She gave a speech about admission issues and carried out ...', '', '<p><span>Amy Mu, the admission officer of National University of Singapore, visited Jinan Xinhang Experimental Foreign Language School on October 31th. She gave a speech about admission issues and carried out a detailed introduction about admission policies, professional settings, tuition fees, educational resources and systems of National University of Singapore, Nanyang Technological University and Singapore Management University. Students gained extensive knowledge in the area from the interaction with Amy.</span></p><p><a href="images/50b8939af28a42069fe5d7edabd50a6b.jpg" target="_blank"><img title="d3121a80d7629967182c22dc51000f7.jpg" src="/uploads/migration/images/50b8939af28a42069fe5d7edabd50a6b.jpg"/></a></p><p><span>As a top university in the whole wold, the National University of Singapore and the Nanyang Technological University have strict management mechanisms and&nbsp;inspecting standards&nbsp;in terms of entrance requirements, course offerings and</span><span>&nbsp;</span><span>major choices.&nbsp;Starting with the two famous universities, the admission&nbsp;officer introduced&nbsp;the similarities and differences between the two universities as well as the preferential policies and admission requirements for Chinese students. It helped&nbsp;students understand the admission policies in a detailed and comprehensive way. Consequently, they can do&nbsp;a targeted preparation for further education.</span></p><p><span>&nbsp;&nbsp;&nbsp; After that,the admission officer,&nbsp;Amy Mu,&nbsp;introduced&nbsp;Singapore Management University which is highly&nbsp;famous for&nbsp;Business major.&nbsp;The various forms of enrolling students and science classes made students feel interested.&nbsp;Finally,&nbsp;Amy showed students the project of visiting training after spring festival this year, and it&nbsp;is helpful for students to accumulate experience and prepare for applying universities in the future.</span></p><p><span><a href="images/ded6ad5bb8cf4d37899c8a42d4ca34bd.jpg" target="_blank"><img title="201631e0b3f76e26fff232a8ef24ae7.jpg" src="/uploads/migration/images/ded6ad5bb8cf4d37899c8a42d4ca34bd.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>There are a fair number of advantages of universities in Singapore for Chinese students regarding tuition fees, teaching methods, visa handling and geographic location compared with American and British universities. The speech provided an instant information and significant entrance guidance for students in Jinan Xinhang Experimental Foreign Language School. </span></span></p><p><span>供稿：李朝阳</span></p><p><span>翻译：于家豪、梁恩玮、张益明</span></p><p><span>翻译指导：孙雨辰</span></p><p><span><br/></span></p><p></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '2019-11-01 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (999, '为赏两岸景，家校共建“桥”：新航实验举行“剧组式”家长会', '', '为加强家校沟通，让老师更全面、更深入地认识学生，同时也让家长近距离了解学生的学习和生活情况，从17日开始，一直到22日晚，济南新航实验外国语学校以班为单位举行学生家长交流会。与常规家长会不同的是，新航实验的家长会以“剧组式”方式开展，各班根据家长工作时间安排，分批邀请家长进校座谈，学生、家长、任课教师、班主任四方共同参加，大家围坐在一起，就像一个个剧组一般，在融洽和谐的氛围中畅谈教育话题。“处处走...', '', '<section><p><br/></p><section><span><span><section>为加强家校沟通，让老师更全面、更深入地认识学生，同时也让家长近距离了解学生的学习和生活情况，从17日开始，一直到22日晚，济南新航实验外国语学校以班为单位举行学生家长交流会。与常规家长会不同的是，新航实验的家长会以“剧组式”方式开展，各班根据家长工作时间安排，分批邀请家长进校座谈，学生、家长、任课教师、班主任四方共同参加，大家围坐在一起，就像一个个剧组一般，在融洽和谐的氛围中畅谈教育话题。</section><section>“处处走心、点评到位，这样的家长会我还是第一次参与，新航实验的老师们确实太用心了！”21日下午，一位刚刚参加完家长交流会的学生家长这样感慨道，看到学校和老师们这么贴心、周到的安排，走出校门时心中已是满满的踏实。</section><section><section><p><a href="images/b6f2727f43d6403da103637b5a3b7ab5.jpg" target="_blank"><img width="671" height="456" title="两岸1.jpg" src="/uploads/migration/images/b6f2727f43d6403da103637b5a3b7ab5.jpg"/></a></p><p>分批组织，一对一面谈成常态</p></section><section>10月17日16时、19时，初一四班分别在两个教室里，组织全班学生和家长举行了两场小型家长交流会，除了两名因出差请假的家长外，其余27名家长全部到场。在一个半小时里，班主任王梦雅老师和任课老师们，针对学生开学以来的表现，与家长们进行了全面深入的探讨，逐个学生进行分析。细致入微的交流、入心走心的点评，赢得家长们的一致好评，“太懂孩子了，真切体会到新航实验老师的用心和付出。”</section><section>实际上，从10月17日开始，一直到10月22日下午，新航实验高一级部和初一级部分别组织召开了类似的“剧组式”新型家长会，每个班单独进行，充分考虑到学生家长的工作时间安排，分批展开座谈，充分尊重学生，发挥学生的主体地位。班主任也从传统的讲述者变为倾听者，给家长充分的时间与任课教师交流，一对一面谈成为常态。</section><section><a href="images/e266b6e986a84b0abbfe2ec16f564a35.jpg" target="_blank"><img width="450" height="330" title="两岸2.jpg" src="/uploads/migration/images/e266b6e986a84b0abbfe2ec16f564a35.jpg"/></a><a href="images/830e07cea6314af09fce08238f2de4bf.jpg" target="_blank"><img width="464" height="370" title="两岸3.jpg" src="/uploads/migration/images/830e07cea6314af09fce08238f2de4bf.jpg"/></a></section><section><section>踊跃发言，家长为学校建言献策</section><section>对于大多数学生来说，在学校里是一种表现，在家里是可能是另一种表现，这就像是河两岸的风景。为了能让老师和家长更全面、近距离看到两岸风景，中间就需要一座桥，一座沟通和交流的桥。10月17日晚，初一五班学生家长走进教室时，看到黑板上学校提出的“为赏两岸景，家校共建‘桥’”这一行字，一下子打开了话匣子。</section><section>据了解，根据活动安排，此次家长交流会大致分五个内容——学习情况分析、科任老师点评、学生在校情况反馈、家长提出建议、老师回应建议和答疑。在交流会上，不少家长踊跃发言，从多个角度提出了对孩子学习的建议，“能否晚自习中拿出10分钟时间固定让孩子练字？”“对于时间管理能力和学习力薄弱的孩子，学校能否组织相关讲座，帮助孩子更好提升综合学习能力？”</section><section><section>为进一步加强家校联系，增进家长对学校工作的了解，真正达到家校携手、共同培养孩子的目的，根据学校统一安排，从17日开始，高一三个普通班分批组织了家长交流会。班主任们首先从学校建设情况入手讲解，之后从班级建设、学生日常学习、生活纪律、生活等方面向家长详细介绍了学生在校情况。最后，各班分别进行一对一、一对多座谈会，三位班主任和三位助理班主任有针对性地与家长沟通。</section><section><section>从10月20日开始，新航实验高一级部两个融合班的家长交流会以沙龙形式展开，20日、21日、22日分三批进行。在21日的家长沙龙上，班主任王春晓老师首先向家长介绍了开学以来的课程设置、活动安排，让家长对学校和孩子有了更深入的了解。</section><section><p><a href="images/41977c2881f9424b8dc641e5fa6ec7e1.jpg" target="_blank"><img width="564" height="378" title="两岸4.jpg" src="/uploads/migration/images/41977c2881f9424b8dc641e5fa6ec7e1.jpg"/></a><a href="images/68a396af263a4f4e95dbff838c76fbd0.jpg" target="_blank"><img width="603" height="554" title="两岸5.jpg" src="/uploads/migration/images/68a396af263a4f4e95dbff838c76fbd0.jpg"/></a></p><p>沙龙讲座，家校齐心助力学生成长</p></section><section>依托山东省实验中学丰富而有效的教学管理经验之上，新航实验开发了独有的周末特色课程服务，当天的家长沙龙上，家长们高度评价了新航实验周末课程的形式和内容设置，同时家长们积极建言献策，针对各个问题畅所欲言，提出了许多具有建设性的想法。</section><section><p>活动最后，新航实验副校长张爱梅做总结发言，她向学生和家长们展示了一条高中三年清晰的时间规划，抚平了家长心中的那一丝焦虑。</p><p><a href="images/1a656375f39c48b8bd0e68382af8ea33.jpg" target="_blank"><img width="547" height="394" title="两岸6.jpg" src="/uploads/migration/images/1a656375f39c48b8bd0e68382af8ea33.jpg"/></a><a href="images/4f190c9775f74fbbba0ecb74714569ef.jpg" target="_blank"><img width="550" height="385" title="两岸7.jpg" src="/uploads/migration/images/4f190c9775f74fbbba0ecb74714569ef.jpg"/></a></p></section></section><section><section><section>“我们家长和学校培养孩子的目标都是一致的，道路方式上思维的碰撞激起的火花，可以照亮孩子成长之路。”一位学生家长感慨道，老师有信心，学生沉下心，家长就能安心，“只要家校齐心，定能点石成金。”</section><section>截至22日晚，新航实验此次“剧组式”家长交流会活动圆满结束，今后类似的家长交流会还将定期展开，加强家校交流，共同为学生成长成才保驾护航。</section><p><br/></p><p><br/></p><p>&nbsp;</p><p><br/></p><p><br/></p></section></section><span><section><span><section><br/></section></span></section></span></section><span><section><span><section><br/></section></span></section></span><span><section><span><section><br/></section></span></section></span></section><span><section><span><section><br/></section></span></section></span><span><section><span><section><br/></section></span></section></span><span><section><span><section><br/></section></span></section></span></section><span><section><span><section><br/></section></span></section></span></span><span><section><span><section><br/></section></span></section></span></span><span></span><section><br/></section><span></span><section><br/></section></section><p><br/></p></section><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-10-31 08:00:00+08', '2019-10-31 08:00:00+08', '2019-10-31 08:00:00+08', '王雪', '新航实验外国语学校', '实验 举行 新航 共建 剧组', '');
INSERT INTO public.news VALUES (1000, 'Knowledge Feast:33 school-based courses are provided for students in JXEFLS', '', '      “Today I must clear up the structural parts I didn&#39;t understand last week , only when I assemble the structure myself can I feel a sense of accomplishment. &quot; On the afternoon of 29th, a...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “Today I must clear up the structural parts I didn&#39;t understand last week ,</span><span>&nbsp;</span><span>only when I assemble the structure myself can I feel a sense of accomplishment. &quot; On the afternoon of 29th, a group of students of Jinan Xinhang Experimental Foreign Language School entered the classroom excitedly. At the same time, technology tutor Ruiqi Meng had already been waiting for them. Over the next two classes, they began the intense and busy robot design.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>In Jinan Xinhang Experimental Foreign Language School, the last two classes every Tuesday afternoon became the most anticipated moment for junior high school students, and the last two classes every Thursday afternoon were the most exciting moment for senior high school students, because they all welcomed their own &quot;buffet&quot; -- 33 school-based courses, allowing each student to find their favorite &quot;dish”.</span></span></p><p><span><a href="images/e4b019dbbefd4560856f756c50933a72.jpg" target="_blank"><img title="f0226ac6d584fda472af06eae646e64.jpg" src="/uploads/migration/images/e4b019dbbefd4560856f756c50933a72.jpg"/></a></span></p><p><span><strong><span>No.1</span></strong><strong><span>&nbsp;</span></strong><strong><span>Curriculum Diversity </span></strong></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; There are 33 kinds of School-based courses in total for students to choose. Robots Design and Construction, the Whole Landform Mars Probes Course, Foreign Language Listening and Speaking, French,&nbsp;Korean, Animation Painting Course ,Ceramic Craft, Chinese Character Theory and Chinese Culture......At first glance, the courses seem to be far away from students, but in Xinhang Experimental Foreign Language School ,the school-based courses are offered for the first grade middle school students .Each of these courses is truly a “ blockbuster”. </span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; At the beginning of October , after students’ adaptation and adjustment , the first batch of 33 school-based courses was officially announced according to the results of the students&#39;&nbsp;learning demands ,the declaration of teachers&#39; independent development in the early stage and students&#39; online independent course selection. It included 17 course for middle school students and 16 course for high school students. In the list of school-based courses for middle school students, there are courses of subject quality and ability improvement ,as well as courses of traditional culture and technical skills .There are 33 courses in 4 categories for students to choose freely.</span></p><p>&nbsp;</p><p><strong><span>No.2 Large Span</span></strong><strong><span>&nbsp;Content</span></strong></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The first batch of 33 school-based courses almost cover all aspects of ancient and modern China and foreign countries, as well as literature,history and science. All the courses include traditional culture courses such as calligraphy and ceramics, language development courses like Korean and French, as well as core literacy courses, STEAM courses and general high school joint courses. Every course has been discussed repeatedly by teachers, presenting students with a &quot;feast of knowledge&quot;.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; On the afternoon of the 29th, the school-based course &quot;Chinese character theory and Chinese culture&quot;, which aims to explore the beauty of Chinese character culture, was once launched again in the library. After the warm-up of the previous classes, the students already had a clear understanding of the structure and content of this school course, and the enthusiasm for learning continues to rise. The instructor Shuangshuang Liu started from the vivid and interesting crossword puzzles, in the face of the flexible culture of Chinese character, the students thought actively, spoke enthusiastically, solved puzzles and marveled at the wonders of Chinese characters. Just when no one wanted to stop, teacher Liu Shuangshuang led the students to the mysterious world of oracle. Everyone got an ancient book of Chinese characters, unlike the colorful modern books , these books are simple and even a little crude, the mottled handwriting on the book seemed to tell an ancient story. &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p><p><span>The students were interested in the rich cultural connotations of oracle bone inscriptions, such as sacrificial offerings and predictions of agricultural activities which are introduced by the teacher,&nbsp;all the students listened with relish and completely lingered in the mysterious ancient world. Then, the students used the knowledge they learned to independently judge the oracle glyphs of the Chinese zodiac and shared their unique discoveries in each character. The interesting findings not only made the children realize the wisdom of the ancients in creating the Chinese characters, but also pushed the classroom atmosphere to the climax.</span></p><p><span><a href="images/0f6bf41b7a4b4bf38c55a2f1eb12ce63.jpg" target="_blank"><img title="ef67102dfd413edfca1ee37a5cb609e.jpg" src="/uploads/migration/images/0f6bf41b7a4b4bf38c55a2f1eb12ce63.jpg"/></a><a href="images/2aa6651760b34cbea037121c5808c0d0.jpg" target="_blank"><img title="f6cfdd6e47cd6df025b5d0e0aa89856.jpg" src="/uploads/migration/images/2aa6651760b34cbea037121c5808c0d0.jpg"/></a><a href="images/bcfaf7eb5f154cfe9db9afd1a90e1bd1.jpg" target="_blank"><img title="f60bddfb3c74385d56c1fd377af29d2.jpg" src="/uploads/migration/images/bcfaf7eb5f154cfe9db9afd1a90e1bd1.jpg"/></a></span></p><p><br/></p><p><strong><span>No.3 Sophisticated Equipment</span></strong></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The advanced and high-end equipment makes students exclaimed “Awesome!”.In addition to the rich curriculum setting and diversified training objectives, there is another important feature in the school-based curriculum schedule of Jinan Xinhang Experimental School that has aroused students&#39; general concern, which is the high hardware facilities.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; In terms of chemistry, our school has opened two school-based courses for high school students which are experimental chemistry and structural chemistry. One of the instructors of experimental chemistry course is Yizhen Liu, who has served as the leader of chemistry teaching and research group in Shandong Experimental High School for nearly twenty years. The other instructor Mingbo Liu has more than ten years&#39; teaching experience . &nbsp;A set of experimental equipment for everyone, high-tech space module integration system, and scientific lab coat let the students have a sense of science-fiction films . However, the experiment content is so close to the life, including the experiment of extracting iodine from kelp, extracting and purifying pigment from spinach and caffeine from tea. Every experiment made the students fall in love with chemistry.</span></p><p><span>In the course of robot design and production developed by teacher Ruiqi Meng, students can not only learn the design and production of robot, including its development process, main technical components (mechanical system, control system, perception system) and control strategy, but also are able to complete relevant production tasks and comprehensive design and production. A set of professional tools and equipment are all configured by the school, students can complete the assembly task without bringing any materials.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; “Students can build a complete robot by themselves after using the assembly tools, practicing the connection of structural parts and developing hands-on skills.&quot; Ruiqi Meng said.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; In addition, Jinan Xinhang Experimental Foreign Language School also equipped with the most advanced intelligent calligraphy classroom system. Students are amazed by the digital copying table set by each student, where they can get close to hundreds of classic steles and tens of thousands of examples of Chinese characters. Laboratory, constant temperature swimming pool, dance room, piano room, campus radio station... In Jinan Xinhang Experimental Foreign Language School, there are still many similar sophisticated equipment, waiting for teachers and students to explore and develop.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; The development and implementation of the first batch of school-based courses fully demonstrated the elegant demeanor of the teachers in Jinan Xinhang Experimental Foreign Language School , and enabled each student to choose a course which is suitable for their own interest development, providing students with a feast of knowledge. After that, the school-based curriculum will continue to enrich and improve, continue to strengthen the characteristics, and truly realize the concept of &quot;let every life bloom brilliantly &quot;.</span></p><p><span>供稿：付真玉、孟瑞琪</span></p><p><span>翻译：李佳怡、王曦羽、段淑雯、陈佳怡、董芊语</span></p><p><span>翻译指导：孙雨辰</span></p><p><span><br/></span></p><p><br/></p><p><span><br/></span></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-10-31 08:00:00+08', '2019-10-31 08:00:00+08', '2019-10-31 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (1001, '现场把脉：济南市教研院莅临新航实验教学督导', '', '          9月24日下午，济南市教育教学研究院一行12人，在副院长李勇和院长助理田序海带领下，来到济南新航实验外国语学校进行实地调研和教学全面督导。新航实验执行校长林宝磊、副校长张爱梅，以及相关教学部门负责人全程陪同调研督导。     林宝磊校长首先围绕学校的办学特色和定位、课程设置、教师队伍建设、培养模式等方面进行介绍，详细阐释了新航实验的办学理念和校风校训的深刻内涵，并对今年初一年级...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp; <br/></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; 9月24日下午，济南市教育教学研究院一行12人，在副院长李勇和院长助理田序海带领下，来到济南新航实验外国语学校进行实地调研和教学全面督导。新航实验执行校长林宝磊、副校长张爱梅，以及相关教学部门负责人全程陪同调研督导。</span></p><p><span><a href="images/f8355c7be3e8428d9949dea17724cba2.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_f8355c7be3e8428d9949dea17724cba2.jpg" width="568" height="374"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; 林宝磊校长首先围绕学校的办学特色和定位、课程设置、教师队伍建设、培养模式等方面进行介绍，详细阐释了新航实验的办学理念和校风校训的深刻内涵，并对今年初一年级和高一年级的招生录取情况进行简要汇报。</span></p><p><span><span><a href="images/1791a5159a4a43108d99404f57477f07.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_1791a5159a4a43108d99404f57477f07.jpg" width="500" height="279"/></a></span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 李勇院长首先介绍了此行前来的各学科市教研员，并表示将继续加强联系，推动全市教学质量的提高。</span></p><p><span><span><a href="images/03b47f4042c040cb983ae9b6ac14e399.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_03b47f4042c040cb983ae9b6ac14e399.jpg" width="500" height="295"/></a></span></span></p><p><span></span></p><p><span><span></span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 随后，各科教研员老师分别进班听课，深入一线课堂调研教学情况，为新航实验教学工作“把脉问诊”，并实地察看了新航实验各功能室和场馆设施，亲自坐在教室里感受学生学习环境。教研员们对新航实验一流的教育教学设施，先进的办学理念，以及学校为学生学习生活所做布置的专业和用心，都给予了充分的肯定。</span></p><p><span></span></p><p><span><span><a href="images/847633dff0744e09a47107d10e519dc9.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_847633dff0744e09a47107d10e519dc9.jpg" width="500" height="209"/></a></span></span></p><p><span><span></span></span></p><p><span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 李勇院长和市教研院教育质量评估部副主任安学宝听取了孙庆华老师的《数轴》一课<span>。</span></span></p><p><span><span></span></span></p><p><span><a href="images/ef9ef05c0c354b5ab107851e0d87706d.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_ef9ef05c0c354b5ab107851e0d87706d.jpg" width="500" height="271"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 市教研院英语教研员刘燕听取了王梦雅老师执教的《My Name is Gina》一课。</span></p><p><span></span></p><p><span><span><a href="images/ffc2bfc9853c4b10a45d74f468f39627.jpg" target="_blank"><img title="市教研6.jpg" src="/uploads/migration/images/ffc2bfc9853c4b10a45d74f468f39627.jpg"/></a></span></span></p><p><span>市教研院音乐教研员闫晓艳听取了闫浩艺老师执教的 《多彩的民歌——汉族民歌》一课。</span></p><p><span></span></p><p><span></span></p><p><span></span><br/></p><p><span><a href="images/4b647064f8d44a88af658bf5531bf959.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4b647064f8d44a88af658bf5531bf959.jpg" width="500" height="333"/></a></span></p><p><span></span></p><p><span><a href="images/c3857efb5bc74dc7be2634dad87ad1e4.jpg" target="_blank"><img title="市教研8.jpg" src="/uploads/migration/images/c3857efb5bc74dc7be2634dad87ad1e4.jpg"/></a></span></p><p><span></span><br/></p><p><span>其中，在听了初中组孙庆华老师的一堂课后，李勇院长专门找到孙庆华进行指导，孙庆华老师感慨的说道：“让我受益匪浅，明白了数学教学应该注意的问题。”作为老师并不是简单的把书本上面的知识带上黑板就可以了，学生们需要的是有温度的教育、分层次的教育，能让学生乐学善学会学，提高学生成绩的同时也提高了老师自己的能力，“争取早日成长为一名合格的中学教师。”</span></p><p><span><span><a href="images/5dbbabe5a78443e5aa59d8df6fb63b22.jpg" target="_blank"></a><a href="images/5dbbabe5a78443e5aa59d8df6fb63b22.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_5dbbabe5a78443e5aa59d8df6fb63b22.jpg" width="500" height="278"/></a></span></span></p><p><span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 在听了初中英语组王梦雅老师的一节英语课后，英语教研员刘燕老师提出了自己的思考，对学生学情建档，连续动态跟踪，教学始终与学生学情同频。</span></p><p><span>&nbsp; &nbsp; &nbsp;在听课结束后，教研员们来到办公室，分别与各学科组老师进行了深入细致的交流，还提出了打造高效课堂的措施与方法。同时，教研员深入了解各学科组，详尽解答了老师们在工作遇到的困惑和问题，为教育教学工作指明了方向。</span></p><p><span>&nbsp; &nbsp; &nbsp;活动最后，林宝磊校长代表学校感谢济南市教研院专家对新航实验的支持和帮助，深入教学一线，为课堂教学带来的提升。作为山东省实验中学教育集团成员校，新航实验全员干劲十足，力争将新航实验打造成一所高起点、高品位、高质量的多元化创新型学校，成为济南基础教育领域的一张亮丽名片。</span></p><p><span><br/></span><br/></p><p><span><br/></span></p><p><br/></p><p><span><br/></span><br/></p><p><span><br/></span></p><p><span><br/></span></p><meta name="ContentEnd">', '', 'research', '', NULL, true, '2019-10-28 08:00:00+08', '2019-10-28 08:00:00+08', '2019-10-28 08:00:00+08', '王雪', '新航实验外国语学校', '莅临 新航 教研 济南市 实验', '');
INSERT INTO public.news VALUES (1002, '庆祖国华诞 燃青春激情­——新航实验举行首场趣味运动会', '', '       9月30日上午，济南新航实验外国语学校迎来了第一届趣味运动会，初一级部和高一级部的同学们在欢声笑语声和呐喊助威声中度过了这场激烈又有趣的运动会，用自己的热情和斗志为祖国的70华诞献礼。         上午8点，在激昂奋进的国歌旋律中，运动会拉开了帷幕。首先由新航实验副校长张爱梅发表致辞，为运动健儿们加油鼓劲。接着全体初一学生合唱《我和我的祖国》，展示了新航实验学子的精神风貌和爱国情...', '', '<p>&nbsp; &nbsp; &nbsp;&nbsp; 9月30日上午，济南新航实验外国语学校迎来了第一届趣味运动会，初一级部和高一级部的同学们在欢声笑语声和呐喊助威声中度过了这场激烈又有趣的运动会，用自己的热情和斗志为祖国的70华诞献礼。</p><p><a href="images/05e6e9a644334cf7be8c1676f43ffa7c.jpg" target="_blank"><img width="714" height="454" title="运动会1.jpg" src="/uploads/migration/images/05e6e9a644334cf7be8c1676f43ffa7c.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 上午8点，在激昂奋进的国歌旋律中，运动会拉开了帷幕。首先由新航实验副校长张爱梅发表致辞，为运动健儿们加油鼓劲。接着全体初一学生合唱《我和我的祖国》，展示了新航实验学子的精神风貌和爱国情怀。</p><p><a href="images/316962469e374f6090c12095546bf39f.jpg" target="_blank"><img width="511" height="364" title="运动会2.jpg" src="/uploads/migration/images/316962469e374f6090c12095546bf39f.jpg"/></a><a href="images/129922d26dfa487fa9822eaec33b76b3.jpg" target="_blank"><img width="509" height="364" title="运动会3.jpg" src="/uploads/migration/images/129922d26dfa487fa9822eaec33b76b3.jpg"/></a></p><p><a href="images/316962469e374f6090c12095546bf39f.jpg" target="_blank"></a><a href="images/01988861c09447bf89c09fe110fa2fb5.jpg" target="_blank"><img title="运动会4.jpg" src="/uploads/migration/images/01988861c09447bf89c09fe110fa2fb5.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 此次趣味运动会的第一个项目是垒球投准，在中华民族传统娱乐项目投壶的基础上推陈出新，以垒球代替羽箭，考验学生投准能力。还有精彩的胯下交替运球跑，参赛者手持篮球，在二十米的赛道上进行胯下运球折返跑，比赛现场气氛热烈，选手们发扬了运动场上勇于拼搏、奋勇争先的精神，为班级荣誉而奋战到底。最有趣的活动是“赶猪赛跑”，参赛者手持体操杆，带动足球进行接力绕杆障碍折返跑，先到达终点者为胜。在这个项目中，初一三班的运动员齐心协力拔得头筹。还有将此次运动会推向高潮的四人协同跑，在激烈的竞赛中，初一一班的运动员脱颖而出，摘得本项目的桂冠！</p><p><a href="images/135a035caa76421494bbf2deb10052af.jpg" target="_blank"><img width="646" height="375" title="运动会5.jpg" src="/uploads/migration/images/135a035caa76421494bbf2deb10052af.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 上午9点，高一级部趣味运动会拉开帷幕，五个班级围绕拔河比赛使出“看家本领”，经过为时一个半小时的多轮比拼，最终高一二班夺得本次拔河比赛冠军。比赛中，每一位同学都全力以赴，拼命拉住手中的拔河绳，谁也不懈怠，谁也不言败，这种团结精神与奋勇争先的精神，实在令人震撼，连在一旁喝彩的同学也受到感染，挥舞着双手，打着节拍，为运动员加油鼓劲！</p><p><a href="images/8c2b266822d9408c8e24199363d626a5.jpg" target="_blank"></a><a href="images/7900afbfd41d44c1b5cd7d0325ddcb5b.jpg" target="_blank"><img width="603" height="656" title="运动会7.jpg" src="/uploads/migration/images/7900afbfd41d44c1b5cd7d0325ddcb5b.jpg"/></a></p><p><a href="images/8c2b266822d9408c8e24199363d626a5.jpg" target="_blank"></a><a href="images/a5d6d6230fb14834b3f22257e08a5939.jpg" target="_blank"><img width="491" height="365" title="运动会8.jpg" src="/uploads/migration/images/a5d6d6230fb14834b3f22257e08a5939.jpg"/></a><br/></p><p><br/></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 令人印象最深的是最后一场，在比赛结束前每一人都屏息凝神，随着一声哨响，瞬间加油声呐喊声充斥这整个校园，令人振奋。<br/></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 此次趣味运动会，培养了学生的集体荣誉感与团结协作的精神，也激励着大家把运动会的精神继续发扬下去，以饱满的姿态迎接祖国的70华诞和来之不易的幸福生活！</p><p><span><span><span><span><br/></span></span></span></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-10-21 08:00:00+08', '2019-10-21 08:00:00+08', '2019-10-21 08:00:00+08', '王雪', '新航实验外国语学校', '新航 实验 激情 举行 青春', '');
INSERT INTO public.news VALUES (1003, '向校园违禁品说不：新航实验启动学生公寓安全大检查', '', '为保障新航实验校园安全，杜绝安全隐患，23日一大早，济南新航实验外国语学校学生公寓内，掀起了一场对校园安全的全面筛查，包括物业、后勤安保、学生发展中心等多部门的十余位工作人员参加，逐一检查学生公寓中的物品，并根据情况做好记录和反馈。       实际上，早在上周，各班班主任就提前通知了每一位学生，将可能会存在安全隐患的物品带回家中，检查过程中，大多数学生公寓安全状况良好，没有发现重大安全隐患。但当...', '', '<section><section><p>为保障新航实验校园安全，杜绝安全隐患，23日一大早，济南新航实验外国语学校学生公寓内，掀起了一场对校园安全的全面筛查，包括物业、后勤安保、学生发展中心等多部门的十余位工作人员参加，逐一检查学生公寓中的物品，并根据情况做好记录和反馈。</p><p><a href="images/ccf245ddce0f431ca4ddd0f967af7a51.jpg" target="_blank"><img width="583" height="385" title="安全检查1.jpg" src="/uploads/migration/images/ccf245ddce0f431ca4ddd0f967af7a51.jpg"/></a></p><p><a href="images/e05d2303ce224e0c952369a537347f23.jpg" target="_blank"><img width="450" height="467" title="安全检查2.jpg" src="/uploads/migration/images/e05d2303ce224e0c952369a537347f23.jpg"/></a></p><p><a href="images/485a3d3e9bd8463aa21aed6cd87dc4a0.jpg" target="_blank"><img width="509" height="332" title="安全检车3.jpg" src="/uploads/migration/images/485a3d3e9bd8463aa21aed6cd87dc4a0.jpg"/></a></p></section></section><p><br/></p><section><section><section></section></section></section><p><br/></p><p><span>&nbsp; &nbsp; &nbsp;&nbsp; 实际上，早在上周，各班班主任就提前通知了每一位学生，将可能会存在安全隐患的物品带回家中，检查过程中，大多数学生公寓安全状况良好，没有发现重大安全隐患。但当天检查中仍发现了部分存在安全隐患的物品，在生活指导老师登记之后被统一暂存代管。</span></p><p><span><a href="images/12d246e81e7c4b528300dfb1ac91183a.jpg" target="_blank"><img width="502" height="458" title="安全检查4.jpg" src="/uploads/migration/images/12d246e81e7c4b528300dfb1ac91183a.jpg"/></a></span><span><span></span></span></p><p><span></span></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 在进行安全大检查的同时，周一上午的升旗仪式上，济南新航实验外国语学校副校长张术磊做了主题为《遵守安全规则，树立安全意识》的发言。“安全无小事，责任大于天。学校一切关注的原点保证生命的安全，所有努力的方向都是为了呵护花蕾一样的你们，所以大家都要做自己生命的第一责任人，能让自己健康安全成长，就是对祖国70周年的最好献礼！”张术磊语重心长地提醒同学们，遵守学校的安全规定，是安全的基本保障。有规矩的自由才是真正的自由，规矩就是保障同学们正常生活的管理规定，没有了规矩的后果只有混乱和不安。“大家可以感受到老师每天会去查寝，食堂有老师陪餐，放学有老师把大家送上班车，本质上都是对于同学们的安全负责。”张术磊说道。</p><p><span></span><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '王雪', '新航实验外国语学校', '启动 实验 学生 公寓 新航', '');
INSERT INTO public.news VALUES (1004, '孟瑞琪', '', '                孟瑞琪，中共党员，天津职业技术师范大学控制理论与控制工程硕士，维修电工二级，中国青少年机器人竞赛国家二级裁判员。在校期间，担任班长，曾获得优秀研究生干部；参与国家863计划、国家重点研发项目等，发表专利、论文多篇，现担任科技辅导教师。', '', '<p>&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;<a href="images/098e441a48bb479f91980bc1d04bcbca.jpg" target="_blank"><img title="孟瑞琪.jpg" src="/uploads/migration/images/098e441a48bb479f91980bc1d04bcbca.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp; 孟瑞琪，中共党员，天津职业技术师范大学控制理论与控制工程硕士，维修电工二级，中国青少年机器人竞赛国家二级裁判员。在校期间，担任班长，曾获得优秀研究生干部；参与国家863计划、国家重点研发项目等，发表专利、论文多篇，现担任科技辅导教师。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '王雪', '新航实验外国语学校', '孟瑞琪', '');
INSERT INTO public.news VALUES (1005, '王雪', '', '      王雪，硕士研究生，毕业于山东师范大学信息科学与工程学院计算机技术专业，英语六级，在校期间担任文体部副部长，曾多次获得校级优秀学生奖学金，优秀研究生，在校期间，曾在淄博实验中学担任过信息技术实习教师，曾在浪潮集团实习，参与多个浪潮-山东师范大学校企合作项目的设计与开发，发表专利两篇，协助导师编写<<软件设计模式>>书籍，指导本科生创新创业大赛，现担任济南新航实验外国语学校信息技术教师。', '', '<p><span><span><a href="images/d5351f0d43b24972970c64e80fc1aee4.jpg" target="_blank"><img title="王雪.jpg" src="/uploads/migration/images/d5351f0d43b24972970c64e80fc1aee4.jpg" width="258" height="383"/></a></span></span></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span>王雪，硕士研究生，毕业于山东师范大学信息科学与工程学院计算机技术专业，英语六级，在校期间担任文体部副部长，曾多次获得校级优秀学生奖学金，优秀研究生，在校期间，曾在淄博实验中学担任过信息技术实习教师，曾在浪潮集团实习，参与多个浪潮-山东师范大学校企合作项目的设计与开发，发表专利两篇，协助导师编写<span>&lt;&lt;</span><span>软件设计模式</span><span>&gt;&gt;</span><span>书籍，指导本科生创新创业大赛，现担任济南新航实验外国语学校信息技术教师。</span></span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '王雪', '新航实验外国语学校', '王雪', '');
INSERT INTO public.news VALUES (1006, '亓嫣娇', '', '             亓嫣娇，毕业于山东师范大学信息管理学院计算机科学与技术专业，英语六级，在校期间多次获得奖学金。毕业后在山东大学职业技术学院计算机专业担任教师，参与组织并主持了济南计算机学会首届济南大学生软件设计大赛、济南大学生计算机专业外语大赛。之后创办了博雅食尚通软件开发有限公司，致力于计算机软件开发以及硬件的技术支持，储备了丰富的专业知识。因为对教育的热爱，受聘于著名辅导机构教授初高...', '', '<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <a href="images/4578892a345144b8a803307bc1952a88.jpg" target="_blank"><img title="亓.jpg" src="/uploads/migration/images/4578892a345144b8a803307bc1952a88.jpg" width="234" height="341"/></a></p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 亓嫣娇，毕业于山东师范大学信息管理学院计算机科学与技术专业，英语六级，在校期间多次获得奖学金。毕业后在山东大学职业技术学院计算机专业担任教师，参与组织并主持了济南计算机学会首届济南大学生软件设计大赛、济南大学生计算机专业外语大赛。之后创办了博雅食尚通软件开发有限公司，致力于计算机软件开发以及硬件的技术支持，储备了丰富的专业知识。因为对教育的热爱，受聘于著名辅导机构教授初高中课程，以平易近人、寓教于乐的教学风格多次获得学生最受欢迎教师。<br/>人生格言是：把爱带给每位学生，用千百倍的耕耘，换来桃李满园香。双手扶持千木茂，慈怀灌注万花稠。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '2019-09-29 08:00:00+08', '王雪', '新航实验外国语学校', '亓嫣娇', '');
INSERT INTO public.news VALUES (1007, '树立规则意识，在方圆的世界里起航', '', '        2019年9月16日，济南新航实验外国语学校在多媒体大剧院举行全校升旗仪式。此次升旗仪式由高一1班承办，并围绕“遵守校规校纪，做文明中学生”这一主题展开。升国旗，行注目礼         仪式开始，首先，由高一一班马骁函宣布济南新航实验外国语学校升旗仪式正式开始，紧接着四名旗手踏着坚定的步伐朝主席台走去，每位同学坚毅的目光和认真的态度展现出了高一一班团结一心、积极进取的班级风貌。国...', '', '<p>&nbsp; &nbsp; &nbsp; &nbsp; <span>2019年9月16日，济南新航实验外国语学校在多媒体大剧院举行全校升旗仪式。此次升旗仪式由高一1班承办，并围绕“遵守校规校纪，做文明中学生”这一主题展开。</span><br/></p><section><section><section><section><section><section><section><p><br/></p><p><strong><span><a href="images/f6e3aef2490c4674a8ade4eac999f7c3.jpg" target="_blank"><img width="531" height="358" title="11.jpg" src="/uploads/migration/images/f6e3aef2490c4674a8ade4eac999f7c3.jpg"/></a></span></strong></p><p><strong><span><span>升国旗，行注目礼</span></span></strong></p></section></section></section></section></section></section></section><p><span>&nbsp; &nbsp;&nbsp;<a href="images/437c86e685f643eba86eaeb1863ab417.jpg" target="_blank"><img width="490" height="381" title="22.jpg" src="/uploads/migration/images/437c86e685f643eba86eaeb1863ab417.jpg"/></a></span></p><p><span>&nbsp; &nbsp;&nbsp; 仪式开始，首先，由高一一班马骁函宣布济南新航实验外国语学校升旗仪式正式开始，紧接着四名旗手踏着坚定的步伐朝主席台走去，每位同学坚毅的目光和认真的态度展现出了高一一班团结一心、积极进取的班级风貌。</span><br/></p><p><a href="images/18db4aebaee2424392a3cd38059678c9.jpg" target="_blank"><img width="519" height="421" title="33.jpg" src="/uploads/migration/images/18db4aebaee2424392a3cd38059678c9.jpg"/></a></p><p><a href="images/dc0ba8cffb8f4bea9f76bd790fe4fef5.jpg" target="_blank"><img width="424" height="321" title="44.jpg" src="/uploads/migration/images/dc0ba8cffb8f4bea9f76bd790fe4fef5.jpg"/></a></p><p><a href="images/7fdc0181c23a4ab5af20721aedc92d1e.jpg" target="_blank"><img width="418" height="375" title="55.jpg" src="/uploads/migration/images/7fdc0181c23a4ab5af20721aedc92d1e.jpg"/></a></p><section><section><section><section><section><section><section><p><strong><span>国旗下演讲</span></strong><span><br/></span></p></section></section></section></section></section></section></section><p><a href="images/d6930445aa1645d9a28b5fcc7281221c.jpg" target="_blank"><img width="444" height="325" title="66.jpg" src="/uploads/migration/images/d6930445aa1645d9a28b5fcc7281221c.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp; <span>随后，由高一一班学生代表郑子馨进行了国旗下讲话，主题为《遵守校规校纪，做文明中学生》。她从学生日常的穿衣服饰、课堂自习以及宿舍纪律等方面谈了自己的体会，并向同学们强调了规则与纪律的重要性。</span><br/></p><section><section><section><section><section><section><section><p><strong><span>总结发言</span></strong></p></section></section></section></section></section></section></section><p><span><a href="images/7e8821ebe37142798be673dcaaef3b6d.jpg" target="_blank"><img width="490" height="353" title="77.jpg" src="/uploads/migration/images/7e8821ebe37142798be673dcaaef3b6d.jpg"/></a></span></p><p>&nbsp; &nbsp; &nbsp;&nbsp; <span>最后，济南新航实验外国语学校学生发展中心、教学管理中心主任王飞做总结发言，分别从课上听讲、按时出勤、自习纪律、午晚休纪律、教室公寓卫生、餐厅安静有序、文明礼貌、出行安全等方面对同学们提出了要求，提出了“安全意识不仅在言语中牢记，还要在行为中落实”的观点，规范了同学们的言行，提高了同学们的安全意识与规则意识。同时也鼓舞了全体师生，以更加饱满的精神面貌投入到今后的学习生活中去。</span></p><p><span><a href="images/c159389dee1d4661a16eaedae2c94730.jpg" target="_blank"><img width="521" height="348" title="88.jpg" src="/uploads/migration/images/c159389dee1d4661a16eaedae2c94730.jpg"/></a></span></p><p><span><a href="images/4ab838bfb703483b99dd60fad6c8f9d0.jpg" target="_blank"><img width="529" height="386" title="99.jpg" src="/uploads/migration/images/4ab838bfb703483b99dd60fad6c8f9d0.jpg"/></a></span></p><p><span><a href="images/ca6c1b4c0f0d4238b677e1d451fc48bc.jpg" target="_blank"><img width="672" height="469" title="110.jpg" src="/uploads/migration/images/ca6c1b4c0f0d4238b677e1d451fc48bc.jpg"/></a></span></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-09-17 08:00:00+08', '2019-09-17 08:00:00+08', '2019-09-17 08:00:00+08', '王雪', '新航实验外国语学校', '世界 规则 方圆 意识 起航', '');
INSERT INTO public.news VALUES (1008, '王冉', '', '       王冉:中共党员，英语专业文学学士，10年英语教学经验，具有高校教师资格证。       曾任大学英语专业课教师，口语专业课教师。曾获校级优秀教师，校级课堂教学技能大赛一等奖，&quot;小金人&quot;奖，山东省首届“新时代”杯写作大赛优秀指导教师奖等。', '', '<p><a href="images/9014ae2024c34bdf819921071c521a71.jpg" target="_blank"><img width="202" height="278" title="王冉.jpg" src="/uploads/migration/images/9014ae2024c34bdf819921071c521a71.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 王冉:中共党员，英语专业文学学士，10年英语教学经验，具有高校教师资格证。<br/>&nbsp; &nbsp; &nbsp;&nbsp; 曾任大学英语专业课教师，口语专业课教师。曾获校级优秀教师，校级课堂教学技能大赛一等奖，&quot;小金人&quot;奖，山东省首届“新时代”杯写作大赛优秀指导教师奖等。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '王雪', '新航实验外国语学校', '王冉', '');
INSERT INTO public.news VALUES (1009, '胡小会', '', '                 胡小会，毕业于山东师范大学人文地理专业，在校期间曾担任校招生就业处创新创业实训中心主席，多次荣获奖学金。', '', '<p><a href="images/6791592377a94200b0aee4c4cb8a9964.jpg" target="_blank"><img width="210" height="236" title="胡小会.jpg" src="/uploads/migration/images/6791592377a94200b0aee4c4cb8a9964.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 胡小会，毕业于山东师范大学人文地理专业，在校期间曾担任校招生就业处创新创业实训中心主席，多次荣获奖学金。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '王雪', '新航实验外国语学校', '胡小会', '');
INSERT INTO public.news VALUES (1010, '张鹏', '', '张鹏，北京大学毕业，主修美术学专业，获文学硕士学位，自幼研习国画书法，在校期间多次获校级奖学金，2013年参加工作。', '', '<p><a href="images/4f22807a46ed435f9ac851cfd753204e.jpg" target="_blank"></a><a href="images/35753d0ece2f43949a5cc892c861693f.jpg" target="_blank"><img title="张鹏 标准照.jpg" src="/uploads/migration/images/35753d0ece2f43949a5cc892c861693f.jpg" width="172" height="257"/></a></p><p>张鹏，北京大学毕业，主修美术学专业，获文学硕士学位，自幼研习国画书法，在校期间多次获校级奖学金，2013年参加工作。</p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '2019-09-16 08:00:00+08', '王雪', '新航实验外国语学校', '张鹏', '');
INSERT INTO public.news VALUES (1011, '孙雨辰', '', '       孙雨辰，女，毕业于常青藤联盟罗素大学集团成员，埃克塞特大学（The University of Exeter）对外英语教学专业硕士学位。先后获得英语专业八级证书，高级教师资格证书及国际英语教师证书。', '', '<p><a href="images/516809f9bc4d41f2aeb3e0a6947f88e9.jpg" target="_blank"><img width="230" height="305" title="孙雨晨.jpg" src="/uploads/migration/images/516809f9bc4d41f2aeb3e0a6947f88e9.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 孙雨辰，女，毕业于常青藤联盟罗素大学集团成员，埃克塞特大学（The University of Exeter）对外英语教学专业硕士学位。先后获得英语专业八级证书，高级教师资格证书及国际英语教师证书。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '王雪', '新航实验外国语学校', '孙雨辰', '');
INSERT INTO public.news VALUES (1012, '尚常慧', '', '       尚常慧   地理教师，毕业于山东师范大学地理与环境学院。教育理念:让学生在生活与实践中学到有用的知识。', '', '<p><a href="images/274e38264df34fd9b4ee8cfec56c5d98.jpg" target="_blank"><img width="209" height="264" title="尚常慧.jpg" src="/uploads/migration/images/274e38264df34fd9b4ee8cfec56c5d98.jpg"/></a></p><p>&nbsp; &nbsp; &nbsp;&nbsp; 尚常慧 &nbsp; 地理教师，毕业于山东师范大学地理与环境学院。教育理念:让学生在生活与实践中学到有用的知识。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '王雪', '新航实验外国语学校', '尚常慧', '');
INSERT INTO public.news VALUES (1013, '高福娜', '', '    高福娜，本科毕业，毕业于鲁东大学计算机科学与技术师范专业，在校期间，曾多次荣获国家励志奖学金，学校优秀奖学金，被授予优秀团干部称号，在校期间曾做过家教工作，主要负责辅导初中数学，暑期独立办过小型辅导机构，教授小学生语数外三门课程。担任辅导机构教师，主要负责教授初中数学。毕业后先后在政和科技股份有限公司，龙岗旅游集团担任前端开发工程师，参与开发项目有政和通，安徽省创新创业服务平台，南昌市创新...', '', '<p><a href="images/3632e08962de4e98a66305a39ed5f380.png" target="_blank"><img width="197" height="279" title="高福娜.png" src="/uploads/migration/images/3632e08962de4e98a66305a39ed5f380.png"/></a></p><p><span>&nbsp; &nbsp; 高福娜，本科毕业，毕业于鲁东大学计算机科学与技术师范专业，在校期间，曾多次荣获国家励志奖学金，学校优秀奖学金，被授予优秀团干部称号，在校期间曾做过家教工作，主要负责辅导初中数学，暑期独立办过小型辅导机构，教授小学生语数外三门课程。担任辅导机构教师，主要负责教授初中数学。毕业后先后在政和科技股份有限公司，龙岗旅游集团担任前端开发工程师，参与开发项目有政和通，安徽省创新创业服务平台，南昌市创新创业服务平台，好客山东网后台管理系统等等。</span><span></span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '王雪', '新航实验外国语学校', '高福娜', '');
INSERT INTO public.news VALUES (1014, '郭婷允', '', '郭婷允，中共党员，学士学位，2019年毕业于哈尔滨体育学院体育教育专业，主修：游泳，辅修：教育心理学，运动生理等，在校期间担任系学生会副主席一职，班级团支书一职。曾担任省级，市级篮球比赛裁判，篮球教练，羽毛球裁判，在俱乐部担任游泳教练。', '', '<p><a href="images/797e19d4f85645ac82afe99c37d33c1e.jpg" target="_blank"><img width="161" height="215" title="郭婷允.jpg" src="/uploads/migration/images/797e19d4f85645ac82afe99c37d33c1e.jpg"/></a></p><p><br/></p><p>郭婷允，中共党员，学士学位，2019年毕业于哈尔滨体育学院体育教育专业，主修：游泳，辅修：教育心理学，运动生理等，在校期间担任系学生会副主席一职，班级团支书一职。曾担任省级，市级篮球比赛裁判，篮球教练，羽毛球裁判，在俱乐部担任游泳教练。</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '2019-09-11 08:00:00+08', '王雪', '新航实验外国语学校', '郭婷允', '');
INSERT INTO public.news VALUES (1015, '十足学术范儿！济南新航实验举行首场开学典礼', '', '筑梦远航作为山东省实验中学教育集团的新成员，济南新航实验外国语学校在这个夏天吸引了省内外的高度关注。9月9日上午，学校建校后的第一次开学典礼在新落成的多媒体剧院隆重举行，近300名新生与200余位家长代表齐聚一堂，见证了首批新航学子重要的人生时刻。典礼在庄严的国歌声中拉开了帷幕。专题短片《走进新航，静待花开——向成长致敬》述说了新航人一路走来的辛苦与付出，向在场师生和来宾介绍了新航实验的硬件设施和...', '', '<section><section><section><section><section><p><strong>筑梦远航</strong><br/></p></section></section></section></section></section><section><section><p>作为山东省实验中学教育集团的新成员，济南新航实验外国语学校在这个夏天吸引了省内外的高度关注。9月9日上午，学校建校后的第一次开学典礼在新落成的多媒体剧院隆重举行，近300名新生与200余位家长代表齐聚一堂，见证了首批新航学子重要的人生时刻。</p><p><a href="images/69db59ccb95141948eea4ada74c1d885.jpg" target="_blank"><img width="425" height="354" title="微信图片_20190910091058.jpg" src="/uploads/migration/images/69db59ccb95141948eea4ada74c1d885.jpg"/></a><br/></p><section><p>典礼在庄严的国歌声中拉开了帷幕。专题短片《走进新航，静待花开——向成长致敬》述说了新航人一路走来的辛苦与付出，向在场师生和来宾介绍了新航实验的硬件设施和文化理念，也让在场的每一位新航学子对未来充满期待，对拼搏充满勇气。<br/></p><p>令在场师生和来宾振奋的是，本次开学典礼还迎来了两位学术“大咖”。他们是国家杰出青年基金获得者、中国科学院博士、耶鲁大学博士后、长江学者特聘教授、南方科技大学教授博导宋学军，国家杰出青年基金获得者、长江学者特聘教授、山东大学化学与化工学院院长郝京诚。</p><p><a href="images/f474c6e0b67c456c870ec2c48bd2701e.jpg" target="_blank"><img width="425" height="331" title="微信图片_20190910091204.jpg" src="/uploads/migration/images/f474c6e0b67c456c870ec2c48bd2701e.jpg"/></a></p></section><p>&nbsp; &nbsp; &nbsp;&nbsp; 郝京诚教授在致辞中表达了对于新航实验的期望和勉励，并给同学们带来了三个学习的锦囊——爱上学习、坚守心中那份梦想、脚踏实地去完成一件件小事。“在学习中，我们要始终坚守自己心中那份最初的梦想，坚实和笃定，时不时抬头仰望星空，并不会影响我们走路的进度，心怀仰望星空的姿态，才能更加清楚自己的行动目标。”郝京诚叮嘱道。<br/></p><section><p>为了感谢在学校前期建设中家长们的关注和付出，此次开学典礼上，还为8位家长颁发了“关心教育——建言献策奖”，也希望在学校未来发展的进程中，形成家校合力，共促学生发展。</p><p><a href="images/27852479b89e48b5835abbdc9ebff516.jpg" target="_blank"><img width="438" height="321" title="3.jpg" src="/uploads/migration/images/27852479b89e48b5835abbdc9ebff516.jpg"/></a></p><p><span>来自初一3班的渠清源和高一4班的王艺霖两位同学，现场朗诵了由新航实验初中语文教师付真玉创作的现代诗《启航与绽放》，共同描绘了新航人心中的美好愿景和发展蓝图。</span></p><p><span><a href="images/56be624999c04598986b8c2d519f41f3.jpg" target="_blank"><img width="411" height="392" title="4.jpg" src="/uploads/migration/images/56be624999c04598986b8c2d519f41f3.jpg"/></a></span></p><p><span></span></p><section><p>杨育红老师作为教师代表发表了热情洋溢的讲话，她深情的说道，“作为教师，我们依然传承山东省实验中学敬业务实的工作精神立足于讲台；以精湛的教学向课堂要效率；以和煦的师德春风去抚慰学生稚嫩的灵魂!“在场师生在杨老师身上看到了浓浓的实验情节和登攀不止的实验精神，无不为之动容。</p><p><a href="images/38441253b5fd48df98edf82684f98324.jpg" target="_blank"><img width="463" height="450" title="5.jpg" src="/uploads/migration/images/38441253b5fd48df98edf82684f98324.jpg"/></a></p><p><span>山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊发表了开学致辞。在致辞中，林校长对新航学子提出了四点要求，首先是扎实求学，新航学子要既有“书卷气”，又有“泥土气”；第二是坚毅笃行，新航学子要既能“坐而论道”，又能“起而行之”；第三是胸怀世界，新航学子要既做“齐鲁君子”，又做“世界公民”；第四是勇立潮头，新航学子要既能“勤勉互助”，又能“敢为人先”。</span></p><p><span><a href="images/d355f2ede2544e5b86e01f30df26dcc8.jpg" target="_blank"><img width="330" height="364" title="6.jpg" src="/uploads/migration/images/d355f2ede2544e5b86e01f30df26dcc8.jpg"/></a><a href="images/9520bfccedef4c1aa0663f13dee0d468.jpg" target="_blank"><img width="377" height="365" title="7.jpg" src="/uploads/migration/images/9520bfccedef4c1aa0663f13dee0d468.jpg"/></a></span></p><p><span><span>在声震全场的宣誓声中，济南新航实验外国语学校建校以来的第一次开学典礼圆满落幕</span>。</span></p><p><span><a href="images/c3f9014405bb4983a3be52cc749879c8.jpg" target="_blank"><img width="372" height="351" title="8.jpg" src="/uploads/migration/images/c3f9014405bb4983a3be52cc749879c8.jpg"/></a></span></p><p><span></span></p><section><p>仪式结束后，国家杰出青年基金获得者、中国科学院博士、长江学者特聘教授、南方科技大学教授博导宋学军，给全场师生和家长们带来主题为《人类“共情心”的社会价值和脑科学基础》的精彩讲座。</p><section><p><a href="images/8ab529290d724fdfbf3a87ad5e7d29ae.jpg" target="_blank"><img width="466" height="395" title="9.jpg" src="/uploads/migration/images/8ab529290d724fdfbf3a87ad5e7d29ae.jpg"/></a></p><p><span>济南市教育局副局长王纮，济南市教育教学研究院院长吕如浩，山东省实验中学校长、党委书记、济南新航实验外国语学校副理事长韩相河，山东新源文化置业有限公司董事长、济南新航实验外国语学校理事长李涛，济南新航实验外国语学校理事孙明等出席了活动。</span></p><p><span><br/></span></p></section><p><br/></p><section><section></section></section><p><br/></p><p><br/></p></section><p><br/></p><section><section></section></section><p><br/></p><p><span><br/></span><br/></p></section><p><br/></p><section><section><section><section></section></section></section></section><p><br/></p><p><span><br/></span><br/></p></section><p><br/></p><p><br/></p></section><p><br/></p></section><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-09-10 08:00:00+08', '2019-09-10 08:00:00+08', '2019-09-10 08:00:00+08', '王雪', '新航实验外国语学校', '实验 新航 济南 举行 范儿', '');
INSERT INTO public.news VALUES (1016, 'Welcome！', '', '      On August 25th, Jinan Xinhang Experimental Foreign Language School welcomed its first batch of students. The freshman admitted by the school this year are accompanied by their parent. Besides th...', '', '<p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; On&nbsp;August 25th,&nbsp;Jinan Xinhang Experimental Foreign Language School welcomed its first batch of students.&nbsp;The&nbsp;freshman admitted by the school this year are accompanied by their parent. Besides&nbsp;the teacher&#39;s guidance, there were also 20 senior volunteer students from Shandong Experimental High School.&nbsp;It is the first time to sort out the house for the freshmen, the first time to attend the class meeting, and also the first time to take a photo with the classmates in the dormitory.&nbsp;They were about to set sail，moving toward their dreams.</span></p><p><a href="images/8d48991e248f49af8756a1f11738731f.jpg" target="_blank"><img title="64ae317ab5df7b8123d26bb0b084ca7.jpg" src="/uploads/migration/images/8d48991e248f49af8756a1f11738731f.jpg"/></a></p><p><span><span>&nbsp;&nbsp;&nbsp;</span><span>&nbsp; The new campus was decorated with colorful balloons and banners at the gate，welcoming outstanding students from different areas.</span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;“He was so excited that got up before dawn and&nbsp;couldn’t wait&nbsp;to see his new school in advance.&nbsp;The equipment is very advanced,&nbsp;and the teachers are very kind,&nbsp;I love it here!”, a parent said. At around 10:00 on the 25th, the first batch of students arrived at the check-in&nbsp;office. At this time, there were still more than four hours left before the registration begins officially.&nbsp;Several students had begun to enjoy the beautiful scenery on campus, and kept taking photos.<a href="images/acf8a22a539d4586a6809224156ddb78.jpg" target="_blank"><img title="7c7544f68429cb642421b7dec92bcbb.jpg" src="/uploads/migration/images/acf8a22a539d4586a6809224156ddb78.jpg"/></a>g photos.</span></p><p><span><a href="images/65360048670c40b0843f20c20ab224f7.jpg" target="_blank"><img title="049ae7591d52ddb29f4bb75ff2822f2.jpg" src="/uploads/migration/images/65360048670c40b0843f20c20ab224f7.jpg"/></a><a href="images/941598d511644b5d848c45e7f4a2abd3.jpg" target="_blank"><img title="dcd75c4868d6d1158f297cea0e21786.jpg" src="/uploads/migration/images/941598d511644b5d848c45e7f4a2abd3.jpg"/></a></span></p><p><span><span>&nbsp;&nbsp;&nbsp;&nbsp;</span><span>&nbsp;<span>&nbsp; At&nbsp;1.00pm，the&nbsp;number of parents is getting larger. &nbsp;They were curious about&nbsp;the facilities of new school. Parents found children’s classroom and dormitory quickly after checking the sign. The step of new students meeting started earlier than planning for an hour. Staff and volunteers welcomed&nbsp;the new students and guided&nbsp;them&nbsp;with enthusiasm.&nbsp;Then students went to tidy their private things and beds in the dormitory. Many students worked with families including parents, grandparents, and siblings. After that, students went to the teaching area. Volunteers from Shandong Experimental High School helped&nbsp;them a lot on the way.&nbsp;&nbsp;&nbsp;</span></span></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; ‘Senior system’ is the special moral educational brand of Shandong Experimental High School.&nbsp;In every corner of the campus we could see their responsible figure.</span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp; When we came to the teaching building,the students entered the classroom one after another.&nbsp;The first thing we could see is the title “Welcome our new students” which were showing on the blackboard.&nbsp;Students and their parents visited every corner in the classroom. The whole building were fulling with the happy laughter.</span></p><p><span><a href="images/c179c1f7aaa84b9f89941b4e839fe4b9.jpg" target="_blank"><img title="22f63151793acf0e2dac989f5297879.jpg" src="/uploads/migration/images/c179c1f7aaa84b9f89941b4e839fe4b9.jpg"/></a><a href="images/05471d3680d647d29f8ecac33d81085c.jpg" target="_blank"><img title="30a64f34e6b0a209102cac55dd7c7fc.jpg" src="/uploads/migration/images/05471d3680d647d29f8ecac33d81085c.jpg"/></a><a href="images/744474dc61374f7598a94c29068f220d.jpg" target="_blank"><img title="149b9cadad1fa9ee3469103e5cf660d.jpg" src="/uploads/migration/images/744474dc61374f7598a94c29068f220d.jpg"/></a></span></p><p><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Starting from the morning of 26th, Jinan Xinhang Experimental Foreign Language School has opened the 2019 freshmen entrance education summer camp officially, which will last until 31st.In the next few days, freshmen will learn eight courses, including safety courses, career planning and psychological courses, etiquette courses, self-care courses and bridge approach courses,in order to have a new beginning in their senior high school life.&nbsp;High school freshmen,we believe in you and bless you!</span></p><p><span><br/></span></p><p><span>供稿：张鹏、张全用</span></p><p><span>翻译：许露丹、李韵祺、陈帅邑、崔馨月</span></p><p><span>翻译指导：孙雨辰</span></p><p><span><br/></span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-08-26 08:00:00+08', '2019-08-26 08:00:00+08', '2019-08-26 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (1017, 'Breaking“Ice”and Enjoying Cooperation —— International Center Amazing Race Team Building', '', 'In order to further deepen mutual understanding between Chinese and foreign teachers, and strengthen the tacit understanding and cohesion of the team, thus laying a solid foundation for the integratio...', '', '<p><span>In order to further deepen mutual understanding between Chinese and foreign teachers, and strengthen the tacit understanding and cohesion of the team, thus laying a solid foundation for the integration of the new semester courses, the International Education Center of Jinan Xinhang Experimental Foreign Language School organized Chinese and Foreign Teachers to take part in interesting league-building activities during the training of new teachers. The event is scheduled to start on the morning of August 22. A group of foreign teachers and secondary teachers who arrived early gathered in the conference room on the 21st for group discussions. The first meeting, we are a bit rusty, but after the team name, clothing, slogans and other details of the discussion, the team atmosphere gradually warm up, between the teachers of the &quot;ice-breaking action&quot; began.</span></p><p><a href="images/11ef8657a6734793bb531edf454c8c64.jpg" target="_blank"><img title="eb89f6c16efddb08b7c17e89c4c0d8a.jpg" src="/uploads/migration/images/11ef8657a6734793bb531edf454c8c64.jpg"/></a></p><p><span>On&nbsp;August the twenty second,all Chinese and foreign teachers arrived at destination on time.Besides, they were expectant and enthusiastic about the coming mysterious assignments. In this activity,Chinese and foreign teachers were divided into three teams.Each team need to get to activity site which is appointed.Then&nbsp;tasks will be allocated to every team and they should try their best to finish.Eventually,judges would select the wining team from&nbsp;total time and the quality of finishing this activity.&nbsp;</span></p><p><span>First of all, teachers came to Eastern&nbsp;Hospital of the Shandong Provincial Hospital by cars.&nbsp;According to the request which was on task cards,they should find specific department.Then,Chinese teachers were asked to teach foreign teachers a special Chinese sentences and make a video to prove that foreign teachers had learned it.After that,they went back to the assembling place and the winner is the team which spent the shortest time.Next activity site is Heng Long Shopping Mall.Every team should find imported food supermarket and bought specific food to bring it back to assembling place.The first team that had eaten&nbsp;entirely would win this game.What’s more,the final destination is Quan Cheng square.Each team was suggested looking for the symbolic construction of the square and taking a group photo.The winner was the team which posted the photograph earliest.After finishing the mission,all of the teachers had a dinner party to celebrate.Meanwhile,winning teams had got their prize.</span></p><p><a href="images/77ce500c31254d11bbef64180fbfb12d.jpg" target="_blank"><img title="462ae6eca36439f8dd35d0aa026e4cc.jpg" src="/uploads/migration/images/77ce500c31254d11bbef64180fbfb12d.jpg"/></a><a href="images/4c8ee287b2d24f0883d9279d4b51e22b.jpg" target="_blank"><img title="38060446f80acf07379ab29321b20d2.jpg" src="/uploads/migration/images/4c8ee287b2d24f0883d9279d4b51e22b.jpg"/></a></p><p><span>&nbsp;All the artful and joyful parts of the activity made teachers feel enjoyable. During the process, they helped each other to complete the tasks and their relationship became closer. That achieved the true meaning of this activity. At the same time, the foreign teachers knew more about Jinan. That would help their life become more convenient in the future. After the activity, teachers showed that this group work not only cultivated their ability of teamwork, but also made them acquire a deeper understanding of the importance of cooperation and experience the pleasure of teamwork. The teachers would teach students in accordance with what they had learned afterwards and mix the faculty, classes, education, management. That would make the goals of International education centre come true.</span></p><p><span><br/></span></p><p><span>供稿：李朝阳</span></p><p><span>翻译：于家豪、梁恩玮、张益明</span></p><p><span>翻译指导：孙雨辰</span></p><meta name="ContentEnd">', '', 'news_en', '', NULL, true, '2019-08-23 08:00:00+08', '2019-08-23 08:00:00+08', '2019-08-23 08:00:00+08', '', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (1018, '张杰', '', '张杰，北京化工大学博士研究生毕业，曾任职企业项目主管、副主任工程师，申请专利十余项，有丰富的项目研发和科学研究经验。2018年担任山东省实验中学西校区化学竞赛教练。现任新航实验高中化学教师、化学竞赛教练，2019-2020年度优秀员工。', '', '<p><a href="images/b1f76a1fd4514a8a9fbd824dd76a71be.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_b1f76a1fd4514a8a9fbd824dd76a71be.jpg" width="300" height="428"/></a></p><p><span></span></p><p><span>张杰，北京化工大学博士研究生毕业，曾任职企业项目主管、副主任工程师，申请专利十余项，有丰富的项目研发和科学研究经验。2018年担任山东省实验中学西校区化学竞赛教练。现任新航实验高中化学教师、化学竞赛教练，2019-2020年度优秀员工。</span></p><p><span></span><br/></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/b1f76a1fd4514a8a9fbd824dd76a71be.jpg', NULL, true, '2019-08-08 05:18:00+08', '2019-08-08 05:18:00+08', '2019-08-08 05:18:00+08', '王雪', '新航实验外国语学校', '张杰', '213321');
INSERT INTO public.news VALUES (1019, '李正华', '', '李正华，副校长、初中部校长，语文高级教师，山东省优秀教师，全国语文优质课大奖赛一等奖，济南市优秀班主任，济南中语会优秀语文教师。济南市首届“立德树人双领军教师”，完成省级教育课题《师生安全心理监护》省级课题《反串互动导学模式研究》结题。在省级、国家级期刊上发表论文十余篇。', '', '<p><a href="images/1ba94ecb85644b5baffa658126098687.jpg" target="_blank"></a><a href="images/4759aa3de95746e08c92749b92f02e4b.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_4759aa3de95746e08c92749b92f02e4b.jpg" width="300" height="428"/></a></p><p><span></span></p><p><span><span>李正华，副校长、初中部校长，</span>语文高级教师，山东省优秀教师，全国语文优质课大奖赛一等奖，济南市优秀班主任，济南中语会优秀语文教师。济南市首届“立德树人双领军教师”，完成省级教育课题《师生安全心理监护》省级课题《反串互动导学模式研究》结题。在省级、国家级期刊上发表论文十余篇。</span></p><p><span></span><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/1ba94ecb85644b5baffa658126098687.jpg', NULL, true, '2019-08-08 05:13:00+08', '2019-08-08 05:13:00+08', '2019-08-08 05:13:00+08', '赵昕晨', '新航实验外国语学校', '李正华', '213324');
INSERT INTO public.news VALUES (1020, '温爱平', '', '', '', '<p><a href="images/5ba0a22a1dad46a9af97d95b70946ba8.jpg" target="_blank"><img width="3454" height="5182" title="微信图片_20190626210257.jpg" src="/uploads/migration/images/5ba0a22a1dad46a9af97d95b70946ba8.jpg"/></a></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '济南新航实验外国语学校，山东省实验中学教育集团新航实验学校，新航', '');
INSERT INTO public.news VALUES (1021, '周冰', '', '周冰  毕业于北华大学外语学院，英语翻译硕士。已通过二级笔译，英语专业八级。2016-2018 从事英语翻译以及英语教学工作。', '', '<p><span><a href="images/df06ae504a5d42e9906a80e4b811729a.jpg" target="_blank"><img width="1050" height="1498" title="周冰照片.jpg" src="/uploads/migration/images/df06ae504a5d42e9906a80e4b811729a.jpg"/></a></span></p><p><span>周冰</span><span> &nbsp;</span><span>毕业于北华大学外语学院，英语翻译硕士。已通过二级笔译，英语专业八级。</span><span>2016-2018 </span><span>从事英语翻译以及英语教学工作。</span></p><p></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '周冰', '');
INSERT INTO public.news VALUES (1022, '刘懿', '', '刘懿   研究生毕业于山东师范大学学科教学（物理）专业，在校期间，多次荣获奖学金并获得教育实习优秀奖，优秀毕业论文等荣誉称号。', '', '<p><span><a href="images/4ea71cab93db49129147a69c83bd2353.jpg" target="_blank"><img width="425" height="590" title="刘懿照片.jpg" src="/uploads/migration/images/4ea71cab93db49129147a69c83bd2353.jpg"/></a></span></p><p><span>刘懿</span><span>&nbsp;&nbsp; </span><span>研究生毕业于山东师范大学学科教学（物理）专业，在校期间，多次荣获奖学金并获得教育实习优秀奖，优秀毕业论文等荣誉称号。</span></p><p></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '刘懿', '');
INSERT INTO public.news VALUES (1023, '刘晓敏', '', '刘晓敏，中共党员，毕业于济南大学政法学院，初中道德与法治教师，公开课曾获槐荫区一等奖。教学理念：做学生成长路上的心灵导师。', '', '<p><span><a href="images/177e1c1de33e4e81a411140d72c7373a.jpg" target="_blank"><img width="1788" height="2502" title="刘晓敏照片.jpg" src="/uploads/migration/images/177e1c1de33e4e81a411140d72c7373a.jpg"/></a></span></p><p><span>刘晓敏，中共党员，毕业于济南大学政法学院，初中道德与法治教师，公开课曾获槐荫区一等奖。教学理念：做学生成长路上的心灵导师。</span></p><p></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '刘晓敏', '');
INSERT INTO public.news VALUES (1024, '易思颖', '', '易思颖，江苏师范大学毕业，中共党员，生物学教育硕士，二级教师。在任教期间，荣获槐荫区新苗展示课第一名、复习课优质课第一名等荣誉称号。', '', '<p><span><a href="images/d7f1fbf9887841ff8fad9bfd466d3f79.jpg" target="_blank"><img width="426" height="592" title="易思颖照片.jpg" src="/uploads/migration/images/d7f1fbf9887841ff8fad9bfd466d3f79.jpg"/></a></span></p><p><span>易思颖，江苏师范大学毕业，中共党员，生物学教育硕士，二级教师。在任教期间，荣获槐荫区新苗展示课第一名、复习课优质课第一名等荣誉称号。</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '易思颖', '');
INSERT INTO public.news VALUES (1025, '崔佩佩', '', '崔佩佩，女，硕士学历，毕业于南开大学化学生物学专业，二级教师。怀着对生命的热爱从药品研发转身投入到教育事业中，学科理论知识扎实，教学风格鲜明。从教以来，多次荣获“教学成绩突出奖”“教学质量先讲个人”。教育感言：用不含敌意的坚决与不带诱惑的深情，与每个孩子建立最有力最温暖的连接，让每个生命都精彩绽放。 ', '', '<p><span><a href="images/badad216e76042b795b9a12c774d1aba.jpg" target="_blank"><img width="1042" height="1279" title="崔佩佩照片.jpg" src="/uploads/migration/images/badad216e76042b795b9a12c774d1aba.jpg"/></a></span></p><p><span>崔佩佩，女，硕士学历，毕业于南开大学化学生物学专业，二级教师。怀着对生命的热爱从药品研发转身投入到教育事业中，学科理论知识扎实，教学风格鲜明。从教以来，多次荣获“教学成绩突出奖”“教学质量先讲个人”。教育感言：用不含敌意的坚决与不带诱惑的深情，与每个孩子建立最有力最温暖的连接，让每个生命都精彩绽放。</span></p><p>&nbsp;</p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '2019-08-07 08:00:00+08', '王雪', '新航实验外国语学校', '崔佩佩', '');
INSERT INTO public.news VALUES (1026, '姚明霞', '', '       姚明霞，生物高级教师 ，毕业于山东师范大学生物系，大学本科学历，担任组长，备课组长工作30余年。山东师范大学进修研究生课程。曾经获得：全国教学设计比赛二等奖、山东省教学能手、山东省优质课比赛一等奖、山东省生物学科奥林匹克优秀辅导员一等奖等。主要作品：《走进生物——生物新教材》山东教育出版社、《高考闯关》山东教育出版社、《高考3+x指导教程》等。', '', '<p><span>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/4594d91a750f4602b77db8e710e97acf.jpg" target="_blank"><img title="姚明霞标准照.jpg" src="/uploads/migration/images/4594d91a750f4602b77db8e710e97acf.jpg" width="223" height="320"/></a></span></p><p><span>姚明霞，生物高级教师 ，毕业于山东师范大学生物系，大学本科学历，担任组长，备课组长工作30余年。山东师范大学进修研究生课程。曾经获得：全国教学设计比赛二等奖、山东省教学能手、山东省优质课比赛一等奖、山东省生物学科奥林匹克优秀辅导员一等奖等。主要作品：《走进生物——生物新教材》山东教育出版社、《高考闯关》山东教育出版社、《高考3+x指导教程》等。</span></p><meta name="ContentStart"/>', '', 'teachers', '', NULL, true, '2019-07-29 23:57:00+08', '2019-07-29 23:57:00+08', '2019-07-29 23:57:00+08', '王雪', '新航实验外国语学校', '姚明霞', '213329');
INSERT INTO public.news VALUES (1027, '刘沂珍', '', '       刘沂珍，山东省特级教师、正高级教师（四级）。济南市政协常委、济南市学科带头人，化学教研组组长。曾获市级教学能手、省级优质课一等奖、国家、省级化学学科竞赛优秀辅导员、“双百工程”骨干教师。三十年如一日地奋斗耕耘在教学一线，积累了丰富的教学经验，精湛的教学艺术、坚实的教育教学功底、优异的教学成绩赢得了广大师生的一致称赞，所带过的班级，班风正、学风浓，尖子学生多、高考升学率高，因而年年都被...', '', '<p><span>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/ff0eac91443b48cd83156dccba115ec0.jpg" target="_blank"><img title="刘沂珍标准照.jpg" src="/uploads/migration/images/ff0eac91443b48cd83156dccba115ec0.jpg" width="226" height="314"/></a></span></p><p><span>刘沂珍，山东省特级教师、正高级教师（四级）。济南市政协常委、济南市学科带头人，化学教研组组长。曾获市级教学能手、省级优质课一等奖、国家、省级化学学科竞赛优秀辅导员、“双百工程”骨干教师。三十年如一日地奋斗耕耘在教学一线，积累了丰富的教学经验，精湛的教学艺术、坚实的教育教学功底、优异的教学成绩赢得了广大师生的一致称赞，所带过的班级，班风正、学风浓，尖子学生多、高考升学率高，因而年年都被学校评为“先进班集体”，刘沂珍老师也年年被学校评为“先进班主任”，近年来共发表教学研究论文十余篇，编写教学用书多部。</span></p><meta name="ContentStart"/>', '', 'teachers', '', NULL, true, '2019-07-29 23:56:00+08', '2019-07-29 23:56:00+08', '2019-07-29 23:56:00+08', '王雪', '新航实验外国语学校', '刘沂', '213330');
INSERT INTO public.news VALUES (1028, '杨育红', '', '        杨育红，山东省正高级数学教师，曾获山东省特级教师、省首届十佳创新班主任、省优秀共产党员、济南名师、泉城第二届巾帼十佳等荣誉称号。从教三十多年，为国家培养了一批又一批优秀人才，坚持赏识教育，面对不同类型的学生，牢固坚持人本主义的教育理念，让每一位学生时时沐浴在爱的阳光下，从而获得最适合自己的成长机会，实现最优化的发展结果。以理性导引学生的个性、以宽容对待学生的不足。杨育红老师为班主任...', '', '<p><span><a href="images/fe8d469948af4b49bc79816872181dc6.jpg" target="_blank"><img title="" src="/uploads/migration/images/s_fe8d469948af4b49bc79816872181dc6.jpg" width="300" height="428"/></a>&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p><p><span>杨育红，山东省正高级数学教师，曾获山东省特级教师、省首届十佳创新班主任、省优秀共产党员、济南名师、泉城第二届巾帼十佳等荣誉称号。</span></p><p><span>从教三十多年，为国家培养了一批又一批优秀人才，坚持赏识教育，面对不同类型的学生，牢固坚持人本主义的教育理念，让每一位学生时时沐浴在爱的阳光下，从而获得最适合自己的成长机会，实现最优化的发展结果。</span></p><p><span>以理性导引学生的个性、以宽容对待学生的不足。杨育红老师为班主任工作赋予了一个全新的角色——“学生成长规划师”，她清醒地认识到，教师的职责不是打磨其性格棱角，不是为其限定标准成长模式，而是以学生的个性智慧类型为依据、以个人的兴趣理想为指导、以扎实的行动为基石，引导学生在认清自己、扬长避短的前提下，固守自己的天空，开拓自己的领地，掌舵自己的航船。</span></p><p><span>一丝不苟搞教研、超越平凡课堂，在课堂上让每个学生既体会到本学科的科学严谨性，又感受到科学的通俗性、趣味性，真正让学生充满激情、愉快地学习数学。她将一个个复杂问题简单化，简单问题道理化，通过深入浅出、幽默的讲解，给学生留下深刻的印象。</span></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/fe8d469948af4b49bc79816872181dc6.jpg', NULL, true, '2019-07-29 23:54:00+08', '2019-07-29 23:54:00+08', '2019-07-29 23:54:00+08', '赵昕晨', '新航实验外国语学校', '杨育红', '213331');
INSERT INTO public.news VALUES (1029, '吕秀亭', '', '吕秀亭，教学副校长，山东省实验中学物理高级教师，现任2017级级部副主任。自参加工作以来已有19年的班主任工作经历。担任物理组备课组长, 担任2012级、2014级、2017级级部副主任，担任2009级物理奥赛教练员暨学科特长班班主任。 曾获山东省第三届中学物理教学改革创新大赛获一等奖、山东省第13届高中物理优质课一等奖第一名、中国教育学会华东六省一市物理教学专业委员会优质课评比一等奖、第八届全国...', '', '<p><span><a href="images/4a13b34c030740dd84d9f0260ecfb029.jpg" target="_blank"><img title="吕秀亭标准照.jpg" src="/uploads/migration/images/4a13b34c030740dd84d9f0260ecfb029.jpg" width="260" height="358"/></a></span></p><p><span>吕秀亭，教学副校长，山东省实验中学物理高级教师，现任2017级级部副主任。自参加工作以来已有19年的班主任工作经历。担任物理组备课组长, 担任2012级、2014级、2017级级部副主任，担任2009级物理奥赛教练员暨学科特长班班主任。 曾获山东省第三届中学物理教学改革创新大赛获一等奖、山东省第13届高中物理优质课一等奖第一名、中国教育学会华东六省一市物理教学专业委员会优质课评比一等奖、第八届全国中学物理教学改革创新大赛一等奖、济南市优秀班主任、省级物理竞赛优秀指导教师等。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '', NULL, true, '2019-07-29 23:52:00+08', '2019-07-29 23:52:00+08', '2019-07-29 23:52:00+08', '王雪', '新航实验外国语学校', '吕秀亭', '213332');
INSERT INTO public.news VALUES (1030, '张术磊', '', '张术磊，新航实验党总支副书记，行政副校长，原山东省实验中学组织人事科科长，语文高级教师，山东省骨干教师，山东师范大学首届教育硕士毕业，任山东省实验中学语文教师、教研组长、年级组长、班主任20余年;曾荣获济南市政府三等功、济南市优质课一等奖、济南市语文教师素质大赛一等奖等荣誉奖励，多次被评为优秀党员、先进工作者。 ', '', '<p><span><a href="images/5e96a72bc1d34469a926157a7426b3d5.jpg" target="_blank"><img title="张术磊标准照.jpg" src="/uploads/migration/images/5e96a72bc1d34469a926157a7426b3d5.jpg" width="258" height="350"/></a></span></p><p><span><span>张术磊，新航实验党总支副书记，</span><span>行政副校长，原山东省实验中学组织人事科科长，语文高级教师，山东省骨干教师，山东师范大学首届教育硕士毕业，任山东省实验中学语文教师、教研组长、年级组长、班主任20余年;曾荣获济南市政府三等功、济南市优质课一等奖、济南市语文教师素质大赛一等奖等荣誉奖励，多次被评为优秀党员、先进工作者。</span></span></p><p>&nbsp;</p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '', NULL, true, '2019-07-29 23:49:00+08', '2019-07-29 23:49:00+08', '2019-07-29 23:49:00+08', '王雪', '新航实验外国语学校', '张术磊', '213334');
INSERT INTO public.news VALUES (1044, '【媒体聚焦】让每个学生有主动发展的无限空间', '', '实验学子在操场上举行2019届高三毕业典礼 新时报记者黄中明 摄师资力量强大让每个学生受益       随着2019年高校自主招生落幕，山东省实验中学再获佳绩，在今年自招全面收紧的背景下，该校共有266人次通过自招初审。其中11人次获得清华大学和北京大学的保送或降分资格，在省内排名首位。成绩背后，得益于学校拔尖人才的培养机制和强大的名师团队。　　强大的师资力量是学校发展的生命线，在省实验中学，名师...', '', '<p><br/></p><p><a href="images/151830dfd79c49898ec2d0e5a7926251.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/151830dfd79c49898ec2d0e5a7926251.jpg"/></a></p><p><br/></p><p><a href="images/aec4559ea43347d39fc136b6168676a1.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/aec4559ea43347d39fc136b6168676a1.jpg"/></a></p><p><span>实验学子在操场上举行2019届高三毕业典礼 新时报记者黄中明 摄</span></p><p><span>师资力量强大让每个学生受益</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;随着2019年高校自主招生落幕，山东省实验中学再获佳绩，在今年自招全面收紧的背景下，该校共有266人次通过自招初审。其中11人次获得清华大学和北京大学的保送或降分资格，在省内排名首位。成绩背后，得益于学校拔尖人才的培养机制和强大的名师团队。</span></p><p><span>　　强大的师资力量是学校发展的生命线，在省实验中学，名师如同繁星，点亮着每个学生。截至目前，该校享受国务院津贴专家1人、特级教师17人、全国优秀教师2人、山东省教育创新人物3人，齐鲁名校长、齐鲁名师5人，省市级教学能手22人、济南市专业技术拔尖人才6人……一流的教师队伍为打造优质教育提供了强大的支撑。</span></p><p><span>　　作业改革、命题研究、集体备课、课程提升，学校对教学的关键问题进行专项突破，引导全体教师研究教学规律、提高教学质量，促进教师的全方位提升，最终受益的是每名学子。</span></p><p><span>课程设置多样每个学生都能找到个性“课表”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;如果说自招比拼的是学生专业知识的深度,那综合评价招生的侧重点则是学生的综合素养，得益于省实验中学的课程体系和多元化人才培养模式，越来越多的实验学子在综招中崭露头角，在2019年的综招中，省实验中学共有720人次通过初审，人数在省内遥遥领先。</span></p><p><span>　　学校不仅有丰富的社团活动、校本课程、专家教授进校园活动，还有科技节、体育节、艺术节、读书节、电影节等特色活动。国家课程、德育课程、选修课程、国际课程、综合实践课程……每个实验学子都能找到适合自己成长的个性“课表”。</span></p><p><span>　　山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊表示，作为山东省首批省级重点学校、省级规范化学校，省实验中学一切从发现学生的兴趣、尊重学生的选择、培养学生的特长出发，构建了独特完整的课程体系。在新高考要求下实行的“选课走班”，省实验中学进行了科学合理安排，确保每个学生都能选到适合的学科组合。</span></p><p><span>　　山大创新班、中科大创新班、中美课程班、航空班……省实验中学加强与高校教育资源的接轨，成为多所知名高校的优秀生源基地，国际班毕业生均被国外知名大学录取，航空班毕业生成绩优秀，省实验全面培养了一批批优秀学子。</span></p><p><span>“实验精神”传承让实验学子念念不忘</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为最早肩负“进行中学教育工作中的实验与改革”使命的山东省实验中学，学校的“实验精神”令很多“老学生”念念不忘。</span></p><p><span>　　1956年在部分济南学校更改校名的情况下，山东省实验中学被要求保留原校名，理由是一座城市教育的发展需要有学校能承担起“创造经验，推动一般”的实验性、示范性的使命，省实验无疑承载了外界对其教学理念和改革先行的期待。</span></p><p><span>　　济南家长姚建27年前从省实验中学毕业，今年他的孩子考入了省实验中学旗下的济南新航实验外国语学校。他回忆道，上高中时语文老师就让他们自导自演话剧《雷雨》。他笑称，家里总调侃他有实验情结，但他从不否认母校在心里的位置。“学校鼓励我们综合发展，又有教学经验丰富、认真负责的老师，再加上学习氛围浓厚，所以实验的孩子虽然看起来玩的时间多，但学习成绩也很好，这些年实验精神一直影响着自己，确实有着不可磨灭的精神力量。”</span></p><p><br/></p><p><span>新时报记者&nbsp; 柴颖颖</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '发展 主动 学生 无限 聚焦', '');
INSERT INTO public.news VALUES (1031, '张爱梅', '', '       张爱梅，原山东省实验中学国际部主任，英语高级教师，市英语中心组成员，2011年创办省实验国际部;山东省英语优质课一等奖,济南市优质课一等奖，济南市优秀班主任，济南市教育系统先进个人，三次济南市教育教学三等功、全国英语竞赛优秀指导教师等荣誉奖励，发表出版著作多部。', '', '<p><span>&nbsp; &nbsp; &nbsp; &nbsp;<a href="images/a5a369242d9949e8a60a2d2122ec5e05.jpeg" target="_blank"><img title="" src="/uploads/migration/images/s_a5a369242d9949e8a60a2d2122ec5e05.jpeg" width="378" height="540"/></a></span></p><p><span>张爱梅，原山东省实验中学国际部主任，英语高级教师，市英语中心组成员，2011年创办省实验国际部;山东省英语优质课一等奖,济南市优质课一等奖，济南市优秀班主任，济南市教育系统先进个人，三次济南市教育教学三等功、全国英语竞赛优秀指导教师等荣誉奖励，发表出版著作多部。</span></p><p><br/></p><meta name="ContentStart"/>', '', 'teachers', '/uploads/migration/images/a5a369242d9949e8a60a2d2122ec5e05.jpeg', NULL, true, '2019-07-29 23:48:00+08', '2019-07-29 23:48:00+08', '2019-07-29 23:48:00+08', '王雪', '新航实验外国语学校', '张爱梅', '213335');
INSERT INTO public.news VALUES (1032, '济南新航实验外国语学校——让每个生命都精彩绽放', '', '作为山东省实验中学教育集团的新成员济南新航实验外国语学校是一所怎样的学校呢？下面，就一起来看看吧！       济南新航实验外国语学校是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所12年一贯制民办非营利学校。1.同根同源的实验文化       济南新航实验外国语学校与山东省实验中学一脉相承、资源共享，是名副其实的“实验+”。山东省实验中学全面负责新航实验外国语学校的教育教学工作，校...', '', '<p><br/></p><p><a href="images/f23e146bc1264aa3b1ae9c52493ff28c.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/f23e146bc1264aa3b1ae9c52493ff28c.jpg"/></a></p><p><span>作为山东省实验中学教育集团的新成员</span></p><p><span>济南新航实验外国语学校是一所怎样的学校呢？</span></p><p><span>下面，就一起来看看吧！</span></p><p><br/></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;济南新航实验外国语学校是山东省实验中学教育集团与山东出版集团强强联合、精心打造的一所12年一贯制民办非营利学校。</span></p><p><span><br/></span></p><p><span>1.同根同源的实验文化</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;济南新航实验外国语学校与山东省实验中学一脉相承、资源共享，是名副其实的“实验+”。山东省实验中学全面负责新航实验外国语学校的教育教学工作，校长、优秀管理团队及骨干教师皆由山东省实验中学教育集团统一调配。秉承山东省实验中学先进的办学理念，在融合中传承、创新、发展，打造一所高起点、高品位、高质量的多元化创新型学校。</span></p><p><br/></p><p><span>2.全人教育的办学理念</span></p><p><span>学校遵从“让每个生命都精彩绽放”的教育理念，以创建促进学生全面而有个性发展、具有国际视野的特色课程体系作为保障，努力创办“高境界、高品质，能够影响学生终生发展的教育”，旨在培养尚德求思、卓越笃行、面向未来的社会精英。从而使学生成为关注生命真谛与未来人类世界发展的探索者，具备融合思维、创新思维、正向思维的思考者，具有厚重学识和执行能力的创造者。<br/></span></p><p><br/></p><p><span>3.素质过硬的教师团队</span></p><p><span>山东省实验中学教育集团统一调配校长、管理团队及骨干教师，强力聚合成一支理念先进、素质过硬、梯度合宜的教师队伍。在第一年的师资团队中，已有荣誉等身的特级教师、正高级教师和硕士研究生导师，有荣获全国、省、市优质课一等奖的中青年骨干教师及教学能手，有43位教师获得博士、硕士学位，还有来自美国、英国、加拿大、澳大利亚等国家的外籍教师11人。绝大多数非英语学科教师的英语水平达到六级。学校着力通过名师引领、系统培训、同伴互助等方式大力推进教师团队的专业化建设。<br/></span></p><p><br/></p><p><span>4.凸显个性的小班教学</span></p><p><span>学校实行小学、初中、高中全学段小班化教学，每班班额不超过30人。充分尊重每个学生的独特性，采取个性化辅导的顾问制度，为每一位学生配备学术顾问老师、生活顾问老师和升学顾问老师，学生在这里接受到的是独一无二、量身定制的教育。<br/></span></p><p><br/></p><p><span>5.以生为本的课程体系</span></p><p><span>基于山东省实验中学课程体系，立足学生发展的三大核心领域：思维训练、能力培养、人格塑造，通过师师之间、师生之间、生生之间的合作创课过程，构建以国家课程为核心的面向未来精英人才培养的个性化“课程+”体系。国家课程坚持基础与拓展相结合，实现国家课程的校本化，满足学生的未来升学需求；校本课程坚持科学素养与人文精神相结合，满足学生的特长发展与综合素质提升。<br/></span></p><p><br/></p><p><span>6.追求卓越的“苗圃计划”</span></p><p><span>针对智力超常、创新潜质突出、适应快节奏学习的学生，学校专门制定卓越人才培养项目——“苗圃计划”，该项目采用“分流培养、滚动升级”等培养机制，由山东省实验中学奥赛辅导教练及毕业于清华大学、中国科学院大学、中国科技大学、南开大学、山东大学等国内著名高校的教师组成专家团队，旨在培养高中毕业能考取双一流大学，未来能够成为某一学科、某一领域内卓越人才乃至领军人物。<br/></span></p><p><br/></p><p><span>7.放眼世界的国际教育</span></p><p><span>学校积极探索现代化、科技化、国际化的融合办学模式。在中英文双语教学的基础上，通过法语、西班牙语等第二语言学习以及模拟联合国、传统文化和跨文化对比项目学习，加强学生跨文化教育，培养国际通用型人才；通过戏剧表演、辩论、专项历史题材阅读与写作、STEAM课程等课程和项目，培养学生的创新思维能力和跨学科整合能力；通过项目式学习、合作式学习、探究式学习，培养学生的团队合作能力、独立研究能力；通过爱丁堡公爵奖项目计划，培养具有全球视野与全球资源整合能力、人文关怀与社会担当的卓越人才。<br/></span></p><p><br/></p><p><span>8.高端先进的办学条件</span></p><p><span>学校坐落于凤凰山南麓，紧邻济南交通大动脉经十东路，环境优美，交通便利。总规划用地面积220亩，以绿色、艺术与科技为设计建造主题，建有游泳馆、羽毛球场、网球场、篮排球场、乒乓球馆、健身房等特色体育场馆；配有独立学科教室、数字图书馆、科技馆、专业实验室、黑匣子剧场等高科技学习场馆；利用智慧教育平台系统，全面推进智慧校园建设，让人工智能助力学校发展；学校专属的“自然营地”，让自然探索课程与学生生活融为一体，真正打造一个安全、稳定、环保、节能的花园式校园。<br/></span></p><p><br/></p><p><span>咨询电话：0531—59516617、0531—59516621</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'news', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '新航实验外国语学校', '');
INSERT INTO public.news VALUES (1033, '梦想启航！新航实验外国语学校举行2019年校园开放日活动', '', '       为向广大考生和家长了解省实验中学的办学理念和成果，6月30日，山东省实验中学各个校区同时举办校园开放日活动。其中，作为山东省实验中学教育集团今年新增的成员校，济南新航实验外国语学校在山东省实验中学中心校区参加了当天的校园开放日活动，为了让更多初中学生和家长近距离看到这所新学校的面貌，组织工作人员陪同讲解，先后有数百位考生和家长前往校园内实地查看。       早上九点多，烈日炎炎，在...', '', '<p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;为向广大考生和家长了解省实验中学的办学理念和成果，6月30日，山东省实验中学各个校区同时举办校园开放日活动。其中，作为山东省实验中学教育集团今年新增的成员校，济南新航实验外国语学校在山东省实验中学中心校区参加了当天的校园开放日活动，为了让更多初中学生和家长近距离看到这所新学校的面貌，组织工作人员陪同讲解，先后有数百位考生和家长前往校园内实地查看。</span></p><p><a href="images/53ac8cd81bd74f618aa3c5ca89728fc1.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/53ac8cd81bd74f618aa3c5ca89728fc1.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;早上九点多，烈日炎炎，在新航实验外国语学校的咨询台前，还是吸引了不少学生和家长前来，热切的咨询着具体的报名事项。“听说省实验中学今年新开了一所民办学校，正式恢复初中招生，我专门带孩子过来看看能不能报上名。”“从初中到高中，真正的六年一贯制培养，对孩子来说确实是个好事！”对于今年九月即将开学的济南新航实验外国语学校，家长们充满了期待。</span></p><p><a href="images/bc31203e49934d2db5dcb8d3ca3552e4.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/bc31203e49934d2db5dcb8d3ca3552e4.jpg"/></a><a href="images/92de80da7dcb401cb151e73a4a43fe83.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/92de80da7dcb401cb151e73a4a43fe83.jpg"/></a><a href="images/27684d7c8cc542d08fa60165cf137bed.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/27684d7c8cc542d08fa60165cf137bed.jpg"/></a><a href="images/f380af32ef2c40aca4f890e33875f04f.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/f380af32ef2c40aca4f890e33875f04f.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;尽管高中部报名已经截止，但在活动现场的咨询台前，还是有不少慕名而来的小学毕业生在家长的陪同下专程赶来。咨询台前，多名骨干教师组成的咨询员队伍，围绕学校教学特色、建设进展、学习生活等方面的问题，耐心细致地向考生和家长们一一解答。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;新航美图最新出炉，快来看</span></p><p><a href="images/f7f4471e9e434793a5c015c9d1eb5eea.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/f7f4471e9e434793a5c015c9d1eb5eea.jpg"/></a><a href="images/a395aa90fc774615a681e0cf80a470f5.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/a395aa90fc774615a681e0cf80a470f5.jpg"/></a><a href="images/30f8800c3f694b4d9f3fc24882fc2eaa.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/30f8800c3f694b4d9f3fc24882fc2eaa.jpg"/></a></p><p><span>初中部启动报名，截止日期为7月5日</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为山东省实验中学教育集团和山东出版集团合力打造的重点项目，济南新航实验外国语学校是名副其实的“实验+”，目前，教学楼、宿舍楼、办公楼等建筑都已基本装修完毕，六月竣工验收后，所有教学设备、家具等物品将在7月底前调试完毕，对于学生和家长来说，新航实验已经做好了准备。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;根据招生进度安排，济南新航实验外国语学校初中部今年采取自主招生方式招收120名首届新生，主要面向济南市七区（市中、历下、槐荫、天桥、历城、高新和南山)内具有学籍的2019年应届小学毕业生，思想品德优秀，身体健康，均可申请报名。6月30日8:30-7月5日17:00期间，考生可登录山东省实验中学教育集团官方网站（/）进行网上申请。网上申请成功后，请于7月4日-6日（8:30—17:00），带齐报名材料到省实验中学中心校区（济南市经七路73号）实验科苑二层多媒体教室（济南新航实验外国语学校初中部招生报名处）现场报名。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;需要准备的报名材料包括：（1）学籍号，共19位，例如 2013370102002010456，可以联系学校班主任获取。（2）考生个人简介一份，要求学生用方格稿纸书写，400字以内。（3）户口本及身份证复印件，户口本索引页、父母页以及考生页复印在一张A4纸（可正反面），身份证正反面复印到一张A4纸。（4）能体现考生特长及能力的证明材料（荣誉证书需是2016.1—2019.7期间获得，查原件，留复印件），最多五件。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;学校招生中心将根据学校育人目标和办学特色对上报的材料进行初审。7月9日8:00—17:00，考生可登录省实验中学教育集团官网查询初审结果。7月13日，省实验中学教育集团官网将公布预录名单。7月16日8：00，组织录取新生办理缴费、量制校服、领取《入学通知书》等入学手续。招生咨询电话：0531—86926756、0531—86924355。</span></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '外国语 学校 实验 举行 校园', '');
INSERT INTO public.news VALUES (1034, '新航实验新生看过来！领航夏令营来了！', '', '2019年领航夏令营暨高一新生家长见面会       为了给首届新航实验学子提供接触科学前沿、体验大师风采、提升学科素养的机会，济南新航实验外国语学校将于2019年7月13日—14日，在山东省实验中学中心校区举行新航实验2019年领航夏令营暨新生家长见面会。2019级新生将通过此次活动走进实验校园、走近实验中学以及新航实验名师、与清华大学教授面对面，开拓视野、增长见识，为即将到来的高中学习和生活做...', '', '<p><br/></p><p><span>2019年领航夏令营暨高一新生家长见面会</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;为了给首届新航实验学子提供接触科学前沿、体验大师风采、提升学科素养的机会，济南新航实验外国语学校将于2019年7月13日—14日，在山东省实验中学中心校区举行新航实验2019年领航夏令营暨新生家长见面会。2019级新生将通过此次活动走进实验校园、走近实验中学以及新航实验名师、与清华大学教授面对面，开拓视野、增长见识，为即将到来的高中学习和生活做足准备。</span></p><p><span>一、时间安排</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;7月13日-14日</span></p><p><span>二、参加人员</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;济南新航实验外国语学校</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;高中部2019级新生及家长</span></p><p><span>三、课程安排</span></p><p><a href="images/b5347051f6e746c19eda8458887ffe9f.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/b5347051f6e746c19eda8458887ffe9f.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为首届新航实验学子在学校的第一次集体活动，领航夏令营对每一位学生来说都是难得的人生经历。期间不仅能帮助学生们在短时间内熟悉同伴，建立信任，培养合作意识，而且学校还将派出阵容豪华的名师团队，为同学们介绍高中学习的特点和整体规划。使同学们在亲身感受实验历史和新航实验文化的同时，快速准确寻找到自己的定位，树立目标，为即将到来的高中生涯做好长足的打算与充分的准备，走好自己的成长成才之路。</span></p><p><span>山东省实验中学教育集团</span></p><p><span>济南新航实验外国语学校</span></p><p><span>2019年7月9日</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '新生 实验 领航 看过 夏令营', '');
INSERT INTO public.news VALUES (1035, '领航营开营！首批新航学子迎来高中第一课', '', '       13日上午，济南新航实验外国语学校首届领航夏令营活动在山东省实验中学中心校区拉开帷幕。早上七点多，距离活动正式开始还有一个多小时，学生们陆续赶来。换上统一的营员服、佩戴上新航胸章，每个学生都精神抖擞的迎来高中第一课。       作为首届新航学子在学校参加的第一次集体活动，领航营对于每一个学生来说都是一次难得的人生经历。开营伊始，原山东省实验中学国际部主任、济南新航实验外国语学校副校...', '', '<p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;13日上午，济南新航实验外国语学校首届领航夏令营活动在山东省实验中学中心校区拉开帷幕。早上七点多，距离活动正式开始还有一个多小时，学生们陆续赶来。换上统一的营员服、佩戴上新航胸章，每个学生都精神抖擞的迎来高中第一课。</span></p><p><a href="images/fa15d6ff715e42798ae04bc9d085d11e.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/fa15d6ff715e42798ae04bc9d085d11e.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为首届新航学子在学校参加的第一次集体活动，领航营对于每一个学生来说都是一次难得的人生经历。开营伊始，原山东省实验中学国际部主任、济南新航实验外国语学校副校长张爱梅代表学校致欢迎辞，“心怀梦想，扬帆起航，风景这边独好，新航实验将成为你们梦想起航的地方，我们定将不忘初心，不负众望，为每位新航学子的追梦之路保驾护航。”</span></p><p><a href="images/bf8d800a79de40cca6a7eb192267ec6c.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/bf8d800a79de40cca6a7eb192267ec6c.jpg"/></a><a href="images/5284b99f5dc64685a3e6f3186f4227b2.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/5284b99f5dc64685a3e6f3186f4227b2.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在简短的开营仪式后，活动正式开始，营员们首先进行自我介绍，每一位同学主动站起来和“小伙伴们”打招呼，学生们很快就熟悉起来。</span></p><p><a href="images/fd077689d91c4902a4c249b5eb4625ad.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/fd077689d91c4902a4c249b5eb4625ad.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“看到你们这些年轻面孔，感谢你们的父母，感谢你们的初中母校，感谢你自己，你们是优秀的，也是勇敢的，成为新航实验的第一届高中学生。我们优秀的师资团队，将为每一个学生都提供个性化、精准化的指导。”山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊对学生们嘱咐道。</span></p><p><a href="images/eb2f57e457884b1cb1fd754f8189a76e.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/eb2f57e457884b1cb1fd754f8189a76e.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;随后，山东省实验中学英语教研组组长宋武栋为到场学生带来英语学法指导，他的妙语连珠赢得了学生们的积极响应。</span></p><p><a href="images/40f64dfc6f92416abf985d92012bc8be.jpg" target="_blank"><img title="640.webp (5).jpg" src="/uploads/migration/images/40f64dfc6f92416abf985d92012bc8be.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;紧接着，由来自清华大学建筑学院的韩孟臻教授给到场营员们带来一场主题为《清华建筑》的主题讲座。实际上，韩孟臻教授还有一个身份---山东省实验中学毕业生。他当年的班主任张术磊老师，如今也多了一重身份:济南新航实验外国语学校副校长，“希望你们每一位同学都能像韩孟臻学长一样，成长成才。”</span></p><p><a href="images/40317205370a4ccda4b2aa72cee8dabb.jpg" target="_blank"><img title="640.webp (6).jpg" src="/uploads/migration/images/40317205370a4ccda4b2aa72cee8dabb.jpg"/></a><a href="images/8d5a9bce539b4ef29acba928618b0e89.jpg" target="_blank"><img title="640.webp (7).jpg" src="/uploads/migration/images/8d5a9bce539b4ef29acba928618b0e89.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;午餐后，营员们在学长学姐的带领下，分批走进山东省实验中学校史馆，实地触摸省实验历史。</span></p><p><a href="images/9ae8ffd4931a41a5ab72bf35ef6d4755.jpg" target="_blank"><img title="640.webp (8).jpg" src="/uploads/migration/images/9ae8ffd4931a41a5ab72bf35ef6d4755.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;下午两点开始，活动继续进行，首先是山东省实验中学教导处副主任、济南新航实验外国语学校教学管理中心主任王飞给普通班学生解读了山东新高考政策，以及新航实验外国语学校新高考政策下的课程建设。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;与此同时，融合班学生在另一个会场内，聆听了张爱梅副校长带来的融合班高中生涯规划指导讲座。</span></p><p><a href="images/6b96516439ed44668a7b07e5b97af0d5.jpg" target="_blank"><img title="640.webp (9).jpg" src="/uploads/migration/images/6b96516439ed44668a7b07e5b97af0d5.jpg"/></a><a href="images/34b55fdad0d84a8eae81cc31372fdcea.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/34b55fdad0d84a8eae81cc31372fdcea.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;随后，山东省实验中学教导处副主任于莉、山东省实验中学教导处主任丁兆华分别为学生带来《高中生涯规划指导》、《拔尖创新人才培养模式》。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;白天的活动结束后，来自济南市外的省招生们在老师的带领下，来到百花洲，亲身感受老济南街区的魅力。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;尽管此次领航营活动只有短短两天时间，学校为学生们安排了丰富的讲座和学习。期间，不仅帮助学生在短时间内熟悉同伴，建立信任，培养起合作意识，而且学校还派出阵容豪华的名师团队，为同学们介绍高中学习生涯一个整体规划。</span></p><p><a href="images/c41b935ccd444ad1a42a50a148802969.jpg" target="_blank"><img title="640.webp (12).jpg" src="/uploads/migration/images/c41b935ccd444ad1a42a50a148802969.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;学生们在亲身感受到实验历史和新航实验文化的同时，快速找到了自己的定位，树立起目标，为即将到来的高中生活做好长足打算和准备。</span></p><p><span>学生感悟</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;从上了初中开始，来实验上学就是我那三年的终极目标，可是，当我真正有机会在这样一个环境中，在各个经验丰富的老师门下学习时，我还是情不自禁地怀疑:我是否有能力有资格在这样的环境中学习。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;但各位老师、校长、主任的讲话，让我明白无论之前有多大的成功，之前有多大的失误，来到新航就是一个新的起点，一个高中生活的新起点。英语老师宋老师在讲座中提到，在高中，就算你全力以赴，也会很吃力。这样的一番话，比我以往了解到的高中生活的艰苦要更通俗。他为我描绘了一幅英语学习的新蓝图。自主学习，阅读和掌握应试技巧，都在高中里必须、一定、无条件的做到。高中的学习过程，不再是零散的学习，它的三年时间里，每一分每一秒都格外的重要，一不小心就有可能被其他同学超越，所以要不断刺激自己努力、努力！</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;韩教授的讲座也让我感悟颇深。一定要逼自己进一个好大学，韩教授所讲的，并不仅仅是清华建筑学院的厉害，还有清华大学优秀的文化教育。优良的环境，大咖级别的老师，只有进入了像这样优秀的学校，才能让自己更优秀，让自己的生活更快乐！</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;今后，我将以新航的校训---“日新博学，志航天下”为座右铭，在新航的三年中努力拼搏，为自己打造一个更好的未来。</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ——首届新航学子&nbsp; 相博文</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '新航 学子 首批 迎来 开营', '');
INSERT INTO public.news VALUES (1036, '省实验多学科大咖做学法指导，首届领航营落幕', '', '       14日，济南新航实验外国语学校首届领航夏令营暨首届家长见面会活动在山东省实验中学中心校区落下帷幕，首先，由省实验中学校长助理李丽介绍校史。一上午时间，语文、数学、理化生、政史地等四个学科，分别由省实验中学语文、数学、物理、政治教研组长李满、潘洪艳、张海、顾静四位大咖，给学生们做学法指导。       “真没想到，新航学子会有机会见到这么多知名大咖，这么多重磅名师。孩子们有这样的机会，...', '', '<p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;14日，济南新航实验外国语学校首届领航夏令营暨首届家长见面会活动在山东省实验中学中心校区落下帷幕，首先，由省实验中学校长助理李丽介绍校史。一上午时间，语文、数学、理化生、政史地等四个学科，分别由省实验中学语文、数学、物理、政治教研组长李满、潘洪艳、张海、顾静四位大咖，给学生们做学法指导。</span></p><p><a href="images/9c3b7bf13bea4f4881bca522c7baa46e.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/9c3b7bf13bea4f4881bca522c7baa46e.jpg"/></a><a href="images/7173da257d4148cbba3ee54b1929efe7.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/7173da257d4148cbba3ee54b1929efe7.jpg"/></a><a href="images/8a12989f92704034876561aae2772194.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/8a12989f92704034876561aae2772194.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“真没想到，新航学子会有机会见到这么多知名大咖，这么多重磅名师。孩子们有这样的机会，确实很难得，孩子们对于暑假怎样学习、高中怎样规划，都有了清楚的想法。”一位学生家长在现场感慨道，各科学法指导让每位学生都收获满满。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;14日中午一点多，家长们陆续赶来，闭营仪式在省实验中学如期举行。山东省实验中学校长、党委书记韩相河与山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊共同登台，依次为每一位首届高一学生颁发录取通知书，亲手递到每一个孩子手中。端庄大气的通知书赢得了不少学生和家长的点赞。</span></p><p><a href="images/6f8d2b5c8e0c4bcd806d245dda757181.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/6f8d2b5c8e0c4bcd806d245dda757181.jpg"/></a><a href="images/c9b8192697c046b9ba294ad1d8765560.jpg" target="_blank"><img title="640.webp (5).jpg" src="/uploads/migration/images/c9b8192697c046b9ba294ad1d8765560.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在随后的闭营仪式上，山东省实验中学校长、党委书记韩相河致辞，“同学们，对于即将到来的高中生活，你们做好准备了吗？你们找到自己的方向了吗？相信两天的领航营活动，已经为你们打开了了解高中生活的一扇窗户。”面对新航实验首届学子即将迎来的高中生活，韩相河嘱咐学生们，“高中三年，是挥洒汗水的三年，虽然只有1000多个日日夜夜，却是你们改变自己命运的最佳时机。”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;领航夏令营活动结束后，紧接着进行的是首届学生家长见面会。济南新航实验外国语学校教学管理中心副主任吕秀亭、济南新航实验外国语学校副校长张爱梅，分别组织普通班、融合班家长见面会，同时邀请往届学生和家长代表到场，为新航实验高一学子和家长解答疑惑。至此，济南新航实验外国语学校首届领航夏令营暨家长见面会圆满结束。</span></p><p><span>学生感悟</span></p><p><span>看见远方</span></p><p><span>首届新航学子 周靖怡</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;有幸听到了清华大学韩孟臻教授的讲座，其中大多专业知识我都听得似懂非懂，但其中一点我捕捉到了——远见。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;韩教授讲到，梁思成和夫人林徽因很早便着手于中国古建筑的研究，这是远见；他的导师在设计图书馆三期工程时考虑到要与环境相融合，这是远见。有远见，是因为他们看见了未来，中国古建筑的研究为如今的建筑学奠定了基础，图书馆精心的设计则让它有了跨越时空，与清华大学融为一体的能力。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;韩教授说，评价一位建筑学家有远见，是对这位建筑师最大的肯定。评价一座建筑能够跨越时间的长河，仍如新生，是对它最高的赞美。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;建筑学如此，我们更是一样，人应该有看见未来的能力，而不只是专注于眼前。</span></p><p><br/></p><p><span>穿越时间的语言</span></p><p><span>首届新航学子 臧曼淇</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;建筑学，陌生而又随处可见的学问，我曾经总是认为，建筑师画好设计图，交付施工单位，是一件高度工业化而毫无美感的事。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;但清华大学韩教授的讲座，彻底颠覆了我对建筑的认识，其中就包括最初由美国建筑师用赔款建成的第一期图书馆。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;听韩教授一个时期连一个时期的娓娓道来，让人恍如隔世之感，时隔几十年的工程，其总建筑师也必须在半个世纪前的红砖白石中，触摸前人的灵魂，用自己的设计与他们融为一体。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;最终，在韩教授向我们展示的二期图书馆照片中，与四周完美契合，承接上代风骨的建筑隐没在一片爬山虎的青翠中，静默地凝视着历史。三期、四期的建筑在风格上仍然是继承初代的基础风格，但三期的大体量和四期对于空间的需求，使得设计师必须做出创新。三期在设计时，特意使用了将高层转化为坡式屋顶的设计，大大减少了二层变四层在视觉上给人的冲击与突兀感。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;四期的设计由韩教授参与设计，在底下坐着听他说起这段几乎等同于历史故事的我，不由得联想到我长期坚持练习的书法，与前人对话，与名帖中书家的书风、书骨相遇，无疑，建筑与书法，与其他艺术一样，是穿越了时间无声的语言。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;感谢领航营，感谢韩教授，带我们穿越了百年时光，让我领略到建筑学风雅而神秘的冰山一角。</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '指导 领航 多学科 学法 落幕', '');
INSERT INTO public.news VALUES (1045, '【媒体聚焦】贯通十二年 初、高中衔接更畅通', '', '济南新航实验外国语学校       今年秋季新学期，山东省实验中学教育集团旗下的济南新航实验外国语学校将正式亮相，初、高中率先招生。　　对于省实验中学打造一所十二年一贯制学校，不少家长仍有些不解。对此，山东省实验中学副校长、济南新航实验外国语学校校长林宝磊表示，打通初、高中更利于学习习惯培养，也更利于教学结构的系统性和完整性，也更利于学生的成长。小班化教学成长方案“量身定制”       作为与山...', '', '<p><br/></p><p><a href="images/c9e4f6003d284ef38566fe96c96c3aa7.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/c9e4f6003d284ef38566fe96c96c3aa7.jpg"/></a><a href="images/8c0d90a059a74bcf91ab2d7be217f0f8.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/8c0d90a059a74bcf91ab2d7be217f0f8.jpg" width="759" height="390"/></a></p><p><span>济南新航实验外国语学校</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;今年秋季新学期，山东省实验中学教育集团旗下的济南新航实验外国语学校将正式亮相，初、高中率先招生。</span></p><p><span>　　对于省实验中学打造一所十二年一贯制学校，不少家长仍有些不解。对此，山东省实验中学副校长、济南新航实验外国语学校校长林宝磊表示，打通初、高中更利于学习习惯培养，也更利于教学结构的系统性和完整性，也更利于学生的成长。</span></p><p><br/></p><p><span>小班化教学成长方案“量身定制”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为与山东省实验中学一脉相承、自带“省实验+”的学校，济南新航实验外国语学校全学段实行小班化教学，每个班级不超过30人，这样一来，每个学生都可以被老师全面关注。</span><br/></p><p><span>　　山东省实验中学国际部主任、新航实验外国语学校副校长张爱梅表示，学校会充分尊重学生的个性，为每一位学生配备学术、生活、升学顾问老师，“学生一入学，老师就会根据学生情况，量身定制学生成长指导方案。”新航实验外国语学校除了有国际领先的图书馆、实验室、功能教室、剧院、多媒体报告厅、体育馆、游泳馆等一流的硬件设施，而且会在教育教学管理、集体备课、考试评估、课题研究等方面实现与省实验中学的无缝对接。</span></p><p><span>　　“就是要给学生无限可能，让每个生命都得到绽放。”张爱梅表示，开学后就会为每一个学生进行规划，让学生认识自我，知道适合的成长道路。</span></p><p><br/></p><p><span>荟萃课程各具特色</span></p><p><span>让学生个性绽放</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;课程是家长最关心的内容之一。初中部开齐开全国家课程，此为学校核心课程的培壅固源教育；初中部的荟萃课程则是学生个性化发展特色教育。其中，体育、音乐、美术、戏剧课程由专业的中国老师和外教共同完成。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;师资力量也备受关注。据了解，新航实验将有济南重点初中的优秀教师加入，还有从全国招聘的优秀教师，以及参加过中考命题的教师作为顾问团队。</span></p><p><span>　　省实验中学为新航实验注入了强大后备力量，由省实验中学教育集团统一调配校长、管理团队和骨干教师，在第一年的师资团队中，已有特级教师、正高级教师和硕士研究生导师，有荣获全国、省、市优质课一等奖的中青年骨干教师及教学能手，有43位教师获得博士、硕士学位，还有来自美国、英国、加拿大、澳大利亚等国家的外籍教师11人，绝大多数非英语学科教师的英语水平达到了六级。</span></p><p><span>　　在张爱梅看来，教师培训、成长是学校发展的生命线，学校计划给老师们更多的学习、培训机会，树立终身学习的思想，掌握学习方法。“在不能完全预计到未来工作变化的情况下，如何使教育与未来的工作相适应”。</span></p><p><br/></p><p><span>贯通十二年</span></p><p><span>打破初高中衔接“壁垒”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;有家长也许会觉得，省实验中学办初中学校没有完善经验，但实际上，省实验很早就有初中办学经验，很多教师也都教授过初中课程，尽管现在课程有变化，但学生的成长规律不会改变，而且，学校在教学中融入了新的理念和方式。</span></p><p><span>　　山东省实验中学副校长林宝磊同时也兼任新航实验外国语学校执行校长，他对十二年一贯的教学模式十分认同。他说，初、高中的六年一贯以及从小学到高中的十二年一贯，非常利于教育资源的均衡和共享，老师的教学方式、风格也更统一，更利于学生的初高中衔接，避免学习上的脱节。</span></p><p><span>　　而且，不同初中学校的教育理念、思想、风格都有差异，如果学生进入高中后不适应高中学校的模式，很有可能产生心理上的一些问题，打通一贯制能够改善这些对学生不利的影响，更利于学习习惯的培养，也更利于教学结构的系统性和完整性，也更利于学生的成长。</span></p><p><span>（新时报记者柴颖颖）</span></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '聚焦 高中 衔接 贯通 畅通', '');
INSERT INTO public.news VALUES (1037, '新航实验领航夏令营又来了！初中部新生看过来！', '', '初中部2019年领航夏令营暨新生家长见面会       为给首届新航实验初中部学子提供接触科学前沿、感受名师风采的机会，济南新航实验外国语学校将于2019年7月19日，在山东省实验中学中心校区举行新航实验初中部领航夏令营暨初一新生家长见面会活动，2019级新生将通过此次活动走进实验校园、走近实验中学以及新航实验名师，开拓视野、增长见识，为即将到来的初中学习和生活做足准备。时间安排：7月19日参加人...', '', '<p><br/></p><p><span>初中部2019年领航夏令营</span></p><p><span>暨新生家长见面会</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;为给首届新航实验初中部学子提供接触科学前沿、感受名师风采的机会，济南新航实验外国语学校将于2019年7月19日，在山东省实验中学中心校区举行新航实验初中部领航夏令营暨初一新生家长见面会活动，2019级新生将通过此次活动走进实验校园、走近实验中学以及新航实验名师，开拓视野、增长见识，为即将到来的初中学习和生活做足准备。</span></p><p><span>时间安排：</span><span>7月19日</span></p><p><span>参加人员：</span><span>济南新航实验外国语学校</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;初中部2019级新生</span></p><p><span>课程安排</span></p><p><a href="images/820628a204bf4080b60096a1deb96e27.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/820628a204bf4080b60096a1deb96e27.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为首届新航实验学子在学校的第一次集体活动，领航夏令营对每一位学生来说都是难得的人生经历。期间不仅能帮助学生们在短时间内熟悉同伴，还能建立信任，培养合作意识。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为新航实验外国语学校的首批学生，通过领航夏令营，他们将亲身感受到实验历史和新航实验文化，树立目标，为即将到来的初中生涯做好长足的打算与充分的准备，走好自己的成长成才之路。</span></p><p><br/></p><p><br/></p><p><span>山东省实验中学教育集团</span></p><p><span>济南新航实验外国语学校</span></p><p><span>&nbsp;2019年7月12日&nbsp;&nbsp;</span></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '初中部 夏令营 领航 实验 新生', '');
INSERT INTO public.news VALUES (1038, '圆满落幕，新航实验初中部举行领航营活动', '', '       “今年，新航实验开始招收初一新生，这在一定程度上意味着省实验中学恢复了初中办学。“各位都经过了我们的优中选优、精挑细选，每个学生身上都带着很多来自社会、学校、家庭的寄托和期望，今天，我们从四面八方来到这里，已经开始了你们在新航的第一步，未来你们还要立足山东、面向世界。”山东省实验中学校长、党委书记韩相河在活动上说道。       19日，济南新航实验外国语学校初中部迎来首届领航营活动...', '', '<p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“今年，新航实验开始招收初一新生，这在一定程度上意味着省实验中学恢复了初中办学。“各位都经过了我们的优中选优、精挑细选，每个学生身上都带着很多来自社会、学校、家庭的寄托和期望，今天，我们从四面八方来到这里，已经开始了你们在新航的第一步，未来你们还要立足山东、面向世界。”山东省实验中学校长、党委书记韩相河在活动上说道。</span></p><p><a href="images/d0594e6c217d4713848c6205f4e0c45a.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/d0594e6c217d4713848c6205f4e0c45a.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;19日，济南新航实验外国语学校初中部迎来首届领航营活动，近120名“准新航学子”在山东省实验中学度过了一个难得的学习经历，从上午的实验历史沿革讲述、破冰游戏、数学文化讲座到下午的实验课、英语课，学生们度过了一个充实难忘的学习之旅，在下午的闭营仪式上，每位同学登台，领到了属于自己的录取通知书。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;早上七点多，距离活动正式开始还有一个多小时，就有学生早早赶来现场。有学生感慨的表示，前几天看到新航实验高中部领航营的活动后，一直很期待着初中部也有自己的领航营，没想到这么快就到了。</span></p><p><a href="images/f1ac58a45259484c931ccd4d6186e1a1.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/f1ac58a45259484c931ccd4d6186e1a1.jpg"/></a><a href="images/71c480c283a74c8aaceeac86468f4efe.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/71c480c283a74c8aaceeac86468f4efe.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在上午的开营仪式上，山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊叮嘱学生们，“从小学一年级到六年级是一个蜕变，初中三年又是一个蜕变，我们期待看到你们蜕变的整个过程，新航实验将为你们的蜕变保驾护航。”</span></p><p><a href="images/bec217f0db48455da7fdb54d84bc261b.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/bec217f0db48455da7fdb54d84bc261b.jpg"/></a></p><p><span>山东省实验中学副校长</span></p><p><span>济南新航实验外国语学校执行校长林宝磊</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“欢迎你们加入实验的大家庭，作为实验学子要具备的特质，包括儒雅的君子之风、胸襟开阔的豁达、明辨是非的正直、认真踏实的严谨、持之以恒的坚毅。要相信，和优秀的人在一起，你会越来越好。”山东省实验中学校长助理李丽讲述实验历史沿革的同时，提醒同学们要勇于做最好的自己。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在上午的破冰游戏环节，学生们进行了自我介绍，与高中部领航营不同的是，19日当天的活动现场，专门增加了一个“我的三十岁名片”的主题活动，学生们亲手设计自己的梦想名片，现场气氛很热烈，学生们纷纷拿出自己名片向身边刚熟悉的小伙伴炫耀，做自我介绍。</span></p><p><a href="images/741871f783d94e0e8322fae042bf0de9.jpg" target="_blank"><img title="640.webp (6).jpg" src="/uploads/migration/images/741871f783d94e0e8322fae042bf0de9.jpg"/></a><a href="images/b101bff065384d0298e4bc64733b8177.jpg" target="_blank"><img title="640.webp (7).jpg" src="/uploads/migration/images/b101bff065384d0298e4bc64733b8177.jpg"/></a><a href="images/e8fe5b676fe343b898ccc5e84becf168.jpg" target="_blank"><img title="640.webp (8).jpg" src="/uploads/migration/images/e8fe5b676fe343b898ccc5e84becf168.jpg"/></a><a href="images/bc1476d0ec93419696816f4c11987ff7.jpg" target="_blank"><img title="640.webp (9).jpg" src="/uploads/migration/images/bc1476d0ec93419696816f4c11987ff7.jpg"/></a></p><p><a href="images/16ee6c8299964aadb822fcf4771488a6.jpg" target="_blank"><img title="640.webp (10).jpg" src="/uploads/migration/images/16ee6c8299964aadb822fcf4771488a6.jpg"/></a><a href="images/6182ba477bb44f57a714179056d49313.jpg" target="_blank"><img title="640.webp (11).jpg" src="/uploads/migration/images/6182ba477bb44f57a714179056d49313.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;紧接着，山东省实验中学数学奥赛主教练龚洪戈老师给学生们带来《数学文化》的讲座。午餐结束后，学生们做老师的带领下，分别做四个实验室进行了创新思维体验课程。</span></p><p><a href="images/181d75be19664058b78acf255d2c975a.jpg" target="_blank"><img title="640.webp (12).jpg" src="/uploads/migration/images/181d75be19664058b78acf255d2c975a.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;之后，省实验中学英语教研组长宋武栋老师给学生们做了题为Enjoy English, Enjoy&nbsp; Life 的主题讲座，赢得了学生和家长们一致好评。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;做当天的闭营仪式上，山东省实验中学校长、党委书记韩相河与山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊上台，郑重的将录取通知书交到每位学生手中。</span></p><p><a href="images/52b532ad3f5b41ffa39e546c041cf829.jpg" target="_blank"><img title="640.webp (13).jpg" src="/uploads/migration/images/52b532ad3f5b41ffa39e546c041cf829.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为首届新航实验学子在学校的第一次集体活动，领航夏令营对每一位学生来说都是难得的人生经历。期间不仅帮助学生们在短时间内熟悉同伴，还培养了合作意识。通过领航夏令营，学生们感受到实验历史与新航文化，为即将到来的初中生涯走出了第一步。</span></p><p><a href="images/a01e9bd33c4f42328c619ebe13ff16cd.jpg" target="_blank"></a></p><p><span>学生感悟</span></p><p><span>三十岁的我</span></p><p><span>新航首届初中部学子&nbsp;&nbsp;</span><span>陈倍乐</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;人的一生，会经历很多个十岁，当你在十字开头的年龄，你期待的三十岁，会是什么样子？</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;今天的第一个活动，是“三十岁我的名片”，你需要填写你的“名片”，然后把它递交给三个同学和三个考生，让他们在背面签上字，这就算完成了。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;里面有一项，是你的职务、公司，总的来说，也就是梦想，我的梦想是当一名服装设计师，我想自己开一家服装店，向人们出售我设计单位服装，慢慢成为世界闻名的著名服装设计师，向世界推广具有中华民族特色的美丽服装，为国争光。大家的理想各不相同，却是同样的远大。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;为了我三十岁前可以实现这个理想，我每周都会抽出时间来设计服装并虚心向人们请教，直到现在，我已经设计了好几套别具一格的服装，他们也都有独具创意的名字。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;我很期待我的三十岁，我也在一直努力着。</span></p><p><span>充实·真心</span></p><p><span>新航首届初中部学子&nbsp;&nbsp;</span><span>王一帆</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;7月19日，我来到了山东省实验中学，在这里度过了充实的一天。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;早上我带着满心的喜悦和好奇走进了校门，这一上午，老师的介绍让我们重新认识了这个学校。中午时，我们在食堂吃饭，可老师们却在旁边饿着肚子，他们帮一些同学换掉不合口味的饭。他们的无私奉献，又有谁能关注到？老师本就是一个默默无闻的职业，他们教书育人，真心帮助学生，和学生成为真正的朋友。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;万物讲究一个真字，只有当你敞开心扉，用一颗真诚的心面对他人，他们才会接受你，用一颗同样的真心来回报你，相信在以后与老师的相处中，我也会明白老师的苦心，宝剑锋从磨砺出，梅花香自苦寒来，我也要努力学习，为祖国贡献自己的力量。</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'campus', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '实验 初中部 新航 举行 落幕', '');
INSERT INTO public.news VALUES (1039, '梦想扬帆起航 风景这边独好 ——记济南新航实验外国语学校第三场高中招生说明会', '', '       6月15日，济南新航实验外国语学校第三场高中说明会在山东省实验中学中心校区实验楼六楼礼堂隆重召开了。       六月的济南迎来了入夏以来的又一个高温预警，在浓浓的盛夏气息的陪伴下，我们的招生季也如约而至。       作为今年备受瞩目的新起之秀，山东省实验中学教育集团的新成员——济南新航实验外国语学校自进入大众视野以来，来自社会各界的关注度就一路升温，在首场说明会迅速爆满紧急加推第...', '', '<p><br/></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;6月15日，济南新航实验外国语学校第三场高中说明会在山东省实验中学中心校区实验楼六楼礼堂隆重召开了。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;六月的济南迎来了入夏以来的又一个高温预警，在浓浓的盛夏气息的陪伴下，我们的招生季也如约而至。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为今年备受瞩目的新起之秀，山东省实验中学教育集团的新成员——济南新航实验外国语学校自进入大众视野以来，来自社会各界的关注度就一路升温，在首场说明会迅速爆满紧急加推第二场的情况下，各种线下咨询热度仍然持续不减。为了满足广大家长和考生的咨询需求，帮助大家更加系统全面地走进新航、了解新航、感受新航，6月15日，济南新航实验外国语学校在山东省实验中学中心校区实验楼六楼礼堂隆重召开了第三场高中说明会。六月骄阳似火，而家长与考生们的关注热情却更似骄阳。原定于九点开始的招生说明会，才刚过八点就迎来了第一批家长，不一会儿，整个礼堂里就已是座无虚席。</span></p><p><br/></p><p><a href="images/1c39ff5089b144e3a39f01687e726f86.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/1c39ff5089b144e3a39f01687e726f86.jpg"/></a></p><p><span>说明会现场</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊率领由山东省实验中学统一调配的骨干教师和管理团队亮相了本场说明会。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;会议开始，山东省实验中学教导处王飞主任首先从校园文化、办学理念、师资团队、课程体系、硬件设施等方面详细介绍了学校的基本情况；随后，林校长针对政策性问题和家长关心的问题做出了详细解答，他强调，“山东省实验教育集团将致力于把济南新航外国语学校打造成精品版的实验中学，传承和发扬实验文化，真正实现让每一个生命都精彩绽放的教育理念；不驰于空想，不骛于虚声，扎扎实实埋头做教育”；最后，山东省实验中学国际部张爱梅主任针对新航实验外国语学校融合课程班的具体情况向大家进行了详细阐述，专业详实的介绍让家长们对融合版课程有了更加深刻的认识和了解。</span></p><p><a href="images/7058ec360ccc49fdbd4b98032e8c9448.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/7058ec360ccc49fdbd4b98032e8c9448.jpg"/></a></p><p><span>山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊讲话</span><br/></p><p><br/></p><p><a href="images/c44ee478daba4312b789c70013dc5214.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/c44ee478daba4312b789c70013dc5214.jpg"/></a></p><p><span>山东省实验中学国际部主任张爱梅讲话</span></p><p><br/></p><p><a href="images/0207e8d79d6142cc9a9e4f35429835ad.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/0207e8d79d6142cc9a9e4f35429835ad.jpg"/></a></p><p><span>山东省实验中学教导处主任王飞讲话</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;整场说明会持续了近两个小时，会议结束后，很多考生和家长还久久不愿散去，礼堂里人头攒动，热度不减。</span></p><p><a href="images/d88a392136e745deb40d2026cd30abb4.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/d88a392136e745deb40d2026cd30abb4.jpg"/></a></p><p><span>会后家长现场咨询</span></p><p><span><br/></span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;济南新航实验外国语学校定将不忘初心，不负众望，为每一位优秀学子的追梦之路保驾护航！金秋九月，期待与你在新航实验相约！</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'admission', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '外国语 独好 济南 实验 新航', '');
INSERT INTO public.news VALUES (1040, '2019年济南新航实验外国语学校（高中部）录取名单公示', '', '根据《济南市2019年高中阶段学校招生工作意见》《济南新航实验外国语学校2019年自主招生方案》，根据学生网上报名，按照学生综合成绩由高到低,结合学生及家长意愿,现将济南新航实验外国语学校（高中部）录取名单公示如下。被我校录取的同学将不再享有其它志愿填报的资格,我校将直接注册学籍。附：济南新航实验外国语学校（高中部）录取名单（按姓氏首字母排序）', '', '<h3><span><span>根据《济南市<span>2019</span>年高中阶段学校招生工作意见》《济南新航实验外国语学校<span>2019</span>年自主招生方案》，根据学生网上报名，按照学生综合成绩由高到低<span>,</span>结合学生及家长意愿<span>,</span>现将济南新航实验外国语学校（高中部）录取名单公示如下。</span><span>被我</span><span>校录取的同学将不再享有其它志愿填报的资格,我校将直接注册学籍。</span></span></h3><p><span>附：济南新航实验外国语学校（高中部）录取名单（按姓氏首字母排序）</span></p><p><br/></p><meta name="ContentEnd">', '', 'admission', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '学校 外国语 高中部 实验 录取', '');
INSERT INTO public.news VALUES (1041, '【媒体聚焦】打造“精品版省实验”！这所新校凭啥吸引那么多人关注', '', '       作为山东省实验中学教育集团和山东出版集团合力打造的重点项目，济南新航实验外国语学校（以下简称新航实验）是名副其实的“实验+”，在这一特殊身份下，这所新学校的一举一动牵动着学生和家长的心。日前，记者驱车来到该校新校园发现，教学楼、宿舍楼、办公楼等建筑都已基本装修完毕，六月竣工验收后，所有教学设备、家具等物品将在7月底前调试完毕，今年秋季正式开门迎来首批新生。小班化：打造“精品版的省实验...', '', '<p><span>&nbsp; &nbsp; &nbsp; &nbsp;作为山东省实验中学教育集团和山东出版集团合力打造的重点项目，济南新航实验外国语学校（以下简称新航实验）是名副其实的“实验+”，在这一特殊身份下，这所新学校的一举一动牵动着学生和家长的心。日前，记者驱车来到该校新校园发现，教学楼、宿舍楼、办公楼等建筑都已基本装修完毕，六月竣工验收后，所有教学设备、家具等物品将在7月底前调试完毕</span><span>，今年秋季正式开门迎来首批新生。</span></p><p><img title="640.webp.jpg" src="/uploads/migration/images/11c6e3f9577844e2a0a9279f6d5164b9.jpg"/><br/></p><p><span>小班化：打造“精品版的省实验”</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“坦白说，学费确实不低，并且是一所建设中的新学校，但真没想到家长们的热情会这么高，我们提前一个小时到场，偌大的会议室里竟然坐满了学生和家长。”家长郑先生感慨道，6月15日，在参加完新航实验的招生说明会后，果断决定要给孩子报名，“从师资到理念，都让人很放心，看得出来，这是一群踏踏实实做教育的人”。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在前不久新航实验举行的发布会上，该校首次公开</span><span>今年的招生计划，即通过自主招生的形式招收初一新生120人、高一新生180人（其中有90个名额面向全省招生），每班30人，实行真正的小班化教学，初一4个班、高一6个班，高中部包括4个普通班、2个融合班。学费方面，初中部计划每年学费7万元，高中每年学费9万元，高中融合课程班每年收费12万元（具体收费情况将以物价部门最终批复为准）。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;招生计划发布后，新航实验引来</span><span>不少学生和家长的瞩目，为此先后三次举行招生说明会，几乎场场爆满。在15日的招生说明会上，山东省实验中学副校长林宝磊正式亮相，此时的他还担负着另一重身份——济南新航实验外国语学校执行校长。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“我们致力于把新航实验打造成精品版的实验中学，传承和发扬实验文化，不驰于空想，不骛于虚声，扎扎实实埋头做教育，让每一个生命在这里都能精彩绽放”。林宝磊介绍道。</span></p><p><a href="images/05058965bfaf42aea6a2f897d4df29e6.jpg" target="_blank"><img title="640.webp (1).jpg" src="/uploads/migration/images/05058965bfaf42aea6a2f897d4df29e6.jpg"/></a></p><p><span>济南新航实验外国语学校施工现场。记者　张鹏　摄</span></p><p><br/></p><p><span>独一份：坐拥山体后花园</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;跨过二环东路，沿经十路一路向东，经过40分钟车程后，记者来到位于历城区彩石街道的新航实验，教学楼、图书馆、宿舍楼、餐厅、体育场……在进行建设收尾的新校园中，各主体工程基本完工，施工人员正在进行最后的装修和清理工作，学校教学楼、宿舍楼、办公楼等建筑内部和外部都已经基本装修完毕，教学楼外砌“哈佛红”砖块，内部墙体为鲜亮的黄、绿、蓝色调。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;据介绍，一侧的体育馆正在建设中，将来这里篮球厅、游泳馆等设施一应俱全，按照计划，6月底前工程将完工验收，教学设备、家具等物品将在7月底前全部调试完毕，开学前，所有建筑、设备还会再次进行细节打磨，以最好状态迎接第一批学生。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“学校北倚玉皇山，向南俯瞰狼猫山水库，真正的依山傍水。”林宝磊介绍道，新航实验占地总面积225亩，南北落差35米，南部为占地155亩的校区，包括幼儿园部、小学部、初中部以及高中部，校区北部为占地70亩的林被，将被建设成山体后公园，“山体公园是学校的一个特色，其中约10亩林被将被建成学生农场，学生可以在这个‘后花园’里进行课外实践活动。”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;据了解，建成后，新航实验将成为济南首个拥有山体后花园的高中学校，依托独有的高度差特色，学校将因地制宜进行设计，将校园打造得错落有致。</span></p><p><br/></p><p><span>人性化：三人间宿舍内有俩卫生间</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在初中部教学楼内，教室装修成极简北欧风格，蓝、灰相间的座椅以及多媒体系统已经基本到位，教室里还有专门的洗手池和橱柜。“后面的柜子是一个平板电脑存储柜，学生上课使用平板电脑查看资料，下课后统一存储在储存柜里。”林宝磊表示，桌椅都是采用环保材料专门定制，椅子完全符合人体力学，而且整体色彩搭配协调，“为学生量身打造的桌椅，确保学习时的舒适度。”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在住宿方面，该校实行生活学院制度，3至4名学生住一间学生公寓，每间公寓有双卫生间，全天候供应直饮纯净水、热水，配备专职生活学院导师指导和管理学生生活。在学生宿舍楼内，有的宿舍里已经安置了床、桌凳家具，学生床位是2.1米长的上下铺，实现干湿分离，宿舍内有公共休息区域，但是不设置书桌，“我们不鼓励学生回到宿舍还继续读书，所以，即使现在有的床下有书桌，今后也会被撤掉。”学校相关负责人说。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;对于学生普遍关心的师资问题，除了省实验名师团队外，新航实验此前已经招聘了63名骨干教师，其中包括11名外籍教师。“我们已经提前对老师们进行线上培训，让他们提前了解学校和工作，6月15日前，每名新应聘教师已经按要求制作了开学后行之有效的校本课程。”林宝磊告诉记者，这些教师7月入职后将在省实验中学接受统一培训，“新航实验与省实验在教育教学管理、集体备课、考试评估、课题研究等方面实行无缝对接，确保教学的高水准。”</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '打造 精品 实验 吸引 聚焦', '');
INSERT INTO public.news VALUES (1042, '【媒体聚焦】11名外教组团“入驻” 每名学生有3位“顾问”', '', '6月17日，无人机俯瞰正在建设中的济南新航实验外国语学校。 本版照片均由新时报记者黄中明 摄6月17日，建设中的济南新航实验外国语学校。       今年秋季开学，山东省实验中学教育集团新成员——济南新航实验外国语学校（以下简称“新航实验”）将正式亮相纳新。6月17日，记者实地探访这所“实验+”校园，提前为家长和学生“揭秘”。不仅有游泳馆还有“后花园”       济南新航实验外国语学校位于历城区...', '', '<p><br/></p><p><a href="images/f8a9ff0b1c524b2aa524c30c0b84f697.jpg" target="_blank"><img title="640.webp (2).jpg" src="/uploads/migration/images/f8a9ff0b1c524b2aa524c30c0b84f697.jpg"/></a></p><p><a href="images/9f72310b95af46a5b2f3f36208ea39be.jpg" target="_blank"><img title="640.webp (3).jpg" src="/uploads/migration/images/9f72310b95af46a5b2f3f36208ea39be.jpg"/></a></p><p><span>6月17日，无人机俯瞰正在建设中的济南新航实验外国语学校。 本版照片均由新时报记者黄中明 摄</span></p><p><br/></p><p><a href="images/8ad36098208243e88698ebe2e4d716b9.jpg" target="_blank"><img title="640.webp (4).jpg" src="/uploads/migration/images/8ad36098208243e88698ebe2e4d716b9.jpg"/></a></p><p><span>6月17日，建设中的济南新航实验外国语学校。</span></p><p><br/></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;今年秋季开学，山东省实验中学教育集团新成员——济南新航实验外国语学校（以下简称“新航实验”）将正式亮相纳新。6月17日，记者实地探访这所“实验+”校园，提前为家长和学生“揭秘”。</span></p><p><span>不仅有游泳馆还有“后花园”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;济南新航实验外国语学校位于历城区彩石街道，经十东路以北，西邻山东省科学院，东邻山东省公路局用地。教学楼、图书馆、宿舍楼、餐厅、体育场……17日，记者在新航实验看到，目前主体工程已经基本完工，学校未来的“模样”已初步展露。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;在初中部教学楼，部分教室已基本布置完毕，桌椅都是采用环保材料专门定制，尤其是椅子坐上去非常舒适，而且整体色彩搭配协调。相关负责人介绍，“这是为学生量身打造的桌椅，确保学习时的舒适度。”在教室里，还有专门的洗手池和属于每个学生的橱柜，保证学习用品收纳整齐。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;记者注意到，教室大都在朝阳的一面，确保光线充足，空间利用更合理。学校实行生活学院制度，3至4名学生住一间学生公寓，每间公寓有双卫生间，全天候供应直饮纯净水、热水，配备专职生活学院导师指导和管理学生生活，学院导师都是本科以上学历。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;餐厅建设已基本完工。将来，各学部都有专门的学生膳食中心，引入蓝海集团负责管理经营，每日三餐由营养师配制食谱，每周提前公布，学生可根据需求自行选购。同时实行分餐制，保障特殊学生的饮食需求。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;目前，学校体育馆还在建设中，游泳馆等设施将来一应俱全。由于新学校背靠玉皇山，学校最高处与最低处相差30多米，学校利用这个高差因地制宜进行设计，将校园打造得错落有致。在校园内车辆禁行。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“学校还有个特色，将来会打造一处‘山体公园’。”山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊介绍，学校将利用自然优势，背靠60多亩的玉皇山山体依势而建，打造成学生的自然实践基地和“后花园”。</span></p><p><span>每名学生都有3个“顾问老师”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;对于一所新学校而言，师资力量无疑是家长最关心的焦点之一。</span></p><p><span>　　在第一年的师资团队中，已有荣誉等身的特级教师、正高级教师和硕士研究生导师，有荣获全国、省、市优质课一等奖的中青年骨干教师及教学能手，有43位教师获得博士、硕士学位。省实验中学数学正高级教师杨育红、化学特级教师刘沂珍、生物高级教师姚明霞都将加入师资队伍。</span></p><p><span>　　省实验中学国际部主任张爱梅加入了学校管理及融合课程团队。学校还有融合课程首席和资深顾问团队，以及来自美国、英国、加拿大、澳大利亚等国家的外籍教师11人，绝大多数非英语学科教师的英语水平达到六级。</span></p><p><span>　　记者注意到，每个班级教室桌椅配备不超过30人。学校实行小学、初中、高中全学段小班化教学，每班班额不超过30人。林宝磊介绍，学校充分尊重每个学生的独特性，采取个性化辅导的顾问制度，为每一位学生配备学术顾问老师、生活顾问老师和升学顾问老师，学生在这里接受到的是独一无二、量身定制的教育。</span></p><p><span>“苗圃计划”精准培养</span></p><p><span>　　今年，新航实验初、高中招生，其中高中有面向全省招生计划。除了多元融合课程，对于优秀生源，学校还专门制定了“苗圃计划”。</span></p><p><span>　　新航实验将开设多元融合课程，通过法语、西班牙语等第二语言学习以及模拟联合国、传统文化和跨文化对比项目学习，加强学生跨文化教育，培养国际通用型人才。</span></p><p><span>　　多元融合课程除国家核心课程之外还包括特色课程、俱乐部课程、项目课程。特色课程有戏剧（外教）、音乐（外教）、美术（外教）、体育（外教）、传统文化（中教）、创新课程、图书馆课程、二外、领导力课程等；俱乐部课程有辩论、MUN（模拟联合国）、足球、课题研究、合唱团、诗社、摄影、影视创作、画室、游泳、3D打印、机器人等；项目课程有“苗圃计划”项目、爱登堡公爵奖项目、EPQ(Extended Project Qualification)等。</span></p><p><span>　　林宝磊介绍，学校针对智力超常、创新潜质突出、适应快节奏学习的学生，专门制定卓越人才培养项目——“苗圃计划”，该项目采用“分流培养、滚动升级”培养机制，由山东省实验中学奥赛辅导教练及毕业于清华大学、中国科学院大学、中国科技大学、南开大学、山东大学等国内著名高校的教师组成专家团队，旨在培养考取双一流大学，未来能够成为某一学科、某一领域内卓越人才乃至领军人物。这也意味着，优秀生源将从一入学就有明确成才目标。</span></p><p><span>　　“孩子今年实验初中毕业，参加中考的同时也报考了新航实验，既是看中了与省实验的关系，也看中了学校的师资和课程。”家长姚先生说，他对新航实验的融合课程很认可，感觉学校这方面师资确实不错。</span></p><p><span>十二年</span><span>一贯打造完整教学链</span></p><p><span>　　今年，学校初中部拟招收学生120名，高中部拟招收学生180名。</span></p><p><span>　　记者了解到，小学部计划明年招生。初中部计划每年学费7万元，高中每年学费9万元，高中融合课程班每年收费12万元(具体收费详情以物价部门最终批复为准)。同时，学校设有奖学金，包括特等、一等、二等、三等4个层次。</span></p><p><span>　　省实验中学有了新航实验后备基地，也有了十二年一贯的实现平台，可以面向全省招生的做法也让不少高中学校有些羡慕。不过，新航实验打造十二年一贯的做法从长远来说，利于打造完整的教育链条，实现教育模式的完整和教学风格的统一，最终对学生是有益的。&nbsp;</span></p><p><br/></p><p><span>新时报记者柴颖颖</span></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '学生 组团 聚焦 外教 媒体', '');
INSERT INTO public.news VALUES (1043, '【媒体聚焦】新航实验正式启航', '', '       今年秋季开学，济南东部一所十二年一贯制学校将迎来第一批新生入学，它就是山东省实验中学教育集团成员校新成员——济南新航实验外国语学校。       记者了解到，济南新航实验外国语学校初中部拟招收学生120名，高中部拟招收学生180名，2019年暂时不招收小学学段的学生。近日，记者实地探访了这所坐落在玉皇山南侧，向南俯瞰郎猫山水库的“实验+”校园，提前为家长和学生“揭开”学校的神秘面纱。...', '', '<p><a href="images/3f15e9dadac246c882aaa715c5251103.jpg" target="_blank"><img title="640.webp.jpg" src="/uploads/migration/images/3f15e9dadac246c882aaa715c5251103.jpg"/></a></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;今年秋季开学，济南东部一所十二年一贯制学校将迎来第一批新生入学，它就是山东省实验中学教育集团成员校新成员——济南新航实验外国语学校。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;记者了解到，济南新航实验外国语学校初中部拟招收学生120名，高中部拟招收学生180名，2019年暂时不招收小学学段的学生。近日，记者实地探访了这所坐落在玉皇山南侧，向南俯瞰郎猫山水库的“实验+”校园，提前为家长和学生“揭开”学校的神秘面纱。</span></p><p><span>4人间宿舍配备两个卫生间</span></p><p><span>依山傍水还有“后花园”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;沿着经十东路一路向东，经过山东省科学院（东院区）后，一片“哈佛红”建筑群特别引人注目，这就是济南新航实验外国语学校。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;教学楼、图书馆、宿舍楼、餐厅、体育场……记者看到，学校目前主体工程已经基本完工，所有建筑外砌“哈佛红”砖块，本月月底前工程将完工验收，教学设备等物品将在7月底前全部调试完毕。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;走进教学楼内，教室装修为简约风格，采用的是最先进的智能交互电子白板，桌椅都是采用环保材料专门定制的，尤其是椅子坐上去非常舒适，而且整体色彩搭配协调。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;“这是为学生量身打造的桌椅，确保学习时的舒适度。”学校相关负责人介绍，在教室北侧专门设置了可以做随堂小实验的实验台，而教室南北两侧各有一排属于学生的橱柜，保证学习用品收纳整齐。“后面的柜子是一个平板电脑存储柜，上课时，学生可以使用平板电脑辅助学习，下课后统一存储到储存柜里。”</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;记者发现，学校的整个教学楼设置非常人性化，以中学部教学楼为例，环型的教学楼朝阳一面均为教室，确保学生课堂上光线充足。而教学楼北侧则是实验室和功能室，保证随时可以进行相关实验。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;学校实行生活学院制度，3至4名学生住一间学生宿舍，其中4人间宿舍配有两个独立卫生间和一间浴室，实现干湿分离。宿舍内还有公共学习区域，全天候供应直饮纯净水、热水，配备专职学院导师，指导和管理学生生活，学院导师都是本科以上学历。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;目前，学校体育馆建设也已接近尾声，游泳馆等设施将来也一应俱全。由于新学校背靠玉皇山，学校最高处与最低处相差30多米，学校利用这个落差因地制宜进行设计，将校园打造得错落有致。据了解，新航实验占地总面积为225亩，南部为占地155亩的校区，校区北部为占地70亩的山林。学校利用自然优势，将70多亩的山体，打造成专属学生的自然营地”和“后花园”，让自然探索课程与学生生活融为一体，真正打造一个安全、稳定、环保、节能的花园式校园。</span></p><p><span>教师统一接受省实验中学培训43位教师</span><span>拥有博士、硕士学位</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>近日，济南新航实验外国语学校将通过自主招生的形式招收初一、高一新生。本次计划招生300人，每班30人，初一年级4个班；高一年级6个班，其中4个班为普通班，2个班为融合班，高一招生名额中有90个面向全省招生。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;据了解，目前新航实验外国语学校已经招聘63名教师，其中包括11名外籍教师。“现在我们已经开始对老师进行线上培训了，让他们通过一些素材了解一下学校和工作。”山东省实验中学副校长、济南新航实验外国语学校执行校长林宝磊介绍，6月15日前，新招聘的教师已经按照学校的要求制作了入职后行之有效的校本课程。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>林宝磊告诉记者，新招聘的老师将在7月入职后开始接受山东省实验中学培训，学校与山东省实验中学在教育教学管理、集体备课、考试评估、课题研究等方面实行无缝对接。省实验中学将派出名师领衔各学科教学，并担任班主任工作，确保学校教学的高水准。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>在第一年的师资团队中，有特级教师、正高级教师和硕士研究生导师，有荣获全国、省、市优质课一等奖的中青年骨干教师及教学能手，有43位教师获得博士、硕士学位。与此同时，省实验中学数学正高级教师杨育红、化学特级教师刘沂珍、生物高级教师姚明霞都将加入学校的教师队伍。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>省实验中学国际部主任张爱梅也加入了学校管理及融合课程团队。学校还有融合课程首席和资深顾问团队，以及来自美国、英国、加拿大、澳大利亚等国家的外籍教师11人。此外，绝大多数非英语学科教师的英语水平也能达到六级。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>记者注意到，每个班级教室桌椅配备不超过30套。学校实行小学、初中、高中全学段小班化教学，每班班额不超过30人。“学校充分尊重每个学生的独特性，采取个性化辅导的顾问制度，为每一位学生配备学术顾问老师、生活顾问老师和升学顾问老师，学生在这里接受到的是独一无二、量身定制的教育。”林宝磊表示。</span></p><p><span>“苗圃计划”精准培养优秀学子学生</span></p><p><span>入学就有明确成才目标</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>基于山东省实验中学课程体系，济南新航实验外国语学校立足学生发展的三大核心领域：思维训练、能力培养、人格塑造。通过师师之间、师生之间、生生之间的合作创课过程，构建以国家课程为核心的面向未来精英人才培养的个性化“课程+”体系。国家课程坚持基础与拓展相结合，实现国家课程的校本化，满足学生的未来升学需求；校本课程坚持科学素养与人文精神相结合，满足学生的特长发展与综合素质提升。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>学校还将积极探索现代化、科技化、国际化的融合办学模式。在中英文双语教学的基础上，通过法语、西班牙语等语言学习以及模拟联合国、传统文化和跨文化对比项目学习，加强学生跨文化教育，培养国际通用型人才。</span></p><p><span><span>&nbsp; &nbsp; &nbsp; &nbsp;</span>通过戏剧表演、辩论、专项历史题材阅读与写作、STEAM课程等课程和项目，培养学生的创新思维能力和跨学科整合能力；通过项目式学习、合作式学习、探究式学习，培养学生的团队合作能力、独立研究能力；通过爱丁堡公爵奖项目计划，培养具有全球视野与全球资源整合能力、人文关怀与社会担当的卓越人才。</span></p><p><br/></p><p><span>济南日报记者 史春勇</span></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '实验 正式 聚焦 新航 启航', '');
INSERT INTO public.news VALUES (1046, '济南新航实验外国语学校拔尖创新人才夏令营来了！', '', '2019年基础学科拔尖创新人才夏令营       为帮助中学生了解科学魅力，增进求知欲望，树立远大目标，济南新航实验外国语学校借助山东省实验中学卓越的师资团队、丰富的课程资源，面向山东省优秀中学生举办基础学科拔尖创新人才夏令营活动，旨在为全省才华卓越的、追求更高学术成就的优秀中学生搭建交流和进一步发展的平台。       此次夏令营课程内容包括学科前沿讲座、名师讲座、实验室探究等，希望通过本届夏令...', '', '<p><br/></p><p><span>2019年基础学科拔尖创新人才夏令营</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;为帮助中学生了解科学魅力，增进求知欲望，树立远大目标，济南新航实验外国语学校借助山东省实验中学卓越的师资团队、丰富的课程资源，面向山东省优秀中学生举办基础学科拔尖创新人才夏令营活动，旨在为全省才华卓越的、追求更高学术成就的优秀中学生搭建交流和进一步发展的平台。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;此次夏令营课程内容包括学科前沿讲座、名师讲座、实验室探究等，希望通过本届夏令营的学习，帮助学生们拓宽视野，树立远大的理想，增强使命感和责任感。</span></p><p><span>一、选拔对象</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;夏令营选拔拟面向山东省综合素质优秀、特长突出、品学兼优、具有较强的自主学习能力和创新潜质的优秀初中应届毕业生，择优录取，额满为止。有数学、物理、化学、生物、信息等学科特长者优先。</span></p><p><br/></p><p><span>二、报名时间</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;2019年7月23日10:00至2019年8月6日17:00</span></p><p><br/></p><p><span>三、报名办法</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;夏令营采取网上申请方式报名，学生可登录山东省实验中学网站（http://sdshiyan.jinan.cn/），点击“2019年基础学科拔尖创新人才夏令营报名端口”进行报名。详情请见山东省实验中学官方网站公告及微信，以及济南新航实验外国语学校官方微信。</span></p><p><span>面向山东招收60名学员，活动全程免费，学生往返交通及食宿费用自理。</span></p><p><br/></p><p><span>四、时间安排</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;活动时间：8月10日—13日</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;报到时间：8月10日8:30，请学员自行前往报到。</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;报到地点：山东省实验中学中心校区实验科苑第二多媒体教室（经七路73号）</span></p><p><br/></p><p><span>五、活动内容</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;课程内容共包括四个模块，24课时，成绩合格者颁发结业证书。</span></p><p><br/></p><p><span>六、咨询电话</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;0531-86926756</span></p><p><span>&nbsp; &nbsp; &nbsp; &nbsp;0531-86924355</span></p><p><br/></p><p><br/></p><p><br/></p><p><span>山东省实验中学教育集团</span></p><p><span>济南新航实验外国语学校</span></p><p><span>2019年7月22日</span></p><p><br/></p><p><br/></p><p><br/></p><p><br/></p><meta name="ContentEnd">', '', 'media', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '学校 外国语 拔尖 创新 实验', '');
INSERT INTO public.news VALUES (1047, '石晶', '', '    石晶，硕士，高级教师，硕士研究生导师。山东省实验中学语文教研组组长。济南市语文学科带头人，济南市中语会副理事长。全国中学语文教学优秀教师，山东省语文优秀教师，山东省教育学院继续教育中心特聘授课专家，教育部项目《普通高中课程标准语文实验教材》编者。济南市建功立业标兵，获得济南市五一劳动奖章。济南市高三教学质量检查指导小级成员。山东省新课程远程研修市级指导教师。济南市优质课一等奖第一名。著有《...', '', '<p><span><a href="images/6732e9a917c1451fa17bd24e58053592.jpg" target="_blank"><img title="1.jpg" src="/uploads/migration/images/6732e9a917c1451fa17bd24e58053592.jpg" width="213" height="285"/></a></span></p><p><span><span>&nbsp; &nbsp; 石晶，硕士，高级教师，硕士研究生导师。山东省实验中学语文教研组组长。济南市语文学科带头人，济南市中语会副理事长。全国中学语文教学优秀教师，山东省语文优秀教师，山东省教育学院继续教育中心特聘授课专家，教育部项目《普通高中课程标准语文实验教材》编者。济南市建功立业标兵，获得济南市五一劳动奖章。济南市高三教学质量检查指导小级成员。山东省新课程远程研修市级指导教师。济南市优质课一等奖第一名。著有《作文故事</span>88<span>》《恐龙词典》；主编山东省五年制师范学校统编教材《写作训练》；参编“普通高中课程标准实验教科书”《语文》。主编《普通高中新课程高考复习丛书》《三点一测丛书》《课堂新坐标》《新高考阅读闯关》《高中新课程同步训练》等。济南市十二五规划课题“生活化作文”的主要参与研究者，撰写结题报告理论部分。作为优秀指导教师，在叶圣陶杯作文大赛、新概念作文大赛、创新作文大赛、华人作文大赛、全国中小学生经典阅读大赛等各级各类比赛中，每年指导的学生都有若干人获奖。</span></span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '石晶', '');
INSERT INTO public.news VALUES (1048, '王飞', '', '王飞，山东省实验中学教导处副主任，高三级部主任，学校教学督导中心副主任，学校课程建设中心委员，曾担任过政教处副主任并兼职负责过东校团委及教科室工作，第七批“济南市青年学术技术带头人”。本着“以生为本”的理念，所带班级多次荣获济南市优秀班集体，荣获济南市优秀班主任，济南市第二届优秀班主任工作室成员，。全国数学竞赛优秀辅导员，荣获济南市、山东省、全国优质课评比一等奖，荣获市级、省级、部级优课，首届山东...', '', '<p><span><a href="images/ebb59cc6e0e4464aa19acbf0e3d8eae8.jpg" target="_blank"><img title="王飞标准照.jpg" src="/uploads/migration/images/ebb59cc6e0e4464aa19acbf0e3d8eae8.jpg" width="252" height="353"/></a></span></p><p><span>王飞，山东省实验中学教导处副主任，高三级部主任，学校教学督导中心副主任，学校课程建设中心委员，曾担任过政教处副主任并兼职负责过东校团委及教科室工作，第七批“济南市青年学术技术带头人”。本着“以生为本”的理念，所带班级多次荣获济南市优秀班集体，荣获济南市优秀班主任，济南市第二届优秀班主任工作室成员，。全国数学竞赛优秀辅导员，荣获济南市、山东省、全国优质课评比一等奖，荣获市级、省级、部级优课，首届山东省创新课堂评比一等奖，参与多项省、市级课题研究，参编多部教学著作或数学学习指导丛书。多次被评为学校“先进工作者”、“优秀共产党员”。</span></p><p><span>&nbsp;</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '王飞', '');
INSERT INTO public.news VALUES (1049, '林宝磊', '', '林宝磊，山东省实验中学副校长，数学高级教师，山东省“富民兴鲁”劳动奖章获得者，全国数学竞赛优秀辅导员。荣获济南市、山东省、全国优质课评比一等奖，济南市青年教师素质大赛一等奖。济南市五一劳动奖章获得者，获得山东省教学能手、济南市“十大”杰出青年岗位操作能手、济南市优秀班主任等荣誉称号，并记济南市三等功。教学教研中，注重吸收先进的教学理念，研究新课改精神，把握学科教学特色和规律，结合学生特点因材施教，...', '', '<p><a href="images/00c3d2dd17004bf4a3bae0a0d9e10068.jpg" target="_blank"><img width="306" height="420" title="林宝磊.jpg" src="/uploads/migration/images/00c3d2dd17004bf4a3bae0a0d9e10068.jpg"/></a></p><p><span>林宝磊，山东省实验中学副校长，数学高级教师，山东省“富民兴鲁”劳动奖章获得者，全国数学竞赛优秀辅导员。荣获济南市、山东省、全国优质课评比一等奖，济南市青年教师素质大赛一等奖。济南市五一劳动奖章获得者，获得山东省教学能手、济南市“十大”杰出青年岗位操作能手、济南市优秀班主任等荣誉称号，并记济南市三等功。</span></p><p><span>教学教研中，注重吸收先进的教学理念，研究新课改精神，把握学科教学特色和规律，结合学生特点因材施教，教育成效显著，多次讲授各级各类示范课、观摩课、参赛课，多次主持并参与各级数学考试命题工作，多次被评为全国数学竞赛优秀辅导员。注重反思总结，凝练提升，论文《浅析数学思想方法在课堂教学中的渗透》荣获全国一等奖，多篇文章在《中学数学教育》、《现代教育》等核心刊物发表，参与编写多本教育教学著作。多次被评为学校“先进工作者”、“优秀共产党员”。</span></p><p><br/></p><meta name="ContentEnd">', '', 'other', '', NULL, true, '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '2019-07-29 08:00:00+08', '王雪', '新航实验外国语学校', '林宝磊', '');


